const DEADLINE_STRIDE: usize = 256;
const CLIP_MASK_DEADLINE_STRIDE: usize = 16 * 1024;
const PRESERVE_3D_SCENE_RECURSION_LIMIT: usize = 32;
const PRESERVE_3D_PLANE_PARALLEL_MIN_PLANES: usize = 8;
const PRESERVE_3D_PLANE_PARALLEL_MIN_PLANES_WITH_WORK: usize = 4;
const PRESERVE_3D_PLANE_PARALLEL_MIN_TOTAL_PIXELS: u64 = 512 * 512;
const TILE_HALO_SAFETY_MARGIN_CSS: f32 = 4.0;
const MAX_PARALLEL_TILE_PIXEL_AMPLIFICATION: u128 = 8;

/// Compute a conservative halo size in *device pixels* for rendering a sub-rectangle of a display
/// list while preserving byte-identical output with a full-frame render.
///
/// This is shared between tiled rendering (parallel paint) and incremental region repaints.
pub(crate) fn conservative_tile_halo_px(list: &DisplayList, device_scale: f32) -> Result<u32> {
  conservative_tile_halo_px_for_items(list.items(), device_scale)
}

pub(crate) fn conservative_tile_halo_px_for_items(
  items: &[DisplayItem],
  device_scale: f32,
) -> Result<u32> {
  let halo_css = max_effect_padding_css(items)? + TILE_HALO_SAFETY_MARGIN_CSS;
  let device_scale = if device_scale.is_finite() {
    device_scale.abs()
  } else {
    0.0
  };
  Ok((halo_css * device_scale).ceil() as u32)
}

fn max_effect_padding_css(items: &[DisplayItem]) -> Result<f32> {
  // Capture the largest expansion any item can paint beyond its base bounds so tiled rendering
  // includes enough halo to avoid clipping strokes, shadows, and filters.
  let mut max_pad = 0.0f32;
  let mut deadline_counter = 0usize;
  let mut transform_stack: Vec<Transform3D> = Vec::new();

  let transform_scale = |transform: Transform3D| -> f32 {
    if transform.is_identity() {
      return 1.0;
    }

    if let Some(affine) = transform.to_2d() {
      return transform_max_axis_scale(Transform::from_row(
        affine.a, affine.b, affine.c, affine.d, 0.0, 0.0,
      ));
    }

    let (approx, valid) = transform.approximate_2d_with_validity();
    if !valid {
      return f32::INFINITY;
    }
    transform_max_axis_scale(Transform::from_row(
      approx.a, approx.b, approx.c, approx.d, 0.0, 0.0,
    ))
  };

  let scaled_pad = |pad: f32, scale: f32| -> f32 {
    if !pad.is_finite() {
      return 0.0;
    }
    let pad = pad.abs();
    if pad <= f32::EPSILON {
      return 0.0;
    }
    if scale.is_infinite() {
      return f32::INFINITY;
    }
    if !scale.is_finite() {
      return 0.0;
    }
    (pad * scale).abs()
  };

  for item in items {
    check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
      .map_err(Error::Render)?;

    let current_transform = *transform_stack.last().unwrap_or(&Transform3D::identity());
    let current_scale = transform_scale(current_transform);

    match item {
      DisplayItem::PushTransform(transform) => {
        let combined = current_transform.multiply(&transform.transform);
        transform_stack.push(combined);
      }
      DisplayItem::PopTransform => {
        let _ = transform_stack.pop();
      }
      DisplayItem::PushStackingContext(sc) => {
        // Filters are specified in the stacking context's local coordinate space. When the
        // stacking context is transformed (scale/rotation/etc), the filter kernel is effectively
        // transformed in output space as well; tile halo estimation must account for that.
        let local_transform = sc.transform.unwrap_or_else(Transform3D::identity);
        let painting_transform = current_transform.multiply(&local_transform);
        let filter_scale = transform_scale(painting_transform);

        let filters_outset =
          filter_halo_outset_with_bounds(&sc.filters, filter_scale, Some(sc.bounds));
        let backdrop_outset =
          filter_halo_outset_with_bounds(&sc.backdrop_filters, filter_scale, Some(sc.bounds));
        max_pad = max_pad.max(filters_outset.max_side().max(backdrop_outset.max_side()));

        let child_transform = if let Some(perspective) = sc.child_perspective.as_ref() {
          painting_transform.multiply(perspective)
        } else {
          painting_transform
        };
        transform_stack.push(child_transform);
      }
      DisplayItem::PopStackingContext => {
        let _ = transform_stack.pop();
      }
      DisplayItem::StrokeRect(stroke) => {
        max_pad = max_pad.max(scaled_pad(stroke.width * 0.5, current_scale));
      }
      DisplayItem::StrokeRoundedRect(stroke) => {
        max_pad = max_pad.max(scaled_pad(stroke.width * 0.5, current_scale));
      }
      DisplayItem::Outline(outline) => {
        max_pad = max_pad.max(scaled_pad(
          outline.width.abs() + outline.offset.abs(),
          current_scale,
        ));
      }
      DisplayItem::Border(border) => {
        let max_w = border
          .top
          .width
          .max(border.right.width)
          .max(border.bottom.width)
          .max(border.left.width);
        max_pad = max_pad.max(scaled_pad(max_w * 0.5, current_scale));
      }
      DisplayItem::BoxShadow(shadow) => {
        if shadow.inset {
          continue;
        }
        if shadow.color.a <= f32::EPSILON {
          continue;
        }
        let blur = box_shadow_blur_radius_to_sigma(shadow.blur_radius) * 3.0;
        let spread = shadow.spread_radius.abs();
        let offset = shadow.offset.x.abs().max(shadow.offset.y.abs());
        max_pad = max_pad.max(scaled_pad(blur + spread + offset, current_scale));
      }
      DisplayItem::Text(text) => {
        if text.synthetic_bold.is_finite() {
          max_pad = max_pad.max(scaled_pad(text.synthetic_bold, current_scale));
        }
        if text.stroke_width.is_finite() {
          max_pad = max_pad.max(scaled_pad(text.stroke_width * 0.5, current_scale));
        }
        for shadow in &text.shadows {
          if shadow.color.a <= f32::EPSILON {
            continue;
          }
          let blur = shadow.blur_radius.abs() * 3.0;
          let offset = shadow.offset.x.abs().max(shadow.offset.y.abs());
          max_pad = max_pad.max(scaled_pad(blur + offset, current_scale));
        }
      }
      DisplayItem::ListMarker(marker) => {
        if marker.synthetic_bold.is_finite() {
          max_pad = max_pad.max(scaled_pad(marker.synthetic_bold, current_scale));
        }
        if marker.stroke_width.is_finite() {
          max_pad = max_pad.max(scaled_pad(marker.stroke_width * 0.5, current_scale));
        }
        for shadow in &marker.shadows {
          if shadow.color.a <= f32::EPSILON {
            continue;
          }
          let blur = shadow.blur_radius.abs() * 3.0;
          let offset = shadow.offset.x.abs().max(shadow.offset.y.abs());
          max_pad = max_pad.max(scaled_pad(blur + offset, current_scale));
        }
      }
      _ => {}
    }
  }

  Ok(max_pad)
}

fn rgba_bytes(width: u32, height: u32) -> Option<u64> {
  u64::from(width)
    .checked_mul(u64::from(height))
    .and_then(|px| px.checked_mul(4))
}

fn map_blend_mode(mode: BlendMode) -> tiny_skia::BlendMode {
  match mode {
    BlendMode::Normal => tiny_skia::BlendMode::SourceOver,
    BlendMode::Multiply => tiny_skia::BlendMode::Multiply,
    BlendMode::Screen => tiny_skia::BlendMode::Screen,
    BlendMode::Overlay => tiny_skia::BlendMode::Overlay,
    BlendMode::Darken => tiny_skia::BlendMode::Darken,
    BlendMode::Lighten => tiny_skia::BlendMode::Lighten,
    BlendMode::ColorDodge => tiny_skia::BlendMode::ColorDodge,
    BlendMode::ColorBurn => tiny_skia::BlendMode::ColorBurn,
    BlendMode::HardLight => tiny_skia::BlendMode::HardLight,
    BlendMode::SoftLight => tiny_skia::BlendMode::SoftLight,
    BlendMode::Difference => tiny_skia::BlendMode::Difference,
    BlendMode::Exclusion => tiny_skia::BlendMode::Exclusion,
    BlendMode::Hue => tiny_skia::BlendMode::Hue,
    BlendMode::Saturation => tiny_skia::BlendMode::Saturation,
    BlendMode::Color => tiny_skia::BlendMode::Color,
    BlendMode::Luminosity => tiny_skia::BlendMode::Luminosity,
    BlendMode::PlusLighter => tiny_skia::BlendMode::Plus,
    BlendMode::PlusDarker => tiny_skia::BlendMode::Darken,
    BlendMode::HueHsv => tiny_skia::BlendMode::Hue,
    BlendMode::SaturationHsv => tiny_skia::BlendMode::Saturation,
    BlendMode::ColorHsv => tiny_skia::BlendMode::Color,
    BlendMode::LuminosityHsv => tiny_skia::BlendMode::Luminosity,
    BlendMode::HueOklch => tiny_skia::BlendMode::Hue,
    BlendMode::ChromaOklch => tiny_skia::BlendMode::Saturation,
    BlendMode::ColorOklch => tiny_skia::BlendMode::Color,
    BlendMode::LuminosityOklch => tiny_skia::BlendMode::Luminosity,
  }
}

fn transform_rect(rect: Rect, ts: &Transform) -> Rect {
  let corners = [
    (rect.min_x(), rect.min_y()),
    (rect.max_x(), rect.min_y()),
    (rect.max_x(), rect.max_y()),
    (rect.min_x(), rect.max_y()),
  ];
  let mut min_x = f32::INFINITY;
  let mut min_y = f32::INFINITY;
  let mut max_x = f32::NEG_INFINITY;
  let mut max_y = f32::NEG_INFINITY;

  for (x, y) in corners {
    let tx = x * ts.sx + y * ts.kx + ts.tx;
    let ty = x * ts.ky + y * ts.sy + ts.ty;
    min_x = min_x.min(tx);
    min_y = min_y.min(ty);
    max_x = max_x.max(tx);
    max_y = max_y.max(ty);
  }

  Rect::from_xywh(min_x, min_y, max_x - min_x, max_y - min_y)
}

fn invert_transform(ts: Transform) -> Option<Transform> {
  let det = ts.sx * ts.sy - ts.kx * ts.ky;
  if !det.is_finite() || det.abs() < 1e-6 {
    return None;
  }
  let inv_det = 1.0 / det;
  let sx = ts.sy * inv_det;
  let kx = -ts.kx * inv_det;
  let ky = -ts.ky * inv_det;
  let sy = ts.sx * inv_det;
  let tx = (ts.kx * ts.ty - ts.sy * ts.tx) * inv_det;
  let ty = (ts.ky * ts.tx - ts.sx * ts.ty) * inv_det;
  Some(Transform::from_row(sx, ky, kx, sy, tx, ty))
}

#[inline]
fn backdrop_root_range(layer_stack: &[LayerRecord]) -> (usize, usize) {
  let parent_depth = layer_stack.len().saturating_sub(1);
  let mut root_depth = 0usize;
  if parent_depth > 0 {
    for idx in (0..parent_depth).rev() {
      if layer_stack[idx].is_backdrop_root {
        root_depth = idx + 1;
        break;
      }
    }
  }
  (root_depth, parent_depth)
}

fn transform_requires_transformed_clip(transform: Transform, radii: BorderRadii) -> bool {
  let eps = 1e-6;
  if !(transform.sx.is_finite()
    && transform.sy.is_finite()
    && transform.kx.is_finite()
    && transform.ky.is_finite())
  {
    return false;
  }

  // Translation-only transforms keep the clip axis-aligned and do not affect radii.
  let has_skew_or_rotation = transform.kx.abs() > eps || transform.ky.abs() > eps;
  if radii.is_zero() {
    return has_skew_or_rotation;
  }

  has_skew_or_rotation || (transform.sx - 1.0).abs() > eps || (transform.sy - 1.0).abs() > eps
}

fn shade_color(color: &Rgba, factor: f32) -> Rgba {
  let clamp = |v: f32| v.clamp(0.0, 255.0) as u8;
  let r = clamp(color.r as f32 * factor);
  let g = clamp(color.g as f32 * factor);
  let b = clamp(color.b as f32 * factor);
  Rgba::new(r, g, b, color.a)
}

fn rgb_to_hsl(r: f32, g: f32, b: f32) -> (f32, f32, f32) {
  let max = r.max(g).max(b);
  let min = r.min(g).min(b);
  let l = (max + min) * 0.5;

  if (max - min).abs() < f32::EPSILON {
    return (0.0, 0.0, l);
  }

  let d = max - min;
  let s = if l > 0.5 {
    d / (2.0 - max - min)
  } else {
    d / (max + min)
  };
  let h = if max == r {
    ((g - b) / d + if g < b { 6.0 } else { 0.0 }) / 6.0
  } else if max == g {
    ((b - r) / d + 2.0) / 6.0
  } else {
    ((r - g) / d + 4.0) / 6.0
  };
  (h, s, l)
}

fn hue_to_rgb(p: f32, q: f32, t: f32) -> f32 {
  let mut t = t;
  if t < 0.0 {
    t += 1.0;
  }
  if t > 1.0 {
    t -= 1.0;
  }
  if t < 1.0 / 6.0 {
    p + (q - p) * 6.0 * t
  } else if t < 0.5 {
    q
  } else if t < 2.0 / 3.0 {
    p + (q - p) * (2.0 / 3.0 - t) * 6.0
  } else {
    p
  }
}

fn hsl_to_rgb(h: f32, s: f32, l: f32) -> (f32, f32, f32) {
  if s <= 0.0 {
    return (l, l, l);
  }
  let q = if l < 0.5 {
    l * (1.0 + s)
  } else {
    l + s - l * s
  };
  let p = 2.0 * l - q;
  let r = hue_to_rgb(p, q, h + 1.0 / 3.0);
  let g = hue_to_rgb(p, q, h);
  let b = hue_to_rgb(p, q, h - 1.0 / 3.0);
  (r, g, b)
}

fn rgb_to_hsv(r: f32, g: f32, b: f32) -> (f32, f32, f32) {
  let max = r.max(g).max(b);
  let min = r.min(g).min(b);
  let v = max;
  let d = max - min;
  if d.abs() < f32::EPSILON {
    return (0.0, 0.0, v);
  }
  let s = if max > 0.0 { d / max } else { 0.0 };
  let h = if (max - r).abs() < f32::EPSILON {
    (g - b) / d + if g < b { 6.0 } else { 0.0 }
  } else if (max - g).abs() < f32::EPSILON {
    (b - r) / d + 2.0
  } else {
    (r - g) / d + 4.0
  } / 6.0;
  (h, s, v)
}

fn hsv_to_rgb(h: f32, s: f32, v: f32) -> (f32, f32, f32) {
  if s <= 0.0 {
    return (v, v, v);
  }
  let hh = (h * 6.0) % 6.0;
  let i = hh.floor();
  let f = hh - i;
  let p = v * (1.0 - s);
  let q = v * (1.0 - s * f);
  let t = v * (1.0 - s * (1.0 - f));
  match i as i32 {
    0 => (v, t, p),
    1 => (q, v, p),
    2 => (p, v, t),
    3 => (p, q, v),
    4 => (t, p, v),
    _ => (v, p, q),
  }
}

fn srgb_to_linear(v: f32) -> f32 {
  if v <= 0.04045 {
    v / 12.92
  } else {
    ((v + 0.055) / 1.055).powf(2.4)
  }
}

fn linear_to_srgb(v: f32) -> f32 {
  if v <= 0.0031308 {
    v * 12.92
  } else {
    1.055 * v.powf(1.0 / 2.4) - 0.055
  }
}

fn linear_srgb_to_oklab(r: f32, g: f32, b: f32) -> (f32, f32, f32) {
  let l = 0.412_221_46 * r + 0.536_332_54 * g + 0.051_445_996 * b;
  let m = 0.211_903_5 * r + 0.680_699_5 * g + 0.107_396_96 * b;
  let s = 0.088_302_46 * r + 0.281_718_85 * g + 0.629_978_7 * b;

  let l_ = l.cbrt();
  let m_ = m.cbrt();
  let s_ = s.cbrt();

  let l_ok = 0.210_454_26 * l_ + 0.793_617_8 * m_ - 0.004_072_047 * s_;
  let a_ok = 1.977_998_5 * l_ - 2.428_592_2 * m_ + 0.450_593_7 * s_;
  let b_ok = 0.025_904_037 * l_ + 0.782_771_77 * m_ - 0.808_675_77 * s_;
  (l_ok, a_ok, b_ok)
}

fn oklab_to_linear_srgb(l: f32, a: f32, b: f32) -> (f32, f32, f32) {
  let l_ = l + 0.396_337_78 * a + 0.215_803_76 * b;
  let m_ = l - 0.105_561_35 * a - 0.063_854_17 * b;
  let s_ = l - 0.089_484_18 * a - 1.291_485_5 * b;

  let l3 = l_.powf(3.0);
  let m3 = m_.powf(3.0);
  let s3 = s_.powf(3.0);

  let r = 4.076_741_7 * l3 - 3.307_711_6 * m3 + 0.230_969_94 * s3;
  let g = -1.268_438_ * l3 + 2.609_757_4 * m3 - 0.341_319_38 * s3;
  let b = 0.004_421_97 * l3 - 0.703_418_6 * m3 + 1.698_594_8 * s3;
  (r, g, b)
}

fn rgb_to_oklch(r: f32, g: f32, b: f32) -> (f32, f32, f32) {
  let (l, a, bb) = linear_srgb_to_oklab(srgb_to_linear(r), srgb_to_linear(g), srgb_to_linear(b));
  let c = (a * a + bb * bb).sqrt();
  let h = bb.atan2(a).to_degrees().rem_euclid(360.0);
  (l, c, h)
}

fn oklch_to_rgb(l: f32, c: f32, h: f32) -> (f32, f32, f32) {
  let hr = h.to_radians();
  let a = c * hr.cos();
  let b = c * hr.sin();
  let (r_lin, g_lin, b_lin) = oklab_to_linear_srgb(l, a, b);
  (
    linear_to_srgb(r_lin).clamp(0.0, 1.0),
    linear_to_srgb(g_lin).clamp(0.0, 1.0),
    linear_to_srgb(b_lin).clamp(0.0, 1.0),
  )
}

fn is_manual_blend(mode: BlendMode) -> bool {
  matches!(
    mode,
    BlendMode::Hue
      | BlendMode::Saturation
      | BlendMode::Color
      | BlendMode::Luminosity
      | BlendMode::HueHsv
      | BlendMode::SaturationHsv
      | BlendMode::ColorHsv
      | BlendMode::LuminosityHsv
      | BlendMode::HueOklch
      | BlendMode::ChromaOklch
      | BlendMode::ColorOklch
      | BlendMode::LuminosityOklch
      | BlendMode::PlusDarker
  )
}

fn apply_manual_blend(
  mode: BlendMode,
  src: (f32, f32, f32),
  dst: (f32, f32, f32),
) -> (f32, f32, f32) {
  match mode {
    BlendMode::Hue | BlendMode::Saturation | BlendMode::Color | BlendMode::Luminosity => {
      let (sh, ss, sl) = rgb_to_hsl(src.0, src.1, src.2);
      let (dh, ds, dl) = rgb_to_hsl(dst.0, dst.1, dst.2);
      match mode {
        BlendMode::Hue => hsl_to_rgb(sh, ds, dl),
        BlendMode::Saturation => hsl_to_rgb(dh, ss, dl),
        BlendMode::Color => hsl_to_rgb(sh, ss, dl),
        BlendMode::Luminosity => hsl_to_rgb(dh, ds, sl),
        _ => dst,
      }
    }
    BlendMode::HueHsv
    | BlendMode::SaturationHsv
    | BlendMode::ColorHsv
    | BlendMode::LuminosityHsv => {
      let (sh, ss, sv) = rgb_to_hsv(src.0, src.1, src.2);
      let (dh, ds, dv) = rgb_to_hsv(dst.0, dst.1, dst.2);
      match mode {
        BlendMode::HueHsv => hsv_to_rgb(sh, ds, dv),
        BlendMode::SaturationHsv => hsv_to_rgb(dh, ss, dv),
        BlendMode::ColorHsv => hsv_to_rgb(sh, ss, dv),
        BlendMode::LuminosityHsv => hsv_to_rgb(dh, ds, sv),
        _ => dst,
      }
    }
    BlendMode::HueOklch
    | BlendMode::ChromaOklch
    | BlendMode::ColorOklch
    | BlendMode::LuminosityOklch => {
      let (sl, sc, sh) = rgb_to_oklch(src.0, src.1, src.2);
      let (dl, dc, dh) = rgb_to_oklch(dst.0, dst.1, dst.2);
      match mode {
        BlendMode::HueOklch => oklch_to_rgb(dl, dc, sh),
        BlendMode::ChromaOklch => oklch_to_rgb(dl, sc, dh),
        BlendMode::ColorOklch => oklch_to_rgb(dl, sc, sh),
        BlendMode::LuminosityOklch => oklch_to_rgb(sl, dc, dh),
        _ => dst,
      }
    }
    BlendMode::PlusDarker => (
      (src.0 + dst.0 - 1.0).max(0.0).min(1.0),
      (src.1 + dst.1 - 1.0).max(0.0).min(1.0),
      (src.2 + dst.2 - 1.0).max(0.0).min(1.0),
    ),
    _ => dst,
  }
}

#[inline]
fn mul_div_255_round_u16(a: u16, b: u16) -> u16 {
  // Exact rounding division by 255 for u8 products.
  //
  // This implements `round((a * b) / 255)` for `a, b ∈ [0, 255]` using only
  // multiplies/shifts. The intermediate range fits in u32.
  let prod = (a as u32) * (b as u32);
  (((prod + 128) * 257) >> 16) as u16
}

#[inline]
fn clamp01(value: f32) -> f32 {
  value.clamp(0.0, 1.0)
}

fn runtime_flag(name: &str) -> bool {
  crate::debug::runtime::runtime_toggles().truthy(name)
}

#[inline]
fn deterministic_paint_enabled() -> bool {
  cfg!(test) || runtime_flag("FASTR_DETERMINISTIC_PAINT")
}

fn runtime_bool_override(name: &str) -> Option<bool> {
  let toggles = crate::debug::runtime::runtime_toggles();
  let raw = toggles.get(name)?;
  if raw.trim().eq_ignore_ascii_case("auto") {
    return None;
  }
  Some(toggles.truthy(name))
}

fn projective_warp_enabled() -> bool {
  let toggles = crate::debug::runtime::runtime_toggles();
  let warp_enabled = cfg!(feature = "preserve3d_warp") || toggles.truthy("FASTR_PRESERVE3D_WARP");
  warp_enabled && !toggles.truthy("FASTR_PRESERVE3D_DISABLE_WARP")
}

static INV_U8_TO_F32: OnceLock<[f32; 256]> = OnceLock::new();

/// Composite `layer` into `target` using manual mix-blend-mode evaluation.
///
/// This is used for blend modes that tiny-skia cannot represent directly (or where the CSS spec
/// differs). The inner loop is optimized for large layers: cooperative deadline checks, reduced
/// float work, and integer alpha compositing where possible.
pub fn composite_manual_layer_pixmap(
  target: &mut Pixmap,
  layer: &Pixmap,
  opacity: f32,
  mode: BlendMode,
  origin: (i32, i32),
  region: Option<&Rect>,
) -> Result<()> {
  let mut target = target.as_mut();
  composite_manual_layer_pixmap_mut(&mut target, layer, opacity, mode, origin, region)
}

pub(crate) fn composite_manual_layer_pixmap_mut(
  target: &mut PixmapMut<'_>,
  layer: &Pixmap,
  opacity: f32,
  mode: BlendMode,
  origin: (i32, i32),
  region: Option<&Rect>,
) -> Result<()> {
  let opacity = opacity.clamp(0.0, 1.0);
  if opacity == 0.0 {
    return Ok(());
  }

  let (mut x0, mut y0, mut x1, mut y1) = (
    origin.0,
    origin.1,
    origin.0 + layer.width() as i32,
    origin.1 + layer.height() as i32,
  );
  if let Some(region) = region {
    let (rx0, ry0, rx1, ry1) = rect_int_bounds(region);
    x0 = x0.max(rx0);
    y0 = y0.max(ry0);
    x1 = x1.min(rx1);
    y1 = y1.min(ry1);
  }
  x0 = x0.max(0);
  y0 = y0.max(0);
  x1 = x1
    .min(target.width() as i32)
    .min(origin.0 + layer.width() as i32);
  y1 = y1
    .min(target.height() as i32)
    .min(origin.1 + layer.height() as i32);
  if x0 >= x1 || y0 >= y1 {
    return Ok(());
  }

  let opacity_is_one = opacity == 1.0;
  let inv_u8 = INV_U8_TO_F32.get_or_init(|| {
    let mut table = [0.0f32; 256];
    for (idx, slot) in table.iter_mut().enumerate().skip(1) {
      *slot = 1.0 / idx as f32;
    }
    table
  });

  let src_pixels = layer.pixels();
  let src_stride = layer.width() as usize;
  let dst_stride = target.width() as usize;
  let dst_pixels = target.pixels_mut();

  let mut deadline_counter = 0usize;

  for y in y0..y1 {
    check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
      .map_err(Error::Render)?;

    let src_row = (y - origin.1) as usize;
    let dst_row = y as usize;
    let src_start = src_row * src_stride + (x0 - origin.0) as usize;
    let dst_start = dst_row * dst_stride + x0 as usize;
    let width = (x1 - x0) as usize;
    let src_slice = &src_pixels[src_start..src_start + width];
    let dst_slice = &mut dst_pixels[dst_start..dst_start + width];

    for (src_px, dst_px) in src_slice.iter().zip(dst_slice.iter_mut()) {
      let raw_sa_u8 = src_px.alpha();
      if raw_sa_u8 == 0 {
        continue;
      }

      // Fast-path for fully-opaque layer compositing (very common: mix-blend-mode with no parent
      // opacity).
      let sa_u16 = if opacity_is_one {
        raw_sa_u8 as u16
      } else {
        // Quantize the effective alpha to u8-space. This keeps the alpha compositing path on
        // integer arithmetic while staying visually close to the previous float pipeline.
        ((raw_sa_u8 as f32) * opacity).round().clamp(0.0, 255.0) as u16
      };
      if sa_u16 == 0 {
        continue;
      }

      let da_u16 = dst_px.alpha() as u16;

      // Unpremultiply (normalized 0..1) for the blend-mode math.
      let inv_raw_sa = inv_u8[raw_sa_u8 as usize];
      let src_rgb = (
        src_px.red() as f32 * inv_raw_sa,
        src_px.green() as f32 * inv_raw_sa,
        src_px.blue() as f32 * inv_raw_sa,
      );
      let dst_rgb = if da_u16 == 0 {
        (0.0, 0.0, 0.0)
      } else {
        let inv_da = inv_u8[da_u16 as usize];
        (
          dst_px.red() as f32 * inv_da,
          dst_px.green() as f32 * inv_da,
          dst_px.blue() as f32 * inv_da,
        )
      };

      let blended = apply_manual_blend(mode, src_rgb, dst_rgb);
      let blended_r = (clamp01(blended.0) * 255.0).round().min(255.0) as u16;
      let blended_g = (clamp01(blended.1) * 255.0).round().min(255.0) as u16;
      let blended_b = (clamp01(blended.2) * 255.0).round().min(255.0) as u16;

      let inv_sa_u16 = 255u16.saturating_sub(sa_u16);

      // Fast-path: fully-opaque effective source alpha (skip dst scaling).
      if inv_sa_u16 == 0 {
        let out_a = 255u16;
        let out_r = blended_r.min(out_a);
        let out_g = blended_g.min(out_a);
        let out_b = blended_b.min(out_a);
        *dst_px = PremultipliedColorU8::from_rgba(out_r as u8, out_g as u8, out_b as u8, 255)
          .unwrap_or(PremultipliedColorU8::TRANSPARENT);
        continue;
      }

      let out_a = if da_u16 == 0 {
        sa_u16
      } else {
        (sa_u16 + mul_div_255_round_u16(da_u16, inv_sa_u16)).min(255)
      };

      // Integer alpha compositing:
      // out = src + dst * (1 - sa)
      // where `src` is the blend-mode result premultiplied by `sa`.
      let src_r = mul_div_255_round_u16(blended_r, sa_u16);
      let src_g = mul_div_255_round_u16(blended_g, sa_u16);
      let src_b = mul_div_255_round_u16(blended_b, sa_u16);

      let (dst_r, dst_g, dst_b) = if da_u16 == 0 {
        (0u16, 0u16, 0u16)
      } else {
        (
          mul_div_255_round_u16(dst_px.red() as u16, inv_sa_u16),
          mul_div_255_round_u16(dst_px.green() as u16, inv_sa_u16),
          mul_div_255_round_u16(dst_px.blue() as u16, inv_sa_u16),
        )
      };

      let out_r = (src_r + dst_r).min(out_a);
      let out_g = (src_g + dst_g).min(out_a);
      let out_b = (src_b + dst_b).min(out_a);

      *dst_px = PremultipliedColorU8::from_rgba(out_r as u8, out_g as u8, out_b as u8, out_a as u8)
        .unwrap_or(PremultipliedColorU8::TRANSPARENT);
    }
  }

  Ok(())
}

#[derive(Copy, Clone)]
enum EdgeOrientation {
  Horizontal,
  Vertical,
}

#[derive(Copy, Clone)]
enum BorderEdge {
  Top,
  Right,
  Bottom,
  Left,
}

impl BorderEdge {
  fn orientation(self) -> EdgeOrientation {
    match self {
      BorderEdge::Top | BorderEdge::Bottom => EdgeOrientation::Horizontal,
      BorderEdge::Left | BorderEdge::Right => EdgeOrientation::Vertical,
    }
  }

  fn parallel_lines(
    &self,
    x1: f32,
    y1: f32,
    x2: f32,
    y2: f32,
    offset: f32,
  ) -> (Option<tiny_skia::Path>, Option<tiny_skia::Path>) {
    match self.orientation() {
      EdgeOrientation::Horizontal => {
        let mut first = PathBuilder::new();
        first.move_to(x1, y1 - offset);
        first.line_to(x2, y2 - offset);

        let mut second = PathBuilder::new();
        second.move_to(x1, y1 + offset);
        second.line_to(x2, y2 + offset);

        (first.finish(), second.finish())
      }
      EdgeOrientation::Vertical => {
        let mut first = PathBuilder::new();
        first.move_to(x1 - offset, y1);
        first.line_to(x2 - offset, y2);

        let mut second = PathBuilder::new();
        second.move_to(x1 + offset, y1);
        second.line_to(x2 + offset, y2);

        (first.finish(), second.finish())
      }
    }
  }

  fn groove_ridge_colors(self, base: &Rgba, style: CssBorderStyle) -> (Rgba, Rgba) {
    let lighten = |c: &Rgba| shade_color(c, 1.25);
    let darken = |c: &Rgba| shade_color(c, 0.75);

    let (first_light, second_light) = match style {
      CssBorderStyle::Groove => (false, true),
      CssBorderStyle::Ridge => (true, false),
      _ => (false, false),
    };

    let (first, second) = match self {
      BorderEdge::Top | BorderEdge::Left => (first_light, second_light),
      BorderEdge::Right | BorderEdge::Bottom => (!first_light, !second_light),
    };

    (
      if first { lighten(base) } else { darken(base) },
      if second { lighten(base) } else { darken(base) },
    )
  }

  fn inset_outset_color(self, base: &Rgba, style: CssBorderStyle) -> Rgba {
    match style {
      CssBorderStyle::Inset => match self {
        BorderEdge::Top | BorderEdge::Left => shade_color(base, 0.75),
        BorderEdge::Right | BorderEdge::Bottom => shade_color(base, 1.25),
      },
      CssBorderStyle::Outset => match self {
        BorderEdge::Top | BorderEdge::Left => shade_color(base, 1.25),
        BorderEdge::Right | BorderEdge::Bottom => shade_color(base, 0.75),
      },
      _ => *base,
    }
  }
}

fn set_paint_color(paint: &mut tiny_skia::Paint, color: &Rgba, opacity: f32) {
  let alpha = (color.a * opacity * 255.0).round().clamp(0.0, 255.0) as u8;
  paint.set_color_rgba8(color.r, color.g, color.b, alpha);
}

type RenderResult<T> = std::result::Result<T, RenderError>;

fn apply_filters(
  pixmap: &mut Pixmap,
  filters: &[ResolvedFilter],
  scale: f32,
  bbox: Rect,
  svg_inputs: crate::paint::svg_filter::SvgFilterStandardInputs,
  mut cache: Option<&mut (dyn BlurCacheOps + 'static)>,
) -> RenderResult<()> {
  for filter in filters {
    match filter {
      ResolvedFilter::Blur(radius) => apply_gaussian_blur_cached(
        pixmap,
        *radius * scale,
        *radius * scale,
        cache.as_deref_mut(),
        scale,
      )?,
      ResolvedFilter::Brightness(amount) => {
        crate::paint::css_filter::apply_color_filter(pixmap, |c, a| {
          (crate::paint::css_filter::scale_color(c, *amount), a)
        })?
      }
      ResolvedFilter::Contrast(amount) => {
        crate::paint::css_filter::apply_color_filter(pixmap, |c, a| {
          (crate::paint::css_filter::apply_contrast(c, *amount), a)
        })?
      }
      ResolvedFilter::Grayscale(amount) => {
        crate::paint::css_filter::apply_color_filter(pixmap, |c, a| {
          (crate::paint::css_filter::grayscale(c, *amount), a)
        })?
      }
      ResolvedFilter::Sepia(amount) => {
        crate::paint::css_filter::apply_color_filter(pixmap, |c, a| {
          (crate::paint::css_filter::sepia(c, *amount), a)
        })?
      }
      ResolvedFilter::Saturate(amount) => {
        crate::paint::css_filter::apply_color_filter(pixmap, |c, a| {
          (crate::paint::css_filter::saturate(c, *amount), a)
        })?
      }
      ResolvedFilter::HueRotate(deg) => {
        crate::paint::css_filter::apply_color_filter(pixmap, |c, a| {
          (crate::paint::css_filter::hue_rotate(c, *deg), a)
        })?
      }
      ResolvedFilter::Invert(amount) => {
        crate::paint::css_filter::apply_color_filter(pixmap, |c, a| {
          (crate::paint::css_filter::invert(c, *amount), a)
        })?
      }
      ResolvedFilter::Opacity(amount) => {
        crate::paint::css_filter::apply_color_filter(pixmap, |c, a| (c, a * *amount))?
      }
      ResolvedFilter::DropShadow {
        offset_x,
        offset_y,
        blur_radius,
        spread,
        color,
      } => apply_drop_shadow(
        pixmap,
        offset_x * scale,
        offset_y * scale,
        blur_radius * scale,
        spread * scale,
        *color,
        cache.as_deref_mut(),
      )?,
      ResolvedFilter::SvgFilter(ref filter) => {
        crate::paint::svg_filter::apply_svg_filter_with_cache(
          filter.as_ref(),
          pixmap,
          scale,
          bbox,
          svg_inputs,
          cache.as_deref_mut(),
        )?;
      }
    }
  }
  Ok(())
}

#[inline]
fn transform_vector_by_skia(transform: Transform, x: f32, y: f32) -> (f32, f32) {
  (
    x * transform.sx + y * transform.kx,
    x * transform.ky + y * transform.sy,
  )
}

#[inline]
fn transform_max_axis_scale(transform: Transform) -> f32 {
  // Compute the magnitudes of the transformed basis vectors. This is used to scale isotropic
  // filter lengths (blur radius, shadow spread) when converting filter parameters from the
  // element's local coordinate system into the pixmap coordinate system the filter is actually
  // executed in.
  //
  // This is exact for rotation + uniform scaling, and conservative for skew/non-uniform scaling.
  let sx = (transform.sx * transform.sx + transform.ky * transform.ky).sqrt();
  let sy = (transform.kx * transform.kx + transform.sy * transform.sy).sqrt();
  let scale = sx.max(sy);
  if scale.is_finite() && scale > 0.0 {
    scale
  } else {
    1.0
  }
}

fn transform_filters_for_pixmap_space(
  filters: &[ResolvedFilter],
  local_to_pixmap: Transform,
) -> Vec<ResolvedFilter> {
  if filters.is_empty() {
    return Vec::new();
  }

  // CSS Filter Effects: filter operations are specified in the element's local coordinate system,
  // but in this renderer we execute them on rasterized pixmaps that have already had the current
  // canvas transform applied.
  //
  // For non-translation transforms (rotation/scale/skew), geometric filter parameters must be
  // converted into the pixmap coordinate space so results match the spec and browser behavior
  // (e.g. `drop-shadow(dx,dy)` offsets rotate with transforms).
  //
  // Spec reference: Filter Effects Level 1, "The filter operations are applied in the element's
  // local coordinate system." (<https://drafts.fxtf.org/filter-effects-1/#FilterProperty>)
  let scale = transform_max_axis_scale(local_to_pixmap);

  filters
    .iter()
    .map(|filter| match *filter {
      ResolvedFilter::Blur(radius) => ResolvedFilter::Blur(radius * scale),
      ResolvedFilter::DropShadow {
        offset_x,
        offset_y,
        blur_radius,
        spread,
        color,
      } => {
        let (dx, dy) = transform_vector_by_skia(local_to_pixmap, offset_x, offset_y);
        ResolvedFilter::DropShadow {
          offset_x: dx,
          offset_y: dy,
          blur_radius: blur_radius * scale,
          spread: spread * scale,
          color,
        }
      }
      ResolvedFilter::Brightness(amount) => ResolvedFilter::Brightness(amount),
      ResolvedFilter::Contrast(amount) => ResolvedFilter::Contrast(amount),
      ResolvedFilter::Grayscale(amount) => ResolvedFilter::Grayscale(amount),
      ResolvedFilter::Sepia(amount) => ResolvedFilter::Sepia(amount),
      ResolvedFilter::Saturate(amount) => ResolvedFilter::Saturate(amount),
      ResolvedFilter::HueRotate(deg) => ResolvedFilter::HueRotate(deg),
      ResolvedFilter::Invert(amount) => ResolvedFilter::Invert(amount),
      ResolvedFilter::Opacity(amount) => ResolvedFilter::Opacity(amount),
      ResolvedFilter::SvgFilter(ref filter) => ResolvedFilter::SvgFilter(Arc::clone(filter)),
    })
    .collect()
}

fn apply_filters_scoped(
  pixmap: &mut Pixmap,
  filters: &[ResolvedFilter],
  scale: f32,
  bbox: Rect,
  bounds: Option<&Rect>,
  cache: Option<&mut (dyn BlurCacheOps + 'static)>,
  backdrop: Option<tiny_skia::PixmapRef<'_>>,
  backdrop_origin: (i32, i32),
) -> RenderResult<()> {
  if filters.is_empty() {
    return Ok(());
  }
  check_active(RenderStage::Paint)?;

  let needs_background = backdrop.is_some()
    && filters.iter().any(|filter| match filter {
      ResolvedFilter::SvgFilter(filter) => filter.uses_background_inputs(),
      _ => false,
    });

  // If there is no bounding region, or if the bounds cover the full pixmap, apply filters in-place.
  if bounds.is_none() {
    return apply_filters_with_optional_svg_backdrop(
      pixmap,
      filters,
      scale,
      bbox,
      cache,
      needs_background.then_some(backdrop).flatten(),
      backdrop_origin,
    );
  }

  let bounds = bounds.unwrap();
  let x = bounds.min_x().floor() as i32;
  let y = bounds.min_y().floor() as i32;
  let width = bounds.width().ceil() as u32;
  let height = bounds.height().ceil() as u32;
  if width == 0 || height == 0 {
    return Ok(());
  }

  let pix_w = pixmap.width() as i32;
  let pix_h = pixmap.height() as i32;
  if x >= pix_w || y >= pix_h {
    return Ok(());
  }

  let clamped_x = x.max(0) as u32;
  let clamped_y = y.max(0) as u32;
  let max_w = pix_w.saturating_sub(clamped_x as i32).max(0) as u32;
  let max_h = pix_h.saturating_sub(clamped_y as i32).max(0) as u32;
  let region_w = width.min(max_w);
  let region_h = height.min(max_h);
  if region_w == 0 || region_h == 0 {
    return Ok(());
  }

  if region_w == pixmap.width() && region_h == pixmap.height() && clamped_x == 0 && clamped_y == 0 {
    return apply_filters_with_optional_svg_backdrop(
      pixmap,
      filters,
      scale,
      bbox,
      cache,
      needs_background.then_some(backdrop).flatten(),
      backdrop_origin,
    );
  }

  let mut scratch = BACKDROP_FILTER_SCRATCH.with(|cell| std::mem::take(&mut *cell.borrow_mut()));
  let mut region = match scratch.region.take() {
    Some(existing) if existing.width() == region_w && existing.height() == region_h => existing,
    _ => match new_pixmap(region_w, region_h) {
      Some(p) => p,
      None => {
        BACKDROP_FILTER_SCRATCH.with(|cell| {
          *cell.borrow_mut() = scratch;
        });
        return apply_filters_with_optional_svg_backdrop(
          pixmap,
          filters,
          scale,
          bbox,
          cache,
          needs_background.then_some(backdrop).flatten(),
          backdrop_origin,
        );
      }
    },
  };

  // Copy the pixels that are being filtered into a compact scratch pixmap.
  let bytes_per_row = pixmap.width() as usize * 4;
  let region_row_bytes = region_w as usize * 4;
  debug_assert_eq!(
    region.data().len(),
    region_row_bytes.saturating_mul(region_h as usize),
    "expected scratch region pixmap to be tightly packed"
  );
  let start = (clamped_y as usize * bytes_per_row) + clamped_x as usize * 4;

  let copy_in = (|| -> RenderResult<()> {
    let data = pixmap.data();
    let dest = region.data_mut();
    let mut deadline_counter = 0usize;
    for row in 0..region_h as usize {
      check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
      let src_idx = start + row * bytes_per_row;
      let dst_idx = row * region_row_bytes;
      dest[dst_idx..dst_idx + region_row_bytes]
        .copy_from_slice(&data[src_idx..src_idx + region_row_bytes]);
    }
    Ok(())
  })();
  if let Err(err) = copy_in {
    scratch.region = Some(region);
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Err(err);
  }

  // Snapshot the already-composited backdrop behind this region if any SVG filter needs it.
  let mut svg_backdrop_pixmap: Option<Pixmap> = None;
  if needs_background {
    if let Some(backdrop) = backdrop {
      let backdrop_pixmap = match scratch.svg_backdrop.take() {
        Some(existing) if existing.width() == region_w && existing.height() == region_h => {
          Some(existing)
        }
        other => {
          scratch.svg_backdrop = other;
          new_pixmap(region_w, region_h)
        }
      };

      if let Some(mut backdrop_pixmap) = backdrop_pixmap {
        let src_x = backdrop_origin.0.saturating_add(clamped_x as i32);
        let src_y = backdrop_origin.1.saturating_add(clamped_y as i32);
        if let Err(err) = copy_pixmap_region_with_offset(&mut backdrop_pixmap, backdrop, src_x, src_y)
        {
          scratch.region = Some(region);
          scratch.svg_backdrop = Some(backdrop_pixmap);
          BACKDROP_FILTER_SCRATCH.with(|cell| {
            *cell.borrow_mut() = scratch;
          });
          return Err(err);
        }
        svg_backdrop_pixmap = Some(backdrop_pixmap);
      }
    }
  }

  let local_bbox = Rect::from_xywh(
    bbox.x() - clamped_x as f32,
    bbox.y() - clamped_y as f32,
    bbox.width(),
    bbox.height(),
  );
  let svg_inputs = crate::paint::svg_filter::SvgFilterStandardInputs {
    background_image: svg_backdrop_pixmap.as_ref(),
    ..Default::default()
  };

  if let Err(err) = apply_filters(&mut region, filters, scale, local_bbox, svg_inputs, cache) {
    scratch.region = Some(region);
    if let Some(backdrop_pixmap) = svg_backdrop_pixmap {
      scratch.svg_backdrop = Some(backdrop_pixmap);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Err(err);
  }

  let copy_out = (|| -> RenderResult<()> {
    let mut deadline_counter = 0usize;
    for row in 0..region_h as usize {
      check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
      let dst_idx = (clamped_y as usize + row) * bytes_per_row + clamped_x as usize * 4;
      let src_idx = row * region_row_bytes;
      let src = &region.data()[src_idx..src_idx + region_row_bytes];
      let dst = &mut pixmap.data_mut()[dst_idx..dst_idx + region_row_bytes];
      dst.copy_from_slice(src);
    }
    Ok(())
  })();
  if let Err(err) = copy_out {
    scratch.region = Some(region);
    if let Some(backdrop_pixmap) = svg_backdrop_pixmap {
      scratch.svg_backdrop = Some(backdrop_pixmap);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Err(err);
  }

  scratch.region = Some(region);
  if let Some(backdrop_pixmap) = svg_backdrop_pixmap {
    scratch.svg_backdrop = Some(backdrop_pixmap);
  }
  BACKDROP_FILTER_SCRATCH.with(|cell| {
    *cell.borrow_mut() = scratch;
  });
  Ok(())
}

fn apply_filters_with_optional_svg_backdrop(
  pixmap: &mut Pixmap,
  filters: &[ResolvedFilter],
  scale: f32,
  bbox: Rect,
  cache: Option<&mut (dyn BlurCacheOps + 'static)>,
  backdrop: Option<tiny_skia::PixmapRef<'_>>,
  backdrop_origin: (i32, i32),
) -> RenderResult<()> {
  let Some(backdrop) = backdrop else {
    return apply_filters(
      pixmap,
      filters,
      scale,
      bbox,
      crate::paint::svg_filter::SvgFilterStandardInputs::default(),
      cache,
    );
  };

  let mut scratch = BACKDROP_FILTER_SCRATCH.with(|cell| std::mem::take(&mut *cell.borrow_mut()));
  let mut backdrop_pixmap = match scratch.svg_backdrop.take() {
    Some(existing)
      if existing.width() == pixmap.width() && existing.height() == pixmap.height() =>
    {
      existing
    }
    _ => match new_pixmap(pixmap.width(), pixmap.height()) {
      Some(p) => p,
      None => {
        BACKDROP_FILTER_SCRATCH.with(|cell| {
          *cell.borrow_mut() = scratch;
        });
        return apply_filters(
          pixmap,
          filters,
          scale,
          bbox,
          crate::paint::svg_filter::SvgFilterStandardInputs::default(),
          cache,
        );
      }
    },
  };

  let result = copy_pixmap_region_with_offset(
    &mut backdrop_pixmap,
    backdrop,
    backdrop_origin.0,
    backdrop_origin.1,
  )
  .and_then(|()| {
    let svg_inputs = crate::paint::svg_filter::SvgFilterStandardInputs {
      background_image: Some(&backdrop_pixmap),
      ..Default::default()
    };
    apply_filters(pixmap, filters, scale, bbox, svg_inputs, cache)
  });

  scratch.svg_backdrop = Some(backdrop_pixmap);
  BACKDROP_FILTER_SCRATCH.with(|cell| {
    *cell.borrow_mut() = scratch;
  });
  result
}

fn copy_pixmap_region_with_offset(
  dst: &mut Pixmap,
  src: tiny_skia::PixmapRef<'_>,
  src_x: i32,
  src_y: i32,
) -> RenderResult<()> {
  let dst_w = dst.width() as i32;
  let dst_h = dst.height() as i32;
  if dst_w <= 0 || dst_h <= 0 {
    return Ok(());
  }
  let dst_stride = dst_w as usize * 4;
  let dst_data = dst.data_mut();
  dst_data.fill(0);

  let src_w = src.width() as i32;
  let src_h = src.height() as i32;
  if src_w <= 0 || src_h <= 0 {
    return Ok(());
  }

  let x0 = src_x.max(0);
  let y0 = src_y.max(0);
  let x1 = (src_x + dst_w).min(src_w);
  let y1 = (src_y + dst_h).min(src_h);
  if x0 >= x1 || y0 >= y1 {
    return Ok(());
  }

  let dst_off_x = (x0 - src_x) as usize;
  let dst_off_y = (y0 - src_y) as usize;
  let copy_w = (x1 - x0) as usize;
  let copy_h = (y1 - y0) as usize;

  let src_stride = src.width() as usize * 4;
  let row_bytes = copy_w * 4;
  let src_data = src.data();

  let mut deadline_counter = 0usize;
  for row in 0..copy_h {
    check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
    let src_idx = (y0 as usize + row) * src_stride + x0 as usize * 4;
    let dst_idx = (dst_off_y + row) * dst_stride + dst_off_x * 4;
    dst_data[dst_idx..dst_idx + row_bytes].copy_from_slice(&src_data[src_idx..src_idx + row_bytes]);
  }
  Ok(())
}
fn apply_backdrop_filters_with_region_filler<F>(
  dest: &mut Pixmap,
  src_size: (u32, u32),
  dest_origin_in_src: (i32, i32),
  bounds_in_src: Rect,
  shape_bounds: Rect,
  filters: &[ResolvedFilter],
  radii: BorderRadii,
  scale: f32,
  clip_mask: Option<&Mask>,
  clip_bounds: Option<Rect>,
  clip_origin: (i32, i32),
  filter_bounds: Rect,
  world_to_dest: Transform,
  blur_cache: Option<&mut (dyn BlurCacheOps + 'static)>,
  backdrop_cache: Option<&mut (dyn BackdropFilterCacheOps + 'static)>,
  fill_region: F,
  projective_backdrop: Option<ProjectiveBackdropFilterContext>,
  post_filter_path: Option<&tiny_skia::Path>,
) -> RenderResult<()>
where
  F: FnOnce(&mut Pixmap, u32, u32) -> RenderResult<()>,
{
  if filters.is_empty() {
    return Ok(());
  }
  check_active(RenderStage::Paint)?;

  let x0_f = bounds_in_src.min_x().floor();
  let y0_f = bounds_in_src.min_y().floor();
  let x1_f = bounds_in_src.max_x().ceil();
  let y1_f = bounds_in_src.max_y().ceil();
  if !(x0_f.is_finite() && y0_f.is_finite() && x1_f.is_finite() && y1_f.is_finite()) {
    return Ok(());
  }

  let x0 = x0_f as i64;
  let y0 = y0_f as i64;
  let x1 = x1_f as i64;
  let y1 = y1_f as i64;
  if x0 >= x1 || y0 >= y1 {
    return Ok(());
  }

  let src_w = i64::from(src_size.0);
  let src_h = i64::from(src_size.1);
  if src_w <= 0 || src_h <= 0 {
    return Ok(());
  }

  let sample_x0 = x0.max(0).min(src_w);
  let sample_y0 = y0.max(0).min(src_h);
  let sample_x1 = x1.max(0).min(src_w);
  let sample_y1 = y1.max(0).min(src_h);
  if sample_x0 >= sample_x1 || sample_y0 >= sample_y1 {
    return Ok(());
  }

  let clamped_x = sample_x0 as u32;
  let clamped_y = sample_y0 as u32;
  let region_w = (sample_x1 - sample_x0) as u32;
  let region_h = (sample_y1 - sample_y0) as u32;
  if region_w == 0 || region_h == 0 {
    return Ok(());
  }

  let mut scratch = BACKDROP_FILTER_SCRATCH.with(|cell| std::mem::take(&mut *cell.borrow_mut()));
  let mut region = match scratch.region.take() {
    Some(existing) if existing.width() == region_w && existing.height() == region_h => existing,
    _ => match new_pixmap(region_w, region_h) {
      Some(p) => p,
      None => {
        BACKDROP_FILTER_SCRATCH.with(|cell| {
          *cell.borrow_mut() = scratch;
        });
        return Ok(());
      }
    },
  };

  if let Err(err) = fill_region(&mut region, clamped_x, clamped_y) {
    scratch.region = Some(region);
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Err(err);
  }

  if let Some(mask) = clip_mask {
    let region_origin_dest = (
      clamped_x as i32 - dest_origin_in_src.0,
      clamped_y as i32 - dest_origin_in_src.1,
    );
    match apply_mask_with_offset(&mut region, region_origin_dest, mask, clip_origin) {
      Ok(applied) => {
        if !applied {
          scratch.region = Some(region);
          BACKDROP_FILTER_SCRATCH.with(|cell| {
            *cell.borrow_mut() = scratch;
          });
          return Ok(());
        }
      }
      Err(err) => {
        scratch.region = Some(region);
        BACKDROP_FILTER_SCRATCH.with(|cell| {
          *cell.borrow_mut() = scratch;
        });
        return Err(err);
      }
    }
  }

  let local_bbox = Rect::from_xywh(
    bounds_in_src.x() - clamped_x as f32,
    bounds_in_src.y() - clamped_y as f32,
    bounds_in_src.width(),
    bounds_in_src.height(),
  );

  let filter_hash = hash_filter_chain(filters);
  let mut cached_filtered: Option<Arc<Pixmap>> = None;
  let mut cache_key: Option<BackdropFilterCacheKey> = None;
  let mut backdrop_cache = backdrop_cache;
  if let Some(cache) = backdrop_cache.as_deref_mut() {
    if let Some(key) = BackdropFilterCacheKey::new(filter_hash, scale, local_bbox, &region) {
      if let Some(hit) = cache.get(&key) {
        cached_filtered = Some(hit);
      } else {
        cache_key = Some(key);
      }
    }
  }

  if cached_filtered.is_none() {
    let needs_svg_background = filters.iter().any(|filter| match filter {
      ResolvedFilter::SvgFilter(filter) => filter.uses_background_inputs(),
      _ => false,
    });

    // SVG filters can request `BackgroundImage` / `BackgroundAlpha`. Provide those by copying the
    // pre-filter region into a scratch pixmap so `apply_filters` has an immutable snapshot.
    let svg_backdrop_pixmap = if needs_svg_background {
      let mut backdrop_pixmap = match scratch.svg_backdrop.take() {
        Some(existing) if existing.width() == region_w && existing.height() == region_h => existing,
        _ => match new_pixmap(region_w, region_h) {
          Some(p) => p,
          None => {
            scratch.region = Some(region);
            BACKDROP_FILTER_SCRATCH.with(|cell| {
              *cell.borrow_mut() = scratch;
            });
            return Ok(());
          }
        },
      };

      let src_data = region.data();
      let dst_data = backdrop_pixmap.data_mut();
      let mut deadline_counter = 0usize;
      for (src, dst) in src_data
        .chunks_exact(CLIP_MASK_DEADLINE_STRIDE)
        .zip(dst_data.chunks_exact_mut(CLIP_MASK_DEADLINE_STRIDE))
      {
        check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
        dst.copy_from_slice(src);
      }
      let rem = src_data.len() % CLIP_MASK_DEADLINE_STRIDE;
      if rem != 0 {
        check_active(RenderStage::Paint)?;
        let start = src_data.len() - rem;
        dst_data[start..].copy_from_slice(&src_data[start..]);
      }
      Some(backdrop_pixmap)
    } else {
      None
    };

    let svg_inputs = crate::paint::svg_filter::SvgFilterStandardInputs {
      background_image: svg_backdrop_pixmap.as_ref(),
      ..Default::default()
    };

    if let Err(err) = apply_filters(
      &mut region,
      filters,
      scale,
      local_bbox,
      svg_inputs,
      blur_cache,
    ) {
      scratch.region = Some(region);
      if let Some(backdrop) = svg_backdrop_pixmap {
        scratch.svg_backdrop = Some(backdrop);
      }
      BACKDROP_FILTER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = scratch;
      });
      return Err(err);
    }
    if let (Some(cache), Some(key)) = (backdrop_cache.as_deref_mut(), cache_key.take()) {
      cache.put(key, &region);
    }
    if let Some(backdrop) = svg_backdrop_pixmap {
      scratch.svg_backdrop = Some(backdrop);
    }
  }

  let (filtered_data, filtered_width, filtered_height) =
    if let Some(cached) = cached_filtered.as_ref() {
      (
        cached.data(),
        cached.width() as usize,
        cached.height() as usize,
      )
    } else {
      (
        region.data(),
        region.width() as usize,
        region.height() as usize,
      )
    };

  // For projective stacking contexts we render the subtree into an untransformed layer and warp it
  // at PopStackingContext time. In that mode we must apply the Filter Effects Level 2 step that
  // cancels transforms between the element and the Backdrop Root: unwarp the filtered backdrop
  // into the local (pre-projective) layer so that the subsequent projective warp does not distort
  // the sampled backdrop image.
  //
  // This matches the spec's:
  //  1) filter backdrop root image in screen space
  //  2) apply inverse of transforms between B and the Backdrop Root to the filtered result
  //  3) later apply B's transform again when compositing the stacking context
  if let Some(projective) = projective_backdrop {
    let filtered_pixmap = cached_filtered
      .as_ref()
      .map(|p| p.as_ref())
      .unwrap_or(&region);
    let corners = [
      (filter_bounds.min_x(), filter_bounds.min_y()),
      (filter_bounds.max_x(), filter_bounds.min_y()),
      (filter_bounds.max_x(), filter_bounds.max_y()),
      (filter_bounds.min_x(), filter_bounds.max_y()),
    ];

    let mut dst_quad_points = [Point::ZERO; 4];
    let mut dst_quad = [(0.0f32, 0.0f32); 4];
    let mut src_quad = [Point::ZERO; 4];
    let mut valid = true;

    for (i, (x, y)) in corners.iter().enumerate() {
      let sx = *x * scale;
      let sy = *y * scale;
      // The backdrop filter output is written into the current offscreen layer, which may have an
      // affine pre-transform applied (e.g. `projective_warp_pre_transform`). Use the active canvas
      // transform (`world_to_dest`) to map world-space filter bounds into the layer's coordinate
      // system so the subsequent PopStackingContext projective warp cancels out correctly.
      let local_x = sx * world_to_dest.sx + sy * world_to_dest.kx + world_to_dest.tx;
      let local_y = sx * world_to_dest.ky + sy * world_to_dest.sy + world_to_dest.ty;
      dst_quad_points[i] = Point::new(local_x, local_y);
      dst_quad[i] = (local_x, local_y);

      let (tx, ty, _tz, tw) = projective.transform.transform_point(*x, *y, 0.0);
      if !tw.is_finite() || tw.abs() < 1e-6 || tw < 0.0 || !tx.is_finite() || !ty.is_finite() {
        valid = false;
        break;
      }
      let px = (tx / tw) * scale;
      let py = (ty / tw) * scale;
      let screen_x = px * projective.parent_transform.sx
        + py * projective.parent_transform.kx
        + projective.parent_transform.tx;
      let screen_y = px * projective.parent_transform.ky
        + py * projective.parent_transform.sy
        + projective.parent_transform.ty;
      if !screen_x.is_finite() || !screen_y.is_finite() {
        valid = false;
        break;
      }
      src_quad[i] = Point::new(screen_x - clamped_x as f32, screen_y - clamped_y as f32);
    }

    if valid {
      if let Some(homography) = Homography::from_quad_to_quad(src_quad, dst_quad_points) {
        // Warp the filtered backdrop (in source-region coordinates) into the local stacking-context
        // layer so that the later projective warp cancels out, keeping backdrop sampling screen-
        // aligned.
        //
        // Clipping (border radii, clips) is applied *after* the warp so we can avoid allocating a
        // full-destination-sized mask for the warp operation.
        match crate::paint::projective_warp::warp_pixmap(
          filtered_pixmap,
          &homography,
          &dst_quad,
          (dest.width(), dest.height()),
          None,
        ) {
          Ok(Some(mut warped)) => {
            if let Some(clip) = clip_bounds {
              let clip = if clip_origin.0 != 0 || clip_origin.1 != 0 {
                Rect::from_xywh(
                  clip.x() + clip_origin.0 as f32,
                  clip.y() + clip_origin.1 as f32,
                  clip.width(),
                  clip.height(),
                )
              } else {
                clip
              };
              if let Err(err) = hard_clip_pixmap_outside_rect_rgba(
                &mut warped.pixmap,
                Rect::from_xywh(
                  clip.x() - warped.offset.0 as f32,
                  clip.y() - warped.offset.1 as f32,
                  clip.width(),
                  clip.height(),
                ),
              ) {
                scratch.region = Some(region);
                BACKDROP_FILTER_SCRATCH.with(|cell| {
                  *cell.borrow_mut() = scratch;
                });
                return Err(err);
              }
            }

            if let Some(mask) = clip_mask {
              match apply_mask_with_offset(&mut warped.pixmap, warped.offset, mask, clip_origin) {
                Ok(applied) => {
                  if !applied {
                    scratch.region = Some(region);
                    BACKDROP_FILTER_SCRATCH.with(|cell| {
                      *cell.borrow_mut() = scratch;
                    });
                    return Ok(());
                  }
                }
                Err(err) => {
                  scratch.region = Some(region);
                  BACKDROP_FILTER_SCRATCH.with(|cell| {
                    *cell.borrow_mut() = scratch;
                  });
                  return Err(err);
                }
              }
            }

            let needs_shape_mask = !radii.is_zero()
              || world_to_dest.kx != 0.0
              || world_to_dest.ky != 0.0
              || world_to_dest.tx.fract().abs() > 1e-6
              || world_to_dest.ty.fract().abs() > 1e-6
              || shape_bounds.x().fract().abs() > 1e-6
              || shape_bounds.y().fract().abs() > 1e-6
              || shape_bounds.width().fract().abs() > 1e-6
              || shape_bounds.height().fract().abs() > 1e-6;

            if needs_shape_mask {
              let mut mask = match scratch.radii_mask.take() {
                Some(existing)
                  if existing.width() == warped.pixmap.width()
                    && existing.height() == warped.pixmap.height() =>
                {
                  existing
                }
                _ => match Mask::new(warped.pixmap.width(), warped.pixmap.height()) {
                  Some(m) => m,
                  None => {
                    scratch.region = Some(region);
                    BACKDROP_FILTER_SCRATCH.with(|cell| {
                      *cell.borrow_mut() = scratch;
                    });
                    return Ok(());
                  }
                },
              };
              if let Err(err) = check_active(RenderStage::Paint) {
                scratch.region = Some(region);
                scratch.radii_mask = Some(mask);
                BACKDROP_FILTER_SCRATCH.with(|cell| {
                  *cell.borrow_mut() = scratch;
                });
                return Err(err);
              }
              mask.data_mut().fill(0);

              let Some(path) = crate::paint::rasterize::build_rounded_rect_path(
                shape_bounds.x(),
                shape_bounds.y(),
                shape_bounds.width(),
                shape_bounds.height(),
                &radii,
              ) else {
                scratch.region = Some(region);
                scratch.radii_mask = Some(mask);
                BACKDROP_FILTER_SCRATCH.with(|cell| {
                  *cell.borrow_mut() = scratch;
                });
                return Ok(());
              };

              let world_to_warped = concat_transforms(
                Transform::from_translate(-(warped.offset.0 as f32), -(warped.offset.1 as f32)),
                world_to_dest,
              );
              // `projective_warp::warp_pixmap` uses a hard inside/outside test for the destination
              // quad (no coverage antialiasing). Match that behavior here so the clipped backdrop
              // output does not pick up semi-transparent edge pixels that would then blend with the
              // already-painted backdrop.
              mask.fill_path(&path, tiny_skia::FillRule::Winding, false, world_to_warped);

              if active_deadline().as_ref().map_or(false, |d| d.is_enabled()) {
                let pix_w = warped.pixmap.width();
                let pix_h = warped.pixmap.height();
                if let Err(err) = apply_mask_rect_rgba(
                  &mut warped.pixmap,
                  &mask,
                  ClipMaskDirtyRect {
                    x0: 0,
                    y0: 0,
                    x1: pix_w,
                    y1: pix_h,
                  },
                ) {
                  scratch.region = Some(region);
                  scratch.radii_mask = Some(mask);
                  BACKDROP_FILTER_SCRATCH.with(|cell| {
                    *cell.borrow_mut() = scratch;
                  });
                  return Err(err);
                }
              } else {
                warped.pixmap.apply_mask(&mask);
              }
              scratch.radii_mask = Some(mask);
            }

            let mut paint = PixmapPaint::default();
            paint.opacity = 1.0;
            paint.quality = tiny_skia::FilterQuality::Nearest;
            paint.blend_mode = SkiaBlendMode::SourceOver;
            dest.draw_pixmap(
              warped.offset.0,
              warped.offset.1,
              warped.pixmap.as_ref(),
              &paint,
              Transform::identity(),
              None,
            );

            scratch.region = Some(region);
            BACKDROP_FILTER_SCRATCH.with(|cell| {
              *cell.borrow_mut() = scratch;
            });
            return Ok(());
          }
          Ok(None) => {}
          Err(err) => {
            scratch.region = Some(region);
            BACKDROP_FILTER_SCRATCH.with(|cell| {
              *cell.borrow_mut() = scratch;
            });
            return Err(err);
          }
        }
      }
    }
  }

  let needs_shape_mask = !radii.is_zero()
    || world_to_dest.kx != 0.0
    || world_to_dest.ky != 0.0
    || world_to_dest.tx.fract().abs() > 1e-6
    || world_to_dest.ty.fract().abs() > 1e-6
    || shape_bounds.x().fract().abs() > 1e-6
    || shape_bounds.y().fract().abs() > 1e-6
    || shape_bounds.width().fract().abs() > 1e-6
    || shape_bounds.height().fract().abs() > 1e-6;

  let region_origin_dest_x = clamped_x as i32 - dest_origin_in_src.0;
  let region_origin_dest_y = clamped_y as i32 - dest_origin_in_src.1;
  let world_to_region = concat_transforms(
    Transform::from_translate(
      -(region_origin_dest_x as f32),
      -(region_origin_dest_y as f32),
    ),
    world_to_dest,
  );

  let radii_mask = if needs_shape_mask {
    let mut mask = match scratch.radii_mask.take() {
      Some(existing) if existing.width() == region_w && existing.height() == region_h => existing,
      _ => match Mask::new(region_w, region_h) {
        Some(m) => m,
        None => {
          scratch.region = Some(region);
          BACKDROP_FILTER_SCRATCH.with(|cell| {
            *cell.borrow_mut() = scratch;
          });
          return Ok(());
        }
      },
    };
    if let Err(err) = check_active(RenderStage::Paint) {
      scratch.region = Some(region);
      scratch.radii_mask = Some(mask);
      BACKDROP_FILTER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = scratch;
      });
      return Err(err);
    }
    mask.data_mut().fill(0);

    let Some(path) = crate::paint::rasterize::build_rounded_rect_path(
      shape_bounds.x(),
      shape_bounds.y(),
      shape_bounds.width(),
      shape_bounds.height(),
      &radii,
    ) else {
      scratch.region = Some(region);
      scratch.radii_mask = Some(mask);
      BACKDROP_FILTER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = scratch;
      });
      return Ok(());
    };
    mask.fill_path(&path, tiny_skia::FillRule::Winding, true, world_to_region);
    Some(mask)
  } else {
    None
  };

  let path_mask = if let Some(path) = post_filter_path {
    let mut mask = match scratch.path_mask.take() {
      Some(existing) if existing.width() == region_w && existing.height() == region_h => existing,
      _ => match Mask::new(region_w, region_h) {
        Some(m) => m,
        None => {
          scratch.region = Some(region);
          if let Some(mask) = radii_mask {
            scratch.radii_mask = Some(mask);
          }
          BACKDROP_FILTER_SCRATCH.with(|cell| {
            *cell.borrow_mut() = scratch;
          });
          return Ok(());
        }
      },
    };
    if let Err(err) = check_active(RenderStage::Paint) {
      scratch.region = Some(region);
      if let Some(mask) = radii_mask {
        scratch.radii_mask = Some(mask);
      }
      scratch.path_mask = Some(mask);
      BACKDROP_FILTER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = scratch;
      });
      return Err(err);
    }
    mask.data_mut().fill(0);
    mask.fill_path(path, tiny_skia::FillRule::Winding, true, world_to_region);
    Some(mask)
  } else {
    None
  };

  let bounds_in_dest = Rect::from_xywh(
    bounds_in_src.x() - dest_origin_in_src.0 as f32,
    bounds_in_src.y() - dest_origin_in_src.1 as f32,
    bounds_in_src.width(),
    bounds_in_src.height(),
  );

  let mut write_rect = bounds_in_dest;
  if let Some(clip) = clip_bounds {
    let clip = if clip_origin.0 != 0 || clip_origin.1 != 0 {
      Rect::from_xywh(
        clip.x() + clip_origin.0 as f32,
        clip.y() + clip_origin.1 as f32,
        clip.width(),
        clip.height(),
      )
    } else {
      clip
    };
    let Some(intersection) = write_rect.intersection(clip) else {
      scratch.region = Some(region);
      if let Some(mask) = radii_mask {
        scratch.radii_mask = Some(mask);
      }
      if let Some(mask) = path_mask {
        scratch.path_mask = Some(mask);
      }
      BACKDROP_FILTER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = scratch;
      });
      return Ok(());
    };
    write_rect = intersection;
  }

  // Clamp the write rectangle to the destination pixmap bounds *and* to the available filtered
  // source region. `write_x/y` are computed via `floor()` which can shift the write origin when the
  // bounds are partially outside the destination; without this clamp we can compute `src_start_*`
  // offsets that push reads beyond the mask/filtered buffers.
  let region_bounds_in_dest = Rect::from_xywh(
    clamped_x as f32 - dest_origin_in_src.0 as f32,
    clamped_y as f32 - dest_origin_in_src.1 as f32,
    region_w as f32,
    region_h as f32,
  );
  let Some(intersection) = write_rect.intersection(region_bounds_in_dest) else {
    scratch.region = Some(region);
    if let Some(mask) = radii_mask {
      scratch.radii_mask = Some(mask);
    }
    if let Some(mask) = path_mask {
      scratch.path_mask = Some(mask);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Ok(());
  };
  write_rect = intersection;

  let dest_bounds = Rect::from_xywh(0.0, 0.0, dest.width() as f32, dest.height() as f32);
  let Some(intersection) = write_rect.intersection(dest_bounds) else {
    scratch.region = Some(region);
    if let Some(mask) = radii_mask {
      scratch.radii_mask = Some(mask);
    }
    if let Some(mask) = path_mask {
      scratch.path_mask = Some(mask);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Ok(());
  };
  write_rect = intersection;

  if write_rect.width() <= 0.0 || write_rect.height() <= 0.0 {
    scratch.region = Some(region);
    if let Some(mask) = radii_mask {
      scratch.radii_mask = Some(mask);
    }
    if let Some(mask) = path_mask {
      scratch.path_mask = Some(mask);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Ok(());
  }

  let dest_w = i64::from(dest.width());
  let dest_h = i64::from(dest.height());
  if dest_w <= 0 || dest_h <= 0 {
    scratch.region = Some(region);
    if let Some(mask) = radii_mask {
      scratch.radii_mask = Some(mask);
    }
    if let Some(mask) = path_mask {
      scratch.path_mask = Some(mask);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Ok(());
  }

  // `filtered_width`/`filtered_height` are derived from the filtered pixmap we will blit into the
  // destination. Keep them in `usize` for indexing; derive `u32`/`i64` views as needed.
  let filtered_width_i64 = filtered_width as i64;
  let filtered_height_u32 = (filtered_height.min(u32::MAX as usize)) as u32;
  let filtered_height_i64 = i64::from(filtered_height_u32);

  // `bounds_in_src` can extend outside `src_size` (e.g. when a tile renderer translates the canvas
  // so some tiles see negative origins). `region` only stores the intersection that we could
  // sample from the source/backdrop root, so we must also clamp the destination write rectangle to
  // the corresponding dest-space intersection to keep pixels aligned (and avoid OOB indexing).
  let region_dest_x0 = i64::from(clamped_x).saturating_sub(i64::from(dest_origin_in_src.0));
  let region_dest_y0 = i64::from(clamped_y).saturating_sub(i64::from(dest_origin_in_src.1));
  let region_dest_x1 = region_dest_x0.saturating_add(filtered_width_i64);
  let region_dest_y1 = region_dest_y0.saturating_add(filtered_height_i64);

  let mut write_x0 = write_rect.min_x().floor() as i64;
  let mut write_y0 = write_rect.min_y().floor() as i64;
  let mut write_x1 = write_rect.max_x().ceil() as i64;
  let mut write_y1 = write_rect.max_y().ceil() as i64;

  write_x0 = write_x0.max(0).min(dest_w);
  write_y0 = write_y0.max(0).min(dest_h);
  write_x1 = write_x1.max(0).min(dest_w);
  write_y1 = write_y1.max(0).min(dest_h);

  write_x0 = write_x0.max(region_dest_x0);
  write_y0 = write_y0.max(region_dest_y0);
  write_x1 = write_x1.min(region_dest_x1);
  write_y1 = write_y1.min(region_dest_y1);

  write_x0 = write_x0.max(0).min(dest_w);
  write_y0 = write_y0.max(0).min(dest_h);
  write_x1 = write_x1.max(0).min(dest_w);
  write_y1 = write_y1.max(0).min(dest_h);

  if write_x0 >= write_x1 || write_y0 >= write_y1 {
    scratch.region = Some(region);
    if let Some(mask) = radii_mask {
      scratch.radii_mask = Some(mask);
    }
    if let Some(mask) = path_mask {
      scratch.path_mask = Some(mask);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Ok(());
  }

  let write_x = write_x0 as u32;
  let write_y = write_y0 as u32;
  let mut write_w = (write_x1 - write_x0) as u32;
  let mut write_h = (write_y1 - write_y0) as u32;
  if write_w == 0 || write_h == 0 {
    scratch.region = Some(region);
    if let Some(mask) = radii_mask {
      scratch.radii_mask = Some(mask);
    }
    if let Some(mask) = path_mask {
      scratch.path_mask = Some(mask);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Ok(());
  }

  let src_start_x = (write_x0
    .saturating_add(i64::from(dest_origin_in_src.0))
    .saturating_sub(i64::from(clamped_x)))
  .clamp(0, filtered_width_i64) as u32;
  let src_start_y = (write_y0
    .saturating_add(i64::from(dest_origin_in_src.1))
    .saturating_sub(i64::from(clamped_y)))
  .clamp(0, filtered_height_i64) as u32;

  write_w = write_w.min((filtered_width_i64 as u32).saturating_sub(src_start_x));
  write_h = write_h.min(filtered_height_u32.saturating_sub(src_start_y));
  if write_w == 0 || write_h == 0 {
    scratch.region = Some(region);
    if let Some(mask) = radii_mask {
      scratch.radii_mask = Some(mask);
    }
    if let Some(mask) = path_mask {
      scratch.path_mask = Some(mask);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Ok(());
  }

  // `bounds_in_src` can extend outside the available backdrop image (e.g. due to blur outsets or
  // off-canvas stacking-context bounds). Clamp the write region to the filtered pixmap extents so
  // mask/data indexing stays in-bounds. Pixels outside the backdrop are treated as fully clipped.
  if src_start_x as usize >= filtered_width || src_start_y >= filtered_height_u32 {
    scratch.region = Some(region);
    if let Some(mask) = radii_mask {
      scratch.radii_mask = Some(mask);
    }
    if let Some(mask) = path_mask {
      scratch.path_mask = Some(mask);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Ok(());
  }
  let max_write_w = filtered_width.saturating_sub(src_start_x as usize) as u32;
  let max_write_h = filtered_height_u32.saturating_sub(src_start_y);
  write_w = write_w.min(max_write_w);
  write_h = write_h.min(max_write_h);
  if write_w == 0 || write_h == 0 {
    scratch.region = Some(region);
    if let Some(mask) = radii_mask {
      scratch.radii_mask = Some(mask);
    }
    if let Some(mask) = path_mask {
      scratch.path_mask = Some(mask);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Ok(());
  }

  let dest_bytes_per_row = dest.width() as usize * 4;
  let clip_mask_data =
    clip_mask.map(|mask| (mask.data(), mask.width() as i32, mask.height() as i32));
  let radii_mask_data = radii_mask.as_ref().map(|mask| mask.data());
  let path_mask_data = path_mask.as_ref().map(|mask| mask.data());

  let write_result = (|| -> RenderResult<()> {
    let dest_data = dest.data_mut();
    if clip_mask_data.is_none() && radii_mask_data.is_none() && path_mask_data.is_none() {
      let row_bytes = write_w as usize * 4;
      let mut deadline_counter = 0usize;
      for row in 0..write_h as usize {
        check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
        let dst_idx = (write_y as usize + row) * dest_bytes_per_row + write_x as usize * 4;
        let src_idx = ((src_start_y as usize + row) * filtered_width + src_start_x as usize) * 4;
        dest_data[dst_idx..dst_idx + row_bytes]
          .copy_from_slice(&filtered_data[src_idx..src_idx + row_bytes]);
      }
    } else {
      let mut deadline_counter = 0usize;
      let mut pixel_counter = 0usize;
      for row in 0..write_h as usize {
        check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
        let dst_idx = (write_y as usize + row) * dest_bytes_per_row + write_x as usize * 4;
        let src_idx = ((src_start_y as usize + row) * filtered_width + src_start_x as usize) * 4;
        let mask_y = write_y as i32 + row as i32 - clip_origin.1;

        for col in 0..write_w as usize {
          if pixel_counter & 4095 == 0 {
            check_active(RenderStage::Paint)?;
          }
          pixel_counter = pixel_counter.wrapping_add(1);
          let dest_offset = dst_idx + col * 4;
          let src_offset = src_idx + col * 4;
          let mut coverage = 255u16;

          if let Some((mask_data, mask_w, mask_h)) = &clip_mask_data {
            let mask_x = write_x as i32 + col as i32 - clip_origin.0;
            if mask_x < 0 || mask_y < 0 || mask_x >= *mask_w || mask_y >= *mask_h {
              coverage = 0;
            } else {
              let mask_idx = (mask_y * mask_w + mask_x) as usize;
              coverage = div_255(coverage * mask_data[mask_idx] as u16);
            }
          }

          if coverage == 0 {
            continue;
          }

          if let Some(mask_data) = radii_mask_data {
            let mask_idx =
              (src_start_y as usize + row) * filtered_width + (src_start_x as usize + col);
            coverage = div_255(coverage * mask_data[mask_idx] as u16);
          }

          if coverage == 0 {
            continue;
          }

          if let Some(mask_data) = path_mask_data {
            let mask_idx =
              (src_start_y as usize + row) * filtered_width + (src_start_x as usize + col);
            coverage = div_255(coverage * mask_data[mask_idx] as u16);
          }

          if coverage >= 255 {
            dest_data[dest_offset..dest_offset + 4]
              .copy_from_slice(&filtered_data[src_offset..src_offset + 4]);
            continue;
          }

          if coverage == 0 {
            continue;
          }

          let cov = coverage as u16;
          let inv = 255u16 - cov;
          let src_px = &filtered_data[src_offset..src_offset + 4];
          let dst_slice = &mut dest_data[dest_offset..dest_offset + 4];
          for i in 0..4 {
            let src_v = src_px[i] as u16;
            let dst_v = dst_slice[i] as u16;
            dst_slice[i] = div_255(src_v * cov + dst_v * inv + 127) as u8;
          }
        }
      }
    }
    Ok(())
  })();

  if let Err(err) = write_result {
    scratch.region = Some(region);
    if let Some(mask) = radii_mask {
      scratch.radii_mask = Some(mask);
    }
    if let Some(mask) = path_mask {
      scratch.path_mask = Some(mask);
    }
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = scratch;
    });
    return Err(err);
  }

  scratch.region = Some(region);
  if let Some(mask) = radii_mask {
    scratch.radii_mask = Some(mask);
  }
  if let Some(mask) = path_mask {
    scratch.path_mask = Some(mask);
  }
  BACKDROP_FILTER_SCRATCH.with(|cell| {
    *cell.borrow_mut() = scratch;
  });
  Ok(())
}

fn apply_backdrop_filters(
  dest: &mut Pixmap,
  src: &Pixmap,
  dest_origin_in_src: (i32, i32),
  bounds_in_src: Rect,
  shape_bounds: Rect,
  filters: &[ResolvedFilter],
  radii: BorderRadii,
  scale: f32,
  clip_mask: Option<&Mask>,
  clip_bounds: Option<Rect>,
  clip_origin: (i32, i32),
  filter_bounds: Rect,
  world_to_dest: Transform,
  blur_cache: Option<&mut (dyn BlurCacheOps + 'static)>,
  backdrop_cache: Option<&mut (dyn BackdropFilterCacheOps + 'static)>,
) -> RenderResult<()> {
  apply_backdrop_filters_with_region_filler(
    dest,
    (src.width(), src.height()),
    dest_origin_in_src,
    bounds_in_src,
    shape_bounds,
    filters,
    radii,
    scale,
    clip_mask,
    clip_bounds,
    clip_origin,
    filter_bounds,
    world_to_dest,
    blur_cache,
    backdrop_cache,
    |region, clamped_x, clamped_y| {
      let src_bytes_per_row = src.width() as usize * 4;
      let region_w = region.width() as usize;
      let region_h = region.height() as usize;
      let region_row_bytes = region_w * 4;
      debug_assert_eq!(
        region.data().len(),
        region_row_bytes.saturating_mul(region_h),
        "expected scratch region pixmap to be tightly packed"
      );
      let start = (clamped_y as usize * src_bytes_per_row) + clamped_x as usize * 4;
      let data = src.data();
      let dest_data = region.data_mut();
      let mut deadline_counter = 0usize;
      for row in 0..region_h {
        check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
        let src_idx = start + row * src_bytes_per_row;
        let dst_idx = row * region_row_bytes;
        dest_data[dst_idx..dst_idx + region_row_bytes]
          .copy_from_slice(&data[src_idx..src_idx + region_row_bytes]);
      }
      Ok(())
    },
    None,
    None,
  )
}

#[derive(Clone, Copy)]
struct ProjectiveBackdropFilterContext {
  transform: Transform3D,
  parent_transform: Transform,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
struct ClipMaskDirtyRect {
  x0: u32,
  y0: u32,
  x1: u32,
  y1: u32,
}

#[derive(Default)]
struct ClipMaskScratch {
  mask: Option<Mask>,
  last_rect: Option<Rect>,
  last_radii: Option<BorderRadii>,
  last_transform: Option<Transform>,
}

thread_local! {
  static CLIP_MASK_SCRATCH: RefCell<ClipMaskScratch> = RefCell::new(ClipMaskScratch::default());
}

#[derive(Default)]
struct MaskLayerPixmapScratch {
  pixmap: Option<Pixmap>,
}

thread_local! {
  static MASK_LAYER_PIXMAP_SCRATCH: RefCell<MaskLayerPixmapScratch> =
    RefCell::new(MaskLayerPixmapScratch::default());
}

thread_local! {
  static MASK_RENDER_SCRATCH: RefCell<Option<Mask>> = RefCell::new(None);
}

#[cfg(test)]
thread_local! {
  static PARALLEL_RENDER_INVOCATIONS: Cell<usize> = Cell::new(0);
}

#[cfg(test)]
thread_local! {
  static RENDER_SCENE_ITEM_INVOCATIONS: Cell<usize> = Cell::new(0);
}

#[derive(Default)]
struct BackdropFilterScratch {
  region: Option<Pixmap>,
  radii_mask: Option<Mask>,
  path_mask: Option<Mask>,
  svg_backdrop: Option<Pixmap>,
}

thread_local! {
  static BACKDROP_FILTER_SCRATCH: RefCell<BackdropFilterScratch> =
    RefCell::new(BackdropFilterScratch::default());
}

#[derive(Default)]
struct SpreadScratch {
  source: Vec<[u8; 4]>,
  horizontal: Vec<[u8; 4]>,
  transposed: Vec<[u8; 4]>,
}

thread_local! {
  static SPREAD_SCRATCH: RefCell<SpreadScratch> = RefCell::new(SpreadScratch::default());
}

#[derive(Default)]
struct Preserve3dClipMaskScratch {
  combined: Option<Mask>,
  temp: Option<Mask>,
}

thread_local! {
  static PRESERVE_3D_CLIP_MASK_SCRATCH: RefCell<Preserve3dClipMaskScratch> =
    RefCell::new(Preserve3dClipMaskScratch::default());
}

fn with_preserve_3d_clip_mask_scratch<R>(f: impl FnOnce(&mut Preserve3dClipMaskScratch) -> R) -> R {
  PRESERVE_3D_CLIP_MASK_SCRATCH.with(|scratch_cell| {
    // Avoid holding a `RefCell` borrow across nested preserve-3d rendering. Preserve-3d planes can
    // rasterize nested preserve-3d contexts (and projective warps may execute rayon work that can
    // re-enter the renderer on the same thread via work stealing). Holding the borrow across those
    // calls triggers a `RefCell already borrowed` panic.
    let mut scratch = {
      let mut borrowed = scratch_cell.borrow_mut();
      std::mem::take(&mut *borrowed)
    };

    let result = f(&mut scratch);

    // Restore scratch masks, keeping whichever allocations are larger in case nested calls
    // populated the TLS scratch while this call was executing.
    {
      let mut borrowed = scratch_cell.borrow_mut();
      let scratch_combined_len = scratch
        .combined
        .as_ref()
        .map(|m| m.data().len())
        .unwrap_or(0);
      let borrowed_combined_len = borrowed
        .combined
        .as_ref()
        .map(|m| m.data().len())
        .unwrap_or(0);
      if scratch_combined_len > borrowed_combined_len {
        borrowed.combined = scratch.combined;
      }
      let scratch_temp_len = scratch.temp.as_ref().map(|m| m.data().len()).unwrap_or(0);
      let borrowed_temp_len = borrowed.temp.as_ref().map(|m| m.data().len()).unwrap_or(0);
      if scratch_temp_len > borrowed_temp_len {
        borrowed.temp = scratch.temp;
      }
    }

    result
  })
}

pub(crate) fn reset_thread_local_scratch_for_tests() {
  CLIP_MASK_SCRATCH.with(|cell| *cell.borrow_mut() = ClipMaskScratch::default());
  MASK_LAYER_PIXMAP_SCRATCH.with(|cell| *cell.borrow_mut() = MaskLayerPixmapScratch::default());
  MASK_RENDER_SCRATCH.with(|cell| *cell.borrow_mut() = None);
  BACKDROP_FILTER_SCRATCH.with(|cell| *cell.borrow_mut() = BackdropFilterScratch::default());
  SPREAD_SCRATCH.with(|cell| *cell.borrow_mut() = SpreadScratch::default());
  PRESERVE_3D_CLIP_MASK_SCRATCH
    .with(|cell| *cell.borrow_mut() = Preserve3dClipMaskScratch::default());
}

fn clip_mask_dirty_bounds(rect: Rect, width: u32, height: u32) -> Option<ClipMaskDirtyRect> {
  let x0 = rect.x().floor().max(0.0) as u32;
  let y0 = rect.y().floor().max(0.0) as u32;
  let x1 = (rect.x() + rect.width()).ceil().max(0.0) as u32;
  let y1 = (rect.y() + rect.height()).ceil().max(0.0) as u32;
  let x0 = x0.saturating_sub(1).min(width);
  let y0 = y0.saturating_sub(1).min(height);
  let x1 = x1.saturating_add(1).min(width);
  let y1 = y1.saturating_add(1).min(height);
  if x0 >= x1 || y0 >= y1 {
    None
  } else {
    Some(ClipMaskDirtyRect { x0, y0, x1, y1 })
  }
}

fn clear_mask_rect(mask: &mut Mask, rect: ClipMaskDirtyRect) -> RenderResult<()> {
  if rect.x0 >= rect.x1 || rect.y0 >= rect.y1 {
    return Ok(());
  }
  let width = mask.width() as usize;
  let stride = width;
  let data = mask.data_mut();
  let x0 = rect.x0 as usize;
  let x1 = rect.x1 as usize;
  let y0 = rect.y0 as usize;
  let y1 = rect.y1 as usize;
  if x0 == 0 && x1 == stride {
    check_active(RenderStage::Paint)?;
    data[y0 * stride..y1 * stride].fill(0);
    return Ok(());
  }
  let row_pixels = x1.saturating_sub(x0).max(1);
  let deadline_row_stride = (CLIP_MASK_DEADLINE_STRIDE / row_pixels).max(1);
  let mut deadline_counter = 0usize;
  for row in y0..y1 {
    check_active_periodic(
      &mut deadline_counter,
      deadline_row_stride,
      RenderStage::Paint,
    )?;
    let offset = row * stride;
    data[offset + x0..offset + x1].fill(0);
  }
  Ok(())
}

#[inline]
fn mul_div_255_round(value: u8, alpha: u8) -> u8 {
  // Match `tiny_skia::Pixmap::apply_mask` rounding behavior.
  let prod = value as u16 * alpha as u16;
  ((prod + 255) >> 8) as u8
}

fn multiply_masks_in_place(into: &mut Mask, other: &Mask) -> RenderResult<()> {
  if into.width() != other.width() || into.height() != other.height() {
    return Ok(());
  }
  check_active(RenderStage::Paint)?;

  let width = into.width() as usize;
  let height = into.height() as usize;
  let dst = into.data_mut();
  let src = other.data();
  let mut deadline_counter = 0usize;
  for row in 0..height {
    check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
    let offset = row * width;
    let dst_row = &mut dst[offset..offset + width];
    let src_row = &src[offset..offset + width];
    for (dst_px, src_px) in dst_row.iter_mut().zip(src_row.iter()) {
      *dst_px = mul_div_255_round(*dst_px, *src_px);
    }
  }

  Ok(())
}

fn copy_pixmap_alpha_into_mask(
  dest: &mut Mask,
  src: &Pixmap,
  offset: (i32, i32),
) -> RenderResult<()> {
  check_active(RenderStage::Paint)?;
  if dest.width() == 0 || dest.height() == 0 || src.width() == 0 || src.height() == 0 {
    return Ok(());
  }

  let dest_w = dest.width() as i32;
  let dest_h = dest.height() as i32;
  let src_w = src.width() as i32;
  let src_h = src.height() as i32;
  let (off_x, off_y) = offset;

  let start_x = off_x.max(0);
  let start_y = off_y.max(0);
  let end_x = (off_x + src_w).min(dest_w);
  let end_y = (off_y + src_h).min(dest_h);
  if start_x >= end_x || start_y >= end_y {
    return Ok(());
  }

  let copy_w = (end_x - start_x) as usize;
  let copy_h = (end_y - start_y) as usize;
  let src_start_x = (start_x - off_x) as usize;
  let src_start_y = (start_y - off_y) as usize;

  let dest_stride = dest.width() as usize;
  let src_stride_bytes = src.width() as usize * 4;
  let dest_data = dest.data_mut();
  let src_data = src.data();

  let mut deadline_counter = 0usize;
  for row in 0..copy_h {
    check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
    let dst_y = start_y as usize + row;
    let src_y = src_start_y + row;
    let dst_row = dst_y * dest_stride + start_x as usize;
    let src_row = src_y * src_stride_bytes + src_start_x * 4;
    for col in 0..copy_w {
      dest_data[dst_row + col] = src_data[src_row + col * 4 + 3];
    }
  }

  Ok(())
}

fn build_clip_path_shape_path(
  clip: &crate::paint::clip_path::ResolvedClipPath,
) -> Option<(tiny_skia::Path, tiny_skia::FillRule)> {
  use crate::paint::clip_path::ResolvedClipPath;

  match clip {
    ResolvedClipPath::Inset { rect, radii } => {
      if rect.width() <= 0.0
        || rect.height() <= 0.0
        || !rect.x().is_finite()
        || !rect.y().is_finite()
        || !rect.width().is_finite()
        || !rect.height().is_finite()
      {
        return None;
      }
      let radii = radii.clamped(rect.width(), rect.height());
      crate::paint::rasterize::build_rounded_rect_path(
        rect.x(),
        rect.y(),
        rect.width(),
        rect.height(),
        &radii,
      )
      .map(|path| (path, tiny_skia::FillRule::Winding))
    }
    ResolvedClipPath::Circle { center, radius } => {
      if *radius <= 0.0 {
        return None;
      }
      let r = *radius;
      let rect = tiny_skia::Rect::from_xywh(center.x - r, center.y - r, r * 2.0, r * 2.0)?;
      PathBuilder::from_oval(rect).map(|path| (path, tiny_skia::FillRule::Winding))
    }
    ResolvedClipPath::Ellipse {
      center,
      radius_x,
      radius_y,
    } => {
      if *radius_x <= 0.0 || *radius_y <= 0.0 {
        return None;
      }
      let rect = tiny_skia::Rect::from_xywh(
        center.x - radius_x,
        center.y - radius_y,
        radius_x * 2.0,
        radius_y * 2.0,
      )?;
      PathBuilder::from_oval(rect).map(|path| (path, tiny_skia::FillRule::Winding))
    }
    ResolvedClipPath::Polygon { points, fill_rule } => {
      if points.len() < 3 {
        return None;
      }
      let mut builder = PathBuilder::new();
      builder.move_to(points[0].x, points[0].y);
      for p in &points[1..] {
        builder.line_to(p.x, p.y);
      }
      builder.close();
      builder.finish().map(|path| (path, *fill_rule))
    }
    ResolvedClipPath::Path { path, fill_rule } => Some((path.clone(), *fill_rule)),
  }
}

fn apply_mask_rect_rgba(
  pixmap: &mut Pixmap,
  mask: &Mask,
  rect: ClipMaskDirtyRect,
) -> RenderResult<()> {
  if rect.x0 >= rect.x1 || rect.y0 >= rect.y1 {
    return Ok(());
  }
  if pixmap.width() != mask.width() || pixmap.height() != mask.height() {
    return Ok(());
  }
  check_active(RenderStage::Paint)?;

  let width = pixmap.width() as usize;
  let pixel_stride = width * 4;
  let mask_stride = width;
  let pixmap_data = pixmap.data_mut();
  let mask_data = mask.data();

  let x0 = rect.x0 as usize;
  let x1 = rect.x1 as usize;
  let mut deadline_counter = 0usize;
  let mut pixel_counter = 0usize;
  for y in rect.y0 as usize..rect.y1 as usize {
    check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
    let pixel_row_start = y * pixel_stride;
    let mask_row_start = y * mask_stride;
    let row_pixels = &mut pixmap_data[pixel_row_start + x0 * 4..pixel_row_start + x1 * 4];
    let row_mask = &mask_data[mask_row_start + x0..mask_row_start + x1];
    for (px, m) in row_pixels.chunks_exact_mut(4).zip(row_mask.iter()) {
      if pixel_counter & 4095 == 0 {
        check_active(RenderStage::Paint)?;
      }
      pixel_counter = pixel_counter.wrapping_add(1);
      let m = *m;
      if m == 255 {
        continue;
      }
      if m == 0 {
        px.fill(0);
        continue;
      }
      px[0] = mul_div_255_round(px[0], m);
      px[1] = mul_div_255_round(px[1], m);
      px[2] = mul_div_255_round(px[2], m);
      px[3] = mul_div_255_round(px[3], m);
    }
  }
  Ok(())
}

fn hard_clip_pixmap_outside_rect_rgba(pixmap: &mut Pixmap, rect: Rect) -> RenderResult<()> {
  check_active(RenderStage::Paint)?;
  let width = pixmap.width();
  let height = pixmap.height();

  // Hard-clip pixels outside the rectangle to avoid filter bleed.
  //
  // This is intentionally done using integer bounds (floor/ceil) so that any pixels outside the
  // clip rect are *fully* cleared even when the clip coordinates are fractional. Filters can
  // otherwise sample premultiplied RGB values outside the clip and bleed them back in.
  let x0 = (rect.x().floor().max(0.0) as u32).min(width);
  let y0 = (rect.y().floor().max(0.0) as u32).min(height);
  let x1 = (rect.x() + rect.width()).ceil().min(width as f32) as u32;
  let y1 = (rect.y() + rect.height()).ceil().min(height as f32) as u32;
  if x0 == 0 && y0 == 0 && x1 == width && y1 == height {
    return Ok(());
  }

  let stride = width as usize * 4;
  let data = pixmap.data_mut();

  // Clear fully outside rows in one contiguous fill.
  check_active(RenderStage::Paint)?;
  data[..y0 as usize * stride].fill(0);
  check_active(RenderStage::Paint)?;
  data[y1 as usize * stride..].fill(0);
  check_active(RenderStage::Paint)?;

  let left_bytes = x0 as usize * 4;
  let right_start = x1 as usize * 4;
  if left_bytes != 0 || right_start != stride {
    let row_pixels = width as usize;
    let deadline_row_stride = (CLIP_MASK_DEADLINE_STRIDE / row_pixels.max(1)).max(1);
    let mut deadline_counter = 0usize;
    for row in y0..y1 {
      check_active_periodic(
        &mut deadline_counter,
        deadline_row_stride,
        RenderStage::Paint,
      )?;
      let offset = row as usize * stride;
      let row = &mut data[offset..offset + stride];
      row[..left_bytes].fill(0);
      row[right_start..].fill(0);
    }
  }
  Ok(())
}

fn apply_clip_mask_rect(
  pixmap: &mut Pixmap,
  rect: Rect,
  radii: BorderRadii,
  diagnostics: Option<&Arc<ClipMaskDiagnostics>>,
) -> RenderResult<()> {
  check_active(RenderStage::Paint)?;
  if rect.width() <= 0.0 || rect.height() <= 0.0 {
    return Ok(());
  }

  let width = pixmap.width();
  let height = pixmap.height();
  if width == 0 || height == 0 {
    return Ok(());
  }

  let timer = diagnostics.map(|_| Instant::now());
  let pixels = diagnostics
    .map(|_| u64::from(width).saturating_mul(u64::from(height)))
    .unwrap_or(0);
  let record = |timer: Option<Instant>| {
    if let (Some(diag), Some(start)) = (diagnostics, timer) {
      diag.record(pixels, start.elapsed());
    }
  };

  // No-op fast path: clipping to a full-coverage axis-aligned rect without radii.
  if radii.is_zero() {
    let right = rect.x() + rect.width();
    let bottom = rect.y() + rect.height();
    if rect.x() <= 0.5
      && rect.y() <= 0.5
      && right >= width as f32 - 0.5
      && bottom >= height as f32 - 0.5
    {
      record(timer);
      return Ok(());
    }
  }

  // Fast path: fully outside the pixmap bounds.
  let right = rect.x() + rect.width();
  let bottom = rect.y() + rect.height();
  if right <= 0.0 || bottom <= 0.0 || rect.x() >= width as f32 || rect.y() >= height as f32 {
    pixmap.data_mut().fill(0);
    record(timer);
    return Ok(());
  }

  // Fast path: pure hard clip for pixel-aligned axis-aligned rects with no radii. For these
  // rectangles the rounded-rect mask would be all-0/255 and therefore equivalent to a hard clip,
  // so we can avoid generating and applying the mask entirely.
  if radii.is_zero() {
    let is_int = |v: f32| v.is_finite() && (v - v.round()).abs() <= 1e-6;
    if is_int(rect.x()) && is_int(rect.y()) && is_int(rect.width()) && is_int(rect.height()) {
      hard_clip_pixmap_outside_rect_rgba(pixmap, rect)?;
      record(timer);
      return Ok(());
    }
  }

  // Generate a rounded-rect alpha mask, reusing a thread-local scratch mask to avoid per-call
  // allocations.
  let applied_mask = CLIP_MASK_SCRATCH.with(|cell| -> RenderResult<bool> {
    let mut scratch = cell.borrow_mut();
    let replace = match scratch.mask.as_ref() {
      Some(existing) => existing.width() != width || existing.height() != height,
      None => true,
    };
    if replace {
      scratch.mask = Mask::new(width, height);
      scratch.last_rect = None;
      scratch.last_radii = None;
      scratch.last_transform = None;
    }

    let clamped = radii.clamped(rect.width(), rect.height());
    let fill_transform = Transform::identity();
    let needs_rebuild = scratch.last_rect != Some(rect)
      || scratch.last_radii != Some(clamped)
      || scratch.last_transform != Some(fill_transform);
    let dirty = clip_mask_dirty_bounds(rect, width, height);

    {
      let Some(mask) = scratch.mask.as_mut() else {
        return Ok(false);
      };

      if needs_rebuild {
        if deterministic_paint_enabled() {
          // In deterministic mode we clear the entire scratch mask before rebuilding to ensure
          // output never depends on leftover bytes from a previous render on the same thread.
          let mut deadline_counter = 0usize;
          for chunk in mask.data_mut().chunks_mut(CLIP_MASK_DEADLINE_STRIDE) {
            check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
            chunk.fill(0);
          }
        } else if let Some(dirty) = dirty {
          clear_mask_rect(mask, dirty)?;
        } else {
          // If the dirty bounds are empty (e.g. due to weird floating point inputs), clear the
          // entire mask so we don't reuse stale data.
          mask.data_mut().fill(0);
        }

        let Some(path) = crate::paint::rasterize::build_rounded_rect_path(
          rect.x(),
          rect.y(),
          rect.width(),
          rect.height(),
          &clamped,
        ) else {
          return Ok(false);
        };

        // Match `fill_rounded_rect` semantics (anti-aliased) without allocating an intermediate
        // RGBA pixmap or converting it to a mask.
        mask.fill_path(&path, tiny_skia::FillRule::Winding, true, fill_transform);
      }

      if let Some(dirty) = dirty {
        let right = rect.x() + rect.width();
        let bottom = rect.y() + rect.height();
        let left_radius = clamped.top_left.x.max(clamped.bottom_left.x);
        let right_radius = clamped.top_right.x.max(clamped.bottom_right.x);
        let top_radius = clamped.top_left.y.max(clamped.top_right.y);
        let bottom_radius = clamped.bottom_left.y.max(clamped.bottom_right.y);
        let skip_x0 = (rect.x() + left_radius).ceil().clamp(0.0, width as f32) as u32;
        let skip_x1 = (right - right_radius).floor().clamp(0.0, width as f32) as u32;
        let skip_y0 = (rect.y() + top_radius).ceil().clamp(0.0, height as f32) as u32;
        let skip_y1 = (bottom - bottom_radius).floor().clamp(0.0, height as f32) as u32;

        let skip_x0 = skip_x0.clamp(dirty.x0, dirty.x1);
        let skip_x1 = skip_x1.clamp(dirty.x0, dirty.x1);
        let skip_y0 = skip_y0.clamp(dirty.y0, dirty.y1);
        let skip_y1 = skip_y1.clamp(dirty.y0, dirty.y1);

        if skip_x0 >= skip_x1 || skip_y0 >= skip_y1 {
          apply_mask_rect_rgba(pixmap, mask, dirty)?;
        } else {
          if dirty.y0 < skip_y0 {
            apply_mask_rect_rgba(
              pixmap,
              mask,
              ClipMaskDirtyRect {
                x0: dirty.x0,
                y0: dirty.y0,
                x1: dirty.x1,
                y1: skip_y0,
              },
            )?;
          }
          if skip_y0 < skip_y1 {
            if dirty.x0 < skip_x0 {
              apply_mask_rect_rgba(
                pixmap,
                mask,
                ClipMaskDirtyRect {
                  x0: dirty.x0,
                  y0: skip_y0,
                  x1: skip_x0,
                  y1: skip_y1,
                },
              )?;
            }
            if skip_x1 < dirty.x1 {
              apply_mask_rect_rgba(
                pixmap,
                mask,
                ClipMaskDirtyRect {
                  x0: skip_x1,
                  y0: skip_y0,
                  x1: dirty.x1,
                  y1: skip_y1,
                },
              )?;
            }
          }
          if skip_y1 < dirty.y1 {
            apply_mask_rect_rgba(
              pixmap,
              mask,
              ClipMaskDirtyRect {
                x0: dirty.x0,
                y0: skip_y1,
                x1: dirty.x1,
                y1: dirty.y1,
              },
            )?;
          }
        }
      } else {
        apply_mask_rect_rgba(
          pixmap,
          mask,
          ClipMaskDirtyRect {
            x0: 0,
            y0: 0,
            x1: width,
            y1: height,
          },
        )?;
      }
    }

    if needs_rebuild {
      scratch.last_rect = Some(rect);
      scratch.last_radii = Some(clamped);
      scratch.last_transform = Some(fill_transform);
    }
    Ok(true)
  });

  let applied_mask = applied_mask?;
  if !applied_mask {
    record(timer);
    return Ok(());
  }

  hard_clip_pixmap_outside_rect_rgba(pixmap, rect)?;
  record(timer);
  Ok(())
}

fn apply_clip_mask_rect_transformed(
  pixmap: &mut Pixmap,
  clip_rect: Rect,
  radii: BorderRadii,
  source_rect: Rect,
  transform: Transform,
  diagnostics: Option<&Arc<ClipMaskDiagnostics>>,
) -> RenderResult<()> {
  check_active(RenderStage::Paint)?;
  if clip_rect.width() <= 0.0 || clip_rect.height() <= 0.0 {
    return Ok(());
  }

  let width = pixmap.width();
  let height = pixmap.height();
  if width == 0 || height == 0 {
    return Ok(());
  }

  let timer = diagnostics.map(|_| Instant::now());
  let pixels = diagnostics
    .map(|_| u64::from(width).saturating_mul(u64::from(height)))
    .unwrap_or(0);
  let record = |timer: Option<Instant>| {
    if let (Some(diag), Some(start)) = (diagnostics, timer) {
      diag.record(pixels, start.elapsed());
    }
  };

  // Fast path: fully outside the pixmap bounds.
  let right = clip_rect.x() + clip_rect.width();
  let bottom = clip_rect.y() + clip_rect.height();
  if right <= 0.0
    || bottom <= 0.0
    || clip_rect.x() >= width as f32
    || clip_rect.y() >= height as f32
  {
    pixmap.data_mut().fill(0);
    record(timer);
    return Ok(());
  }

  let applied_mask = CLIP_MASK_SCRATCH.with(|cell| -> RenderResult<bool> {
    let mut scratch = cell.borrow_mut();
    let replace = match scratch.mask.as_ref() {
      Some(existing) => existing.width() != width || existing.height() != height,
      None => true,
    };
    if replace {
      scratch.mask = Mask::new(width, height);
      scratch.last_rect = None;
      scratch.last_radii = None;
      scratch.last_transform = None;
    }

    let clamped = radii.clamped(source_rect.width(), source_rect.height());
    let needs_rebuild = scratch.last_rect != Some(source_rect)
      || scratch.last_radii != Some(clamped)
      || scratch.last_transform != Some(transform);
    let dirty = clip_mask_dirty_bounds(clip_rect, width, height);

    {
      let Some(mask) = scratch.mask.as_mut() else {
        return Ok(false);
      };

      if needs_rebuild {
        if let Some(dirty) = dirty {
          clear_mask_rect(mask, dirty)?;
        } else {
          mask.data_mut().fill(0);
        }

        let Some(path) = crate::paint::rasterize::build_rounded_rect_path(
          source_rect.x(),
          source_rect.y(),
          source_rect.width(),
          source_rect.height(),
          &clamped,
        ) else {
          return Ok(false);
        };

        mask.fill_path(&path, tiny_skia::FillRule::Winding, true, transform);
      }

      if let Some(dirty) = dirty {
        apply_mask_rect_rgba(pixmap, mask, dirty)?;
      } else {
        apply_mask_rect_rgba(
          pixmap,
          mask,
          ClipMaskDirtyRect {
            x0: 0,
            y0: 0,
            x1: width,
            y1: height,
          },
        )?;
      }
    }

    if needs_rebuild {
      scratch.last_rect = Some(source_rect);
      scratch.last_radii = Some(clamped);
      scratch.last_transform = Some(transform);
    }

    Ok(true)
  });

  let applied_mask = applied_mask?;
  if !applied_mask {
    record(timer);
    return Ok(());
  }

  hard_clip_pixmap_outside_rect_rgba(pixmap, clip_rect)?;
  record(timer);
  Ok(())
}

fn rect_int_bounds(rect: &Rect) -> (i32, i32, i32, i32) {
  let x0 = rect.min_x().floor() as i32;
  let y0 = rect.min_y().floor() as i32;
  let x1 = rect.max_x().ceil() as i32;
  let y1 = rect.max_y().ceil() as i32;
  (x0, y0, x1, y1)
}

fn apply_drop_shadow(
  pixmap: &mut Pixmap,
  offset_x: f32,
  offset_y: f32,
  blur_radius: f32,
  spread: f32,
  color: Rgba,
  cache: Option<&mut (dyn BlurCacheOps + 'static)>,
) -> RenderResult<()> {
  let width = pixmap.width();
  let height = pixmap.height();
  if width == 0 || height == 0 {
    return Ok(());
  }
  check_active(RenderStage::Paint)?;

  let Some((min_x, min_y, bounds_w, bounds_h)) = alpha_bounds(pixmap) else {
    return Ok(());
  };
  check_active(RenderStage::Paint)?;
  let blur_pad = (blur_radius.abs() * 3.0).ceil() as u64;
  // Negative spread is an erosion pass. Even though it shrinks the shadow, we still need a
  // transparent margin so edge pixels can observe transparent neighbors; otherwise a tight
  // alpha-bounds crop would clamp-to-edge and prevent the erosion from taking effect.
  //
  // Positive spread already needs padding to avoid clipping the dilation.
  let spread_pad = spread.abs().ceil() as u64;
  let pad = match blur_pad.checked_add(spread_pad) {
    Some(pad) => match u32::try_from(pad) {
      Ok(pad) => pad,
      Err(_) => return Ok(()),
    },
    None => return Ok(()),
  };
  let pad_i32 = match i32::try_from(pad) {
    Ok(pad) => pad,
    Err(_) => return Ok(()),
  };
  let pad2 = match pad.checked_mul(2) {
    Some(pad2) => pad2,
    None => return Ok(()),
  };
  let shadow_w = match bounds_w.checked_add(pad2) {
    Some(w) => w,
    None => return Ok(()),
  };
  let shadow_h = match bounds_h.checked_add(pad2) {
    Some(h) => h,
    None => return Ok(()),
  };

  let mut shadow = match new_pixmap(shadow_w, shadow_h) {
    Some(p) => p,
    None => return Ok(()),
  };

  {
    let src = pixmap.pixels();
    let src_stride = width as usize;
    let dst_stride = shadow.width() as usize;
    let dst = shadow.pixels_mut();
    let mut deadline_counter = 0usize;
    for y in 0..bounds_h as usize {
      check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
      let src_row = (min_y as usize + y) * src_stride;
      let dst_row = (pad as usize + y) * dst_stride;
      for x in 0..bounds_w as usize {
        check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)?;
        let src_px = src[src_row + min_x as usize + x];
        let alpha = src_px.alpha() as f32 / 255.0;
        let dst_idx = dst_row + pad as usize + x;
        if alpha == 0.0 {
          dst[dst_idx] = PremultipliedColorU8::TRANSPARENT;
          continue;
        }
        let total_alpha = (color.a * alpha).clamp(0.0, 1.0);
        let r = (color.r as f32 / 255.0) * total_alpha;
        let g = (color.g as f32 / 255.0) * total_alpha;
        let b = (color.b as f32 / 255.0) * total_alpha;
        let a = total_alpha * 255.0;
        dst[dst_idx] = PremultipliedColorU8::from_rgba(
          (r * 255.0).round() as u8,
          (g * 255.0).round() as u8,
          (b * 255.0).round() as u8,
          a.round().clamp(0.0, 255.0) as u8,
        )
        .unwrap_or(PremultipliedColorU8::TRANSPARENT);
      }
    }
  }

  if spread != 0.0 {
    apply_spread(&mut shadow, spread)?;
  }

  if blur_radius > 0.0 {
    apply_gaussian_blur_cached(&mut shadow, blur_radius, blur_radius, cache, 1.0)?;
  }

  let mut paint = PixmapPaint::default();
  paint.blend_mode = SkiaBlendMode::DestinationOver;
  let dest_x = match i32::try_from(min_x) {
    Ok(min_x) => min_x - pad_i32,
    Err(_) => return Ok(()),
  };
  let dest_y = match i32::try_from(min_y) {
    Ok(min_y) => min_y - pad_i32,
    Err(_) => return Ok(()),
  };
  pixmap.draw_pixmap(
    dest_x,
    dest_y,
    shadow.as_ref(),
    &paint,
    Transform::from_translate(offset_x, offset_y),
    None,
  );
  Ok(())
}

fn apply_spread(pixmap: &mut Pixmap, spread: f32) -> RenderResult<()> {
  // Run a separable square dilation/erosion with sliding-window extrema to avoid
  // the quadratic neighborhood scan.
  let radius = spread.abs().ceil() as i32;
  if radius <= 0 || spread == 0.0 {
    return Ok(());
  }
  let width = pixmap.width() as usize;
  let height = pixmap.height() as usize;
  if width == 0 || height == 0 {
    return Ok(());
  }
  check_active(RenderStage::Paint)?;
  let expand = spread > 0.0;
  let radius = radius as usize;
  // Clamp-to-edge addressing saturates once the radius exceeds the image dimensions. Clamp here
  // to avoid pathological `extended_len` loops and large sliding-window buffers for hostile CSS.
  let radius_x = radius.min(width.saturating_sub(1));
  let radius_y = radius.min(height.saturating_sub(1));
  let len = width
    .checked_mul(height)
    .ok_or(RenderError::InvalidParameters {
      message: format!("drop shadow spread: buffer size overflow ({width}x{height})"),
    })?;

  let mut scratch = SPREAD_SCRATCH.with(|cell| std::mem::take(&mut *cell.borrow_mut()));
  let result = (|| -> RenderResult<()> {
    scratch
      .source
      .try_reserve_exact(len.saturating_sub(scratch.source.len()))
      .map_err(|err| RenderError::InvalidParameters {
        message: format!("drop shadow spread: scratch allocation failed: {err}"),
      })?;
    scratch.source.resize(len, [0u8; 4]);

    scratch
      .horizontal
      .try_reserve_exact(len.saturating_sub(scratch.horizontal.len()))
      .map_err(|err| RenderError::InvalidParameters {
        message: format!("drop shadow spread: scratch allocation failed: {err}"),
      })?;
    scratch.horizontal.resize(len, [0u8; 4]);

    scratch
      .transposed
      .try_reserve_exact(len.saturating_sub(scratch.transposed.len()))
      .map_err(|err| RenderError::InvalidParameters {
        message: format!("drop shadow spread: scratch allocation failed: {err}"),
      })?;
    scratch.transposed.resize(len, [0u8; 4]);
    debug_assert_eq!(scratch.source.len(), len);
    debug_assert_eq!(scratch.horizontal.len(), len);
    debug_assert_eq!(scratch.transposed.len(), len);
    let mut deadline_counter = 0usize;
    for (src, dst) in pixmap.pixels().iter().zip(scratch.source.iter_mut()) {
      check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)?;
      *dst = [src.red(), src.green(), src.blue(), src.alpha()];
    }

    apply_spread_horizontal(
      &scratch.source,
      &mut scratch.horizontal,
      width,
      height,
      radius_x,
      expand,
    )?;

    // Transpose so the vertical pass can reuse the horizontal sliding window.
    transpose_channels(&scratch.horizontal, width, height, &mut scratch.transposed)?;

    // Reuse the horizontal buffer to store the vertical pass output.
    apply_spread_horizontal(
      &scratch.transposed,
      &mut scratch.horizontal,
      height,
      width,
      radius_y,
      expand,
    )?;

    let dst = pixmap.pixels_mut();
    write_transposed_to_pixmap(&scratch.horizontal, width, height, dst)?;
    Ok(())
  })();

  SPREAD_SCRATCH.with(|cell| *cell.borrow_mut() = scratch);
  result
}

fn apply_spread_horizontal(
  src: &[[u8; 4]],
  dst: &mut [[u8; 4]],
  width: usize,
  height: usize,
  radius: usize,
  expand: bool,
) -> RenderResult<()> {
  debug_assert_eq!(src.len(), width * height);
  debug_assert_eq!(dst.len(), width * height);
  if radius == 0 {
    dst.copy_from_slice(src);
    return Ok(());
  }
  let window_size = radius
    .checked_mul(2)
    .and_then(|size| size.checked_add(1))
    .ok_or(RenderError::InvalidParameters {
      message: format!("drop shadow spread: window size overflow (radius={radius})"),
    })?;
  let extended_len = width
    .checked_add(
      radius
        .checked_mul(2)
        .ok_or(RenderError::InvalidParameters {
          message: format!("drop shadow spread: buffer size overflow (radius={radius})"),
        })?,
    )
    .ok_or(RenderError::InvalidParameters {
      message: format!("drop shadow spread: buffer size overflow (width={width}, radius={radius})"),
    })?;
  let queue_capacity = window_size
    .checked_add(1)
    .ok_or(RenderError::InvalidParameters {
      message: format!("drop shadow spread: window size overflow (radius={radius})"),
    })?;
  let deadline = active_deadline();
  dst
    .par_chunks_mut(width)
    .enumerate()
    .try_for_each(|(y, dst_row)| {
      with_deadline(deadline.as_ref(), || -> RenderResult<()> {
        check_active(RenderStage::Paint)?;
        let row_start = y * width;
        let mut queues = [
          VecDeque::new(),
          VecDeque::new(),
          VecDeque::new(),
          VecDeque::new(),
        ];
        for queue in queues.iter_mut() {
          queue.try_reserve_exact(queue_capacity).map_err(|err| {
            RenderError::InvalidParameters {
              message: format!("drop shadow spread: window buffer allocation failed: {err}"),
            }
          })?;
        }
        let mut deadline_counter = 0usize;

        for j in 0..extended_len {
          check_active_periodic(&mut deadline_counter, 256, RenderStage::Paint)?;
          let src_x = if j < radius {
            0
          } else if j >= radius + width {
            width - 1
          } else {
            j - radius
          };
          let idx = row_start + src_x;
          let value = src[idx];

          for (channel, queue) in queues.iter_mut().enumerate() {
            if expand {
              while let Some(&(_, v)) = queue.back() {
                if v >= value[channel] {
                  break;
                }
                queue.pop_back();
              }
            } else {
              while let Some(&(_, v)) = queue.back() {
                if v <= value[channel] {
                  break;
                }
                queue.pop_back();
              }
            }
            queue.push_back((j, value[channel]));
          }

          if j >= window_size {
            let expire = j - window_size;
            for queue in queues.iter_mut() {
              while let Some(&(idx, _)) = queue.front() {
                if idx <= expire {
                  queue.pop_front();
                } else {
                  break;
                }
              }
            }
          }

          if j + 1 >= window_size {
            let out_x = j + 1 - window_size;
            let mut out = [0u8; 4];
            for (channel, queue) in queues.iter().enumerate() {
              out[channel] = queue.front().map(|(_, v)| *v).unwrap_or(0);
            }
            dst_row[out_x] = out;
          }
        }
        Ok(())
      })
    })?;
  Ok(())
}

fn transpose_channels(
  src: &[[u8; 4]],
  width: usize,
  height: usize,
  dst: &mut [[u8; 4]],
) -> RenderResult<()> {
  debug_assert_eq!(src.len(), width * height);
  debug_assert_eq!(dst.len(), width * height);
  check_active(RenderStage::Paint)?;
  let mut deadline_counter = 0usize;
  for y in 0..height {
    check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)?;
    let row_start = y * width;
    for x in 0..width {
      check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)?;
      dst[x * height + y] = src[row_start + x];
    }
  }
  Ok(())
}

fn write_transposed_to_pixmap(
  src: &[[u8; 4]],
  width: usize,
  height: usize,
  dst: &mut [PremultipliedColorU8],
) -> RenderResult<()> {
  debug_assert_eq!(src.len(), width * height);
  debug_assert_eq!(dst.len(), width * height);
  check_active(RenderStage::Paint)?;
  let mut deadline_counter = 0usize;
  for y in 0..height {
    check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)?;
    for x in 0..width {
      check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)?;
      let channels = src[x * height + y];
      dst[y * width + x] =
        PremultipliedColorU8::from_rgba(channels[0], channels[1], channels[2], channels[3])
          .unwrap_or(PremultipliedColorU8::TRANSPARENT);
    }
  }
  Ok(())
}

#[cfg(test)]
fn apply_spread_slow_reference(pixmap: &mut Pixmap, spread: f32) {
  let radius = spread.abs().ceil() as i32;
  if radius <= 0 || spread == 0.0 {
    return;
  }
  let expand = spread > 0.0;
  let width = pixmap.width() as i32;
  let height = pixmap.height() as i32;
  let original = pixmap.clone();
  let src = original.pixels();
  let dst = pixmap.pixels_mut();
  let row_len = width as usize;

  let deadline = active_deadline();
  dst.par_iter_mut().enumerate().for_each(|(idx, dst_px)| {
    with_deadline(deadline.as_ref(), || {
      let y = (idx / row_len) as i32;
      let x = (idx % row_len) as i32;
      let mut agg = if expand { [0u8; 4] } else { [255u8; 4] };
      for dy in -radius..=radius {
        for dx in -radius..=radius {
          let ny = (y + dy).clamp(0, height - 1);
          let nx = (x + dx).clamp(0, width - 1);
          let sample_idx = (ny as usize) * row_len + nx as usize;
          let px = src[sample_idx];
          if expand {
            agg[0] = agg[0].max(px.red());
            agg[1] = agg[1].max(px.green());
            agg[2] = agg[2].max(px.blue());
            agg[3] = agg[3].max(px.alpha());
          } else {
            agg[0] = agg[0].min(px.red());
            agg[1] = agg[1].min(px.green());
            agg[2] = agg[2].min(px.blue());
            agg[3] = agg[3].min(px.alpha());
          }
        }
      }
      *dst_px = PremultipliedColorU8::from_rgba(agg[0], agg[1], agg[2], agg[3])
        .unwrap_or(PremultipliedColorU8::TRANSPARENT);
    });
  });
}

/// Configuration for parallel display list painting.
///
/// Parallel painting is enabled by default with adaptive thresholds to avoid
/// oversubscribing small pages. Use [`PaintParallelism::disabled`] to force
/// serial painting.
///
/// When enabled, the renderer splits the target pixmap into tiles and paints
/// them in parallel, blitting the results back into the final surface. Each
/// tile renders the full paint order for its (halo-expanded) region, so effects
/// that depend on previously painted pixels (for example `backdrop-filter`)
/// still see a fully rendered backdrop for that tile.
///
/// The renderer still falls back to serial rendering for effects that cannot be
/// evaluated correctly in isolation (for example preserve-3d stacking contexts).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum PaintParallelismMode {
  Disabled,
  Enabled,
  Auto,
}

impl Default for PaintParallelismMode {
  fn default() -> Self {
    PaintParallelismMode::Auto
  }
}

#[derive(Debug, Clone, Copy)]
pub struct PaintParallelism {
  /// How rasterization should be parallelized.
  pub mode: PaintParallelismMode,
  /// Target tile size in device pixels (before scale is applied).
  pub tile_size: u32,
  /// Emit timing information when rendering.
  pub log_timing: bool,
  /// Minimum display items required before parallelizing rasterization.
  pub min_display_items: usize,
  /// Minimum number of tiles before switching to parallel rasterization.
  pub min_tiles: usize,
  /// Minimum fragment count before parallel display list building is attempted.
  pub min_build_fragments: usize,
  /// Target batch size when fan-out building the display list.
  pub build_chunk_size: usize,
  /// Optional cap on the number of rayon threads used for tile fan-out.
  ///
  /// This does not reconfigure the global rayon pool. Instead, it limits how much work the
  /// renderer exposes to the pool at once so callers can keep total CPU usage under control
  /// (for example when `pageset_progress` is already running N worker processes).
  pub max_threads: Option<usize>,
}

impl PaintParallelism {
  /// Enable parallel painting with conservative defaults and adaptive thresholds.
  pub fn auto() -> Self {
    Self {
      mode: PaintParallelismMode::Auto,
      tile_size: 256,
      log_timing: false,
      min_display_items: 128,
      min_tiles: 4,
      min_build_fragments: 128,
      build_chunk_size: 32,
      max_threads: None,
    }
  }

  /// Force tiled rasterization (still subject to safety fallbacks for parallel-incompatible
  /// effects).
  pub fn enabled() -> Self {
    Self {
      mode: PaintParallelismMode::Enabled,
      ..Self::auto()
    }
  }

  /// Backwards-compatible alias for [`PaintParallelism::auto`].
  pub fn adaptive() -> Self {
    Self::auto()
  }

  pub fn disabled() -> Self {
    Self {
      mode: PaintParallelismMode::Disabled,
      ..Self::auto()
    }
  }
}

impl Default for PaintParallelism {
  fn default() -> Self {
    Self::auto()
  }
}

/// Rendering report returned by `render_with_report`.
pub struct RenderReport {
  /// The rendered pixmap.
  pub pixmap: Pixmap,
  /// Whether parallel tiling was used.
  pub parallel_used: bool,
  /// Number of tiles rendered (1 for serial).
  pub tiles: usize,
  /// Total paint duration.
  pub duration: Duration,
  /// Optional reason parallel rendering was disabled.
  pub fallback_reason: Option<String>,
  /// Gradient rasterization statistics collected during the render.
  pub gradient_stats: GradientStats,
  /// Rasterized gradient pixmap cache hits.
  pub gradient_pixmap_cache_hits: u64,
  /// Rasterized gradient pixmap cache misses.
  pub gradient_pixmap_cache_misses: u64,
  /// Bytes currently held by the rasterized gradient pixmap cache.
  pub gradient_pixmap_cache_bytes: u64,
  /// Image pixmap conversion cache hits during paint.
  pub image_pixmap_cache_hits: u64,
  /// Image pixmap conversion cache misses during paint.
  pub image_pixmap_cache_misses: u64,
  /// Time spent converting image buffers into pixmaps during paint.
  pub image_pixmap_ms: f64,
  /// Time spent painting background tiles (images + gradients) during paint.
  pub background_ms: f64,
  /// Clip mask operations performed during paint.
  pub clip_mask_calls: u64,
  /// Time spent building/applying clip masks during paint.
  pub clip_mask_ms: f64,
  /// Total pixels covered by clip masks during paint (counts mask buffer pixels).
  pub clip_mask_pixels: u64,
  /// Offscreen layer pixmap allocations during paint (stacking contexts, opacity, shadows).
  pub layer_allocations: u64,
  /// Total bytes allocated for offscreen layers during paint.
  pub layer_alloc_bytes: u64,
  /// Backdrop stack composite pixmap allocations performed while preparing `backdrop-filter` roots.
  pub backdrop_composite_allocations: u64,
  /// Total bytes allocated for backdrop stack composites during paint.
  pub backdrop_composite_bytes: u64,
  /// Backdrop stack composite cache hits.
  pub backdrop_composite_cache_hits: u64,
  /// Backdrop stack composite cache misses.
  pub backdrop_composite_cache_misses: u64,
  /// Number of parallel tasks spawned during rasterization.
  pub parallel_tasks: usize,
  /// Rayon thread budget available for parallel tiling.
  ///
  /// This is derived from the configured paint pool size (or the current/global Rayon pool when no
  /// dedicated paint pool is active), capped by `PaintParallelism::max_threads` and tile count.
  ///
  /// Note: This is intentionally **not** the number of distinct OS threads that happened to execute
  /// work for this render; in highly parallel test runs Rayon may schedule work on a subset of the
  /// available threads.
  pub parallel_threads: usize,
  /// Wall-clock time spent in the parallel raster path.
  pub parallel_duration: Duration,
  /// Wall-clock time spent painting serially.
  pub serial_duration: Duration,
}

/// Report for an incremental/partial repaint operation.
///
/// Partial repaint renders a subset of tiles into an existing pixmap and blits the result back.
/// The operation may fall back to a full repaint for correctness (e.g. preserve-3d scenes).
pub struct PartialRepaintReport {
  /// The rendered pixmap (either updated in-place or freshly repainted).
  pub pixmap: Pixmap,
  /// Whether the repaint used the partial repaint path.
  pub used_partial: bool,
  /// Number of tiles that were repainted (0 when falling back to full repaint).
  pub repainted_tiles: usize,
  /// Optional reason partial repaint was not used.
  pub fallback_reason: Option<String>,
}

/// Report for a scroll-blit + exposed-strip repaint operation.
pub struct ScrollBlitReport {
  /// The rendered pixmap.
  pub pixmap: Pixmap,
  /// Whether the scroll blit fast-path was used.
  pub scroll_blit_used: bool,
  /// Whether partial repaint was used to repaint the exposed strip.
  pub partial_repaint_used: bool,
  /// Device-pixel rectangles that were repainted after the blit (i.e. regions where previous-frame
  /// pixels were overwritten).
  ///
  /// This is primarily useful for callers that apply post-processing overlays (such as find-in-page
  /// highlights) to the pixmap: when the scroll-blit path is used, the existing pixels already
  /// include those overlays, so they must only be re-applied to the regions that were repainted
  /// after the blit to avoid double-applying alpha.
  pub repainted_device_rects: Vec<Rect>,
  /// Optional reason the optimization was not used.
  pub fallback_reason: Option<String>,
}

#[derive(Debug, Default)]
struct RepaintTilesReport {
  tiles: usize,
  device_rects: Vec<Rect>,
}

#[derive(Default)]
struct ImagePixmapDiagnostics {
  hits: AtomicU64,
  misses: AtomicU64,
  nanos: AtomicU64,
}

#[derive(Clone, Copy, Default)]
struct ImagePixmapSnapshot {
  hits: u64,
  misses: u64,
  nanos: u64,
}

impl ImagePixmapDiagnostics {
  #[inline]
  fn record_hit(&self) {
    self.hits.fetch_add(1, Ordering::Relaxed);
  }

  #[inline]
  fn record_miss(&self) {
    self.misses.fetch_add(1, Ordering::Relaxed);
  }

  #[inline]
  fn record_duration(&self, duration: Duration) {
    let nanos = duration.as_nanos().min(u128::from(u64::MAX)) as u64;
    self.nanos.fetch_add(nanos, Ordering::Relaxed);
  }

  fn snapshot(&self) -> ImagePixmapSnapshot {
    ImagePixmapSnapshot {
      hits: self.hits.load(Ordering::Relaxed),
      misses: self.misses.load(Ordering::Relaxed),
      nanos: self.nanos.load(Ordering::Relaxed),
    }
  }
}

impl ImagePixmapSnapshot {
  fn millis(self) -> f64 {
    self.nanos as f64 / 1_000_000.0
  }
}

#[derive(Default)]
struct ClipMaskDiagnostics {
  calls: AtomicU64,
  pixels: AtomicU64,
  nanos: AtomicU64,
}

#[derive(Clone, Copy, Default)]
struct ClipMaskSnapshot {
  calls: u64,
  pixels: u64,
  nanos: u64,
}

impl ClipMaskDiagnostics {
  #[inline]
  fn record(&self, pixels: u64, duration: Duration) {
    self.calls.fetch_add(1, Ordering::Relaxed);
    if pixels > 0 {
      self.pixels.fetch_add(pixels, Ordering::Relaxed);
    }
    let nanos = duration.as_nanos().min(u128::from(u64::MAX)) as u64;
    self.nanos.fetch_add(nanos, Ordering::Relaxed);
  }

  fn snapshot(&self) -> ClipMaskSnapshot {
    ClipMaskSnapshot {
      calls: self.calls.load(Ordering::Relaxed),
      pixels: self.pixels.load(Ordering::Relaxed),
      nanos: self.nanos.load(Ordering::Relaxed),
    }
  }
}

impl ClipMaskSnapshot {
  fn millis(self) -> f64 {
    self.nanos as f64 / 1_000_000.0
  }
}

#[derive(Default)]
struct LayerAllocationDiagnostics {
  allocations: AtomicU64,
  bytes: AtomicU64,
}

#[derive(Clone, Copy, Default)]
struct LayerAllocationSnapshot {
  allocations: u64,
  bytes: u64,
}

impl LayerAllocationDiagnostics {
  #[inline]
  fn record(&self, width: u32, height: u32) {
    self.allocations.fetch_add(1, Ordering::Relaxed);
    let bytes = u64::from(width)
      .saturating_mul(u64::from(height))
      .saturating_mul(4);
    if bytes > 0 {
      self.bytes.fetch_add(bytes, Ordering::Relaxed);
    }
  }

  fn snapshot(&self) -> LayerAllocationSnapshot {
    LayerAllocationSnapshot {
      allocations: self.allocations.load(Ordering::Relaxed),
      bytes: self.bytes.load(Ordering::Relaxed),
    }
  }
}

#[derive(Default)]
struct BackdropCompositeDiagnostics {
  allocations: AtomicU64,
  bytes: AtomicU64,
  cache_hits: AtomicU64,
  cache_misses: AtomicU64,
}

#[derive(Clone, Copy, Default)]
struct BackdropCompositeSnapshot {
  allocations: u64,
  bytes: u64,
  cache_hits: u64,
  cache_misses: u64,
}

impl BackdropCompositeDiagnostics {
  #[inline]
  fn record_allocation(&self, width: u32, height: u32) {
    self.allocations.fetch_add(1, Ordering::Relaxed);
    let bytes = u64::from(width)
      .saturating_mul(u64::from(height))
      .saturating_mul(4);
    if bytes > 0 {
      self.bytes.fetch_add(bytes, Ordering::Relaxed);
    }
  }

  #[inline]
  fn record_hit(&self) {
    self.cache_hits.fetch_add(1, Ordering::Relaxed);
  }

  #[inline]
  fn record_miss(&self) {
    self.cache_misses.fetch_add(1, Ordering::Relaxed);
  }

  fn snapshot(&self) -> BackdropCompositeSnapshot {
    BackdropCompositeSnapshot {
      allocations: self.allocations.load(Ordering::Relaxed),
      bytes: self.bytes.load(Ordering::Relaxed),
      cache_hits: self.cache_hits.load(Ordering::Relaxed),
      cache_misses: self.cache_misses.load(Ordering::Relaxed),
    }
  }
}

#[derive(Default)]
struct BackgroundPaintDiagnostics {
  nanos: AtomicU64,
}

#[derive(Clone, Copy, Default)]
struct BackgroundPaintSnapshot {
  nanos: u64,
}

impl BackgroundPaintDiagnostics {
  #[inline]
  fn record_duration(&self, duration: Duration) {
    let nanos = duration.as_nanos().min(u128::from(u64::MAX)) as u64;
    self.nanos.fetch_add(nanos, Ordering::Relaxed);
  }

  fn snapshot(&self) -> BackgroundPaintSnapshot {
    BackgroundPaintSnapshot {
      nanos: self.nanos.load(Ordering::Relaxed),
    }
  }
}

impl BackgroundPaintSnapshot {
  fn millis(self) -> f64 {
    self.nanos as f64 / 1_000_000.0
  }
}

