thread_local! {
  static PRESERVE_3D_PLANE_PARALLEL_DEPTH: Cell<usize> = const { Cell::new(0) };
}

struct Preserve3dPlaneParallelGuard;

impl Preserve3dPlaneParallelGuard {
  fn enter() -> Self {
    PRESERVE_3D_PLANE_PARALLEL_DEPTH.with(|depth| {
      depth.set(depth.get().saturating_add(1));
    });
    Self
  }
}

impl Drop for Preserve3dPlaneParallelGuard {
  fn drop(&mut self) {
    PRESERVE_3D_PLANE_PARALLEL_DEPTH.with(|depth| {
      depth.set(depth.get().saturating_sub(1));
    });
  }
}

fn preserve_3d_plane_parallel_active() -> bool {
  PRESERVE_3D_PLANE_PARALLEL_DEPTH.with(|depth| depth.get() > 0)
}

#[derive(Clone)]
struct Preserve3dSceneRasterConfig {
  font_ctx: FontContext,
  scale: f32,
  preserve_3d_disabled: bool,
  preserve_3d_scene_depth: usize,
  gradient_cache: GradientLutCache,
  gradient_pixmap_cache: GradientPixmapCache,
  diagnostics_enabled: bool,
  image_pixmap_diagnostics: Option<Arc<ImagePixmapDiagnostics>>,
  background_paint_diagnostics: Option<Arc<BackgroundPaintDiagnostics>>,
  clip_mask_diagnostics: Option<Arc<ClipMaskDiagnostics>>,
  layer_alloc_diagnostics: Option<Arc<LayerAllocationDiagnostics>>,
  backdrop_composite_diagnostics: Option<Arc<BackdropCompositeDiagnostics>>,
}

impl Preserve3dSceneRasterConfig {
  fn rasterize(&self, item: &Preserve3dSceneItem) -> Result<(Option<Pixmap>, GradientStats)> {
    let bounds = item.bounds;
    if bounds.width() <= 0.0 || bounds.height() <= 0.0 {
      return Ok((None, GradientStats::default()));
    }

    let width = (bounds.width() * self.scale).ceil().max(1.0) as u32;
    let height = (bounds.height() * self.scale).ceil().max(1.0) as u32;

    let mut list = DisplayList::new();
    let translation = Transform3D::translate(-bounds.x(), -bounds.y(), 0.0);
    list.push(DisplayItem::PushTransform(TransformItem {
      transform: translation,
    }));
    for effect in &item.effects {
      list.push(effect.push_item(bounds));
    }

    let mut effects_after = item.effects.clone();
    match &item.source {
      Preserve3dSceneItemSource::Segment(items) => {
        let mut deadline_counter = 0usize;
        for it in items {
          check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
            .map_err(Error::Render)?;
          update_scene_effect_stack(&mut effects_after, it, Transform3D::identity());
          list.push(it.clone());
        }
      }
      Preserve3dSceneItemSource::FlattenedSubtree(node) => {
        let mut deadline_counter = 0usize;
        for (i, it) in node.subtree_items.iter().enumerate() {
          check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
            .map_err(Error::Render)?;
          if i == 0 {
            if let DisplayItem::PushStackingContext(sc) = it {
              let mut adjusted = sc.clone();
              adjusted.transform = None;
              adjusted.backdrop_filters.clear();
              adjusted.mix_blend_mode = BlendMode::Normal;
              let display_item = DisplayItem::PushStackingContext(adjusted);
              update_scene_effect_stack(&mut effects_after, &display_item, Transform3D::identity());
              list.push(display_item);
              continue;
            }
          }
          update_scene_effect_stack(&mut effects_after, it, Transform3D::identity());
          list.push(it.clone());
        }
      }
    }

    for effect in effects_after.iter().rev() {
      list.push(effect.pop_item());
    }
    list.push(DisplayItem::PopTransform);

    let mut renderer = DisplayListRenderer::new_scaled(
      width,
      height,
      Rgba::TRANSPARENT,
      self.font_ctx.clone(),
      self.scale,
    )?;
    renderer.preserve_3d_disabled = self.preserve_3d_disabled;
    renderer.preserve_3d_scene_depth = self.preserve_3d_scene_depth.saturating_add(1);
    renderer.paint_parallelism = PaintParallelism::disabled();
    renderer.gradient_cache = self.gradient_cache.clone();
    renderer.gradient_pixmap_cache = self.gradient_pixmap_cache.clone();
    renderer.diagnostics_enabled = self.diagnostics_enabled;
    renderer.image_pixmap_diagnostics = self.image_pixmap_diagnostics.clone();
    renderer.background_paint_diagnostics = self.background_paint_diagnostics.clone();
    renderer.clip_mask_diagnostics = self.clip_mask_diagnostics.clone();
    renderer.layer_alloc_diagnostics = self.layer_alloc_diagnostics.clone();
    renderer.backdrop_composite_diagnostics = self.backdrop_composite_diagnostics.clone();
    let report = renderer.render_with_report(&list)?;
    Ok((Some(report.pixmap), report.gradient_stats))
  }
}

#[derive(Clone, Debug)]
enum SceneEffect {
  Clip {
    clip: ClipItem,
    transform: Transform3D,
  },
  Opacity(f32),
}

impl SceneEffect {
  fn push_item(&self, raster_bounds: Rect) -> DisplayItem {
    match self {
      SceneEffect::Clip { .. } => DisplayItem::PushClip(ClipItem {
        shape: ClipShape::Rect {
          rect: raster_bounds,
          radii: None,
        },
      }),
      SceneEffect::Opacity(opacity) => DisplayItem::PushOpacity(OpacityItem { opacity: *opacity }),
    }
  }

  fn pop_item(&self) -> DisplayItem {
    match self {
      SceneEffect::Clip { .. } => DisplayItem::PopClip,
      SceneEffect::Opacity(_) => DisplayItem::PopOpacity,
    }
  }
}

fn update_scene_effect_stack(
  stack: &mut Vec<SceneEffect>,
  item: &DisplayItem,
  transform: Transform3D,
) {
  match item {
    DisplayItem::PushClip(clip) => {
      stack.push(SceneEffect::Clip {
        clip: clip.clone(),
        transform,
      });
    }
    DisplayItem::PopClip => {
      if let Some(pos) = stack
        .iter()
        .rposition(|eff| matches!(eff, SceneEffect::Clip { .. }))
      {
        stack.remove(pos);
      }
    }
    DisplayItem::PushOpacity(OpacityItem { opacity }) => {
      stack.push(SceneEffect::Opacity(*opacity));
    }
    DisplayItem::PopOpacity => {
      if let Some(pos) = stack
        .iter()
        .rposition(|eff| matches!(eff, SceneEffect::Opacity(_)))
      {
        stack.remove(pos);
      }
    }
    _ => {}
  }
}

fn parse_stacking_node<T>(items: &T, start: usize) -> Option<(StackingNode, usize)>
where
  T: DisplayItemSource + ?Sized,
{
  if start >= items.len() {
    return None;
  }
  let DisplayItem::PushStackingContext(context) = items.get(start)? else {
    return None;
  };

  let mut idx = start + 1;
  let mut segments = Vec::new();
  let mut current_items = Vec::new();
  while idx < items.len() {
    let item = items.get(idx)?;
    match item {
      DisplayItem::PushStackingContext(_) => {
        if !current_items.is_empty() {
          segments.push(StackingSegment::Items(current_items));
          current_items = Vec::new();
        }
        let Some((child, end)) = parse_stacking_node(items, idx) else {
          return None;
        };
        segments.push(StackingSegment::Child(child));
        idx = end + 1;
        continue;
      }
      DisplayItem::PopStackingContext => {
        break;
      }
      other => current_items.push(other.clone()),
    }
    idx += 1;
  }

  if idx >= items.len() {
    return None;
  }

  if !current_items.is_empty() {
    segments.push(StackingSegment::Items(current_items));
  }

  let end_index = idx;
  let mut subtree_items = Vec::new();
  for i in start..=end_index {
    subtree_items.push(items.get(i)?.clone());
  }
  Some((
    StackingNode {
      context: context.clone(),
      start_index: start,
      end_index,
      segments,
      subtree_items,
    },
    end_index,
  ))
}

fn compute_items_bounds(items: &[DisplayItem]) -> Option<Rect> {
  let mut bounds: Option<Rect> = None;
  for item in items {
    if let Some(b) = item.bounds() {
      bounds = Some(match bounds {
        Some(existing) => existing.union(b),
        None => b,
      });
    }
  }
  bounds
}

fn collect_scene_items(
  node: &StackingNode,
  parent_transform: &Transform3D,
  in_preserve_context: bool,
  order_counter: &mut usize,
  is_scene_root: bool,
  inherited_effects: &[SceneEffect],
  backdrop_root_chain: &mut Vec<usize>,
  backdrop_root_counter: &mut usize,
) -> Vec<Preserve3dSceneItem> {
  let local_transform = node.context.transform.unwrap_or_else(Transform3D::identity);
  let combined_transform = parent_transform.multiply_perspective_optimized(&local_transform);
  let child_transform = node
    .context
    .child_perspective
    .as_ref()
    .map(|perspective| combined_transform.multiply(perspective))
    .unwrap_or(combined_transform);
  let mut items = Vec::new();
  let transform_style = node.context.transform_style;

  let should_flatten =
    !in_preserve_context || !matches!(transform_style, TransformStyle::Preserve3d);

  let establishes_backdrop_root_layer = !node.context.is_root
    && node.context.establishes_backdrop_root
    && node.context.has_backdrop_sensitive_descendants;
  let pushed_backdrop_root = if !should_flatten && !is_scene_root && establishes_backdrop_root_layer
  {
    let id = *backdrop_root_counter;
    *backdrop_root_counter = backdrop_root_counter.saturating_add(1);
    backdrop_root_chain.push(id);
    Some(id)
  } else {
    None
  };

  if should_flatten {
    let computed_bounds = compute_items_bounds(&node.subtree_items).and_then(|bounds| {
      let is_valid = bounds.width() > 0.0
        && bounds.height() > 0.0
        && bounds.x().is_finite()
        && bounds.y().is_finite()
        && bounds.width().is_finite()
        && bounds.height().is_finite();
      if !is_valid {
        return None;
      }

      let filter_outset =
        filter_outset_with_bounds(&node.context.filters, 1.0, Some(node.context.bounds));
      let expanded = Rect::from_xywh(
        bounds.x() - filter_outset.left,
        bounds.y() - filter_outset.top,
        bounds.width() + filter_outset.left + filter_outset.right,
        bounds.height() + filter_outset.top + filter_outset.bottom,
      );

      let expanded_valid = expanded.width() > 0.0
        && expanded.height() > 0.0
        && expanded.x().is_finite()
        && expanded.y().is_finite()
        && expanded.width().is_finite()
        && expanded.height().is_finite();
      expanded_valid.then_some(expanded)
    });
    let order = *order_counter;
    *order_counter += 1;
    let filter_bounds = {
      let candidate = node.context.plane_rect;
      if candidate.width() > 0.0
        && candidate.height() > 0.0
        && candidate.x().is_finite()
        && candidate.y().is_finite()
        && candidate.width().is_finite()
        && candidate.height().is_finite()
      {
        candidate
      } else {
        node.context.bounds
      }
    };
    items.push(Preserve3dSceneItem {
      source: Preserve3dSceneItemSource::FlattenedSubtree(node.clone()),
      transform: combined_transform,
      // When flattening a subtree into a single preserve-3d plane, the raster surface must be at
      // least as large as the stacking context bounds. Otherwise nested preserve-3d warps inside
      // the flattened subtree can project outside the raw paint bounds and get clipped.
      bounds: computed_bounds
        .map(|bounds| bounds.union(node.context.bounds))
        .unwrap_or(node.context.bounds),
      plane_rect: node.context.plane_rect,
      backface_visibility: node.context.backface_visibility,
      paint_order: order,
      effects: inherited_effects.to_vec(),
      backdrop_root_chain: backdrop_root_chain.clone(),
      backdrop_filters: node.context.backdrop_filters.clone(),
      radii: node.context.radii,
      filter_bounds,
      compositing: Some(Preserve3dCompositing {
        mix_blend_mode: node.context.mix_blend_mode,
        is_isolated: node.context.is_isolated,
      }),
    });
    return items;
  }

  let mut effects = inherited_effects.to_vec();
  for segment in &node.segments {
    match segment {
      StackingSegment::Items(list) => {
        let prefix_effects = effects.clone();
        for it in list {
          update_scene_effect_stack(&mut effects, it, combined_transform);
        }

        if list.is_empty() || !list.iter().any(|it| !it.is_stack_operation()) {
          continue;
        }

        let bounds = compute_items_bounds(list).unwrap_or(node.context.bounds);
        let plane_rect = {
          let candidate = node.context.plane_rect;
          if candidate.width() > 0.0
            && candidate.height() > 0.0
            && candidate.x().is_finite()
            && candidate.y().is_finite()
            && candidate.width().is_finite()
            && candidate.height().is_finite()
          {
            candidate
          } else {
            bounds
          }
        };
        let order = *order_counter;
        *order_counter += 1;
        items.push(Preserve3dSceneItem {
          source: Preserve3dSceneItemSource::Segment(list.clone()),
          transform: combined_transform,
          bounds,
          plane_rect,
          backface_visibility: node.context.backface_visibility,
          paint_order: order,
          effects: prefix_effects,
          backdrop_root_chain: backdrop_root_chain.clone(),
          backdrop_filters: Vec::new(),
          radii: BorderRadii::ZERO,
          filter_bounds: bounds,
          compositing: None,
        });
      }
      StackingSegment::Child(child) => {
        items.extend(collect_scene_items(
          child,
          &child_transform,
          true,
          order_counter,
          false,
          &effects,
          backdrop_root_chain,
          backdrop_root_counter,
        ));
      }
    }
  }

  if pushed_backdrop_root.is_some() {
    backdrop_root_chain.pop();
  }
  items
}

impl DisplayListRenderer {
  #[inline]
  fn ds_len(&self, v: f32) -> f32 {
    if !v.is_finite() {
      return 0.0;
    }
    v * self.scale
  }

  fn to_skia_transform_checked(&self, transform: &Transform3D) -> (Transform, bool) {
    if let Some(affine) = transform.to_2d() {
      return (
        Transform::from_row(
          affine.a,
          affine.b,
          affine.c,
          affine.d,
          self.ds_len(affine.e),
          self.ds_len(affine.f),
        ),
        true,
      );
    }

    let (approx, valid) = transform.approximate_2d_with_validity();
    (
      Transform::from_row(
        approx.a,
        approx.b,
        approx.c,
        approx.d,
        self.ds_len(approx.e),
        self.ds_len(approx.f),
      ),
      valid,
    )
  }

  fn projective_warp_pre_transform(
    &self,
    projective: &Transform3D,
    parent_transform: Transform,
  ) -> Option<(Transform, Rect)> {
    let visible_device = self
      .canvas
      .clip_bounds()
      .unwrap_or_else(|| self.canvas.bounds());
    if visible_device.width() <= 0.0 || visible_device.height() <= 0.0 {
      return None;
    }
    let inv_parent = invert_transform(parent_transform)?;
    let visible_parent_device = transform_rect(visible_device, &inv_parent);
    if visible_parent_device.width() <= 0.0
      || visible_parent_device.height() <= 0.0
      || !visible_parent_device.x().is_finite()
      || !visible_parent_device.y().is_finite()
      || !visible_parent_device.width().is_finite()
      || !visible_parent_device.height().is_finite()
    {
      return None;
    }
    if self.scale <= 0.0 || !self.scale.is_finite() {
      return None;
    }
    let visible_parent_css = Rect::from_xywh(
      visible_parent_device.x() / self.scale,
      visible_parent_device.y() / self.scale,
      visible_parent_device.width() / self.scale,
      visible_parent_device.height() / self.scale,
    );
    if visible_parent_css.width() <= 0.0
      || visible_parent_css.height() <= 0.0
      || !visible_parent_css.x().is_finite()
      || !visible_parent_css.y().is_finite()
      || !visible_parent_css.width().is_finite()
      || !visible_parent_css.height().is_finite()
    {
      return None;
    }

    let inv_h = Homography::from_transform3d_z0(projective).inverse()?;
    let corners = [
      Point::new(visible_parent_css.min_x(), visible_parent_css.min_y()),
      Point::new(visible_parent_css.max_x(), visible_parent_css.min_y()),
      Point::new(visible_parent_css.max_x(), visible_parent_css.max_y()),
      Point::new(visible_parent_css.min_x(), visible_parent_css.max_y()),
    ];

    let mut min_x = f32::INFINITY;
    let mut min_y = f32::INFINITY;
    let mut max_x = f32::NEG_INFINITY;
    let mut max_y = f32::NEG_INFINITY;
    for corner in corners {
      let mapped = inv_h.map_point(corner)?;
      min_x = min_x.min(mapped.x);
      min_y = min_y.min(mapped.y);
      max_x = max_x.max(mapped.x);
      max_y = max_y.max(mapped.y);
    }

    if !min_x.is_finite() || !min_y.is_finite() || !max_x.is_finite() || !max_y.is_finite() {
      return None;
    }
    let local_bounds_css = Rect::from_xywh(min_x, min_y, max_x - min_x, max_y - min_y);
    if local_bounds_css.width() <= 0.0
      || local_bounds_css.height() <= 0.0
      || !local_bounds_css.width().is_finite()
      || !local_bounds_css.height().is_finite()
    {
      return None;
    }

    let local_bounds_device_w = local_bounds_css.width() * self.scale;
    let local_bounds_device_h = local_bounds_css.height() * self.scale;
    if local_bounds_device_w <= 0.0
      || local_bounds_device_h <= 0.0
      || !local_bounds_device_w.is_finite()
      || !local_bounds_device_h.is_finite()
    {
      return None;
    }

    let sx = visible_parent_device.width() / local_bounds_device_w;
    let sy = visible_parent_device.height() / local_bounds_device_h;
    if sx <= 0.0 || sy <= 0.0 || !sx.is_finite() || !sy.is_finite() {
      return None;
    }

    let tx = visible_parent_device.min_x() - sx * local_bounds_css.min_x() * self.scale;
    let ty = visible_parent_device.min_y() - sy * local_bounds_css.min_y() * self.scale;
    if !tx.is_finite() || !ty.is_finite() {
      return None;
    }

    Some((
      Transform::from_row(sx, 0.0, 0.0, sy, tx, ty),
      local_bounds_css,
    ))
  }

  #[inline]
  fn ds_point(&self, p: Point) -> Point {
    Point::new(p.x * self.scale, p.y * self.scale)
  }

  #[inline]
  fn ds_rect(&self, rect: Rect) -> Rect {
    Rect::from_xywh(
      rect.x() * self.scale,
      rect.y() * self.scale,
      rect.width() * self.scale,
      rect.height() * self.scale,
    )
  }

  #[inline]
  fn is_near_integer(value: f32) -> bool {
    (value - value.round()).abs() < 1e-3
  }

  #[inline]
  fn snap_near_integer(value: f32, epsilon: f32) -> Option<f32> {
    if !value.is_finite() || !epsilon.is_finite() || epsilon <= 0.0 {
      return None;
    }
    let rounded = value.round();
    ((value - rounded).abs() < epsilon).then_some(rounded)
  }

  #[inline]
  fn snap_rect_edges_to_near_integers(rect: Rect, epsilon: f32) -> Option<Rect> {
    let x0 = Self::snap_near_integer(rect.min_x(), epsilon)?;
    let y0 = Self::snap_near_integer(rect.min_y(), epsilon)?;
    let x1 = Self::snap_near_integer(rect.max_x(), epsilon)?;
    let y1 = Self::snap_near_integer(rect.max_y(), epsilon)?;
    let w = x1 - x0;
    let h = y1 - y0;
    if !(w.is_finite() && h.is_finite() && w > 0.0 && h > 0.0) {
      return None;
    }
    Some(Rect::from_xywh(x0, y0, w, h))
  }

  #[inline]
  fn snap_rect_to_near_integer_edges_or_size(rect: Rect, epsilon: f32) -> Option<Rect> {
    let (min_x, min_y, w, h) = (rect.min_x(), rect.min_y(), rect.width(), rect.height());
    if !(min_x.is_finite()
      && min_y.is_finite()
      && w.is_finite()
      && h.is_finite()
      && w > 0.0
      && h > 0.0)
    {
      return None;
    }

    let max_x = min_x + w;
    let max_y = min_y + h;

    let sx0 = Self::snap_near_integer(min_x, epsilon);
    let sx1 = Self::snap_near_integer(max_x, epsilon);
    let sw = Self::snap_near_integer(w, epsilon);

    let sy0 = Self::snap_near_integer(min_y, epsilon);
    let sy1 = Self::snap_near_integer(max_y, epsilon);
    let sh = Self::snap_near_integer(h, epsilon);

    let (out_x0, out_x1, snapped_x) = match (sx0, sx1, sw) {
      (Some(x0), Some(x1), _) => (x0, x1, true),
      (Some(x0), None, Some(w)) => (x0, x0 + w, true),
      (None, Some(x1), Some(w)) => (x1 - w, x1, true),
      _ => (min_x, max_x, false),
    };

    let (out_y0, out_y1, snapped_y) = match (sy0, sy1, sh) {
      (Some(y0), Some(y1), _) => (y0, y1, true),
      (Some(y0), None, Some(h)) => (y0, y0 + h, true),
      (None, Some(y1), Some(h)) => (y1 - h, y1, true),
      _ => (min_y, max_y, false),
    };

    if !snapped_x && !snapped_y {
      return None;
    }

    let out_w = out_x1 - out_x0;
    let out_h = out_y1 - out_y0;
    if !(out_w.is_finite() && out_h.is_finite() && out_w > 0.0 && out_h > 0.0) {
      return None;
    }

    Some(Rect::from_xywh(out_x0, out_y0, out_w, out_h))
  }

  #[inline]
  fn snap_axis_aligned_stroke_center_to_device_pixels(coord: f32, width: f32) -> f32 {
    if width <= 0.0 || !coord.is_finite() || !width.is_finite() {
      return coord;
    }
    if !Self::is_near_integer(width) {
      return coord;
    }
    let width_i = width.round() as i32;
    if width_i <= 0 {
      return coord;
    }
    if width_i % 2 == 0 {
      coord.round()
    } else {
      (coord - 0.5).round() + 0.5
    }
  }

  #[inline]
  fn snap_rect_origin_to_device_pixels(rect: Rect) -> Rect {
    Rect::from_xywh(
      rect.x().floor(),
      rect.y().floor(),
      rect.width(),
      rect.height(),
    )
  }

  #[inline]
  fn round_rect_origin_to_device_pixels(rect: Rect) -> Rect {
    Rect::from_xywh(
      rect.x().round(),
      rect.y().round(),
      rect.width(),
      rect.height(),
    )
  }

  #[inline]
  fn is_translation_only_transform(transform: Transform) -> bool {
    let eps = 1e-6;
    (transform.sx - 1.0).abs() <= eps
      && (transform.sy - 1.0).abs() <= eps
      && transform.kx.abs() <= eps
      && transform.ky.abs() <= eps
      && transform.tx.is_finite()
      && transform.ty.is_finite()
  }

  #[inline]
  fn snap_rect_origin_to_device_pixels_with_translation(rect: Rect, transform: Transform) -> Rect {
    // `rect` is in "world" coordinates which will be transformed by `transform` during rasterization.
    // When the transform is a pure translation (e.g. paint tiling offsets), snap the *transformed*
    // origin to integer device pixels and then undo the translation so the caller can keep passing
    // world-space rectangles.
    let eff_x = rect.x() + transform.tx;
    let eff_y = rect.y() + transform.ty;
    Rect::from_xywh(
      eff_x.floor() - transform.tx,
      eff_y.floor() - transform.ty,
      rect.width(),
      rect.height(),
    )
  }

  #[inline]
  fn round_rect_origin_to_device_pixels_with_translation(rect: Rect, transform: Transform) -> Rect {
    let eff_x = rect.x() + transform.tx;
    let eff_y = rect.y() + transform.ty;
    Rect::from_xywh(
      eff_x.round() - transform.tx,
      eff_y.round() - transform.ty,
      rect.width(),
      rect.height(),
    )
  }

  #[inline]
  fn maybe_snap_axis_aligned_clip_rect(&self, rect: Rect) -> Rect {
    // tiny-skia uses floating-point transforms for `draw_pixmap` / mask rasterization. For
    // axis-aligned integer-sized clips, snapping near-integer edges to device pixels tends to
    // align better with Chrome's pixel grid behavior.
    //
    // Be conservative: only snap when the clip rect edges are already very close to integer
    // device pixels. Snapping a significantly fractional origin (e.g. 99.8) can shift the clip
    // region far enough to include adjacent pixels, which then interacts badly with 1:1 image
    // snapping and can cause clipped content to overpaint borders (e.g. the HN logo).
    let transform = self.canvas.transform();
    if transform != Transform::identity()
      && (!Self::is_translation_only_transform(transform)
        || !Self::is_near_integer(transform.tx)
        || !Self::is_near_integer(transform.ty))
    {
      return rect;
    }
    if rect.width() <= 0.0
      || rect.height() <= 0.0
      || !rect.x().is_finite()
      || !rect.y().is_finite()
      || !rect.width().is_finite()
      || !rect.height().is_finite()
    {
      return rect;
    }

    const CLIP_SNAP_EPSILON: f32 = 1e-3;

    if transform == Transform::identity() {
      Self::snap_rect_edges_to_near_integers(rect, CLIP_SNAP_EPSILON).unwrap_or(rect)
    } else {
      // Snap in device space so tile-based translation transforms behave identically to full
      // surface rendering.
      let eff = Rect::from_xywh(
        rect.x() + transform.tx,
        rect.y() + transform.ty,
        rect.width(),
        rect.height(),
      );
      if let Some(snapped) = Self::snap_rect_edges_to_near_integers(eff, CLIP_SNAP_EPSILON) {
        Rect::from_xywh(
          snapped.x() - transform.tx,
          snapped.y() - transform.ty,
          snapped.width(),
          snapped.height(),
        )
      } else {
        rect
      }
    }
  }

  #[inline]
  fn maybe_snap_unscaled_image_dest_rect(&self, dest_rect: Rect, pixmap: &Pixmap) -> Rect {
    let transform = self.canvas.transform();
    if transform != Transform::identity()
      && (!Self::is_translation_only_transform(transform)
        || !Self::is_near_integer(transform.tx)
        || !Self::is_near_integer(transform.ty))
    {
      return dest_rect;
    }
    if dest_rect.width() <= 0.0
      || dest_rect.height() <= 0.0
      || !dest_rect.x().is_finite()
      || !dest_rect.y().is_finite()
      || !dest_rect.width().is_finite()
      || !dest_rect.height().is_finite()
    {
      return dest_rect;
    }

    let (src_w, src_h) = (pixmap.width() as f32, pixmap.height() as f32);
    if src_w <= 0.0 || src_h <= 0.0 {
      return dest_rect;
    }

    let scale_x = dest_rect.width() / src_w;
    let scale_y = dest_rect.height() / src_h;
    if !scale_x.is_finite() || !scale_y.is_finite() {
      return dest_rect;
    }

    // Only snap 1:1 draws. This avoids impacting down/upscaled content where subpixel translation
    // can be more visible (and where we may intentionally preserve fractional offsets).
    if (scale_x - 1.0).abs() > 1e-6 || (scale_y - 1.0).abs() > 1e-6 {
      return dest_rect;
    }

    // If we have an axis-aligned integer clip, snap the image origin *down* so that the unscaled
    // draw lands on the same pixel grid as the clip rect. (Rounding up would shift content below
    // the clip, leaving a missing row/column.)
    let clip_snapped_to_device_pixels = self.canvas.clip_bounds().is_some_and(|clip| {
      Self::is_near_integer(clip.x())
        && Self::is_near_integer(clip.y())
        && Self::is_near_integer(clip.width())
        && Self::is_near_integer(clip.height())
    });
    let snapped_origin = if clip_snapped_to_device_pixels {
      if transform == Transform::identity() {
        Self::snap_rect_origin_to_device_pixels(dest_rect)
      } else {
        Self::snap_rect_origin_to_device_pixels_with_translation(dest_rect, transform)
      }
    } else if transform == Transform::identity() {
      Self::round_rect_origin_to_device_pixels(dest_rect)
    } else {
      Self::round_rect_origin_to_device_pixels_with_translation(dest_rect, transform)
    };
    let width = if Self::is_near_integer(snapped_origin.width()) {
      snapped_origin.width().round()
    } else {
      snapped_origin.width()
    };
    let height = if Self::is_near_integer(snapped_origin.height()) {
      snapped_origin.height().round()
    } else {
      snapped_origin.height()
    };
    Rect::from_xywh(snapped_origin.x(), snapped_origin.y(), width, height)
  }

  #[inline]
  fn ds_radii(&self, radii: BorderRadii) -> BorderRadii {
    BorderRadii {
      top_left: radii.top_left * self.scale,
      top_right: radii.top_right * self.scale,
      bottom_right: radii.bottom_right * self.scale,
      bottom_left: radii.bottom_left * self.scale,
    }
  }

  fn stacking_layer_bounds(
    &self,
    bounds: Rect,
    css_bounds: Rect,
    transform: Transform,
    filters: &[ResolvedFilter],
    backdrop_filters: &[ResolvedFilter],
  ) -> Option<Rect> {
    let has_filters = !(filters.is_empty() && backdrop_filters.is_empty());

    let mut layer_bounds = transform_rect(bounds, &transform);
    let filters_for_outset = transform_filters_for_pixmap_space(filters, transform);
    let (f_l, f_t, f_r, f_b) =
      filter_outset_with_bounds(&filters_for_outset, self.scale, Some(css_bounds)).as_tuple();
    let (b_l, b_t, b_r, b_b) =
      filter_outset_with_bounds(backdrop_filters, self.scale, Some(css_bounds)).as_tuple();
    let expand_left = f_l.max(b_l);
    let expand_top = f_t.max(b_t);
    let expand_right = f_r.max(b_r);
    let expand_bottom = f_b.max(b_b);
    layer_bounds = Rect::from_xywh(
      layer_bounds.x() - expand_left,
      layer_bounds.y() - expand_top,
      layer_bounds.width() + expand_left + expand_right,
      layer_bounds.height() + expand_top + expand_bottom,
    );

    if has_filters {
      // For filter effects, the input to the filter must not be clipped to the current clip/canvas
      // bounds. Otherwise, pixels just outside the viewport/clip are treated as transparent when
      // evaluating kernels like `blur()`, which darkens or truncates the halo near the edge.
      //
      // Filter kernels also sample neighboring pixels. If the current canvas clip is tighter than
      // the filter's halo region (e.g. an `overflow:hidden` ancestor clips the filtered element),
      // we still need to allocate enough transparent padding around the visible region to avoid
      // edge clamping artifacts during filtering.
      //
      // Instead, compute the *visible* portion (what will be composited into the parent surface),
      // then expand it by a conservative halo so the filter can see the neighboring pixels it
      // depends on.
      let mut visible = layer_bounds;
      if let Some(clip) = self.canvas.clip_bounds() {
        visible = visible.intersection(clip)?;
      }
      visible = visible.intersection(self.canvas.bounds())?;

      if visible.width() <= 0.0 || visible.height() <= 0.0 {
        return None;
      }

      let halo_filters =
        filter_halo_outset_with_bounds(&filters_for_outset, self.scale, Some(css_bounds));
      let halo_backdrop =
        filter_halo_outset_with_bounds(backdrop_filters, self.scale, Some(css_bounds));
      let halo_left = halo_filters.left.max(halo_backdrop.left);
      let halo_top = halo_filters.top.max(halo_backdrop.top);
      let halo_right = halo_filters.right.max(halo_backdrop.right);
      let halo_bottom = halo_filters.bottom.max(halo_backdrop.bottom);

      let expanded_visible = Rect::from_xywh(
        visible.x() - halo_left,
        visible.y() - halo_top,
        visible.width() + halo_left + halo_right,
        visible.height() + halo_top + halo_bottom,
      );

      layer_bounds = expanded_visible.intersection(layer_bounds)?;
    } else {
      if let Some(clip) = self.canvas.clip_bounds() {
        layer_bounds = match layer_bounds.intersection(clip) {
          Some(r) => r,
          None => return None,
        };
      }

      layer_bounds = match layer_bounds.intersection(self.canvas.bounds()) {
        Some(r) => r,
        None => return None,
      };
    }
    if layer_bounds.width() <= 0.0
      || layer_bounds.height() <= 0.0
      || !layer_bounds.x().is_finite()
      || !layer_bounds.y().is_finite()
    {
      return None;
    }

    Some(layer_bounds)
  }

  fn projective_backdrop_layer_bounds(
    &self,
    plane_css_bounds: Rect,
    css_bounds: Rect,
    parent_transform: Transform,
    projective_transform: &Transform3D,
    filters: &[ResolvedFilter],
    backdrop_filters: &[ResolvedFilter],
  ) -> Option<Rect> {
    let quad = projective_transform.project_quad(plane_css_bounds)?;
    let mut min_x = f32::INFINITY;
    let mut min_y = f32::INFINITY;
    let mut max_x = f32::NEG_INFINITY;
    let mut max_y = f32::NEG_INFINITY;
    for p in quad {
      min_x = min_x.min(p.x);
      min_y = min_y.min(p.y);
      max_x = max_x.max(p.x);
      max_y = max_y.max(p.y);
    }

    let projected_css = Rect::from_xywh(min_x, min_y, max_x - min_x, max_y - min_y);
    let projected_device = self.ds_rect(projected_css);
    let mut layer_bounds = transform_rect(projected_device, &parent_transform);
    let (f_l, f_t, f_r, f_b) =
      filter_outset_with_bounds(filters, self.scale, Some(css_bounds)).as_tuple();
    let (b_l, b_t, b_r, b_b) =
      filter_outset_with_bounds(backdrop_filters, self.scale, Some(css_bounds)).as_tuple();
    let expand_left = f_l.max(b_l);
    let expand_top = f_t.max(b_t);
    let expand_right = f_r.max(b_r);
    let expand_bottom = f_b.max(b_b);
    layer_bounds = Rect::from_xywh(
      layer_bounds.x() - expand_left,
      layer_bounds.y() - expand_top,
      layer_bounds.width() + expand_left + expand_right,
      layer_bounds.height() + expand_top + expand_bottom,
    );

    if let Some(clip) = self.canvas.clip_bounds() {
      let expanded_clip = Rect::from_xywh(
        clip.x() - expand_left,
        clip.y() - expand_top,
        clip.width() + expand_left + expand_right,
        clip.height() + expand_top + expand_bottom,
      );
      layer_bounds = match layer_bounds.intersection(expanded_clip) {
        Some(r) => r,
        None => return None,
      };
    }

    let canvas_bounds = self.canvas.bounds();
    let expanded_canvas = Rect::from_xywh(
      canvas_bounds.x() - expand_left,
      canvas_bounds.y() - expand_top,
      canvas_bounds.width() + expand_left + expand_right,
      canvas_bounds.height() + expand_top + expand_bottom,
    );
    layer_bounds = match layer_bounds.intersection(expanded_canvas) {
      Some(r) => r,
      None => return None,
    };

    if layer_bounds.width() <= 0.0
      || layer_bounds.height() <= 0.0
      || !layer_bounds.x().is_finite()
      || !layer_bounds.y().is_finite()
    {
      return None;
    }

    Some(layer_bounds)
  }

  fn layer_space_bounds(&self, bounds: Rect, origin: (i32, i32), layer: &Pixmap) -> Option<Rect> {
    let translated = Rect::from_xywh(
      bounds.x() - origin.0 as f32,
      bounds.y() - origin.1 as f32,
      bounds.width(),
      bounds.height(),
    );
    let layer_rect = Rect::from_xywh(0.0, 0.0, layer.width() as f32, layer.height() as f32);
    translated.intersection(layer_rect)
  }

  fn ds_filters(&self, filters: &[ResolvedFilter]) -> Vec<ResolvedFilter> {
    filters.to_vec()
  }

  fn scale_text_item(&self, item: &TextItem) -> TextItem {
    let mut scaled = item.clone();
    scaled.origin = self.ds_point(item.origin);
    scaled.font_size = self.ds_len(item.font_size);
    scaled.advance_width = self.ds_len(item.advance_width);
    scaled.synthetic_bold = self.ds_len(item.synthetic_bold);
    scaled.stroke_width = self.ds_len(item.stroke_width);
    scaled.glyphs = item
      .glyphs
      .iter()
      .map(|g| GlyphInstance {
        glyph_id: g.glyph_id,
        cluster: g.cluster,
        x_offset: self.ds_len(g.x_offset),
        y_offset: self.ds_len(g.y_offset),
        x_advance: self.ds_len(g.x_advance),
        y_advance: self.ds_len(g.y_advance),
      })
      .collect();
    scaled.shadows = item
      .shadows
      .iter()
      .map(|s| TextShadowItem {
        offset: self.ds_point(s.offset),
        blur_radius: self.ds_len(s.blur_radius),
        color: s.color,
      })
      .collect();
    if let Some(emphasis) = &item.emphasis {
      let mut e = emphasis.clone();
      e.size = self.ds_len(e.size);
      e.inline_vertical = emphasis.inline_vertical;
      e.marks = e
        .marks
        .iter()
        .map(|m| EmphasisMark {
          center: self.ds_point(m.center),
        })
        .collect();
      if let Some(text) = &e.text {
        let mut t = text.clone();
        t.width = self.ds_len(t.width);
        t.height = self.ds_len(t.height);
        t.baseline_offset = self.ds_len(t.baseline_offset);
        t.runs = t
          .runs
          .into_iter()
          .map(|run| crate::paint::display_list::EmphasisTextRun {
            glyphs: run
              .glyphs
              .into_iter()
              .map(|g| GlyphInstance {
                glyph_id: g.glyph_id,
                cluster: g.cluster,
                x_offset: self.ds_len(g.x_offset),
                y_offset: self.ds_len(g.y_offset),
                x_advance: self.ds_len(g.x_advance),
                y_advance: self.ds_len(g.y_advance),
              })
              .collect(),
            font: run.font,
            font_id: run.font_id,
            font_size: self.ds_len(run.font_size),
            advance_width: self.ds_len(run.advance_width),
            variations: run.variations,
            palette_index: run.palette_index,
            palette_overrides: run.palette_overrides,
            palette_override_hash: run.palette_override_hash,
            synthetic_bold: self.ds_len(run.synthetic_bold),
            synthetic_oblique: run.synthetic_oblique,
          })
          .collect();
        e.text = Some(t);
      }
      scaled.emphasis = Some(e);
    }
    scaled.cached_bounds = item.cached_bounds.map(|bounds| self.ds_rect(bounds));
    scaled
  }

  fn scale_list_marker_item(&self, item: &ListMarkerItem) -> ListMarkerItem {
    let text_equiv = TextItem {
      origin: item.origin,
      cached_bounds: item.cached_bounds,
      glyphs: item.glyphs.clone(),
      color: item.color,
      allow_subpixel_aa: item.allow_subpixel_aa,
      stroke_width: item.stroke_width,
      stroke_color: item.stroke_color,
      font_smoothing: item.font_smoothing,
      text_rendering: item.text_rendering,
      palette_index: item.palette_index,
      palette_overrides: item.palette_overrides.clone(),
      palette_override_hash: item.palette_override_hash,
      rotation: item.rotation,
      scale: item.scale,
      shadows: item.shadows.clone(),
      font_size: item.font_size,
      advance_width: item.advance_width,
      font_id: item.font_id.clone(),
      font: item.font.clone(),
      variations: item.variations.clone(),
      synthetic_bold: item.synthetic_bold,
      synthetic_oblique: item.synthetic_oblique,
      emphasis: item.emphasis.clone(),
      decorations: Vec::new(),
      ..Default::default()
    };
    let scaled = self.scale_text_item(&text_equiv);
    ListMarkerItem {
      origin: scaled.origin,
      cached_bounds: scaled.cached_bounds,
      glyphs: scaled.glyphs,
      color: scaled.color,
      allow_subpixel_aa: scaled.allow_subpixel_aa,
      stroke_width: scaled.stroke_width,
      stroke_color: scaled.stroke_color,
      font_smoothing: scaled.font_smoothing,
      text_rendering: scaled.text_rendering,
      shadows: scaled.shadows,
      font_size: scaled.font_size,
      advance_width: scaled.advance_width,
      font_id: scaled.font_id,
      palette_index: scaled.palette_index,
      palette_overrides: scaled.palette_overrides,
      palette_override_hash: scaled.palette_override_hash,
      rotation: scaled.rotation,
      scale: scaled.scale,
      font: scaled.font,
      variations: scaled.variations,
      synthetic_bold: scaled.synthetic_bold,
      synthetic_oblique: scaled.synthetic_oblique,
      emphasis: scaled.emphasis,
      background: item.background,
    }
  }

  fn scale_decoration_item(
    &self,
    item: &crate::paint::display_list::TextDecorationItem,
  ) -> crate::paint::display_list::TextDecorationItem {
    let mut scaled = item.clone();
    scaled.bounds = self.ds_rect(item.bounds);
    scaled.line_start = self.ds_len(item.line_start);
    scaled.line_width = self.ds_len(item.line_width);
    scaled.inline_vertical = item.inline_vertical;
    scaled.decorations = item
      .decorations
      .iter()
      .map(|d| {
        let scale_stroke = |s: &Option<DecorationStroke>| -> Option<DecorationStroke> {
          s.as_ref().map(|stroke| DecorationStroke {
            center: self.ds_len(stroke.center),
            thickness: self.ds_len(stroke.thickness),
            segments: stroke.segments.as_ref().map(|segs| {
              segs
                .iter()
                .map(|(a, b)| (self.ds_len(*a), self.ds_len(*b)))
                .collect()
            }),
          })
        };
        DecorationPaint {
          style: d.style,
          color: d.color,
          underline: scale_stroke(&d.underline),
          overline: scale_stroke(&d.overline),
          line_through: scale_stroke(&d.line_through),
        }
      })
      .collect();
    scaled
  }

  /// Creates a renderer with the given dimensions and background color.
  pub fn new(width: u32, height: u32, background: Rgba, font_ctx: FontContext) -> Result<Self> {
    Self::new_scaled(width, height, background, font_ctx, 1.0)
  }

  /// Creates a renderer with an explicit device scale (DPR). Coordinates are in CSS px.
  pub fn new_scaled(
    width: u32,
    height: u32,
    background: Rgba,
    font_ctx: FontContext,
    scale: f32,
  ) -> Result<Self> {
    let scale = if scale.is_finite() && scale > 0.0 {
      scale
    } else {
      1.0
    };
    let device_w = ((width as f32) * scale).round().max(1.0) as u32;
    let device_h = ((height as f32) * scale).round().max(1.0) as u32;
    let color_renderer = shared_color_renderer();
    let color_cache = shared_color_cache();
    let glyph_cache = shared_glyph_cache();
    Self::new_with_text_state(
      device_w,
      device_h,
      background,
      font_ctx,
      scale,
      color_renderer,
      color_cache,
      glyph_cache,
    )
  }

  /// Wraps an existing pixmap (already in device pixels) in a renderer without clearing it.
  pub fn new_from_existing_pixmap(
    pixmap: Pixmap,
    background: Rgba,
    font_ctx: FontContext,
  ) -> Result<Self> {
    Self::new_scaled_from_existing_pixmap(pixmap, background, font_ctx, 1.0)
  }

  /// Wraps an existing pixmap (already in device pixels) in a renderer without clearing it.
  ///
  /// The provided `scale` must match the scale that was used to produce the pixmap.
  pub fn new_scaled_from_existing_pixmap(
    pixmap: Pixmap,
    background: Rgba,
    font_ctx: FontContext,
    scale: f32,
  ) -> Result<Self> {
    let scale = if scale.is_finite() && scale > 0.0 {
      scale
    } else {
      1.0
    };
    let color_renderer = shared_color_renderer();
    let color_cache = shared_color_cache();
    let glyph_cache = shared_glyph_cache();
    Self::new_with_text_state_from_existing_pixmap(
      pixmap,
      background,
      font_ctx,
      scale,
      color_renderer,
      color_cache,
      glyph_cache,
    )
  }

  /// Creates a renderer that paints directly into an externally-owned RGBA8 buffer.
  ///
  /// The buffer is expected to be tightly packed (stride == width_px * 4). The canvas dimensions
  /// are still specified in CSS pixels; `scale` controls how CSS pixels map to device pixels.
  pub(crate) fn new_scaled_into_rgba_buffer(
    width: u32,
    height: u32,
    background: Rgba,
    font_ctx: FontContext,
    scale: f32,
    out: &mut [u8],
    stride_bytes: usize,
  ) -> Result<Self> {
    let scale = if scale.is_finite() && scale > 0.0 {
      scale
    } else {
      1.0
    };
    let device_w = ((width as f32) * scale).round().max(1.0) as u32;
    let device_h = ((height as f32) * scale).round().max(1.0) as u32;
    let color_renderer = shared_color_renderer();
    let color_cache = shared_color_cache();
    let glyph_cache = shared_glyph_cache();
    let text_rasterizer = TextRasterizer::with_caches(
      glyph_cache.clone(),
      color_renderer.clone(),
      color_cache.clone(),
    );
    let canvas = Canvas::from_rgba_buffer(
      out,
      device_w.max(1),
      device_h.max(1),
      stride_bytes,
      background,
      text_rasterizer,
    )?;
    Self::new_with_canvas(
      canvas,
      background,
      font_ctx,
      scale,
      color_renderer,
      color_cache,
      glyph_cache,
    )
  }

  /// Configure parallel painting.
  pub fn with_parallelism(mut self, parallelism: PaintParallelism) -> Self {
    self.paint_parallelism = parallelism;
    self
  }

  /// Configure parallel painting on an existing renderer.
  pub fn set_parallelism(&mut self, parallelism: PaintParallelism) {
    self.paint_parallelism = parallelism;
  }

  /// Configure whether the viewport reserves classic scrollbar gutter space (CSS Overflow 3
  /// `scrollbar-gutter: stable[/both-edges]`).
  ///
  /// When gutters are reserved, scroll-driven repaint optimizations such as scroll blitting are not
  /// generally correct unless they are implemented in scrollport space (leaving gutter pixels
  /// untouched). Callers that attempt scroll blits should set these flags based on the prepared
  /// layout viewport vs paint viewport sizes.
  pub fn with_viewport_scrollbar_gutter_reserved_axes(
    mut self,
    reserved_x: bool,
    reserved_y: bool,
  ) -> Self {
    self.viewport_scrollbar_gutter_reserved_x = reserved_x;
    self.viewport_scrollbar_gutter_reserved_y = reserved_y;
    self
  }

  /// Like [`DisplayListRenderer::with_viewport_scrollbar_gutter_reserved_axes`], but mutates an
  /// existing renderer.
  pub fn set_viewport_scrollbar_gutter_reserved_axes(
    &mut self,
    reserved_x: bool,
    reserved_y: bool,
  ) {
    self.viewport_scrollbar_gutter_reserved_x = reserved_x;
    self.viewport_scrollbar_gutter_reserved_y = reserved_y;
  }

  fn new_with_canvas(
    canvas: Canvas,
    background: Rgba,
    font_ctx: FontContext,
    scale: f32,
    color_renderer: ColorFontRenderer,
    color_cache: Arc<Mutex<ColorGlyphCache>>,
    glyph_cache: Arc<Mutex<GlyphCache>>,
  ) -> Result<Self> {
    let scale = if scale.is_finite() && scale > 0.0 {
      scale
    } else {
      1.0
    };
    let toggles = crate::debug::runtime::runtime_toggles();
    let image_cache_items = toggles.usize_with_default(
      ENV_IMAGE_PIXMAP_CACHE_ITEMS,
      DEFAULT_IMAGE_PIXMAP_CACHE_ITEMS,
    );
    let image_cache_bytes = toggles.usize_with_default(
      ENV_IMAGE_PIXMAP_CACHE_BYTES,
      DEFAULT_IMAGE_PIXMAP_CACHE_BYTES,
    );
    let diagnostics_enabled = paint_diagnostics_enabled();
    Ok(Self {
      canvas,
      font_ctx,
      color_cache,
      color_renderer,
      glyph_cache,
      stacking_layers: Vec::new(),
      blend_stack: Vec::new(),
      opacity_stack: Vec::new(),
      scale,
      viewport_scrollbar_gutter_reserved_x: false,
      viewport_scrollbar_gutter_reserved_y: false,
      transform_stack: vec![Transform3D::identity()],
      perspective_stack: vec![Transform3D::identity()],
      culled_depth: 0,
      preserve_3d_disabled: runtime_flag("FASTR_PRESERVE3D_DISABLE_SCENE"),
      preserve_3d_scene_depth: 0,
      projective_warp_enabled: projective_warp_enabled(),
      projective_warp_depth: 0,
      preserve_3d_debug: runtime_flag("FASTR_PRESERVE3D_DEBUG"),
      background,
      paint_parallelism: PaintParallelism::default(),
      image_cache: ImagePixmapCache::new(image_cache_items, image_cache_bytes),
      cropped_image_cache: LruCache::new(
        NonZeroUsize::new(CROPPED_IMAGE_CACHE_CAPACITY)
          .unwrap_or_else(|| NonZeroUsize::new(1).expect("nonzero")),
      ),
      scaled_image_cache: LruCache::new(
        NonZeroUsize::new(SCALED_IMAGE_CACHE_CAPACITY)
          .unwrap_or_else(|| NonZeroUsize::new(1).expect("nonzero")),
      ),
      shared_image_pixmaps: None,
      #[cfg(test)]
      image_cache_misses: Arc::new(AtomicUsize::new(0)),
      image_pixmap_diagnostics: diagnostics_enabled
        .then(|| Arc::new(ImagePixmapDiagnostics::default())),
      background_paint_diagnostics: diagnostics_enabled
        .then(|| Arc::new(BackgroundPaintDiagnostics::default())),
      clip_mask_diagnostics: diagnostics_enabled.then(|| Arc::new(ClipMaskDiagnostics::default())),
      layer_alloc_diagnostics: diagnostics_enabled
        .then(|| Arc::new(LayerAllocationDiagnostics::default())),
      backdrop_composite_diagnostics: diagnostics_enabled
        .then(|| Arc::new(BackdropCompositeDiagnostics::default())),
      warp_cache: WarpCache::new(WARP_CACHE_CAPACITY),
      blur_cache: BlurCache::default(),
      shared_blur_cache: None,
      backdrop_filter_cache: BackdropFilterCache::default(),
      shared_backdrop_filter_cache: None,
      gradient_cache: GradientLutCache::default(),
      gradient_pixmap_cache: GradientPixmapCache::default(),
      gradient_stats: GradientStats::default(),
      diagnostics_enabled,
      trace_backdrop_stack: runtime_flag("FASTR_TRACE_BACKDROP_STACK"),
      backdrop_composite_cache: LruCache::new(
        NonZeroUsize::new(BACKDROP_COMPOSITE_CACHE_CAPACITY)
          .unwrap_or_else(|| NonZeroUsize::new(1).expect("nonzero")),
      ),
      backdrop_composite_cache_enabled: true,
      canvas_mutations: vec![0],
    })
  }

  fn new_with_text_state_from_existing_pixmap(
    pixmap: Pixmap,
    background: Rgba,
    font_ctx: FontContext,
    scale: f32,
    color_renderer: ColorFontRenderer,
    color_cache: Arc<Mutex<ColorGlyphCache>>,
    glyph_cache: Arc<Mutex<GlyphCache>>,
  ) -> Result<Self> {
    let scale = if scale.is_finite() && scale > 0.0 {
      scale
    } else {
      1.0
    };
    let text_rasterizer = TextRasterizer::with_caches(
      glyph_cache.clone(),
      color_renderer.clone(),
      color_cache.clone(),
    );
    let canvas = Canvas::from_pixmap_with_text_rasterizer(pixmap, text_rasterizer);
    Self::new_with_canvas(
      canvas,
      background,
      font_ctx,
      scale,
      color_renderer,
      color_cache,
      glyph_cache,
    )
  }

  fn new_with_text_state(
    device_width: u32,
    device_height: u32,
    background: Rgba,
    font_ctx: FontContext,
    scale: f32,
    color_renderer: ColorFontRenderer,
    color_cache: Arc<Mutex<ColorGlyphCache>>,
    glyph_cache: Arc<Mutex<GlyphCache>>,
  ) -> Result<Self> {
    let scale = if scale.is_finite() && scale > 0.0 {
      scale
    } else {
      1.0
    };
    let text_rasterizer = TextRasterizer::with_caches(
      glyph_cache.clone(),
      color_renderer.clone(),
      color_cache.clone(),
    );
    let canvas = Canvas::new_with_text_rasterizer(
      device_width.max(1),
      device_height.max(1),
      background,
      text_rasterizer,
    )?;
    Self::new_with_canvas(
      canvas,
      background,
      font_ctx,
      scale,
      color_renderer,
      color_cache,
      glyph_cache,
    )
  }

  #[inline]
  fn record_gradient_usage(&mut self, pixels: u64, start: Instant) {
    if self.diagnostics_enabled {
      self.gradient_stats.record(pixels, start.elapsed());
    }
  }

  #[inline]
  fn record_layer_allocation(&self, width: u32, height: u32) {
    if let Some(diag) = self.layer_alloc_diagnostics.as_ref() {
      diag.record(width, height);
    }
  }

  #[inline]
  fn record_backdrop_composite_allocation(&self, width: u32, height: u32) {
    if let Some(diag) = self.backdrop_composite_diagnostics.as_ref() {
      diag.record_allocation(width, height);
    }
  }

  #[inline]
  fn record_backdrop_composite_cache_hit(&self) {
    if let Some(diag) = self.backdrop_composite_diagnostics.as_ref() {
      diag.record_hit();
    }
  }

  #[inline]
  fn record_backdrop_composite_cache_miss(&self) {
    if let Some(diag) = self.backdrop_composite_diagnostics.as_ref() {
      diag.record_miss();
    }
  }

  #[inline]
  fn mark_current_pixmap_mutated(&mut self) {
    debug_assert_eq!(
      self.canvas_mutations.len(),
      self.canvas.layer_stack_len().saturating_add(1),
      "canvas mutation stack must track the canvas layer stack"
    );
    if let Some(counter) = self.canvas_mutations.last_mut() {
      *counter = counter.wrapping_add(1);
    }
  }

  #[inline]
  fn push_layer_mutation_state(&mut self) {
    self.canvas_mutations.push(0);
  }

  #[inline]
  fn pop_layer_mutation_state(&mut self) {
    let _ = self.canvas_mutations.pop();
  }

  #[inline]
  fn push_layer_tracked(&mut self, opacity: f32, is_backdrop_root: bool) -> Result<()> {
    self
      .canvas
      .push_layer_with_blend_and_backdrop_root(opacity, None, is_backdrop_root)?;
    self.push_layer_mutation_state();
    Ok(())
  }

  #[inline]
  fn push_layer_with_blend_tracked(
    &mut self,
    opacity: f32,
    blend: Option<SkiaBlendMode>,
    is_backdrop_root: bool,
  ) -> Result<()> {
    self
      .canvas
      .push_layer_with_blend_and_backdrop_root(opacity, blend, is_backdrop_root)?;
    self.push_layer_mutation_state();
    Ok(())
  }

  #[inline]
  fn push_layer_with_blend_initialized_from_backdrop_tracked(
    &mut self,
    opacity: f32,
    blend: Option<SkiaBlendMode>,
    is_backdrop_root: bool,
  ) -> Result<()> {
    self
      .canvas
      .push_layer_with_blend_initialized_from_backdrop_and_backdrop_root(
        opacity,
        blend,
        is_backdrop_root,
      )?;
    self.push_layer_mutation_state();
    Ok(())
  }

  #[inline]
  fn push_layer_bounded_tracked(
    &mut self,
    opacity: f32,
    blend: Option<SkiaBlendMode>,
    bounds: Rect,
    is_backdrop_root: bool,
  ) -> Result<()> {
    self
      .canvas
      .push_layer_bounded_with_backdrop_root(opacity, blend, bounds, is_backdrop_root)?;
    self.push_layer_mutation_state();
    Ok(())
  }

  #[inline]
  fn push_layer_bounded_unclipped_tracked(
    &mut self,
    opacity: f32,
    blend: Option<SkiaBlendMode>,
    bounds: Rect,
    is_backdrop_root: bool,
  ) -> Result<()> {
    self
      .canvas
      .push_layer_bounded_unclipped_with_backdrop_root(opacity, blend, bounds, is_backdrop_root)?;
    self.push_layer_mutation_state();
    Ok(())
  }

  #[inline]
  fn pop_layer_tracked(&mut self) -> Result<()> {
    self.canvas.pop_layer()?;
    self.pop_layer_mutation_state();
    // Compositing the popped layer mutates the restored parent pixmap.
    self.mark_current_pixmap_mutated();
    Ok(())
  }

  #[inline]
  fn pop_layer_raw_tracked(&mut self) -> Result<(Pixmap, (i32, i32), f32, Option<SkiaBlendMode>)> {
    let popped = self.canvas.pop_layer_raw()?;
    self.pop_layer_mutation_state();
    Ok(popped)
  }

  #[inline]
  fn composite_layer_tracked(
    &mut self,
    layer: &Pixmap,
    opacity: f32,
    blend: Option<SkiaBlendMode>,
    origin: (i32, i32),
  ) {
    self.canvas.composite_layer(layer, opacity, blend, origin);
    self.mark_current_pixmap_mutated();
  }

  #[inline]
  fn blur_cache_mut(&mut self) -> &mut (dyn BlurCacheOps + 'static) {
    match self.shared_blur_cache.as_mut() {
      Some(shared) => shared,
      None => &mut self.blur_cache,
    }
  }

  #[inline]
  fn backdrop_filter_cache_mut(&mut self) -> &mut (dyn BackdropFilterCacheOps + 'static) {
    match self.shared_backdrop_filter_cache.as_mut() {
      Some(shared) => shared,
      None => &mut self.backdrop_filter_cache,
    }
  }

  #[inline]
  fn record_background_paint(&self, start: Option<Instant>) {
    if let (Some(diag), Some(start)) = (self.background_paint_diagnostics.as_ref(), start) {
      diag.record_duration(start.elapsed());
    }
  }

  fn gradient_visible_rect(&self, rect_device: Rect) -> Option<Rect> {
    if rect_device.width() <= 0.0
      || rect_device.height() <= 0.0
      || !rect_device.x().is_finite()
      || !rect_device.y().is_finite()
    {
      return None;
    }

    let mut visible_device = self.canvas.bounds();
    if let Some(clip) = self.canvas.clip_bounds() {
      visible_device = visible_device.intersection(clip)?;
    }

    if visible_device.width() <= 0.0 || visible_device.height() <= 0.0 {
      return None;
    }

    let transform = self.canvas.transform();
    let visible_local = if transform == Transform::identity() {
      visible_device
    } else {
      let inv = invert_transform(transform)?;
      transform_rect(visible_device, &inv)
    };

    let clipped = rect_device.intersection(visible_local)?;
    if clipped.width() <= 0.0 || clipped.height() <= 0.0 {
      return None;
    }
    Some(clipped)
  }

  fn render_linear_gradient(&mut self, item: &LinearGradientItem) -> Result<()> {
    let rect = self.ds_rect(item.rect);
    let visible_rect = match self.gradient_visible_rect(rect) {
      Some(r) => r,
      None => return Ok(()),
    };

    let Some(stops) = self.convert_stops_rgba(&item.stops) else {
      return Ok(());
    };

    let offset_x = visible_rect.x() - rect.x();
    let offset_y = visible_rect.y() - rect.y();
    let start = Point::new(
      self.ds_len(item.start.x) - offset_x,
      self.ds_len(item.start.y) - offset_y,
    );
    let end = Point::new(
      self.ds_len(item.end.x) - offset_x,
      self.ds_len(item.end.y) - offset_y,
    );
    let spread = match item.spread {
      crate::paint::display_list::GradientSpread::Pad => SpreadMode::Pad,
      crate::paint::display_list::GradientSpread::Repeat => SpreadMode::Repeat,
      crate::paint::display_list::GradientSpread::Reflect => SpreadMode::Reflect,
    };

    let original_width = rect.width().ceil().max(0.0) as u32;
    let original_height = rect.height().ceil().max(0.0) as u32;
    let background_timer = self
      .background_paint_diagnostics
      .as_ref()
      .map(|_| Instant::now());
    let timer = self.diagnostics_enabled.then(Instant::now);
    let canvas_transform = self.canvas.transform();

    // Fast path: paint directly into the destination surface when the gradient is axis-aligned and
    // uses a normal source-over blend. This matches Skia/Chrome's behavior more closely for
    // partially-transparent gradients by applying ordered dithering *after* blending, rather than
    // rasterizing into an intermediate u8 pixmap and then compositing.
    //
    // Keep this conservative: it intentionally opts out when fractional positioning/transform/clip
    // would require resampling or partial coverage at the edges.
    let translation_only = (canvas_transform.sx - 1.0).abs() <= 1e-6
      && (canvas_transform.sy - 1.0).abs() <= 1e-6
      && canvas_transform.kx.abs() <= 1e-6
      && canvas_transform.ky.abs() <= 1e-6
      && canvas_transform.tx.is_finite()
      && canvas_transform.ty.is_finite();
    let tx = canvas_transform.tx.round();
    let ty = canvas_transform.ty.round();
    let translation_integral = (canvas_transform.tx - tx).abs() <= 1e-6
      && (canvas_transform.ty - ty).abs() <= 1e-6
      && tx >= i32::MIN as f32
      && tx <= i32::MAX as f32
      && ty >= i32::MIN as f32
      && ty <= i32::MAX as f32;

    // When the gradient rect lands on fractional device pixels, the generic pixmap + draw_pixmap
    // path below must avoid expanding to the `floor/ceil` bounds of the rect. Otherwise it can
    // overwrite adjacent 1px borders (e.g. python.org top-bar active tab covering the bar's bottom
    // border). For source-over gradients under a translation-only integer transform, we can paint
    // directly into the destination surface using the same pixel-center inclusion rule as
    // axis-aligned opaque rect fills.
    if translation_only
      && translation_integral
      && self.canvas.blend_mode() == SkiaBlendMode::SourceOver
    {
      let clip_mask = self.canvas.clip_mask_rc();

      // Pixel-center bounds in *device* space: a device pixel at coordinate `i` is covered if its
      // center `i + 0.5` lies within the gradient rect.
      let mut x0 = (visible_rect.min_x() + tx - 0.5).ceil();
      let mut y0 = (visible_rect.min_y() + ty - 0.5).ceil();
      let mut x1 = (visible_rect.max_x() + tx - 0.5).ceil();
      let mut y1 = (visible_rect.max_y() + ty - 0.5).ceil();

      x0 = x0.clamp(0.0, self.canvas.width() as f32);
      y0 = y0.clamp(0.0, self.canvas.height() as f32);
      x1 = x1.clamp(0.0, self.canvas.width() as f32);
      y1 = y1.clamp(0.0, self.canvas.height() as f32);

      let x0_i32 = x0 as i32;
      let y0_i32 = y0 as i32;
      let x1_i32 = x1 as i32;
      let y1_i32 = y1 as i32;
      if x0_i32 < x1_i32 && y0_i32 < y1_i32 {
        let width = (x1_i32 - x0_i32) as u32;
        let height = (y1_i32 - y0_i32) as u32;

        let tx_i32 = tx as i32;
        let ty_i32 = ty as i32;
        let origin_x = x0_i32.wrapping_sub(tx_i32);
        let origin_y = y0_i32.wrapping_sub(ty_i32);
        let dither_phase = (((origin_y & 7) as u8) << 3) | ((origin_x & 7) as u8);

        // Convert gradient start/end points into the local coordinate space of the painted pixel
        // rect.
        let start_abs_x = rect.x() + tx + self.ds_len(item.start.x);
        let start_abs_y = rect.y() + ty + self.ds_len(item.start.y);
        let end_abs_x = rect.x() + tx + self.ds_len(item.end.x);
        let end_abs_y = rect.y() + ty + self.ds_len(item.end.y);
        let start_rel = Point::new(start_abs_x - x0_i32 as f32, start_abs_y - y0_i32 as f32);
        let end_rel = Point::new(end_abs_x - x0_i32 as f32, end_abs_y - y0_i32 as f32);

        self
          .canvas
          .with_mirrored_pixmap_mut_result(|pixmap| -> Result<()> {
            paint_linear_gradient_src_over_mut(
              pixmap,
              x0_i32,
              y0_i32,
              width,
              height,
              start_rel,
              end_rel,
              spread,
              &stops,
              &self.gradient_cache,
              gradient_bucket(original_width.max(original_height)),
              dither_phase,
              clip_mask.as_deref(),
            )
            .map_err(Error::Render)?;
            Ok(())
          })?;
        if let Some(start) = timer {
          self.record_gradient_usage((width * height) as u64, start);
        }
        self.record_background_paint(background_timer);
        return Ok(());
      }
    }

    let width = visible_rect.width().ceil() as u32;
    let height = visible_rect.height().ceil() as u32;
    if width == 0 || height == 0 {
      return Ok(());
    }
    let dest_x = visible_rect.x().floor() as i32;
    let dest_y = visible_rect.y().floor() as i32;
    let dither_phase = (((dest_y & 7) as u8) << 3) | ((dest_x & 7) as u8);
    let Some(pix) = rasterize_linear_gradient_cached(
      &self.gradient_pixmap_cache,
      width,
      height,
      start,
      end,
      spread,
      &stops,
      &self.gradient_cache,
      gradient_bucket(original_width.max(original_height)),
      dither_phase,
    )?
    else {
      return Ok(());
    };
    if let Some(start) = timer {
      self.record_gradient_usage((width * height) as u64, start);
    }

    let frac_x = visible_rect.x() - dest_x as f32;
    let frac_y = visible_rect.y() - dest_y as f32;
    let canvas_transform = self.canvas.transform();
    let needs_filtering = canvas_transform.kx.abs() > 1e-6
      || canvas_transform.ky.abs() > 1e-6
      || (canvas_transform.sx - 1.0).abs() > 1e-6
      || (canvas_transform.sy - 1.0).abs() > 1e-6
      || canvas_transform.tx.fract().abs() > 1e-6
      || canvas_transform.ty.fract().abs() > 1e-6
      || frac_x.abs() > 1e-6
      || frac_y.abs() > 1e-6;
    let paint = tiny_skia::PixmapPaint {
      opacity: 1.0,
      blend_mode: self.canvas.blend_mode(),
      quality: if needs_filtering {
        FilterQuality::Bilinear
      } else {
        FilterQuality::Nearest
      },
    };
    let transform = Transform::from_translate(frac_x, frac_y).post_concat(canvas_transform);
    let clip = self.canvas.clip_mask_rc();
    self.canvas.with_mirrored_pixmap_mut(|pixmap| {
      pixmap.draw_pixmap(
        dest_x,
        dest_y,
        pix.as_ref().as_ref(),
        &paint,
        transform,
        clip.as_deref(),
      );
    });
    self.record_background_paint(background_timer);
    Ok(())
  }

  fn render_linear_gradient_pattern(&mut self, item: &LinearGradientPatternItem) -> Result<()> {
    let opacity = self.canvas.opacity().clamp(0.0, 1.0);
    if opacity <= 0.0 {
      return Ok(());
    }

    // Fast path: when the destination rect falls entirely within a single tile, we can render the
    // gradient directly without rasterizing a tile pixmap and sampling it through a scaled
    // repeating pattern. This avoids resampling artifacts when the tile size is fractional at
    // device scale (common for `background-size` / `repeat-round`).
    let tile_w_css = item.tile_size.width;
    let tile_h_css = item.tile_size.height;
    let dest_w_css = item.dest_rect.width();
    let dest_h_css = item.dest_rect.height();
    if tile_w_css > 0.0
      && tile_h_css > 0.0
      && dest_w_css > 0.0
      && dest_h_css > 0.0
      && tile_w_css.is_finite()
      && tile_h_css.is_finite()
      && dest_w_css.is_finite()
      && dest_h_css.is_finite()
      && item.dest_rect.x().is_finite()
      && item.dest_rect.y().is_finite()
      && item.origin.x.is_finite()
      && item.origin.y.is_finite()
    {
      let mut phase_x = (item.dest_rect.x() - item.origin.x).rem_euclid(tile_w_css);
      let mut phase_y = (item.dest_rect.y() - item.origin.y).rem_euclid(tile_h_css);
      // Floating-point rounding can occasionally produce a remainder equal to the divisor for
      // large values; clamp that back to 0 so we keep the phase in `[0, tile)` as intended.
      const PHASE_EPS: f32 = 1e-4;
      if phase_x >= tile_w_css || phase_x.abs() <= PHASE_EPS {
        phase_x = 0.0;
      }
      if phase_y >= tile_h_css || phase_y.abs() <= PHASE_EPS {
        phase_y = 0.0;
      }

      let single_tile_x = phase_x + dest_w_css <= tile_w_css + PHASE_EPS;
      let single_tile_y = phase_y + dest_h_css <= tile_h_css + PHASE_EPS;
      if single_tile_x && single_tile_y {
        let direct = LinearGradientItem {
          rect: item.dest_rect,
          start: Point::new(item.start.x - phase_x, item.start.y - phase_y),
          end: Point::new(item.end.x - phase_x, item.end.y - phase_y),
          stops: item.stops.clone(),
          spread: item.spread,
        };
        return self.render_linear_gradient(&direct);
      }
    }

    let dest_rect = self.ds_rect(item.dest_rect);
    let visible_rect = match self.gradient_visible_rect(dest_rect) {
      Some(r) => r,
      None => return Ok(()),
    };

    let tile_w = self.ds_len(item.tile_size.width);
    let tile_h = self.ds_len(item.tile_size.height);
    if tile_w <= 0.0 || tile_h <= 0.0 || !tile_w.is_finite() || !tile_h.is_finite() {
      return Ok(());
    }

    let canvas_transform = self.canvas.transform();

    let width = tile_w.ceil().max(1.0) as u32;
    let height = tile_h.ceil().max(1.0) as u32;
    if width == 0 || height == 0 {
      return Ok(());
    }

    let Some(stops) = self.convert_stops_rgba(&item.stops) else {
      return Ok(());
    };

    let origin = self.ds_point(item.origin);
    let start_tile = Point::new(self.ds_len(item.start.x), self.ds_len(item.start.y));
    let end_tile = Point::new(self.ds_len(item.end.x), self.ds_len(item.end.y));
    let spread = match item.spread {
      crate::paint::display_list::GradientSpread::Pad => SpreadMode::Pad,
      crate::paint::display_list::GradientSpread::Repeat => SpreadMode::Repeat,
      crate::paint::display_list::GradientSpread::Reflect => SpreadMode::Reflect,
    };

    // The tile pixmap is rasterized at an integer pixel size, then scaled via the pattern shader
    // so the repetition period matches `tile_w/tile_h` exactly (which can be fractional at device
    // scale). Convert gradient geometry from tile-space (device px) into the raster pixmap's
    // coordinate space so scaling the pixmap back preserves the intended gradient geometry.
    let raster_scale_x = width as f32 / tile_w;
    let raster_scale_y = height as f32 / tile_h;
    if !raster_scale_x.is_finite() || !raster_scale_y.is_finite() {
      return Ok(());
    }

    let background_timer = self
      .background_paint_diagnostics
      .as_ref()
      .map(|_| Instant::now());
    let timer = self.diagnostics_enabled.then(Instant::now);

    // Fast path: if the visible portion of the destination rectangle fits entirely within a
    // single pattern tile, paint the gradient directly into the destination surface.
    //
    // This avoids rasterizing the full backing tile and more closely matches Skia/Chrome for
    // partially-transparent gradients by applying ordered dithering after the source-over blend.
    //
    // Keep this conservative: it requires an identity canvas transform and no clip mask.
    let visible_x = visible_rect.x();
    let visible_y = visible_rect.y();
    let dest_x = visible_x.floor() as i32;
    let dest_y = visible_y.floor() as i32;
    let visible_w = visible_rect.width().ceil() as u32;
    let visible_h = visible_rect.height().ceil() as u32;
    let visible_rect_is_pixel_aligned = (visible_x - dest_x as f32).abs() <= 1e-6
      && (visible_y - dest_y as f32).abs() <= 1e-6
      && (visible_rect.width() - visible_w as f32).abs() <= 1e-6
      && (visible_rect.height() - visible_h as f32).abs() <= 1e-6;
    let needs_pattern_repeat_x = ((visible_rect.min_x() - origin.x) / tile_w).floor();
    let needs_pattern_repeat_y = ((visible_rect.min_y() - origin.y) / tile_h).floor();
    let tile_origin_x = origin.x + needs_pattern_repeat_x * tile_w;
    let tile_origin_y = origin.y + needs_pattern_repeat_y * tile_h;
    let visible_in_single_tile = tile_origin_x.is_finite()
      && tile_origin_y.is_finite()
      && visible_rect.min_x() >= tile_origin_x - 1e-6
      && visible_rect.min_y() >= tile_origin_y - 1e-6
      && visible_rect.max_x() <= tile_origin_x + tile_w + 1e-6
      && visible_rect.max_y() <= tile_origin_y + tile_h + 1e-6;
    let translation_only = (canvas_transform.sx - 1.0).abs() <= 1e-6
      && (canvas_transform.sy - 1.0).abs() <= 1e-6
      && canvas_transform.kx.abs() <= 1e-6
      && canvas_transform.ky.abs() <= 1e-6
      && canvas_transform.tx.is_finite()
      && canvas_transform.ty.is_finite();
    let tx = canvas_transform.tx.round();
    let ty = canvas_transform.ty.round();
    let translation_integral = (canvas_transform.tx - tx).abs() <= 1e-6
      && (canvas_transform.ty - ty).abs() <= 1e-6
      && tx >= i32::MIN as f32
      && tx <= i32::MAX as f32
      && ty >= i32::MIN as f32
      && ty <= i32::MAX as f32;
    let dest_x_dev = dest_x.saturating_add(tx as i32);
    let dest_y_dev = dest_y.saturating_add(ty as i32);
    if opacity >= 1.0 - f32::EPSILON
      && visible_rect_is_pixel_aligned
      && visible_in_single_tile
      && translation_only
      && translation_integral
      && self.canvas.clip_mask().is_none()
      && self.canvas.blend_mode() == SkiaBlendMode::SourceOver
    {
      let offset_x = visible_x - tile_origin_x;
      let offset_y = visible_y - tile_origin_y;
      let start = Point::new(start_tile.x - offset_x, start_tile.y - offset_y);
      let end = Point::new(end_tile.x - offset_x, end_tile.y - offset_y);
      let dither_phase = (((dest_y & 7) as u8) << 3) | ((dest_x & 7) as u8);
      self
        .canvas
        .with_mirrored_pixmap_mut_result(|pixmap| -> Result<()> {
          paint_linear_gradient_src_over_mut(
            pixmap,
            dest_x_dev,
            dest_y_dev,
            visible_w,
            visible_h,
            start,
            end,
            spread,
            &stops,
            &self.gradient_cache,
            gradient_bucket(width.max(height)),
            dither_phase,
            None,
          )
          .map_err(Error::Render)?;
          Ok(())
        })?;
      if let Some(start) = timer {
        self.record_gradient_usage((visible_w * visible_h) as u64, start);
      }
      self.record_background_paint(background_timer);
      return Ok(());
    }

    let origin_x = origin.x.floor() as i32;
    let origin_y = origin.y.floor() as i32;
    let dither_phase = (((origin_y & 7) as u8) << 3) | ((origin_x & 7) as u8);

    let start = Point::new(start_tile.x * raster_scale_x, start_tile.y * raster_scale_y);
    let end = Point::new(end_tile.x * raster_scale_x, end_tile.y * raster_scale_y);

    let Some(tile) = rasterize_linear_gradient_cached(
      &self.gradient_pixmap_cache,
      width,
      height,
      start,
      end,
      spread,
      &stops,
      &self.gradient_cache,
      gradient_bucket(width.max(height)),
      dither_phase,
    )?
    else {
      return Ok(());
    };
    if let Some(start) = timer {
      self.record_gradient_usage((width * height) as u64, start);
    }

    let scale_x = tile_w / tile.width() as f32;
    let scale_y = tile_h / tile.height() as f32;
    if !scale_x.is_finite() || !scale_y.is_finite() {
      return Ok(());
    }

    let clip_mask = self.canvas.clip_mask_rc();

    let axis_aligned = canvas_transform.kx.abs() <= 1e-6 && canvas_transform.ky.abs() <= 1e-6;
    let can_invert = canvas_transform.sx.is_finite()
      && canvas_transform.sy.is_finite()
      && canvas_transform.sx.abs() > 1e-6
      && canvas_transform.sy.abs() > 1e-6;

    if axis_aligned && can_invert {
      let bounds = transform_rect(dest_rect, &canvas_transform);
      let mut x0 = (bounds.min_x() - 0.5).ceil();
      let mut y0 = (bounds.min_y() - 0.5).ceil();
      let mut x1 = (bounds.max_x() - 0.5).ceil();
      let mut y1 = (bounds.max_y() - 0.5).ceil();

      x0 = x0.clamp(0.0, self.canvas.width() as f32);
      y0 = y0.clamp(0.0, self.canvas.height() as f32);
      x1 = x1.clamp(0.0, self.canvas.width() as f32);
      y1 = y1.clamp(0.0, self.canvas.height() as f32);

      let x0_u32 = x0 as u32;
      let y0_u32 = y0 as u32;
      let x1_u32 = x1 as u32;
      let y1_u32 = y1 as u32;
      if x0_u32 >= x1_u32 || y0_u32 >= y1_u32 {
        self.record_background_paint(background_timer);
        return Ok(());
      }

      let tmp_w = x1_u32 - x0_u32;
      let tmp_h = y1_u32 - y0_u32;
      let Some(mut tmp) = new_pixmap(tmp_w, tmp_h) else {
        // Allocation failed; fall back to tiny-skia's pattern fill.
        // (This may reintroduce parallel seams, but failing to paint is worse.)
        let mut paint = tiny_skia::Paint::default();
        paint.shader = Pattern::new(
          tile.as_ref().as_ref(),
          SpreadMode::Repeat,
          tiny_skia::FilterQuality::Nearest,
          opacity,
          Transform::from_row(scale_x, 0.0, 0.0, scale_y, origin.x, origin.y),
        );
        paint.anti_alias = false;
        paint.blend_mode = self.canvas.blend_mode();

        let Some(skia_rect) = tiny_skia::Rect::from_xywh(
          dest_rect.x(),
          dest_rect.y(),
          dest_rect.width(),
          dest_rect.height(),
        ) else {
          self.record_background_paint(background_timer);
          return Ok(());
        };
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          pixmap.fill_rect(skia_rect, &paint, canvas_transform, clip_mask.as_deref());
        });
        self.record_background_paint(background_timer);
        return Ok(());
      };

      let src_w = tile.width();
      let src_h = tile.height();
      if src_w == 0 || src_h == 0 {
        self.record_background_paint(background_timer);
        return Ok(());
      }

      let src_w_i64 = src_w as i64;
      let src_h_i64 = src_h as i64;
      let inv_canvas_sx = 1.0f64 / canvas_transform.sx as f64;
      let inv_canvas_sy = 1.0f64 / canvas_transform.sy as f64;
      let canvas_tx = canvas_transform.tx as f64;
      let canvas_ty = canvas_transform.ty as f64;
      let origin_x = origin.x as f64;
      let origin_y = origin.y as f64;
      let pattern_scale_x = scale_x as f64;
      let pattern_scale_y = scale_y as f64;
      if !pattern_scale_x.is_finite() || !pattern_scale_y.is_finite() {
        self.record_background_paint(background_timer);
        return Ok(());
      }

      let mut xs: Vec<u32> = Vec::new();
      let mut ys: Vec<u32> = Vec::new();
      if xs.try_reserve_exact(tmp_w as usize).is_ok()
        && ys.try_reserve_exact(tmp_h as usize).is_ok()
      {
        for x in 0..tmp_w {
          let dx = (x0_u32 + x) as f64 + 0.5;
          let local_x = (dx - canvas_tx) * inv_canvas_sx;
          let rel_x = local_x - origin_x;
          let src_x = rel_x / pattern_scale_x - 0.5;
          let ix = (src_x + 0.5).floor() as i64;
          let ix = ix.rem_euclid(src_w_i64) as u32;
          xs.push(ix);
        }
        for y in 0..tmp_h {
          let dy = (y0_u32 + y) as f64 + 0.5;
          let local_y = (dy - canvas_ty) * inv_canvas_sy;
          let rel_y = local_y - origin_y;
          let src_y = rel_y / pattern_scale_y - 0.5;
          let iy = (src_y + 0.5).floor() as i64;
          let iy = iy.rem_euclid(src_h_i64) as u32;
          ys.push(iy);
        }

        let src = tile.data();
        let dst = tmp.data_mut();
        let src_stride = src_w as usize * 4;
        let dst_stride = tmp_w as usize * 4;

        let mut deadline_counter = 0usize;
        for (y, &iy) in ys.iter().enumerate() {
          check_active_periodic(&mut deadline_counter, 128, RenderStage::Paint)
            .map_err(Error::Render)?;
          let row_src = iy as usize * src_stride;
          let row_dst = y * dst_stride;
          for (x, &ix) in xs.iter().enumerate() {
            let src_idx = row_src + ix as usize * 4;
            let dst_idx = row_dst + x * 4;
            dst[dst_idx..dst_idx + 4].copy_from_slice(&src[src_idx..src_idx + 4]);
          }
        }

        let blend_mode = self.canvas.blend_mode();
        let clip = clip_mask.as_deref();
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          composite_layer_into_pixmap_mut(
            pixmap,
            &tmp,
            opacity,
            blend_mode,
            (x0_u32 as i32, y0_u32 as i32),
            clip,
          );
        });

        self.record_background_paint(background_timer);
        return Ok(());
      }

      // Allocation failed; fall back to tiny-skia's pattern fill below.
    }

    let mut paint = tiny_skia::Paint::default();
    paint.shader = Pattern::new(
      tile.as_ref().as_ref(),
      SpreadMode::Repeat,
      tiny_skia::FilterQuality::Nearest,
      opacity,
      Transform::from_row(scale_x, 0.0, 0.0, scale_y, origin.x, origin.y),
    );
    paint.anti_alias = false;
    paint.blend_mode = self.canvas.blend_mode();

    let Some(skia_rect) = tiny_skia::Rect::from_xywh(
      dest_rect.x(),
      dest_rect.y(),
      dest_rect.width(),
      dest_rect.height(),
    ) else {
      return Ok(());
    };
    let transform = canvas_transform;

    let bounds = transform_rect(dest_rect, &transform);
    let needs_scratch = bounds.min_x() < 0.0
      || bounds.min_y() < 0.0
      || bounds.max_x() > self.canvas.width() as f32
      || bounds.max_y() > self.canvas.height() as f32;

    if needs_scratch {
      // When the pattern rect extends beyond the tile pixmap, tiny-skia's pattern fill can become
      // sensitive to the raster surface clip bounds, producing seams between tiles. Avoid this by
      // drawing into a scratch pixmap that fully contains the transformed destination rect, then
      // copying the affected pixels back.
      const PATTERN_SCRATCH_MARGIN_PX: i64 = 2;

      let mut x0 = bounds.min_x().floor() as i64;
      let mut y0 = bounds.min_y().floor() as i64;
      let mut x1 = bounds.max_x().ceil() as i64;
      let mut y1 = bounds.max_y().ceil() as i64;
      x0 = x0.saturating_sub(PATTERN_SCRATCH_MARGIN_PX);
      y0 = y0.saturating_sub(PATTERN_SCRATCH_MARGIN_PX);
      x1 = x1.saturating_add(PATTERN_SCRATCH_MARGIN_PX);
      y1 = y1.saturating_add(PATTERN_SCRATCH_MARGIN_PX);

      let scratch_w_i64 = x1 - x0;
      let scratch_h_i64 = y1 - y0;
      let Ok(scratch_w) = u32::try_from(scratch_w_i64) else {
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          pixmap.fill_rect(skia_rect, &paint, transform, clip_mask.as_deref());
        });
        self.record_background_paint(background_timer);
        return Ok(());
      };
      let Ok(scratch_h) = u32::try_from(scratch_h_i64) else {
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          pixmap.fill_rect(skia_rect, &paint, transform, clip_mask.as_deref());
        });
        self.record_background_paint(background_timer);
        return Ok(());
      };
      if scratch_w == 0 || scratch_h == 0 {
        self.record_background_paint(background_timer);
        return Ok(());
      }

      let dest_w = self.canvas.width() as i64;
      let dest_h = self.canvas.height() as i64;
      let inter_x0 = x0.max(0);
      let inter_y0 = y0.max(0);
      let inter_x1 = x1.min(dest_w);
      let inter_y1 = y1.min(dest_h);
      if inter_x1 <= inter_x0 || inter_y1 <= inter_y0 {
        self.record_background_paint(background_timer);
        return Ok(());
      }

      let Some(mut tmp) = new_pixmap(scratch_w, scratch_h) else {
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          pixmap.fill_rect(skia_rect, &paint, transform, clip_mask.as_deref());
        });
        self.record_background_paint(background_timer);
        return Ok(());
      };
      tmp.data_mut().fill(0);

      // Seed scratch with the destination contents so blending matches a direct fill.
      {
        let src = self.canvas.pixmap_ref().data();
        let dst = tmp.data_mut();
        let src_stride = self.canvas.width() as usize * 4;
        let dst_stride = scratch_w as usize * 4;
        let copy_w = (inter_x1 - inter_x0) as usize;
        let copy_h = (inter_y1 - inter_y0) as usize;
        let row_bytes = copy_w * 4;
        let src_x = inter_x0 as usize * 4;
        let dst_x = (inter_x0 - x0) as usize * 4;
        let src_y = inter_y0 as usize;
        let dst_y = (inter_y0 - y0) as usize;
        for row in 0..copy_h {
          let src_off = (src_y + row) * src_stride + src_x;
          let dst_off = (dst_y + row) * dst_stride + dst_x;
          dst[dst_off..dst_off + row_bytes].copy_from_slice(&src[src_off..src_off + row_bytes]);
        }
      }

      let mut tmp_mask: Option<Mask> = None;
      let tmp_clip: Option<&Mask> = if let Some(clip_mask) = clip_mask.as_deref() {
        let Some(mut mask) = Mask::new(scratch_w, scratch_h) else {
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            pixmap.fill_rect(skia_rect, &paint, transform, Some(clip_mask));
          });
          self.record_background_paint(background_timer);
          return Ok(());
        };
        mask.data_mut().fill(0);
        {
          let src = clip_mask.data();
          let dst = mask.data_mut();
          let src_stride = clip_mask.width() as usize;
          let dst_stride = scratch_w as usize;
          let copy_w = (inter_x1 - inter_x0) as usize;
          let copy_h = (inter_y1 - inter_y0) as usize;
          let src_x = inter_x0 as usize;
          let dst_x = (inter_x0 - x0) as usize;
          let src_y = inter_y0 as usize;
          let dst_y = (inter_y0 - y0) as usize;
          for row in 0..copy_h {
            let src_off = (src_y + row) * src_stride + src_x;
            let dst_off = (dst_y + row) * dst_stride + dst_x;
            dst[dst_off..dst_off + copy_w].copy_from_slice(&src[src_off..src_off + copy_w]);
          }
        }
        tmp_mask = Some(mask);
        tmp_mask.as_ref()
      } else {
        None
      };

      tmp.fill_rect(
        skia_rect,
        &paint,
        transform.post_translate(-(x0 as f32), -(y0 as f32)),
        tmp_clip,
      );

      // Copy the updated pixels back into the destination pixmap.
      {
        let src = tmp.data();
        let src_stride = scratch_w as usize * 4;
        let copy_w = (inter_x1 - inter_x0) as usize;
        let copy_h = (inter_y1 - inter_y0) as usize;
        let row_bytes = copy_w * 4;
        let src_x = (inter_x0 - x0) as usize * 4;
        let src_y = (inter_y0 - y0) as usize;
        let dst_x = inter_x0 as usize * 4;
        let dst_y = inter_y0 as usize;
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          let dst_stride = pixmap.width() as usize * 4;
          let dst = pixmap.data_mut();
          for row in 0..copy_h {
            let src_off = (src_y + row) * src_stride + src_x;
            let dst_off = (dst_y + row) * dst_stride + dst_x;
            dst[dst_off..dst_off + row_bytes].copy_from_slice(&src[src_off..src_off + row_bytes]);
          }
        });
      }

      self.record_background_paint(background_timer);
      return Ok(());
    }

    self.canvas.with_mirrored_pixmap_mut(|pixmap| {
      pixmap.fill_rect(skia_rect, &paint, transform, clip_mask.as_deref());
    });

    self.record_background_paint(background_timer);
    Ok(())
  }

  fn render_radial_gradient(&mut self, item: &RadialGradientItem) -> Result<()> {
    let rect = self.ds_rect(item.rect);
    let visible_rect = match self.gradient_visible_rect(rect) {
      Some(r) => r,
      None => return Ok(()),
    };
    let width = visible_rect.width().ceil() as u32;
    let height = visible_rect.height().ceil() as u32;
    if width == 0 || height == 0 {
      return Ok(());
    }

    let Some(stops_rgba) = self.convert_stops_rgba(&item.stops) else {
      return Ok(());
    };

    let spread = match item.spread {
      crate::paint::display_list::GradientSpread::Pad => SpreadMode::Pad,
      crate::paint::display_list::GradientSpread::Repeat => SpreadMode::Repeat,
      crate::paint::display_list::GradientSpread::Reflect => SpreadMode::Reflect,
    };

    let offset_x = visible_rect.x() - rect.x();
    let offset_y = visible_rect.y() - rect.y();
    let center = Point::new(
      self.ds_len(item.center.x) - offset_x,
      self.ds_len(item.center.y) - offset_y,
    );
    let radii = Point::new(self.ds_len(item.radii.x), self.ds_len(item.radii.y));
    let dest_x = visible_rect.x().floor() as i32;
    let dest_y = visible_rect.y().floor() as i32;
    let dither_phase = (((dest_y & 7) as u8) << 3) | ((dest_x & 7) as u8);
    let Some(key) = GradientPixmapCacheKey::radial(
      width,
      height,
      center,
      radii,
      spread,
      &stops_rgba,
      dither_phase,
    ) else {
      return Ok(());
    };

    let background_timer = self
      .background_paint_diagnostics
      .as_ref()
      .map(|_| Instant::now());
    let timer = self.diagnostics_enabled.then(Instant::now);

    let bucket = gradient_bucket(width.max(height));
    let Some(pix) = self.gradient_pixmap_cache.get_or_insert(key, || {
      rasterize_radial_gradient(
        width,
        height,
        center,
        radii,
        spread,
        &stops_rgba,
        &self.gradient_cache,
        bucket,
        dither_phase,
      )
    })?
    else {
      return Ok(());
    };

    if let Some(start) = timer {
      self.record_gradient_usage((width * height) as u64, start);
    }

    let frac_x = visible_rect.x() - dest_x as f32;
    let frac_y = visible_rect.y() - dest_y as f32;
    let canvas_transform = self.canvas.transform();
    let needs_filtering = canvas_transform.kx.abs() > 1e-6
      || canvas_transform.ky.abs() > 1e-6
      || (canvas_transform.sx - 1.0).abs() > 1e-6
      || (canvas_transform.sy - 1.0).abs() > 1e-6
      || canvas_transform.tx.fract().abs() > 1e-6
      || canvas_transform.ty.fract().abs() > 1e-6
      || frac_x.abs() > 1e-6
      || frac_y.abs() > 1e-6;
    let paint = tiny_skia::PixmapPaint {
      opacity: 1.0,
      blend_mode: self.canvas.blend_mode(),
      quality: if needs_filtering {
        FilterQuality::Bilinear
      } else {
        FilterQuality::Nearest
      },
    };
    let transform = Transform::from_translate(frac_x, frac_y).post_concat(canvas_transform);
    let clip = self.canvas.clip_mask_rc();
    self.canvas.with_mirrored_pixmap_mut(|pixmap| {
      pixmap.draw_pixmap(
        dest_x,
        dest_y,
        pix.as_ref().as_ref(),
        &paint,
        transform,
        clip.as_deref(),
      );
    });

    self.record_background_paint(background_timer);
    Ok(())
  }

  fn render_radial_gradient_pattern(&mut self, item: &RadialGradientPatternItem) -> Result<()> {
    let opacity = self.canvas.opacity().clamp(0.0, 1.0);
    if opacity <= 0.0 {
      return Ok(());
    }

    let dest_rect = self.ds_rect(item.dest_rect);
    if self.canvas.apply_clip(dest_rect).is_none() {
      return Ok(());
    }
    if dest_rect.width() <= 0.0 || dest_rect.height() <= 0.0 {
      return Ok(());
    }

    let tile_w = self.ds_len(item.tile_size.width);
    let tile_h = self.ds_len(item.tile_size.height);
    if tile_w <= 0.0 || tile_h <= 0.0 {
      return Ok(());
    }

    let width = tile_w.ceil().max(1.0) as u32;
    let height = tile_h.ceil().max(1.0) as u32;
    if width == 0 || height == 0 {
      return Ok(());
    }

    let Some(stops_rgba) = self.convert_stops_rgba(&item.stops) else {
      return Ok(());
    };

    let raster_scale_x = width as f32 / tile_w;
    let raster_scale_y = height as f32 / tile_h;
    if !raster_scale_x.is_finite() || !raster_scale_y.is_finite() {
      return Ok(());
    }

    let center = SkiaPoint::from_xy(
      self.ds_len(item.center.x) * raster_scale_x,
      self.ds_len(item.center.y) * raster_scale_y,
    );
    let radii = SkiaPoint::from_xy(
      self.ds_len(item.radii.x) * raster_scale_x,
      self.ds_len(item.radii.y) * raster_scale_y,
    );
    let spread = match item.spread {
      crate::paint::display_list::GradientSpread::Pad => SpreadMode::Pad,
      crate::paint::display_list::GradientSpread::Repeat => SpreadMode::Repeat,
      crate::paint::display_list::GradientSpread::Reflect => SpreadMode::Reflect,
    };
    let center_key = Point::new(center.x, center.y);
    let radii_key = Point::new(radii.x, radii.y);

    let background_timer = self
      .background_paint_diagnostics
      .as_ref()
      .map(|_| Instant::now());
    let timer = self.diagnostics_enabled.then(Instant::now);

    let origin = self.ds_point(item.origin);

    let canvas_transform = self.canvas.transform();
    let clip_mask = self.canvas.clip_mask_rc();
    let clip_bounds = self.canvas.clip_bounds();

    let mut bounds = transform_rect(dest_rect, &canvas_transform);
    if let Some(clip) = clip_bounds {
      let Some(intersection) = bounds.intersection(clip) else {
        self.record_background_paint(background_timer);
        return Ok(());
      };
      bounds = intersection;
    }

    let mut x0 = (bounds.min_x() - 0.5).ceil();
    let mut y0 = (bounds.min_y() - 0.5).ceil();
    let mut x1 = (bounds.max_x() - 0.5).ceil();
    let mut y1 = (bounds.max_y() - 0.5).ceil();

    x0 = x0.clamp(0.0, self.canvas.width() as f32);
    y0 = y0.clamp(0.0, self.canvas.height() as f32);
    x1 = x1.clamp(0.0, self.canvas.width() as f32);
    y1 = y1.clamp(0.0, self.canvas.height() as f32);

    let x0_u32 = x0 as u32;
    let y0_u32 = y0 as u32;
    let x1_u32 = x1 as u32;
    let y1_u32 = y1 as u32;
    if x0_u32 >= x1_u32 || y0_u32 >= y1_u32 {
      self.record_background_paint(background_timer);
      return Ok(());
    }

    let tmp_w = x1_u32 - x0_u32;
    let tmp_h = y1_u32 - y0_u32;
    let visible_pixels = u64::from(tmp_w).saturating_mul(u64::from(tmp_h));
    let tile_pixels = u64::from(width).saturating_mul(u64::from(height));
    let bucket = gradient_bucket(width.max(height));

    // Avoid rasterizing huge gradient tiles when only a small clipped region is actually visible.
    // This comes up on ebay.com, where a large rotated radial-gradient background is clipped down to
    // the hero viewport. Rasterizing the full tile dominates paint time and can trigger timeouts.
    const DIRECT_SAMPLE_MIN_TILE_PIXELS: u64 = 1_000_000;
    const DIRECT_SAMPLE_TILE_TO_VISIBLE_RATIO: u64 = 4;
    let use_direct = tile_pixels >= DIRECT_SAMPLE_MIN_TILE_PIXELS
      && tile_pixels > visible_pixels.saturating_mul(DIRECT_SAMPLE_TILE_TO_VISIBLE_RATIO);

    if use_direct {
      if let Some(inv_transform) = invert_transform(canvas_transform) {
        if let Some(mut tmp) = new_pixmap(tmp_w, tmp_h) {
          let inv_sx = inv_transform.sx as f64;
          let inv_kx = inv_transform.kx as f64;
          let inv_ky = inv_transform.ky as f64;
          let inv_sy = inv_transform.sy as f64;
          let inv_tx = inv_transform.tx as f64;
          let inv_ty = inv_transform.ty as f64;
          if inv_sx.is_finite()
            && inv_kx.is_finite()
            && inv_ky.is_finite()
            && inv_sy.is_finite()
            && inv_tx.is_finite()
            && inv_ty.is_finite()
          {
            let origin_x = origin.x as f64;
            let origin_y = origin.y as f64;
            let raster_scale_x = raster_scale_x as f64;
            let raster_scale_y = raster_scale_y as f64;
            if raster_scale_x.is_finite()
              && raster_scale_y.is_finite()
              && raster_scale_x.abs() > 1e-9
              && raster_scale_y.abs() > 1e-9
            {
              let center_x = center_key.x as f64;
              let center_y = center_key.y as f64;
              let radii_x = radii_key.x as f64;
              let radii_y = radii_key.y as f64;
              let inv_rx = 1.0 / radii_x;
              let inv_ry = 1.0 / radii_y;
              if radii_x.is_finite()
                && radii_y.is_finite()
                && radii_x > 0.0
                && radii_y > 0.0
                && inv_rx.is_finite()
                && inv_ry.is_finite()
              {
                let tile_w_f64 = width as f64;
                let tile_h_f64 = height as f64;

                let dest_min_x = dest_rect.min_x() as f64;
                let dest_min_y = dest_rect.min_y() as f64;
                let dest_max_x = dest_rect.max_x() as f64;
                let dest_max_y = dest_rect.max_y() as f64;

                let lut = get_gradient_lut(&self.gradient_cache, &stops_rgba, spread, bucket);
                let dst = tmp.pixels_mut();
                let stride = tmp_w as usize;

                let base_device_x = x0_u32 as f64 + 0.5;
                let base_device_y = y0_u32 as f64 + 0.5;
                let base_local_x = base_device_x * inv_sx + base_device_y * inv_kx + inv_tx;
                let base_local_y = base_device_x * inv_ky + base_device_y * inv_sy + inv_ty;

                let step_x_local_x = inv_sx;
                let step_x_local_y = inv_ky;
                let step_y_local_x = inv_kx;
                let step_y_local_y = inv_sy;

                let mut deadline_counter = 0usize;
                for y in 0..tmp_h as usize {
                  check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)
                    .map_err(Error::Render)?;
                  let mut local_x = base_local_x + y as f64 * step_y_local_x;
                  let mut local_y = base_local_y + y as f64 * step_y_local_y;
                  let row_off = y * stride;
                  for x in 0..tmp_w as usize {
                    if local_x.is_finite()
                      && local_y.is_finite()
                      && local_x >= dest_min_x
                      && local_x < dest_max_x
                      && local_y >= dest_min_y
                      && local_y < dest_max_y
                    {
                      let mut tx = (local_x - origin_x) * raster_scale_x;
                      let mut ty = (local_y - origin_y) * raster_scale_y;
                      tx = tx.rem_euclid(tile_w_f64);
                      ty = ty.rem_euclid(tile_h_f64);
                      let dx = (tx - center_x) * inv_rx;
                      let dy = (ty - center_y) * inv_ry;
                      let t = (dx * dx + dy * dy).sqrt() as f32;
                      dst[row_off + x] = lut.sample(t);
                    }
                    local_x += step_x_local_x;
                    local_y += step_x_local_y;
                  }
                }

                let blend_mode = self.canvas.blend_mode();
                let clip = clip_mask.as_deref();
                self.canvas.with_mirrored_pixmap_mut(|pixmap| {
                  composite_layer_into_pixmap_mut(
                    pixmap,
                    &tmp,
                    opacity,
                    blend_mode,
                    (x0_u32 as i32, y0_u32 as i32),
                    clip,
                  );
                });

                if let Some(start) = timer {
                  self.record_gradient_usage(visible_pixels, start);
                }
                self.record_background_paint(background_timer);
                return Ok(());
              }
            }
          }
        }
      }
    }

    let origin_x = origin.x.floor() as i32;
    let origin_y = origin.y.floor() as i32;
    let dither_phase = (((origin_y & 7) as u8) << 3) | ((origin_x & 7) as u8);
    let Some(key) = GradientPixmapCacheKey::radial(
      width,
      height,
      center_key,
      radii_key,
      spread,
      &stops_rgba,
      dither_phase,
    ) else {
      self.record_background_paint(background_timer);
      return Ok(());
    };

    let Some(tile) = self.gradient_pixmap_cache.get_or_insert(key, || {
      rasterize_radial_gradient(
        width,
        height,
        center_key,
        radii_key,
        spread,
        &stops_rgba,
        &self.gradient_cache,
        bucket,
        dither_phase,
      )
    })?
    else {
      self.record_background_paint(background_timer);
      return Ok(());
    };
    if let Some(start) = timer {
      self.record_gradient_usage(tile_pixels, start);
    }

    let scale_x = tile_w / tile.width() as f32;
    let scale_y = tile_h / tile.height() as f32;
    if !scale_x.is_finite() || !scale_y.is_finite() {
      self.record_background_paint(background_timer);
      return Ok(());
    }

    let axis_aligned = canvas_transform.kx.abs() <= 1e-6 && canvas_transform.ky.abs() <= 1e-6;
    let can_invert = canvas_transform.sx.is_finite()
      && canvas_transform.sy.is_finite()
      && canvas_transform.sx.abs() > 1e-6
      && canvas_transform.sy.abs() > 1e-6;

    if axis_aligned && can_invert {
      if let Some(mut tmp) = new_pixmap(tmp_w, tmp_h) {
        let src_w = tile.width();
        let src_h = tile.height();
        if src_w == 0 || src_h == 0 {
          self.record_background_paint(background_timer);
          return Ok(());
        }

        let src_w_i64 = src_w as i64;
        let src_h_i64 = src_h as i64;
        let inv_canvas_sx = 1.0f64 / canvas_transform.sx as f64;
        let inv_canvas_sy = 1.0f64 / canvas_transform.sy as f64;
        let canvas_tx = canvas_transform.tx as f64;
        let canvas_ty = canvas_transform.ty as f64;
        let origin_x = origin.x as f64;
        let origin_y = origin.y as f64;
        let pattern_scale_x = scale_x as f64;
        let pattern_scale_y = scale_y as f64;

        if !pattern_scale_x.is_finite() || !pattern_scale_y.is_finite() {
          self.record_background_paint(background_timer);
          return Ok(());
        }

        let mut xs: Vec<u32> = Vec::new();
        let mut ys: Vec<u32> = Vec::new();
        if xs.try_reserve_exact(tmp_w as usize).is_ok()
          && ys.try_reserve_exact(tmp_h as usize).is_ok()
        {
          for x in 0..tmp_w {
            let dx = (x0_u32 + x) as f64 + 0.5;
            let local_x = (dx - canvas_tx) * inv_canvas_sx;
            let rel_x = local_x - origin_x;
            let src_x = rel_x / pattern_scale_x - 0.5;
            let ix = (src_x + 0.5).floor() as i64;
            xs.push(ix.rem_euclid(src_w_i64) as u32);
          }
          for y in 0..tmp_h {
            let dy = (y0_u32 + y) as f64 + 0.5;
            let local_y = (dy - canvas_ty) * inv_canvas_sy;
            let rel_y = local_y - origin_y;
            let src_y = rel_y / pattern_scale_y - 0.5;
            let iy = (src_y + 0.5).floor() as i64;
            ys.push(iy.rem_euclid(src_h_i64) as u32);
          }

          let src = tile.data();
          let dst = tmp.data_mut();
          let src_stride = src_w as usize * 4;
          let dst_stride = tmp_w as usize * 4;
          let mut deadline_counter = 0usize;
          for (y, &sy) in ys.iter().enumerate() {
            check_active_periodic(&mut deadline_counter, 128, RenderStage::Paint)
              .map_err(Error::Render)?;
            let src_row = sy as usize * src_stride;
            let dst_row = y * dst_stride;
            for (x, &sx) in xs.iter().enumerate() {
              let src_idx = src_row + sx as usize * 4;
              let dst_idx = dst_row + x * 4;
              dst[dst_idx..dst_idx + 4].copy_from_slice(&src[src_idx..src_idx + 4]);
            }
          }

          let blend_mode = self.canvas.blend_mode();
          let clip = clip_mask.as_deref();
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            composite_layer_into_pixmap_mut(
              pixmap,
              &tmp,
              opacity,
              blend_mode,
              (x0_u32 as i32, y0_u32 as i32),
              clip,
            );
          });

          self.record_background_paint(background_timer);
          return Ok(());
        }
      }

      // Allocation failed; fall back to tiny-skia's pattern fill below.
    }

    if let Some(inv_transform) = invert_transform(canvas_transform) {
      if let Some(mut tmp) = new_pixmap(tmp_w, tmp_h) {
        let src_w = tile.width();
        let src_h = tile.height();
        if src_w == 0 || src_h == 0 {
          self.record_background_paint(background_timer);
          return Ok(());
        }

        let src_w_i64 = src_w as i64;
        let src_h_i64 = src_h as i64;
        let inv_sx = inv_transform.sx as f64;
        let inv_kx = inv_transform.kx as f64;
        let inv_ky = inv_transform.ky as f64;
        let inv_sy = inv_transform.sy as f64;
        let inv_tx = inv_transform.tx as f64;
        let inv_ty = inv_transform.ty as f64;
        if !inv_sx.is_finite()
          || !inv_kx.is_finite()
          || !inv_ky.is_finite()
          || !inv_sy.is_finite()
          || !inv_tx.is_finite()
          || !inv_ty.is_finite()
        {
          self.record_background_paint(background_timer);
          return Ok(());
        }

        let origin_x = origin.x as f64;
        let origin_y = origin.y as f64;
        let pattern_scale_x = scale_x as f64;
        let pattern_scale_y = scale_y as f64;
        if !pattern_scale_x.is_finite()
          || !pattern_scale_y.is_finite()
          || pattern_scale_x.abs() < 1e-9
          || pattern_scale_y.abs() < 1e-9
        {
          self.record_background_paint(background_timer);
          return Ok(());
        }

        let dest_min_x = dest_rect.min_x() as f64;
        let dest_min_y = dest_rect.min_y() as f64;
        let dest_max_x = dest_rect.max_x() as f64;
        let dest_max_y = dest_rect.max_y() as f64;

        let src = tile.data();
        let dst = tmp.data_mut();
        let src_stride = src_w as usize * 4;
        let dst_stride = tmp_w as usize * 4;
        let mut deadline_counter = 0usize;

        for y in 0..tmp_h as usize {
          check_active_periodic(&mut deadline_counter, 128, RenderStage::Paint)
            .map_err(Error::Render)?;
          let device_y = y0_u32 as f64 + y as f64 + 0.5;
          let row_off = y * dst_stride;
          for x in 0..tmp_w as usize {
            let device_x = x0_u32 as f64 + x as f64 + 0.5;
            let local_x = device_x * inv_sx + device_y * inv_kx + inv_tx;
            let local_y = device_x * inv_ky + device_y * inv_sy + inv_ty;
            if !(local_x.is_finite() && local_y.is_finite()) {
              continue;
            }
            if local_x < dest_min_x
              || local_x >= dest_max_x
              || local_y < dest_min_y
              || local_y >= dest_max_y
            {
              continue;
            }

            let rel_x = local_x - origin_x;
            let rel_y = local_y - origin_y;
            let sx = (rel_x / pattern_scale_x).floor() as i64;
            let sy = (rel_y / pattern_scale_y).floor() as i64;
            let sx = sx.rem_euclid(src_w_i64) as usize;
            let sy = sy.rem_euclid(src_h_i64) as usize;
            let src_idx = sy * src_stride + sx * 4;
            let dst_idx = row_off + x * 4;
            dst[dst_idx..dst_idx + 4].copy_from_slice(&src[src_idx..src_idx + 4]);
          }
        }

        let blend_mode = self.canvas.blend_mode();
        let clip = clip_mask.as_deref();
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          composite_layer_into_pixmap_mut(
            pixmap,
            &tmp,
            opacity,
            blend_mode,
            (x0_u32 as i32, y0_u32 as i32),
            clip,
          );
        });

        self.record_background_paint(background_timer);
        return Ok(());
      }
    }

    let mut paint = tiny_skia::Paint::default();
    paint.shader = Pattern::new(
      tile.as_ref().as_ref(),
      SpreadMode::Repeat,
      tiny_skia::FilterQuality::Nearest,
      opacity,
      Transform::from_row(scale_x, 0.0, 0.0, scale_y, origin.x, origin.y),
    );
    paint.anti_alias = false;
    paint.blend_mode = self.canvas.blend_mode();

    let Some(skia_rect) = tiny_skia::Rect::from_xywh(
      dest_rect.x(),
      dest_rect.y(),
      dest_rect.width(),
      dest_rect.height(),
    ) else {
      return Ok(());
    };
    self.canvas.with_mirrored_pixmap_mut(|pixmap| {
      pixmap.fill_rect(skia_rect, &paint, canvas_transform, clip_mask.as_deref());
    });

    self.record_background_paint(background_timer);
    Ok(())
  }

  fn render_conic_gradient(&mut self, item: &ConicGradientItem) -> Result<()> {
    let rect = self.ds_rect(item.rect);
    let visible_rect = match self.gradient_visible_rect(rect) {
      Some(r) => r,
      None => return Ok(()),
    };
    let width = visible_rect.width().ceil() as u32;
    let height = visible_rect.height().ceil() as u32;
    if width == 0 || height == 0 {
      return Ok(());
    }

    let Some(stops) = self.convert_stops_rgba(&item.stops) else {
      return Ok(());
    };

    let offset_x = visible_rect.x() - rect.x();
    let offset_y = visible_rect.y() - rect.y();
    let center = Point::new(
      self.ds_len(item.center.x) - offset_x,
      self.ds_len(item.center.y) - offset_y,
    );
    let spread = if item.repeating {
      SpreadMode::Repeat
    } else {
      SpreadMode::Pad
    };
    let original_width = rect.width().ceil().max(0.0) as u32;
    let original_height = rect.height().ceil().max(0.0) as u32;
    let background_timer = self
      .background_paint_diagnostics
      .as_ref()
      .map(|_| Instant::now());
    let timer = self.diagnostics_enabled.then(Instant::now);
    let Some(pix) = rasterize_conic_gradient_cached(
      &self.gradient_pixmap_cache,
      width,
      height,
      center,
      item.from_angle.to_radians(),
      spread,
      &stops,
      &self.gradient_cache,
      gradient_bucket(original_width.max(original_height).saturating_mul(2)),
    )?
    else {
      return Ok(());
    };
    if let Some(start) = timer {
      self.record_gradient_usage((width * height) as u64, start);
    }

    let paint = tiny_skia::PixmapPaint {
      opacity: 1.0,
      blend_mode: self.canvas.blend_mode(),
      ..Default::default()
    };
    let dest_x = visible_rect.x().floor() as i32;
    let dest_y = visible_rect.y().floor() as i32;
    let frac_x = visible_rect.x() - dest_x as f32;
    let frac_y = visible_rect.y() - dest_y as f32;
    let transform = Transform::from_translate(frac_x, frac_y).post_concat(self.canvas.transform());
    let clip = self.canvas.clip_mask_rc();
    self.canvas.with_mirrored_pixmap_mut(|pixmap| {
      pixmap.draw_pixmap(
        dest_x,
        dest_y,
        pix.as_ref().as_ref(),
        &paint,
        transform,
        clip.as_deref(),
      );
    });
    self.record_background_paint(background_timer);
    Ok(())
  }

  fn render_conic_gradient_pattern(&mut self, item: &ConicGradientPatternItem) -> Result<()> {
    let opacity = self.canvas.opacity().clamp(0.0, 1.0);
    if opacity <= 0.0 {
      return Ok(());
    }

    let dest_rect = self.ds_rect(item.dest_rect);
    if self.canvas.apply_clip(dest_rect).is_none() {
      return Ok(());
    }
    if dest_rect.width() <= 0.0 || dest_rect.height() <= 0.0 {
      return Ok(());
    }

    let tile_w = self.ds_len(item.tile_size.width);
    let tile_h = self.ds_len(item.tile_size.height);
    if tile_w <= 0.0 || tile_h <= 0.0 {
      return Ok(());
    }

    let width = tile_w.ceil().max(1.0) as u32;
    let height = tile_h.ceil().max(1.0) as u32;
    if width == 0 || height == 0 {
      return Ok(());
    }

    let Some(stops) = self.convert_stops_rgba(&item.stops) else {
      return Ok(());
    };

    let scale_x = tile_w / width as f32;
    let scale_y = tile_h / height as f32;
    if !scale_x.is_finite() || !scale_y.is_finite() || scale_x <= 0.0 || scale_y <= 0.0 {
      return Ok(());
    }

    let center = Point::new(
      self.ds_len(item.center.x) / scale_x,
      self.ds_len(item.center.y) / scale_y,
    );
    let spread = if item.repeating {
      SpreadMode::Repeat
    } else {
      SpreadMode::Pad
    };

    let background_timer = self
      .background_paint_diagnostics
      .as_ref()
      .map(|_| Instant::now());
    let timer = self.diagnostics_enabled.then(Instant::now);
    let Some(tile) = rasterize_conic_gradient_scaled_cached(
      &self.gradient_pixmap_cache,
      width,
      height,
      center,
      item.from_angle.to_radians(),
      spread,
      &stops,
      &self.gradient_cache,
      gradient_bucket(width.max(height).saturating_mul(2)),
      scale_x,
      scale_y,
    )?
    else {
      return Ok(());
    };
    if let Some(start) = timer {
      self.record_gradient_usage((width * height) as u64, start);
    }

    let origin = self.ds_point(item.origin);

    let mut paint = tiny_skia::Paint::default();
    paint.shader = Pattern::new(
      tile.as_ref().as_ref(),
      SpreadMode::Repeat,
      tiny_skia::FilterQuality::Nearest,
      opacity,
      Transform::from_row(scale_x, 0.0, 0.0, scale_y, origin.x, origin.y),
    );
    paint.anti_alias = false;
    paint.blend_mode = self.canvas.blend_mode();

    let Some(skia_rect) = tiny_skia::Rect::from_xywh(
      dest_rect.x(),
      dest_rect.y(),
      dest_rect.width(),
      dest_rect.height(),
    ) else {
      return Ok(());
    };
    let transform = self.canvas.transform();
    let clip_mask = self.canvas.clip_mask_rc();
    self.canvas.with_mirrored_pixmap_mut(|pixmap| {
      pixmap.fill_rect(skia_rect, &paint, transform, clip_mask.as_deref());
    });

    self.record_background_paint(background_timer);
    Ok(())
  }

  fn render_border(&mut self, item: &BorderItem) -> Result<()> {
    let opacity = self.canvas.opacity().clamp(0.0, 1.0);
    if opacity <= 0.0 {
      return Ok(());
    }

    let transform = self.canvas.transform();
    let blend_mode = self.canvas.blend_mode();
    let rect = self.ds_rect(item.rect);
    let radii = self.ds_radii(item.radii);
    let gap = item
      .gap
      .map(|gap| (gap.edge, gap.start * self.scale, gap.end * self.scale));
    let top = BorderSide {
      width: self.ds_len(item.top.width),
      ..item.top.clone()
    };
    let right = BorderSide {
      width: self.ds_len(item.right.width),
      ..item.right.clone()
    };
    let bottom = BorderSide {
      width: self.ds_len(item.bottom.width),
      ..item.bottom.clone()
    };
    let left = BorderSide {
      width: self.ds_len(item.left.width),
      ..item.left.clone()
    };

    // Rounded borders must follow the corner curves. The generic edge-stroke approach below draws
    // straight segments and clips them to the border box, which leaves visible gaps near rounded
    // corners. When all four sides are identical solid strokes we can render the border as the
    // (outer rounded rect) minus (inner rounded rect) region, which matches the CSS border
    // geometry and produces correct corners.
    if radii.has_radius()
      && item.image.is_none()
      && gap.is_none()
      && matches!(
        (top.style, right.style, bottom.style, left.style),
        (
          CssBorderStyle::Solid,
          CssBorderStyle::Solid,
          CssBorderStyle::Solid,
          CssBorderStyle::Solid
        )
      )
      && top.color == right.color
      && top.color == bottom.color
      && top.color == left.color
      && !top.color.is_transparent()
    {
      let border_width = top.width;
      let eps = 1e-6;
      let uniform_widths = border_width > 0.0
        && (border_width - right.width).abs() <= eps
        && (border_width - bottom.width).abs() <= eps
        && (border_width - left.width).abs() <= eps;
      if uniform_widths && rect.width() > 0.0 && rect.height() > 0.0 {
        // Match Chrome/Skia's box-decoration pixel snapping behaviour for opaque axis-aligned
        // borders. Without this, tiny-skia will anti-alias the straight border edges when layout
        // produces fractional coordinates, causing 1px "washed out" borders and subtle bleed into
        // adjacent pixels (notably on cdc.gov's outline buttons).
        let mut ring_rect = rect;
        let mut ring_transform = transform;
        let mut snapped_ring_rect = false;
        if blend_mode == tiny_skia::BlendMode::SourceOver
          && Self::is_translation_only_transform(transform)
          && Self::is_near_integer(transform.tx)
          && Self::is_near_integer(transform.ty)
        {
          let alpha = (top.color.a * opacity).clamp(0.0, 1.0);
          let alpha_u8 = (alpha * 255.0).round().clamp(0.0, 255.0) as u8;
          if alpha_u8 == 255 {
            // Bake the near-integer translation into the border geometry so we can snap in device
            // space (stable under tile-based rendering) and render with an identity transform.
            let tx = transform.tx.round();
            let ty = transform.ty.round();
            let rect = Rect::from_xywh(rect.x() + tx, rect.y() + ty, rect.width(), rect.height());

            // Snap the outer rect edges to integer device pixels. When the border ring is built
            // from this snapped rect, the straight edges land exactly on pixel boundaries so
            // anti-aliasing only affects the curved corners.
            //
            // Use the same pixel-center rule as Canvas's opaque fill snapping. Chrome/Skia's
            // axis-aligned, non-AA fills treat pixel centers on the min edge as outside, and pixel
            // centers on the max edge as inside (`open min / closed max`).
            let dx0 = rect.min_x();
            let dx1 = rect.max_x();
            let dy0 = rect.min_y();
            let dy1 = rect.max_y();
            let start_x = (dx0.min(dx1) + 0.5).floor();
            let end_x = (dx0.max(dx1) + 0.5).floor();
            let start_y = (dy0.min(dy1) + 0.5).floor();
            let end_y = (dy0.max(dy1) + 0.5).floor();
            let snapped = Rect::from_xywh(start_x, start_y, end_x - start_x, end_y - start_y);
            if snapped.width() > 0.0 && snapped.height() > 0.0 {
              ring_rect = snapped;
              ring_transform = Transform::identity();
              snapped_ring_rect = true;
            } else {
              ring_rect = rect;
              ring_transform = Transform::identity();
            }
          }
        }

        // tiny-skia's anti-aliased path fill tends to treat both sides of an axis-aligned edge as
        // "inside", causing snapped 1px borders to still bleed by one sample row/column into the
        // border interior (e.g. Chrome shows a crisp `#ccc` 1px border, while tiny-skia produces a
        // slightly washed-out edge and a faint inner halo).
        //
        // Nudge the inner contour outward (toward the outer edge) by a tiny epsilon (by shrinking
        // the inset) so those
        // boundary samples land definitively inside the hole rather than on the edge.
        let ring_inset =
          if snapped_ring_rect && Self::is_near_integer(border_width) && border_width >= 1.0 {
            (border_width - 1e-3).max(0.0)
          } else {
            border_width
          };

        if let Some(path) = crate::paint::rasterize::build_rounded_rect_ring_path(
          ring_rect.x(),
          ring_rect.y(),
          ring_rect.width(),
          ring_rect.height(),
          &radii,
          ring_inset,
        ) {
          let mut paint = tiny_skia::Paint::default();
          set_paint_color(&mut paint, &top.color, opacity);
          paint.blend_mode = blend_mode;
          paint.anti_alias = true;

          let clip = self.canvas.clip_mask_rc();
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            pixmap.fill_path(
              &path,
              &paint,
              tiny_skia::FillRule::EvenOdd,
              ring_transform,
              clip.as_deref(),
            );
          });
          return Ok(());
        }
      }
    }

    // Fast path for simple solid borders without radii/gaps/images.
    //
    // The generic edge-stroke logic below uses anti-aliased strokes. For axis-aligned content this
    // can introduce subtle subpixel blending at border edges when layout coordinates are
    // fractional, which tends to diverge from Chrome/Skia's border rasterization. The `Canvas`
    // rectangle fill path includes snap-to-device-pixel and source-over compositing behavior tuned
    // against Chrome; reuse it here when the border can be expressed as a set of non-overlapping
    // rect fills.
    if item.image.is_none()
      && gap.is_none()
      && !radii.has_radius()
      && blend_mode == tiny_skia::BlendMode::SourceOver
      && transform.kx.abs() < 1e-6
      && transform.ky.abs() < 1e-6
    {
      let sides = [&top, &right, &bottom, &left];
      let mut solid_color: Option<Rgba> = None;
      let mut ok = true;
      for side in sides {
        if side.width <= 0.0 {
          continue;
        }
        if side.style != CssBorderStyle::Solid || side.color.is_transparent() {
          ok = false;
          break;
        }
        match solid_color {
          Some(existing) if existing != side.color => {
            ok = false;
            break;
          }
          Some(_) => {}
          None => solid_color = Some(side.color),
        }
      }

      if ok && solid_color.is_some() {
        let x = rect.x();
        let y = rect.y();
        let w = rect.width();
        let h = rect.height();

        // Fill non-overlapping strips so opacity < 1 does not double-blend at the corners.
        if top.width > 0.0 {
          self
            .canvas
            .draw_rect(Rect::from_xywh(x, y, w, top.width), top.color);
        }
        if bottom.width > 0.0 {
          // Chrome/Skia's rasterization of single-edge 1px borders differs from our general
          // axis-aligned opaque fill snapping. In particular, a `border-bottom: 1px solid` whose
          // top edge lands on a fractional device pixel (common with text-heavy layouts) is
          // painted one device pixel lower than a naïve 1px fill-rect would suggest.
          //
          // This shows up as 1px "stripe swaps" on pages like `doc.rust-lang.org`, where Chrome's
          // bottom borders land on row N+1 while FastRender paints row N.
          //
          // Match Chrome by biasing *single-edge* bottom borders (no other sides) down by half a
          // device pixel when the border width is an integer number of device pixels and the top
          // edge falls in the first half of a device pixel. This avoids our opaque-fill snapping
          // expanding the strip by an extra scanline (and also avoids shifting pixel-aligned
          // borders down by 1px).
          //
          // Even-width borders can still land on fractional device pixels (because the border box
          // height is often fractional in text-heavy layouts). Without this bias the fill-rect snap
          // path rounds the top edge up/down based on the pixel-center rule, which can place the
          // border one row too high and "swap" a stripe of background/border color (notably in
          // arxiv.org's 2px header divider).
          let mut bottom_y = y + h - bottom.width;
          let single_edge_bottom =
            top.width <= 0.0 && right.width <= 0.0 && left.width <= 0.0 && bottom.width > 0.0;
          if single_edge_bottom && Self::is_near_integer(bottom.width) && bottom_y.is_finite() {
            // Only apply the Chrome-matching bias when the border's top edge falls in the *first
            // half* of a device pixel. In that range our opaque fill snapping (`ceil(max)`) would
            // otherwise expand the snapped rect by an extra scanline (producing a (k+1)px tall
            // border for an intended kpx border). Avoid applying the bias when already
            // pixel-aligned, as it shifts the border down by 1px and can move it outside the
            // element's border box.
            let frac = bottom_y.rem_euclid(1.0);
            if frac > 1e-3 && frac < 0.5 - 1e-3 {
              bottom_y += 0.5;
            }
          }
          self
            .canvas
            .draw_rect(Rect::from_xywh(x, bottom_y, w, bottom.width), bottom.color);
        }

        let mid_y = y + top.width;
        let mid_h = (h - top.width - bottom.width).max(0.0);
        if mid_h > 0.0 {
          if left.width > 0.0 {
            self
              .canvas
              .draw_rect(Rect::from_xywh(x, mid_y, left.width, mid_h), left.color);
          }
          if right.width > 0.0 {
            self.canvas.draw_rect(
              Rect::from_xywh(x + w - right.width, mid_y, right.width, mid_h),
              right.color,
            );
          }
        }

        return Ok(());
      }
    }

    // For solid borders with square corners, CSS border geometry is a set of trapezoids/triangles
    // meeting at diagonal miters. Stroking each edge paints rectangles, which is incorrect when
    // border widths/colors differ (e.g. CSS border triangles that rely on transparent borders).
    if !radii.has_radius()
      && item.image.is_none()
      && gap.is_none()
      && matches!(
        top.style,
        CssBorderStyle::Solid | CssBorderStyle::None | CssBorderStyle::Hidden
      )
      && matches!(
        right.style,
        CssBorderStyle::Solid | CssBorderStyle::None | CssBorderStyle::Hidden
      )
      && matches!(
        bottom.style,
        CssBorderStyle::Solid | CssBorderStyle::None | CssBorderStyle::Hidden
      )
      && matches!(
        left.style,
        CssBorderStyle::Solid | CssBorderStyle::None | CssBorderStyle::Hidden
      )
    {
      let eps = 1e-6;
      let uniform_solid = matches!(
        (top.style, right.style, bottom.style, left.style),
        (
          CssBorderStyle::Solid,
          CssBorderStyle::Solid,
          CssBorderStyle::Solid,
          CssBorderStyle::Solid
        )
      ) && (top.width - right.width).abs() <= eps
        && (top.width - bottom.width).abs() <= eps
        && (top.width - left.width).abs() <= eps
        && top.color == right.color
        && top.color == bottom.color
        && top.color == left.color;

      // Keep the existing edge-stroke code path for the common uniform case to avoid introducing
      // seams along the diagonal miter split when all sides are identical.
      if !uniform_solid && rect.width() > 0.0 && rect.height() > 0.0 {
        let top_w = if top.style == CssBorderStyle::Solid {
          top.width
        } else {
          0.0
        };
        let right_w = if right.style == CssBorderStyle::Solid {
          right.width
        } else {
          0.0
        };
        let bottom_w = if bottom.style == CssBorderStyle::Solid {
          bottom.width
        } else {
          0.0
        };
        let left_w = if left.style == CssBorderStyle::Solid {
          left.width
        } else {
          0.0
        };

        let x0 = rect.x();
        let y0 = rect.y();
        let x1 = x0 + rect.width();
        let y1 = y0 + rect.height();

        let mut inner_left = (x0 + left_w).min(x1);
        let mut inner_right = (x1 - right_w).max(x0);
        if inner_right < inner_left {
          let mid = (inner_left + inner_right) * 0.5;
          inner_left = mid;
          inner_right = mid;
        }
        let mut inner_top = (y0 + top_w).min(y1);
        let mut inner_bottom = (y1 - bottom_w).max(y0);
        if inner_bottom < inner_top {
          let mid = (inner_top + inner_bottom) * 0.5;
          inner_top = mid;
          inner_bottom = mid;
        }

        let clip = self.canvas.clip_mask_rc();
        let mut paint = tiny_skia::Paint::default();
        paint.blend_mode = blend_mode;
        paint.anti_alias = true;

        let mut fill_quad = |pts: [(f32, f32); 4], color: &Rgba| {
          if color.is_transparent() {
            return;
          }
          let mut pb = PathBuilder::new();
          pb.move_to(pts[0].0, pts[0].1);
          pb.line_to(pts[1].0, pts[1].1);
          pb.line_to(pts[2].0, pts[2].1);
          pb.line_to(pts[3].0, pts[3].1);
          pb.close();
          let Some(path) = pb.finish() else {
            return;
          };
          set_paint_color(&mut paint, color, opacity);
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            pixmap.fill_path(
              &path,
              &paint,
              tiny_skia::FillRule::Winding,
              transform,
              clip.as_deref(),
            );
          });
        };

        if top_w > 0.0 && top.style == CssBorderStyle::Solid {
          fill_quad(
            [
              (x0, y0),
              (x1, y0),
              (inner_right, inner_top),
              (inner_left, inner_top),
            ],
            &top.color,
          );
        }
        if right_w > 0.0 && right.style == CssBorderStyle::Solid {
          fill_quad(
            [
              (x1, y0),
              (x1, y1),
              (inner_right, inner_bottom),
              (inner_right, inner_top),
            ],
            &right.color,
          );
        }
        if bottom_w > 0.0 && bottom.style == CssBorderStyle::Solid {
          fill_quad(
            [
              (x0, y1),
              (x1, y1),
              (inner_right, inner_bottom),
              (inner_left, inner_bottom),
            ],
            &bottom.color,
          );
        }
        if left_w > 0.0 && left.style == CssBorderStyle::Solid {
          fill_quad(
            [
              (x0, y0),
              (x0, y1),
              (inner_left, inner_bottom),
              (inner_left, inner_top),
            ],
            &left.color,
          );
        }

        return Ok(());
      }
    }

    // Dotted borders use round caps, which can extend outside the border box. Clip to the border
    // rect (and any corner radii) so the stroke stays within the border box.
    let wants_stroke_clip = matches!(
      (top.style, right.style, bottom.style, left.style),
      (CssBorderStyle::Dotted, _, _, _)
        | (_, CssBorderStyle::Dotted, _, _)
        | (_, _, CssBorderStyle::Dotted, _)
        | (_, _, _, CssBorderStyle::Dotted)
    );
    let mut pushed_clip = false;
    if radii.has_radius() {
      self.canvas.save();
      self.canvas.set_clip_with_radii(rect, Some(radii))?;
      pushed_clip = true;
    }

    let mut clip = self.canvas.clip_mask_rc();

    if let Some(border_image) = item.image.as_ref() {
      if self.render_border_image(
        border_image,
        rect,
        top.width,
        right.width,
        bottom.width,
        left.width,
        opacity,
        clip.as_deref(),
        transform,
      )? {
        if pushed_clip {
          self.canvas.restore();
        }
        return Ok(());
      }
    }

    if wants_stroke_clip && !pushed_clip {
      self.canvas.save();
      self.canvas.set_clip_force_mask(rect)?;
      pushed_clip = true;
      clip = self.canvas.clip_mask_rc();
    }

    let top_center = rect.y() + top.width * 0.5;
    let bottom_center = rect.y() + rect.height() - bottom.width * 0.5;
    let left_center = rect.x() + left.width * 0.5;
    let right_center = rect.x() + rect.width() - right.width * 0.5;

    // Use the outer border box corners as endpoints so each edge meets cleanly at corners (avoids
    // leaving 1px gaps when drawing each edge independently). Dotted borders are clipped to the
    // border box above so round caps can't extend outside the border box.
    let outer_left = rect.x();
    let outer_top = rect.y();
    let outer_right = rect.x() + rect.width();
    let outer_bottom = rect.y() + rect.height();
    let edges: [(_, _, _, _); 4] = [
      (
        BorderEdge::Top,
        &top,
        (outer_left, top_center),
        (outer_right, top_center),
      ),
      (
        BorderEdge::Right,
        &right,
        (right_center, outer_top),
        (right_center, outer_bottom),
      ),
      (
        BorderEdge::Bottom,
        &bottom,
        (outer_left, bottom_center),
        (outer_right, bottom_center),
      ),
      (
        BorderEdge::Left,
        &left,
        (left_center, outer_top),
        (left_center, outer_bottom),
      ),
    ];

    for (edge, side, (x1, y1), (x2, y2)) in edges {
      let gap_matches_edge = gap.is_some_and(|(gap_edge, _, _)| {
        gap_edge
          == match edge {
            BorderEdge::Top => PhysicalSide::Top,
            BorderEdge::Right => PhysicalSide::Right,
            BorderEdge::Bottom => PhysicalSide::Bottom,
            BorderEdge::Left => PhysicalSide::Left,
          }
      });

      if let (true, Some((_, gap_start, gap_end))) = (gap_matches_edge, gap) {
        match edge.orientation() {
          EdgeOrientation::Horizontal => {
            let min_x = x1.min(x2);
            let max_x = x1.max(x2);
            let start = gap_start.clamp(min_x, max_x);
            let end = gap_end.clamp(min_x, max_x);
            if end > start {
              if start > min_x {
                self.render_border_edge(
                  edge,
                  min_x,
                  y1,
                  start,
                  y1,
                  side,
                  blend_mode,
                  opacity,
                  clip.as_deref(),
                  transform,
                );
              }
              if end < max_x {
                self.render_border_edge(
                  edge,
                  end,
                  y1,
                  max_x,
                  y1,
                  side,
                  blend_mode,
                  opacity,
                  clip.as_deref(),
                  transform,
                );
              }
              continue;
            }
          }
          EdgeOrientation::Vertical => {
            let min_y = y1.min(y2);
            let max_y = y1.max(y2);
            let start = gap_start.clamp(min_y, max_y);
            let end = gap_end.clamp(min_y, max_y);
            if end > start {
              if start > min_y {
                self.render_border_edge(
                  edge,
                  x1,
                  min_y,
                  x1,
                  start,
                  side,
                  blend_mode,
                  opacity,
                  clip.as_deref(),
                  transform,
                );
              }
              if end < max_y {
                self.render_border_edge(
                  edge,
                  x1,
                  end,
                  x1,
                  max_y,
                  side,
                  blend_mode,
                  opacity,
                  clip.as_deref(),
                  transform,
                );
              }
              continue;
            }
          }
        }
      }

      self.render_border_edge(
        edge,
        x1,
        y1,
        x2,
        y2,
        side,
        blend_mode,
        opacity,
        clip.as_deref(),
        transform,
      );
    }

    if pushed_clip {
      self.canvas.restore();
    }
    Ok(())
  }

  fn render_outline(&mut self, item: &OutlineItem) {
    let width = self.ds_len(item.width);
    if width <= 0.0 || matches!(item.style, CssBorderStyle::None | CssBorderStyle::Hidden) {
      return;
    }
    let offset = self.ds_len(item.offset);
    let expand = offset + width;
    let rect = self.ds_rect(item.rect);
    let outer_x = rect.x() - expand;
    let outer_y = rect.y() - expand;
    let outer_w = rect.width() + 2.0 * expand;
    let outer_h = rect.height() + 2.0 * expand;
    let blend_mode = if item.invert {
      tiny_skia::BlendMode::Difference
    } else {
      self.canvas.blend_mode()
    };
    let opacity = self.canvas.opacity().clamp(0.0, 1.0);
    // CSS outlines should not be clipped by overflow/clip regions.
    let clip = None;
    self.canvas.save();
    self.canvas.clear_clip();
    let transform = self.canvas.transform();
    let color = item.color;

    // When the element has rounded corners, the outline should follow the same corner curves.
    // Rendering it as a set of straight edge strokes produces square corners and can visibly
    // diverge from browsers (e.g. pill-shaped focus rings).
    let radii = self.ds_radii(item.radii);
    let outer_radii = radii.shrink(-expand);
    if outer_radii.has_radius()
      && matches!(item.style, CssBorderStyle::Solid)
      && !color.is_transparent()
      && outer_w > 0.0
      && outer_h > 0.0
    {
      if let Some(path) = crate::paint::rasterize::build_rounded_rect_ring_path(
        outer_x,
        outer_y,
        outer_w,
        outer_h,
        &outer_radii,
        width,
      ) {
        let mut paint = tiny_skia::Paint::default();
        set_paint_color(&mut paint, &color, opacity);
        paint.blend_mode = blend_mode;
        paint.anti_alias = true;
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          pixmap.fill_path(
            &path,
            &paint,
            tiny_skia::FillRule::EvenOdd,
            transform,
            clip.as_ref(),
          );
        });
        self.canvas.restore();
        return;
      }
    }

    // Top
    self.render_border_edge(
      BorderEdge::Top,
      outer_x,
      outer_y + width * 0.5,
      outer_x + outer_w,
      outer_y + width * 0.5,
      &BorderSide {
        width,
        style: item.style,
        color,
      },
      blend_mode,
      opacity,
      clip.as_ref(),
      transform,
    );
    // Bottom
    self.render_border_edge(
      BorderEdge::Bottom,
      outer_x,
      outer_y + outer_h - width * 0.5,
      outer_x + outer_w,
      outer_y + outer_h - width * 0.5,
      &BorderSide {
        width,
        style: item.style,
        color,
      },
      blend_mode,
      opacity,
      clip.as_ref(),
      transform,
    );
    // Left
    self.render_border_edge(
      BorderEdge::Left,
      outer_x + width * 0.5,
      outer_y,
      outer_x + width * 0.5,
      outer_y + outer_h,
      &BorderSide {
        width,
        style: item.style,
        color,
      },
      blend_mode,
      opacity,
      clip.as_ref(),
      transform,
    );
    // Right
    self.render_border_edge(
      BorderEdge::Right,
      outer_x + outer_w - width * 0.5,
      outer_y,
      outer_x + outer_w - width * 0.5,
      outer_y + outer_h,
      &BorderSide {
        width,
        style: item.style,
        color,
      },
      blend_mode,
      opacity,
      clip.as_ref(),
      transform,
    );
    self.canvas.restore();
  }

  fn render_border_image(
    &mut self,
    border_image: &BorderImageItem,
    rect: Rect,
    top: f32,
    right: f32,
    bottom: f32,
    left: f32,
    opacity: f32,
    clip: Option<&Mask>,
    transform: Transform,
  ) -> RenderResult<bool> {
    let border_widths = BorderImageWidths {
      top,
      right,
      bottom,
      left,
    };
    let target_widths = resolve_border_image_widths(
      &border_image.width,
      border_widths,
      rect.width(),
      rect.height(),
      border_image.font_size,
      border_image.root_font_size,
      border_image.viewport,
    );
    let outsets = resolve_border_image_outset(
      &border_image.outset,
      target_widths,
      border_image.font_size,
      border_image.root_font_size,
      border_image.viewport,
    );

    let outer_rect = Rect::from_xywh(
      rect.x() - outsets.left,
      rect.y() - outsets.top,
      rect.width() + outsets.left + outsets.right,
      rect.height() + outsets.top + outsets.bottom,
    );
    let inner_rect = Rect::from_xywh(
      outer_rect.x() + target_widths.left,
      outer_rect.y() + target_widths.top,
      outer_rect.width() - target_widths.left - target_widths.right,
      outer_rect.height() - target_widths.top - target_widths.bottom,
    );
    if inner_rect.width() <= 0.0 || inner_rect.height() <= 0.0 {
      return Ok(true);
    }

    let (pixmap, img_w, img_h) = match &border_image.source {
      BorderImageSourceItem::Raster(image) => {
        let Some(pixmap) = self.image_data_to_pixmap(image)? else {
          return Ok(false);
        };
        let (w, h) = (pixmap.width(), pixmap.height());
        if w == 0 || h == 0 {
          return Ok(false);
        }
        (pixmap, w, h)
      }
      BorderImageSourceItem::Generated(bg) => {
        let img_w = outer_rect.width().max(1.0).round() as u32;
        let img_h = outer_rect.height().max(1.0).round() as u32;
        let timer = self.diagnostics_enabled.then(Instant::now);
        let Some(pixmap) = render_generated_border_image(
          bg,
          border_image.current_color,
          border_image.used_dark_color_scheme,
          border_image.forced_colors,
          img_w,
          img_h,
          border_image.font_size,
          border_image.root_font_size,
          border_image.viewport,
          &self.gradient_pixmap_cache,
          &self.gradient_cache,
        ) else {
          return Ok(false);
        };
        if let Some(start) = timer {
          self.record_gradient_usage((img_w * img_h) as u64, start);
        }
        let (w, h) = (pixmap.width(), pixmap.height());
        if w == 0 || h == 0 {
          return Ok(false);
        }
        (pixmap, w, h)
      }
    };

    let slice_top = resolve_slice_value(border_image.slice.top, img_h);
    let slice_right = resolve_slice_value(border_image.slice.right, img_w);
    let slice_bottom = resolve_slice_value(border_image.slice.bottom, img_h);
    let slice_left = resolve_slice_value(border_image.slice.left, img_w);

    let sx0 = 0.0;
    let sx1 = slice_left.min(img_w as f32);
    let sx2 = (img_w as f32 - slice_right).max(sx1);
    let sx3 = img_w as f32;

    let sy0 = 0.0;
    let sy1 = slice_top.min(img_h as f32);
    let sy2 = (img_h as f32 - slice_bottom).max(sy1);
    let sy3 = img_h as f32;

    let (repeat_x, repeat_y) = border_image.repeat;

    // Corners
    self.paint_border_patch(
      &pixmap,
      Rect::from_xywh(sx0, sy0, sx1 - sx0, sy1 - sy0),
      Rect::from_xywh(
        outer_rect.x(),
        outer_rect.y(),
        target_widths.left,
        target_widths.top,
      ),
      BorderImageRepeat::Stretch,
      BorderImageRepeat::Stretch,
      opacity,
      clip,
      transform,
    );
    self.paint_border_patch(
      &pixmap,
      Rect::from_xywh(sx2, sy0, sx3 - sx2, sy1 - sy0),
      Rect::from_xywh(
        outer_rect.x() + outer_rect.width() - target_widths.right,
        outer_rect.y(),
        target_widths.right,
        target_widths.top,
      ),
      BorderImageRepeat::Stretch,
      BorderImageRepeat::Stretch,
      opacity,
      clip,
      transform,
    );
    self.paint_border_patch(
      &pixmap,
      Rect::from_xywh(sx0, sy2, sx1 - sx0, sy3 - sy2),
      Rect::from_xywh(
        outer_rect.x(),
        outer_rect.y() + outer_rect.height() - target_widths.bottom,
        target_widths.left,
        target_widths.bottom,
      ),
      BorderImageRepeat::Stretch,
      BorderImageRepeat::Stretch,
      opacity,
      clip,
      transform,
    );
    self.paint_border_patch(
      &pixmap,
      Rect::from_xywh(sx2, sy2, sx3 - sx2, sy3 - sy2),
      Rect::from_xywh(
        outer_rect.x() + outer_rect.width() - target_widths.right,
        outer_rect.y() + outer_rect.height() - target_widths.bottom,
        target_widths.right,
        target_widths.bottom,
      ),
      BorderImageRepeat::Stretch,
      BorderImageRepeat::Stretch,
      opacity,
      clip,
      transform,
    );

    // Edges
    self.paint_border_patch(
      &pixmap,
      Rect::from_xywh(sx1, sy0, sx2 - sx1, sy1 - sy0),
      Rect::from_xywh(
        inner_rect.x(),
        outer_rect.y(),
        inner_rect.width(),
        target_widths.top,
      ),
      repeat_x,
      BorderImageRepeat::Stretch,
      opacity,
      clip,
      transform,
    );
    self.paint_border_patch(
      &pixmap,
      Rect::from_xywh(sx1, sy2, sx2 - sx1, sy3 - sy2),
      Rect::from_xywh(
        inner_rect.x(),
        outer_rect.y() + outer_rect.height() - target_widths.bottom,
        inner_rect.width(),
        target_widths.bottom,
      ),
      repeat_x,
      BorderImageRepeat::Stretch,
      opacity,
      clip,
      transform,
    );
    self.paint_border_patch(
      &pixmap,
      Rect::from_xywh(sx0, sy1, sx1 - sx0, sy2 - sy1),
      Rect::from_xywh(
        outer_rect.x(),
        inner_rect.y(),
        target_widths.left,
        inner_rect.height(),
      ),
      BorderImageRepeat::Stretch,
      repeat_y,
      opacity,
      clip,
      transform,
    );
    self.paint_border_patch(
      &pixmap,
      Rect::from_xywh(sx2, sy1, sx3 - sx2, sy2 - sy1),
      Rect::from_xywh(
        outer_rect.x() + outer_rect.width() - target_widths.right,
        inner_rect.y(),
        target_widths.right,
        inner_rect.height(),
      ),
      BorderImageRepeat::Stretch,
      repeat_y,
      opacity,
      clip,
      transform,
    );

    if border_image.slice.fill {
      self.paint_border_patch(
        &pixmap,
        Rect::from_xywh(sx1, sy1, sx2 - sx1, sy2 - sy1),
        inner_rect,
        repeat_x,
        repeat_y,
        opacity,
        clip,
        transform,
      );
    }

    Ok(true)
  }

  fn render_border_edge(
    &mut self,
    edge: BorderEdge,
    x1: f32,
    y1: f32,
    x2: f32,
    y2: f32,
    side: &BorderSide,
    blend_mode: tiny_skia::BlendMode,
    opacity: f32,
    clip: Option<&Mask>,
    transform: Transform,
  ) {
    if side.width <= 0.0
      || matches!(side.style, CssBorderStyle::None | CssBorderStyle::Hidden)
      || side.color.is_transparent()
    {
      return;
    }

    let mut paint = tiny_skia::Paint::default();
    set_paint_color(&mut paint, &side.color, opacity);
    paint.blend_mode = blend_mode;
    // For axis-aligned transforms, prefer crisp pixel-snapped solid borders rather than
    // anti-aliased strokes. This matches the rest of the renderer's rect filling behaviour (e.g.
    // background fills) and avoids semi-transparent "bleed" when border edges land on fractional
    // device pixels (common with percentage + centering layouts).
    let axis_aligned_transform = transform.kx.abs() <= 1e-6 && transform.ky.abs() <= 1e-6;
    paint.anti_alias = !axis_aligned_transform || !matches!(side.style, CssBorderStyle::Solid);

    let mut stroke = Stroke::default();
    stroke.width = side.width;
    stroke.line_cap = match side.style {
      CssBorderStyle::Dotted => tiny_skia::LineCap::Round,
      _ => tiny_skia::LineCap::Butt,
    };

    match side.style {
      CssBorderStyle::Dotted => {
        // CSS `dotted` borders are round dots with diameter equal to the border width.
        //
        // A dash length equal to the stroke width with round caps causes adjacent dashes to touch
        // (caps extend by half the stroke width), producing a solid line. Use a gap that is larger
        // than the stroke width so caps don't overlap.
        // Use a relatively large gap so anti-aliased round caps don't visually merge into a
        // continuous line at small border widths.
        stroke.dash = StrokeDash::new(vec![side.width, 3.0 * side.width], 0.0);
      }
      CssBorderStyle::Dashed => {
        stroke.dash = StrokeDash::new(vec![3.0 * side.width, side.width], 0.0);
      }
      _ => {}
    }

    let mut x1 = x1;
    let mut y1 = y1;
    let mut x2 = x2;
    let mut y2 = y2;
    let transform_is_translate_only = (transform.sx - 1.0).abs() < 1e-6
      && (transform.sy - 1.0).abs() < 1e-6
      && transform.kx.abs() < 1e-6
      && transform.ky.abs() < 1e-6;
    if transform_is_translate_only
      && stroke.dash.is_none()
      && matches!(stroke.line_cap, tiny_skia::LineCap::Butt)
      && Self::is_near_integer(stroke.width)
    {
      match edge.orientation() {
        EdgeOrientation::Horizontal => {
          let device_y = y1 + transform.ty;
          let snapped_device_y =
            Self::snap_axis_aligned_stroke_center_to_device_pixels(device_y, stroke.width);
          let snapped_local_y = snapped_device_y - transform.ty;
          y1 = snapped_local_y;
          y2 = snapped_local_y;
        }
        EdgeOrientation::Vertical => {
          let device_x = x1 + transform.tx;
          let snapped_device_x =
            Self::snap_axis_aligned_stroke_center_to_device_pixels(device_x, stroke.width);
          let snapped_local_x = snapped_device_x - transform.tx;
          x1 = snapped_local_x;
          x2 = snapped_local_x;
        }
      }
      paint.anti_alias = false;
    }

    let mut path = PathBuilder::new();
    path.move_to(x1, y1);
    path.line_to(x2, y2);
    let Some(base_path) = path.finish() else {
      return;
    };

    match side.style {
      CssBorderStyle::Double => {
        // When the stroke is too thin to draw two lines and a gap, fall back to a solid stroke.
        if side.width < 3.0 {
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            pixmap.stroke_path(&base_path, &paint, &stroke, transform, clip);
          });
          return;
        }

        let third = side.width / 3.0;
        let offset = third + third * 0.5;

        let (outer_path, inner_path) = edge.parallel_lines(x1, y1, x2, y2, offset);

        let mut inner_stroke = stroke.clone();
        inner_stroke.width = third;
        stroke.width = third;

        if let Some(outer) = outer_path {
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            pixmap.stroke_path(&outer, &paint, &stroke, transform, clip);
          });
        }
        if let Some(inner) = inner_path {
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            pixmap.stroke_path(&inner, &paint, &inner_stroke, transform, clip);
          });
        }
      }
      CssBorderStyle::Groove | CssBorderStyle::Ridge => {
        let half = side.width / 2.0;
        let offset = half * 0.5;
        let (first_path, second_path) = edge.parallel_lines(x1, y1, x2, y2, offset);

        let mut first_paint = paint.clone();
        let mut second_paint = paint.clone();
        let mut first_stroke = stroke.clone();
        let mut second_stroke = stroke.clone();
        first_stroke.width = half;
        second_stroke.width = half;

        let (first_color, second_color) = edge.groove_ridge_colors(&side.color, side.style);
        set_paint_color(&mut first_paint, &first_color, opacity);
        set_paint_color(&mut second_paint, &second_color, opacity);

        if let Some(first) = first_path {
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            pixmap.stroke_path(&first, &first_paint, &first_stroke, transform, clip);
          });
        }
        if let Some(second) = second_path {
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            pixmap.stroke_path(&second, &second_paint, &second_stroke, transform, clip);
          });
        }
      }
      CssBorderStyle::Inset | CssBorderStyle::Outset => {
        let shaded = edge.inset_outset_color(&side.color, side.style);
        set_paint_color(&mut paint, &shaded, opacity);
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          pixmap.stroke_path(&base_path, &paint, &stroke, transform, clip);
        });
      }
      _ => {
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          pixmap.stroke_path(&base_path, &paint, &stroke, transform, clip);
        });
      }
    }
  }

  fn paint_border_patch(
    &mut self,
    source: &Pixmap,
    src_rect: Rect,
    dest_rect: Rect,
    repeat_x: BorderImageRepeat,
    repeat_y: BorderImageRepeat,
    opacity: f32,
    clip: Option<&Mask>,
    transform: Transform,
  ) {
    if src_rect.width() <= 0.0
      || src_rect.height() <= 0.0
      || dest_rect.width() <= 0.0
      || dest_rect.height() <= 0.0
    {
      return;
    }

    let sx0 = src_rect.x().max(0.0).floor() as u32;
    let sy0 = src_rect.y().max(0.0).floor() as u32;
    let sx1 = (src_rect.x() + src_rect.width())
      .ceil()
      .min(source.width() as f32)
      .max(0.0) as u32;
    let sy1 = (src_rect.y() + src_rect.height())
      .ceil()
      .min(source.height() as f32)
      .max(0.0) as u32;
    if sx1 <= sx0 || sy1 <= sy0 {
      return;
    }
    let width = sx1 - sx0;
    let height = sy1 - sy0;

    let Some(size) = IntSize::from_wh(width, height) else {
      return;
    };
    let Some(bytes) = rgba_bytes(width, height) else {
      return;
    };
    let mut patch = match reserve_buffer(bytes, "border-image patch") {
      Ok(buf) => buf,
      Err(_) => return,
    };

    let data = source.data();
    let source_width = source.width();
    let Some(row_bytes) = u64::from(width).checked_mul(4) else {
      return;
    };
    for row in sy0..sy1 {
      let Some(start) = u64::from(row)
        .checked_mul(u64::from(source_width))
        .and_then(|v| v.checked_add(u64::from(sx0)))
        .and_then(|v| v.checked_mul(4))
      else {
        return;
      };
      let Some(end) = start.checked_add(row_bytes) else {
        return;
      };
      let Ok(start) = usize::try_from(start) else {
        return;
      };
      let Ok(end) = usize::try_from(end) else {
        return;
      };
      if end > data.len() || start > end {
        return;
      }
      patch.extend_from_slice(&data[start..end]);
    }
    let Some(patch_pixmap) = Pixmap::from_vec(patch, size) else {
      return;
    };

    let mut tile_w = dest_rect.width();
    let mut tile_h = dest_rect.height();

    let mut scale_x = tile_w / width as f32;
    let mut scale_y = tile_h / height as f32;

    if repeat_x != BorderImageRepeat::Stretch {
      scale_x = scale_y;
      tile_w = width as f32 * scale_x;
    }
    if repeat_y != BorderImageRepeat::Stretch {
      scale_y = scale_x;
      tile_h = height as f32 * scale_y;
    }

    if repeat_x == BorderImageRepeat::Round && tile_w > 0.0 {
      let count = (dest_rect.width() / tile_w).round().max(1.0);
      tile_w = dest_rect.width() / count;
      scale_x = tile_w / width as f32;
    }
    if repeat_y == BorderImageRepeat::Round && tile_h > 0.0 {
      let count = (dest_rect.height() / tile_h).round().max(1.0);
      tile_h = dest_rect.height() / count;
      scale_y = tile_h / height as f32;
    }

    // Border image repeat modes can request an unbounded number of tiles when the destination is
    // extremely thin (e.g. height ≪ 1px but width is reasonable). Casting those huge counts to
    // usize can panic (capacity overflow) and even bounded counts can still OOM if we try to
    // allocate position tables. Keep this path stable by bounding tile counts and falling back to
    // a repeated pattern shader when the manual tiling would be pathological.
    const MAX_BORDER_IMAGE_TILES_PER_AXIS: f32 = 4096.0;
    let paint_repeated_patch = |renderer: &mut Self| {
      let Some(dest_sk_rect) = tiny_skia::Rect::from_xywh(
        dest_rect.x(),
        dest_rect.y(),
        dest_rect.width(),
        dest_rect.height(),
      ) else {
        return;
      };
      let mut paint = tiny_skia::Paint::default();
      paint.shader = Pattern::new(
        patch_pixmap.as_ref(),
        SpreadMode::Repeat,
        tiny_skia::FilterQuality::Bilinear,
        opacity,
        Transform::from_row(scale_x, 0.0, 0.0, scale_y, dest_rect.x(), dest_rect.y()),
      );
      paint.anti_alias = false;
      renderer.canvas.with_mirrored_pixmap_mut(|pixmap| {
        pixmap.fill_rect(dest_sk_rect, &paint, transform, clip);
      });
    };

    let tiles_x = dest_rect.width() / tile_w;
    let tiles_y = dest_rect.height() / tile_h;
    let too_many_x = repeat_x != BorderImageRepeat::Stretch
      && (!tiles_x.is_finite() || tiles_x > MAX_BORDER_IMAGE_TILES_PER_AXIS);
    let too_many_y = repeat_y != BorderImageRepeat::Stretch
      && (!tiles_y.is_finite() || tiles_y > MAX_BORDER_IMAGE_TILES_PER_AXIS);
    if too_many_x || too_many_y {
      paint_repeated_patch(self);
      return;
    }

    let positions_x = match repeat_x {
      BorderImageRepeat::Stretch => vec![dest_rect.x()],
      BorderImageRepeat::Round => {
        let end = dest_rect.x() + dest_rect.width();
        if tile_w <= 0.0 {
          return;
        }
        let count =
          (tiles_x.ceil().max(1.0) as usize).min(MAX_BORDER_IMAGE_TILES_PER_AXIS as usize);
        let mut pos = Vec::new();
        if pos.try_reserve_exact(count).is_err() {
          paint_repeated_patch(self);
          return;
        }
        let mut cursor = dest_rect.x();
        for _ in 0..count {
          if cursor >= end - 1e-3 {
            break;
          }
          pos.push(cursor);
          cursor += tile_w;
        }
        pos
      }
      BorderImageRepeat::Space => {
        if tile_w <= 0.0 {
          return;
        }
        let count = tiles_x.floor();
        if count < 1.0 {
          vec![dest_rect.x() + (dest_rect.width() - tile_w) * 0.5]
        } else if count < 2.0 {
          vec![dest_rect.x() + (dest_rect.width() - tile_w) * 0.5]
        } else {
          let spacing = (dest_rect.width() - tile_w * count) / (count - 1.0);
          let count = count as usize;
          let mut pos = Vec::new();
          if pos.try_reserve_exact(count).is_err() {
            paint_repeated_patch(self);
            return;
          }
          let mut cursor = dest_rect.x();
          for _ in 0..count {
            pos.push(cursor);
            cursor += tile_w + spacing;
          }
          pos
        }
      }
      BorderImageRepeat::Repeat => {
        let end = dest_rect.x() + dest_rect.width();
        if tile_w <= 0.0 {
          return;
        }
        let count =
          (tiles_x.ceil().max(1.0) as usize).min(MAX_BORDER_IMAGE_TILES_PER_AXIS as usize);
        let mut pos = Vec::new();
        if pos.try_reserve_exact(count).is_err() {
          paint_repeated_patch(self);
          return;
        }
        let mut cursor = dest_rect.x();
        for _ in 0..count {
          if cursor >= end - 1e-3 {
            break;
          }
          pos.push(cursor);
          cursor += tile_w;
        }
        pos
      }
    };

    let positions_y = match repeat_y {
      BorderImageRepeat::Stretch => vec![dest_rect.y()],
      BorderImageRepeat::Round => {
        let end = dest_rect.y() + dest_rect.height();
        if tile_h <= 0.0 {
          return;
        }
        let count =
          (tiles_y.ceil().max(1.0) as usize).min(MAX_BORDER_IMAGE_TILES_PER_AXIS as usize);
        let mut pos = Vec::new();
        if pos.try_reserve_exact(count).is_err() {
          paint_repeated_patch(self);
          return;
        }
        let mut cursor = dest_rect.y();
        for _ in 0..count {
          if cursor >= end - 1e-3 {
            break;
          }
          pos.push(cursor);
          cursor += tile_h;
        }
        pos
      }
      BorderImageRepeat::Space => {
        if tile_h <= 0.0 {
          return;
        }
        let count = tiles_y.floor();
        if count < 1.0 {
          vec![dest_rect.y() + (dest_rect.height() - tile_h) * 0.5]
        } else if count < 2.0 {
          vec![dest_rect.y() + (dest_rect.height() - tile_h) * 0.5]
        } else {
          let spacing = (dest_rect.height() - tile_h * count) / (count - 1.0);
          let count = count as usize;
          let mut pos = Vec::new();
          if pos.try_reserve_exact(count).is_err() {
            paint_repeated_patch(self);
            return;
          }
          let mut cursor = dest_rect.y();
          for _ in 0..count {
            pos.push(cursor);
            cursor += tile_h + spacing;
          }
          pos
        }
      }
      BorderImageRepeat::Repeat => {
        let end = dest_rect.y() + dest_rect.height();
        if tile_h <= 0.0 {
          return;
        }
        let count =
          (tiles_y.ceil().max(1.0) as usize).min(MAX_BORDER_IMAGE_TILES_PER_AXIS as usize);
        let mut pos = Vec::new();
        if pos.try_reserve_exact(count).is_err() {
          paint_repeated_patch(self);
          return;
        }
        let mut cursor = dest_rect.y();
        for _ in 0..count {
          if cursor >= end - 1e-3 {
            break;
          }
          pos.push(cursor);
          cursor += tile_h;
        }
        pos
      }
    };

    let clip_rect = dest_rect;
    for ty in positions_y.iter().copied() {
      for tx in positions_x.iter().copied() {
        let tile_rect = Rect::from_xywh(tx, ty, tile_w, tile_h);
        let Some(intersection) = tile_rect.intersection(clip_rect) else {
          continue;
        };
        if intersection.width() <= 0.0 || intersection.height() <= 0.0 {
          continue;
        }
        let Some(src_rect) = tiny_skia::Rect::from_xywh(
          intersection.x(),
          intersection.y(),
          intersection.width(),
          intersection.height(),
        ) else {
          continue;
        };
        let mut paint = tiny_skia::Paint::default();
        paint.shader = Pattern::new(
          patch_pixmap.as_ref(),
          SpreadMode::Pad,
          tiny_skia::FilterQuality::Bilinear,
          opacity,
          Transform::from_row(scale_x, 0.0, 0.0, scale_y, tx, ty),
        );
        paint.anti_alias = false;
        paint.blend_mode = self.canvas.blend_mode();
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          pixmap.fill_rect(src_rect, &paint, transform, clip);
        });
      }
    }
  }

  fn render_mask(&mut self, mask: &ResolvedMask) -> RenderResult<Option<OffsetMask>> {
    check_active(RenderStage::Paint)?;
    let mut reusable_mask = MASK_RENDER_SCRATCH.with(|cell| cell.borrow_mut().take());

    let viewport = mask.viewport.unwrap_or((
      self.canvas.width() as f32 / self.scale,
      self.canvas.height() as f32 / self.scale,
    ));
    let rects = mask.rects;
    let mut combined: Option<CompositeMask> = None;
    let transform = self.canvas.transform();
    let inv_transform = (transform == Transform::identity())
      .then_some(Transform::identity())
      .or_else(|| {
        // `render_mask` needs to clip mask rasterization to the visible canvas region. Mask
        // reference rectangles are expressed in global CSS coordinates, while the underlying
        // canvas pixmap is always rooted at (0,0) in *pixmap* space. When the canvas has a
        // translation (parallel tiling or bounded layers), we must map the pixmap bounds back into
        // CSS space to intersect correctly.
        invert_transform(transform)
      });

    let (canvas_bounds_css, canvas_clip_bounds_css) = if let Some(inv) = inv_transform {
      let bounds_device = transform_rect(self.canvas.bounds(), &inv);
      let bounds_css = Rect::from_xywh(
        bounds_device.x() / self.scale,
        bounds_device.y() / self.scale,
        bounds_device.width() / self.scale,
        bounds_device.height() / self.scale,
      );
      let clip_css = self
        .canvas
        .clip_bounds()
        .map(|rect| {
          let clip_device = transform_rect(rect, &inv);
          Rect::from_xywh(
            clip_device.x() / self.scale,
            clip_device.y() / self.scale,
            clip_device.width() / self.scale,
            clip_device.height() / self.scale,
          )
        })
        .unwrap_or(bounds_css);
      (bounds_css, clip_css)
    } else {
      // Non-invertible transforms can't be mapped back into CSS space; fall back to the legacy
      // origin-at-(0,0) behavior rather than allocating an unbounded mask.
      let bounds_css = Rect::from_xywh(0.0, 0.0, viewport.0, viewport.1);
      let clip_css = self
        .canvas
        .clip_bounds()
        .map(|rect| {
          Rect::from_xywh(
            rect.x() / self.scale,
            rect.y() / self.scale,
            rect.width() / self.scale,
            rect.height() / self.scale,
          )
        })
        .unwrap_or(bounds_css);
      (bounds_css, clip_css)
    };

    let wants_text_clip = mask
      .layers
      .iter()
      .any(|layer| matches!(layer.clip, MaskClip::Text));
    let text_clip_runs = mask.text_clip.as_deref();
    let has_text_clip_runs = text_clip_runs.is_some_and(|runs| !runs.is_empty());
    let text_clip_bounds_css = text_clip_runs.map(crate::paint::display_list::text_runs_bounds);
    let text_clip_mask: Option<Rc<Mask>> = if wants_text_clip && has_text_clip_runs {
      let scaled: Vec<TextItem> = text_clip_runs
        .unwrap_or(&[])
        .iter()
        .map(|run| self.scale_text_item(run))
        .collect();

      // Rasterize a text alpha mask once per `render_mask` call and re-use it for any layers that
      // specify `mask-clip: text`. Use `Canvas::set_clip_text` to keep serial vs tiled output
      // byte-identical (it includes padding/cropping logic to avoid seams at tile boundaries).
      self.canvas.save();
      self.canvas.clear_clip();
      let clip_result = self.canvas.set_clip_text(&scaled);
      let clip_mask = self.canvas.clip_mask_rc();
      self.canvas.restore();

      clip_result.map_err(|err| match err {
        Error::Render(render_err) => render_err,
        other => RenderError::PaintFailed {
          operation: other.to_string(),
        },
      })?;

      clip_mask
    } else {
      None
    };

    for layer in mask.layers.iter().rev() {
      // When `mask-clip:text` is specified but no text runs were captured for the masked subtree,
      // treat the layer as fully transparent (matching typical browser behavior).
      if matches!(layer.clip, MaskClip::Text) && !has_text_clip_runs {
        combined = Some(match combined.take() {
          Some(existing) => {
            match apply_mask_composite(existing, CompositeMask::Transparent, layer.composite)? {
              Some(mask) => mask,
              None => return Ok(None),
            }
          }
          None => CompositeMask::Transparent,
        });
        continue;
      }

      let origin_rect_css = match layer.origin {
        MaskOrigin::BorderBox => rects.border,
        MaskOrigin::PaddingBox => rects.padding,
        MaskOrigin::ContentBox | MaskOrigin::Text => rects.content,
      };
      let clip_rect_css = match layer.clip {
        MaskClip::BorderBox => rects.border,
        MaskClip::PaddingBox => rects.padding,
        MaskClip::ContentBox => rects.content,
        MaskClip::Text => text_clip_bounds_css.unwrap_or(rects.content),
        MaskClip::NoClip => canvas_bounds_css,
      };
      if origin_rect_css.width() <= 0.0
        || origin_rect_css.height() <= 0.0
        || clip_rect_css.width() <= 0.0
        || clip_rect_css.height() <= 0.0
      {
        continue;
      }

      let Some(clip_rect_css) = clip_rect_css
        .intersection(canvas_bounds_css)
        .and_then(|r| r.intersection(canvas_clip_bounds_css))
      else {
        combined = Some(match combined.take() {
          Some(existing) => {
            match apply_mask_composite(existing, CompositeMask::Transparent, layer.composite)? {
              Some(mask) => mask,
              None => return Ok(None),
            }
          }
          None => CompositeMask::Transparent,
        });
        continue;
      };
      if clip_rect_css.width() <= 0.0 || clip_rect_css.height() <= 0.0 {
        combined = Some(match combined.take() {
          Some(existing) => {
            match apply_mask_composite(existing, CompositeMask::Transparent, layer.composite)? {
              Some(mask) => mask,
              None => return Ok(None),
            }
          }
          None => CompositeMask::Transparent,
        });
        continue;
      }

      let (img_w, img_h, intrinsic_ratio) = match &layer.image {
        ResolvedMaskImage::Raster(image) => {
          let img_w = image.css_width;
          let img_h = image.css_height;
          let ratio = if image.has_intrinsic_ratio {
            if img_w > 0.0 && img_h > 0.0 {
              Some(img_w / img_h)
            } else if image.width > 0 && image.height > 0 {
              // When an image has an intrinsic ratio but no intrinsic size (e.g. viewBox-only SVG),
              // we keep `css_width/css_height` at 0 but can still recover the ratio from the raster
              // buffer which preserves that aspect ratio.
              Some(image.width as f32 / image.height as f32)
            } else {
              None
            }
          } else {
            None
          };
          (img_w, img_h, ratio.filter(|r| r.is_finite() && *r > 0.0))
        }
        ResolvedMaskImage::Generated(_) => (0.0, 0.0, None),
      };
      let (mut tile_w, mut tile_h) = compute_background_size_from_value(
        &layer.size,
        mask.font_size,
        mask.root_font_size,
        viewport,
        origin_rect_css.width(),
        origin_rect_css.height(),
        img_w,
        img_h,
        intrinsic_ratio,
      );
      if tile_w <= 0.0 || tile_h <= 0.0 {
        continue;
      }

      let mut rounded_x = false;
      let mut rounded_y = false;
      if layer.repeat.x == BackgroundRepeatKeyword::Round {
        tile_w = round_tile_length(origin_rect_css.width(), tile_w);
        rounded_x = true;
      }
      if layer.repeat.y == BackgroundRepeatKeyword::Round {
        tile_h = round_tile_length(origin_rect_css.height(), tile_h);
        rounded_y = true;
      }
      if rounded_x ^ rounded_y
        && matches!(
          layer.size,
          BackgroundSize::Explicit(BackgroundSizeComponent::Auto, BackgroundSizeComponent::Auto)
        )
      {
        let aspect = intrinsic_ratio.unwrap_or_else(|| {
          if img_w > 0.0 && img_h > 0.0 {
            img_w / img_h
          } else {
            1.0
          }
        });
        if rounded_x {
          tile_h = tile_w / aspect;
        } else {
          tile_w = tile_h * aspect;
        }
      }

      let (offset_x, offset_y) = resolve_background_offset(
        layer.position,
        origin_rect_css.width(),
        origin_rect_css.height(),
        tile_w,
        tile_h,
        mask.font_size,
        mask.root_font_size,
        viewport,
      );

      let positions_x = tile_axis_plan(
        layer.repeat.x,
        origin_rect_css.x(),
        origin_rect_css.width(),
        tile_w,
        offset_x,
        clip_rect_css.min_x(),
        clip_rect_css.max_x(),
      );
      let positions_y = tile_axis_plan(
        layer.repeat.y,
        origin_rect_css.y(),
        origin_rect_css.height(),
        tile_h,
        offset_y,
        clip_rect_css.min_y(),
        clip_rect_css.max_y(),
      );
      if positions_x.count == 0 || positions_y.count == 0 {
        combined = Some(match combined.take() {
          Some(existing) => {
            match apply_mask_composite(existing, CompositeMask::Transparent, layer.composite)? {
              Some(mask) => mask,
              None => return Ok(None),
            }
          }
          None => CompositeMask::Transparent,
        });
        continue;
      }

      // Generated images (gradients) have no intrinsic size, so `auto` sizing expands them to the
      // full positioning area. On long-scrolling pages this can yield enormous tiles even though
      // we only ever sample the part that intersects the current viewport. When the tiling plan
      // produces a single tile for both axes, crop the generated gradient to the visible portion
      // so we avoid rasterizing the entire (potentially multi-megapixel) backing image.
      let mut generated_tile_override: Option<(f32, f32, f32, f32)> = None;
      let tile = match &layer.image {
        ResolvedMaskImage::Generated(image) => {
          let full_w = tile_w.ceil().max(1.0) as u32;
          let full_h = tile_h.ceil().max(1.0) as u32;
          let timer = self.diagnostics_enabled.then(Instant::now);

          let mut result = None;
          let mut pixels = (full_w as u64).saturating_mul(full_h as u64);
          if positions_x.count == 1 && positions_y.count == 1 {
            let tx = positions_x.start;
            let ty = positions_y.start;
            let tile_rect = Rect::from_xywh(tx, ty, tile_w, tile_h);
            if let Some(intersection) = tile_rect.intersection(clip_rect_css) {
              let scale_x = tile_w / full_w.max(1) as f32;
              let scale_y = tile_h / full_h.max(1) as f32;
              if scale_x.is_finite()
                && scale_y.is_finite()
                && scale_x > 0.0
                && scale_y > 0.0
                && intersection.width() > 0.0
                && intersection.height() > 0.0
              {
                let crop_x = ((intersection.x() - tx) / scale_x).max(0.0);
                let crop_y = ((intersection.y() - ty) / scale_y).max(0.0);
                let crop_w = (intersection.width() / scale_x).ceil().max(1.0) as u32;
                let crop_h = (intersection.height() / scale_y).ceil().max(1.0) as u32;
                let cropped = render_generated_border_image_subrect(
                  image,
                  mask.color,
                  mask.used_dark_color_scheme,
                  mask.forced_colors,
                  full_w,
                  full_h,
                  crop_x,
                  crop_y,
                  crop_w,
                  crop_h,
                  mask.font_size,
                  mask.root_font_size,
                  Some(viewport),
                  &self.gradient_pixmap_cache,
                  &self.gradient_cache,
                );
                if cropped.is_some() {
                  generated_tile_override = Some((
                    intersection.x(),
                    intersection.y(),
                    intersection.width(),
                    intersection.height(),
                  ));
                  pixels = (crop_w as u64).saturating_mul(crop_h as u64);
                  result = cropped;
                }
              }
            }
          }

          let result = result.or_else(|| {
            render_generated_border_image(
              image,
              mask.color,
              mask.used_dark_color_scheme,
              mask.forced_colors,
              full_w,
              full_h,
              mask.font_size,
              mask.root_font_size,
              Some(viewport),
              &self.gradient_pixmap_cache,
              &self.gradient_cache,
            )
          });

          if let (Some(start), Some(_)) = (timer, result.as_ref()) {
            self.record_gradient_usage(pixels, start);
          }
          result
        }
        ResolvedMaskImage::Raster(image) => self.image_data_to_pixmap(image)?,
      };
      let Some(tile) = tile else { continue };
      let mut converted_tile = None;
      let mask_tile = match layer.mode {
        MaskMode::Alpha | MaskMode::MatchSource => tile.as_ref(),
        MaskMode::Luminance => {
          let Some(mask_tile) = mask_tile_from_image(tile.as_ref(), layer.mode)? else {
            continue;
          };
          converted_tile = Some(mask_tile);
          converted_tile.as_ref().unwrap()
        }
      };

      // `clip_rect_css` is expressed in global CSS coordinates. Convert it into device space and
      // then through the current canvas transform so we allocate the mask in the correct pixmap
      // coordinate space (tile-local, bounded-layer-local, etc.).
      let device_x0 = (clip_rect_css.min_x() * self.scale).floor() as i32;
      let device_y0 = (clip_rect_css.min_y() * self.scale).floor() as i32;
      let device_x1 = (clip_rect_css.max_x() * self.scale).ceil() as i32;
      let device_y1 = (clip_rect_css.max_y() * self.scale).ceil() as i32;
      let device_w = device_x1.saturating_sub(device_x0);
      let device_h = device_y1.saturating_sub(device_y0);

      let device_rect = Rect::from_xywh(
        device_x0 as f32,
        device_y0 as f32,
        device_w as f32,
        device_h as f32,
      );
      let pixmap_rect = if transform == Transform::identity() {
        device_rect
      } else {
        transform_rect(device_rect, &transform)
      };

      let canvas_w = self.canvas.width() as i32;
      let canvas_h = self.canvas.height() as i32;
      let mut pix_x0 = pixmap_rect.min_x().floor() as i32;
      let mut pix_y0 = pixmap_rect.min_y().floor() as i32;
      let mut pix_x1 = pixmap_rect.max_x().ceil() as i32;
      let mut pix_y1 = pixmap_rect.max_y().ceil() as i32;
      pix_x0 = pix_x0.clamp(0, canvas_w);
      pix_y0 = pix_y0.clamp(0, canvas_h);
      pix_x1 = pix_x1.clamp(0, canvas_w);
      pix_y1 = pix_y1.clamp(0, canvas_h);
      let region_w = pix_x1.saturating_sub(pix_x0) as u32;
      let region_h = pix_y1.saturating_sub(pix_y0) as u32;
      if region_w == 0 || region_h == 0 {
        combined = Some(match combined.take() {
          Some(existing) => {
            match apply_mask_composite(existing, CompositeMask::Transparent, layer.composite)? {
              Some(mask) => mask,
              None => return Ok(None),
            }
          }
          None => CompositeMask::Transparent,
        });
        continue;
      }

      // `paint_mask_tile` draws into a standalone pixmap and expects the destination origin in
      // *device* coordinates (CSS * scale). The `OffsetMask` origin we return must be in the
      // *parent pixmap* coordinate space so it lines up with `Canvas::pop_layer_raw` origins.
      let dest_origin_device = if transform == Transform::identity() {
        (pix_x0, pix_y0)
      } else if let Some(inv) = inv_transform {
        let x = pix_x0 as f32;
        let y = pix_y0 as f32;
        let dx = x * inv.sx + y * inv.kx + inv.tx;
        let dy = x * inv.ky + y * inv.sy + inv.ty;
        (dx.round() as i32, dy.round() as i32)
      } else {
        (device_x0, device_y0)
      };

      let wants_reuse =
        reusable_mask.is_some() && matches!(combined, None | Some(CompositeMask::Transparent));
      let mut layer_mask = if wants_reuse {
        match reusable_mask.take() {
          Some(mask) if mask.width() == region_w && mask.height() == region_h => mask,
          Some(_) | None => {
            let Some(mask) = Mask::new(region_w, region_h) else {
              return Ok(None);
            };
            mask
          }
        }
      } else {
        let Some(mask) = Mask::new(region_w, region_h) else {
          return Ok(None);
        };
        mask
      };

      let apply_text_clip = matches!(layer.clip, MaskClip::Text);
      let text_clip_mask_ref = text_clip_mask.as_deref();

      let rendered_layer = MASK_LAYER_PIXMAP_SCRATCH.with(|cell| -> RenderResult<Option<()>> {
        let mut scratch = cell.borrow_mut();
        let replace = match scratch.pixmap.as_ref() {
          Some(existing) => existing.width() != region_w || existing.height() != region_h,
          None => true,
        };
        if replace {
          scratch.pixmap = new_pixmap(region_w, region_h);
        }
        let Some(mask_pixmap) = scratch.pixmap.as_mut() else {
          return Ok(None);
        };
        let mut clear_deadline_counter = 0usize;
        let clear_chunk_bytes = CLIP_MASK_DEADLINE_STRIDE.saturating_mul(4);
        for chunk in mask_pixmap.data_mut().chunks_mut(clear_chunk_bytes) {
          check_active_periodic(&mut clear_deadline_counter, 1, RenderStage::Paint)?;
          chunk.fill(0);
        }
        let mut tile_deadline_counter = 0usize;
        if let Some((tx, ty, tile_w, tile_h)) = generated_tile_override {
          check_active_periodic(
            &mut tile_deadline_counter,
            DEADLINE_STRIDE,
            RenderStage::Paint,
          )?;
          paint_mask_tile(
            mask_pixmap,
            mask_tile,
            tx,
            ty,
            tile_w,
            tile_h,
            clip_rect_css,
            self.scale,
            dest_origin_device,
          );
        } else {
          for ty in positions_y.iter() {
            for tx in positions_x.iter() {
              check_active_periodic(
                &mut tile_deadline_counter,
                DEADLINE_STRIDE,
                RenderStage::Paint,
              )?;
              paint_mask_tile(
                mask_pixmap,
                mask_tile,
                tx,
                ty,
                tile_w,
                tile_h,
                clip_rect_css,
                self.scale,
                dest_origin_device,
              );
            }
          }
        }

        let expected_len = (region_w as usize).saturating_mul(region_h as usize);
        let src = mask_pixmap.data();
        debug_assert_eq!(
          layer_mask.data().len(),
          expected_len,
          "expected mask byte length to match region dimensions"
        );
        debug_assert_eq!(
          src.len(),
          expected_len.saturating_mul(4),
          "expected scratch mask pixmap to be tightly packed RGBA"
        );

        if !apply_text_clip {
          let mut alpha_deadline_counter = 0usize;
          let mut src_idx = 3usize;
          for dst_chunk in layer_mask.data_mut().chunks_mut(CLIP_MASK_DEADLINE_STRIDE) {
            check_active_periodic(&mut alpha_deadline_counter, 1, RenderStage::Paint)?;
            for dst in dst_chunk.iter_mut() {
              *dst = src[src_idx];
              src_idx += 4;
            }
          }
          debug_assert_eq!(
            src_idx,
            expected_len.saturating_mul(4).saturating_add(3),
            "expected to copy exactly one alpha byte per RGBA pixel"
          );
        } else if let Some(text_mask) = text_clip_mask_ref {
          debug_assert_eq!(
            text_mask.width(),
            self.canvas.width(),
            "expected text clip mask width to match canvas width"
          );
          debug_assert_eq!(
            text_mask.height(),
            self.canvas.height(),
            "expected text clip mask height to match canvas height"
          );

          let text_stride = text_mask.width() as usize;
          let text_data = text_mask.data();
          let row_len = region_w as usize;
          let dst = layer_mask.data_mut();
          let mut alpha_deadline_counter = 0usize;
          for row in 0..region_h as usize {
            let dst_row_idx = row * row_len;
            let src_row_idx = row * row_len * 4;
            let text_row_idx = (pix_y0 as usize + row) * text_stride + pix_x0 as usize;
            for x0 in (0..row_len).step_by(CLIP_MASK_DEADLINE_STRIDE) {
              check_active_periodic(&mut alpha_deadline_counter, 1, RenderStage::Paint)?;
              let x1 = (x0 + CLIP_MASK_DEADLINE_STRIDE).min(row_len);
              for x in x0..x1 {
                let alpha = src[src_row_idx + x * 4 + 3] as u16;
                let clip = text_data[text_row_idx + x] as u16;
                dst[dst_row_idx + x] = div_255(alpha * clip) as u8;
              }
            }
          }
        } else {
          // If no text clip mask is available, treat the layer as fully transparent.
          layer_mask.data_mut().fill(0);
        }
        Ok(Some(()))
      });
      let rendered_layer = rendered_layer?;
      if rendered_layer.is_none() {
        return Ok(None);
      }

      let layer_mask = CompositeMask::Region(OffsetMask {
        mask: layer_mask,
        origin: (pix_x0, pix_y0),
      });

      combined = Some(match combined.take() {
        Some(existing) => match apply_mask_composite(existing, layer_mask, layer.composite)? {
          Some(mask) => mask,
          None => return Ok(None),
        },
        None => layer_mask,
      });
    }

    Ok(match combined {
      None => {
        MASK_RENDER_SCRATCH.with(|cell| {
          *cell.borrow_mut() = reusable_mask;
        });
        None
      }
      Some(CompositeMask::Region(mask)) => Some(mask),
      Some(CompositeMask::Transparent) => {
        MASK_RENDER_SCRATCH.with(|cell| {
          *cell.borrow_mut() = reusable_mask;
        });
        let Some(mut mask) = Mask::new(1, 1) else {
          return Ok(None);
        };
        mask.data_mut()[0] = 0;
        Some(OffsetMask {
          mask,
          origin: (0, 0),
        })
      }
    })
  }

  fn render_mask_border(
    &mut self,
    mask_border: &ResolvedMaskBorder,
    transform: Transform,
  ) -> RenderResult<Option<OffsetMask>> {
    check_active(RenderStage::Paint)?;
    let mut reusable_mask = MASK_RENDER_SCRATCH.with(|cell| cell.borrow_mut().take());

    // Align to the element's border box in global CSS coordinates.
    let rect_css = mask_border.rect;
    if rect_css.width() <= 0.0 || rect_css.height() <= 0.0 {
      MASK_RENDER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = reusable_mask;
      });
      return Ok(None);
    }

    let viewport = mask_border.viewport.unwrap_or((
      self.canvas.width() as f32 / self.scale,
      self.canvas.height() as f32 / self.scale,
    ));
    let inv_transform = (transform == Transform::identity())
      .then_some(Transform::identity())
      .or_else(|| invert_transform(transform));

    let (canvas_bounds_css, canvas_clip_bounds_css) = if let Some(inv) = inv_transform {
      let bounds_device = transform_rect(self.canvas.bounds(), &inv);
      let bounds_css = Rect::from_xywh(
        bounds_device.x() / self.scale,
        bounds_device.y() / self.scale,
        bounds_device.width() / self.scale,
        bounds_device.height() / self.scale,
      );
      let clip_css = self
        .canvas
        .clip_bounds()
        .map(|rect| {
          let clip_device = transform_rect(rect, &inv);
          Rect::from_xywh(
            clip_device.x() / self.scale,
            clip_device.y() / self.scale,
            clip_device.width() / self.scale,
            clip_device.height() / self.scale,
          )
        })
        .unwrap_or(bounds_css);
      (bounds_css, clip_css)
    } else {
      let bounds_css = Rect::from_xywh(0.0, 0.0, viewport.0, viewport.1);
      let clip_css = self
        .canvas
        .clip_bounds()
        .map(|rect| {
          Rect::from_xywh(
            rect.x() / self.scale,
            rect.y() / self.scale,
            rect.width() / self.scale,
            rect.height() / self.scale,
          )
        })
        .unwrap_or(bounds_css);
      (bounds_css, clip_css)
    };

    // Decode (or generate) the source image first so we can resolve slice-based `auto` widths.
    let (source_pixmap, img_w, img_h, intrinsic_css_size) = match &mask_border.source {
      BorderImageSourceItem::Raster(image) => {
        let Some(pixmap) = self.image_data_to_pixmap(image)? else {
          MASK_RENDER_SCRATCH.with(|cell| {
            *cell.borrow_mut() = reusable_mask;
          });
          return Ok(None);
        };
        let (w, h) = (pixmap.width(), pixmap.height());
        if w == 0 || h == 0 {
          MASK_RENDER_SCRATCH.with(|cell| {
            *cell.borrow_mut() = reusable_mask;
          });
          return Ok(None);
        }
        (pixmap, w, h, Some((image.css_width, image.css_height)))
      }
      BorderImageSourceItem::Generated(bg) => {
        // Generated images have no intrinsic size; render at the mask border's outer rect size
        // (in CSS px) so slice percentages resolve consistently with border-image painting.
        let img_w = rect_css.width().ceil().max(1.0) as u32;
        let img_h = rect_css.height().ceil().max(1.0) as u32;
        let timer = self.diagnostics_enabled.then(Instant::now);
        let Some(pixmap) = render_generated_border_image(
          bg,
          mask_border.current_color,
          mask_border.used_dark_color_scheme,
          mask_border.forced_colors,
          img_w,
          img_h,
          mask_border.font_size,
          mask_border.root_font_size,
          mask_border.viewport,
          &self.gradient_pixmap_cache,
          &self.gradient_cache,
        ) else {
          MASK_RENDER_SCRATCH.with(|cell| {
            *cell.borrow_mut() = reusable_mask;
          });
          return Ok(None);
        };
        if let Some(start) = timer {
          self.record_gradient_usage((img_w * img_h) as u64, start);
        }
        let (w, h) = (pixmap.width(), pixmap.height());
        if w == 0 || h == 0 {
          MASK_RENDER_SCRATCH.with(|cell| {
            *cell.borrow_mut() = reusable_mask;
          });
          return Ok(None);
        }
        (pixmap, w, h, None)
      }
    };

    let slice_top_px = resolve_slice_value(mask_border.slice.top, img_h);
    let slice_right_px = resolve_slice_value(mask_border.slice.right, img_w);
    let slice_bottom_px = resolve_slice_value(mask_border.slice.bottom, img_h);
    let slice_left_px = resolve_slice_value(mask_border.slice.left, img_w);

    let auto_slice_css = intrinsic_css_size.and_then(|(css_w, css_h)| {
      if css_w.is_finite()
        && css_h.is_finite()
        && css_w > 0.0
        && css_h > 0.0
        && img_w > 0
        && img_h > 0
      {
        Some(BorderImageWidths {
          top: slice_top_px * (css_h / img_h as f32),
          right: slice_right_px * (css_w / img_w as f32),
          bottom: slice_bottom_px * (css_h / img_h as f32),
          left: slice_left_px * (css_w / img_w as f32),
        })
      } else {
        None
      }
    });

    let border_widths = BorderImageWidths {
      top: mask_border.border_widths.top,
      right: mask_border.border_widths.right,
      bottom: mask_border.border_widths.bottom,
      left: mask_border.border_widths.left,
    };

    let resolve_width =
      |value: BorderImageWidthValue, border: f32, axis: f32, auto: Option<f32>| -> f32 {
        match value {
          BorderImageWidthValue::Auto => auto.unwrap_or(border).max(0.0),
          BorderImageWidthValue::Number(n) => (n * border).max(0.0),
          BorderImageWidthValue::Length(len) => resolve_length_for_border_image(
            &len,
            axis,
            mask_border.font_size,
            mask_border.root_font_size,
            mask_border.viewport,
          )
          .max(0.0),
          BorderImageWidthValue::Percentage(p) => ((p / 100.0) * axis).max(0.0),
        }
      };

    let target_widths = BorderImageWidths {
      top: resolve_width(
        mask_border.width.top,
        border_widths.top,
        rect_css.height(),
        auto_slice_css.map(|w| w.top),
      ),
      right: resolve_width(
        mask_border.width.right,
        border_widths.right,
        rect_css.width(),
        auto_slice_css.map(|w| w.right),
      ),
      bottom: resolve_width(
        mask_border.width.bottom,
        border_widths.bottom,
        rect_css.height(),
        auto_slice_css.map(|w| w.bottom),
      ),
      left: resolve_width(
        mask_border.width.left,
        border_widths.left,
        rect_css.width(),
        auto_slice_css.map(|w| w.left),
      ),
    };

    let outsets = resolve_border_image_outset(
      &mask_border.outset,
      target_widths,
      mask_border.font_size,
      mask_border.root_font_size,
      mask_border.viewport,
    );

    let outer_rect_css = Rect::from_xywh(
      rect_css.x() - outsets.left,
      rect_css.y() - outsets.top,
      rect_css.width() + outsets.left + outsets.right,
      rect_css.height() + outsets.top + outsets.bottom,
    );
    if outer_rect_css.width() <= 0.0 || outer_rect_css.height() <= 0.0 {
      MASK_RENDER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = reusable_mask;
      });
      return Ok(None);
    }

    let inner_rect_css = Rect::from_xywh(
      outer_rect_css.x() + target_widths.left,
      outer_rect_css.y() + target_widths.top,
      outer_rect_css.width() - target_widths.left - target_widths.right,
      outer_rect_css.height() - target_widths.top - target_widths.bottom,
    );

    let Some(clip_rect_css) = outer_rect_css
      .intersection(canvas_bounds_css)
      .and_then(|r| r.intersection(canvas_clip_bounds_css))
    else {
      MASK_RENDER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = reusable_mask;
      });
      let Some(mut mask) = Mask::new(1, 1) else {
        return Ok(None);
      };
      mask.data_mut()[0] = 0;
      return Ok(Some(OffsetMask {
        mask,
        origin: (0, 0),
      }));
    };
    if clip_rect_css.width() <= 0.0 || clip_rect_css.height() <= 0.0 {
      MASK_RENDER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = reusable_mask;
      });
      let Some(mut mask) = Mask::new(1, 1) else {
        return Ok(None);
      };
      mask.data_mut()[0] = 0;
      return Ok(Some(OffsetMask {
        mask,
        origin: (0, 0),
      }));
    }

    // Convert the clip rect into device space and through the current canvas transform so the
    // resulting mask aligns with the layer pixmap returned by `Canvas::pop_layer_raw`.
    let device_x0 = (clip_rect_css.min_x() * self.scale).floor() as i32;
    let device_y0 = (clip_rect_css.min_y() * self.scale).floor() as i32;
    let device_x1 = (clip_rect_css.max_x() * self.scale).ceil() as i32;
    let device_y1 = (clip_rect_css.max_y() * self.scale).ceil() as i32;
    let device_w = device_x1.saturating_sub(device_x0);
    let device_h = device_y1.saturating_sub(device_y0);

    let device_rect = Rect::from_xywh(
      device_x0 as f32,
      device_y0 as f32,
      device_w as f32,
      device_h as f32,
    );
    let pixmap_rect = if transform == Transform::identity() {
      device_rect
    } else {
      transform_rect(device_rect, &transform)
    };

    let canvas_w = self.canvas.width() as i32;
    let canvas_h = self.canvas.height() as i32;
    let mut pix_x0 = pixmap_rect.min_x().floor() as i32;
    let mut pix_y0 = pixmap_rect.min_y().floor() as i32;
    let mut pix_x1 = pixmap_rect.max_x().ceil() as i32;
    let mut pix_y1 = pixmap_rect.max_y().ceil() as i32;
    pix_x0 = pix_x0.clamp(0, canvas_w);
    pix_y0 = pix_y0.clamp(0, canvas_h);
    pix_x1 = pix_x1.clamp(0, canvas_w);
    pix_y1 = pix_y1.clamp(0, canvas_h);
    let region_w = pix_x1.saturating_sub(pix_x0) as u32;
    let region_h = pix_y1.saturating_sub(pix_y0) as u32;
    if region_w == 0 || region_h == 0 {
      MASK_RENDER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = reusable_mask;
      });
      let Some(mut mask) = Mask::new(1, 1) else {
        return Ok(None);
      };
      mask.data_mut()[0] = 0;
      return Ok(Some(OffsetMask {
        mask,
        origin: (0, 0),
      }));
    }

    // `paint_mask_border_patch` operates in untransformed device coordinates (CSS * scale) and
    // expects the destination origin in that same coordinate space.
    let dest_origin_device = if transform == Transform::identity() {
      (pix_x0, pix_y0)
    } else if let Some(inv) = inv_transform {
      let x = pix_x0 as f32;
      let y = pix_y0 as f32;
      let dx = x * inv.sx + y * inv.kx + inv.tx;
      let dy = x * inv.ky + y * inv.sy + inv.ty;
      (dx.round() as i32, dy.round() as i32)
    } else {
      (device_x0, device_y0)
    };

    let mut layer_mask = match reusable_mask.take() {
      Some(mask) if mask.width() == region_w && mask.height() == region_h => mask,
      Some(_) | None => {
        let Some(mask) = Mask::new(region_w, region_h) else {
          return Ok(None);
        };
        mask
      }
    };

    let mode = match mask_border.mode {
      MaskBorderMode::MatchSource => MaskMode::MatchSource,
      MaskBorderMode::Alpha => MaskMode::Alpha,
      MaskBorderMode::Luminance => MaskMode::Luminance,
    };
    let mut converted_source = None;
    let source_for_paint = match mode {
      MaskMode::Alpha | MaskMode::MatchSource => source_pixmap.as_ref(),
      MaskMode::Luminance => {
        let Some(tile) = mask_tile_from_image(source_pixmap.as_ref(), mode)? else {
          MASK_RENDER_SCRATCH.with(|cell| {
            *cell.borrow_mut() = Some(layer_mask);
          });
          return Ok(None);
        };
        converted_source.insert(tile)
      }
    };

    let sx0 = 0.0;
    let sx1 = slice_left_px.min(img_w as f32);
    let sx2 = (img_w as f32 - slice_right_px).max(sx1);
    let sx3 = img_w as f32;

    let sy0 = 0.0;
    let sy1 = slice_top_px.min(img_h as f32);
    let sy2 = (img_h as f32 - slice_bottom_px).max(sy1);
    let sy3 = img_h as f32;

    let (repeat_x, repeat_y) = mask_border.repeat;

    let render_result = MASK_LAYER_PIXMAP_SCRATCH.with(|cell| -> RenderResult<Option<()>> {
      let mut scratch = cell.borrow_mut();
      let replace = match scratch.pixmap.as_ref() {
        Some(existing) => existing.width() != region_w || existing.height() != region_h,
        None => true,
      };
      if replace {
        scratch.pixmap = new_pixmap(region_w, region_h);
      }
      let Some(mask_pixmap) = scratch.pixmap.as_mut() else {
        return Ok(None);
      };

      // Clear previous pixels.
      let mut clear_deadline_counter = 0usize;
      let clear_chunk_bytes = CLIP_MASK_DEADLINE_STRIDE.saturating_mul(4);
      for chunk in mask_pixmap.data_mut().chunks_mut(clear_chunk_bytes) {
        check_active_periodic(&mut clear_deadline_counter, 1, RenderStage::Paint)?;
        chunk.fill(0);
      }

      // `mask-border-slice` default behavior: when `fill` is not set, the center is treated as
      // fully opaque.
      if !mask_border.slice.fill && inner_rect_css.width() > 0.0 && inner_rect_css.height() > 0.0 {
        if let Some(inner_clip) = inner_rect_css.intersection(clip_rect_css) {
          let device_rect = Rect::from_xywh(
            inner_clip.x() * self.scale - dest_origin_device.0 as f32,
            inner_clip.y() * self.scale - dest_origin_device.1 as f32,
            inner_clip.width() * self.scale,
            inner_clip.height() * self.scale,
          );
          if device_rect.width() > 0.0 && device_rect.height() > 0.0 {
            if let Some(rect) = tiny_skia::Rect::from_xywh(
              device_rect.x(),
              device_rect.y(),
              device_rect.width(),
              device_rect.height(),
            ) {
              let mut paint = tiny_skia::Paint::default();
              paint.set_color_rgba8(255, 255, 255, 255);
              paint.anti_alias = false;
              mask_pixmap.fill_rect(rect, &paint, Transform::identity(), None);
            }
          }
        }
      }

      let clip_rect_device = Rect::from_xywh(
        clip_rect_css.x() * self.scale - dest_origin_device.0 as f32,
        clip_rect_css.y() * self.scale - dest_origin_device.1 as f32,
        clip_rect_css.width() * self.scale,
        clip_rect_css.height() * self.scale,
      );

      let outer_rect_device = Rect::from_xywh(
        outer_rect_css.x() * self.scale - dest_origin_device.0 as f32,
        outer_rect_css.y() * self.scale - dest_origin_device.1 as f32,
        outer_rect_css.width() * self.scale,
        outer_rect_css.height() * self.scale,
      );
      let inner_rect_device = Rect::from_xywh(
        inner_rect_css.x() * self.scale - dest_origin_device.0 as f32,
        inner_rect_css.y() * self.scale - dest_origin_device.1 as f32,
        inner_rect_css.width() * self.scale,
        inner_rect_css.height() * self.scale,
      );
      let target_widths_device = BorderImageWidths {
        top: target_widths.top * self.scale,
        right: target_widths.right * self.scale,
        bottom: target_widths.bottom * self.scale,
        left: target_widths.left * self.scale,
      };

      // Corners
      paint_mask_border_patch(
        mask_pixmap,
        source_for_paint,
        Rect::from_xywh(sx0, sy0, sx1 - sx0, sy1 - sy0),
        Rect::from_xywh(
          outer_rect_device.x(),
          outer_rect_device.y(),
          target_widths_device.left,
          target_widths_device.top,
        ),
        BorderImageRepeat::Stretch,
        BorderImageRepeat::Stretch,
        clip_rect_device,
      );
      paint_mask_border_patch(
        mask_pixmap,
        source_for_paint,
        Rect::from_xywh(sx2, sy0, sx3 - sx2, sy1 - sy0),
        Rect::from_xywh(
          outer_rect_device.x() + outer_rect_device.width() - target_widths_device.right,
          outer_rect_device.y(),
          target_widths_device.right,
          target_widths_device.top,
        ),
        BorderImageRepeat::Stretch,
        BorderImageRepeat::Stretch,
        clip_rect_device,
      );
      paint_mask_border_patch(
        mask_pixmap,
        source_for_paint,
        Rect::from_xywh(sx0, sy2, sx1 - sx0, sy3 - sy2),
        Rect::from_xywh(
          outer_rect_device.x(),
          outer_rect_device.y() + outer_rect_device.height() - target_widths_device.bottom,
          target_widths_device.left,
          target_widths_device.bottom,
        ),
        BorderImageRepeat::Stretch,
        BorderImageRepeat::Stretch,
        clip_rect_device,
      );
      paint_mask_border_patch(
        mask_pixmap,
        source_for_paint,
        Rect::from_xywh(sx2, sy2, sx3 - sx2, sy3 - sy2),
        Rect::from_xywh(
          outer_rect_device.x() + outer_rect_device.width() - target_widths_device.right,
          outer_rect_device.y() + outer_rect_device.height() - target_widths_device.bottom,
          target_widths_device.right,
          target_widths_device.bottom,
        ),
        BorderImageRepeat::Stretch,
        BorderImageRepeat::Stretch,
        clip_rect_device,
      );

      // Edges
      if inner_rect_device.width() > 0.0 && inner_rect_device.height() > 0.0 {
        paint_mask_border_patch(
          mask_pixmap,
          source_for_paint,
          Rect::from_xywh(sx1, sy0, sx2 - sx1, sy1 - sy0),
          Rect::from_xywh(
            inner_rect_device.x(),
            outer_rect_device.y(),
            inner_rect_device.width(),
            target_widths_device.top,
          ),
          repeat_x,
          BorderImageRepeat::Stretch,
          clip_rect_device,
        );
        paint_mask_border_patch(
          mask_pixmap,
          source_for_paint,
          Rect::from_xywh(sx1, sy2, sx2 - sx1, sy3 - sy2),
          Rect::from_xywh(
            inner_rect_device.x(),
            outer_rect_device.y() + outer_rect_device.height() - target_widths_device.bottom,
            inner_rect_device.width(),
            target_widths_device.bottom,
          ),
          repeat_x,
          BorderImageRepeat::Stretch,
          clip_rect_device,
        );
        paint_mask_border_patch(
          mask_pixmap,
          source_for_paint,
          Rect::from_xywh(sx0, sy1, sx1 - sx0, sy2 - sy1),
          Rect::from_xywh(
            outer_rect_device.x(),
            inner_rect_device.y(),
            target_widths_device.left,
            inner_rect_device.height(),
          ),
          BorderImageRepeat::Stretch,
          repeat_y,
          clip_rect_device,
        );
        paint_mask_border_patch(
          mask_pixmap,
          source_for_paint,
          Rect::from_xywh(sx2, sy1, sx3 - sx2, sy2 - sy1),
          Rect::from_xywh(
            outer_rect_device.x() + outer_rect_device.width() - target_widths_device.right,
            inner_rect_device.y(),
            target_widths_device.right,
            inner_rect_device.height(),
          ),
          BorderImageRepeat::Stretch,
          repeat_y,
          clip_rect_device,
        );

        if mask_border.slice.fill {
          paint_mask_border_patch(
            mask_pixmap,
            source_for_paint,
            Rect::from_xywh(sx1, sy1, sx2 - sx1, sy2 - sy1),
            inner_rect_device,
            repeat_x,
            repeat_y,
            clip_rect_device,
          );
        }
      }

      // Copy alpha into the output mask.
      let mut alpha_deadline_counter = 0usize;
      let expected_len = (region_w as usize).saturating_mul(region_h as usize);
      let mut src_idx = 3usize;
      let src = mask_pixmap.data();
      debug_assert_eq!(
        layer_mask.data().len(),
        expected_len,
        "expected mask byte length to match region dimensions"
      );
      debug_assert_eq!(
        src.len(),
        expected_len.saturating_mul(4),
        "expected scratch mask pixmap to be tightly packed RGBA"
      );
      for dst_chunk in layer_mask.data_mut().chunks_mut(CLIP_MASK_DEADLINE_STRIDE) {
        check_active_periodic(&mut alpha_deadline_counter, 1, RenderStage::Paint)?;
        for dst in dst_chunk.iter_mut() {
          *dst = src[src_idx];
          src_idx += 4;
        }
      }
      Ok(Some(()))
    });

    if render_result?.is_none() {
      MASK_RENDER_SCRATCH.with(|cell| {
        *cell.borrow_mut() = Some(layer_mask);
      });
      return Ok(None);
    }

    Ok(Some(OffsetMask {
      mask: layer_mask,
      origin: (pix_x0, pix_y0),
    }))
  }

  fn convert_stops_rgba(
    &self,
    stops: &[crate::paint::display_list::GradientStop],
  ) -> Option<Vec<(f32, Rgba)>> {
    if stops.is_empty() {
      return None;
    }
    let opacity = self.canvas.opacity().clamp(0.0, 1.0);
    Some(
      stops
        .iter()
        .map(|s| {
          let mut color = s.color;
          color.a *= opacity;
          let pos = if s.position.is_finite() {
            s.position
          } else {
            0.0
          };
          (pos, color)
        })
        .collect(),
    )
  }

  fn convert_stops(
    &self,
    stops: &[crate::paint::display_list::GradientStop],
  ) -> Option<Vec<tiny_skia::GradientStop>> {
    if stops.is_empty() {
      return None;
    }
    let opacity = self.canvas.opacity().clamp(0.0, 1.0);
    Some(
      stops
        .iter()
        .map(|s| {
          let pos = if s.position.is_finite() {
            s.position
          } else {
            0.0
          };
          let alpha = (s.color.a * opacity * 255.0).round().clamp(0.0, 255.0) as u8;
          SkiaGradientStop::new(
            pos,
            tiny_skia::Color::from_rgba8(s.color.r, s.color.g, s.color.b, alpha),
          )
        })
        .collect(),
    )
  }

  fn render_box_shadow(&mut self, item: &BoxShadowItem) -> Result<()> {
    let mut shadow = BoxShadow {
      offset_x: self.ds_len(item.offset.x),
      offset_y: self.ds_len(item.offset.y),
      // `rasterize::BoxShadow.blur_radius` stores the CSS blur radius in *device* px; the rasterizer
      // converts to gaussian sigma internally (matching Skia/Blink).
      blur_radius: self.ds_len(item.blur_radius),
      spread_radius: self.ds_len(item.spread_radius),
      color: item.color,
      inset: item.inset,
    };

    let rect = self.ds_rect(item.rect);
    let radii = self.ds_radii(item.radii);

    // Apply current opacity to the shadow when compositing.
    let opacity = self.canvas.opacity().clamp(0.0, 1.0);
    shadow.color.a *= opacity;
    if shadow.color.a <= f32::EPSILON {
      return Ok(());
    }

    // Compute a tight device-space bounding box for the shadow and render it into a small
    // offscreen pixmap. This avoids allocating a full-canvas temporary surface per shadow.
    //
    // Note: The bounds must be computed in the same untransformed device coordinate space that
    // `render_box_shadow` expects. The current canvas transform is applied only when compositing
    // the offscreen pixmap back onto the destination.
    let (shadow_bounds, blur_pad) = if shadow.inset {
      // Match the internal `rasterize::render_box_shadow` math (spread + 3σ blur padding).
      let sigma = box_shadow_blur_radius_to_sigma(shadow.blur_radius);
      let blur_pad = (sigma * 3.0).ceil();
      let spread = shadow.spread_radius;
      let pad_x = (blur_pad + shadow.offset_x.abs() + spread.abs()).ceil();
      let pad_y = (blur_pad + shadow.offset_y.abs() + spread.abs()).ceil();

      let min_x = (rect.x() - pad_x).floor();
      let min_y = (rect.y() - pad_y).floor();
      let max_x = (rect.x() + rect.width() + pad_x).ceil();
      let max_y = (rect.y() + rect.height() + pad_y).ceil();
      (
        Rect::from_xywh(min_x, min_y, max_x - min_x, max_y - min_y),
        blur_pad,
      )
    } else {
      // Match the internal `rasterize::render_box_shadow` math (spread + 3σ blur padding).
      let sigma = box_shadow_blur_radius_to_sigma(shadow.blur_radius);
      let spread = shadow.spread_radius;
      let shadow_rect = Rect::from_xywh(
        rect.x() + shadow.offset_x - spread,
        rect.y() + shadow.offset_y - spread,
        rect.width() + spread * 2.0,
        rect.height() + spread * 2.0,
      );
      let blur_pad = (sigma * 3.0).ceil();
      let min_x = (shadow_rect.x() - blur_pad).floor();
      let min_y = (shadow_rect.y() - blur_pad).floor();
      let max_x = (shadow_rect.x() + shadow_rect.width() + blur_pad).ceil();
      let max_y = (shadow_rect.y() + shadow_rect.height() + blur_pad).ceil();
      (
        Rect::from_xywh(min_x, min_y, max_x - min_x, max_y - min_y),
        blur_pad,
      )
    };

    if shadow_bounds.width() <= 0.0
      || shadow_bounds.height() <= 0.0
      || !shadow_bounds.x().is_finite()
      || !shadow_bounds.y().is_finite()
      || !shadow_bounds.width().is_finite()
      || !shadow_bounds.height().is_finite()
    {
      return Ok(());
    }

    let clipped_bounds = {
      let mut visible_device = self.canvas.bounds();
      if let Some(clip) = self.canvas.clip_bounds() {
        let Some(intersection) = visible_device.intersection(clip) else {
          return Ok(());
        };
        visible_device = intersection;
      }
      if visible_device.width() <= 0.0 || visible_device.height() <= 0.0 {
        return Ok(());
      }

      // Avoid overly conservative allocations for huge shadows: only the portion of the shadow
      // that maps to the visible device region (respecting the current transform) can contribute
      // to the final output.
      let transform = self.canvas.transform();
      let visible_local = if transform == Transform::identity() {
        Some(visible_device)
      } else {
        invert_transform(transform).map(|inv| transform_rect(visible_device, &inv))
      };

      if let Some(visible_local) = visible_local {
        // The final output is clipped to the visible device region, but we still need a guard band
        // around it so the gaussian blur kernel can sample pixels just outside the clip.
        let guard = blur_pad.max(0.0) + 1.0;
        let visible_local = visible_local.inflate(guard);
        match shadow_bounds.intersection(visible_local) {
          Some(bounds) => bounds,
          None => return Ok(()),
        }
      } else {
        // If the transform is non-invertible, fall back to the un-clipped bounds.
        shadow_bounds
      }
    };

    let region_w = clipped_bounds.width().ceil().max(1.0) as u32;
    let region_h = clipped_bounds.height().ceil().max(1.0) as u32;

    let blend_mode = self.canvas.blend_mode();
    let paint = tiny_skia::PixmapPaint {
      opacity: 1.0,
      blend_mode,
      ..Default::default()
    };
    let clip = self.canvas.clip_mask_rc();

    // Box shadows can still have moderately large bounds even after clipping to the visible region.
    // To avoid allocating one large intermediate pixmap per shadow, rasterize into a fixed-size
    // tile surface and blit the tiles back onto the canvas.
    const BOX_SHADOW_TILE_SIZE: u32 = 32;
    let canvas_transform = self.canvas.transform();
    let can_tile = (region_w > BOX_SHADOW_TILE_SIZE || region_h > BOX_SHADOW_TILE_SIZE)
      && Self::is_translation_only_transform(canvas_transform)
      && Self::is_near_integer(canvas_transform.tx)
      && Self::is_near_integer(canvas_transform.ty)
      && Self::is_near_integer(clipped_bounds.x())
      && Self::is_near_integer(clipped_bounds.y());

    if can_tile {
      let tile_w = BOX_SHADOW_TILE_SIZE.min(region_w).max(1);
      let tile_h = BOX_SHADOW_TILE_SIZE.min(region_h).max(1);
      let mut tile = match new_pixmap(tile_w, tile_h) {
        Some(p) => p,
        None => return Ok(()),
      };

      let tiles_x = (region_w + tile_w - 1) / tile_w;
      let tiles_y = (region_h + tile_h - 1) / tile_h;
      let base_x = clipped_bounds.x();
      let base_y = clipped_bounds.y();
      let tx = canvas_transform.tx.round() as i32;
      let ty = canvas_transform.ty.round() as i32;

      for tile_y in 0..tiles_y {
        for tile_x in 0..tiles_x {
          tile.data_mut().fill(0);

          let offset_x = tile_x * tile_w;
          let offset_y = tile_y * tile_h;
          let origin_x = base_x + offset_x as f32;
          let origin_y = base_y + offset_y as f32;

          let _ = render_box_shadow_cached_with_clamp(
            &mut tile,
            rect.x() - origin_x,
            rect.y() - origin_y,
            rect.width(),
            rect.height(),
            &radii,
            &shadow,
            Some(self.blur_cache_mut()),
            // Expand so each tile's pixels are computed with the full blur kernel, avoiding seams
            // at tile boundaries.
            BoxShadowSurfaceClamp::ExpandByBlurRadius,
          )?;

          // For edge tiles, clear the portion that lies outside the clipped region so we don't
          // paint stray pixels when compositing the full tile surface back.
          let active_w = region_w.saturating_sub(offset_x).min(tile_w);
          let active_h = region_h.saturating_sub(offset_y).min(tile_h);
          if active_w != tile_w || active_h != tile_h {
            let stride = tile.width() as usize * 4;
            let active_row_bytes = active_w as usize * 4;
            let data = tile.data_mut();
            if active_h < tile_h {
              let start = active_h as usize * stride;
              data[start..].fill(0);
            }
            if active_w < tile_w {
              for row in 0..active_h as usize {
                let start = row * stride + active_row_bytes;
                let end = (row + 1) * stride;
                data[start..end].fill(0);
              }
            }
          }

          let dest_x = origin_x.round() as i32 + tx;
          let dest_y = origin_y.round() as i32 + ty;
          let clip_ref = clip.as_deref();
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            composite_layer_into_pixmap_mut(pixmap, &tile, 1.0, blend_mode, (dest_x, dest_y), clip_ref);
          });
        }
      }

      return Ok(());
    }

    let mut temp = match new_pixmap(region_w, region_h) {
      Some(p) => p,
      None => return Ok(()),
    };

    let _ = render_box_shadow_cached_with_clamp(
      &mut temp,
      rect.x() - clipped_bounds.x(),
      rect.y() - clipped_bounds.y(),
      rect.width(),
      rect.height(),
      &radii,
      &shadow,
      Some(self.blur_cache_mut()),
      BoxShadowSurfaceClamp::ClampToDestination,
    )?;

    let dest_x = clipped_bounds.x().floor() as i32;
    let dest_y = clipped_bounds.y().floor() as i32;
    let frac_x = clipped_bounds.x() - dest_x as f32;
    let frac_y = clipped_bounds.y() - dest_y as f32;
    let transform = Transform::from_translate(frac_x, frac_y).post_concat(canvas_transform);
    self.canvas.with_mirrored_pixmap_mut(|pixmap| {
      // Prefer manual compositing for translation-only draws: this matches Chrome/Skia's integer
      // `mul/255` math for `source-over` and avoids tiny-skia's ordered dithering patterns.
      //
      // For non-translation transforms (rotation/scale/projective), fall back to tiny-skia so the
      // shadow pixmap is sampled correctly.
      if Self::is_translation_only_transform(transform)
        && Self::is_near_integer(transform.tx)
        && Self::is_near_integer(transform.ty)
      {
        composite_layer_into_pixmap_mut(
          pixmap,
          &temp,
          1.0,
          blend_mode,
          (
            dest_x + transform.tx.round() as i32,
            dest_y + transform.ty.round() as i32,
          ),
          clip.as_deref(),
        );
        return;
      }

      pixmap.draw_pixmap(
        dest_x,
        dest_y,
        temp.as_ref(),
        &paint,
        transform,
        clip.as_deref(),
      );
    });
    Ok(())
  }

  fn composite_manual_layer(
    &mut self,
    layer: &Pixmap,
    opacity: f32,
    mode: BlendMode,
    origin: (i32, i32),
    region: Option<&Rect>,
  ) -> Result<()> {
    let result = self.canvas.with_mirrored_pixmap_mut_result(|dest| {
      composite_manual_layer_pixmap_mut(dest, layer, opacity, mode, origin, region)
    });
    if result.is_ok() {
      self.mark_current_pixmap_mutated();
    }
    result
  }

  /// Consumes the renderer and returns the painted pixmap.
  pub fn render(mut self, list: &DisplayList) -> Result<Pixmap> {
    Ok(self.render_with_report(list)?.pixmap)
  }

  /// Renders the display list into the renderer's existing canvas.
  ///
  /// Unlike [`Self::render_with_report`], this does not attempt to extract an owned [`Pixmap`] from
  /// the renderer. This makes it usable with canvases backed by an externally-owned RGBA buffer.
  pub(crate) fn render_into(&mut self, list: &DisplayList) -> Result<()> {
    let composed = self
      .preserve_3d_disabled
      .then(|| crate::paint::preserve_3d::composite_preserve_3d(list));
    let list = composed.as_ref().unwrap_or(list);
    check_active(RenderStage::Paint).map_err(Error::Render)?;
    self.render_slice(list.items())?;
    // Like the legacy painter, `render_slice` checks periodically before each display item. Run a
    // final check so we don't miss deadlines expiring during the last item.
    check_active(RenderStage::Paint).map_err(Error::Render)?;
    Ok(())
  }

  /// Renders the display list and returns timing/parallelism metadata.
  pub fn render_with_report(mut self, list: &DisplayList) -> Result<RenderReport> {
    let composed = self
      .preserve_3d_disabled
      .then(|| crate::paint::preserve_3d::composite_preserve_3d(list));
    let list = composed.as_ref().unwrap_or(list);
    check_active(RenderStage::Paint).map_err(Error::Render)?;
    let start = Instant::now();
    let mut fallback_reason = None;

    let tile_estimate = self.estimated_tile_count();
    let parallel_supported =
      self.should_render_parallel(list, tile_estimate, &mut fallback_reason)?;

    if parallel_supported {
      let halo_px = self.tile_halo_px(list)?;
      if let Some(reason) = self.halo_amplification_fallback_reason(halo_px) {
        fallback_reason = Some(reason);
      } else {
        let (pixmap, tiles, tasks, threads_used, parallel_duration) =
          self.render_parallel(list, halo_px)?;
        // Ensure we catch deadlines that expire during the final tile render/blit.
        check_active(RenderStage::Paint).map_err(Error::Render)?;
        let duration = start.elapsed();
        let serial_duration = duration.saturating_sub(parallel_duration);
        if self.paint_parallelism.log_timing {
          eprintln!(
            "paint_parallel tiles={} threads={} tile_size={} duration_ms={:.2}",
            tiles,
            threads_used,
            self.paint_parallelism.tile_size,
            duration.as_secs_f64() * 1000.0
          );
        }
        let image_stats = self
          .image_pixmap_diagnostics
          .as_ref()
          .map(|d| d.snapshot())
          .unwrap_or_default();
        let background_stats = self
          .background_paint_diagnostics
          .as_ref()
          .map(|d| d.snapshot())
          .unwrap_or_default();
        let clip_stats = self
          .clip_mask_diagnostics
          .as_ref()
          .map(|d| d.snapshot())
          .unwrap_or_default();
        let layer_stats = self
          .layer_alloc_diagnostics
          .as_ref()
          .map(|d| d.snapshot())
          .unwrap_or_default();
        let backdrop_stats = self
          .backdrop_composite_diagnostics
          .as_ref()
          .map(|d| d.snapshot())
          .unwrap_or_default();
        let gradient_pixmap_stats = self.gradient_pixmap_cache.snapshot();
        return Ok(RenderReport {
          pixmap,
          parallel_used: true,
          tiles,
          duration,
          fallback_reason,
          gradient_stats: self.gradient_stats,
          gradient_pixmap_cache_hits: gradient_pixmap_stats.hits,
          gradient_pixmap_cache_misses: gradient_pixmap_stats.misses,
          gradient_pixmap_cache_bytes: gradient_pixmap_stats.bytes,
          image_pixmap_cache_hits: image_stats.hits,
          image_pixmap_cache_misses: image_stats.misses,
          image_pixmap_ms: image_stats.millis(),
          background_ms: background_stats.millis(),
          clip_mask_calls: clip_stats.calls,
          clip_mask_ms: clip_stats.millis(),
          clip_mask_pixels: clip_stats.pixels,
          layer_allocations: layer_stats.allocations,
          layer_alloc_bytes: layer_stats.bytes,
          backdrop_composite_allocations: backdrop_stats.allocations,
          backdrop_composite_bytes: backdrop_stats.bytes,
          backdrop_composite_cache_hits: backdrop_stats.cache_hits,
          backdrop_composite_cache_misses: backdrop_stats.cache_misses,
          parallel_tasks: tasks,
          parallel_threads: threads_used,
          parallel_duration,
          serial_duration,
        });
      }
    }

    self.render_slice(list.items())?;
    // Like the legacy painter, `render_slice` checks periodically before each display item. Run a
    // final check so we don't miss deadlines expiring during the last item.
    check_active(RenderStage::Paint).map_err(Error::Render)?;
    let serial_duration = start.elapsed();
    let image_stats = self
      .image_pixmap_diagnostics
      .as_ref()
      .map(|d| d.snapshot())
      .unwrap_or_default();
    let background_stats = self
      .background_paint_diagnostics
      .as_ref()
      .map(|d| d.snapshot())
      .unwrap_or_default();
    let clip_stats = self
      .clip_mask_diagnostics
      .as_ref()
      .map(|d| d.snapshot())
      .unwrap_or_default();
    let layer_stats = self
      .layer_alloc_diagnostics
      .as_ref()
      .map(|d| d.snapshot())
      .unwrap_or_default();
    let backdrop_stats = self
      .backdrop_composite_diagnostics
      .as_ref()
      .map(|d| d.snapshot())
      .unwrap_or_default();
    let gradient_pixmap_stats = self.gradient_pixmap_cache.snapshot();
    Ok(RenderReport {
      pixmap: self.canvas.into_pixmap(),
      parallel_used: false,
      tiles: 1,
      duration: serial_duration,
      fallback_reason,
      gradient_stats: self.gradient_stats,
      gradient_pixmap_cache_hits: gradient_pixmap_stats.hits,
      gradient_pixmap_cache_misses: gradient_pixmap_stats.misses,
      gradient_pixmap_cache_bytes: gradient_pixmap_stats.bytes,
      image_pixmap_cache_hits: image_stats.hits,
      image_pixmap_cache_misses: image_stats.misses,
      image_pixmap_ms: image_stats.millis(),
      background_ms: background_stats.millis(),
      clip_mask_calls: clip_stats.calls,
      clip_mask_ms: clip_stats.millis(),
      clip_mask_pixels: clip_stats.pixels,
      layer_allocations: layer_stats.allocations,
      layer_alloc_bytes: layer_stats.bytes,
      backdrop_composite_allocations: backdrop_stats.allocations,
      backdrop_composite_bytes: backdrop_stats.bytes,
      backdrop_composite_cache_hits: backdrop_stats.cache_hits,
      backdrop_composite_cache_misses: backdrop_stats.cache_misses,
      parallel_tasks: 0,
      parallel_threads: 1,
      parallel_duration: Duration::ZERO,
      serial_duration,
    })
  }

  /// Repaints only the region covered by `damage_rect` by rendering the display list in
  /// halo-expanded tiles and blitting the updated tiles into the existing pixmap.
  ///
  /// The renderer must have been constructed via [`Self::new_from_existing_pixmap`] /
  /// [`Self::new_scaled_from_existing_pixmap`] so the canvas contains the previously rendered
  /// pixels. When tile isolation is not supported for the display list, this falls back to a full
  /// repaint and reports the reason.
  pub fn render_damage_with_report(
    mut self,
    list: &DisplayList,
    damage_rect: Rect,
  ) -> Result<PartialRepaintReport> {
    let original_list = list;
    let composed = self
      .preserve_3d_disabled
      .then(|| crate::paint::preserve_3d::composite_preserve_3d(list));
    let list = composed.as_ref().unwrap_or(list);

    let (tile_ok, reason) = self.tile_isolation_supported(list)?;
    if !tile_ok {
      // Full repaint fallback: render into a fresh surface so we do not depend on the existing
      // pixmap contents.
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(PartialRepaintReport {
        pixmap,
        used_partial: false,
        repainted_tiles: 0,
        fallback_reason: reason,
      });
    }

    // Treat non-finite damage rectangles as a request for a full repaint to avoid leaving stale
    // pixels in place.
    if !damage_rect.x().is_finite()
      || !damage_rect.y().is_finite()
      || !damage_rect.width().is_finite()
      || !damage_rect.height().is_finite()
    {
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(PartialRepaintReport {
        pixmap,
        used_partial: false,
        repainted_tiles: 0,
        fallback_reason: Some("damage rect is non-finite; full repaint".to_string()),
      });
    }

    let halo_px = self.tile_halo_px(list)?;
    let repainted_tiles = self
      .repaint_tiles_for_damage(list, halo_px, damage_rect)?
      .tiles;
    Ok(PartialRepaintReport {
      pixmap: self.canvas.into_pixmap(),
      used_partial: true,
      repainted_tiles,
      fallback_reason: None,
    })
  }

  /// Applies a scroll-blit optimization (copying pixels from the previous frame) and repaints the
  /// newly exposed region.
  ///
  /// This is intended for scroll-driven repaints where the scroll delta is a translation in
  /// device pixels. When the delta is unsupported (non-integer after scaling, too large, or
  /// zero), or when the display list is not safe to evaluate in isolation, the method falls back
  /// to a full repaint.
  pub fn render_scroll_blit_with_report(
    mut self,
    list: &DisplayList,
    scroll_delta_css: Point,
  ) -> Result<ScrollBlitReport> {
    let original_list = list;
    if list.has_scroll_linked_animations() {
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(ScrollBlitReport {
        pixmap,
        scroll_blit_used: false,
        partial_repaint_used: false,
        repainted_device_rects: Vec::new(),
        fallback_reason: Some(
          "scroll-linked animation timeline present; full repaint".to_string(),
        ),
      });
    }

    // When time-based animation sampling is enabled, animated GIF frame selection can change
    // between paints even if the only visible change is scrolling. Scroll-blitting (copying pixels
    // from the previous frame and repainting only the exposed strip) would leave stale GIF frames
    // in regions that are not repainted.
    //
    // Conservatively fall back to a full repaint whenever the current display list contains any
    // images whose pixels can depend on `animation_time`.
    if original_list.has_animation_time_dependent_images() {
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(ScrollBlitReport {
        pixmap,
        scroll_blit_used: false,
        partial_repaint_used: false,
        repainted_device_rects: Vec::new(),
        fallback_reason: Some(
          "animated GIFs / animation_time affects images; full repaint".to_string(),
        ),
      });
    }
    let composed = self
      .preserve_3d_disabled
      .then(|| crate::paint::preserve_3d::composite_preserve_3d(list));
    let list = composed.as_ref().unwrap_or(list);

    let (tile_ok, reason) = self.tile_isolation_supported(list)?;
    if !tile_ok {
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(ScrollBlitReport {
        pixmap,
        scroll_blit_used: false,
        partial_repaint_used: false,
        repainted_device_rects: Vec::new(),
        fallback_reason: reason,
      });
    }

    if !(scroll_delta_css.x.is_finite() && scroll_delta_css.y.is_finite()) {
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(ScrollBlitReport {
        pixmap,
        scroll_blit_used: false,
        partial_repaint_used: false,
        repainted_device_rects: Vec::new(),
        fallback_reason: Some("scroll delta is non-finite; full repaint".to_string()),
      });
    }

    let dx_f = scroll_delta_css.x * self.scale;
    let dy_f = scroll_delta_css.y * self.scale;
    let to_i32 = |v: f32| -> Option<i32> {
      if !v.is_finite() {
        return None;
      }
      if v < i32::MIN as f32 || v > i32::MAX as f32 {
        return None;
      }
      Some(v as i32)
    };
    let dx = Self::snap_near_integer(dx_f, 1e-3).and_then(to_i32);
    let dy = Self::snap_near_integer(dy_f, 1e-3).and_then(to_i32);

    // Require integer scroll delta in device pixels so the blit is an exact pixel translation.
    let Some(dx) = dx else {
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(ScrollBlitReport {
        pixmap,
        scroll_blit_used: false,
        partial_repaint_used: false,
        repainted_device_rects: Vec::new(),
        fallback_reason: Some(
          "scroll delta X is not an integer in device pixels; full repaint".to_string(),
        ),
      });
    };
    let Some(dy) = dy else {
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(ScrollBlitReport {
        pixmap,
        scroll_blit_used: false,
        partial_repaint_used: false,
        repainted_device_rects: Vec::new(),
        fallback_reason: Some(
          "scroll delta Y is not an integer in device pixels; full repaint".to_string(),
        ),
      });
    };

    if dx == 0 && dy == 0 {
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(ScrollBlitReport {
        pixmap,
        scroll_blit_used: false,
        partial_repaint_used: false,
        repainted_device_rects: Vec::new(),
        fallback_reason: Some("scroll delta unsupported; full repaint".to_string()),
      });
    }

    // When the viewport reserves classic scrollbar gutters (`scrollbar-gutter: stable[/both-edges]`)
    // the scrollport is smaller than the painted surface. This means the newly exposed strip is
    // at the scrollport edge (not the outer paint edge), so a full-surface scroll blit would copy
    // gutter pixels into the scrollport boundary and leave seams. Disable the optimization until a
    // scrollport-only blit path exists.
    if (dy != 0 && self.viewport_scrollbar_gutter_reserved_y)
      || (dx != 0 && self.viewport_scrollbar_gutter_reserved_x)
    {
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(ScrollBlitReport {
        pixmap,
        scroll_blit_used: false,
        partial_repaint_used: false,
        repainted_device_rects: Vec::new(),
        fallback_reason: Some("viewport scrollbar-gutter reserved space".to_string()),
      });
    }

    let width = self.canvas.width() as i32;
    let height = self.canvas.height() as i32;
    if width <= 0 || height <= 0 {
      return Ok(ScrollBlitReport {
        pixmap: self.canvas.into_pixmap(),
        scroll_blit_used: false,
        partial_repaint_used: false,
        repainted_device_rects: Vec::new(),
        fallback_reason: Some("empty surface".to_string()),
      });
    }
    if dx.saturating_abs() >= width || dy.saturating_abs() >= height {
      let mut full_renderer = DisplayListRenderer::new_with_text_state(
        self.canvas.width(),
        self.canvas.height(),
        self.background,
        self.font_ctx.clone(),
        self.scale,
        self.color_renderer.clone(),
        self.color_cache.clone(),
        self.glyph_cache.clone(),
      )?;
      full_renderer.paint_parallelism = self.paint_parallelism;
      let pixmap = full_renderer.render_with_report(original_list)?.pixmap;
      return Ok(ScrollBlitReport {
        pixmap,
        scroll_blit_used: false,
        partial_repaint_used: false,
        repainted_device_rects: Vec::new(),
        fallback_reason: Some("scroll delta exceeds viewport; full repaint".to_string()),
      });
    }

    // Apply the blit: new(x,y) = old(x+dx, y+dy) (dx/dy in device pixels).
    let bg = tiny_skia::Color::from_rgba8(
      self.background.r,
      self.background.g,
      self.background.b,
      self.background.alpha_u8(),
    );
    self.canvas.with_mirrored_pixmap_mut_result(|dest| {
      let mut scratch = new_pixmap_with_context(dest.width(), dest.height(), "scroll_blit")?;
      scratch.fill(bg);

      let dst_w = dest.width() as i32;
      let dst_h = dest.height() as i32;
      let dest_width = dest.width() as usize;
      let dest_height = dest.height() as usize;
      if dst_w <= 0 || dst_h <= 0 {
        dest.data_mut().copy_from_slice(scratch.data());
        return Ok(());
      }

      let src_w = dest_width as i32;
      let src_h = dest_height as i32;
      let x0 = dx.max(0);
      let y0 = dy.max(0);
      let x1 = (dx + dst_w).min(src_w);
      let y1 = (dy + dst_h).min(src_h);
      let src_stride = dest_width * 4;
      if x0 < x1 && y0 < y1 {
        let dst_off_x = (x0 - dx) as usize;
        let dst_off_y = (y0 - dy) as usize;
        let copy_w = (x1 - x0) as usize;
        let copy_h = (y1 - y0) as usize;
        let dst_stride = scratch.width() as usize * 4;
        let row_bytes = copy_w * 4;
        {
          // `tiny-skia::PixmapMut` no longer exposes an immutable `data()` accessor; read from the
          // backing buffer via `data_mut()` and narrow it to `&[u8]`. Keep the borrow scoped so we
          // can later overwrite `dest` with the completed scratch buffer.
          let src_data: &[u8] = &*dest.data_mut();
          let dst_data = scratch.data_mut();
          for row in 0..copy_h {
            let src_idx = (y0 as usize + row) * src_stride + x0 as usize * 4;
            let dst_idx = (dst_off_y + row) * dst_stride + dst_off_x * 4;
            dst_data[dst_idx..dst_idx + row_bytes]
              .copy_from_slice(&src_data[src_idx..src_idx + row_bytes]);
          }
        }
      }

      dest.data_mut().copy_from_slice(scratch.data());
      Ok(())
    })?;
    self.mark_current_pixmap_mutated();

    let halo_px = self.tile_halo_px(list)?;
    let mut repainted_tiles = 0usize;
    let mut repainted_device_rects: Vec<Rect> = Vec::new();
    // Avoid capturing `&self` in this closure; we need to mutably borrow `self` below for partial
    // repaint and Rust considers the closure's borrow live across the whole call.
    let scale = self.scale;
    let to_css = move |device: Rect| {
      Rect::from_xywh(
        device.x() / scale,
        device.y() / scale,
        device.width() / scale,
        device.height() / scale,
      )
    };

    if dy != 0 {
      let exposed_device = if dy > 0 {
        Rect::from_xywh(0.0, (height - dy) as f32, width as f32, dy as f32)
      } else {
        Rect::from_xywh(0.0, 0.0, width as f32, (-dy) as f32)
      };
      let repainted = self.repaint_tiles_for_damage(list, halo_px, to_css(exposed_device))?;
      repainted_tiles = repainted_tiles.saturating_add(repainted.tiles);
      repainted_device_rects.extend(repainted.device_rects);
    }

    if dx != 0 {
      let exposed_device = if dx > 0 {
        Rect::from_xywh((width - dx) as f32, 0.0, dx as f32, height as f32)
      } else {
        Rect::from_xywh(0.0, 0.0, (-dx) as f32, height as f32)
      };
      let repainted = self.repaint_tiles_for_damage(list, halo_px, to_css(exposed_device))?;
      repainted_tiles = repainted_tiles.saturating_add(repainted.tiles);
      repainted_device_rects.extend(repainted.device_rects);
    }

    // Avoid reporting duplicate tiles for diagonal scroll deltas. Callers may apply post-processing
    // overlays (e.g. find-in-page highlights) by iterating the reported rects; duplicates would
    // double-apply alpha.
    if repainted_device_rects.len() > 1 {
      repainted_device_rects.sort_by_key(|r| {
        (
          r.x().round() as i32,
          r.y().round() as i32,
          r.width().round() as i32,
          r.height().round() as i32,
        )
      });
      repainted_device_rects.dedup();
    }

    Ok(ScrollBlitReport {
      pixmap: self.canvas.into_pixmap(),
      scroll_blit_used: true,
      partial_repaint_used: repainted_tiles > 0,
      repainted_device_rects,
      fallback_reason: None,
    })
  }

  fn backdrop_composite_cache_key(
    layer_stack: &[LayerRecord],
    root_depth: usize,
    parent_depth: usize,
  ) -> Option<BackdropCompositeCacheKey> {
    if root_depth >= parent_depth {
      return None;
    }
    let parent = layer_stack.get(parent_depth).map(|record| &record.pixmap)?;
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    for idx in root_depth..parent_depth {
      let record = layer_stack.get(idx)?;
      record.origin.hash(&mut hasher);
      record.effective_opacity().to_bits().hash(&mut hasher);
      std::mem::discriminant(&record.effective_blend_mode()).hash(&mut hasher);
    }
    Some(BackdropCompositeCacheKey {
      root_depth,
      parent_depth,
      width: parent.width(),
      height: parent.height(),
      origins_hash: hasher.finish(),
    })
  }

  fn backdrop_composite_mutation_fingerprint(&self, root_depth: usize, parent_depth: usize) -> u64 {
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    let upper = parent_depth.min(self.canvas_mutations.len().saturating_sub(1));
    for counter in self.canvas_mutations[root_depth.min(upper)..=upper].iter() {
      counter.hash(&mut hasher);
    }
    hasher.finish()
  }

  fn ensure_backdrop_composite_cached(
    &mut self,
    root_depth: usize,
    parent_depth: usize,
  ) -> RenderResult<Option<BackdropCompositeCacheKey>> {
    if !self.backdrop_composite_cache_enabled || root_depth >= parent_depth {
      return Ok(None);
    }
    let layer_stack = self.canvas.layer_stack();
    let Some(target_key) =
      Self::backdrop_composite_cache_key(layer_stack, root_depth, parent_depth)
    else {
      return Ok(None);
    };
    let target_fingerprint = self.backdrop_composite_mutation_fingerprint(root_depth, parent_depth);

    if self
      .backdrop_composite_cache
      .peek(&target_key)
      .is_some_and(|entry| entry.mutation_fingerprint == target_fingerprint)
    {
      self.record_backdrop_composite_cache_hit();
      return Ok(Some(target_key));
    }
    self.record_backdrop_composite_cache_miss();

    // Find the deepest valid cached intermediate composite we can start from.
    let mut start_depth = root_depth;
    let mut start_key: Option<BackdropCompositeCacheKey> = None;
    for depth in (root_depth..parent_depth).rev() {
      let Some(key) = Self::backdrop_composite_cache_key(layer_stack, root_depth, depth) else {
        continue;
      };
      let fingerprint = self.backdrop_composite_mutation_fingerprint(root_depth, depth);
      if self
        .backdrop_composite_cache
        .peek(&key)
        .is_some_and(|entry| entry.mutation_fingerprint == fingerprint)
      {
        start_depth = depth;
        start_key = Some(key);
        break;
      }
    }

    let mut staged: Vec<(BackdropCompositeCacheKey, BackdropCompositeCacheEntry)> = Vec::new();

    // Build missing composites. To avoid borrowing the cache mutably while we hold references to
    // its pixmaps, we stage insertions and commit them after the compositing loop completes.
    let build_result: RenderResult<bool> = (|| {
      // `Canvas::fill_backdrop_root_region` strips the initialization backdrop when the nearest
      // Backdrop Root layer surface was initialized from the already-painted backdrop (e.g. for a
      // non-isolated mix-blend-mode group). Mirror that behavior here so cached composites don't
      // accidentally include pixels from above the Backdrop Root boundary.
      let root_initialized_from_backdrop =
        root_depth > 0 && layer_stack[root_depth - 1].is_initialized_from_backdrop();
      let mut root_uncomposited: Option<Pixmap> = None;
      let start_src: tiny_skia::PixmapRef<'_> = if let Some(key) = start_key.as_ref() {
        let Some(entry) = self.backdrop_composite_cache.peek(key) else {
          return Ok(false);
        };
        entry.pixmap.as_ref()
      } else {
        let Some(record) = layer_stack.get(root_depth) else {
          return Ok(false);
        };
        if root_initialized_from_backdrop {
          let Some(root_record) = layer_stack.get(root_depth - 1) else {
            return Ok(false);
          };
          let Some(mut pixmap) = record.pixmap.clone_to_pixmap() else {
            return Ok(false);
          };
          crate::paint::canvas::uncomposite_layer_source_over_backdrop(
            &mut pixmap,
            root_record.pixmap.as_ref(),
            root_record.origin,
            root_record.source_alpha().map(|alpha| (alpha, (0, 0))),
          )?;
           root_uncomposited = Some(pixmap);
           root_uncomposited
             .as_ref()
             .expect("just set root_uncomposited") // fastrender-allow-unwrap
             .as_ref()
         } else {
           record.pixmap.as_ref()
         }
      };

      let mut current: Option<(BackdropCompositeCacheKey, u64, Pixmap)> = None;
      for idx in start_depth.saturating_add(1)..=parent_depth {
        let Some(layer_record) = layer_stack.get(idx) else {
          return Ok(false);
        };
        let Some(parent_record) = layer_stack.get(idx.saturating_sub(1)) else {
          return Ok(false);
        };
        let origin = parent_record.origin;
        let opacity = parent_record.effective_opacity();
        let blend_mode = parent_record.effective_blend_mode();
        let Some(key) = Self::backdrop_composite_cache_key(layer_stack, root_depth, idx) else {
          return Ok(false);
        };
        let fingerprint = self.backdrop_composite_mutation_fingerprint(root_depth, idx);

        let layer_pixmap = &layer_record.pixmap;
        let mut next = match new_pixmap(layer_pixmap.width(), layer_pixmap.height()) {
          Some(p) => p,
          None => return Ok(false),
        };
        self.record_backdrop_composite_allocation(next.width(), next.height());

        {
          let src = match current.as_ref() {
            Some((_, _, pixmap)) => pixmap.as_ref(),
            None => start_src,
          };
          copy_pixmap_region_with_offset(&mut next, src, origin.0, origin.1)?;
        }
        if opacity > 0.0 {
          let mut paint = PixmapPaint::default();
          paint.opacity = opacity;
          paint.quality = tiny_skia::FilterQuality::Nearest;
          paint.blend_mode = blend_mode;
          if blend_mode == SkiaBlendMode::Plus {
            draw_pixmap_with_plus_blend(
              &mut next,
              0,
              0,
              layer_pixmap.as_ref(),
              opacity,
              paint.quality,
              Transform::identity(),
              None,
            );
          } else {
            next.draw_pixmap(
              0,
              0,
              layer_pixmap.as_ref(),
              &paint,
              Transform::identity(),
              None,
            );
          }
        }

        if let Some((prev_key, prev_fingerprint, prev_pixmap)) = current.take() {
          staged.push((
            prev_key,
            BackdropCompositeCacheEntry {
              pixmap: prev_pixmap,
              mutation_fingerprint: prev_fingerprint,
            },
          ));
        }
        current = Some((key, fingerprint, next));
      }

      if let Some((key, fingerprint, pixmap)) = current.take() {
        staged.push((
          key,
          BackdropCompositeCacheEntry {
            pixmap,
            mutation_fingerprint: fingerprint,
          },
        ));
      }
      Ok(true)
    })();

    let built = match build_result {
      Ok(built) => built,
      Err(err) => return Err(err),
    };
    if !built {
      return Ok(None);
    }

    for (key, entry) in staged {
      self.backdrop_composite_cache.put(key, entry);
    }

    if self
      .backdrop_composite_cache
      .peek(&target_key)
      .is_some_and(|entry| entry.mutation_fingerprint == target_fingerprint)
    {
      return Ok(Some(target_key));
    }

    Ok(None)
  }

  fn apply_pending_backdrop(&mut self, next_item: &DisplayItem) -> RenderResult<()> {
    let (pending, layer_origin, projective_backdrop) = {
      let Some(record) = self.stacking_layers.last_mut() else {
        return Ok(());
      };
      if record.pending_backdrop.is_none() {
        return Ok(());
      }
      if matches!(next_item, DisplayItem::PushClip(_)) {
        return Ok(());
      }
      let Some(pending) = record.pending_backdrop.take() else {
        return Ok(());
      };
      let layer_origin = record.layer_origin;

      let projective_backdrop = record
        .projective_transform
        .and_then(|projective_transform| {
          // Only apply projective backdrop compensation when the stacking context will be warped at
          // `PopStackingContext` time. Otherwise we'd pre-unwarp the filtered backdrop but never
          // re-apply the element's projective transform.
          let warp_bounds = if record.filters.is_empty() {
            record.css_bounds
          } else {
            let (out_l, out_t, out_r, out_b) =
              filter_outset_with_bounds(&record.filters, 1.0, Some(record.css_bounds)).as_tuple();
            let expanded = Rect::from_xywh(
              record.css_bounds.x() - out_l,
              record.css_bounds.y() - out_t,
              record.css_bounds.width() + out_l + out_r,
              record.css_bounds.height() + out_t + out_b,
            );
            if expanded.width() > 0.0 && expanded.height() > 0.0 {
              expanded
            } else {
              record.css_bounds
            }
          };

          let corners = [
            (warp_bounds.min_x(), warp_bounds.min_y()),
            (warp_bounds.max_x(), warp_bounds.min_y()),
            (warp_bounds.max_x(), warp_bounds.max_y()),
            (warp_bounds.min_x(), warp_bounds.max_y()),
          ];

          let mut src_quad = [Point::ZERO; 4];
          let mut dst_quad_points = [Point::ZERO; 4];
          let mut valid = true;

          for (i, (x, y)) in corners.iter().enumerate() {
            let sx = *x * self.scale;
            let sy = *y * self.scale;
            let src_x = sx * record.parent_transform.sx
              + sy * record.parent_transform.kx
              + record.parent_transform.tx;
            let src_y = sx * record.parent_transform.ky
              + sy * record.parent_transform.sy
              + record.parent_transform.ty;
            src_quad[i] = Point::new(src_x - layer_origin.0 as f32, src_y - layer_origin.1 as f32);

            let (tx, ty, _tz, tw) = projective_transform.transform_point(*x, *y, 0.0);
            if !tw.is_finite() || tw.abs() < 1e-6 || tw < 0.0 || !tx.is_finite() || !ty.is_finite()
            {
              valid = false;
              break;
            }
            let px = (tx / tw) * self.scale;
            let py = (ty / tw) * self.scale;
            let dst_x = px * record.parent_transform.sx
              + py * record.parent_transform.kx
              + record.parent_transform.tx;
            let dst_y = px * record.parent_transform.ky
              + py * record.parent_transform.sy
              + record.parent_transform.ty;
            if !dst_x.is_finite() || !dst_y.is_finite() {
              valid = false;
              break;
            }
            dst_quad_points[i] = Point::new(dst_x, dst_y);
          }

          let warp_valid =
            valid && Homography::from_quad_to_quad(src_quad, dst_quad_points).is_some();
          warp_valid.then_some(ProjectiveBackdropFilterContext {
            transform: projective_transform,
            parent_transform: record.parent_transform,
          })
        });

      (pending, layer_origin, projective_backdrop)
    };

    let clip_mask = self.canvas.clip_mask_rc();
    let clip_bounds = self.canvas.clip_bounds();
    let world_to_dest = self.canvas.transform();
    let scale = self.scale;

    let layer_stack = self.canvas.layer_stack();
    if layer_stack.is_empty() {
      // Without an active layer, there's nowhere to write the filtered backdrop.
      return Ok(());
    }
    let (root_depth, parent_depth) = backdrop_root_range(layer_stack);
    let trace_cache_hit = if self.trace_backdrop_stack
      && self.backdrop_composite_cache_enabled
      && root_depth < parent_depth
    {
      Self::backdrop_composite_cache_key(layer_stack, root_depth, parent_depth).is_some_and(|key| {
        let fingerprint = self.backdrop_composite_mutation_fingerprint(root_depth, parent_depth);
        self
          .backdrop_composite_cache
          .peek(&key)
          .is_some_and(|entry| entry.mutation_fingerprint == fingerprint)
      })
    } else {
      false
    };

    let cached_key = self.ensure_backdrop_composite_cached(root_depth, parent_depth)?;

    let (layer_stack, dest_pixmap) = self.canvas.split_layer_stack_and_pixmap_mut();
    let Some(parent_surface) = layer_stack.last().map(|record| &record.pixmap) else {
      // Without an active layer, there's nowhere to write the filtered backdrop.
      return Ok(());
    };
    let cached_backdrop = cached_key
      .as_ref()
      .and_then(|key| self.backdrop_composite_cache.peek(key))
      .map(|entry| &entry.pixmap);
    let composite_steps = parent_depth.saturating_sub(root_depth);
    let backdrop_diag = self.backdrop_composite_diagnostics.clone();
    if self.trace_backdrop_stack {
      eprintln!(
        "backdrop_stack apply_backdrop_filter range={}..{} composite_allocated={} cache_hit={} composite_steps={}",
        root_depth,
        parent_depth,
        cached_backdrop.is_some(),
        trace_cache_hit,
        composite_steps
      );
    }
    let clip_origin = (0, 0);
    let blur_cache: &mut (dyn BlurCacheOps + 'static) = match self.shared_blur_cache.as_mut() {
      Some(shared) => shared,
      None => &mut self.blur_cache,
    };
    let backdrop_cache: &mut (dyn BackdropFilterCacheOps + 'static) =
      match self.shared_backdrop_filter_cache.as_mut() {
        Some(shared) => shared,
        None => &mut self.backdrop_filter_cache,
      };

    apply_backdrop_filters_with_region_filler(
      dest_pixmap,
      (parent_surface.width(), parent_surface.height()),
      layer_origin,
      pending.bounds,
      pending.shape_bounds,
      &pending.filters,
      pending.radii,
      scale,
      clip_mask.as_deref(),
      clip_bounds,
      clip_origin,
      pending.filter_bounds,
      world_to_dest,
      Some(blur_cache),
      Some(backdrop_cache),
      |region, clamped_x, clamped_y| {
        if let Some(backdrop) = cached_backdrop {
          copy_pixmap_region_with_offset(
            region,
            backdrop.as_ref(),
            clamped_x as i32,
            clamped_y as i32,
          )
        } else {
          if composite_steps > 0 {
            if let Some(diag) = backdrop_diag.as_ref() {
              for _ in 0..composite_steps {
                diag.record_allocation(region.width(), region.height());
              }
            }
          }
          Canvas::fill_backdrop_root_region(
            layer_stack,
            region,
            (clamped_x as i32, clamped_y as i32),
          )
        }
      },
      projective_backdrop,
      None,
    )?;
    self.mark_current_pixmap_mutated();
    Ok(())
  }

  /// Returns whether `list` can be evaluated in isolation for a sub-region.
  ///
  /// This is the same safety requirement as the tile-parallel renderer: any optimization that
  /// renders a halo-expanded region in isolation (then crops/blits it into a larger surface) must
  /// ensure the display list does not depend on pixels or ordering outside that region.
  ///
  /// The returned `reason` is intended for diagnostics/counters when the list is not safe.
  pub fn tile_isolation_supported(&self, list: &DisplayList) -> Result<(bool, Option<String>)> {
    let mut reason = None;
    let incompatible = self
      .has_parallel_incompatible_effects(list.items(), &mut reason)
      .map_err(Error::Render)?;
    Ok((!incompatible, reason))
  }

  /// Returns `true` if the display list contains effects that are not currently supported by the
  /// tile-parallel renderer.
  ///
  /// Today this includes `transform-style: preserve-3d` stacking contexts (which require depth
  /// sorting/compositing across the full scene), as well as nested halo-generating
  /// `backdrop-filter` chains that would require a compounded halo per tile. We also fall back
  /// for manual mix-blend-mode stacking contexts with non-translation transforms (e.g. rotated
  /// hue/saturation), since the tile renderer can produce per-tile rasterization differences for
  /// those cases.
  ///
  /// Note that isolated groups, blend modes, and Filter Effects Level 2 *Backdrop Roots* only
  /// affect compositing/sampling semantics and do not by themselves make a subtree
  /// parallel-incompatible.
  fn has_parallel_incompatible_effects(
    &self,
    items: &[DisplayItem],
    fallback_reason: &mut Option<String>,
  ) -> std::result::Result<bool, RenderError> {
    let mut deadline_counter = 0usize;
    let mut backdrop_root_stack: Vec<Vec<Rect>> = vec![Vec::new()];
    let mut backdrop_root_pop_stack: Vec<bool> = Vec::new();
    for item in items {
      check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)?;
      match item {
        DisplayItem::PushStackingContext(sc) => {
          if !self.preserve_3d_disabled && matches!(sc.transform_style, TransformStyle::Preserve3d)
          {
            *fallback_reason =
              Some("preserve-3d stacking contexts require serial painting".to_string());
            return Ok(true);
          }

          if is_manual_blend(sc.mix_blend_mode) {
            if let Some(transform) = sc.transform.as_ref() {
              let is_non_translation = match transform.to_2d() {
                Some(affine) => {
                  const EPS: f32 = 1e-6;
                  (affine.a - 1.0).abs() > EPS
                    || affine.b.abs() > EPS
                    || affine.c.abs() > EPS
                    || (affine.d - 1.0).abs() > EPS
                }
                None => true,
              };
              if is_non_translation {
                *fallback_reason = Some(
                  "manual mix-blend-mode with non-translation transform requires serial painting"
                    .to_string(),
                );
                return Ok(true);
              }
            }
          }

          let mut has_kernel_backdrop = false;
          let mut sample_rect: Option<Rect> = None;
          if !sc.backdrop_filters.is_empty() {
            let outset = filter_outset_with_bounds(&sc.backdrop_filters, 1.0, Some(sc.bounds));
            let max_outset = outset.max_side();
            if !max_outset.is_finite() {
              *fallback_reason = Some("backdrop-filter halo is non-finite".to_string());
              return Ok(true);
            }
            if max_outset > 0.0 {
              has_kernel_backdrop = true;
              let (l, t, r, b) = outset.as_tuple();
              let rect = Rect::from_xywh(
                sc.bounds.x() - l,
                sc.bounds.y() - t,
                sc.bounds.width() + l + r,
                sc.bounds.height() + t + b,
              );
              if rect.width() <= 0.0
                || rect.height() <= 0.0
                || !rect.x().is_finite()
                || !rect.y().is_finite()
                || !rect.width().is_finite()
                || !rect.height().is_finite()
              {
                *fallback_reason = Some("backdrop-filter halo is invalid".to_string());
                return Ok(true);
              }
              sample_rect = Some(rect);
            }
          }

          if has_kernel_backdrop {
            let Some(sample_rect) = sample_rect else {
              *fallback_reason = Some("backdrop-filter halo rect missing".to_string());
              return Ok(true);
            };
            if backdrop_root_stack
              .last()
              .is_some_and(|scope| scope.iter().any(|prior| prior.intersects(sample_rect)))
            {
              *fallback_reason = Some(
                "backdrop-filter depends on previously filtered backdrop; requires serial painting"
                  .to_string(),
              );
              return Ok(true);
            }
            if let Some(scope) = backdrop_root_stack.last_mut() {
              scope.push(sc.bounds);
            }
          }

          let establishes_backdrop_root = sc.establishes_backdrop_root;
          backdrop_root_pop_stack.push(establishes_backdrop_root);
          if establishes_backdrop_root {
            let mut scope = Vec::new();
            if has_kernel_backdrop {
              scope.push(sc.bounds);
            }
            backdrop_root_stack.push(scope);
          }
        }
        DisplayItem::PopStackingContext => {
          if backdrop_root_pop_stack.pop().unwrap_or(false) && backdrop_root_stack.len() > 1 {
            backdrop_root_stack.pop();
          }
        }
        _ => {}
      }
    }
    Ok(false)
  }

  fn estimated_tile_count(&self) -> usize {
    let tile = self.paint_parallelism.tile_size.max(1);
    let tiles_x = (self.canvas.width() + tile - 1) / tile;
    let tiles_y = (self.canvas.height() + tile - 1) / tile;
    tiles_x.saturating_mul(tiles_y) as usize
  }

  fn parallel_thread_budget(&self, tile_estimate: usize) -> usize {
    let paint_pool = crate::paint::paint_thread_pool::paint_pool();
    let mut threads = paint_pool.threads.max(1);
    if let Some(max_threads) = self.paint_parallelism.max_threads {
      threads = threads.min(max_threads.max(1));
    }
    threads.min(tile_estimate.max(1)).max(1)
  }

  fn should_render_parallel(
    &self,
    list: &DisplayList,
    tile_estimate: usize,
    fallback_reason: &mut Option<String>,
  ) -> Result<bool> {
    if matches!(self.paint_parallelism.mode, PaintParallelismMode::Disabled)
      || self.paint_parallelism.tile_size == 0
    {
      *fallback_reason = Some("parallel painting disabled".to_string());
      return Ok(false);
    }

    let task_capacity = self.parallel_thread_budget(tile_estimate);
    if task_capacity <= 1 && matches!(self.paint_parallelism.mode, PaintParallelismMode::Auto) {
      let paint_pool = crate::paint::paint_thread_pool::paint_pool();
      let mut message = "parallel paint thread budget is single-threaded".to_string();
      if paint_pool.threads <= 1 {
        if let Some(extra) = paint_pool.dedicated_fallback {
          message = format!("{message}; {extra}");
        }
      }
      *fallback_reason = Some(message);
      return Ok(false);
    }

    if matches!(self.paint_parallelism.mode, PaintParallelismMode::Auto)
      && tile_estimate < self.paint_parallelism.min_tiles
    {
      *fallback_reason = Some("tile count below parallel threshold".to_string());
      return Ok(false);
    }

    if self.canvas.width() <= self.paint_parallelism.tile_size
      && self.canvas.height() <= self.paint_parallelism.tile_size
    {
      *fallback_reason = Some("viewport smaller than tile size".to_string());
      return Ok(false);
    }

    let (supported, reason) = self.tile_isolation_supported(list)?;
    if !supported {
      *fallback_reason = reason;
      return Ok(false);
    }

    if matches!(self.paint_parallelism.mode, PaintParallelismMode::Enabled) {
      return Ok(true);
    }

    let work_estimate = list.len().saturating_mul(tile_estimate.max(1));
    let base_work = self
      .paint_parallelism
      .min_display_items
      .saturating_mul(self.paint_parallelism.min_tiles.max(1));
    let scaled_work = self
      .paint_parallelism
      .min_display_items
      .saturating_mul(task_capacity);
    let work_threshold = base_work.max(scaled_work);

    if work_estimate >= work_threshold {
      return Ok(true);
    }

    let (expensive_pixels, image_source_pixels, image_tile_count) =
      self.estimate_expensive_raster_pixels(list.items(), task_capacity)?;
    let tile = u64::from(self.paint_parallelism.tile_size.max(1));
    let tile_pixels = tile.saturating_mul(tile);
    let min_expensive_per_thread =
      tile_pixels.saturating_mul(self.paint_parallelism.min_tiles.max(1) as u64);
    let mut expensive_per_thread = expensive_pixels / task_capacity.max(1) as u64;
    // Some costs (notably converting raw `ImageData` into a premultiplied `Pixmap`) scale with the
    // *source* pixel count and can dominate pages with many large-but-thumbnail-sized images.
    //
    // This work is only meaningfully parallelized when those images are spread across multiple
    // tiles (so different tile tasks request and convert different images concurrently).
    if image_tile_count > 1 && image_source_pixels > 0 {
      let image_threads = image_tile_count.max(1) as u64;
      expensive_per_thread =
        expensive_per_thread.saturating_add(image_source_pixels / image_threads);
    }
    if expensive_per_thread < min_expensive_per_thread {
      *fallback_reason = Some("estimated paint work below parallel threshold".to_string());
      return Ok(false);
    }

    Ok(true)
  }

  fn estimate_expensive_raster_pixels(
    &self,
    items: &[DisplayItem],
    task_capacity: usize,
  ) -> Result<(u64, u64, usize)> {
    const GRADIENT_WEIGHT: u64 = 4;
    const IMAGE_LINEAR_WEIGHT: u64 = 2;
    const OPACITY_WEIGHT: u64 = 1;
    const BLEND_WEIGHT: u64 = 1;
    const MANUAL_BLEND_WEIGHT: u64 = 4;

    let viewport = Rect::from_xywh(
      0.0,
      0.0,
      self.canvas.width() as f32,
      self.canvas.height() as f32,
    );
    let mut total = 0u64;
    let mut image_source_pixels = 0u64;
    let tile_size = self.paint_parallelism.tile_size.max(1);
    let tiles_x = (self.canvas.width() + tile_size - 1) / tile_size;
    let tiles_y = (self.canvas.height() + tile_size - 1) / tile_size;
    let tile_cap = task_capacity
      .max(1)
      .min((tiles_x.saturating_mul(tiles_y)).max(1) as usize);
    struct BlendScope {
      weight: u64,
      bounds: Option<Rect>,
    }

    struct OpacityScope {
      weight: u64,
      bounds: Option<Rect>,
    }

    let mut image_tiles: Vec<u64> = Vec::with_capacity(tile_cap.min(8));
    let mut deadline_counter = 0usize;
    // Track blend-mode groups introduced by `PushBlendMode`. In auto parallel mode we use these
    // to estimate per-pixel compositor cost so large blend-mode layers don't stay serial.
    let mut blend_stack: Vec<BlendScope> = Vec::new();
    let mut active_blend_scopes = 0usize;
    let mut opacity_stack: Vec<OpacityScope> = Vec::new();
    let mut active_opacity_scopes = 0usize;
    let union_bounds = |dst: &mut Option<Rect>, rect: Rect| {
      *dst = Some(match *dst {
        Some(prev) => prev.union(rect),
        None => rect,
      });
    };

    let add_rect = |total: &mut u64, rect: Rect, weight: u64| -> Option<Rect> {
      if weight == 0 {
        return None;
      }
      let Some(intersection) = rect.intersection(viewport) else {
        return None;
      };
      let w = intersection.width().ceil().max(0.0) as u64;
      let h = intersection.height().ceil().max(0.0) as u64;
      if w == 0 || h == 0 {
        return None;
      }
      let area = w.saturating_mul(h);
      *total = total.saturating_add(area.saturating_mul(weight));
      Some(intersection)
    };

    for item in items {
      check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
        .map_err(Error::Render)?;
      if (active_blend_scopes > 0 || active_opacity_scopes > 0) && !item.is_stack_operation() {
        if let Some(bounds) = item.bounds() {
          if active_blend_scopes > 0 {
            if let Some(scope) = blend_stack.iter_mut().rev().find(|scope| scope.weight > 0) {
              union_bounds(&mut scope.bounds, bounds);
            }
          }
          if active_opacity_scopes > 0 {
            if let Some(scope) = opacity_stack
              .iter_mut()
              .rev()
              .find(|scope| scope.weight > 0)
            {
              union_bounds(&mut scope.bounds, bounds);
            }
          }
        }
      }
      match item {
        DisplayItem::PushBlendMode(item) => {
          let weight = if matches!(item.mode, BlendMode::Normal) {
            0
          } else if is_manual_blend(item.mode) {
            MANUAL_BLEND_WEIGHT
          } else {
            BLEND_WEIGHT
          };
          if weight > 0 {
            active_blend_scopes = active_blend_scopes.saturating_add(1);
          }
          blend_stack.push(BlendScope {
            weight,
            bounds: None,
          });
        }
        DisplayItem::PopBlendMode => {
          let Some(scope) = blend_stack.pop() else {
            continue;
          };
          if scope.weight > 0 {
            active_blend_scopes = active_blend_scopes.saturating_sub(1);
          }
          if scope.weight == 0 {
            continue;
          };
          let Some(bounds) = scope.bounds else {
            continue;
          };
          let _ = add_rect(&mut total, self.ds_rect(bounds), scope.weight);
          if let Some(parent) = blend_stack.iter_mut().rev().find(|scope| scope.weight > 0) {
            union_bounds(&mut parent.bounds, bounds);
          }
        }
        DisplayItem::PushOpacity(item) => {
          let weight = if item.opacity < 1.0 - f32::EPSILON {
            OPACITY_WEIGHT
          } else {
            0
          };
          if weight > 0 {
            active_opacity_scopes = active_opacity_scopes.saturating_add(1);
          }
          opacity_stack.push(OpacityScope {
            weight,
            bounds: None,
          });
        }
        DisplayItem::PopOpacity => {
          let Some(scope) = opacity_stack.pop() else {
            continue;
          };
          if scope.weight > 0 {
            active_opacity_scopes = active_opacity_scopes.saturating_sub(1);
          }
          if scope.weight == 0 {
            continue;
          }
          let Some(bounds) = scope.bounds else {
            continue;
          };
          let _ = add_rect(&mut total, self.ds_rect(bounds), scope.weight);
          if let Some(parent) = opacity_stack
            .iter_mut()
            .rev()
            .find(|scope| scope.weight > 0)
          {
            union_bounds(&mut parent.bounds, bounds);
          }
        }
        DisplayItem::LinearGradient(item) => {
          let _ = add_rect(&mut total, self.ds_rect(item.rect), GRADIENT_WEIGHT);
        }
        DisplayItem::LinearGradientPattern(item) => {
          let _ = add_rect(&mut total, self.ds_rect(item.dest_rect), GRADIENT_WEIGHT);
        }
        DisplayItem::RadialGradient(item) => {
          let _ = add_rect(&mut total, self.ds_rect(item.rect), GRADIENT_WEIGHT);
        }
        DisplayItem::RadialGradientPattern(item) => {
          let _ = add_rect(&mut total, self.ds_rect(item.dest_rect), GRADIENT_WEIGHT);
        }
        DisplayItem::ConicGradient(item) => {
          let _ = add_rect(&mut total, self.ds_rect(item.rect), GRADIENT_WEIGHT);
        }
        DisplayItem::ConicGradientPattern(item) => {
          let _ = add_rect(&mut total, self.ds_rect(item.dest_rect), GRADIENT_WEIGHT);
        }
        DisplayItem::Image(item) => {
          let weight = match item.filter_quality {
            ImageFilterQuality::Nearest => 1,
            ImageFilterQuality::Linear => IMAGE_LINEAR_WEIGHT,
          };
          let dest_rect = self.ds_rect(item.dest_rect);
          let Some(intersection) = add_rect(&mut total, dest_rect, weight) else {
            continue;
          };
          if tile_cap <= 1 {
            continue;
          }
          let target_w = dest_rect.width().abs().ceil().max(1.0) as u32;
          let target_h = dest_rect.height().abs().ceil().max(1.0) as u32;
          let needs_full_pixmap = item.src_rect.is_some()
            || !Self::should_use_scaled_image_pixmap(
              item.filter_quality,
              item.image.width,
              item.image.height,
              target_w,
              target_h,
            );
          if !needs_full_pixmap {
            continue;
          }
          let src_px = u64::from(item.image.width).saturating_mul(u64::from(item.image.height));
          image_source_pixels = image_source_pixels.saturating_add(src_px);
          if image_tiles.len() >= tile_cap {
            continue;
          }
          let min_x = intersection.x().floor().max(0.0) as u32;
          let min_y = intersection.y().floor().max(0.0) as u32;
          let max_x = (intersection.x() + intersection.width()).ceil().max(0.0) as u32;
          let max_y = (intersection.y() + intersection.height()).ceil().max(0.0) as u32;
          if max_x == 0 || max_y == 0 {
            continue;
          }
          let tile_x0 = min_x / tile_size;
          let tile_y0 = min_y / tile_size;
          let tile_x1 = max_x.saturating_sub(1) / tile_size;
          let tile_y1 = max_y.saturating_sub(1) / tile_size;
          for ty in tile_y0..=tile_y1 {
            for tx in tile_x0..=tile_x1 {
              let id = u64::from(ty).saturating_mul(u64::from(tiles_x)) + u64::from(tx);
              if image_tiles.contains(&id) {
                continue;
              }
              image_tiles.push(id);
              if image_tiles.len() >= tile_cap {
                break;
              }
            }
            if image_tiles.len() >= tile_cap {
              break;
            }
          }
        }
        DisplayItem::ImagePattern(item) => {
          let weight = match item.filter_quality {
            ImageFilterQuality::Nearest => 1,
            ImageFilterQuality::Linear => IMAGE_LINEAR_WEIGHT,
          };
          let _ = add_rect(&mut total, self.ds_rect(item.dest_rect), weight);
        }
        DisplayItem::BoxShadow(item) => {
          let shadow = BoxShadow {
            offset_x: self.ds_len(item.offset.x),
            offset_y: self.ds_len(item.offset.y),
            blur_radius: self.ds_len(item.blur_radius),
            spread_radius: self.ds_len(item.spread_radius),
            color: item.color,
            inset: item.inset,
          };
          let rect = self.ds_rect(item.rect);
          let tmp_pixels = estimate_box_shadow_work_pixels(rect.width(), rect.height(), &shadow);
          let blur_weight = if shadow.blur_radius.abs() > 0.0 { 8 } else { 1 };
          total = total.saturating_add(tmp_pixels.saturating_mul(blur_weight));
        }
        DisplayItem::PushStackingContext(sc) => {
          let bounds = self.ds_rect(sc.bounds);

          if sc.opacity < 1.0 - f32::EPSILON {
            let _ = add_rect(&mut total, bounds, OPACITY_WEIGHT);
          }

          if !matches!(sc.mix_blend_mode, BlendMode::Normal) {
            // Blend modes composite an intermediate surface back into the destination. Manual blend
            // modes (HSL/HSV/OKLCH conversions + plus-darker) are more expensive than tiny-skia
            // blend modes, so give them a higher weight to nudge `PaintParallelismMode::Auto`
            // toward tiling for pages dominated by blending.
            let weight = if is_manual_blend(sc.mix_blend_mode) {
              MANUAL_BLEND_WEIGHT
            } else {
              BLEND_WEIGHT
            };
            let _ = add_rect(&mut total, bounds, weight);
          }

          if sc.filters.is_empty() && sc.backdrop_filters.is_empty() {
            continue;
          }

          // `filter` and `backdrop-filter` both allocate and rasterize intermediate surfaces.
          // Treat them similarly in the heuristics that decide whether parallel tiling is worth
          // the overhead, otherwise pages dominated by backdrop filters stay serial.
          let mut add_filters = |filters: &[ResolvedFilter], total: &mut u64| {
            if filters.is_empty() {
              return;
            }

            let mut weight = 0u64;
            for filter in filters {
              weight += match filter {
                ResolvedFilter::Blur(radius) => {
                  let r = self.ds_len(*radius).abs().round().min(32.0) as u64;
                  8 + r
                }
                ResolvedFilter::DropShadow { blur_radius, .. } => {
                  let r = self.ds_len(*blur_radius).abs().round().min(32.0) as u64;
                  8 + r
                }
                ResolvedFilter::SvgFilter(_) => 24,
                _ => 4,
              };
            }

            if weight == 0 {
              return;
            }

            let outset = filter_outset_with_bounds(filters, self.scale, Some(sc.bounds));
            let inflated = Rect::from_xywh(
              bounds.x() - outset.left,
              bounds.y() - outset.top,
              bounds.width() + outset.left + outset.right,
              bounds.height() + outset.top + outset.bottom,
            );
            add_rect(total, inflated, weight);
          };

          add_filters(&sc.filters, &mut total);
          add_filters(&sc.backdrop_filters, &mut total);
        }
        _ => {}
      }
    }

    Ok((total, image_source_pixels, image_tiles.len()))
  }

  fn tile_halo_px(&self, list: &DisplayList) -> Result<u32> {
    conservative_tile_halo_px(list, self.scale)
  }

  fn estimate_tiled_render_pixels(&self, halo_px: u32) -> u128 {
    let tile_size = self.paint_parallelism.tile_size.max(1);
    let width = self.canvas.width();
    let height = self.canvas.height();
    let halo2 = halo_px.saturating_mul(2);

    let mut sum_w = 0u128;
    for x in (0..width).step_by(tile_size as usize) {
      let tile_w = width.saturating_sub(x).min(tile_size);
      let render_x = x.saturating_sub(halo_px);
      let max_w = width.saturating_sub(render_x);
      let render_w = tile_w.saturating_add(halo2).min(max_w).max(tile_w);
      sum_w = sum_w.saturating_add(u128::from(render_w));
    }

    let mut sum_h = 0u128;
    for y in (0..height).step_by(tile_size as usize) {
      let tile_h = height.saturating_sub(y).min(tile_size);
      let render_y = y.saturating_sub(halo_px);
      let max_h = height.saturating_sub(render_y);
      let render_h = tile_h.saturating_add(halo2).min(max_h).max(tile_h);
      sum_h = sum_h.saturating_add(u128::from(render_h));
    }

    sum_w.saturating_mul(sum_h)
  }

  fn halo_amplification_fallback_reason(&self, halo_px: u32) -> Option<String> {
    let canvas_pixels =
      u128::from(self.canvas.width()).saturating_mul(u128::from(self.canvas.height()));
    if canvas_pixels == 0 {
      return None;
    }

    let tiled_pixels = self.estimate_tiled_render_pixels(halo_px);
    let max_pixels = canvas_pixels.saturating_mul(MAX_PARALLEL_TILE_PIXEL_AMPLIFICATION);
    if tiled_pixels > max_pixels {
      let amplification = tiled_pixels as f64 / canvas_pixels as f64;
      Some(format!(
        "halo amplification too large ({:.1}x, halo_px={}, tile_size={})",
        amplification,
        halo_px,
        self.paint_parallelism.tile_size.max(1)
      ))
    } else {
      None
    }
  }

  fn build_tiles<'a>(&self, list: &'a DisplayList, halo_px: u32) -> Result<Vec<TileWork<'a>>> {
    let tile_size = self.paint_parallelism.tile_size.max(1);
    let width = self.canvas.width();
    let height = self.canvas.height();
    let halo2 = halo_px.saturating_mul(2);
    let optimizer = DisplayListOptimizer::new();
    let mut tiles = Vec::new();
    let mut deadline_counter = 0usize;

    for y in (0..height).step_by(tile_size as usize) {
      let tile_h = height.saturating_sub(y).min(tile_size);
      for x in (0..width).step_by(tile_size as usize) {
        check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
          .map_err(Error::Render)?;
        let tile_w = width.saturating_sub(x).min(tile_size);

        let render_x = x.saturating_sub(halo_px);
        let render_y = y.saturating_sub(halo_px);
        let max_w = width.saturating_sub(render_x);
        let max_h = height.saturating_sub(render_y);
        let render_w = tile_w.saturating_add(halo2).min(max_w).max(tile_w);
        let render_h = tile_h.saturating_add(halo2).min(max_h).max(tile_h);

        let render_css_rect = Rect::from_xywh(
          render_x as f32 / self.scale,
          render_y as f32 / self.scale,
          render_w as f32 / self.scale,
          render_h as f32 / self.scale,
        );
        let slice = optimizer
          .intersect_view(list.items(), render_css_rect)
          .map_err(Error::Render)?;

        tiles.push(TileWork {
          tile_x: x,
          tile_y: y,
          tile_w,
          tile_h,
          render_x,
          render_y,
          render_w,
          render_h,
          list: slice,
        });
      }
    }

    Ok(tiles)
  }

  fn build_tiles_for_device_rect<'a>(
    &self,
    list: &'a DisplayList,
    halo_px: u32,
    device_rect: Rect,
  ) -> Result<Vec<TileWork<'a>>> {
    let tile_size = self.paint_parallelism.tile_size.max(1);
    let width = self.canvas.width();
    let height = self.canvas.height();
    let halo2 = halo_px.saturating_mul(2);
    let optimizer = DisplayListOptimizer::new();
    let mut tiles = Vec::new();
    let mut deadline_counter = 0usize;

    let device_rect = device_rect
      .intersection(Rect::from_xywh(0.0, 0.0, width as f32, height as f32))
      .unwrap_or(Rect::from_xywh(0.0, 0.0, 0.0, 0.0));

    if device_rect.width() <= 0.0 || device_rect.height() <= 0.0 {
      return Ok(tiles);
    }

    for y in (0..height).step_by(tile_size as usize) {
      let tile_h = height.saturating_sub(y).min(tile_size);
      for x in (0..width).step_by(tile_size as usize) {
        check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
          .map_err(Error::Render)?;
        let tile_w = width.saturating_sub(x).min(tile_size);

        let tile_rect = Rect::from_xywh(x as f32, y as f32, tile_w as f32, tile_h as f32);
        if !tile_rect.intersects(device_rect) {
          continue;
        }

        let render_x = x.saturating_sub(halo_px);
        let render_y = y.saturating_sub(halo_px);
        let max_w = width.saturating_sub(render_x);
        let max_h = height.saturating_sub(render_y);
        let render_w = tile_w.saturating_add(halo2).min(max_w).max(tile_w);
        let render_h = tile_h.saturating_add(halo2).min(max_h).max(tile_h);

        let render_css_rect = Rect::from_xywh(
          render_x as f32 / self.scale,
          render_y as f32 / self.scale,
          render_w as f32 / self.scale,
          render_h as f32 / self.scale,
        );
        let slice = optimizer
          .intersect_view(list.items(), render_css_rect)
          .map_err(Error::Render)?;

        tiles.push(TileWork {
          tile_x: x,
          tile_y: y,
          tile_w,
          tile_h,
          render_x,
          render_y,
          render_w,
          render_h,
          list: slice,
        });
      }
    }

    Ok(tiles)
  }

  fn blit_tile(&mut self, work: &TileWork, pixmap: &Pixmap) -> Result<()> {
    self.canvas.with_mirrored_pixmap_mut_result(|dest| {
      let dest_bpr = dest.width() as usize * 4;
      let src_bpr = pixmap.width() as usize * 4;
      let start_x = work.tile_x.saturating_sub(work.render_x) as usize;
      let start_y = work.tile_y.saturating_sub(work.render_y) as usize;

      let mut deadline_counter = 0usize;
      for row in 0..work.tile_h as usize {
        check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
          .map_err(Error::Render)?;
        let dest_offset = (work.tile_y as usize + row) * dest_bpr + work.tile_x as usize * 4;
        let src_offset = (start_y + row) * src_bpr + start_x * 4;
        let len = work.tile_w as usize * 4;
        dest.data_mut()[dest_offset..dest_offset + len]
          .copy_from_slice(&pixmap.data()[src_offset..src_offset + len]);
      }

      Ok(())
    })
  }

  fn repaint_tiles_for_damage(
    &mut self,
    list: &DisplayList,
    halo_px: u32,
    damage_rect: Rect,
  ) -> Result<RepaintTilesReport> {
    if damage_rect.width() <= 0.0
      || damage_rect.height() <= 0.0
      || !damage_rect.x().is_finite()
      || !damage_rect.y().is_finite()
      || !damage_rect.width().is_finite()
      || !damage_rect.height().is_finite()
    {
      return Ok(RepaintTilesReport {
        tiles: 0,
        device_rects: Vec::new(),
      });
    }

    let device_damage = self.ds_rect(damage_rect);
    let tiles = self.build_tiles_for_device_rect(list, halo_px, device_damage)?;
    if tiles.is_empty() {
      return Ok(RepaintTilesReport {
        tiles: 0,
        device_rects: Vec::new(),
      });
    }

    let font_ctx = self.font_ctx.clone();
    let scale = self.scale;
    let background = self.background;
    let preserve_3d_disabled = self.preserve_3d_disabled;
    let preserve_3d_scene_depth = self.preserve_3d_scene_depth;
    let projective_warp_enabled = self.projective_warp_enabled;
    let projective_warp_depth = self.projective_warp_depth;
    let preserve_3d_debug = self.preserve_3d_debug;
    let color_renderer = self.color_renderer.clone();
    let color_cache = self.color_cache.clone();
    let glyph_cache = self.glyph_cache.clone();
    let gradient_cache = self.gradient_cache.clone();
    let gradient_pixmap_cache = self.gradient_pixmap_cache.clone();
    let diagnostics_enabled = self.diagnostics_enabled;
    let image_pixmap_diagnostics = self.image_pixmap_diagnostics.clone();
    let background_paint_diagnostics = self.background_paint_diagnostics.clone();
    let clip_mask_diagnostics = self.clip_mask_diagnostics.clone();
    let layer_alloc_diagnostics = self.layer_alloc_diagnostics.clone();
    let backdrop_composite_diagnostics = self.backdrop_composite_diagnostics.clone();
    let shared_image_pixmaps = self.shared_image_pixmaps.clone();
    let shared_backdrop_filter_cache = self.shared_backdrop_filter_cache.clone();

    let mut repainted = 0usize;
    let mut repainted_device_rects: Vec<Rect> = Vec::new();
    let mut tile_stats = GradientStats::default();
    for work in tiles {
      check_active(RenderStage::Paint).map_err(Error::Render)?;
      let mut renderer = DisplayListRenderer::new_with_text_state(
        work.render_w,
        work.render_h,
        background,
        font_ctx.clone(),
        scale,
        color_renderer.clone(),
        color_cache.clone(),
        glyph_cache.clone(),
      )?;
      renderer.preserve_3d_disabled = preserve_3d_disabled;
      renderer.preserve_3d_scene_depth = preserve_3d_scene_depth;
      renderer.projective_warp_enabled = projective_warp_enabled;
      renderer.projective_warp_depth = projective_warp_depth;
      renderer.preserve_3d_debug = preserve_3d_debug;
      renderer.paint_parallelism = PaintParallelism::disabled();
      renderer.gradient_cache = gradient_cache.clone();
      renderer.gradient_pixmap_cache = gradient_pixmap_cache.clone();
      renderer.shared_backdrop_filter_cache = shared_backdrop_filter_cache.clone();
      renderer.diagnostics_enabled = diagnostics_enabled;
      renderer.image_pixmap_diagnostics = image_pixmap_diagnostics.clone();
      renderer.background_paint_diagnostics = background_paint_diagnostics.clone();
      renderer.clip_mask_diagnostics = clip_mask_diagnostics.clone();
      renderer.layer_alloc_diagnostics = layer_alloc_diagnostics.clone();
      renderer.backdrop_composite_diagnostics = backdrop_composite_diagnostics.clone();
      renderer.shared_image_pixmaps = shared_image_pixmaps.clone();

      if work.render_x > 0 || work.render_y > 0 {
        renderer
          .canvas
          .translate(-(work.render_x as f32), -(work.render_y as f32));
      }
      renderer.render_slice(&work.list)?;
      tile_stats.merge(&renderer.gradient_stats);
      self.blit_tile(&work, renderer.canvas.pixmap())?;
      repainted = repainted.saturating_add(1);
      repainted_device_rects.push(Rect::from_xywh(
        work.tile_x as f32,
        work.tile_y as f32,
        work.tile_w as f32,
        work.tile_h as f32,
      ));
    }

    self.gradient_stats.merge(&tile_stats);
    if repainted > 0 {
      self.mark_current_pixmap_mutated();
    }
    Ok(RepaintTilesReport {
      tiles: repainted,
      device_rects: repainted_device_rects,
    })
  }

  fn render_parallel(
    &mut self,
    list: &DisplayList,
    halo_px: u32,
  ) -> Result<(Pixmap, usize, usize, usize, Duration)> {
    #[cfg(test)]
    PARALLEL_RENDER_INVOCATIONS.with(|count| count.set(count.get().saturating_add(1)));
    let mut tiles = self.build_tiles(list, halo_px)?;
    let tile_count = tiles.len();
    self.canvas.clear(self.background);

    let paint_pool = crate::paint::paint_thread_pool::paint_pool();
    let font_ctx = self.font_ctx.clone();
    let scale = self.scale;
    let background = self.background;
    let preserve_3d_disabled = self.preserve_3d_disabled;
    let preserve_3d_scene_depth = self.preserve_3d_scene_depth;
    let color_renderer = self.color_renderer.clone();
    let color_cache = self.color_cache.clone();
    let glyph_cache = self.glyph_cache.clone();
    let gradient_cache = self.gradient_cache.clone();
    let gradient_pixmap_cache = self.gradient_pixmap_cache.clone();
    // NOTE: Tile renderers run concurrently. Sharing a single blur cache across tiles can lead to
    // incorrect results for some filter chains (notably `backdrop-filter` + blur). Keep blur cache
    // state local to each tile renderer to guarantee serial/parallel byte equality.
    let shared_blur_cache: Option<SharedBlurCache> = None;
    let shared_backdrop_filter_cache = SharedBackdropFilterCache::default();
    let diagnostics_enabled = self.diagnostics_enabled;
    let diagnostics_session = paint_diagnostics_session_id();
    let text_diagnostics_session = text_diagnostics_session_id();
    let image_pixmap_diagnostics = self.image_pixmap_diagnostics.clone();
    let background_paint_diagnostics = self.background_paint_diagnostics.clone();
    let clip_mask_diagnostics = self.clip_mask_diagnostics.clone();
    let layer_alloc_diagnostics = self.layer_alloc_diagnostics.clone();
    let backdrop_composite_diagnostics = self.backdrop_composite_diagnostics.clone();

    let deadline = active_deadline();
    let stage = active_stage();
    let stage_heartbeat = active_stage_heartbeat();
    let allocation_budget = active_allocation_budget();

    let task_capacity = self.parallel_thread_budget(tile_count);
    let shared_image_cache_items = crate::debug::runtime::runtime_toggles().usize_with_default(
      ENV_SHARED_IMAGE_PIXMAP_CACHE_ITEMS,
      DEFAULT_SHARED_IMAGE_PIXMAP_CACHE_ITEMS,
    );
    let shared_image_pixmaps = Arc::new(SharedImagePixmaps::new(
      shared_image_cache_items,
      SCALED_IMAGE_CACHE_CAPACITY,
    ));
    let chunk_size = tile_count
      .checked_add(task_capacity.saturating_sub(1))
      .unwrap_or(tile_count)
      / task_capacity.max(1);
    let mut chunks: Vec<Vec<TileWork<'_>>> = Vec::new();
    while !tiles.is_empty() {
      let take = chunk_size.min(tiles.len()).max(1);
      chunks.push(tiles.drain(..take).collect());
    }
    let task_count = chunks.len();

    let parallel_start = Instant::now();
    let run_tiles = || -> Result<Vec<Vec<(TileWork<'_>, Pixmap, GradientStats)>>> {
      chunks
        .into_par_iter()
        .map(|chunk| {
          let _diagnostics_guard = diagnostics_session.map(PaintDiagnosticsThreadGuard::enter);
          let _text_diagnostics_guard =
            text_diagnostics_session.map(TextDiagnosticsThreadGuard::enter);
          with_allocation_budget(allocation_budget.as_ref(), || {
            let _heartbeat_guard = StageHeartbeatGuard::install(stage_heartbeat);
            with_deadline(deadline.as_ref(), || {
              let _stage_guard = StageGuard::install(stage);
              let mut out = Vec::with_capacity(chunk.len());
              for work in chunk {
                check_active(RenderStage::Paint).map_err(Error::Render)?;
                let mut renderer = DisplayListRenderer::new_with_text_state(
                  work.render_w,
                  work.render_h,
                  background,
                  font_ctx.clone(),
                  scale,
                  color_renderer.clone(),
                  color_cache.clone(),
                  glyph_cache.clone(),
                )?;
                renderer.preserve_3d_disabled = preserve_3d_disabled;
                renderer.preserve_3d_scene_depth = preserve_3d_scene_depth;
                renderer.paint_parallelism = PaintParallelism::disabled();
                renderer.gradient_cache = gradient_cache.clone();
                renderer.gradient_pixmap_cache = gradient_pixmap_cache.clone();
                renderer.shared_blur_cache = shared_blur_cache.clone();
                renderer.shared_backdrop_filter_cache = Some(shared_backdrop_filter_cache.clone());
                renderer.diagnostics_enabled = diagnostics_enabled;
                renderer.image_pixmap_diagnostics = image_pixmap_diagnostics.clone();
                renderer.background_paint_diagnostics = background_paint_diagnostics.clone();
                renderer.clip_mask_diagnostics = clip_mask_diagnostics.clone();
                renderer.layer_alloc_diagnostics = layer_alloc_diagnostics.clone();
                renderer.backdrop_composite_diagnostics = backdrop_composite_diagnostics.clone();
                renderer.shared_image_pixmaps = Some(shared_image_pixmaps.clone());
                if work.render_x > 0 || work.render_y > 0 {
                  renderer
                    .canvas
                    .translate(-(work.render_x as f32), -(work.render_y as f32));
                }
                renderer.render_slice(&work.list)?;
                let stats = renderer.gradient_stats;
                out.push((work, renderer.canvas.into_pixmap(), stats));
              }
              Ok(out)
            })
          })
        })
        .collect()
    };

    let results = if let Some(pool) = paint_pool.pool {
      pool.install(run_tiles)
    } else {
      run_tiles()
    };
    let parallel_duration = parallel_start.elapsed();

    let results = results?;
    let mut tile_stats = GradientStats::default();
    let mut deadline_counter = 0usize;
    for chunk in results {
      for (work, pixmap, stats) in chunk {
        check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
          .map_err(Error::Render)?;
        tile_stats.merge(&stats);
        self.blit_tile(&work, &pixmap)?;
      }
    }
    self.gradient_stats.merge(&tile_stats);
    let threads_used = task_capacity.max(1);

    let pixmap = self.canvas.pixmap().clone();
    Ok((
      pixmap,
      tile_count,
      task_count,
      threads_used,
      parallel_duration,
    ))
  }

  fn render_slice<T>(&mut self, items: &T) -> Result<()>
  where
    T: DisplayItemSource + ?Sized,
  {
    check_active(RenderStage::Paint).map_err(Error::Render)?;
    let mut idx = 0;
    while idx < items.len() {
      check_active(RenderStage::Paint).map_err(Error::Render)?;
      let item = items
        .get(idx)
        .expect("display list iteration should remain in-bounds");
      if self.culled_depth == 0
        && !self.preserve_3d_disabled
        && self.preserve_3d_scene_depth < PRESERVE_3D_SCENE_RECURSION_LIMIT
      {
        if let DisplayItem::PushStackingContext(sc) = item {
          if matches!(sc.transform_style, TransformStyle::Preserve3d) {
            // `render_item` normally applies pending backdrop filters before processing the next
            // item. We skip `render_item` for preserve-3d roots to render the subtree as a
            // depth-sorted scene, so apply pending backdrops here to keep behavior consistent.
            self.apply_pending_backdrop(item)?;
            idx = self.render_preserve_3d_context(items, idx)? + 1;
            continue;
          }
        }
      }
      self.render_item(item)?;
      idx += 1;
    }
    Ok(())
  }

  fn preserve_3d_scene_raster_config(&self) -> Preserve3dSceneRasterConfig {
    Preserve3dSceneRasterConfig {
      font_ctx: self.font_ctx.clone(),
      scale: self.scale,
      preserve_3d_disabled: self.preserve_3d_disabled,
      preserve_3d_scene_depth: self.preserve_3d_scene_depth,
      gradient_cache: self.gradient_cache.clone(),
      gradient_pixmap_cache: self.gradient_pixmap_cache.clone(),
      diagnostics_enabled: self.diagnostics_enabled,
      image_pixmap_diagnostics: self.image_pixmap_diagnostics.clone(),
      background_paint_diagnostics: self.background_paint_diagnostics.clone(),
      clip_mask_diagnostics: self.clip_mask_diagnostics.clone(),
      layer_alloc_diagnostics: self.layer_alloc_diagnostics.clone(),
      backdrop_composite_diagnostics: self.backdrop_composite_diagnostics.clone(),
    }
  }

  fn estimate_preserve_3d_plane_pixels(&self, bounds: Rect) -> u64 {
    if bounds.width() <= 0.0 || bounds.height() <= 0.0 {
      return 0;
    }
    if !bounds.width().is_finite() || !bounds.height().is_finite() {
      return 0;
    }
    let width = (bounds.width() * self.scale).ceil().max(1.0) as u64;
    let height = (bounds.height() * self.scale).ceil().max(1.0) as u64;
    width.saturating_mul(height)
  }

  fn should_rasterize_preserve_3d_planes_parallel(
    &self,
    scene_items: &[Preserve3dSceneItem],
  ) -> bool {
    if scene_items.len() < 2 {
      return false;
    }

    // Avoid recursively parallelizing preserve-3d contexts created by plane-level raster tasks.
    if preserve_3d_plane_parallel_active() {
      return false;
    }

    if let Some(force) = runtime_bool_override("FASTR_PRESERVE3D_PLANE_PARALLEL") {
      return force;
    }

    let task_capacity = self.parallel_thread_budget(scene_items.len());
    if task_capacity <= 1 {
      return false;
    }

    let mut total_pixels = 0u64;
    for item in scene_items {
      total_pixels =
        total_pixels.saturating_add(self.estimate_preserve_3d_plane_pixels(item.bounds));
    }

    scene_items.len() >= PRESERVE_3D_PLANE_PARALLEL_MIN_PLANES
      || (scene_items.len() >= PRESERVE_3D_PLANE_PARALLEL_MIN_PLANES_WITH_WORK
        && total_pixels >= PRESERVE_3D_PLANE_PARALLEL_MIN_TOTAL_PIXELS)
  }

  fn rasterize_preserve_3d_planes_parallel(
    &mut self,
    scene_items: &[Preserve3dSceneItem],
    order: &[usize],
  ) -> Result<Vec<Option<Pixmap>>> {
    let plane_count = scene_items.len();
    if plane_count == 0 {
      return Ok(Vec::new());
    }
    debug_assert_eq!(
      plane_count,
      order.len(),
      "preserve-3d paint order should reference every plane exactly once"
    );

    let paint_pool = crate::paint::paint_thread_pool::paint_pool();
    let mut threads = paint_pool.threads.max(1);
    if let Some(max_threads) = self.paint_parallelism.max_threads {
      threads = threads.min(max_threads.max(1));
    }
    let task_capacity = threads.min(plane_count.max(1)).max(1);

    let raster_config = self.preserve_3d_scene_raster_config();
    let deadline = active_deadline();
    let stage = active_stage();
    let stage_heartbeat = active_stage_heartbeat();
    let allocation_budget = active_allocation_budget();
    let diagnostics_session = paint_diagnostics_session_id();
    let text_diagnostics_session = text_diagnostics_session_id();

    let chunk_size = plane_count
      .checked_add(task_capacity.saturating_sub(1))
      .unwrap_or(plane_count)
      / task_capacity.max(1);
    let mut indices: Vec<usize> = order.to_vec();
    let mut chunks: Vec<Vec<usize>> = Vec::new();
    while !indices.is_empty() {
      let take = chunk_size.min(indices.len()).max(1);
      chunks.push(indices.drain(..take).collect());
    }

    let run_planes = || -> Result<Vec<Vec<(usize, Option<Pixmap>, GradientStats)>>> {
      chunks
        .into_par_iter()
        .map(|chunk| {
          let _diagnostics_guard = diagnostics_session.map(PaintDiagnosticsThreadGuard::enter);
          let _text_diagnostics_guard =
            text_diagnostics_session.map(TextDiagnosticsThreadGuard::enter);
          with_allocation_budget(allocation_budget.as_ref(), || {
            let _heartbeat_guard = StageHeartbeatGuard::install(stage_heartbeat);
            with_deadline(deadline.as_ref(), || {
              let _stage_guard = StageGuard::install(stage);
              let _plane_guard = Preserve3dPlaneParallelGuard::enter();
              let mut out = Vec::with_capacity(chunk.len());
              for idx in chunk {
                check_active(RenderStage::Paint).map_err(Error::Render)?;
                let (pixmap, stats) = raster_config.rasterize(&scene_items[idx])?;
                out.push((idx, pixmap, stats));
              }
              Ok(out)
            })
          })
        })
        .collect()
    };

    let results = if let Some(pool) = paint_pool.pool {
      pool.install(run_planes)
    } else {
      run_planes()
    };

    let results = results?;
    let mut rendered = vec![None; plane_count];
    let mut combined_stats = GradientStats::default();
    let mut deadline_counter = 0usize;
    for chunk in results {
      for (idx, pixmap, stats) in chunk {
        check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
          .map_err(Error::Render)?;
        rendered[idx] = pixmap;
        combined_stats.merge(&stats);
      }
    }
    self.gradient_stats.merge(&combined_stats);
    Ok(rendered)
  }

  fn render_preserve_3d_context<T>(&mut self, items: &T, start_index: usize) -> Result<usize>
  where
    T: DisplayItemSource + ?Sized,
  {
    let Some((node, end_idx)) = parse_stacking_node(items, start_index) else {
      // Fallback to normal rendering if the tree is malformed.
      if let Some(item) = items.get(start_index) {
        self.render_item(item)?;
      }
      return Ok(start_index);
    };

    let parent_transform = *self
      .perspective_stack
      .last()
      .unwrap_or(&Transform3D::identity());
    let local_transform = node.context.transform.unwrap_or_else(Transform3D::identity);
    let combined_root = parent_transform.multiply(&local_transform);

    if matches!(node.context.backface_visibility, BackfaceVisibility::Hidden)
      && backface_is_hidden(&combined_root)
    {
      return Ok(end_idx);
    }

    let root_opacity = node.context.opacity.clamp(0.0, 1.0);
    let root_mix_blend_mode = node.context.mix_blend_mode;
    let root_manual_blend = is_manual_blend(root_mix_blend_mode).then_some(root_mix_blend_mode);

    // Preserve-3d scenes still respect stacking-context compositing/sampling boundaries:
    //
    // - `filter`/`backdrop-filter`/`mask`: preserve-3d roots bypass the normal stacking-context
    //   Push/Pop pipeline, so we must explicitly allocate the same group surface and apply the
    //   corresponding effects to the fully composited preserve-3d scene output.
    // - Backdrop Root scoping (Filter Effects Level 2): roots that establish a Backdrop Root (e.g.
    //   via `filter`, `backdrop-filter`, `mask`, `clip-path`, `opacity`, `mix-blend-mode`, or
    //   `will-change`) must scope descendant `backdrop-filter` sampling. For triggers that do not
    //   otherwise require a group surface (notably `clip-path` and `will-change`), we only force a
    //   canvas layer boundary when the subtree actually contains backdrop-sensitive effects.
    let root_filters = self.ds_filters(&node.context.filters);
    let root_backdrop_filters = self.ds_filters(&node.context.backdrop_filters);
    let root_has_backdrop = !root_backdrop_filters.is_empty();
    let root_mask_style = node.context.mask.clone();
    let root_radii = self.ds_radii(node.context.radii);
    let root_filter_bounds = {
      let candidate = node.context.plane_rect;
      if candidate.width() > 0.0
        && candidate.height() > 0.0
        && candidate.x().is_finite()
        && candidate.y().is_finite()
        && candidate.width().is_finite()
        && candidate.height().is_finite()
      {
        candidate
      } else {
        node.context.bounds
      }
    };

    // Match `PushStackingContext` Backdrop Root trigger detection.
    let root_is_backdrop_root = node.context.establishes_backdrop_root
      || !root_filters.is_empty()
      || root_has_backdrop
      || root_opacity < 1.0 - f32::EPSILON
      || root_mask_style.is_some()
      || node.context.has_clip_path
      || !matches!(root_mix_blend_mode, BlendMode::Normal);

    // `backdrop-filter` needs an isolated group surface so sampling excludes the element's own
    // contents.
    let root_isolated = node.context.is_isolated || root_has_backdrop;
    let root_needs_layer_for_effects =
      root_isolated || !root_filters.is_empty() || root_has_backdrop || root_mask_style.is_some();

    // Like `PushStackingContext`, only force a layer boundary for Backdrop Root triggers that don't
    // otherwise need a surface when a descendant would observe it (and never for the document
    // root, which is represented by the base canvas surface).
    let root_backdrop_root_layer = !node.context.is_root
      && root_is_backdrop_root
      && node.context.has_backdrop_sensitive_descendants;

    let needs_root_layer = root_needs_layer_for_effects
      || root_backdrop_root_layer
      || root_opacity < 1.0 - f32::EPSILON
      || !matches!(root_mix_blend_mode, BlendMode::Normal);

    // Non-isolated compositing groups need descendant blend operations to see the already-painted
    // backdrop. When we allocate an offscreen surface for a preserve-3d root (opacity /
    // mix-blend-mode), seed it from the parent surface only when the subtree actually contains
    // backdrop-sensitive effects, and only when the root is not acting as a backdrop-root
    // boundary for blending (mirrors `maybe_init_non_isolated_group_backdrop`).
    let init_from_backdrop = needs_root_layer
      && !root_isolated
      && node.context.has_backdrop_sensitive_descendants
      && !(root_is_backdrop_root && matches!(root_mix_blend_mode, BlendMode::Normal));
    let root_composite_blend = (!matches!(root_mix_blend_mode, BlendMode::Normal)
      && root_manual_blend.is_none())
    .then(|| map_blend_mode(root_mix_blend_mode));

    let mut order = 0;
    let mut backdrop_root_chain: Vec<usize> = Vec::new();
    let mut backdrop_root_counter = 0usize;
    let mut scene_items = collect_scene_items(
      &node,
      &parent_transform,
      true,
      &mut order,
      true,
      &[],
      &mut backdrop_root_chain,
      &mut backdrop_root_counter,
    );
    let before_backface_cull = scene_items.len();
    scene_items.retain(|item| {
      !matches!(item.backface_visibility, BackfaceVisibility::Hidden)
        || !backface_is_hidden(&item.transform)
    });
    if self.preserve_3d_debug {
      let culled = before_backface_cull.saturating_sub(scene_items.len());
      eprintln!(
        "preserve-3d context start={} end={} items={} culled_backfaces={} warp_enabled={}",
        start_index,
        end_idx,
        scene_items.len(),
        culled,
        self.projective_warp_enabled
      );
    }
    let sort_items: Vec<depth_sort::SceneItem> = scene_items
      .iter()
      .map(|item| depth_sort::SceneItem {
        transform: item.transform,
        plane_rect: item.plane_rect,
        paint_order: item.paint_order,
      })
      .collect();
    let paint_order = depth_sort::depth_sort_checked(&sort_items)?;

    let mut plane_pixmaps = self
      .should_rasterize_preserve_3d_planes_parallel(&scene_items)
      .then(|| {
        if self.preserve_3d_debug {
          eprintln!(
            "preserve-3d plane-parallel rasterization enabled planes={}",
            scene_items.len()
          );
        }
        self.rasterize_preserve_3d_planes_parallel(&scene_items, &paint_order)
      })
      .transpose()?;

    if needs_root_layer {
      if init_from_backdrop {
        self.push_layer_with_blend_initialized_from_backdrop_tracked(
          root_opacity,
          root_composite_blend,
          root_is_backdrop_root,
        )?;
      } else if root_composite_blend.is_some() {
        self.push_layer_with_blend_tracked(
          root_opacity,
          root_composite_blend,
          root_is_backdrop_root,
        )?;
      } else {
        self.push_layer_tracked(root_opacity, root_is_backdrop_root)?;
      }
      self.record_layer_allocation(self.canvas.width(), self.canvas.height());
    }

    // Preserve-3d scenes can contain intermediate Filter Effects Level 2 Backdrop Root boundaries
    // (e.g. `will-change`) that scope descendant `backdrop-filter` sampling without otherwise
    // requiring an offscreen compositing surface. We cannot represent these boundaries via the
    // canvas layer stack without breaking 3D ordering, so maintain per-boundary scratch buffers
    // that track the composited content *within* each nested backdrop root.
    //
    // These buffers are allocated on-demand for the subset of nested backdrop roots that are
    // actually sampled by a descendant `backdrop-filter`.
    let mut nested_backdrop_buffers: Vec<Option<Pixmap>> = vec![None; backdrop_root_counter];
    if backdrop_root_counter > 0 {
      let mut needs_buffer: Vec<bool> = vec![false; backdrop_root_counter];
      for item in &scene_items {
        if !item.backdrop_filters.is_empty() {
          if let Some(&id) = item.backdrop_root_chain.last() {
            if id < needs_buffer.len() {
              needs_buffer[id] = true;
            }
          }
        }
        // `mix-blend-mode` is also backdrop-sensitive: inside a preserve-3d scene compositor we
        // need a scratch buffer for the nearest intermediate Backdrop Root so blending does not
        // sample/composite against content above that boundary.
        if item
          .compositing
          .as_ref()
          .is_some_and(|compositing| !matches!(compositing.mix_blend_mode, BlendMode::Normal))
        {
          if let Some(&id) = item.backdrop_root_chain.last() {
            if id < needs_buffer.len() {
              needs_buffer[id] = true;
            }
          }
        }
      }

      if needs_buffer.iter().any(|needed| *needed) {
        let buffer_w = self.canvas.width();
        let buffer_h = self.canvas.height();
        for (id, needed) in needs_buffer.iter().enumerate() {
          if !*needed {
            continue;
          }
          if let Some(pixmap) = new_pixmap(buffer_w, buffer_h) {
            nested_backdrop_buffers[id] = Some(pixmap);
          }
        }
      }
    }

    // The preserve-3d scene compositor draws into the current pixmap directly (warps/composites
    // planes), so treat the destination surface as mutated for backdrop-cache invalidation.
    self.mark_current_pixmap_mutated();

    // Apply root-level backdrop filters (Filter Effects Level 2) before drawing planes so the
    // filtered backdrop becomes part of the preserve-3d scene output.
    if needs_root_layer && root_has_backdrop {
      let backdrop_result = (|| -> Result<()> {
        let Some(bounds_in_src) = self.preserve_3d_rect_device_bounds(
          root_filter_bounds,
          &combined_root,
          self.canvas.transform(),
        ) else {
          return Ok(());
        };

        let layer_origin = self
          .canvas
          .layer_stack()
          .last()
          .map(|record| record.origin)
          .unwrap_or((0, 0));
        let shape_bounds = Rect::from_xywh(
          bounds_in_src.x() - layer_origin.0 as f32,
          bounds_in_src.y() - layer_origin.1 as f32,
          bounds_in_src.width(),
          bounds_in_src.height(),
        );

        let clip_bounds = self.canvas.clip_bounds();
        let clip_mask_rc = self.canvas.clip_mask_rc();
        let clip_mask = clip_mask_rc.as_deref();

        let (layer_stack, dest_pixmap) = self.canvas.split_layer_stack_and_pixmap_mut();
        let Some(parent_surface) = layer_stack.last().map(|record| &record.pixmap) else {
          // Without an active layer, there's nowhere to write the filtered backdrop.
          return Ok(());
        };
        if self.trace_backdrop_stack {
          let (root_depth, parent_depth) = backdrop_root_range(layer_stack);
          eprintln!(
            "backdrop_stack apply_backdrop_filter preserve3d_root range={}..{} composite_allocated={} cache_hit={} composite_steps={}",
            root_depth,
            parent_depth,
            false,
            false,
            parent_depth.saturating_sub(root_depth)
          );
        }
        let scale = self.scale;
        let blur_cache: &mut (dyn BlurCacheOps + 'static) = match self.shared_blur_cache.as_mut() {
          Some(shared) => shared,
          None => &mut self.blur_cache,
        };
        let backdrop_cache: &mut (dyn BackdropFilterCacheOps + 'static) =
          match self.shared_backdrop_filter_cache.as_mut() {
            Some(shared) => shared,
            None => &mut self.backdrop_filter_cache,
          };

        apply_backdrop_filters_with_region_filler(
          dest_pixmap,
          (parent_surface.width(), parent_surface.height()),
          layer_origin,
          bounds_in_src,
          shape_bounds,
          &root_backdrop_filters,
          root_radii,
          scale,
          clip_mask,
          clip_bounds,
          (0, 0),
          root_filter_bounds,
          Transform::identity(),
          Some(blur_cache),
          Some(backdrop_cache),
          |region, clamped_x, clamped_y| {
            Canvas::fill_backdrop_root_region(
              layer_stack,
              region,
              (clamped_x as i32, clamped_y as i32),
            )
          },
          None,
          None,
        )?;
        self.mark_current_pixmap_mutated();
        Ok(())
      })();

      // If backdrop-filter initialization fails, still pop the root layer to restore the canvas
      // state before returning.
      if backdrop_result.is_err() {
        let _ = self.pop_layer_raw_tracked();
      }
      backdrop_result?;
    }

    let paint_result = (|| -> Result<()> {
      let mut deadline_counter = 0usize;
      for idx in paint_order {
        check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
          .map_err(Error::Render)?;
        let scene_item = &scene_items[idx];
        let nested_backdrop_needs_update = !nested_backdrop_buffers.is_empty()
          && scene_item.backdrop_root_chain.iter().any(|id| {
            nested_backdrop_buffers
              .get(*id)
              .is_some_and(|buf| buf.is_some())
          });
        let sampling_backdrop_root = scene_item.backdrop_root_chain.last().copied();
        let scene_result = (|| -> Result<()> {
          let has_backdrop = !scene_item.backdrop_filters.is_empty();
          let parent_transform = self.canvas.transform();
          let parent_bounds = self.canvas.bounds();
          let parent_clip_bounds = self.canvas.clip_bounds();
          let adjusted_transform = scene_item.transform.multiply(&Transform3D::translate(
            scene_item.bounds.x(),
            scene_item.bounds.y(),
            0.0,
          ));

          let backdrop_bounds = if has_backdrop {
            let local_bounds = Rect::from_xywh(
              scene_item.filter_bounds.x() - scene_item.bounds.x(),
              scene_item.filter_bounds.y() - scene_item.bounds.y(),
              scene_item.filter_bounds.width(),
              scene_item.filter_bounds.height(),
            );
            self.preserve_3d_rect_device_bounds(local_bounds, &adjusted_transform, parent_transform)
          } else {
            None
          };

          let should_apply_backdrop = has_backdrop && backdrop_bounds.is_some();

          // Match the normal stacking-context backdrop-filter pipeline: paint into an isolated
          // layer, populate it with the filtered backdrop from the already-composited scene, then
          // warp/draw the plane content over it.
          let (layer_bounds, layer_origin) = if should_apply_backdrop {
            let Some(bounds) = backdrop_bounds.as_ref() else {
              return Ok(());
            };
            let (out_l, out_t, out_r, out_b) = filter_outset_with_bounds(
              &scene_item.backdrop_filters,
              self.scale,
              Some(scene_item.filter_bounds),
            )
            .as_tuple();
            let mut layer_bounds = Rect::from_xywh(
              bounds.x() - out_l,
              bounds.y() - out_t,
              bounds.width() + out_l + out_r,
              bounds.height() + out_t + out_b,
            );

            if let Some(clip) = parent_clip_bounds {
              layer_bounds = match layer_bounds.intersection(clip) {
                Some(r) => r,
                None => return Ok(()),
              };
            }

            layer_bounds = match layer_bounds.intersection(parent_bounds) {
              Some(r) => r,
              None => return Ok(()),
            };

            if layer_bounds.width() <= 0.0
              || layer_bounds.height() <= 0.0
              || !layer_bounds.x().is_finite()
              || !layer_bounds.y().is_finite()
            {
              (None, (0, 0))
            } else {
              let origin = (
                layer_bounds.min_x().floor() as i32,
                layer_bounds.min_y().floor() as i32,
              );
              (Some(layer_bounds), origin)
            }
          } else {
            (None, (0, 0))
          };

          let pushed_layer = if should_apply_backdrop {
            if let Some(bounds) = layer_bounds {
              self.push_layer_bounded_tracked(1.0, None, bounds, true)?;
            } else {
              self.push_layer_tracked(1.0, true)?;
            }
            self.record_layer_allocation(self.canvas.width(), self.canvas.height());
            true
          } else {
            false
          };

          let draw_result =
            self.with_preserve_3d_clip_override(&scene_item.effects, |renderer, clip_override| {
              let mut drawable = renderer.canvas.bounds();
              if let Some(clip) = renderer.canvas.clip_bounds() {
                drawable = match drawable.intersection(clip) {
                  Some(r) => r,
                  None => return Ok(()),
                };
              }
              if drawable.width() <= 0.0 || drawable.height() <= 0.0 {
                return Ok(());
              }

              let plane_offscreen = renderer
                .preserve_3d_plane_device_bounds(scene_item.bounds, &adjusted_transform)
                .is_some_and(|bounds| bounds.intersection(drawable).is_none());
              if plane_offscreen && !should_apply_backdrop {
                return Ok(());
              }

              if should_apply_backdrop {
                let Some(bounds_in_src) = backdrop_bounds else {
                  return Ok(());
                };

                let clip_bounds = renderer.canvas.clip_bounds();
                let clip_mask_rc = clip_override
                  .is_none()
                  .then(|| renderer.canvas.clip_mask_rc())
                  .flatten();
                let clip_mask = clip_override.or_else(|| clip_mask_rc.as_deref());
                let scale = renderer.scale;
                let radii = renderer.ds_radii(scene_item.radii);
                let shape_bounds = Rect::from_xywh(
                  bounds_in_src.x() - layer_origin.0 as f32,
                  bounds_in_src.y() - layer_origin.1 as f32,
                  bounds_in_src.width(),
                  bounds_in_src.height(),
                );
                let projected_quad_path = (renderer.projective_warp_enabled
                  && !Homography::from_transform3d_z0(&adjusted_transform).is_affine())
                .then(|| {
                  let local_bounds = Rect::from_xywh(
                    scene_item.filter_bounds.x() - scene_item.bounds.x(),
                    scene_item.filter_bounds.y() - scene_item.bounds.y(),
                    scene_item.filter_bounds.width(),
                    scene_item.filter_bounds.height(),
                  );
                  if local_bounds.width() <= 0.0
                    || local_bounds.height() <= 0.0
                    || !local_bounds.x().is_finite()
                    || !local_bounds.y().is_finite()
                    || !local_bounds.width().is_finite()
                    || !local_bounds.height().is_finite()
                  {
                    return None;
                  }

                  let corners = [
                    (local_bounds.min_x(), local_bounds.min_y()),
                    (local_bounds.max_x(), local_bounds.min_y()),
                    (local_bounds.max_x(), local_bounds.max_y()),
                    (local_bounds.min_x(), local_bounds.max_y()),
                  ];
                  let mut builder = PathBuilder::new();
                  for (idx, (x, y)) in corners.iter().enumerate() {
                    let (tx, ty, _tz, tw) = adjusted_transform.transform_point(*x, *y, 0.0);
                    if !tw.is_finite()
                      || tw.abs() < Transform3D::MIN_PROJECTIVE_W
                      || tw < 0.0
                      || !tx.is_finite()
                      || !ty.is_finite()
                    {
                      return None;
                    }
                    let px = (tx / tw) * scale;
                    let py = (ty / tw) * scale;
                    let dst_x = px * parent_transform.sx
                      + py * parent_transform.kx
                      + parent_transform.tx
                      - layer_origin.0 as f32;
                    let dst_y = px * parent_transform.ky
                      + py * parent_transform.sy
                      + parent_transform.ty
                      - layer_origin.1 as f32;
                    if !dst_x.is_finite() || !dst_y.is_finite() {
                      return None;
                    }
                    if idx == 0 {
                      builder.move_to(dst_x, dst_y);
                    } else {
                      builder.line_to(dst_x, dst_y);
                    }
                  }
                  builder.close();
                  builder.finish()
                })
                .flatten();

                let (layer_stack, dest_pixmap) = renderer.canvas.split_layer_stack_and_pixmap_mut();
                let Some(parent_surface) = layer_stack.last().map(|record| &record.pixmap) else {
                  // Without an active layer, there's nowhere to write the filtered backdrop.
                  return Ok(());
                };
                if renderer.trace_backdrop_stack {
                  let (root_depth, parent_depth) = backdrop_root_range(layer_stack);
                  eprintln!(
                    "backdrop_stack apply_backdrop_filter preserve3d range={}..{} composite_allocated={} cache_hit={} composite_steps={}",
                    root_depth,
                    parent_depth,
                    false,
                    false,
                    parent_depth.saturating_sub(root_depth)
                  );
                }
                let blur_cache: &mut (dyn BlurCacheOps + 'static) =
                  match renderer.shared_blur_cache.as_mut() {
                    Some(shared) => shared,
                    None => &mut renderer.blur_cache,
                  };
                let backdrop_cache: &mut (dyn BackdropFilterCacheOps + 'static) =
                  match renderer.shared_backdrop_filter_cache.as_mut() {
                    Some(shared) => shared,
                    None => &mut renderer.backdrop_filter_cache,
                  };
                let nested_backdrop = sampling_backdrop_root
                  .and_then(|id| nested_backdrop_buffers.get(id))
                  .and_then(|buf| buf.as_ref());
                apply_backdrop_filters_with_region_filler(
                  dest_pixmap,
                  (parent_surface.width(), parent_surface.height()),
                  layer_origin,
                  bounds_in_src,
                  shape_bounds,
                  &scene_item.backdrop_filters,
                  radii,
                  scale,
                  clip_mask,
                  clip_bounds,
                  (0, 0),
                  scene_item.filter_bounds,
                  Transform::identity(),
                  Some(blur_cache),
                  Some(backdrop_cache),
                  |region, clamped_x, clamped_y| {
                    if let Some(backdrop) = nested_backdrop {
                      copy_pixmap_region_with_offset(
                        region,
                        backdrop.as_ref(),
                        clamped_x as i32,
                        clamped_y as i32,
                      )
                    } else {
                      Canvas::fill_backdrop_root_region(
                        layer_stack,
                        region,
                        (clamped_x as i32, clamped_y as i32),
                      )
                    }
                  },
                  None,
                  projected_quad_path.as_ref(),
                )?;
              }

              if plane_offscreen {
                return Ok(());
              }

              let pixmap = if let Some(pixmaps) = plane_pixmaps.as_mut() {
                pixmaps[idx].take()
              } else {
                renderer.render_scene_item(scene_item)?
              };

              if let Some(pixmap) = pixmap {
                if renderer.preserve_3d_debug {
                  let is_affine = Homography::from_transform3d_z0(&adjusted_transform).is_affine();
                  let depth = {
                    let center = scene_item.plane_rect.center();
                    let (_tx, _ty, tz, tw) = scene_item
                      .transform
                      .transform_point(center.x, center.y, 0.0);
                    if tz.is_finite()
                      && tw.is_finite()
                      && tw.abs() >= Transform3D::MIN_PROJECTIVE_W
                    {
                      tz / tw
                    } else {
                      f32::NAN
                    }
                  };
                  eprintln!(
                    "preserve-3d item order={} depth={depth:.4} affine={is_affine} bounds=({}, {}, {}, {})",
                    scene_item.paint_order,
                    scene_item.bounds.x(),
                    scene_item.bounds.y(),
                    scene_item.bounds.width(),
                    scene_item.bounds.height(),
                  );
                }
                let blend = scene_item.compositing.as_ref().and_then(|compositing| {
                  (!matches!(compositing.mix_blend_mode, BlendMode::Normal))
                    .then_some(compositing.mix_blend_mode)
                });
                let mut painted = false;
                if nested_backdrop_needs_update && !pushed_layer {
                  if let Some(warped) = renderer.warp_pixmap_for_manual_blend(
                    &pixmap,
                    &adjusted_transform,
                    clip_override,
                  )? {
                    painted = true;
                    if let Some(mode) = blend {
                      // `mix-blend-mode` backdrops are scoped by Filter Effects Level 2 Backdrop
                      // Roots. When inside an intermediate backdrop-root chain, blend operations
                      // must see the corresponding nested backdrop buffer rather than the global
                      // canvas (which already includes pixels above the boundary).
                      let mut scoped = false;
                      if let Some(scope_id) = sampling_backdrop_root {
                        let w = warped.pixmap().width();
                        let h = warped.pixmap().height();
                        if let (Some(mut backdrop_region), Some(mut blended_region)) =
                          (new_pixmap(w, h), new_pixmap(w, h))
                        {
                          let copied_backdrop = {
                            if let Some(scope_buffer) =
                              nested_backdrop_buffers.get(scope_id).and_then(|buf| buf.as_ref())
                            {
                              copy_pixmap_region_with_offset(
                                &mut backdrop_region,
                                scope_buffer.as_ref(),
                                warped.offset().0,
                                warped.offset().1,
                              )?;
                              true
                            } else {
                              false
                            }
                          };

                          if copied_backdrop {
                            blended_region
                              .data_mut()
                              .copy_from_slice(backdrop_region.data());

                            if is_manual_blend(mode) {
                              composite_manual_layer_pixmap(
                                &mut blended_region,
                                warped.pixmap(),
                                1.0,
                                mode,
                                (0, 0),
                                None,
                              )?;
                            } else {
                              composite_layer_into_pixmap(
                                &mut blended_region,
                                warped.pixmap(),
                                1.0,
                                map_blend_mode(mode),
                                (0, 0),
                                None,
                              );
                            }

                            // Convert the blended output into an isolated source image so we can
                            // composite it with normal source-over onto the global canvas and all
                            // nested backdrop buffers without re-blending against the wrong
                            // backdrops.
                            crate::paint::canvas::uncomposite_layer_source_over_backdrop(
                              &mut blended_region,
                              backdrop_region.as_ref(),
                              (0, 0),
                              Some((warped.pixmap(), (0, 0))),
                            )?;

                            renderer.canvas.with_mirrored_pixmap_mut(|dest| {
                              composite_layer_into_pixmap_mut(
                                dest,
                                &blended_region,
                                1.0,
                                SkiaBlendMode::SourceOver,
                                warped.offset(),
                                None,
                              );
                            });
                            renderer.mark_current_pixmap_mutated();
                            for &root_id in &scene_item.backdrop_root_chain {
                              if let Some(buffer) = nested_backdrop_buffers
                                .get_mut(root_id)
                                .and_then(|buf| buf.as_mut())
                              {
                                composite_layer_into_pixmap(
                                  buffer,
                                  &blended_region,
                                  1.0,
                                  SkiaBlendMode::SourceOver,
                                  warped.offset(),
                                  None,
                                );
                              }
                            }
                            scoped = true;
                          }
                        }
                      }

                      if !scoped {
                        // Fall back to the unscoped blend logic (matches the previous behavior).
                        if is_manual_blend(mode) {
                          renderer.composite_manual_layer(
                            warped.pixmap(),
                            1.0,
                            mode,
                            warped.offset(),
                            None,
                          )?;
                          for &root_id in &scene_item.backdrop_root_chain {
                            if let Some(buffer) = nested_backdrop_buffers
                              .get_mut(root_id)
                              .and_then(|buf| buf.as_mut())
                            {
                              composite_manual_layer_pixmap(
                                buffer,
                                warped.pixmap(),
                                1.0,
                                mode,
                                warped.offset(),
                                None,
                              )?;
                            }
                          }
                        } else {
                          let blend_mode = map_blend_mode(mode);
                          renderer.canvas.with_mirrored_pixmap_mut(|dest| {
                            composite_layer_into_pixmap_mut(
                              dest,
                              warped.pixmap(),
                              1.0,
                              blend_mode,
                              warped.offset(),
                              None,
                            );
                          });
                          renderer.mark_current_pixmap_mutated();
                          for &root_id in &scene_item.backdrop_root_chain {
                            if let Some(buffer) = nested_backdrop_buffers
                              .get_mut(root_id)
                              .and_then(|buf| buf.as_mut())
                            {
                              composite_layer_into_pixmap(
                                buffer,
                                warped.pixmap(),
                                1.0,
                                blend_mode,
                                warped.offset(),
                                None,
                              );
                            }
                          }
                        }
                      }
                    } else {
                      let blend_mode = renderer.canvas.blend_mode();
                      renderer.canvas.with_mirrored_pixmap_mut(|dest| {
                        composite_layer_into_pixmap_mut(
                          dest,
                          warped.pixmap(),
                          1.0,
                          blend_mode,
                          warped.offset(),
                          None,
                        );
                      });
                      renderer.mark_current_pixmap_mutated();
                      for &root_id in &scene_item.backdrop_root_chain {
                        if let Some(buffer) = nested_backdrop_buffers
                          .get_mut(root_id)
                          .and_then(|buf| buf.as_mut())
                        {
                          composite_layer_into_pixmap(
                            buffer,
                            warped.pixmap(),
                            1.0,
                            blend_mode,
                            warped.offset(),
                            None,
                          );
                        }
                      }
                    }
                  }
                }

                if !painted {
                  if let Some(mode) = blend {
                    if is_manual_blend(mode) {
                      if let Some(warped) = renderer.warp_pixmap_for_manual_blend(
                        &pixmap,
                        &adjusted_transform,
                        clip_override,
                      )? {
                        renderer.composite_manual_layer(
                          warped.pixmap(),
                          1.0,
                          mode,
                          warped.offset(),
                          None,
                        )?;
                      }
                    } else {
                      renderer.warp_pixmap(
                        &pixmap,
                        &adjusted_transform,
                        clip_override,
                        map_blend_mode(mode),
                      )?;
                    }
                  } else {
                    renderer.warp_pixmap(
                      &pixmap,
                      &adjusted_transform,
                      clip_override,
                      renderer.canvas.blend_mode(),
                    )?;
                  }
                }
              }
              Ok(())
            });

          if pushed_layer {
            // If drawing failed, still pop the layer to restore the canvas state before returning.
            if draw_result.is_err() {
              let _ = self.pop_layer_raw_tracked();
            } else if nested_backdrop_needs_update {
              let (layer, origin, opacity, composite_blend) = self.pop_layer_raw_tracked()?;
              let blend_mode = composite_blend.unwrap_or(self.canvas.blend_mode());
              let clip = self.canvas.clip_mask();
              for &root_id in &scene_item.backdrop_root_chain {
                if let Some(buffer) = nested_backdrop_buffers
                  .get_mut(root_id)
                  .and_then(|buf| buf.as_mut())
                {
                  composite_layer_into_pixmap(buffer, &layer, opacity, blend_mode, origin, clip);
                }
              }
              self.composite_layer_tracked(&layer, opacity, composite_blend, origin);
            } else {
              self.pop_layer_tracked()?;
            }
          }
          draw_result?;
          Ok(())
        })();
        scene_result?;
      }

      Ok(())
    })();

    if needs_root_layer {
      if paint_result.is_err() {
        let _ = self.pop_layer_raw_tracked();
      } else if let Some(mode) = root_manual_blend {
        let (layer, origin, opacity, _blend) = self.pop_layer_raw_tracked()?;
        self.composite_manual_layer(&layer, opacity, mode, origin, None)?;
      } else {
        let (mut layer, origin, opacity, composite_blend) = self.pop_layer_raw_tracked()?;

        // Root `mask` is applied to the composed preserve-3d scene output, matching the
        // stacking-context pop pipeline.
        if let Some(mask_style) = root_mask_style.as_ref() {
          if let Some(mask) = self.render_mask(mask_style)? {
            let OffsetMask {
              mask,
              origin: mask_origin,
            } = mask;
            let applied = apply_mask_with_offset(&mut layer, origin, &mask, mask_origin)?;
            if mask.width() > 1 || mask.height() > 1 {
              MASK_RENDER_SCRATCH.with(|cell| {
                *cell.borrow_mut() = Some(mask);
              });
            }
            if !applied {
              paint_result?;
              return Ok(end_idx);
            }
          }
        }

        // Root `filter` applies to the entire preserve-3d scene output (post-warp composition).
        if !root_filters.is_empty() {
          let bounds = self.preserve_3d_rect_device_bounds(
            node.context.bounds,
            &combined_root,
            self.canvas.transform(),
          );
          let (out_l, out_t, out_r, out_b) =
            filter_outset_with_bounds(&root_filters, self.scale, Some(node.context.bounds))
              .as_tuple();
          let effect_bounds = bounds.map(|bounds| {
            Rect::from_xywh(
              bounds.x() - out_l,
              bounds.y() - out_t,
              bounds.width() + out_l + out_r,
              bounds.height() + out_t + out_b,
            )
          });
          let layer_region =
            effect_bounds.and_then(|rect| self.layer_space_bounds(rect, origin, &layer));
          let bbox = bounds
            .map(|bounds| {
              Rect::from_xywh(
                bounds.x() - origin.0 as f32,
                bounds.y() - origin.1 as f32,
                bounds.width(),
                bounds.height(),
              )
            })
            .unwrap_or_else(|| {
              Rect::from_xywh(0.0, 0.0, layer.width() as f32, layer.height() as f32)
            });

          let scale = self.scale;
          let needs_svg_background = root_filters.iter().any(|filter| match filter {
            ResolvedFilter::SvgFilter(filter) => filter.uses_background_inputs(),
            _ => false,
          });
          let backdrop = needs_svg_background.then(|| self.canvas.pixmap_ref());
          let blur_cache: &mut (dyn BlurCacheOps + 'static) = match self.shared_blur_cache.as_mut()
          {
            Some(shared) => shared,
            None => &mut self.blur_cache,
          };
          apply_filters_scoped(
            &mut layer,
            &root_filters,
            scale,
            bbox,
            layer_region.as_ref(),
            Some(blur_cache),
            backdrop,
            origin,
          )?;

          // Clamp the filtered output to the filter region (expanded by `filter_outset_with_bounds`)
          // to match the normal stacking-context behavior.
          if let Some(bounds) = bounds {
            let clip_rect = Rect::from_xywh(
              bounds.x() - out_l,
              bounds.y() - out_t,
              bounds.width() + out_l + out_r,
              bounds.height() + out_t + out_b,
            );
            if let Some(local_clip) = self.layer_space_bounds(clip_rect, origin, &layer) {
              apply_clip_mask_rect(
                &mut layer,
                local_clip,
                root_radii,
                self.clip_mask_diagnostics.as_ref(),
              )?;
            }
          }
        }

        self.composite_layer_tracked(&layer, opacity, composite_blend, origin);
      }
    }

    paint_result?;
    Ok(end_idx)
  }

  fn render_scene_item(&mut self, item: &Preserve3dSceneItem) -> Result<Option<Pixmap>> {
    #[cfg(test)]
    RENDER_SCENE_ITEM_INVOCATIONS.with(|count| count.set(count.get().saturating_add(1)));
    let raster_config = self.preserve_3d_scene_raster_config();
    let (pixmap, stats) = raster_config.rasterize(item)?;
    self.gradient_stats.merge(&stats);
    Ok(pixmap)
  }

  fn preserve_3d_plane_device_bounds(&self, bounds: Rect, transform: &Transform3D) -> Option<Rect> {
    if bounds.width() <= 0.0
      || bounds.height() <= 0.0
      || !bounds.width().is_finite()
      || !bounds.height().is_finite()
    {
      return None;
    }

    let src_w_px = (bounds.width() * self.scale).ceil().max(1.0) as u32;
    let src_h_px = (bounds.height() * self.scale).ceil().max(1.0) as u32;
    if src_w_px == 0 || src_h_px == 0 {
      return None;
    }
    let src_w = src_w_px as f32;
    let src_h = src_h_px as f32;
    let parent_transform = self.canvas.transform();

    let homography = Homography::from_transform3d_z0(transform);
    let warp_enabled = self.projective_warp_enabled;
    if homography.is_affine() || !warp_enabled {
      let (t, _valid) = self.to_skia_transform_checked(transform);
      let skia_transform = concat_transforms(parent_transform, t);
      let rect = transform_rect(Rect::from_xywh(0.0, 0.0, src_w, src_h), &skia_transform);
      if rect.x().is_finite()
        && rect.y().is_finite()
        && rect.width().is_finite()
        && rect.height().is_finite()
      {
        return Some(rect);
      }
      return None;
    }

    let css_w = src_w / self.scale;
    let css_h = src_h / self.scale;
    if !css_w.is_finite() || !css_h.is_finite() {
      return None;
    }

    let corners = [(0.0, 0.0), (css_w, 0.0), (css_w, css_h), (0.0, css_h)];

    let mut min_x = f32::INFINITY;
    let mut min_y = f32::INFINITY;
    let mut max_x = f32::NEG_INFINITY;
    let mut max_y = f32::NEG_INFINITY;

    for (x, y) in corners {
      let projected = transform.project_point_2d(x, y)?;
      let px = projected.x * self.scale;
      let py = projected.y * self.scale;
      let dst_x = px * parent_transform.sx + py * parent_transform.kx + parent_transform.tx;
      let dst_y = px * parent_transform.ky + py * parent_transform.sy + parent_transform.ty;
      if !dst_x.is_finite() || !dst_y.is_finite() {
        return None;
      }
      min_x = min_x.min(dst_x);
      min_y = min_y.min(dst_y);
      max_x = max_x.max(dst_x);
      max_y = max_y.max(dst_y);
    }

    if !min_x.is_finite() || !min_y.is_finite() || !max_x.is_finite() || !max_y.is_finite() {
      return None;
    }

    Some(Rect::from_xywh(min_x, min_y, max_x - min_x, max_y - min_y))
  }

  fn preserve_3d_rect_device_bounds(
    &self,
    rect: Rect,
    transform: &Transform3D,
    parent_transform: Transform,
  ) -> Option<Rect> {
    if rect.width() <= 0.0 || rect.height() <= 0.0 {
      return None;
    }
    if !rect.x().is_finite()
      || !rect.y().is_finite()
      || !rect.width().is_finite()
      || !rect.height().is_finite()
    {
      return None;
    }

    let homography = Homography::from_transform3d_z0(transform);
    let warp_enabled = self.projective_warp_enabled;

    let affine_bounds = || {
      let (t, _valid) = self.to_skia_transform_checked(transform);
      let skia_transform = concat_transforms(parent_transform, t);
      transform_rect(self.ds_rect(rect), &skia_transform)
    };

    if homography.is_affine() || !warp_enabled {
      return Some(affine_bounds());
    }

    let corners = [
      (rect.min_x(), rect.min_y()),
      (rect.max_x(), rect.min_y()),
      (rect.max_x(), rect.max_y()),
      (rect.min_x(), rect.max_y()),
    ];

    let mut min_x = f32::INFINITY;
    let mut min_y = f32::INFINITY;
    let mut max_x = f32::NEG_INFINITY;
    let mut max_y = f32::NEG_INFINITY;

    for (x, y) in corners {
      let (tx, ty, _tz, tw) = transform.transform_point(x, y, 0.0);
      if !tw.is_finite() || tw.abs() < Transform3D::MIN_PROJECTIVE_W || tw < 0.0 {
        return Some(affine_bounds());
      }
      let px = (tx / tw) * self.scale;
      let py = (ty / tw) * self.scale;
      let dst_x = px * parent_transform.sx + py * parent_transform.kx + parent_transform.tx;
      let dst_y = px * parent_transform.ky + py * parent_transform.sy + parent_transform.ty;
      if !dst_x.is_finite() || !dst_y.is_finite() {
        return Some(affine_bounds());
      }
      min_x = min_x.min(dst_x);
      min_y = min_y.min(dst_y);
      max_x = max_x.max(dst_x);
      max_y = max_y.max(dst_y);
    }

    if !min_x.is_finite() || !min_y.is_finite() || !max_x.is_finite() || !max_y.is_finite() {
      return Some(affine_bounds());
    }

    let bounds = Rect::from_xywh(min_x, min_y, max_x - min_x, max_y - min_y);
    if bounds.width() <= 0.0 || bounds.height() <= 0.0 {
      return Some(affine_bounds());
    }
    Some(bounds)
  }

  fn with_preserve_3d_clip_override<T, F>(&mut self, effects: &[SceneEffect], f: F) -> Result<T>
  where
    F: FnOnce(&mut Self, Option<&Mask>) -> Result<T>,
  {
    if !effects
      .iter()
      .any(|effect| matches!(effect, SceneEffect::Clip { .. }))
    {
      return f(self, None);
    }

    let canvas_w = self.canvas.width();
    let canvas_h = self.canvas.height();
    let parent_transform = self.canvas.transform();
    let warp_enabled = self.projective_warp_enabled;

    let mut f = Some(f);
    let result = with_preserve_3d_clip_mask_scratch(|scratch| -> Result<Option<T>> {
      let resize = |slot: &mut Option<Mask>| {
        let replace = slot
          .as_ref()
          .map(|mask| mask.width() != canvas_w || mask.height() != canvas_h)
          .unwrap_or(true);
        if replace {
          *slot = Mask::new(canvas_w, canvas_h);
        }
      };
      resize(&mut scratch.combined);
      resize(&mut scratch.temp);

      let (combined_slot, temp_slot) = (&mut scratch.combined, &mut scratch.temp);
      let Some(combined) = combined_slot.as_mut() else {
        return Ok(None);
      };
      let Some(temp) = temp_slot.as_mut() else {
        return Ok(None);
      };

      if let Some(base) = self.canvas.clip_mask() {
        if base.width() != canvas_w || base.height() != canvas_h {
          return Ok(None);
        }
        combined.data_mut().copy_from_slice(base.data());
      } else {
        combined.data_mut().fill(255);
      }

      for effect in effects {
        let SceneEffect::Clip { clip, transform } = effect else {
          continue;
        };
        temp.data_mut().fill(0);
        let filled = self
          .fill_projected_preserve_3d_clip_mask(
            temp,
            clip,
            transform,
            parent_transform,
            warp_enabled,
          )
          .map_err(Error::Render)?;
        if !filled {
          if self.preserve_3d_debug {
            eprintln!(
              "preserve-3d clip override: falling back (unsupported clip shape or invalid projection)"
            );
          }
          return Ok(None);
        }
        multiply_masks_in_place(combined, temp).map_err(Error::Render)?;
      }

      let f = f.take().expect("callback should only run once");
      f(self, Some(combined)).map(Some)
    })?;

    if let Some(result) = result {
      if self.preserve_3d_debug {
        eprintln!("preserve-3d clip override: using projected clip mask");
      }
      return Ok(result);
    }

    // Fall back to affine canvas clipping when we can't build a projected clip mask (unsupported
    // shapes, degenerate projections, etc.).
    let f = f.take().expect("callback should only run once");
    let mut pushed_clips = 0usize;
    for effect in effects {
      if let SceneEffect::Clip { clip, .. } = effect {
        self.push_clip(clip)?;
        pushed_clips += 1;
      }
    }
    let result = f(self, None);
    for _ in 0..pushed_clips {
      self.pop_clip();
    }
    result
  }

  fn fill_projected_preserve_3d_clip_mask(
    &self,
    dest: &mut Mask,
    clip: &ClipItem,
    transform: &Transform3D,
    parent_transform: Transform,
    warp_enabled: bool,
  ) -> RenderResult<bool> {
    match &clip.shape {
      ClipShape::Rect { .. } => {
        let Some(path) = self.projected_preserve_3d_clip_rect_path(
          clip,
          transform,
          parent_transform,
          warp_enabled,
        ) else {
          return Ok(false);
        };
        dest.fill_path(
          &path,
          tiny_skia::FillRule::Winding,
          true,
          Transform::identity(),
        );
        Ok(true)
      }
      ClipShape::Path { path } => {
        let homography = Homography::from_transform3d_z0(transform);
        if warp_enabled && !homography.is_affine() {
          self.fill_projective_preserve_3d_clip_path_mask(dest, path, transform, parent_transform)
        } else {
          let Some((shape_path, fill_rule)) = build_clip_path_shape_path(path) else {
            return Ok(false);
          };
          let (t, _valid) = self.to_skia_transform_checked(transform);
          let transform = concat_transforms(
            parent_transform,
            concat_transforms(t, Transform::from_scale(self.scale, self.scale)),
          );
          dest.fill_path(&shape_path, fill_rule, true, transform);
          Ok(true)
        }
      }
      ClipShape::Text { runs } => self.fill_projected_preserve_3d_text_clip_mask(
        dest,
        runs,
        transform,
        parent_transform,
        warp_enabled,
      ),
      ClipShape::AlphaMask { image, rect } => self.fill_projected_preserve_3d_alpha_mask_clip_mask(
        dest,
        image.as_ref(),
        *rect,
        transform,
        parent_transform,
        warp_enabled,
      ),
    }
  }

  fn fill_projected_preserve_3d_alpha_mask_clip_mask(
    &self,
    dest: &mut Mask,
    image: &ImageData,
    rect: Rect,
    transform: &Transform3D,
    parent_transform: Transform,
    warp_enabled: bool,
  ) -> RenderResult<bool> {
    // Keep alpha-mask rasterization away from the source pixmap boundaries to avoid unstable edge
    // coverage when the mask is later warped/clipped (similar to `Canvas::set_clip_path`).
    const ALPHA_MASK_PADDING_PX: u32 = 32;

    if rect.width() <= 0.0
      || rect.height() <= 0.0
      || !rect.x().is_finite()
      || !rect.y().is_finite()
      || !rect.width().is_finite()
      || !rect.height().is_finite()
    {
      return Ok(false);
    }
    if !self.scale.is_finite() || self.scale <= 0.0 {
      return Ok(false);
    }

    let Some(image_pixmap) = image_data_to_pixmap_inner(image)? else {
      return Ok(false);
    };
    if image_pixmap.width() == 0 || image_pixmap.height() == 0 {
      return Ok(false);
    }

    // Rasterize the alpha mask into an offscreen alpha surface in the clip's plane coordinates.
    let pad = ALPHA_MASK_PADDING_PX as i32;
    let min_x = (rect.min_x() * self.scale).floor();
    let min_y = (rect.min_y() * self.scale).floor();
    let max_x = (rect.max_x() * self.scale).ceil();
    let max_y = (rect.max_y() * self.scale).ceil();
    if !min_x.is_finite() || !min_y.is_finite() || !max_x.is_finite() || !max_y.is_finite() {
      return Ok(false);
    }

    let origin_x = (min_x as i32).saturating_sub(pad);
    let origin_y = (min_y as i32).saturating_sub(pad);
    let end_x = (max_x as i32).saturating_add(pad);
    let end_y = (max_y as i32).saturating_add(pad);
    let width = end_x.saturating_sub(origin_x) as u32;
    let height = end_y.saturating_sub(origin_y) as u32;
    if width == 0 || height == 0 {
      return Ok(false);
    }

    let Some(mut src_pixmap) = new_pixmap(width, height) else {
      return Ok(false);
    };
    src_pixmap.data_mut().fill(0);

    let scale_x = rect.width() * self.scale / image_pixmap.width() as f32;
    let scale_y = rect.height() * self.scale / image_pixmap.height() as f32;
    if !scale_x.is_finite() || !scale_y.is_finite() || scale_x <= 0.0 || scale_y <= 0.0 {
      return Ok(false);
    }

    let tx = rect.x() * self.scale - origin_x as f32;
    let ty = rect.y() * self.scale - origin_y as f32;
    if !tx.is_finite() || !ty.is_finite() {
      return Ok(false);
    }

    let local_transform = Transform::from_row(scale_x, 0.0, 0.0, scale_y, tx, ty);
    let paint = PixmapPaint {
      opacity: 1.0,
      blend_mode: SkiaBlendMode::SourceOver,
      quality: FilterQuality::Bilinear,
    };
    src_pixmap.draw_pixmap(0, 0, image_pixmap.as_ref(), &paint, local_transform, None);

    // Projectively warp the alpha surface into canvas space.
    let left_css = origin_x as f32 / self.scale;
    let top_css = origin_y as f32 / self.scale;
    let right_css = (origin_x as f32 + width as f32) / self.scale;
    let bottom_css = (origin_y as f32 + height as f32) / self.scale;
    if !left_css.is_finite()
      || !top_css.is_finite()
      || !right_css.is_finite()
      || !bottom_css.is_finite()
    {
      return Ok(false);
    }

    let corners = [
      (left_css, top_css),
      (right_css, top_css),
      (right_css, bottom_css),
      (left_css, bottom_css),
    ];

    let mut dst_quad_points = [Point::ZERO; 4];
    let mut dst_quad = [(0.0f32, 0.0f32); 4];
    for (i, (x, y)) in corners.iter().enumerate() {
      let Some((dx, dy)) =
        self.project_preserve_3d_clip_point(transform, *x, *y, parent_transform, warp_enabled)
      else {
        return Ok(false);
      };
      dst_quad[i] = (dx, dy);
      dst_quad_points[i] = Point::new(dx, dy);
    }

    let projected_bounds = crate::paint::homography::quad_bounds(&dst_quad_points);
    let dest_bounds = Rect::from_xywh(0.0, 0.0, dest.width() as f32, dest.height() as f32);
    if projected_bounds.intersection(dest_bounds).is_none() {
      return Ok(true);
    }

    let src_w = width as f32;
    let src_h = height as f32;
    let src_quad = [
      Point::new(0.0, 0.0),
      Point::new(src_w, 0.0),
      Point::new(src_w, src_h),
      Point::new(0.0, src_h),
    ];
    let Some(homography) = Homography::from_quad_to_quad(src_quad, dst_quad_points) else {
      return Ok(false);
    };

    let target_size = (dest.width(), dest.height());
    let Some(warped) = crate::paint::projective_warp::warp_pixmap(
      &src_pixmap,
      &homography,
      &dst_quad,
      target_size,
      None,
    )?
    else {
      return Ok(false);
    };

    copy_pixmap_alpha_into_mask(dest, &warped.pixmap, warped.offset)?;
    Ok(true)
  }

  fn fill_projective_preserve_3d_clip_path_mask(
    &self,
    dest: &mut Mask,
    clip: &crate::paint::clip_path::ResolvedClipPath,
    transform: &Transform3D,
    parent_transform: Transform,
  ) -> RenderResult<bool> {
    // Keep clip-path rasterization away from the source pixmap boundaries to avoid unstable edge
    // coverage when the clip is later warped/clipped (similar to `Canvas::set_clip_path`).
    const CLIP_PATH_MASK_PADDING_PX: u32 = 32;

    let bounds = clip.bounds();
    if bounds.width() <= 0.0
      || bounds.height() <= 0.0
      || !bounds.x().is_finite()
      || !bounds.y().is_finite()
      || !bounds.width().is_finite()
      || !bounds.height().is_finite()
    {
      return Ok(false);
    }
    if !self.scale.is_finite() || self.scale <= 0.0 {
      return Ok(false);
    }

    // Compute an integer device-space raster region for the clip shape.
    let pad = CLIP_PATH_MASK_PADDING_PX as i32;
    let min_x = (bounds.min_x() * self.scale).floor();
    let min_y = (bounds.min_y() * self.scale).floor();
    let max_x = (bounds.max_x() * self.scale).ceil();
    let max_y = (bounds.max_y() * self.scale).ceil();
    if !min_x.is_finite() || !min_y.is_finite() || !max_x.is_finite() || !max_y.is_finite() {
      return Ok(false);
    }
    let origin_x = (min_x as i32).saturating_sub(pad);
    let origin_y = (min_y as i32).saturating_sub(pad);
    let end_x = (max_x as i32).saturating_add(pad);
    let end_y = (max_y as i32).saturating_add(pad);
    let width = end_x.saturating_sub(origin_x) as u32;
    let height = end_y.saturating_sub(origin_y) as u32;
    if width == 0 || height == 0 {
      return Ok(false);
    }

    let Some((shape_path, fill_rule)) = build_clip_path_shape_path(clip) else {
      return Ok(false);
    };

    let Some(mut src) = new_pixmap(width, height) else {
      return Ok(false);
    };
    src.data_mut().fill(0);

    let mut paint = tiny_skia::Paint::default();
    paint.anti_alias = true;
    paint.set_color(tiny_skia::Color::from_rgba8(255, 255, 255, 255));

    let local_transform = concat_transforms(
      Transform::from_translate(-(origin_x as f32), -(origin_y as f32)),
      Transform::from_scale(self.scale, self.scale),
    );
    src.fill_path(&shape_path, &paint, fill_rule, local_transform, None);

    // Build the destination quad by projecting the source-region corners through the clip's
    // Transform3D.
    let scale = self.scale;
    let left_css = origin_x as f32 / scale;
    let top_css = origin_y as f32 / scale;
    let right_css = (origin_x as f32 + width as f32) / scale;
    let bottom_css = (origin_y as f32 + height as f32) / scale;
    if !left_css.is_finite()
      || !top_css.is_finite()
      || !right_css.is_finite()
      || !bottom_css.is_finite()
    {
      return Ok(false);
    }
    let corners_css = [
      (left_css, top_css),
      (right_css, top_css),
      (right_css, bottom_css),
      (left_css, bottom_css),
    ];
    let mut dst_quad = [(0.0f32, 0.0f32); 4];
    let mut dst_points = [Point::ZERO; 4];
    for (i, (x, y)) in corners_css.iter().enumerate() {
      let (px, py) =
        match self.project_preserve_3d_clip_point(transform, *x, *y, parent_transform, true) {
          Some(pt) => pt,
          None => return Ok(false),
        };
      dst_quad[i] = (px, py);
      dst_points[i] = Point::new(px, py);
    }

    let src_quad = [
      Point::new(0.0, 0.0),
      Point::new(width as f32, 0.0),
      Point::new(width as f32, height as f32),
      Point::new(0.0, height as f32),
    ];
    let Some(homography) = Homography::from_quad_to_quad(src_quad, dst_points) else {
      return Ok(false);
    };
    let warped = crate::paint::projective_warp::warp_pixmap(
      &src,
      &homography,
      &dst_quad,
      (dest.width(), dest.height()),
      None,
    )?;
    let Some(warped) = warped else {
      return Ok(false);
    };

    copy_pixmap_alpha_into_mask(dest, &warped.pixmap, warped.offset)?;
    Ok(true)
  }

  fn projected_preserve_3d_clip_rect_path(
    &self,
    clip: &ClipItem,
    transform: &Transform3D,
    parent_transform: Transform,
    warp_enabled: bool,
  ) -> Option<tiny_skia::Path> {
    let ClipShape::Rect { rect, radii } = &clip.shape else {
      return None;
    };

    let rect = *rect;
    if rect.width() <= 0.0
      || rect.height() <= 0.0
      || !rect.x().is_finite()
      || !rect.y().is_finite()
      || !rect.width().is_finite()
      || !rect.height().is_finite()
    {
      return None;
    }

    let radii = radii
      .unwrap_or(BorderRadii::ZERO)
      .clamped(rect.width(), rect.height());
    let (x0, y0) = (rect.min_x(), rect.min_y());
    let (x1, y1) = (rect.max_x(), rect.max_y());
    let corners = [(x0, y0), (x1, y0), (x1, y1), (x0, y1)];

    let points_css: Vec<(f32, f32)> = if radii.is_zero() {
      vec![corners[0], corners[1], corners[2], corners[3]]
    } else {
      const ARC_STEPS: usize = 8;
      let normalize = |rx: f32, ry: f32| -> (f32, f32) {
        let rx = rx.max(0.0);
        let ry = ry.max(0.0);
        if rx > 0.0 && ry > 0.0 {
          (rx, ry)
        } else {
          (0.0, 0.0)
        }
      };

      let (tl_rx, tl_ry) = normalize(radii.top_left.x, radii.top_left.y);
      let (tr_rx, tr_ry) = normalize(radii.top_right.x, radii.top_right.y);
      let (br_rx, br_ry) = normalize(radii.bottom_right.x, radii.bottom_right.y);
      let (bl_rx, bl_ry) = normalize(radii.bottom_left.x, radii.bottom_left.y);

      let mut pts = Vec::with_capacity(4 + ARC_STEPS * 4);

      let push_arc =
        |pts: &mut Vec<(f32, f32)>, cx: f32, cy: f32, rx: f32, ry: f32, start: f32, end: f32| {
          if rx <= 0.0 || ry <= 0.0 {
            return;
          }
          for step in 1..=ARC_STEPS {
            let t = step as f32 / ARC_STEPS as f32;
            let angle = start + (end - start) * t;
            pts.push((cx + rx * angle.cos(), cy + ry * angle.sin()));
          }
        };

      pts.push((x0 + tl_rx, y0));
      pts.push((x1 - tr_rx, y0));
      push_arc(
        &mut pts,
        x1 - tr_rx,
        y0 + tr_ry,
        tr_rx,
        tr_ry,
        -std::f32::consts::FRAC_PI_2,
        0.0,
      );

      pts.push((x1, y1 - br_ry));
      push_arc(
        &mut pts,
        x1 - br_rx,
        y1 - br_ry,
        br_rx,
        br_ry,
        0.0,
        std::f32::consts::FRAC_PI_2,
      );

      pts.push((x0 + bl_rx, y1));
      push_arc(
        &mut pts,
        x0 + bl_rx,
        y1 - bl_ry,
        bl_rx,
        bl_ry,
        std::f32::consts::FRAC_PI_2,
        std::f32::consts::PI,
      );

      pts.push((x0, y0 + tl_ry));
      push_arc(
        &mut pts,
        x0 + tl_rx,
        y0 + tl_ry,
        tl_rx,
        tl_ry,
        std::f32::consts::PI,
        std::f32::consts::PI * 1.5,
      );

      pts
    };

    if points_css.len() < 3 {
      return None;
    }

    let mut builder = PathBuilder::new();
    for (idx, (x, y)) in points_css.into_iter().enumerate() {
      let (px, py) =
        self.project_preserve_3d_clip_point(transform, x, y, parent_transform, warp_enabled)?;
      if idx == 0 {
        builder.move_to(px, py);
      } else {
        builder.line_to(px, py);
      }
    }
    builder.close();
    builder.finish()
  }

  fn fill_projected_preserve_3d_text_clip_mask(
    &self,
    dest: &mut Mask,
    runs: &Arc<[TextItem]>,
    transform: &Transform3D,
    parent_transform: Transform,
    warp_enabled: bool,
  ) -> RenderResult<bool> {
    if runs.is_empty() {
      // An empty text clip means nothing is drawable. `dest` is expected to be cleared by the
      // caller, so we're done.
      return Ok(true);
    }
    if !(self.scale.is_finite() && self.scale > 0.0) {
      return Ok(false);
    }

    // Conservative bounds for the text clip in CSS px (mirrors `Canvas::set_clip_text`).
    let mut clip_bounds: Option<Rect> = None;
    for run in runs.iter() {
      let mut run_bounds = crate::paint::display_list::text_bounds(run);
      let outline_size = run.font_size * run.scale;
      let overhang = outline_size.abs() * 0.5;
      let synthetic = run.synthetic_bold.abs() * 2.0;
      let pad = (overhang + synthetic).max(0.0);
      if pad > 0.0 {
        run_bounds = run_bounds.inflate(pad);
      }
      if run.scale != 1.0 {
        // Scale only affects glyph outlines, not positions. Inflate to keep bounds conservative.
        let extra = (run.font_size * (run.scale - 1.0).abs()).max(0.0);
        if extra > 0.0 {
          run_bounds = run_bounds.inflate(extra);
        }
      }
      let mapped = if let Some(rot) = rotation_transform(run.rotation, run.origin.x, run.origin.y) {
        transform_rect(run_bounds, &rot)
      } else {
        run_bounds
      };
      clip_bounds = Some(match clip_bounds {
        Some(prev) => prev.union(mapped),
        None => mapped,
      });
    }

    let clip_bounds = clip_bounds.unwrap_or(Rect::ZERO);
    if clip_bounds.width() <= 0.0 || clip_bounds.height() <= 0.0 {
      return Ok(true);
    }
    if !clip_bounds.x().is_finite()
      || !clip_bounds.y().is_finite()
      || !clip_bounds.width().is_finite()
      || !clip_bounds.height().is_finite()
    {
      return Ok(false);
    }

    // Rasterize the clip text into an offscreen alpha surface in the clip's plane coordinates.
    const TEXT_MASK_PADDING_PX: i64 = 32;
    let bounds_px = Rect::from_xywh(
      clip_bounds.x() * self.scale,
      clip_bounds.y() * self.scale,
      clip_bounds.width() * self.scale,
      clip_bounds.height() * self.scale,
    );
    if !bounds_px.x().is_finite()
      || !bounds_px.y().is_finite()
      || !bounds_px.width().is_finite()
      || !bounds_px.height().is_finite()
    {
      return Ok(false);
    }

    let x0 = bounds_px.min_x().floor() as i64 - TEXT_MASK_PADDING_PX;
    let y0 = bounds_px.min_y().floor() as i64 - TEXT_MASK_PADDING_PX;
    let x1 = bounds_px.max_x().ceil() as i64 + TEXT_MASK_PADDING_PX;
    let y1 = bounds_px.max_y().ceil() as i64 + TEXT_MASK_PADDING_PX;
    let width_i64 = x1 - x0;
    let height_i64 = y1 - y0;
    if width_i64 <= 0 || height_i64 <= 0 {
      return Ok(true);
    }
    let Ok(width) = u32::try_from(width_i64) else {
      return Ok(false);
    };
    let Ok(height) = u32::try_from(height_i64) else {
      return Ok(false);
    };
    if width == 0 || height == 0 {
      return Ok(true);
    }

    let Some(mut src_pixmap) = new_pixmap(width, height) else {
      return Ok(false);
    };
    src_pixmap.data_mut().fill(0);

    let scaled_runs: Vec<TextItem> = runs.iter().map(|run| self.scale_text_item(run)).collect();

    let mut rasterizer = TextRasterizer::with_caches(
      self.glyph_cache.clone(),
      self.color_renderer.clone(),
      self.color_cache.clone(),
    );
    let state = TextRenderState {
      transform: Transform::from_translate(-(x0 as f32), -(y0 as f32)),
      clip_mask: None,
      opacity: 1.0,
      blend_mode: SkiaBlendMode::SourceOver,
      allow_subpixel_aa: false,
      font_smoothing: crate::style::types::FontSmoothing::Auto,
      text_rendering: crate::style::types::TextRendering::Auto,
    };

    for run in &scaled_runs {
      if run.glyphs.is_empty() {
        continue;
      }
      let Some(font) = run.font.as_deref() else {
        continue;
      };

      let hb_variations: Vec<Variation> = run
        .variations
        .iter()
        .map(|v| Variation {
          tag: v.tag,
          value: v.value(),
        })
        .collect();
      let positions: Vec<GlyphPosition> = run
        .glyphs
        .iter()
        .map(|g| GlyphPosition {
          glyph_id: g.glyph_id,
          cluster: g.cluster,
          x_offset: g.x_offset,
          y_offset: g.y_offset,
          x_advance: g.x_advance,
          y_advance: g.y_advance,
        })
        .collect();
      let rotation = rotation_transform(run.rotation, run.origin.x, run.origin.y);
      let run_state = TextRenderState {
        font_smoothing: run.font_smoothing,
        text_rendering: run.text_rendering,
        ..state
      };
      rasterizer
        .render_glyph_run(
          &positions,
          font,
          run.font_size * run.scale,
          run.synthetic_bold,
          run.synthetic_oblique,
          run.palette_index,
          run.palette_overrides.as_slice(),
          run.palette_override_hash,
          &hb_variations,
          rotation,
          run.origin.x,
          run.origin.y,
          Rgba::WHITE,
          run_state,
          &mut src_pixmap,
        )
        .map_err(|err| match err {
          Error::Render(render_err) => render_err,
          other => RenderError::RasterizationFailed {
            reason: other.to_string(),
          },
        })?;
    }

    // Projectively warp the alpha surface into canvas space.
    let src_w = width as f32;
    let src_h = height as f32;
    let css_w = src_w / self.scale;
    let css_h = src_h / self.scale;
    if !css_w.is_finite() || !css_h.is_finite() {
      return Ok(false);
    }

    let origin_css_x = x0 as f32 / self.scale;
    let origin_css_y = y0 as f32 / self.scale;
    let corners = [
      (origin_css_x, origin_css_y),
      (origin_css_x + css_w, origin_css_y),
      (origin_css_x + css_w, origin_css_y + css_h),
      (origin_css_x, origin_css_y + css_h),
    ];

    let mut dst_quad_points = [Point::ZERO; 4];
    let mut dst_quad = [(0.0f32, 0.0f32); 4];
    for (i, (x, y)) in corners.iter().enumerate() {
      let Some((dx, dy)) =
        self.project_preserve_3d_clip_point(transform, *x, *y, parent_transform, warp_enabled)
      else {
        return Ok(false);
      };
      dst_quad[i] = (dx, dy);
      dst_quad_points[i] = Point::new(dx, dy);
    }

    let projected_bounds = crate::paint::homography::quad_bounds(&dst_quad_points);
    let dest_bounds = Rect::from_xywh(0.0, 0.0, dest.width() as f32, dest.height() as f32);
    if projected_bounds.intersection(dest_bounds).is_none() {
      return Ok(true);
    }

    let src_quad = [
      Point::new(0.0, 0.0),
      Point::new(src_w, 0.0),
      Point::new(src_w, src_h),
      Point::new(0.0, src_h),
    ];
    let Some(homography) = Homography::from_quad_to_quad(src_quad, dst_quad_points) else {
      return Ok(false);
    };

    let target_size = (dest.width(), dest.height());
    let Some(warped) = crate::paint::projective_warp::warp_pixmap(
      &src_pixmap,
      &homography,
      &dst_quad,
      target_size,
      None,
    )?
    else {
      return Ok(false);
    };

    copy_pixmap_alpha_into_mask(dest, &warped.pixmap, warped.offset)?;

    Ok(true)
  }

  fn project_preserve_3d_clip_point(
    &self,
    transform: &Transform3D,
    x: f32,
    y: f32,
    parent_transform: Transform,
    warp_enabled: bool,
  ) -> Option<(f32, f32)> {
    if warp_enabled {
      let (tx, ty, _tz, tw) = transform.transform_point(x, y, 0.0);
      if !tw.is_finite()
        || tw.abs() < Transform3D::MIN_PROJECTIVE_W
        || tw < 0.0
        || !tx.is_finite()
        || !ty.is_finite()
      {
        return None;
      }
      let px = (tx / tw) * self.scale;
      let py = (ty / tw) * self.scale;
      let dst_x = px * parent_transform.sx + py * parent_transform.kx + parent_transform.tx;
      let dst_y = px * parent_transform.ky + py * parent_transform.sy + parent_transform.ty;
      if dst_x.is_finite() && dst_y.is_finite() {
        Some((dst_x, dst_y))
      } else {
        None
      }
    } else {
      let (t, _valid) = self.to_skia_transform_checked(transform);
      let px = x * self.scale;
      let py = y * self.scale;
      let tx = px * t.sx + py * t.kx + t.tx;
      let ty = px * t.ky + py * t.sy + t.ty;
      let dst_x = tx * parent_transform.sx + ty * parent_transform.kx + parent_transform.tx;
      let dst_y = tx * parent_transform.ky + ty * parent_transform.sy + parent_transform.ty;
      if dst_x.is_finite() && dst_y.is_finite() {
        Some((dst_x, dst_y))
      } else {
        None
      }
    }
  }

  fn projective_warp(
    &mut self,
    pixmap: &Pixmap,
    homography: &Homography,
    dst_quad: &[(f32, f32); 4],
    clip_override: Option<&Mask>,
    use_cache: bool,
  ) -> RenderResult<Option<Arc<WarpedPixmap>>> {
    let target_size = (self.canvas.width(), self.canvas.height());
    let clip = clip_override.or_else(|| self.canvas.clip_mask());
    warp_pixmap_cached(
      if use_cache {
        Some(&mut self.warp_cache)
      } else {
        None
      },
      pixmap,
      homography,
      dst_quad,
      target_size,
      clip,
    )
  }

  fn warp_pixmap_for_manual_blend(
    &mut self,
    pixmap: &Pixmap,
    transform: &Transform3D,
    clip_override: Option<&Mask>,
  ) -> Result<Option<Preserve3dWarpedLayer>> {
    let parent_transform = self.canvas.transform();
    let homography = Homography::from_transform3d_z0(transform);
    let warp_enabled = self.projective_warp_enabled;
    if !homography.is_affine() && warp_enabled {
      let src_w = pixmap.width() as f32;
      let src_h = pixmap.height() as f32;
      if src_w > 0.0 && src_h > 0.0 {
        let css_w = src_w / self.scale;
        let css_h = src_h / self.scale;
        if css_w.is_finite() && css_h.is_finite() {
          let corners = [(0.0, 0.0), (css_w, 0.0), (css_w, css_h), (0.0, css_h)];
          let mut dst_quad_points = [Point::ZERO; 4];
          let mut dst_quad = [(0.0f32, 0.0f32); 4];
          let mut valid = true;

          for (i, (x, y)) in corners.iter().enumerate() {
            let Some(projected) = transform.project_point_2d(*x, *y) else {
              valid = false;
              break;
            };
            let px = projected.x * self.scale;
            let py = projected.y * self.scale;
            let dst_x = px * parent_transform.sx + py * parent_transform.kx + parent_transform.tx;
            let dst_y = px * parent_transform.ky + py * parent_transform.sy + parent_transform.ty;
            if !dst_x.is_finite() || !dst_y.is_finite() {
              valid = false;
              break;
            }
            dst_quad[i] = (dst_x, dst_y);
            dst_quad_points[i] = Point::new(dst_x, dst_y);
          }

          let src_quad = [
            Point::new(0.0, 0.0),
            Point::new(src_w, 0.0),
            Point::new(src_w, src_h),
            Point::new(0.0, src_h),
          ];
          let use_cache = clip_override.is_none();
          let warped = if valid {
            Homography::from_quad_to_quad(src_quad, dst_quad_points)
              .map(|h| self.projective_warp(pixmap, &h, &dst_quad, clip_override, use_cache))
              .transpose()
              .map_err(Error::Render)?
              .flatten()
          } else {
            None
          };
          if let Some(warped) = warped {
            return Ok(Some(Preserve3dWarpedLayer::Warped(warped)));
          }
        }
      }
    }

    // Affine fallback (also used when projective warps are disabled).
    let (t, _valid) = self.to_skia_transform_checked(transform);
    let skia_transform = concat_transforms(parent_transform, t);
    let src_rect = Rect::from_xywh(0.0, 0.0, pixmap.width() as f32, pixmap.height() as f32);
    let mut bounds = transform_rect(src_rect, &skia_transform);
    if let Some(clip) = self.canvas.clip_bounds() {
      bounds = match bounds.intersection(clip) {
        Some(r) => r,
        None => return Ok(None),
      };
    }
    bounds = match bounds.intersection(self.canvas.bounds()) {
      Some(r) => r,
      None => return Ok(None),
    };
    if bounds.width() <= 0.0
      || bounds.height() <= 0.0
      || !bounds.x().is_finite()
      || !bounds.y().is_finite()
    {
      return Ok(None);
    }

    let origin_x = bounds.min_x().floor() as i32;
    let origin_y = bounds.min_y().floor() as i32;
    let x1 = bounds.max_x().ceil() as i32;
    let y1 = bounds.max_y().ceil() as i32;
    let width = x1.saturating_sub(origin_x) as u32;
    let height = y1.saturating_sub(origin_y) as u32;
    if width == 0 || height == 0 {
      return Ok(None);
    }

    let mut layer = match new_pixmap(width, height) {
      Some(p) => p,
      None => return Ok(None),
    };
    let local_transform = concat_transforms(
      Transform::from_translate(-(origin_x as f32), -(origin_y as f32)),
      skia_transform,
    );
    let mut paint = PixmapPaint::default();
    paint.blend_mode = SkiaBlendMode::SourceOver;
    layer.draw_pixmap(0, 0, pixmap.as_ref(), &paint, local_transform, None);

    if let Some(mask) = clip_override.or_else(|| self.canvas.clip_mask()) {
      let Some(cropped) =
        crop_mask_i32(mask, origin_x, origin_y, width, height).map_err(Error::Render)?
      else {
        return Ok(None);
      };
      if active_deadline().as_ref().map_or(false, |d| d.is_enabled()) {
        apply_mask_rect_rgba(
          &mut layer,
          &cropped,
          ClipMaskDirtyRect {
            x0: 0,
            y0: 0,
            x1: width,
            y1: height,
          },
        )
        .map_err(Error::Render)?;
      } else {
        layer.apply_mask(&cropped);
      }
    }

    Ok(Some(Preserve3dWarpedLayer::Affine {
      pixmap: layer,
      offset: (origin_x, origin_y),
    }))
  }

  fn warp_pixmap(
    &mut self,
    pixmap: &Pixmap,
    transform: &Transform3D,
    clip_override: Option<&Mask>,
    blend_mode: SkiaBlendMode,
  ) -> Result<()> {
    let mut paint = PixmapPaint::default();
    paint.blend_mode = blend_mode;

    let parent_transform = self.canvas.transform();

    let homography = Homography::from_transform3d_z0(transform);
    let warp_enabled = self.projective_warp_enabled;
    if homography.is_affine() || !warp_enabled {
      if self.preserve_3d_debug && !homography.is_affine() && !warp_enabled {
        eprintln!("preserve-3d warp disabled; using affine approximation");
      }
      // `draw_pixmap` needs a borrowable `&Mask` while we also mutably borrow the pixmap; grab an
      // `Rc` clone of the canvas clip mask instead of deep-cloning the full mask.
      let clip_rc = clip_override
        .is_none()
        .then(|| self.canvas.clip_mask_rc())
        .flatten();
      let clip_ref = clip_override.or_else(|| clip_rc.as_deref());
      let (t, _valid) = self.to_skia_transform_checked(transform);
      let skia_transform = concat_transforms(parent_transform, t);
      self.canvas.with_mirrored_pixmap_mut(|dest| {
        dest.draw_pixmap(0, 0, pixmap.as_ref(), &paint, skia_transform, clip_ref);
      });
      return Ok(());
    }

    let src_w = pixmap.width() as f32;
    let src_h = pixmap.height() as f32;
    if src_w <= 0.0 || src_h <= 0.0 {
      return Ok(());
    }
    let css_w = src_w / self.scale;
    let css_h = src_h / self.scale;

    let corners = [(0.0, 0.0), (css_w, 0.0), (css_w, css_h), (0.0, css_h)];
    let mut dst_quad_points = [Point::ZERO; 4];
    let mut dst_quad = [(0.0f32, 0.0f32); 4];
    let mut valid = true;

    for (i, (x, y)) in corners.iter().enumerate() {
      let Some(projected) = transform.project_point_2d(*x, *y) else {
        valid = false;
        break;
      };
      let px = projected.x * self.scale;
      let py = projected.y * self.scale;
      let dst_x = px * parent_transform.sx + py * parent_transform.kx + parent_transform.tx;
      let dst_y = px * parent_transform.ky + py * parent_transform.sy + parent_transform.ty;
      if !dst_x.is_finite() || !dst_y.is_finite() {
        valid = false;
        break;
      }
      dst_quad[i] = (dst_x, dst_y);
      dst_quad_points[i] = Point::new(dst_x, dst_y);
    }

    let src_quad = [
      Point::new(0.0, 0.0),
      Point::new(src_w, 0.0),
      Point::new(src_w, src_h),
      Point::new(0.0, src_h),
    ];
    let use_cache = clip_override.is_none();
    let warped = if valid {
      Homography::from_quad_to_quad(src_quad, dst_quad_points)
        .map(|h| self.projective_warp(pixmap, &h, &dst_quad, clip_override, use_cache))
        .transpose()
        .map_err(Error::Render)?
        .flatten()
    } else {
      None
    };

    if let Some(warped) = warped {
      self.canvas.with_mirrored_pixmap_mut(|pixmap| {
        pixmap.draw_pixmap(
          warped.offset.0,
          warped.offset.1,
          warped.pixmap.as_ref(),
          &paint,
          Transform::identity(),
          None,
        );
      });
      return Ok(());
    }

    // Fall back to the affine approximation when a stable projective warp can't be computed.
    if self.preserve_3d_debug {
      eprintln!("preserve-3d warp fallback; using affine approximation");
    }
    let clip_rc = clip_override
      .is_none()
      .then(|| self.canvas.clip_mask_rc())
      .flatten();
    let clip_ref = clip_override.or_else(|| clip_rc.as_deref());
    let (t, _valid) = self.to_skia_transform_checked(transform);
    let skia_transform = concat_transforms(parent_transform, t);
    self.canvas.with_mirrored_pixmap_mut(|dest| {
      dest.draw_pixmap(0, 0, pixmap.as_ref(), &paint, skia_transform, clip_ref);
    });
    Ok(())
  }

  fn render_table_collapsed_borders(&mut self, item: &TableCollapsedBordersItem) -> Result<()> {
    let zero_side = BorderSide {
      width: 0.0,
      style: CssBorderStyle::None,
      color: Rgba::TRANSPARENT,
    };

    let column_lines = &item.borders.column_line_positions;
    let row_lines = &item.borders.row_line_positions;

    let mut deadline_counter = 0usize;
    for col_idx in 0..=item.borders.column_count {
      check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
        .map_err(Error::Render)?;
      let base_x = item.origin.x + column_lines.get(col_idx).copied().unwrap_or(0.0);
      let base_edge_width = item.borders.vertical_line_width(col_idx);
      for row_idx in 0..item.borders.row_count {
        let Some(border) = item.borders.vertical_segment(col_idx, row_idx) else {
          continue;
        };
        if !border.is_visible() {
          continue;
        }
        let is_left_edge = col_idx == 0;
        let is_right_edge = col_idx == item.borders.column_count;
        // Interior grid lines are centered: the stroke extends `width/2` to either side of the
        // grid line center.
        //
        // Outer edges are special (CSS 2.1 §17.6.2): layout positions the grid using "baseline"
        // outer line widths (recorded in `*_line_base`; for left/right this comes from the first
        // row). A later row/column may still resolve a thicker winning segment on the outer edge,
        // but that must not move the inside edge of the table; the extra thickness is painted on
        // the outside (spills outward into the margin).
        //
        // `inside` is therefore capped to the baseline half-width so any excess thickness paints
        // outward only. When changing this logic, keep `TableCollapsedBorders.paint_bounds` in
        // sync: display list culling relies on it. With the table fragment origin aligned to the
        // baseline outer border paint edge, `paint_bounds` becomes negative only when a thicker
        // outer-edge winner spills outward beyond that baseline (WPT `border-collapse-basic-001`).
        let baseline_edge = if is_left_edge || is_right_edge {
          base_edge_width
        } else {
          border.width
        };
        let inside = if is_left_edge || is_right_edge {
          (border.width.min(baseline_edge)) * 0.5
        } else {
          border.width * 0.5
        };
        let x = if is_left_edge {
          base_x - (border.width - inside)
        } else {
          base_x - inside
        };
        let row_start = item.origin.y + row_lines.get(row_idx).copied().unwrap_or(0.0);
        let row_end = item.origin.y + row_lines.get(row_idx + 1).copied().unwrap_or(row_start);
        let corner_top = item
          .borders
          .corner(row_idx, col_idx)
          .map(|c| c.width * 0.5)
          .unwrap_or(0.0);
        let corner_bottom = item
          .borders
          .corner(row_idx + 1, col_idx)
          .map(|c| c.width * 0.5)
          .unwrap_or(0.0);
        let y_start = row_start + corner_top;
        let y_end = row_end - corner_bottom;
        let height = (y_end - y_start).max(0.0);
        if height <= 0.0 {
          continue;
        }
        let border_item = BorderItem {
          rect: Rect::from_xywh(x, y_start, border.width, height),
          top: zero_side.clone(),
          right: zero_side.clone(),
          bottom: zero_side.clone(),
          left: BorderSide {
            width: border.width,
            style: border.style,
            color: border.color,
          },
          image: None,
          radii: BorderRadii::ZERO,
          gap: None,
        };
        self.render_border(&border_item)?;
      }
    }

    for row_idx in 0..=item.borders.row_count {
      check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
        .map_err(Error::Render)?;
      let base_y = item.origin.y + row_lines.get(row_idx).copied().unwrap_or(0.0);
      let base_edge_width = item.borders.horizontal_line_width(row_idx);
      for col_idx in 0..item.borders.column_count {
        let Some(border) = item.borders.horizontal_segment(row_idx, col_idx) else {
          continue;
        };
        if !border.is_visible() {
          continue;
        }
        let is_top_edge = row_idx == 0;
        let is_bottom_edge = row_idx == item.borders.row_count;
        // See the vertical loop above for the baseline-vs-spill rationale. The same rule applies
        // here: clamp how much of an outer edge segment is allowed inside the table, and let any
        // excess thickness paint outward.
        let baseline_edge = if is_top_edge || is_bottom_edge {
          base_edge_width
        } else {
          border.width
        };
        let inside = if is_top_edge || is_bottom_edge {
          (border.width.min(baseline_edge)) * 0.5
        } else {
          border.width * 0.5
        };
        let y = if is_top_edge {
          base_y - (border.width - inside)
        } else {
          base_y - inside
        };
        let col_start = item.origin.x + column_lines.get(col_idx).copied().unwrap_or(0.0);
        let col_end = item.origin.x + column_lines.get(col_idx + 1).copied().unwrap_or(col_start);
        let corner_left = item
          .borders
          .corner(row_idx, col_idx)
          .map(|c| c.width * 0.5)
          .unwrap_or(0.0);
        let corner_right = item
          .borders
          .corner(row_idx, col_idx + 1)
          .map(|c| c.width * 0.5)
          .unwrap_or(0.0);
        let x_start = col_start + corner_left;
        let x_end = col_end - corner_right;
        let width = (x_end - x_start).max(0.0);
        if width <= 0.0 {
          continue;
        }
        let border_item = BorderItem {
          rect: Rect::from_xywh(x_start, y, width, border.width),
          top: BorderSide {
            width: border.width,
            style: border.style,
            color: border.color,
          },
          right: zero_side.clone(),
          bottom: zero_side.clone(),
          left: zero_side.clone(),
          image: None,
          radii: BorderRadii::ZERO,
          gap: None,
        };
        self.render_border(&border_item)?;
      }
    }

    for r in 0..=item.borders.row_count {
      for c in 0..=item.borders.column_count {
        check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)
          .map_err(Error::Render)?;
        let Some(corner) = item.borders.corner(r, c) else {
          continue;
        };
        if !corner.is_visible() {
          continue;
        }
        let x = item.origin.x + column_lines.get(c).copied().unwrap_or(0.0) - corner.width * 0.5;
        let y = item.origin.y + row_lines.get(r).copied().unwrap_or(0.0) - corner.width * 0.5;
        let rect = Rect::from_xywh(x, y, corner.width, corner.width);
        if !corner.color.is_transparent() {
          self.canvas.draw_rect(self.ds_rect(rect), corner.color);
        }
        let side = BorderSide {
          width: corner.width,
          style: corner.style,
          color: corner.color,
        };
        let border_item = BorderItem {
          rect,
          top: side.clone(),
          right: side.clone(),
          bottom: side.clone(),
          left: side,
          image: None,
          radii: BorderRadii::ZERO,
          gap: None,
        };
        self.render_border(&border_item)?;
      }
    }

    Ok(())
  }

  #[inline]
  fn display_item_mutates_current_pixmap(item: &DisplayItem) -> bool {
    matches!(
      item,
      DisplayItem::FillRect(_)
        | DisplayItem::StrokeRect(_)
        | DisplayItem::Outline(_)
        | DisplayItem::FillRoundedRect(_)
        | DisplayItem::StrokeRoundedRect(_)
        | DisplayItem::Text(_)
        | DisplayItem::Image(_)
        | DisplayItem::ImagePattern(_)
        | DisplayItem::BoxShadow(_)
        | DisplayItem::ListMarker(_)
        | DisplayItem::LinearGradient(_)
        | DisplayItem::LinearGradientPattern(_)
        | DisplayItem::RadialGradient(_)
        | DisplayItem::RadialGradientPattern(_)
        | DisplayItem::ConicGradient(_)
        | DisplayItem::ConicGradientPattern(_)
        | DisplayItem::Border(_)
        | DisplayItem::TableCollapsedBorders(_)
        | DisplayItem::TextDecoration(_)
    )
  }

  /// Render a single display list item.
  ///
  /// ### Stacking-context compositing flags
  ///
  /// When consuming a [`StackingContextItem`], keep the following model in mind:
  ///
  /// - [`StackingContextItem::is_isolated`] is the Compositing & Blending concept: render the
  ///   subtree into an offscreen surface whose initial backdrop is transparent (an "isolated
  ///   group"). This confines descendant `mix-blend-mode` blending.
  /// - [`StackingContextItem::establishes_backdrop_root`] is the Filter Effects Level 2 concept:
  ///   a *Backdrop Root* boundary that scopes descendant `backdrop-filter` sampling (Backdrop
  ///   Root Image). Backdrop Root scoping is implemented via the canvas layer stack. To avoid
  ///   unnecessary offscreen layers, we only force a layer boundary for backdrop roots when the
  ///   stacking context subtree actually contains backdrop-sampling effects (see
  ///   [`StackingContextItem::has_backdrop_sensitive_descendants`]).
  ///
  /// These flags describe compositing/sampling semantics; tile-parallel paint eligibility is
  /// determined separately (see [`Self::has_parallel_incompatible_effects`]).
  ///
  /// Spec references:
  /// - Filter Effects Level 2: Backdrop Root (<https://drafts.fxtf.org/filter-effects-2/#BackdropRoot>)
  /// - CSS Compositing and Blending: isolated groups (<https://www.w3.org/TR/compositing-1/#isolatedgroups>)
  fn maybe_init_non_isolated_group_backdrop(&mut self, item: &DisplayItem) -> Result<()> {
    let needs_backdrop = match item {
      DisplayItem::PushStackingContext(sc) => !matches!(sc.mix_blend_mode, BlendMode::Normal),
      // `PushBlendMode` is currently used to implement CSS `background-blend-mode` while painting a
      // single element's background layers. Unlike `mix-blend-mode`, background blending is
      // confined to the element's own background stack and must *not* sample pixels outside the
      // current compositing group. Seeding the active group surface from the already-painted
      // backdrop would incorrectly cause background layers to blend against the page contents.
      _ => false,
    };
    if !needs_backdrop {
      return Ok(());
    }

    // Non-isolated stacking contexts (`isolation: auto`) need descendant blend operations to see
    // the already-painted backdrop. We do *not* initialize the group surface from backdrop eagerly
    // because doing so forces an uncompositing step later (to avoid double-counting the backdrop)
    // that can change results for blend modes on opaque backdrops.
    //
    // Instead, initialize lazily: only when a descendant blend operation actually needs to sample
    // backdrop pixels outside the group, and only when the group's offscreen surface is currently
    // the active canvas layer.
    let init_stacking_backdrop = self.stacking_layers.last().is_some_and(|record| {
      record.needs_layer
        && !record.is_isolated
        && !(record.establishes_backdrop_root && matches!(record.mix_blend_mode, BlendMode::Normal))
        && !record.init_from_backdrop
        && self.canvas.layer_stack_len() == record.canvas_layer_depth
    });

    if init_stacking_backdrop {
      self.canvas.ensure_current_layer_source_alpha()?;
      let Some(active_origin) = self.canvas.layer_stack().last().map(|layer| layer.origin) else {
        return Ok(());
      };
      let Some((backdrop, pixmap)) = self.canvas.split_backdrop_and_pixmap_mut() else {
        return Ok(());
      };
      let mut paint = PixmapPaint::default();
      paint.opacity = 1.0;
      paint.blend_mode = SkiaBlendMode::DestinationOver;
      pixmap.draw_pixmap(
        -active_origin.0,
        -active_origin.1,
        backdrop.as_ref(),
        &paint,
        Transform::identity(),
        None,
      );
      self.canvas.mark_current_layer_initialized_from_backdrop();
      self.mark_current_pixmap_mutated();
      if let Some(record) = self.stacking_layers.last_mut() {
        record.init_from_backdrop = true;
      }
      return Ok(());
    }

    // Some non-stacking-context layers (notably `PushOpacity`) are also non-isolated compositing
    // groups. When a descendant blend operation needs to sample backdrop pixels outside the group,
    // initialize the active opacity layer from its parent surface so subsequent blend operations
    // see the correct backdrop.
    let init_opacity_backdrop = self.opacity_stack.last().is_some_and(|record| {
      !record.is_backdrop_root
        && !record.init_from_backdrop
        && self.canvas.layer_stack_len() == record.canvas_layer_depth
    });

    if init_opacity_backdrop {
      self.canvas.ensure_current_layer_source_alpha()?;
      let Some(active_origin) = self.canvas.layer_stack().last().map(|layer| layer.origin) else {
        return Ok(());
      };
      let Some((backdrop, pixmap)) = self.canvas.split_backdrop_and_pixmap_mut() else {
        return Ok(());
      };
      let mut paint = PixmapPaint::default();
      paint.opacity = 1.0;
      paint.blend_mode = SkiaBlendMode::DestinationOver;
      pixmap.draw_pixmap(
        -active_origin.0,
        -active_origin.1,
        backdrop.as_ref(),
        &paint,
        Transform::identity(),
        None,
      );
      self.canvas.mark_current_layer_initialized_from_backdrop();
      self.mark_current_pixmap_mutated();
      if let Some(record) = self.opacity_stack.last_mut() {
        record.init_from_backdrop = true;
      }
    }
    Ok(())
  }

  fn render_item(&mut self, item: &DisplayItem) -> Result<()> {
    if self.culled_depth > 0 {
      match item {
        DisplayItem::PushStackingContext(_) | DisplayItem::PushBackfaceVisibility(_) => {
          self.culled_depth += 1;
        }
        DisplayItem::PopStackingContext | DisplayItem::PopBackfaceVisibility => {
          if self.culled_depth > 0 {
            self.culled_depth -= 1;
          }
        }
        _ => {}
      }
      return Ok(());
    }

    self.maybe_init_non_isolated_group_backdrop(item)?;
    self.apply_pending_backdrop(item)?;

    if Self::display_item_mutates_current_pixmap(item) {
      self.mark_current_pixmap_mutated();
    }

    match item {
      DisplayItem::FillRect(FillRectItem { rect, color }) => {
        self.canvas.draw_rect(self.ds_rect(*rect), *color)
      }
      DisplayItem::StrokeRect(StrokeRectItem {
        rect,
        color,
        width,
        blend_mode,
      }) => self.canvas.stroke_rect_with_blend(
        self.ds_rect(*rect),
        *color,
        self.ds_len(*width),
        *blend_mode,
      ),
      DisplayItem::FillRoundedRect(item) => {
        self.canvas.draw_rounded_rect(
          self.ds_rect(item.rect),
          self.ds_radii(item.radii),
          item.color,
        );
      }
      DisplayItem::StrokeRoundedRect(item) => self.canvas.stroke_rounded_rect(
        self.ds_rect(item.rect),
        self.ds_radii(item.radii),
        item.color,
        self.ds_len(item.width),
      ),
      DisplayItem::Outline(item) => self.render_outline(item),
      DisplayItem::LinearGradient(item) => self.render_linear_gradient(item)?,
      DisplayItem::LinearGradientPattern(item) => self.render_linear_gradient_pattern(item)?,
      DisplayItem::RadialGradient(item) => self.render_radial_gradient(item)?,
      DisplayItem::RadialGradientPattern(item) => self.render_radial_gradient_pattern(item)?,
      DisplayItem::ConicGradient(item) => self.render_conic_gradient(item)?,
      DisplayItem::ConicGradientPattern(item) => self.render_conic_gradient_pattern(item)?,
      DisplayItem::Border(item) => self.render_border(item)?,
      DisplayItem::TableCollapsedBorders(item) => self.render_table_collapsed_borders(item)?,
      DisplayItem::TextDecoration(item) => {
        let scaled = self.scale_decoration_item(item);
        self.render_text_decoration(&scaled)?;
      }
      DisplayItem::Text(item) => {
        let scaled = self.scale_text_item(item);
        self.render_text(&scaled)?;
      }
      DisplayItem::Image(item) => self.render_image(item)?,
      DisplayItem::RemoteFrameSlot(_) => {
        // Metadata-only marker consumed by higher-level OOPIF compositing code.
      }
      DisplayItem::ImagePattern(item) => self.render_image_pattern(item)?,
      DisplayItem::BoxShadow(item) => self.render_box_shadow(item)?,
      DisplayItem::ListMarker(item) => {
        let scaled = self.scale_list_marker_item(item);
        self.render_list_marker(&scaled)?;
      }
      DisplayItem::PushStackingContext(item) => {
        let canvas_layer_depth_before = self.canvas.layer_stack_len();
        let stacking_depth_before = self.stacking_layers.len();
        // If the current clip rectangle excludes the entire canvas, the stacking context cannot
        // affect any pixels. Avoid allocating layers and traversing the subtree in this case.
        if let Some(clip_bounds) = self.canvas.clip_bounds().filter(|bounds| {
          bounds.x().is_finite()
            && bounds.y().is_finite()
            && bounds.width().is_finite()
            && bounds.height().is_finite()
        }) {
          let has_visible_pixels = clip_bounds
            .intersection(self.canvas.bounds())
            .is_some_and(|bounds| bounds.width() > 0.0 && bounds.height() > 0.0);
          if !has_visible_pixels {
            self.culled_depth = 1;
            return Ok(());
          }
        }
        let parent_child_transform = *self
          .transform_stack
          .last()
          .unwrap_or(&Transform3D::identity());
        let parent_perspective = *self
          .perspective_stack
          .last()
          .unwrap_or(&Transform3D::identity());
        let local_transform = item.transform.unwrap_or(Transform3D::identity());
        let painting_transform_3d = parent_child_transform.multiply(&local_transform);

        if matches!(item.backface_visibility, BackfaceVisibility::Hidden)
          && backface_is_hidden(&painting_transform_3d)
        {
          self.culled_depth = 1;
          return Ok(());
        }

        // When an ancestor `perspective` / `perspective-origin` matrix is multiplied with a child
        // transform matrix, naive 4×4 multiplication can accumulate slightly different floating
        // point rounding than the equivalent `perspective()` function inside the transform list.
        //
        // This matters for WPT reftests like `transforms/perspective-preserve-3d-001` which assert
        // those representations are equivalent.
        let mut warp_candidate =
          parent_perspective.multiply_perspective_optimized(&local_transform);
        if self.projective_warp_depth > 0 {
          let parent_global = self
            .stacking_layers
            .last()
            .map(|record| record.global_transform_3d)
            .unwrap_or_else(Transform3D::identity);
          let parent_h = Homography::from_transform3d_z0(&parent_global);
          if let Some(inv) = parent_h.inverse() {
            let child_h = Homography::from_transform3d_z0(&painting_transform_3d);
            let relative = inv.multiply(&child_h);
            if relative.is_finite() {
              warp_candidate = relative.to_transform3d_z0();
            }
          }
        }
        let warp_candidate_is_projective =
          !Homography::from_transform3d_z0(&warp_candidate).is_affine();
        let projective_transform =
          (self.projective_warp_enabled && warp_candidate_is_projective).then_some(warp_candidate);

        let child_base_transform = if let Some(perspective) = item.child_perspective.as_ref() {
          painting_transform_3d.multiply(perspective)
        } else {
          painting_transform_3d
        };

        let scaled_filters = self.ds_filters(&item.filters);
        let scaled_backdrop = self.ds_filters(&item.backdrop_filters);
        let has_backdrop = !scaled_backdrop.is_empty();
        let opacity = item.opacity.clamp(0.0, 1.0);
        let css_bounds = item.bounds;
        let plane_css_bounds = {
          let candidate = item.plane_rect;
          if candidate.width() > 0.0
            && candidate.height() > 0.0
            && candidate.x().is_finite()
            && candidate.y().is_finite()
            && candidate.width().is_finite()
            && candidate.height().is_finite()
          {
            candidate
          } else {
            css_bounds
          }
        };
        let bounds = self.ds_rect(css_bounds);
        let plane_bounds = self.ds_rect(plane_css_bounds);
        let radii = self.ds_radii(item.radii);
        let mask = item.mask.clone();
        let mask_border = item.mask_border.clone();

        // `backdrop-filter` needs an isolated group surface (transparent initial backdrop) so
        // sampling does not include the element's own contents. `mix-blend-mode` isolation is
        // controlled by the `isolation` property instead; non-isolated blend groups still need to
        // see the already-painted backdrop for descendant blending (handled lazily in
        // `maybe_init_non_isolated_group_backdrop`).
        let is_isolated = item.is_isolated || has_backdrop;
        let manual_blend = if is_manual_blend(item.mix_blend_mode) {
          Some(item.mix_blend_mode)
        } else {
          None
        };

        let parent_transform = self.canvas.transform();
        let mut local_skia_transform: Option<Transform> = None;
        let mut combined_transform = parent_transform;
        let mut applied_perspective = false;
        let mut perspective_residual: Option<Transform3D> = None;
        let mut projective_warp_bounds = None;
        if projective_transform.is_some() {
          if let Some((t, bounds)) =
            self.projective_warp_pre_transform(&warp_candidate, parent_transform)
          {
            local_skia_transform = Some(t);
            combined_transform = concat_transforms(combined_transform, t);
            projective_warp_bounds = Some(bounds);
          } else {
            let (t, valid) = self.to_skia_transform_checked(&warp_candidate);
            if valid {
              local_skia_transform = Some(t);
              combined_transform = concat_transforms(combined_transform, t);
            }
          }
        } else if item.transform.is_some()
          || (!self.projective_warp_enabled && warp_candidate_is_projective)
        {
          let mut uses_warp_candidate = false;
          let transform_for_canvas =
            if !self.projective_warp_enabled && warp_candidate_is_projective {
              uses_warp_candidate = true;
              &warp_candidate
            } else if item.transform.is_some()
              && (self.projective_warp_depth > 0 || !parent_perspective.is_identity())
            {
              // Even when the combined transform is affine on the z=0 plane (e.g. `perspective` +
              // `translateZ`), we must apply the ancestor perspective to get the correct projected
              // scale/translation for this stacking context.
              uses_warp_candidate = true;
              &warp_candidate
            } else {
              &local_transform
            };
          let (t, valid) = self.to_skia_transform_checked(transform_for_canvas);
          if valid {
            local_skia_transform = Some(t);
            combined_transform = concat_transforms(combined_transform, t);
            applied_perspective = !self.projective_warp_enabled && warp_candidate_is_projective;

            if uses_warp_candidate && !parent_perspective.is_identity() {
              // We applied an affine approximation of a transform that still has 3D components
              // (e.g. ancestor `perspective`). Carry forward the remaining 3D residual so
              // descendants compose transforms correctly.
              let affine = warp_candidate
                .to_2d()
                .unwrap_or_else(|| warp_candidate.approximate_2d_with_validity().0);
              if let Some(inv) = affine.inverse() {
                let residual = Transform3D::from_2d(&inv).multiply(&warp_candidate);
                perspective_residual = Some(residual);
              }
            }
          }
        }

        self.transform_stack.push(child_base_transform);
        let perspective_base = if applied_perspective {
          Transform3D::identity()
        } else if let Some(residual) = perspective_residual {
          residual
        } else if projective_transform.is_some() {
          Transform3D::identity()
        } else {
          parent_perspective
        };
        let next_perspective = item
          .child_perspective
          .as_ref()
          .map(|p| perspective_base.multiply(p))
          .unwrap_or(perspective_base);
        self.perspective_stack.push(next_perspective);

        let mut pending_backdrop = if has_backdrop {
          let backdrop_bounds = if let Some(projective_transform) = projective_transform.as_ref() {
            let projected_css = projective_transform.transform_rect(plane_css_bounds);
            let projected_device = self.ds_rect(projected_css);
            transform_rect(projected_device, &parent_transform)
          } else {
            transform_rect(plane_bounds, &combined_transform)
          };
          Some(PendingBackdrop {
            bounds: backdrop_bounds,
            shape_bounds: plane_bounds,
            filters: scaled_backdrop.clone(),
            radii,
            filter_bounds: plane_css_bounds,
          })
        } else {
          None
        };
        let mask_bounds = transform_rect(bounds, &combined_transform);

        // Tracks whether this stacking context should be treated as a Backdrop Root for sampling
        // the Backdrop Root Image (Filter Effects Level 2).
        let is_backdrop_root = item.establishes_backdrop_root
          || !scaled_filters.is_empty()
          || has_backdrop
          || opacity < 1.0 - f32::EPSILON
          || mask.is_some()
          || mask_border.is_some()
          || item.has_clip_path
          || !matches!(item.mix_blend_mode, BlendMode::Normal);
        let establishes_backdrop_root_layer = !item.is_root
          && item.establishes_backdrop_root
          && item.has_backdrop_sensitive_descendants;
        let needs_layer = is_isolated
          || !matches!(
            item.mix_blend_mode,
            crate::paint::display_list::BlendMode::Normal
          )
          || !scaled_filters.is_empty()
          || has_backdrop
          || opacity < 1.0 - f32::EPSILON
          || mask.is_some()
          || mask_border.is_some()
          || projective_transform.is_some()
          // Filter Effects Level 2 Backdrop Roots must isolate backdrop sampling for descendant
          // `backdrop-filter` / `mix-blend-mode` effects. Some triggers (notably `will-change` and
          // `clip-path`) can establish a backdrop root without otherwise requiring an offscreen
          // surface, so only force a layer boundary when a descendant would observe it (and never
          // for the document root).
          || establishes_backdrop_root_layer;
        let mut layer_bounds = needs_layer
          .then(|| {
            let bounds_transform = combined_transform;
            self.stacking_layer_bounds(
              bounds,
              css_bounds,
              bounds_transform,
              &scaled_filters,
              &scaled_backdrop,
            )
          })
          .flatten();
        if projective_transform.is_some() {
          layer_bounds = None;
        }

        let mut allocation_bounds = layer_bounds;
        if needs_layer && has_backdrop {
          if let Some(projective_transform) = projective_transform.as_ref() {
            if let Some(projected_bounds) = self.projective_backdrop_layer_bounds(
              plane_css_bounds,
              css_bounds,
              parent_transform,
              projective_transform,
              &scaled_filters,
              &scaled_backdrop,
            ) {
              let mut merged = layer_bounds
                .map(|existing| existing.union(projected_bounds))
                .unwrap_or(projected_bounds);

              // `projective_warp_pre_transform` can apply an affine pre-transform to the offscreen
              // layer that maps the element's local plane into a region wider than the projected
              // quad. Ensure the bounded layer allocation also includes those pre-warp (affine)
              // bounds so projective backdrop-filter compensation has space to write pixels.
              let extra_bounds = if mask_bounds.width() > 0.0
                && mask_bounds.height() > 0.0
                && mask_bounds.x().is_finite()
                && mask_bounds.y().is_finite()
                && mask_bounds.width().is_finite()
                && mask_bounds.height().is_finite()
              {
                let mut extra = mask_bounds;
                if let Some(clip) = self.canvas.clip_bounds() {
                  extra = match extra.intersection(clip) {
                    Some(r) => r,
                    None => Rect::ZERO,
                  };
                }
                extra.intersection(self.canvas.bounds())
              } else {
                None
              };
              if let Some(extra) =
                extra_bounds.filter(|rect| rect.width() > 0.0 && rect.height() > 0.0)
              {
                merged = merged.union(extra);
              }

              allocation_bounds = Some(merged);
              layer_bounds = Some(merged);
            } else {
              // If we fail to compute safe projective bounds, fall back to the previous unbounded
              // allocation behavior rather than risking cropped warps.
              allocation_bounds = None;
            }
          }
        }

        let (bounded_rect, layer_origin) = if needs_layer {
          let origin = allocation_bounds
            .map(|rect| (rect.min_x().floor() as i32, rect.min_y().floor() as i32))
            .unwrap_or((0, 0));
          (allocation_bounds, origin)
        } else {
          (None, (0, 0))
        };
        // Non-isolated blend groups must initialize their group surface from the already-painted
        // backdrop *only* when they contain descendant backdrop-sensitive effects (mix-blend-mode
        // or backdrop-filter). Leaf blend-mode elements can render into a transparent group
        // surface and blend against the parent at composite time, avoiding ambiguous
        // out==backdrop uncompositing when the source happens to match the backdrop.
        let init_from_backdrop = !is_isolated
          && !matches!(item.mix_blend_mode, BlendMode::Normal)
          && item.has_backdrop_sensitive_descendants;
        let needs_unclipped_layer = !scaled_filters.is_empty() || has_backdrop;
        if needs_layer {
          if manual_blend.is_some() {
            if let Some(layer_rect) = bounded_rect {
              if init_from_backdrop {
                if needs_unclipped_layer {
                  self
                    .canvas
                    .push_layer_bounded_unclipped_initialized_from_backdrop_and_backdrop_root(
                      opacity,
                      None,
                      layer_rect,
                      is_backdrop_root,
                    )?;
                } else {
                  self
                    .canvas
                    .push_layer_bounded_initialized_from_backdrop_and_backdrop_root(
                      opacity,
                      None,
                      layer_rect,
                      is_backdrop_root,
                    )?;
                }
                self.push_layer_mutation_state();
              } else if needs_unclipped_layer {
                self.push_layer_bounded_unclipped_tracked(
                  opacity,
                  None,
                  layer_rect,
                  is_backdrop_root,
                )?;
              } else {
                self.push_layer_bounded_tracked(opacity, None, layer_rect, is_backdrop_root)?;
              }
            } else if init_from_backdrop {
              self
                .canvas
                .push_layer_with_blend_initialized_from_backdrop_and_backdrop_root(
                  opacity,
                  None,
                  is_backdrop_root,
                )?;
              self.push_layer_mutation_state();
            } else {
              self.push_layer_tracked(opacity, is_backdrop_root)?;
            }
          } else {
            let blend = map_blend_mode(item.mix_blend_mode);
            if let Some(layer_rect) = bounded_rect {
              if init_from_backdrop {
                if needs_unclipped_layer {
                  self
                    .canvas
                    .push_layer_bounded_unclipped_initialized_from_backdrop_and_backdrop_root(
                      opacity,
                      Some(blend),
                      layer_rect,
                      is_backdrop_root,
                    )?;
                } else {
                  self
                    .canvas
                    .push_layer_bounded_initialized_from_backdrop_and_backdrop_root(
                      opacity,
                      Some(blend),
                      layer_rect,
                      is_backdrop_root,
                    )?;
                }
                self.push_layer_mutation_state();
              } else if needs_unclipped_layer {
                self.push_layer_bounded_unclipped_tracked(
                  opacity,
                  Some(blend),
                  layer_rect,
                  is_backdrop_root,
                )?;
              } else {
                self.push_layer_bounded_tracked(
                  opacity,
                  Some(blend),
                  layer_rect,
                  is_backdrop_root,
                )?;
              }
            } else if init_from_backdrop {
              self
                .canvas
                .push_layer_with_blend_initialized_from_backdrop_and_backdrop_root(
                  opacity,
                  Some(blend),
                  is_backdrop_root,
                )?;
              self.push_layer_mutation_state();
            } else {
              self.push_layer_with_blend_tracked(opacity, Some(blend), is_backdrop_root)?;
            }
          }
          self.record_layer_allocation(self.canvas.width(), self.canvas.height());
          // CSS `filter` / `backdrop-filter` effects are applied to the stacking context's output
          // before ancestor clips (e.g. `overflow:hidden`) are applied. If we inherit the ancestor
          // clip while painting into the offscreen layer, kernel-based filters like blur will treat
          // the clip edge as transparent and produce incorrect results near the boundary.
          //
          // Clear the inherited clip when a filter effect is present so descendants can paint into
          // the halo region we allocated in `stacking_layer_bounds`.
          if projective_transform.is_some() || needs_unclipped_layer {
            self.canvas.clear_clip();
          }
        } else {
          self.canvas.save();
        }

        let layer_transform_for_canvas = local_skia_transform.map(|t| {
          let mut layer_transform = concat_transforms(parent_transform, t);
          if needs_layer && layer_origin != (0, 0) {
            layer_transform = concat_transforms(
              Transform::from_translate(-(layer_origin.0 as f32), -(layer_origin.1 as f32)),
              layer_transform,
            );
          }
          layer_transform
        });
        let clip_transform = layer_transform_for_canvas.unwrap_or_else(|| self.canvas.transform());
        let clip = (needs_layer
          && projective_transform.is_none()
          && transform_requires_transformed_clip(clip_transform, radii))
        .then_some(TransformedClipRect {
          rect: bounds,
          transform: clip_transform,
        });
        // Non-isolated group surfaces may be lazily initialized from backdrop once a descendant
        // `mix-blend-mode` operation needs it (see `maybe_init_non_isolated_group_backdrop`).
        self.stacking_layers.push(StackingRecord {
          establishes_backdrop_root: is_backdrop_root,
          needs_layer,
          canvas_layer_depth: self.canvas.layer_stack_len(),
          is_isolated,
          mix_blend_mode: item.mix_blend_mode,
          init_from_backdrop,
          filters: scaled_filters,
          radii,
          bounds,
          mask_bounds,
          mask,
          mask_border,
          css_bounds,
          manual_blend,
          layer_bounds,
          layer_origin,
          global_transform_3d: painting_transform_3d,
          projective_transform,
          projective_warp_bounds,
          parent_transform,
          warp_source_transform: combined_transform,
          clip,
          culled: false,
          pending_backdrop,
        });
        if projective_transform.is_some() {
          self.projective_warp_depth = self.projective_warp_depth.saturating_add(1);
        }

        if let Some(layer_transform) = layer_transform_for_canvas {
          self.canvas.set_transform(layer_transform);
        }

        if self.trace_backdrop_stack {
          let depth_after = self.canvas.layer_stack_len();
          let init_from_backdrop = self
            .stacking_layers
            .last()
            .is_some_and(|record| record.init_from_backdrop);
          eprintln!(
            "backdrop_stack push_sc backdrop_root={} needs_layer={} mix_blend_mode={:?} init_from_backdrop={} canvas_layers={} -> {} stacking_depth={} -> {}",
            is_backdrop_root,
            needs_layer,
            item.mix_blend_mode,
            init_from_backdrop,
            canvas_layer_depth_before,
            depth_after,
            stacking_depth_before,
            stacking_depth_before + 1
          );
        }
      }
      DisplayItem::PopStackingContext => {
        let canvas_layer_depth_before = self.canvas.layer_stack_len();
        let stacking_depth_before = self.stacking_layers.len();
        let record = self
          .stacking_layers
          .pop()
          .unwrap_or_else(|| StackingRecord {
            establishes_backdrop_root: false,
            needs_layer: false,
            canvas_layer_depth: 0,
            is_isolated: false,
            mix_blend_mode: BlendMode::Normal,
            init_from_backdrop: false,
            filters: Vec::new(),
            radii: BorderRadii::ZERO,
            bounds: Rect::ZERO,
            mask_bounds: Rect::ZERO,
            mask: None,
            mask_border: None,
            css_bounds: Rect::ZERO,
            manual_blend: None,
            layer_bounds: None,
            layer_origin: (0, 0),
            global_transform_3d: Transform3D::identity(),
            projective_transform: None,
            projective_warp_bounds: None,
            parent_transform: Transform::identity(),
            warp_source_transform: Transform::identity(),
            clip: None,
            culled: false,
            pending_backdrop: None,
          });

        let _ = self.transform_stack.pop();
        let _ = self.perspective_stack.pop();
        if record.projective_transform.is_some() {
          self.projective_warp_depth = self.projective_warp_depth.saturating_sub(1);
        }
        if record.culled {
          if self.culled_depth > 0 {
            self.culled_depth -= 1;
          }
          return Ok(());
        }

        if self.trace_backdrop_stack {
          let depth_after = canvas_layer_depth_before.saturating_sub(record.needs_layer as usize);
          eprintln!(
            "backdrop_stack pop_sc backdrop_root={} needs_layer={} mix_blend_mode={:?} init_from_backdrop={} canvas_layers={} -> {} stacking_depth={} -> {}",
            record.establishes_backdrop_root,
            record.needs_layer,
            record.mix_blend_mode,
            record.init_from_backdrop,
            canvas_layer_depth_before,
            depth_after,
            stacking_depth_before,
            stacking_depth_before.saturating_sub(1)
          );
        }

        if self.trace_backdrop_stack && !matches!(record.mix_blend_mode, BlendMode::Normal) {
          // The mix-blend-mode backdrop is the Backdrop Root Image in the element's parent surface.
          // Mirror `Canvas::fill_backdrop_root_region` so traces show the same root→parent scoping
          // as `backdrop-filter`.
          let (root_depth, parent_depth) = backdrop_root_range(self.canvas.layer_stack());
          eprintln!(
            "backdrop_stack composite_mix_blend mode={:?} range={}..{} composite_allocated={}",
            record.mix_blend_mode, root_depth, parent_depth, false
          );
        }
        if record.needs_layer {
          let (mut layer, origin, opacity, composite_blend) = self.pop_layer_raw_tracked()?;

          // Convert geometric filter parameters (e.g. drop-shadow offsets) from the element's local
          // coordinate system into the pixmap coordinate space the filter is executed in. The
          // pixmap already includes the stacking context's current canvas transform, so without
          // this conversion filters would behave differently depending on whether the subtree was
          // rendered via affine transforms or the projective-warp path.
          let filters_for_effects =
            transform_filters_for_pixmap_space(&record.filters, record.warp_source_transform);
          let (out_l, out_t, out_r, out_b) =
            filter_outset_with_bounds(&filters_for_effects, self.scale, Some(record.css_bounds))
              .as_tuple();

          let mut effect_bounds = record.layer_bounds;
          if effect_bounds.is_none() {
            let expanded_bounds = Rect::from_xywh(
              record.mask_bounds.x() - out_l,
              record.mask_bounds.y() - out_t,
              record.mask_bounds.width() + out_l + out_r,
              record.mask_bounds.height() + out_t + out_b,
            );
            if expanded_bounds.width() > 0.0 && expanded_bounds.height() > 0.0 {
              effect_bounds = Some(expanded_bounds);
            }
          }

          let layer_region =
            effect_bounds.and_then(|rect| self.layer_space_bounds(rect, origin, &layer));

          if let Some(mask_style) = record.mask.as_ref() {
            if let Some(mask) = self.render_mask(mask_style)? {
              let OffsetMask {
                mask,
                origin: mask_origin,
              } = mask;
              let applied = apply_mask_with_offset(&mut layer, origin, &mask, mask_origin)?;
              // Don't overwrite the reusable scratch with the 1x1 all-transparent sentinel mask;
              // that case is common for fully clipped masks and would otherwise destroy the
              // allocation we want to reuse for subsequent (larger) masks.
              if mask.width() > 1 || mask.height() > 1 {
                MASK_RENDER_SCRATCH.with(|cell| {
                  *cell.borrow_mut() = Some(mask);
                });
              }
              if !applied {
                return Ok(());
              }
            }
          }

          if let Some(mask_border) = record.mask_border.as_ref() {
            if let Some(mask) =
              self.render_mask_border(mask_border, record.warp_source_transform)?
            {
              let OffsetMask {
                mask,
                origin: mask_origin,
              } = mask;
              let applied = apply_mask_with_offset(&mut layer, origin, &mask, mask_origin)?;
              if mask.width() > 1 || mask.height() > 1 {
                MASK_RENDER_SCRATCH.with(|cell| {
                  *cell.borrow_mut() = Some(mask);
                });
              }
              if !applied {
                return Ok(());
              }
            }
          }

          if !record.filters.is_empty() {
            let bbox = Rect::from_xywh(
              record.mask_bounds.x() - origin.0 as f32,
              record.mask_bounds.y() - origin.1 as f32,
              record.mask_bounds.width(),
              record.mask_bounds.height(),
            );
            let needs_svg_background = record.filters.iter().any(|filter| match filter {
              ResolvedFilter::SvgFilter(filter) => filter.uses_background_inputs(),
              _ => false,
            });
            let backdrop = needs_svg_background.then(|| self.canvas.pixmap_ref());
            let blur_cache: &mut (dyn BlurCacheOps + 'static) =
              match self.shared_blur_cache.as_mut() {
                Some(shared) => shared,
                None => &mut self.blur_cache,
              };
            apply_filters_scoped(
              &mut layer,
              &filters_for_effects,
              self.scale,
              bbox,
              layer_region.as_ref(),
              Some(blur_cache),
              backdrop,
              origin,
            )?;
          }

          // Clamp filtered output to the filter region (expanded by `filter_outset_with_bounds`) to
          // avoid bleed from pixels that landed outside the intended output bounds.
          //
          // This must be an axis-aligned rect clamp: `border-radius` does *not* create an implicit
          // clip for stacking-context descendants when `overflow` is visible.
          if !record.filters.is_empty() {
            let clip_rect = Rect::from_xywh(
              record.mask_bounds.x() - out_l,
              record.mask_bounds.y() - out_t,
              record.mask_bounds.width() + out_l + out_r,
              record.mask_bounds.height() + out_t + out_b,
            );
            if let Some(local_clip) = self.layer_space_bounds(clip_rect, origin, &layer) {
              hard_clip_pixmap_outside_rect_rgba(&mut layer, local_clip)?;
            }
          }

          // Ancestor clips (`overflow:hidden`, etc.) are applied after filter effects, but the
          // canvas can represent rectangular clips as bounds-only (no per-pixel mask) for
          // performance. `Canvas::composite_layer` only applies the mask, so explicitly hard-clip
          // the layer output to the active clip bounds in that case.
          if self.canvas.clip_mask().is_none() {
            if let Some(clip_bounds) = self.canvas.clip_bounds() {
              if let Some(local_clip) = self.layer_space_bounds(clip_bounds, origin, &layer) {
                hard_clip_pixmap_outside_rect_rgba(&mut layer, local_clip)?;
              } else {
                return Ok(());
              }
            }
          }

          if let Some(projective_transform) = record.projective_transform {
            let base_bounds = record.projective_warp_bounds.unwrap_or(record.css_bounds);
            let warp_bounds = if record.filters.is_empty() {
              base_bounds
            } else {
              let (out_l, out_t, out_r, out_b) =
                filter_outset_with_bounds(&record.filters, 1.0, Some(record.css_bounds)).as_tuple();
              let expanded = Rect::from_xywh(
                base_bounds.x() - out_l,
                base_bounds.y() - out_t,
                base_bounds.width() + out_l + out_r,
                base_bounds.height() + out_t + out_b,
              );
              if expanded.width() > 0.0 && expanded.height() > 0.0 {
                expanded
              } else {
                base_bounds
              }
            };

            let corners = [
              (warp_bounds.min_x(), warp_bounds.min_y()),
              (warp_bounds.max_x(), warp_bounds.min_y()),
              (warp_bounds.max_x(), warp_bounds.max_y()),
              (warp_bounds.min_x(), warp_bounds.max_y()),
            ];
            let mut src_quad = [Point::ZERO; 4];
            let mut dst_quad_points = [Point::ZERO; 4];
            let mut dst_quad = [(0.0f32, 0.0f32); 4];
            let mut valid = true;

            for (i, (x, y)) in corners.iter().enumerate() {
              let sx = *x * self.scale;
              let sy = *y * self.scale;
              let src_x = sx * record.warp_source_transform.sx
                + sy * record.warp_source_transform.kx
                + record.warp_source_transform.tx;
              let src_y = sx * record.warp_source_transform.ky
                + sy * record.warp_source_transform.sy
                + record.warp_source_transform.ty;
              src_quad[i] = Point::new(src_x - origin.0 as f32, src_y - origin.1 as f32);

              let (tx, ty, _tz, tw) = projective_transform.transform_point(*x, *y, 0.0);
              if !tw.is_finite()
                || tw.abs() < 1e-6
                || tw < 0.0
                || !tx.is_finite()
                || !ty.is_finite()
              {
                valid = false;
                break;
              }
              let px = (tx / tw) * self.scale;
              let py = (ty / tw) * self.scale;
              let dst_x = px * record.parent_transform.sx
                + py * record.parent_transform.kx
                + record.parent_transform.tx;
              let dst_y = px * record.parent_transform.ky
                + py * record.parent_transform.sy
                + record.parent_transform.ty;
              if !dst_x.is_finite() || !dst_y.is_finite() {
                valid = false;
                break;
              }
              dst_quad[i] = (dst_x, dst_y);
              dst_quad_points[i] = Point::new(dst_x, dst_y);
            }
            let warped = if valid {
              Homography::from_quad_to_quad(src_quad, dst_quad_points)
                .map(|homography| self.projective_warp(&layer, &homography, &dst_quad, None, true))
                .transpose()
                .map_err(Error::Render)?
                .flatten()
            } else {
              None
            };

            if let Some(warped) = warped {
              if let Some(mode) = record.manual_blend {
                self.composite_manual_layer(&warped.pixmap, opacity, mode, warped.offset, None)?;
              } else {
                let mut paint = PixmapPaint::default();
                paint.opacity = opacity;
                paint.blend_mode = composite_blend.unwrap_or(self.canvas.blend_mode());
                self.canvas.with_mirrored_pixmap_mut(|pixmap| {
                  pixmap.draw_pixmap(
                    warped.offset.0,
                    warped.offset.1,
                    warped.pixmap.as_ref(),
                    &paint,
                    Transform::identity(),
                    None,
                  );
                });
              }
            } else if let Some(mode) = record.manual_blend {
              if let Some(mask) = self.canvas.clip_mask_rc() {
                let applied = apply_mask_with_offset(&mut layer, origin, mask.as_ref(), (0, 0))?;
                if !applied {
                  return Ok(());
                }
              }
              self.composite_manual_layer(&layer, opacity, mode, origin, effect_bounds.as_ref())?;
            } else {
              self.composite_layer_tracked(&layer, opacity, composite_blend, origin);
            }
          } else if let Some(mode) = record.manual_blend {
            if let Some(mask) = self.canvas.clip_mask_rc() {
              let applied = apply_mask_with_offset(&mut layer, origin, mask.as_ref(), (0, 0))?;
              if !applied {
                return Ok(());
              }
            }
            self.composite_manual_layer(&layer, opacity, mode, origin, effect_bounds.as_ref())?;
          } else {
            self.composite_layer_tracked(&layer, opacity, composite_blend, origin);
          }
        } else {
          self.canvas.restore();
        }
      }
      DisplayItem::PushBackfaceVisibility(visibility) => {
        if matches!(visibility, BackfaceVisibility::Hidden) {
          let current_transform = *self
            .transform_stack
            .last()
            .unwrap_or(&Transform3D::identity());
          if backface_is_hidden(&current_transform) {
            self.culled_depth = 1;
            return Ok(());
          }
        }
      }
      DisplayItem::PopBackfaceVisibility => {}
      DisplayItem::PushClip(clip) => self.push_clip(clip)?,
      DisplayItem::PopClip => self.pop_clip(),
      DisplayItem::PushOpacity(OpacityItem { opacity }) => {
        let canvas_layer_depth_before = self
          .trace_backdrop_stack
          .then(|| self.canvas.layer_stack_len());
        let is_backdrop_root = *opacity < 1.0 - f32::EPSILON;
        let clip_bounds = self.canvas.clip_bounds().filter(|bounds| {
          bounds.x().is_finite()
            && bounds.y().is_finite()
            && bounds.width().is_finite()
            && bounds.height().is_finite()
        });
        let has_clip_bounds = clip_bounds.is_some();
        let layer_bounds = clip_bounds
          .and_then(|bounds| bounds.intersection(self.canvas.bounds()))
          .filter(|bounds| bounds.width() > 0.0 && bounds.height() > 0.0);
        if let Some(bounds) = layer_bounds {
          self.push_layer_bounded_tracked(*opacity, None, bounds, is_backdrop_root)?;
        } else if has_clip_bounds {
          // Clip rect exists but does not cover any pixels in the current canvas. Avoid allocating a
          // full-size opacity layer for a fully clipped subtree; a minimal placeholder layer keeps
          // stack bookkeeping intact.
          self.push_layer_bounded_tracked(
            *opacity,
            None,
            Rect::from_xywh(0.0, 0.0, 1.0, 1.0),
            is_backdrop_root,
          )?;
        } else {
          self.push_layer_tracked(*opacity, is_backdrop_root)?;
        }
        self.record_layer_allocation(self.canvas.width(), self.canvas.height());
        self.opacity_stack.push(OpacityRecord {
          canvas_layer_depth: self.canvas.layer_stack_len(),
          init_from_backdrop: false,
          is_backdrop_root,
        });
        if self.trace_backdrop_stack {
          let depth_after = self.canvas.layer_stack_len();
          eprintln!(
            "backdrop_stack push_opacity opacity={} backdrop_root={} canvas_layers={} -> {}",
            opacity,
            is_backdrop_root,
            canvas_layer_depth_before.unwrap_or(depth_after),
            depth_after
          );
        }
      }
      DisplayItem::PopOpacity => {
        let (canvas_layer_depth_before, backdrop_root) = if self.trace_backdrop_stack {
          (
            self.canvas.layer_stack_len(),
            self
              .canvas
              .layer_stack()
              .last()
              .is_some_and(|record| record.is_backdrop_root),
          )
        } else {
          (0, false)
        };
        let _opacity_record = self.opacity_stack.pop().unwrap_or_default();
        self.pop_layer_tracked()?;
        if self.trace_backdrop_stack {
          let depth_after = self.canvas.layer_stack_len();
          eprintln!(
            "backdrop_stack pop_opacity backdrop_root={} canvas_layers={} -> {}",
            backdrop_root, canvas_layer_depth_before, depth_after
          );
        }
      }
      DisplayItem::PushTransform(transform) => {
        let parent = *self
          .transform_stack
          .last()
          .unwrap_or(&Transform3D::identity());
        let combined = parent.multiply(&transform.transform);
        self.transform_stack.push(combined);
        self.push_transform(transform);
      }
      DisplayItem::PopTransform => {
        let _ = self.transform_stack.pop();
        self.canvas.restore();
      }
      DisplayItem::PushBlendMode(mode) => {
        let canvas_layer_depth_before = self
          .trace_backdrop_stack
          .then(|| self.canvas.layer_stack_len());
        let is_backdrop_root = !matches!(mode.mode, BlendMode::Normal);
        let clip_bounds = self.canvas.clip_bounds().filter(|bounds| {
          bounds.x().is_finite()
            && bounds.y().is_finite()
            && bounds.width().is_finite()
            && bounds.height().is_finite()
        });
        let has_clip_bounds = clip_bounds.is_some();
        let layer_bounds = clip_bounds
          .and_then(|bounds| bounds.intersection(self.canvas.bounds()))
          .filter(|bounds| bounds.width() > 0.0 && bounds.height() > 0.0);
        if is_manual_blend(mode.mode) {
          if let Some(bounds) = layer_bounds {
            self.push_layer_bounded_tracked(1.0, None, bounds, is_backdrop_root)?;
          } else if has_clip_bounds {
            self.push_layer_bounded_tracked(
              1.0,
              None,
              Rect::from_xywh(0.0, 0.0, 1.0, 1.0),
              is_backdrop_root,
            )?;
          } else {
            self.push_layer_tracked(1.0, is_backdrop_root)?;
          }
        } else {
          let blend = map_blend_mode(mode.mode);
          if let Some(bounds) = layer_bounds {
            self.push_layer_bounded_tracked(1.0, Some(blend), bounds, is_backdrop_root)?;
          } else if has_clip_bounds {
            self.push_layer_bounded_tracked(
              1.0,
              Some(blend),
              Rect::from_xywh(0.0, 0.0, 1.0, 1.0),
              is_backdrop_root,
            )?;
          } else {
            self.push_layer_with_blend_tracked(1.0, Some(blend), is_backdrop_root)?;
          }
        }
        self.record_layer_allocation(self.canvas.width(), self.canvas.height());
        self.blend_stack.push(mode.mode);

        if self.trace_backdrop_stack {
          let depth_after = self.canvas.layer_stack_len();
          eprintln!(
            "backdrop_stack push_blend_mode mode={:?} backdrop_root={} canvas_layers={} -> {}",
            mode.mode,
            is_backdrop_root,
            canvas_layer_depth_before.unwrap_or(depth_after),
            depth_after
          );
        }
      }
      DisplayItem::PopBlendMode => {
        let mode = self.blend_stack.pop().unwrap_or_default();
        let trace_range = self.trace_backdrop_stack.then(|| {
          let layer_stack = self.canvas.layer_stack();
          let (root_depth, parent_depth) = backdrop_root_range(layer_stack);
          let depth_before = layer_stack.len();
          (root_depth, parent_depth, depth_before)
        });

        if is_manual_blend(mode) {
          let (layer, origin, opacity, _) = self.pop_layer_raw_tracked()?;
          let region = self.canvas.clip_bounds();
          self.composite_manual_layer(&layer, opacity, mode, origin, region.as_ref())?;
        } else {
          self.pop_layer_tracked()?;
        }

        if let Some((root_depth, parent_depth, depth_before)) = trace_range {
          let depth_after = self.canvas.layer_stack_len();
          eprintln!(
            "backdrop_stack pop_blend_mode mode={:?} range={}..{} canvas_layers={} -> {} composite_allocated={}",
            mode,
            root_depth,
            parent_depth,
            depth_before,
            depth_after,
            false
          );
        }
      }
    }

    Ok(())
  }

  fn render_text(&mut self, item: &TextItem) -> Result<()> {
    let Some(font) = self.resolve_font(item.font_id.as_ref(), item.font.as_ref()) else {
      return Err(
        RenderError::RasterizationFailed {
          reason: "Unable to resolve font for display list text".into(),
        }
        .into(),
      );
    };

    if !item.shadows.is_empty() {
      self.render_text_shadows(&font, item)?;
    }

    self.canvas.draw_text_run_with_stroke_and_font_smoothing(
      item.origin,
      &item.glyphs,
      &font,
      item.font_size,
      item.scale,
      item.rotation,
      item.allow_subpixel_aa,
      item.color,
      item.stroke_width,
      item.stroke_color,
      item.synthetic_bold,
      item.synthetic_oblique,
      item.palette_index,
      item.palette_overrides.as_slice(),
      item.palette_override_hash,
      &item.variations,
      item.font_smoothing,
      item.text_rendering,
    )?;
    if let Some(emphasis) = &item.emphasis {
      self.render_emphasis(emphasis, item.allow_subpixel_aa, item.text_rendering)?;
    }
    Ok(())
  }

  fn render_list_marker(&mut self, item: &ListMarkerItem) -> Result<()> {
    if let Some(bg) = item.background {
      let bounds = crate::paint::display_list::list_marker_bounds(item);
      self.canvas.draw_rect(bounds, bg);
    }

    let text = TextItem {
      origin: item.origin,
      cached_bounds: item.cached_bounds,
      glyphs: item.glyphs.clone(),
      color: item.color,
      allow_subpixel_aa: item.allow_subpixel_aa,
      stroke_width: item.stroke_width,
      stroke_color: item.stroke_color,
      font_smoothing: item.font_smoothing,
      text_rendering: item.text_rendering,
      palette_index: item.palette_index,
      palette_overrides: item.palette_overrides.clone(),
      palette_override_hash: item.palette_override_hash,
      rotation: item.rotation,
      scale: item.scale,
      shadows: item.shadows.clone(),
      font_size: item.font_size,
      advance_width: item.advance_width,
      font_id: item.font_id.clone(),
      font: item.font.clone(),
      variations: item.variations.clone(),
      synthetic_bold: item.synthetic_bold,
      synthetic_oblique: item.synthetic_oblique,
      emphasis: item.emphasis.clone(),
      decorations: Vec::new(),
      ..Default::default()
    };
    self.render_text(&text)
  }

  fn render_text_decoration(
    &mut self,
    item: &crate::paint::display_list::TextDecorationItem,
  ) -> Result<()> {
    if item.decorations.is_empty() || item.line_width <= 0.0 {
      return Ok(());
    }

    let inline_vertical = item.inline_vertical;
    let inline_start = item.line_start;
    let inline_len = item.line_width;
    let clip = self.canvas.clip_mask_rc();
    let transform = self.canvas.transform();
    let blend_mode = self.canvas.blend_mode();
    let axis_aligned_transform = Self::is_translation_only_transform(transform);

    let draw_solid_line = |pixmap: &mut PixmapMut<'_>,
                           paint: &tiny_skia::Paint,
                           start: f32,
                           len: f32,
                           center: f32,
                           thickness: f32| {
      if thickness <= 0.0 || len <= 0.0 {
        return;
      }
      const NEAR_INTEGER_EPSILON_PX: f32 = 1e-3;

      // Match Chrome's device-pixel snapping for solid text decoration strokes.
      //
      // In practice Chrome snaps the decoration thickness to whole device pixels and aligns the
      // decoration's *outer edge* (top edge for horizontal underlines) to the device pixel grid.
      // Without snapping, a nominally-1px underline can be anti-aliased across two device rows when
      // font metrics land on fractional coordinates (e.g. rust-lang.org, si.edu).
      //
      // Restrict snapping to axis-aligned transforms (identity / translation-only) so we don't
      // distort decorations under rotation/skew/scale transforms.
      let (center, thickness) =
        if axis_aligned_transform && center.is_finite() && thickness.is_finite() {
          let snapped_thickness = thickness.floor().max(1.0);
          // Use the *pre-snap* thickness to compute the decoration's outer edge; this matches
          // Chrome and avoids snapping one device pixel too far "inside" the text when the authored
          // thickness is fractional (e.g. 1.8px).
          let raw_edge = center - thickness * 0.5;
          if raw_edge.is_finite() {
            let cross_translation = if inline_vertical {
              transform.tx
            } else {
              transform.ty
            };
            // Chrome aligns decoration strokes by rounding to the nearest device pixel edge. Using
            // `floor()` consistently biases underlines upward and shows up as a 1px offset in
            // Chrome-vs-FastRender diffs on pages with many links (e.g. lite.cnn.com).
            let snapped_edge = (raw_edge + cross_translation).round() - cross_translation;
            (snapped_edge + snapped_thickness * 0.5, snapped_thickness)
          } else {
            (center, thickness)
          }
        } else {
          (center, thickness)
        };

      let rect = if inline_vertical {
        tiny_skia::Rect::from_xywh(center - thickness * 0.5, start, thickness, len)
      } else {
        tiny_skia::Rect::from_xywh(start, center - thickness * 0.5, len, thickness)
      };
      if let Some(rect) = rect {
        if axis_aligned_transform {
          let tx_round = transform.tx.round();
          let ty_round = transform.ty.round();
          if (transform.tx - tx_round).abs() <= NEAR_INTEGER_EPSILON_PX
            && (transform.ty - ty_round).abs() <= NEAR_INTEGER_EPSILON_PX
          {
            // When tiny-skia applies a floating-point translation, axis-aligned rectangles can end
            // up slightly off the device grid due to float noise (visible as blurry 1px lines).
            // If the current transform is a near-integer translation, apply that translation to
            // the rect and draw with an identity transform so the rasterizer sees device-space
            // coordinates directly.
            if let Some(device_rect) = tiny_skia::Rect::from_xywh(
              rect.x() + tx_round,
              rect.y() + ty_round,
              rect.width(),
              rect.height(),
            ) {
              let path = PathBuilder::from_rect(device_rect);
              pixmap.fill_path(
                &path,
                paint,
                tiny_skia::FillRule::Winding,
                Transform::identity(),
                clip.as_deref(),
              );
              return;
            }
          }
        }

        let path = PathBuilder::from_rect(rect);
        pixmap.fill_path(
          &path,
          paint,
          tiny_skia::FillRule::Winding,
          transform,
          clip.as_deref(),
        );
      }
    };

    let draw_stroked_line = |pixmap: &mut PixmapMut<'_>,
                              paint: &tiny_skia::Paint,
                              segment_start: f32,
                              start: f32,
                              len: f32,
                              center: f32,
                              thickness: f32,
                              dash: Option<Vec<f32>>,
                              round: bool| {
      let mut path = PathBuilder::new();
      if inline_vertical {
        path.move_to(center, start);
        path.line_to(center, start + len);
      } else {
        path.move_to(start, center);
        path.line_to(start + len, center);
      }
      let Some(path) = path.finish() else { return };

      let mut stroke = Stroke::default();
      stroke.width = thickness;
      stroke.line_cap = if round {
        tiny_skia::LineCap::Round
      } else {
        tiny_skia::LineCap::Butt
      };
      if let Some(arr) = dash {
        let offset = dash_offset_for_segment(&arr, segment_start);
        stroke.dash = tiny_skia::StrokeDash::new(arr, offset);
      }

      pixmap.stroke_path(&path, paint, &stroke, transform, clip.as_deref());
    };

    let draw_wavy_line = |pixmap: &mut PixmapMut<'_>,
                          paint: &tiny_skia::Paint,
                          segment_start: f32,
                          start: f32,
                          len: f32,
                          center: f32,
                          thickness: f32| {
      if thickness <= 0.0 || len <= 0.0 {
        return;
      }
      let wavelength = (thickness * 4.0).max(6.0);
      let amplitude = (thickness * 0.75).max(thickness * 0.5);

      if !wavelength.is_finite() || wavelength <= 0.0 || !segment_start.is_finite() {
        return;
      }

      let lerp = |a: (f32, f32), b: (f32, f32), t: f32| -> (f32, f32) {
        (a.0 + (b.0 - a.0) * t, a.1 + (b.1 - a.1) * t)
      };

      let split_quadratic = |p0: (f32, f32),
                             p1: (f32, f32),
                             p2: (f32, f32),
                             t: f32|
       -> (
        ((f32, f32), (f32, f32), (f32, f32)),
        ((f32, f32), (f32, f32), (f32, f32)),
      ) {
        let p01 = lerp(p0, p1, t);
        let p12 = lerp(p1, p2, t);
        let p0112 = lerp(p01, p12, t);
        ((p0, p01, p0112), (p0112, p12, p2))
      };

      let point_on_quadratic = |p0: (f32, f32), p1: (f32, f32), p2: (f32, f32), t: f32| {
        let p01 = lerp(p0, p1, t);
        let p12 = lerp(p1, p2, t);
        lerp(p01, p12, t)
      };

      let quadratic_subsegment = |p0: (f32, f32),
                                  p1: (f32, f32),
                                  p2: (f32, f32),
                                  t0: f32,
                                  t1: f32|
       -> ((f32, f32), (f32, f32), (f32, f32)) {
        if t0 <= 0.0 && t1 >= 1.0 {
          return (p0, p1, p2);
        }
        let (left, _) = split_quadratic(p0, p1, p2, t1);
        if t0 <= 0.0 {
          return left;
        }
        let u = if t1 > 0.0 {
          (t0 / t1).clamp(0.0, 1.0)
        } else {
          0.0
        };
        let (_, right) = split_quadratic(left.0, left.1, left.2, u);
        right
      };

      let wave_points_for_cursor =
        |cursor: f32, up: bool| -> ((f32, f32), (f32, f32), (f32, f32)) {
          let sign = if up { -1.0 } else { 1.0 };
          if inline_vertical {
            (
              (center, cursor),
              (center + sign * amplitude, cursor + wavelength * 0.5),
              (center, cursor + wavelength),
            )
          } else {
            (
              (cursor, center),
              (cursor + wavelength * 0.5, center + sign * amplitude),
              (cursor + wavelength, center),
            )
          }
        };

      let (cursor_start, mut up) = wavy_phase_for_segment(wavelength, segment_start);
      // `cursor_start` is relative to the decoration's start (inline_start); convert to
      // absolute coords so it can be compared to `start`.
      let mut cursor = inline_start + cursor_start;
      let end_pos = start + len;

      // Position the path at the correct point along the wave, even when the segment starts mid
      // "wavelength" (e.g. when skip-ink introduces a gap).
      let (p0, p1, p2) = wave_points_for_cursor(cursor, up);
      let t0 = ((start - cursor) / wavelength).clamp(0.0, 1.0);
      let (sx, sy) = point_on_quadratic(p0, p1, p2, t0);
      let mut path = PathBuilder::new();
      path.move_to(sx, sy);

      while cursor < end_pos {
        let wave_end = cursor + wavelength;
        let draw_start = start.max(cursor);
        let draw_end = end_pos.min(wave_end);
        if draw_end <= draw_start {
          // Advance to the next wave segment if this one ends before the visible segment begins.
          cursor = wave_end;
          up = !up;
          continue;
        }

        let (p0, p1, p2) = wave_points_for_cursor(cursor, up);
        let t0 = ((draw_start - cursor) / wavelength).clamp(0.0, 1.0);
        let t1 = ((draw_end - cursor) / wavelength).clamp(0.0, 1.0);
        if t1 > t0 {
          let (_q0, q1, q2) = quadratic_subsegment(p0, p1, p2, t0, t1);
          path.quad_to(q1.0, q1.1, q2.0, q2.1);
        }

        if draw_end >= end_pos {
          break;
        }
        cursor = wave_end;
        up = !up;
      }

      if let Some(path) = path.finish() {
        let mut stroke = Stroke::default();
        stroke.width = thickness.max(0.5);
        stroke.line_cap = tiny_skia::LineCap::Round;
        pixmap.stroke_path(&path, paint, &stroke, transform, clip.as_deref());
      }
    };

    let render_line = |pixmap: &mut PixmapMut<'_>,
                       paint: &tiny_skia::Paint,
                       style: TextDecorationStyle,
                       segment_start: f32,
                       start: f32,
                       len: f32,
                       center: f32,
                       thickness: f32| match style {
      TextDecorationStyle::Solid => draw_solid_line(pixmap, paint, start, len, center, thickness),
      TextDecorationStyle::Double => {
        let line_thickness = (thickness * 0.7).max(0.5);
        let gap = line_thickness.max(thickness * 0.6);
        draw_solid_line(
          pixmap,
          paint,
          start,
          len,
          center - (gap * 0.5),
          line_thickness,
        );
        draw_solid_line(
          pixmap,
          paint,
          start,
          len,
          center + (gap * 0.5),
          line_thickness,
        );
      }
      TextDecorationStyle::Dotted => {
        draw_stroked_line(
          pixmap,
          paint,
          segment_start,
          start,
          len,
          center,
          thickness,
          Some(vec![thickness, thickness]),
          true,
        );
      }
      TextDecorationStyle::Dashed => {
        draw_stroked_line(
          pixmap,
          paint,
          segment_start,
          start,
          len,
          center,
          thickness,
          Some(vec![3.0 * thickness, thickness]),
          false,
        );
      }
      TextDecorationStyle::Wavy => {
        draw_wavy_line(pixmap, paint, segment_start, start, len, center, thickness)
      }
    };

    self.canvas.with_mirrored_pixmap_mut(|pixmap| {
      for deco in &item.decorations {
        let mut paint = tiny_skia::Paint::default();
        paint.anti_alias = true;
        let alpha = (deco.color.a * 255.0).round().clamp(0.0, 255.0) as u8;
        paint.set_color_rgba8(deco.color.r, deco.color.g, deco.color.b, alpha);
        paint.blend_mode = blend_mode;

        if let Some(underline) = &deco.underline {
          if let Some(segments) = &underline.segments {
            for (start, end) in segments {
              let len = end - start;
              if len <= 0.0 {
                continue;
              }
              render_line(
                pixmap,
                &paint,
                deco.style,
                *start,
                inline_start + *start,
                len,
                underline.center,
                underline.thickness,
              );
            }
          } else {
            render_line(
              pixmap,
              &paint,
              deco.style,
              0.0,
              inline_start,
              inline_len,
              underline.center,
              underline.thickness,
            );
          }
        }

        if let Some(overline) = &deco.overline {
          if let Some(segments) = &overline.segments {
            for (start, end) in segments {
              let len = end - start;
              if len <= 0.0 {
                continue;
              }
              render_line(
                pixmap,
                &paint,
                deco.style,
                *start,
                inline_start + *start,
                len,
                overline.center,
                overline.thickness,
              );
            }
          } else {
            render_line(
              pixmap,
              &paint,
              deco.style,
              0.0,
              inline_start,
              inline_len,
              overline.center,
              overline.thickness,
            );
          }
        }

        if let Some(strike) = &deco.line_through {
          if let Some(segments) = &strike.segments {
            for (start, end) in segments {
              let len = end - start;
              if len <= 0.0 {
                continue;
              }
              render_line(
                pixmap,
                &paint,
                deco.style,
                *start,
                inline_start + *start,
                len,
                strike.center,
                strike.thickness,
              );
            }
          } else {
            render_line(
              pixmap,
              &paint,
              deco.style,
              0.0,
              inline_start,
              inline_len,
              strike.center,
              strike.thickness,
            );
          }
        }
      }
    });

    Ok(())
  }

  fn text_shadow_bounds(&self, font: &LoadedFont, item: &TextItem) -> PathBounds {
    let mut bounds = PathBounds::new();

    if item.glyphs.is_empty() || !item.font_size.is_finite() || item.font_size <= 0.0 {
      return bounds;
    }

    let effective_font_size = item.font_size * item.scale;
    let ascent = effective_font_size;
    let descent = effective_font_size * 0.25;

    // Prefer per-glyph bounding boxes from the parsed face; unlike outline extraction, this does
    // not require walking the glyph outline for each glyph.
    //
    // For variable fonts, apply the item's variation coordinates so bbox-based bounds match the
    // outlines used during rasterization.
    let face = crate::text::face_cache::get_ttf_face(font).map(|cached| {
      let mut face = cached.clone_face();
      if !item.variations.is_empty() {
        let variations: Vec<Variation> = item
          .variations
          .iter()
          .map(|v| Variation {
            tag: v.tag,
            value: v.value(),
          })
          .collect();
        crate::text::variations::apply_rustybuzz_variations(&mut face, &variations);
      }
      face
    });
    let face = face.as_ref();

    let is_color_font = face.is_some_and(crate::text::font_db::face_has_color_tables);
    let (scale, has_bbox) = if let Some(face) = face {
      let units_per_em = face.units_per_em() as f32;
      if units_per_em > 0.0 && units_per_em.is_finite() {
        // COLR/bitmap/SVG color glyphs frequently have an empty "base" glyph bounding box (the
        // actual painted bounds come from color layers). Using those bboxes can drastically
        // under-estimate the shadow surface size, which in turn causes color glyph rasterization
        // to be rejected by safety limits (yielding empty shadows). Fall back to conservative
        // advance/ascent bounds for color fonts.
        (effective_font_size / units_per_em, !is_color_font)
      } else {
        (0.0, false)
      }
    } else {
      (0.0, false)
    };

    let mut cursor_x = item.origin.x;
    let mut cursor_y = 0.0_f32;
    let skew = if item.synthetic_oblique.is_finite() {
      item.synthetic_oblique
    } else {
      0.0
    };

    let rotation =
      crate::paint::text_rasterize::rotation_transform(item.rotation, item.origin.x, item.origin.y);

    for glyph in &item.glyphs {
      let glyph_x = cursor_x + glyph.x_offset;
      let glyph_y = item.origin.y + cursor_y + glyph.y_offset;

      if has_bbox {
        if let (Some(face), Ok(glyph_id)) =
          (face, u16::try_from(glyph.glyph_id).map(ttf_parser::GlyphId))
        {
          if let Some(bbox) = face.glyph_bounding_box(glyph_id) {
            let corners = [
              (bbox.x_min as f32, bbox.y_min as f32),
              (bbox.x_min as f32, bbox.y_max as f32),
              (bbox.x_max as f32, bbox.y_min as f32),
              (bbox.x_max as f32, bbox.y_max as f32),
            ];
            for (px, py) in corners {
              let mut x = glyph_x + (px + skew * py) * scale;
              let mut y = glyph_y - py * scale;
              if let Some(t) = rotation {
                let rx = x * t.sx + y * t.kx + t.tx;
                let ry = x * t.ky + y * t.sy + t.ty;
                x = rx;
                y = ry;
              }
              bounds.min_x = bounds.min_x.min(x);
              bounds.max_x = bounds.max_x.max(x);
              bounds.min_y = bounds.min_y.min(y);
              bounds.max_y = bounds.max_y.max(y);
            }
          } else {
            let x0 = glyph_x.min(glyph_x + glyph.x_advance);
            let x1 = glyph_x.max(glyph_x + glyph.x_advance);
            let y0 = glyph_y - ascent;
            let y1 = glyph_y + descent;
            let corners = [(x0, y0), (x0, y1), (x1, y0), (x1, y1)];
            for (mut x, mut y) in corners {
              if let Some(t) = rotation {
                let rx = x * t.sx + y * t.kx + t.tx;
                let ry = x * t.ky + y * t.sy + t.ty;
                x = rx;
                y = ry;
              }
              bounds.min_x = bounds.min_x.min(x);
              bounds.max_x = bounds.max_x.max(x);
              bounds.min_y = bounds.min_y.min(y);
              bounds.max_y = bounds.max_y.max(y);
            }
          }
        }
      } else {
        let x0 = glyph_x.min(glyph_x + glyph.x_advance);
        let x1 = glyph_x.max(glyph_x + glyph.x_advance);
        let y0 = glyph_y - ascent;
        let y1 = glyph_y + descent;
        let corners = [(x0, y0), (x0, y1), (x1, y0), (x1, y1)];
        for (mut x, mut y) in corners {
          if let Some(t) = rotation {
            let rx = x * t.sx + y * t.kx + t.tx;
            let ry = x * t.ky + y * t.sy + t.ty;
            x = rx;
            y = ry;
          }
          bounds.min_x = bounds.min_x.min(x);
          bounds.max_x = bounds.max_x.max(x);
          bounds.min_y = bounds.min_y.min(y);
          bounds.max_y = bounds.max_y.max(y);
        }
      }

      cursor_x += glyph.x_advance;
      cursor_y += glyph.y_advance;
    }

    if !bounds.is_valid() {
      if let Some(rect) = item.cached_bounds {
        bounds.min_x = rect.min_x();
        bounds.min_y = rect.min_y();
        bounds.max_x = rect.max_x();
        bounds.max_y = rect.max_y();
      }
    }

    if bounds.is_valid() {
      let bold_pad = if item.synthetic_bold.is_finite() {
        item.synthetic_bold.abs()
      } else {
        0.0
      };
      let stroke_pad = if item.stroke_width.is_finite() {
        item.stroke_width.abs() * 0.5
      } else {
        0.0
      };
      let oblique_pad = skew.abs() * (ascent + descent);
      let pad_x = bold_pad + stroke_pad + oblique_pad + 1.0;
      let pad_y = bold_pad + stroke_pad + 1.0;
      bounds.min_x -= pad_x;
      bounds.max_x += pad_x;
      bounds.min_y -= pad_y;
      bounds.max_y += pad_y;
    }

    bounds
  }

  fn tint_shadow_pixmap(pixmap: &mut Pixmap, color: Rgba) -> RenderResult<()> {
    let mut deadline_counter = 0usize;
    let r = color.r as u16;
    let g = color.g as u16;
    let b = color.b as u16;

    for px in pixmap.pixels_mut() {
      check_active_periodic(&mut deadline_counter, DEADLINE_STRIDE, RenderStage::Paint)?;
      let a = px.alpha();
      if a == 0 {
        *px = PremultipliedColorU8::TRANSPARENT;
        continue;
      }
      let a16 = a as u16;
      let rp = mul_div_255_round_u16(r, a16) as u8;
      let gp = mul_div_255_round_u16(g, a16) as u8;
      let bp = mul_div_255_round_u16(b, a16) as u8;
      *px =
        PremultipliedColorU8::from_rgba(rp, gp, bp, a).unwrap_or(PremultipliedColorU8::TRANSPARENT);
    }

    Ok(())
  }

  fn render_text_shadows(&mut self, font: &LoadedFont, item: &TextItem) -> Result<()> {
    if item.shadows.is_empty() || item.glyphs.is_empty() {
      return Ok(());
    }

    let bounds = self.text_shadow_bounds(font, item);
    if !bounds.is_valid() {
      return Ok(());
    }

    let opacity = self.canvas.opacity().clamp(0.0, 1.0);
    if opacity == 0.0 {
      return Ok(());
    }

    let glyph_positions: Vec<GlyphPosition> = item
      .glyphs
      .iter()
      .map(|g| GlyphPosition {
        glyph_id: g.glyph_id,
        cluster: g.cluster,
        x_offset: g.x_offset,
        y_offset: g.y_offset,
        x_advance: g.x_advance,
        y_advance: g.y_advance,
      })
      .collect();
    let variations: Vec<Variation> = item
      .variations
      .iter()
      .map(|v| Variation {
        tag: v.tag,
        value: v.value(),
      })
      .collect();
    let rotation =
      crate::paint::text_rasterize::rotation_transform(item.rotation, item.origin.x, item.origin.y);

    let mut rasterizer = TextRasterizer::with_caches(
      self.glyph_cache.clone(),
      self.color_renderer.clone(),
      self.color_cache.clone(),
    );

    for shadow in &item.shadows {
      let blur_margin = (shadow.blur_radius.abs() * 3.0).ceil();
      let shadow_min_x = bounds.min_x + shadow.offset.x - blur_margin;
      let shadow_max_x = bounds.max_x + shadow.offset.x + blur_margin;
      let shadow_min_y = bounds.min_y + shadow.offset.y - blur_margin;
      let shadow_max_y = bounds.max_y + shadow.offset.y + blur_margin;

      let shadow_width = (shadow_max_x - shadow_min_x).ceil().max(0.0) as u32;
      let shadow_height = (shadow_max_y - shadow_min_y).ceil().max(0.0) as u32;
      if shadow_width == 0 || shadow_height == 0 {
        continue;
      }

      let mut shadow_pixmap =
        match new_pixmap_with_context(shadow_width, shadow_height, "text shadow") {
          Ok(pixmap) => pixmap,
          Err(err) => {
            // Render-control failures (deadline/budget) must bubble up; a cancelled render must not
            // silently continue just because text shadows are best-effort.
            if matches!(
              &err,
              RenderError::Timeout { .. }
                | RenderError::StageMemoryBudgetExceeded { .. }
                | RenderError::StageAllocationBudgetExceeded { .. }
            ) {
              return Err(Error::Render(err));
            }
            continue;
          }
        };
      self.record_layer_allocation(shadow_width, shadow_height);

      let translate_x = -bounds.min_x + blur_margin;
      let translate_y = -bounds.min_y + blur_margin;
      let state = TextRenderState {
        transform: Transform::from_translate(translate_x, translate_y),
        opacity,
        blend_mode: SkiaBlendMode::SourceOver,
        clip_mask: None,
        allow_subpixel_aa: item.allow_subpixel_aa,
        font_smoothing: item.font_smoothing,
        text_rendering: item.text_rendering,
      };

      // Ignore text rasterizer failures so shadows don't prevent painting the rest of the scene.
      // However, render-control failures should always bubble up so paint-stage cancellation doesn't
      // get silently ignored.
      let stroke = (item.stroke_width > 0.0 && item.stroke_color.a > 0.0).then_some(
        crate::paint::text_rasterize::TextStroke {
          width: item.stroke_width,
          color: shadow.color,
        },
      );
      match rasterizer.render_glyph_run_with_stroke(
        &glyph_positions,
        font,
        item.font_size * item.scale,
        item.synthetic_bold,
        item.synthetic_oblique,
        item.palette_index,
        item.palette_overrides.as_slice(),
        item.palette_override_hash,
        &variations,
        rotation,
        item.origin.x,
        item.origin.y,
        shadow.color,
        stroke,
        state,
        &mut shadow_pixmap,
      ) {
        Ok(_) => {}
        Err(
          err @ Error::Render(
            RenderError::Timeout { .. }
            | RenderError::StageMemoryBudgetExceeded { .. }
            | RenderError::StageAllocationBudgetExceeded { .. },
          ),
        ) => return Err(err),
        Err(_) => continue,
      }

      Self::tint_shadow_pixmap(&mut shadow_pixmap, shadow.color)?;

      if shadow.blur_radius > 0.0 {
        apply_gaussian_blur_cached(
          &mut shadow_pixmap,
          shadow.blur_radius,
          shadow.blur_radius,
          Some(self.blur_cache_mut()),
          1.0,
        )?;
      }

      let dest_x = shadow_min_x.floor() as i32;
      let dest_y = shadow_min_y.floor() as i32;
      let frac_x = shadow_min_x - dest_x as f32;
      let frac_y = shadow_min_y - dest_y as f32;
      let pixmap_paint = tiny_skia::PixmapPaint {
        opacity: 1.0,
        blend_mode: self.canvas.blend_mode(),
        ..Default::default()
      };
      let clip = self.canvas.clip_mask_rc();
      let transform =
        Transform::from_translate(frac_x, frac_y).post_concat(self.canvas.transform());
      self.canvas.with_mirrored_pixmap_mut(|pixmap| {
        pixmap.draw_pixmap(
          dest_x,
          dest_y,
          shadow_pixmap.as_ref(),
          &pixmap_paint,
          transform,
          clip.as_deref(),
        );
      });
    }

    Ok(())
  }

  fn render_emphasis(
    &mut self,
    emphasis: &TextEmphasis,
    allow_subpixel_aa: bool,
    text_rendering: crate::style::types::TextRendering,
  ) -> Result<()> {
    if emphasis.marks.is_empty() {
      return Ok(());
    }

    let inline_vertical = emphasis.inline_vertical;
    if let TextEmphasisStyle::String(_) = emphasis.style {
      if let Some(text) = &emphasis.text {
        let mut fonts = Vec::with_capacity(text.runs.len());
        for run in &text.runs {
          let font = self
            .resolve_font(run.font_id.as_ref(), run.font.as_ref())
            .ok_or_else(|| RenderError::RasterizationFailed {
              reason: "Unable to resolve font for emphasis string".into(),
            })?;
          fonts.push(font);
        }
        for mark in &emphasis.marks {
          let mark_origin = if inline_vertical {
            Point::new(
              mark.center.x - text.height * 0.5 + text.baseline_offset,
              mark.center.y - text.width * 0.5,
            )
          } else {
            Point::new(
              mark.center.x - text.width * 0.5,
              mark.center.y - text.height * 0.5 + text.baseline_offset,
            )
          };
          let mut pen = 0.0_f32;
          for (run, font) in text.runs.iter().zip(fonts.iter()) {
            let run_origin = if inline_vertical {
              Point::new(mark_origin.x, mark_origin.y + pen)
            } else {
              Point::new(mark_origin.x + pen, mark_origin.y)
            };
            self.canvas.draw_text_run(
              run_origin,
              &run.glyphs,
              &font,
              run.font_size,
              1.0,
              crate::text::pipeline::RunRotation::None,
              allow_subpixel_aa,
              emphasis.color,
              run.synthetic_bold,
              run.synthetic_oblique,
              run.palette_index,
              run.palette_overrides.as_slice(),
              run.palette_override_hash,
              &run.variations,
              text_rendering,
            )?;
            pen += run.advance_width;
          }
        }
        return Ok(());
      }
    }

    let mut paint = tiny_skia::Paint::default();
    paint.anti_alias = true;
    let alpha = (emphasis.color.a * self.canvas.opacity() * 255.0)
      .round()
      .clamp(0.0, 255.0) as u8;
    paint.set_color_rgba8(emphasis.color.r, emphasis.color.g, emphasis.color.b, alpha);
    paint.blend_mode = self.canvas.blend_mode();
    let transform = self.canvas.transform();
    let clip = self.canvas.clip_mask_rc();

    let (fill, shape) = match &emphasis.style {
      TextEmphasisStyle::Mark { fill, shape } => {
        let shape = shape.unwrap_or_else(|| {
          if inline_vertical {
            TextEmphasisShape::Sesame
          } else {
            TextEmphasisShape::Circle
          }
        });
        (*fill, shape)
      }
      _ => return Ok(()),
    };

    for mark in &emphasis.marks {
      match shape {
        TextEmphasisShape::Dot => {
          let radius = emphasis.size * 0.5;
          if let Some(path) =
            tiny_skia::PathBuilder::from_circle(mark.center.x, mark.center.y, radius)
          {
            match fill {
              TextEmphasisFill::Filled => {
                self.canvas.with_mirrored_pixmap_mut(|pixmap| {
                  pixmap.fill_path(
                    &path,
                    &paint,
                    tiny_skia::FillRule::EvenOdd,
                    transform,
                    clip.as_deref(),
                  );
                });
              }
              TextEmphasisFill::Open => {
                let mut stroke = tiny_skia::Stroke::default();
                stroke.width = (emphasis.size * 0.18).max(0.5);
                self.canvas.with_mirrored_pixmap_mut(|pixmap| {
                  pixmap.stroke_path(&path, &paint, &stroke, transform, clip.as_deref());
                });
              }
            }
          }
        }
        TextEmphasisShape::Circle => {
          let radius = emphasis.size * 0.5;
          if let Some(path) =
            tiny_skia::PathBuilder::from_circle(mark.center.x, mark.center.y, radius)
          {
            match fill {
              TextEmphasisFill::Filled => {
                self.canvas.with_mirrored_pixmap_mut(|pixmap| {
                  pixmap.fill_path(
                    &path,
                    &paint,
                    tiny_skia::FillRule::EvenOdd,
                    transform,
                    clip.as_deref(),
                  );
                });
              }
              TextEmphasisFill::Open => {
                let mut stroke = tiny_skia::Stroke::default();
                stroke.width = (emphasis.size * 0.18).max(0.5);
                self.canvas.with_mirrored_pixmap_mut(|pixmap| {
                  pixmap.stroke_path(&path, &paint, &stroke, transform, clip.as_deref());
                });
              }
            }
          }
        }
        TextEmphasisShape::DoubleCircle => {
          let mut stroke = tiny_skia::Stroke::default();
          stroke.width = (emphasis.size * 0.14).max(0.5);
          let radii = [emphasis.size * 0.5, emphasis.size * 0.33];
          for radius in radii {
            if let Some(path) =
              tiny_skia::PathBuilder::from_circle(mark.center.x, mark.center.y, radius)
            {
              self.canvas.with_mirrored_pixmap_mut(|pixmap| {
                pixmap.stroke_path(&path, &paint, &stroke, transform, clip.as_deref());
              });
            }
          }
        }
        TextEmphasisShape::Triangle => {
          let half = emphasis.size * 0.5;
          let height = emphasis.size * 0.9;
          let mut builder = tiny_skia::PathBuilder::new();
          let apex_y = mark.center.y - height * 0.5;
          let base_y = mark.center.y + height * 0.5;
          builder.move_to(mark.center.x, apex_y);
          builder.line_to(mark.center.x - half, base_y);
          builder.line_to(mark.center.x + half, base_y);
          builder.close();
          if let Some(path) = builder.finish() {
            match fill {
              TextEmphasisFill::Filled => {
                self.canvas.with_mirrored_pixmap_mut(|pixmap| {
                  pixmap.fill_path(
                    &path,
                    &paint,
                    tiny_skia::FillRule::EvenOdd,
                    transform,
                    clip.as_deref(),
                  );
                });
              }
              TextEmphasisFill::Open => {
                let mut stroke = tiny_skia::Stroke::default();
                stroke.width = (emphasis.size * 0.18).max(0.5);
                self.canvas.with_mirrored_pixmap_mut(|pixmap| {
                  pixmap.stroke_path(&path, &paint, &stroke, transform, clip.as_deref());
                });
              }
            }
          }
        }
        TextEmphasisShape::Sesame => {
          let len = emphasis.size * 0.75;
          let angle = 20.0_f32.to_radians();
          let dx = (angle.cos() * len * 0.5, angle.sin() * len * 0.5);
          let mut builder = tiny_skia::PathBuilder::new();
          builder.move_to(mark.center.x - dx.0, mark.center.y - dx.1);
          builder.line_to(mark.center.x + dx.0, mark.center.y + dx.1);
          if let Some(path) = builder.finish() {
            let mut stroke = tiny_skia::Stroke::default();
            stroke.width = (emphasis.size * 0.2).max(0.6);
            stroke.line_cap = tiny_skia::LineCap::Round;
            self.canvas.with_mirrored_pixmap_mut(|pixmap| {
              pixmap.stroke_path(&path, &paint, &stroke, transform, clip.as_deref());
            });
          }
        }
      }
    }

    Ok(())
  }

  fn render_image(&mut self, item: &ImageItem) -> Result<()> {
    // Some pixmap backends have historically failed to respect nested clip masks when drawing
    // images. To keep `overflow: hidden` robust for replaced elements, opportunistically crop the
    // image to the current clip bounds when no transform is active.
    let mut clipped_item: Option<ImageItem> = None;
    let item = if self.canvas.transform() == Transform::identity() {
      if let Some(clip_device) = self.canvas.clip_bounds() {
        if self.scale.is_finite() && self.scale > 0.0 {
          let inv_scale = 1.0 / self.scale;
          let clip_css = Rect::from_xywh(
            clip_device.x() * inv_scale,
            clip_device.y() * inv_scale,
            clip_device.width() * inv_scale,
            clip_device.height() * inv_scale,
          );
          // When both the clip and the image are axis-aligned and unscaled (1:1), we snap their
          // origins to integer device pixels. `clip_css` is already derived from the snapped clip
          // bounds, but the image snap happens later once the pixmap is resolved. Use the snapped
          // image origin here when deciding whether we need the overflow-hidden cropping fallback,
          // otherwise we'd incorrectly think only part of the image is visible and introduce
          // unintended scaling.
          let dest_css = if item.src_rect.is_none()
            && Self::is_near_integer(clip_device.width())
            && Self::is_near_integer(clip_device.height())
            && Self::is_near_integer(clip_device.x())
            && Self::is_near_integer(clip_device.y())
          {
            let dest_device = self.ds_rect(item.dest_rect);
            let src_w = item.image.width as f32;
            let src_h = item.image.height as f32;
            if src_w > 0.0
              && src_h > 0.0
              && src_w.is_finite()
              && src_h.is_finite()
              && dest_device.width().is_finite()
              && dest_device.height().is_finite()
            {
              let scale_x = dest_device.width() / src_w;
              let scale_y = dest_device.height() / src_h;
              if (scale_x - 1.0).abs() <= 1e-6 && (scale_y - 1.0).abs() <= 1e-6 {
                let snapped = Self::snap_rect_origin_to_device_pixels(dest_device);
                Rect::from_xywh(
                  snapped.x() * inv_scale,
                  snapped.y() * inv_scale,
                  item.dest_rect.width(),
                  item.dest_rect.height(),
                )
              } else {
                item.dest_rect
              }
            } else {
              item.dest_rect
            }
          } else {
            item.dest_rect
          };
          let Some(visible_css) = dest_css.intersection(clip_css) else {
            return Ok(());
          };
          if visible_css != dest_css {
            let dest_w = dest_css.width();
            let dest_h = dest_css.height();
            let src_w = item.image.width as f32;
            let src_h = item.image.height as f32;
            if dest_w > 0.0 && dest_h > 0.0 && src_w > 0.0 && src_h > 0.0 {
              let base_src = item
                .src_rect
                .unwrap_or_else(|| Rect::from_xywh(0.0, 0.0, src_w, src_h));

              let rel_x0 = (visible_css.min_x() - dest_css.min_x()) / dest_w;
              let rel_y0 = (visible_css.min_y() - dest_css.min_y()) / dest_h;
              let rel_x1 = (visible_css.max_x() - dest_css.min_x()) / dest_w;
              let rel_y1 = (visible_css.max_y() - dest_css.min_y()) / dest_h;

              let rel_x0 = rel_x0.clamp(0.0, 1.0);
              let rel_y0 = rel_y0.clamp(0.0, 1.0);
              let rel_x1 = rel_x1.clamp(0.0, 1.0);
              let rel_y1 = rel_y1.clamp(0.0, 1.0);

              let src_x = base_src.x() + rel_x0 * base_src.width();
              let src_y = base_src.y() + rel_y0 * base_src.height();
              let src_w = (rel_x1 - rel_x0) * base_src.width();
              let src_h = (rel_y1 - rel_y0) * base_src.height();

              if src_x.is_finite()
                && src_y.is_finite()
                && src_w.is_finite()
                && src_h.is_finite()
                && src_w > 0.0
                && src_h > 0.0
              {
                clipped_item = Some(ImageItem {
                  dest_rect: visible_css,
                  image: item.image.clone(),
                  filter_quality: item.filter_quality,
                  src_rect: Some(Rect::from_xywh(src_x, src_y, src_w, src_h)),
                });
              }
            }
          }
        }
      }
      clipped_item.as_ref().unwrap_or(item)
    } else {
      item
    };

    // When an image is scaled with linear sampling, tiny floating-point drift in the destination
    // rectangle (e.g. `0.05px` instead of `0px`) can shift sampling phase and produce large diffs.
    //
    // If the rect is *already* very close to integer device pixels, snap it so the resample uses
    // the stable integer-aligned phase.
    let mut snapped_item: Option<ImageItem> = None;
    if item.filter_quality == ImageFilterQuality::Linear
      && item.src_rect.is_none()
      && self.scale.is_finite()
      && self.scale > 0.0
    {
      let transform = self.canvas.transform();
      if transform == Transform::identity()
        || (Self::is_translation_only_transform(transform)
          && Self::is_near_integer(transform.tx)
          && Self::is_near_integer(transform.ty))
      {
        let dest_device = self.ds_rect(item.dest_rect);
        let src_w = item.image.width as f32;
        let src_h = item.image.height as f32;
        if src_w > 0.0
          && src_h > 0.0
          && src_w.is_finite()
          && src_h.is_finite()
          && dest_device.width().is_finite()
          && dest_device.height().is_finite()
        {
          let scale_x = dest_device.width() / src_w;
          let scale_y = dest_device.height() / src_h;
          let scaled_draw = (scale_x - 1.0).abs() > 1e-6 || (scale_y - 1.0).abs() > 1e-6;
          if scaled_draw {
            // Fractional CSS layout often produces values that are very close to device pixels
            // (e.g. `34.944px` instead of `35px`). Preserving those tiny errors can shift bilinear
            // sampling phase and produce large diffs across photo-heavy regions.
            //
            // Snap the destination rect to the device pixel grid when either its edges or its
            // origin+size are close to integer pixels. Do this per-axis so we can snap the
            // horizontal phase without forcing a vertical snap (and vice versa).
            const SNAP_EPSILON: f32 = 0.125;
            if let Some(snapped_device) =
              Self::snap_rect_to_near_integer_edges_or_size(dest_device, SNAP_EPSILON)
            {
              let inv_scale = 1.0 / self.scale;
              let mut snapped = item.clone();
              snapped.dest_rect = Rect::from_xywh(
                snapped_device.x() * inv_scale,
                snapped_device.y() * inv_scale,
                snapped_device.width() * inv_scale,
                snapped_device.height() * inv_scale,
              );
              snapped_item = Some(snapped);
            }
          }
        }
      }
    }

    let item = snapped_item.as_ref().unwrap_or(item);

    let mut dest_rect = self.ds_rect(item.dest_rect);
    if self.canvas.apply_clip(dest_rect).is_none() {
      return Ok(());
    }

    let background_timer = item
      .src_rect
      .is_some()
      .then(|| {
        self
          .background_paint_diagnostics
          .as_ref()
          .map(|_| Instant::now())
      })
      .flatten();

    // When a scaled image is drawn with a fractional device-pixel phase (either a subpixel
    // translation/non-integer size *or* a fractional `src_rect` crop common with
    // `background-size: cover/contain`), tiny-skia's internal sampling differs slightly from
    // Skia/Chrome and can produce large "everything is off by 1" diffs across photo-heavy regions.
    //
    // To improve fidelity, pre-rasterize a device-pixel-aligned pixmap for these draws (encoding the
    // sampling phase into the resample) and then draw it 1:1 with an integer translation.
    if item.filter_quality == ImageFilterQuality::Linear {
      let canvas_transform = self.canvas.transform();
      if canvas_transform == Transform::identity()
        || (Self::is_translation_only_transform(canvas_transform)
          && canvas_transform.tx.is_finite()
          && canvas_transform.ty.is_finite())
      {
        let device_rect = transform_rect(dest_rect, &canvas_transform);

        if device_rect.x().is_finite()
          && device_rect.y().is_finite()
          && device_rect.width().is_finite()
          && device_rect.height().is_finite()
          && device_rect.width() > 0.0
          && device_rect.height() > 0.0
        {
          let dest_aligned = Self::is_near_integer(device_rect.x())
            && Self::is_near_integer(device_rect.y())
            && Self::is_near_integer(device_rect.max_x())
            && Self::is_near_integer(device_rect.max_y());
          // `None` means "use the full decoded image", which is always pixel-aligned.
          let src_aligned = item.src_rect.is_none()
            || item.src_rect.is_some_and(|src_rect| {
              Self::is_near_integer(src_rect.x())
                && Self::is_near_integer(src_rect.y())
                && Self::is_near_integer(src_rect.width())
                && Self::is_near_integer(src_rect.height())
            });

          // Pre-rasterize when the destination edges are not pixel-aligned (fractional rect) or
          // when the source rect is fractional (e.g. `background-size: cover`), since tiny-skia's
          // sampling differs from Skia/Chrome in those phase-sensitive cases.
          let clip_snapped_to_device_pixels = self.canvas.clip_bounds().is_some_and(|clip| {
            Self::is_near_integer(clip.x())
              && Self::is_near_integer(clip.y())
              && Self::is_near_integer(clip.width())
              && Self::is_near_integer(clip.height())
          });
          let unscaled_draw = item.src_rect.is_none()
            && device_rect.width().is_finite()
            && device_rect.height().is_finite()
            && (device_rect.width() - item.image.width as f32).abs() <= 1e-6
            && (device_rect.height() - item.image.height as f32).abs() <= 1e-6;
          // When we can snap a 1:1 draw to an integer clip rect, prefer snapping over the
          // phase-aware pre-rasterization path so the image lands on the same pixel grid as the
          // clip mask.
          let can_snap_to_clip = unscaled_draw && clip_snapped_to_device_pixels;
          if (!dest_aligned || !src_aligned) && !can_snap_to_clip {
            let origin_x = (device_rect.x() - 0.5).ceil();
            let origin_y = (device_rect.y() - 0.5).ceil();
            let max_x = (device_rect.x() + device_rect.width() - 0.5).ceil();
            let max_y = (device_rect.y() + device_rect.height() - 0.5).ceil();
            if origin_x.is_finite()
              && origin_y.is_finite()
              && max_x.is_finite()
              && max_y.is_finite()
              && max_x > origin_x
              && max_y > origin_y
            {
              let out_w = (max_x - origin_x).round() as u32;
              let out_h = (max_y - origin_y).round() as u32;
              let (src_w, src_h) = if let Some(src_rect) = item.src_rect {
                let src_w = src_rect.width().ceil().max(0.0);
                let src_h = src_rect.height().ceil().max(0.0);
                if !(src_w.is_finite()
                  && src_h.is_finite()
                  && src_w <= u32::MAX as f32
                  && src_h <= u32::MAX as f32)
                {
                  // Invalid source rect; skip the phase-aware fast path and fall back to
                  // `image_to_pixmap` below, which already guards against bad inputs.
                  (0, 0)
                } else {
                  (src_w as u32, src_h as u32)
                }
              } else {
                (item.image.width, item.image.height)
              };
              // `should_use_scaled_image_pixmap` is tuned for *cached* scaled pixmaps to avoid
              // exploding memory usage for near-identity resizes. This phase-aware path is not
              // cached, and exists primarily for fidelity: tiny-skia's bilinear sampling can drift
              // from Skia/Chrome even for modest resizes when the destination rect is fractional
              // (common with `object-fit: cover` crops).
              //
              // Be more aggressive than the cached path, but cap by output pixel count to keep the
              // per-draw CPU/memory bounded.
              let target_pixels = u64::from(out_w).saturating_mul(u64::from(out_h));
              // This fidelity path pre-rasterizes a temporary pixmap, so it needs a hard cap to
              // avoid allocating enormous buffers for pathological pages. The default fixture
              // viewport (1040x1240) is ~1.29M pixels though, so we allow modestly more than 1M to
              // ensure large `background-size: cover` images with fractional `src_rect`s don't
              // fall back to tiny-skia's shader sampling (which can diverge significantly from
              // Chrome/Skia on some inputs).
              const PHASE_AWARE_RASTER_MAX_PIXELS: u64 = 2 * 1024 * 1024;
              let should_phase_rasterize =
                target_pixels > 0 && target_pixels <= PHASE_AWARE_RASTER_MAX_PIXELS;
              if Self::should_use_scaled_image_pixmap(
                item.filter_quality,
                src_w,
                src_h,
                out_w,
                out_h,
              ) || should_phase_rasterize
              {
                let diag = self.image_pixmap_diagnostics.as_ref();
                if let Some(diag) = diag {
                  diag.record_miss();
                }
                let timer = diag.map(|_| Instant::now());

                let pixmap = match item.src_rect {
                  None => image_data_to_scaled_pixmap_with_phase_inner(
                    &item.image,
                    device_rect,
                    out_w,
                    out_h,
                    origin_x,
                    origin_y,
                  )?,
                  Some(src_rect) => image_data_to_scaled_pixmap_from_src_rect_with_phase_inner(
                    &item.image,
                    src_rect,
                    device_rect,
                    out_w,
                    out_h,
                    origin_x,
                    origin_y,
                  )?,
                };

                let Some(pixmap) = pixmap else {
                  return Ok(());
                };

                if let (Some(diag), Some(start)) = (diag, timer) {
                  diag.record_duration(start.elapsed());
                }

                let paint = tiny_skia::PixmapPaint {
                  opacity: self.canvas.opacity(),
                  blend_mode: self.canvas.blend_mode(),
                  quality: FilterQuality::Nearest,
                };
                let clip_mask = self.canvas.clip_mask().cloned();
                let local_x = origin_x - canvas_transform.tx;
                let local_y = origin_y - canvas_transform.ty;
                let transform =
                  Transform::from_translate(local_x, local_y).post_concat(canvas_transform);
                self.canvas.with_mirrored_pixmap_mut(|dest| {
                  dest.draw_pixmap(0, 0, pixmap.as_ref(), &paint, transform, clip_mask.as_ref());
                });
                self.record_background_paint(background_timer);
                return Ok(());
              }
            }
          }
        }
      }
    }

    if let Some((pixmap, x, y)) =
      self.maybe_rasterize_linear_image_to_device_pixels(item, dest_rect)?
    {
      // The pixmap has already been sampled onto the final device-pixel grid, so we only need a
      // 1:1 nearest-neighbour blit here.
      let opacity = self.canvas.opacity();
      let blend_mode = self.canvas.blend_mode();
      let clip_mask = self.canvas.clip_mask_rc();
      let pixmap_ref = pixmap.as_ref();
      self.canvas.with_mirrored_pixmap_mut(|dest| {
        composite_layer_into_pixmap_mut(
          dest,
          pixmap_ref,
          opacity,
          blend_mode,
          (x, y),
          clip_mask.as_deref(),
        );
      });
      self.record_background_paint(background_timer);
      return Ok(());
    }
    let Some(pixmap) = self.image_to_pixmap(item)? else {
      return Ok(());
    };

    if dest_rect.width() <= 0.0 || dest_rect.height() <= 0.0 {
      return Ok(());
    }

    if matches!(item.filter_quality, ImageFilterQuality::Nearest)
      && (dest_rect.width() > pixmap.width() as f32 || dest_rect.height() > pixmap.height() as f32)
    {
      let (snapped_w, offset_x) =
        crate::paint::painter::snap_upscale(dest_rect.width(), pixmap.width() as f32)
          .unwrap_or_else(|| (dest_rect.width(), 0.0));
      let (snapped_h, offset_y) =
        crate::paint::painter::snap_upscale(dest_rect.height(), pixmap.height() as f32)
          .unwrap_or_else(|| (dest_rect.height(), 0.0));
      dest_rect = Rect::from_xywh(
        dest_rect.x() + offset_x,
        dest_rect.y() + offset_y,
        snapped_w,
        snapped_h,
      );
    }

    dest_rect = self.maybe_snap_unscaled_image_dest_rect(dest_rect, pixmap.as_ref());

    let paint = tiny_skia::PixmapPaint {
      opacity: self.canvas.opacity(),
      blend_mode: self.canvas.blend_mode(),
      quality: item.filter_quality.into(),
    };

    let full_src_rect = Rect::from_xywh(0.0, 0.0, pixmap.width() as f32, pixmap.height() as f32);
    let src_rect = match item.src_rect {
      // When we return a full-size pixmap (same dimensions as the decoded image), `src_rect` is in
      // that same pixel coordinate space and can be applied directly.
      Some(src_rect)
        if pixmap.width() == item.image.width && pixmap.height() == item.image.height =>
      {
        src_rect
      }
      // When `image_to_pixmap` already baked the crop/scale (e.g. clipped downscales), treat the
      // pixmap itself as the source coordinate space.
      Some(_) => full_src_rect,
      None => full_src_rect,
    };
    if src_rect.width() <= 0.0 || src_rect.height() <= 0.0 {
      return Ok(());
    }

    let scale_x = dest_rect.width() / src_rect.width();
    let scale_y = dest_rect.height() / src_rect.height();
    if !scale_x.is_finite() || !scale_y.is_finite() {
      return Ok(());
    }

    // Map the source rect into the destination rect. This keeps fractional source offsets (from
    // e.g. `background-size: cover`) intact so bilinear filtering matches browser behavior.
    let tx = dest_rect.x() - src_rect.x() * scale_x;
    let ty = dest_rect.y() - src_rect.y() * scale_y;
    let image_transform = Transform::from_row(scale_x, 0.0, 0.0, scale_y, tx, ty);
    // When `src_rect` refers to a sub-rectangle of the image but we are still drawing from the full
    // pixmap (i.e. `image_to_pixmap` didn't crop it), applying the transform directly can paint
    // outside `dest_rect`. Rasterize via a pattern fill constrained to `dest_rect` to avoid image
    // "bleed" into adjacent content.
    let needs_dest_clip = item.src_rect.is_some()
      && ((src_rect.x().abs() > 1e-6)
        || (src_rect.y().abs() > 1e-6)
        || ((src_rect.width() - full_src_rect.width()).abs() > 1e-6)
        || ((src_rect.height() - full_src_rect.height()).abs() > 1e-6));
    let clip_mask = self.canvas.clip_mask_rc();
    let clip = clip_mask.as_deref();
    let pixmap_ref = pixmap.as_ref();
    if needs_dest_clip {
      let Some(skia_rect) = tiny_skia::Rect::from_xywh(
        dest_rect.x(),
        dest_rect.y(),
        dest_rect.width(),
        dest_rect.height(),
      ) else {
        return Ok(());
      };
      let mut fill = tiny_skia::Paint::default();
      fill.shader = Pattern::new(
        pixmap_ref.as_ref(),
        SpreadMode::Pad,
        item.filter_quality.into(),
        self.canvas.opacity(),
        image_transform,
      );
      fill.anti_alias = false;
      fill.blend_mode = self.canvas.blend_mode();

      let transform = self.canvas.transform();
      self.canvas.with_mirrored_pixmap_mut(|dest| {
        dest.fill_rect(skia_rect, &fill, transform, clip);
      });
    } else {
      let canvas_transform = self.canvas.transform();
      // tiny-skia's `draw_pixmap` sampling path can slightly blur image edges even for 1:1 draws
      // when we express the placement as a floating-point translation matrix. Prefer the integer
      // offset fast-path when we can prove this is an axis-aligned 1:1 blit.
      if item.src_rect.is_none()
        && (scale_x - 1.0).abs() <= 1e-6
        && (scale_y - 1.0).abs() <= 1e-6
        && Self::is_translation_only_transform(canvas_transform)
        && Self::is_near_integer(canvas_transform.tx)
        && Self::is_near_integer(canvas_transform.ty)
      {
        let tx = tx + canvas_transform.tx;
        let ty = ty + canvas_transform.ty;
        if tx.is_finite()
          && ty.is_finite()
          && Self::is_near_integer(tx)
          && Self::is_near_integer(ty)
          && tx >= i32::MIN as f32
          && tx <= i32::MAX as f32
          && ty >= i32::MIN as f32
          && ty <= i32::MAX as f32
        {
          let x = tx.round() as i32;
          let y = ty.round() as i32;
          self.canvas.with_mirrored_pixmap_mut(|dest| {
            dest.draw_pixmap(
              x,
              y,
              pixmap_ref.as_ref(),
              &paint,
              Transform::identity(),
              clip,
            );
          });
          self.record_background_paint(background_timer);
          return Ok(());
        }
      }

      let transform = image_transform.post_concat(canvas_transform);
      self.canvas.with_mirrored_pixmap_mut(|dest| {
        dest.draw_pixmap(0, 0, pixmap_ref.as_ref(), &paint, transform, clip);
      });
    }

    self.record_background_paint(background_timer);
    Ok(())
  }

  fn maybe_rasterize_linear_image_to_device_pixels(
    &mut self,
    item: &ImageItem,
    dest_rect_device: Rect,
  ) -> RenderResult<Option<(Arc<Pixmap>, i32, i32)>> {
    // tiny-skia's draw-time bilinear filtering can diverge from Chrome/Skia when the destination
    // rect has a fractional origin or size. That shows up as large page-loop diffs on thumbnail
    // grids (e.g. `arstechnica.com`).
    //
    // For significant downscales, sample directly from `ImageData` into a pixmap whose pixels
    // correspond to the destination device-pixel grid (including subpixel translation/size). We
    // then blit that pixmap with a nearest-neighbour transform so no further sampling happens.
    if item.filter_quality != ImageFilterQuality::Linear {
      return Ok(None);
    }
    let src_rect = item.src_rect;
    let src_rect_is_fractional = src_rect.is_some_and(|src| {
      !(Self::is_near_integer(src.x())
        && Self::is_near_integer(src.y())
        && Self::is_near_integer(src.width())
        && Self::is_near_integer(src.height()))
    });

    let transform = self.canvas.transform();
    if !Self::is_translation_only_transform(transform) {
      return Ok(None);
    }

    if dest_rect_device.width() <= 0.0
      || dest_rect_device.height() <= 0.0
      || !dest_rect_device.x().is_finite()
      || !dest_rect_device.y().is_finite()
      || !dest_rect_device.width().is_finite()
      || !dest_rect_device.height().is_finite()
    {
      return Ok(None);
    }

    let (full_src_w, full_src_h) = (item.image.width, item.image.height);
    if full_src_w == 0 || full_src_h == 0 {
      return Ok(None);
    }

    // Compute the destination rect in device space after applying the current translation-only
    // transform (e.g. tiling offsets).
    let dx0 = dest_rect_device.min_x() + transform.tx;
    let dx1 = dest_rect_device.max_x() + transform.tx;
    let dy0 = dest_rect_device.min_y() + transform.ty;
    let dy1 = dest_rect_device.max_y() + transform.ty;
    if !dx0.is_finite() || !dx1.is_finite() || !dy0.is_finite() || !dy1.is_finite() {
      return Ok(None);
    }

    let min_x = dx0.min(dx1);
    let max_x = dx0.max(dx1);
    let min_y = dy0.min(dy1);
    let max_y = dy0.max(dy1);
    let dest_w = max_x - min_x;
    let dest_h = max_y - min_y;
    if dest_w <= 0.0 || dest_h <= 0.0 || !dest_w.is_finite() || !dest_h.is_finite() {
      return Ok(None);
    }

    // Convert float edges into integer device pixels using the same pixel-center rule as clip mask
    // rasterization.
    let mut x0 = (min_x - 0.5).ceil() as i64;
    let mut y0 = (min_y - 0.5).ceil() as i64;
    let mut x1 = (max_x - 0.5).ceil() as i64;
    let mut y1 = (max_y - 0.5).ceil() as i64;

    let w_i64 = self.canvas.width() as i64;
    let h_i64 = self.canvas.height() as i64;
    x0 = x0.clamp(0, w_i64);
    y0 = y0.clamp(0, h_i64);
    x1 = x1.clamp(0, w_i64);
    y1 = y1.clamp(0, h_i64);
    if x1 <= x0 || y1 <= y0 {
      return Ok(None);
    }

    let out_w = (x1 - x0) as u32;
    let out_h = (y1 - y0) as u32;

    let phase_x = x0 as f32 - min_x;
    let phase_y = y0 as f32 - min_y;
    let needs_bake = !Self::is_near_integer(phase_x)
      || !Self::is_near_integer(phase_y)
      || !Self::is_near_integer(dest_w)
      || !Self::is_near_integer(dest_h);

    // If we're drawing a sub-rect of the image (e.g. `background-size: cover`) and it includes
    // fractional coordinates, we can't safely bake/crop to integer pixel bounds up-front without
    // losing information that affects sampling. We still want to avoid tiny-skia's draw-time
    // bilinear drift vs Chrome/Skia, so pre-rasterize onto the destination device-pixel grid and
    // incorporate the source-rect transform into the sampler's destination mapping.
    //
    // For non-fractional `src_rect`, `image_to_pixmap` already has specialized crop/downscale paths
    // (and caching), so keep those fast paths by only handling the fractional case here.
    let (effective_src_w, effective_src_h) = if src_rect_is_fractional {
      let Some(src) = src_rect else {
        return Ok(None);
      };
      if !(src.width().is_finite()
        && src.height().is_finite()
        && src.width() > 0.0
        && src.height() > 0.0
        && src.x().is_finite()
        && src.y().is_finite())
      {
        return Ok(None);
      }
      (
        src.width().ceil().max(0.0) as u32,
        src.height().ceil().max(0.0) as u32,
      )
    } else {
      (full_src_w, full_src_h)
    };

    let src_pixels = u64::from(effective_src_w).saturating_mul(u64::from(effective_src_h));
    let target_pixels = u64::from(out_w).saturating_mul(u64::from(out_h));
    let should_bake_downscale = Self::should_use_scaled_image_pixmap(
      item.filter_quality,
      effective_src_w,
      effective_src_h,
      out_w,
      out_h,
    );
    // Existing fast path for very small images (icons), where baking is cheap and avoids tiny-skia
    // rounding drift.
    let should_bake_upscale =
      target_pixels > src_pixels && src_pixels <= 64 && target_pixels <= 4096;
    if should_bake_downscale {
      // Keep integer-aligned downscales on the existing cached pixmap path; only bake when subpixel
      // translation/size would diverge.
      if !needs_bake && !src_rect_is_fractional {
        return Ok(None);
      }
    } else if !should_bake_upscale {
      return Ok(None);
    }

    let mut dest_device = Rect::from_xywh(min_x, min_y, dest_w, dest_h);
    if src_rect_is_fractional {
      let Some(src) = src_rect else {
        return Ok(None);
      };
      let scale_x = dest_w / src.width();
      let scale_y = dest_h / src.height();
      if !scale_x.is_finite() || !scale_y.is_finite() {
        return Ok(None);
      }
      let tx = min_x - src.x() * scale_x;
      let ty = min_y - src.y() * scale_y;
      let full_w = full_src_w as f32 * scale_x;
      let full_h = full_src_h as f32 * scale_y;
      if !(tx.is_finite()
        && ty.is_finite()
        && full_w.is_finite()
        && full_h.is_finite()
        && full_w > 0.0
        && full_h > 0.0)
      {
        return Ok(None);
      }
      dest_device = Rect::from_xywh(tx, ty, full_w, full_h);
    }
    let Some(pixmap) = image_data_to_scaled_pixmap_with_phase_inner(
      &item.image,
      dest_device,
      out_w,
      out_h,
      x0 as f32,
      y0 as f32,
    )?
    else {
      return Ok(None);
    };

    Ok(Some((Arc::new(pixmap), x0 as i32, y0 as i32)))
  }

  fn render_image_pattern(&mut self, item: &ImagePatternItem) -> Result<()> {
    let opacity = self.canvas.opacity().clamp(0.0, 1.0);
    if opacity <= 0.0 {
      return Ok(());
    }

    let dest_rect = self.ds_rect(item.dest_rect);
    if self.canvas.apply_clip(dest_rect).is_none() {
      return Ok(());
    }
    if dest_rect.width() <= 0.0 || dest_rect.height() <= 0.0 {
      return Ok(());
    }

    let background_timer = self
      .background_paint_diagnostics
      .as_ref()
      .map(|_| Instant::now());

    let tile_w = self.ds_len(item.tile_size.width);
    let tile_h = self.ds_len(item.tile_size.height);
    if tile_w <= 0.0 || tile_h <= 0.0 {
      return Ok(());
    }

    let canvas_transform = self.canvas.transform();
    let tile_target = transform_rect(Rect::from_xywh(0.0, 0.0, tile_w, tile_h), &canvas_transform);
    let target_w = tile_target.width().ceil().max(1.0) as u32;
    let target_h = tile_target.height().ceil().max(1.0) as u32;
    let Some(pixmap) =
      self.image_data_to_pixmap_at_size(&item.image, target_w, target_h, item.filter_quality)?
    else {
      return Ok(());
    };
    let (img_w, img_h) = (pixmap.width() as f32, pixmap.height() as f32);
    if img_w <= 0.0 || img_h <= 0.0 {
      return Ok(());
    }

    let origin = self.ds_point(item.origin);
    let scale_x = tile_w / img_w;
    let scale_y = tile_h / img_h;
    if !scale_x.is_finite() || !scale_y.is_finite() {
      return Ok(());
    }

    let spread = match item.repeat {
      ImagePatternRepeat::Repeat => SpreadMode::Repeat,
    };

    let clip_mask = self.canvas.clip_mask_rc();

    let axis_aligned = canvas_transform.kx.abs() <= 1e-6 && canvas_transform.ky.abs() <= 1e-6;
    let can_invert = canvas_transform.sx.is_finite()
      && canvas_transform.sy.is_finite()
      && canvas_transform.sx.abs() > 1e-6
      && canvas_transform.sy.abs() > 1e-6;

    if axis_aligned && can_invert {
      let bounds = transform_rect(dest_rect, &canvas_transform);
      let mut x0 = (bounds.min_x() - 0.5).ceil();
      let mut y0 = (bounds.min_y() - 0.5).ceil();
      let mut x1 = (bounds.max_x() - 0.5).ceil();
      let mut y1 = (bounds.max_y() - 0.5).ceil();

      x0 = x0.clamp(0.0, self.canvas.width() as f32);
      y0 = y0.clamp(0.0, self.canvas.height() as f32);
      x1 = x1.clamp(0.0, self.canvas.width() as f32);
      y1 = y1.clamp(0.0, self.canvas.height() as f32);

      let x0_u32 = x0 as u32;
      let y0_u32 = y0 as u32;
      let x1_u32 = x1 as u32;
      let y1_u32 = y1 as u32;
      if x0_u32 >= x1_u32 || y0_u32 >= y1_u32 {
        self.record_background_paint(background_timer);
        return Ok(());
      }

      let tmp_w = x1_u32 - x0_u32;
      let tmp_h = y1_u32 - y0_u32;
      let Some(mut tmp) = new_pixmap(tmp_w, tmp_h) else {
        // Allocation failed; fall back to tiny-skia's pattern fill.
        // (This may reintroduce parallel seams, but failing to paint is worse.)
        let pixmap_ref = pixmap.as_ref();
        let mut paint = tiny_skia::Paint::default();
        paint.shader = Pattern::new(
          pixmap_ref.as_ref(),
          spread,
          item.filter_quality.into(),
          opacity,
          Transform::from_row(scale_x, 0.0, 0.0, scale_y, origin.x, origin.y),
        );
        paint.anti_alias = false;
        paint.blend_mode = self.canvas.blend_mode();
        if let Some(skia_rect) = tiny_skia::Rect::from_xywh(
          dest_rect.x(),
          dest_rect.y(),
          dest_rect.width(),
          dest_rect.height(),
        ) {
          self.canvas.with_mirrored_pixmap_mut(|pixmap| {
            pixmap.fill_rect(skia_rect, &paint, canvas_transform, clip_mask.as_deref());
          });
        }
        self.record_background_paint(background_timer);
        return Ok(());
      };

      let src_w = pixmap.width();
      let src_h = pixmap.height();
      if src_w == 0 || src_h == 0 {
        self.record_background_paint(background_timer);
        return Ok(());
      }

      #[derive(Clone, Copy)]
      struct AxisSample {
        i0: u32,
        i1: u32,
        t: f32,
      }

      let src_w_i64 = src_w as i64;
      let src_h_i64 = src_h as i64;
      let inv_canvas_sx = 1.0f64 / canvas_transform.sx as f64;
      let inv_canvas_sy = 1.0f64 / canvas_transform.sy as f64;
      let canvas_tx = canvas_transform.tx as f64;
      let canvas_ty = canvas_transform.ty as f64;
      let origin_x = origin.x as f64;
      let origin_y = origin.y as f64;
      let pattern_scale_x = scale_x as f64;
      let pattern_scale_y = scale_y as f64;

      if !pattern_scale_x.is_finite() || !pattern_scale_y.is_finite() {
        self.record_background_paint(background_timer);
        return Ok(());
      }

      let mut xs: Vec<AxisSample> = Vec::new();
      let mut ys: Vec<AxisSample> = Vec::new();
      if xs.try_reserve_exact(tmp_w as usize).is_ok()
        && ys.try_reserve_exact(tmp_h as usize).is_ok()
      {
        match item.filter_quality {
          ImageFilterQuality::Nearest => {
            for x in 0..tmp_w {
              let dx = (x0_u32 + x) as f64 + 0.5;
              let local_x = (dx - canvas_tx) * inv_canvas_sx;
              let rel_x = local_x - origin_x;
              let src_x = rel_x / pattern_scale_x - 0.5;
              let ix = (src_x + 0.5).floor() as i64;
              let ix = ix.rem_euclid(src_w_i64) as u32;
              xs.push(AxisSample {
                i0: ix,
                i1: ix,
                t: 0.0,
              });
            }
            for y in 0..tmp_h {
              let dy = (y0_u32 + y) as f64 + 0.5;
              let local_y = (dy - canvas_ty) * inv_canvas_sy;
              let rel_y = local_y - origin_y;
              let src_y = rel_y / pattern_scale_y - 0.5;
              let iy = (src_y + 0.5).floor() as i64;
              let iy = iy.rem_euclid(src_h_i64) as u32;
              ys.push(AxisSample {
                i0: iy,
                i1: iy,
                t: 0.0,
              });
            }
          }
          ImageFilterQuality::Linear => {
            for x in 0..tmp_w {
              let dx = (x0_u32 + x) as f64 + 0.5;
              let local_x = (dx - canvas_tx) * inv_canvas_sx;
              let rel_x = local_x - origin_x;
              let src_x = rel_x / pattern_scale_x - 0.5;
              let x0f = src_x.floor();
              let i0 = x0f as i64;
              let t = (src_x - x0f).clamp(0.0, 1.0) as f32;
              let i1 = i0 + 1;
              let i0 = i0.rem_euclid(src_w_i64) as u32;
              let i1 = i1.rem_euclid(src_w_i64) as u32;
              xs.push(AxisSample { i0, i1, t });
            }
            for y in 0..tmp_h {
              let dy = (y0_u32 + y) as f64 + 0.5;
              let local_y = (dy - canvas_ty) * inv_canvas_sy;
              let rel_y = local_y - origin_y;
              let src_y = rel_y / pattern_scale_y - 0.5;
              let y0f = src_y.floor();
              let i0 = y0f as i64;
              let t = (src_y - y0f).clamp(0.0, 1.0) as f32;
              let i1 = i0 + 1;
              let i0 = i0.rem_euclid(src_h_i64) as u32;
              let i1 = i1.rem_euclid(src_h_i64) as u32;
              ys.push(AxisSample { i0, i1, t });
            }
          }
        }

        let src = pixmap.data();
        let dst = tmp.data_mut();
        let dst_stride = tmp_w as usize * 4;
        let src_stride = src_w as usize * 4;
        let lerp = |a: f32, b: f32, t: f32| a + (b - a) * t;

        let mut deadline_counter = 0usize;
        for (y, ysamp) in ys.iter().enumerate() {
          check_active_periodic(&mut deadline_counter, 128, RenderStage::Paint)
            .map_err(Error::Render)?;
          let row_dst = y * dst_stride;
          let row0 = ysamp.i0 as usize * src_stride;
          let row1 = ysamp.i1 as usize * src_stride;
          let fy = ysamp.t;
          for (x, xsamp) in xs.iter().enumerate() {
            let col0 = xsamp.i0 as usize * 4;
            let col1 = xsamp.i1 as usize * 4;
            let fx = xsamp.t;

            let idx00 = row0 + col0;
            let idx10 = row0 + col1;
            let idx01 = row1 + col0;
            let idx11 = row1 + col1;

            let read = |idx: usize| -> (f32, f32, f32, f32) {
              (
                src[idx] as f32,
                src[idx + 1] as f32,
                src[idx + 2] as f32,
                src[idx + 3] as f32,
              )
            };

            let (r00, g00, b00, a00) = read(idx00);
            let (r10, g10, b10, a10) = read(idx10);
            let (r01, g01, b01, a01) = read(idx01);
            let (r11, g11, b11, a11) = read(idx11);

            let top_r = lerp(r00, r10, fx);
            let top_g = lerp(g00, g10, fx);
            let top_b = lerp(b00, b10, fx);
            let top_a = lerp(a00, a10, fx);

            let bot_r = lerp(r01, r11, fx);
            let bot_g = lerp(g01, g11, fx);
            let bot_b = lerp(b01, b11, fx);
            let bot_a = lerp(a01, a11, fx);

            let mut r = lerp(top_r, bot_r, fy).round().clamp(0.0, 255.0) as u8;
            let mut g = lerp(top_g, bot_g, fy).round().clamp(0.0, 255.0) as u8;
            let mut b = lerp(top_b, bot_b, fy).round().clamp(0.0, 255.0) as u8;
            let a = lerp(top_a, bot_a, fy).round().clamp(0.0, 255.0) as u8;
            r = r.min(a);
            g = g.min(a);
            b = b.min(a);

            let dst_idx = row_dst + x * 4;
            dst[dst_idx] = r;
            dst[dst_idx + 1] = g;
            dst[dst_idx + 2] = b;
            dst[dst_idx + 3] = a;
          }
        }

        let blend_mode = self.canvas.blend_mode();
        let clip = clip_mask.as_deref();
        self.canvas.with_mirrored_pixmap_mut(|pixmap| {
          composite_layer_into_pixmap_mut(
            pixmap,
            &tmp,
            opacity,
            blend_mode,
            (x0_u32 as i32, y0_u32 as i32),
            clip,
          );
        });

        self.record_background_paint(background_timer);
        return Ok(());
      }

      // Allocation failed; fall back to tiny-skia's pattern shader below.
    }

    // Fallback to tiny-skia's pattern shader for non-axis-aligned transforms.
    let pixmap_ref = pixmap.as_ref();
    let mut paint = tiny_skia::Paint::default();
    paint.shader = Pattern::new(
      pixmap_ref.as_ref(),
      spread,
      item.filter_quality.into(),
      opacity,
      Transform::from_row(scale_x, 0.0, 0.0, scale_y, origin.x, origin.y),
    );
    paint.anti_alias = false;
    paint.blend_mode = self.canvas.blend_mode();

    let Some(skia_rect) = tiny_skia::Rect::from_xywh(
      dest_rect.x(),
      dest_rect.y(),
      dest_rect.width(),
      dest_rect.height(),
    ) else {
      return Ok(());
    };
    self.canvas.with_mirrored_pixmap_mut(|pixmap| {
      pixmap.fill_rect(skia_rect, &paint, canvas_transform, clip_mask.as_deref());
    });

    self.record_background_paint(background_timer);
    Ok(())
  }

  fn push_clip(&mut self, clip: &ClipItem) -> Result<()> {
    let diag = self.clip_mask_diagnostics.clone();
    let timer = diag.as_ref().map(|_| Instant::now());
    let pixels = diag
      .as_ref()
      .map(|_| u64::from(self.canvas.width()).saturating_mul(u64::from(self.canvas.height())))
      .unwrap_or(0);

    self.canvas.save();
    match &clip.shape {
      ClipShape::Rect { rect, radii } => {
        let radii = radii.map(|r| self.ds_radii(r));
        let rect = self.maybe_snap_axis_aligned_clip_rect(self.ds_rect(*rect));
        self.canvas.set_clip_with_radii(rect, radii)?;
      }
      ClipShape::Path { path } => {
        self.canvas.set_clip_path(path, self.scale)?;
      }
      ClipShape::Text { runs } => {
        let scaled: Vec<TextItem> = runs.iter().map(|run| self.scale_text_item(run)).collect();
        self.canvas.set_clip_text(&scaled)?;
      }
      ClipShape::AlphaMask { image, rect } => {
        if let Some(pixmap) = self.image_data_to_pixmap(image.as_ref())? {
          self.canvas.set_clip_image_mask(
            pixmap.as_ref(),
            self.ds_rect(*rect),
            FilterQuality::Bilinear,
          )?;
        }
      }
    }

    if let (Some(diag), Some(start)) = (diag.as_ref(), timer) {
      diag.record(pixels, start.elapsed());
    }
    Ok(())
  }

  fn pop_clip(&mut self) {
    self.canvas.restore();
  }

  fn push_transform(&mut self, transform: &TransformItem) {
    self.canvas.save();
    let (matrix, valid) = self.to_skia_transform_checked(&transform.transform);
    if valid {
      let combined = concat_transforms(self.canvas.transform(), matrix);
      self.canvas.set_transform(combined);
    }
  }

  fn resolve_font(
    &self,
    font_id: Option<&FontId>,
    font: Option<&Arc<LoadedFont>>,
  ) -> Option<LoadedFont> {
    if let Some(f) = font {
      return Some((**f).clone());
    }

    if let Some(id) = font_id {
      if let Some(font) = self.font_ctx.get_font_by_id(*id) {
        return Some(font);
      }
    }
    self.font_ctx.get_sans_serif()
  }

  fn image_to_pixmap(&mut self, item: &ImageItem) -> RenderResult<Option<Arc<Pixmap>>> {
    let dest_rect_device = self.ds_rect(item.dest_rect);
    let target_bounds = transform_rect(dest_rect_device, &self.canvas.transform());
    let target_w = target_bounds.width().ceil().max(1.0) as u32;
    let target_h = target_bounds.height().ceil().max(1.0) as u32;

    // The scaled-pixmap fast path intentionally ignores the destination rectangle's translation so
    // scaled results can be cached/reused across different draws. This matches many common cases
    // (integer-aligned images), but it diverges from Skia/Chrome when the image is drawn at a
    // fractional device-pixel offset: the subpixel translation influences sampling.
    //
    // Prefer fidelity over caching for those subpixel cases by falling back to the full-resolution
    // image pixmap.
    let can_use_scaled_pixmap = {
      let transform = self.canvas.transform();
      if transform == Transform::identity() {
        Self::is_near_integer(dest_rect_device.x()) && Self::is_near_integer(dest_rect_device.y())
      } else if Self::is_translation_only_transform(transform) {
        // When painting is offset by a translation (e.g. tiled render), use the effective device
        // origin when determining whether the draw is pixel-aligned.
        let eff_x = dest_rect_device.x() + transform.tx;
        let eff_y = dest_rect_device.y() + transform.ty;
        Self::is_near_integer(eff_x) && Self::is_near_integer(eff_y)
      } else {
        false
      }
    };

    if let Some(src) = item.src_rect {
      // `ImageItem::src_rect` is in the source image's pixel coordinate space. When it includes
      // fractional offsets (common with `background-size: cover/contain`), cropping to integer
      // pixel bounds would lose information that affects sampling. Keep the full pixmap in those
      // cases and let `render_image` apply the source-rect transform.
      if !(Self::is_near_integer(src.x())
        && Self::is_near_integer(src.y())
        && Self::is_near_integer(src.width())
        && Self::is_near_integer(src.height()))
      {
        return self.image_data_to_pixmap(&item.image);
      }

      let crop_diag = self.image_pixmap_diagnostics.clone();
      let crop_timer = crop_diag.as_ref().map(|_| Instant::now());

      let src_x = src.x().max(0.0).round() as u32;
      let src_y = src.y().max(0.0).round() as u32;
      let src_w = src.width().round().max(0.0) as u32;
      let src_h = src.height().round().max(0.0) as u32;
      if src_w == 0 || src_h == 0 {
        return Ok(None);
      }

      let max_x = item.image.width.saturating_sub(src_x);
      let max_y = item.image.height.saturating_sub(src_y);
      let crop_w = src_w.min(max_x);
      let crop_h = src_h.min(max_y);
      if crop_w == 0 || crop_h == 0 {
        return Ok(None);
      }

      // `src_rect` covers the entire image; treat it like a normal draw so we still get downscale
      // caching (and avoid baking a no-op crop).
      if src_x == 0 && src_y == 0 && crop_w == item.image.width && crop_h == item.image.height {
        if can_use_scaled_pixmap {
          return self.image_data_to_pixmap_at_size(
            &item.image,
            target_w,
            target_h,
            item.filter_quality,
          );
        }
        return self.image_data_to_pixmap(&item.image);
      }

      // If the cropped region is being downscaled, sample directly from the original `ImageData`
      // into a scaled pixmap. This avoids building an intermediate cropped pixmap and ensures we
      // still use the Skia-aligned mipmapped linear sampler for clipped draws.
      if can_use_scaled_pixmap
        && Self::should_use_scaled_image_pixmap(
          item.filter_quality,
          crop_w,
          crop_h,
          target_w,
          target_h,
        )
      {
        if let Some(pixmap) = image_data_to_scaled_pixmap_from_rect_inner(
          &item.image,
          src_x,
          src_y,
          crop_w,
          crop_h,
          target_w,
          target_h,
          item.filter_quality,
        )? {
          return Ok(Some(Arc::new(pixmap)));
        }
      }

      let Some(full) = self.image_data_to_pixmap(&item.image)? else {
        return Ok(None);
      };
      let key = ImageCropKey {
        image: ImageKey::new(&item.image),
        src_x,
        src_y,
        crop_w,
        crop_h,
      };
      let cropped = if let Some(cached) = self.cropped_image_cache.get(&key) {
        cached.clone()
      } else {
        check_active(RenderStage::Paint)?;
        let Some(mut cropped) = new_pixmap(crop_w, crop_h) else {
          return Ok(None);
        };
        let mut deadline_counter = 0usize;
        for row in 0..crop_h {
          check_active_periodic(&mut deadline_counter, 32, RenderStage::Paint)?;
          let src_index = ((src_y + row) * item.image.width + src_x) as usize * 4;
          let dst_index = (row * crop_w) as usize * 4;
          cropped.data_mut()[dst_index..dst_index + (crop_w as usize * 4)]
            .copy_from_slice(&full.data()[src_index..src_index + (crop_w as usize * 4)]);
        }
        if let (Some(diag), Some(start)) = (crop_diag.as_ref(), crop_timer) {
          diag.record_duration(start.elapsed());
        }
        let cropped = Arc::new(cropped);
        self.cropped_image_cache.put(key, cropped.clone());
        cropped
      };
      Ok(Some(cropped))
    } else if can_use_scaled_pixmap {
      self.image_data_to_pixmap_at_size(&item.image, target_w, target_h, item.filter_quality)
    } else {
      self.image_data_to_pixmap(&item.image)
    }
  }

  #[inline]
  fn image_filter_quality_bits(quality: ImageFilterQuality) -> u8 {
    match quality {
      ImageFilterQuality::Nearest => 0,
      ImageFilterQuality::Linear => 1,
    }
  }

  fn should_use_scaled_image_pixmap(
    quality: ImageFilterQuality,
    src_width: u32,
    src_height: u32,
    target_width: u32,
    target_height: u32,
  ) -> bool {
    if quality != ImageFilterQuality::Linear {
      return false;
    }
    if src_width == 0 || src_height == 0 || target_width == 0 || target_height == 0 {
      return false;
    }
    if target_width == src_width && target_height == src_height {
      return false;
    }

    let src_pixels = u64::from(src_width).saturating_mul(u64::from(src_height));
    let target_pixels = u64::from(target_width).saturating_mul(u64::from(target_height));

    // For downscaled images, we opportunistically rasterize a scaled pixmap up-front (and cache
    // it) instead of letting `tiny-skia` resample at draw time.
    //
    // This is both a performance win (smaller pixmap + cheaper draw) and, importantly, it lets us
    // use our Skia-aligned mipmapped linear sampler (see `image_data_to_scaled_pixmap_inner`),
    // which has significantly better fixture-vs-Chrome stability for scaled raster images.
    //
    // Avoid generating nearly-identical copies for tiny downscales (which can explode cache
    // memory). The threshold here is intentionally conservative: a <= 10% reduction in pixel area
    // is treated as a "slight" downscale.
    if target_pixels.saturating_mul(10) <= src_pixels.saturating_mul(9) {
      return true;
    }

    // For large upscales, tiny-skia's built-in bilinear filtering rounds to the nearest 8-bit
    // channel value while Skia/Chrome round down. Pre-rasterize relatively small upscales so we
    // can use our Skia-aligned sampler (see `image_data_to_scaled_pixmap_inner`) without exploding
    // cache memory for large images.
    const UPSCALE_MIN_AREA_RATIO: u64 = 4;
    const UPSCALE_MAX_TARGET_PIXELS: u64 = 512 * 512;
    target_pixels <= UPSCALE_MAX_TARGET_PIXELS
      && target_pixels >= src_pixels.saturating_mul(UPSCALE_MIN_AREA_RATIO)
  }

  fn image_data_to_pixmap_at_size(
    &mut self,
    image: &ImageData,
    target_width: u32,
    target_height: u32,
    quality: ImageFilterQuality,
  ) -> RenderResult<Option<Arc<Pixmap>>> {
    if !Self::should_use_scaled_image_pixmap(
      quality,
      image.width,
      image.height,
      target_width,
      target_height,
    ) {
      return self.image_data_to_pixmap(image);
    }

    let key = ImageScaledKey {
      image: ImageKey::new(image),
      target_w: target_width,
      target_h: target_height,
      quality_bits: Self::image_filter_quality_bits(quality),
    };

    if let Some(cached) = self.scaled_image_cache.get(&key) {
      if let Some(diag) = self.image_pixmap_diagnostics.as_ref() {
        diag.record_hit();
      }
      return Ok(Some(cached.clone()));
    }

    if let Some(shared) = self.shared_image_pixmaps.as_ref() {
      if let Some(cell) = shared.scaled_cell(key) {
        if let Some(cached) = cell.get() {
          if let Some(diag) = self.image_pixmap_diagnostics.as_ref() {
            diag.record_hit();
          }
          let cached = cached.clone()?;
          if let Some(pixmap) = cached.as_ref() {
            self.scaled_image_cache.put(key, pixmap.clone());
          }
          return Ok(cached);
        }

        let diag = self.image_pixmap_diagnostics.clone();
        let cached = cell
          .get_or_init(|| {
            if let Some(diag) = diag.as_ref() {
              diag.record_miss();
            }
            let timer = diag.as_ref().map(|_| Instant::now());
            let pixmap =
              match image_data_to_scaled_pixmap_inner(image, target_width, target_height, quality)?
              {
                Some(pixmap) => Some(pixmap),
                None => image_data_to_pixmap_inner(image)?,
              };
            let Some(pixmap) = pixmap else {
              return Ok(None);
            };
            let pixmap = Arc::new(pixmap);
            if let (Some(diag), Some(start)) = (diag.as_ref(), timer) {
              diag.record_duration(start.elapsed());
            }
            Ok(Some(pixmap))
          })
          .clone()?;
        if let Some(pixmap) = cached.as_ref() {
          self.scaled_image_cache.put(key, pixmap.clone());
        }
        return Ok(cached);
      }
    }

    let diag = self.image_pixmap_diagnostics.as_ref();
    if let Some(diag) = diag {
      diag.record_miss();
    }
    let timer = diag.map(|_| Instant::now());
    let Some(pixmap) =
      image_data_to_scaled_pixmap_inner(image, target_width, target_height, quality)?
    else {
      return self.image_data_to_pixmap(image);
    };
    let pixmap = Arc::new(pixmap);
    if let (Some(diag), Some(start)) = (diag, timer) {
      diag.record_duration(start.elapsed());
    }
    #[cfg(test)]
    self.image_cache_misses.fetch_add(1, Ordering::Relaxed);
    self.scaled_image_cache.put(key, pixmap.clone());
    Ok(Some(pixmap))
  }

  fn image_data_to_pixmap(&mut self, image: &ImageData) -> RenderResult<Option<Arc<Pixmap>>> {
    let key = ImageKey::new(image);
    if let Some(cached) = self.image_cache.get(&key) {
      if let Some(diag) = self.image_pixmap_diagnostics.as_ref() {
        diag.record_hit();
      }
      return Ok(Some(cached));
    }

    if let Some(shared) = self.shared_image_pixmaps.as_ref() {
      let cell = shared.image_cell(key);
      if let Some(cached) = cell.get() {
        if let Some(diag) = self.image_pixmap_diagnostics.as_ref() {
          diag.record_hit();
        }
        let cached = cached.clone()?;
        if let Some(pixmap) = cached.as_ref() {
          self.image_cache.insert(key, pixmap.clone());
        }
        return Ok(cached);
      }

      let diag = self.image_pixmap_diagnostics.clone();
      let cached = cell
        .get_or_init(|| {
          if let Some(diag) = diag.as_ref() {
            diag.record_miss();
          }
          let timer = diag.as_ref().map(|_| Instant::now());
          let Some(pixmap) = image_data_to_pixmap_inner(image)? else {
            return Ok(None);
          };
          let pixmap = Arc::new(pixmap);
          if let (Some(diag), Some(start)) = (diag.as_ref(), timer) {
            diag.record_duration(start.elapsed());
          }
          Ok(Some(pixmap))
        })
        .clone()?;
      if let Some(pixmap) = cached.as_ref() {
        self.image_cache.insert(key, pixmap.clone());
      }
      return Ok(cached);
    }

    let diag = self.image_pixmap_diagnostics.as_ref();
    if let Some(diag) = diag {
      diag.record_miss();
    }
    let timer = diag.map(|_| Instant::now());
    let Some(pixmap) = image_data_to_pixmap_inner(image)? else {
      return Ok(None);
    };
    let pixmap = Arc::new(pixmap);
    if let (Some(diag), Some(start)) = (diag, timer) {
      diag.record_duration(start.elapsed());
    }
    #[cfg(test)]
    self.image_cache_misses.fetch_add(1, Ordering::Relaxed);
    self.image_cache.insert(key, pixmap.clone());
    Ok(Some(pixmap))
  }
}

fn image_data_to_pixmap_inner(image: &ImageData) -> RenderResult<Option<Pixmap>> {
  let Some(size) = tiny_skia::IntSize::from_wh(image.width, image.height) else {
    return Ok(None);
  };

  let Some(bytes) = u64::from(image.width)
    .checked_mul(u64::from(image.height))
    .and_then(|px| px.checked_mul(4))
  else {
    return Ok(None);
  };
  let Ok(expected_len) = usize::try_from(bytes) else {
    return Ok(None);
  };

  let src_pixels = image.pixels.as_ref().as_slice();
  if src_pixels.len() != expected_len {
    return Ok(None);
  }

  let mut data = match reserve_buffer(bytes, "image pixmap") {
    Ok(buf) => buf,
    Err(_) => return Ok(None),
  };

  if image.premultiplied {
    data.extend_from_slice(src_pixels);
    return Ok(Pixmap::from_vec(data, size));
  }

  check_active(RenderStage::Paint)?;
  let mut pixel_counter = 0usize;
  for chunk in src_pixels.chunks_exact(4) {
    if (pixel_counter & 4095) == 0 {
      check_active(RenderStage::Paint)?;
    }
    pixel_counter = pixel_counter.wrapping_add(1);
    let r = chunk[0] as f32;
    let g = chunk[1] as f32;
    let b = chunk[2] as f32;
    let a = chunk[3] as f32 / 255.0;
    data.push((r * a).round() as u8);
    data.push((g * a).round() as u8);
    data.push((b * a).round() as u8);
    data.push(chunk[3]);
  }

  Ok(Pixmap::from_vec(data, size))
}

#[derive(Clone)]
struct MipmapLevelBuf {
  width: u32,
  height: u32,
  /// Premultiplied RGBA8 pixels.
  pixels: Vec<u8>,
}

#[inline]
fn read_image_pixel_premul(
  src_pixels: &[u8],
  idx: usize,
  premultiplied: bool,
) -> (f32, f32, f32, f32) {
  let r = src_pixels[idx] as f32;
  let g = src_pixels[idx + 1] as f32;
  let b = src_pixels[idx + 2] as f32;
  let a = src_pixels[idx + 3] as f32;
  if premultiplied {
    (r, g, b, a)
  } else {
    let af = a / 255.0;
    (r * af, g * af, b * af, a)
  }
}

#[inline]
fn read_image_pixel_premul_u16(
  src_pixels: &[u8],
  idx: usize,
  premultiplied: bool,
) -> (u16, u16, u16, u16) {
  let r = src_pixels[idx] as u16;
  let g = src_pixels[idx + 1] as u16;
  let b = src_pixels[idx + 2] as u16;
  let a = src_pixels[idx + 3] as u16;
  if premultiplied {
    (r, g, b, a)
  } else {
    (div_255(r * a), div_255(g * a), div_255(b * a), a)
  }
}

fn mipmap_lod_for_scale(scale_x: f32, scale_y: f32) -> Option<(u32, f32)> {
  let max_scale = scale_x.max(scale_y);
  if !max_scale.is_finite() || max_scale <= 1.0 {
    return Some((0, 0.0));
  }

  // Skia/Chrome's raster image filtering does not appear to switch to mipmapped sampling for a
  // simple 2x downscale. Using mipmaps at exactly 2x produces noticeably different results for
  // subpixel-positioned images (e.g. CSS background images placed at fractional device pixels),
  // while full-resolution bilinear sampling more closely matches Chrome.
  //
  // Keep mipmaps for larger downscales where they materially reduce aliasing.
  if max_scale <= 2.0 {
    return Some((0, 0.0));
  }

  let mut lod = max_scale.log2();
  if !lod.is_finite() || lod < 0.0 {
    lod = 0.0;
  }

  let mut base = lod.floor();
  let frac = lod - base;

  // Keep the boundary stable when `lod` is extremely close to an integer. This avoids dithering
  // between mip levels due to float noise.
  let eps = 1e-6;
  if frac > 1.0 - eps {
    base += 1.0;
  }
  // Chrome/Skia tends to behave closer to `mipmap: nearest` than full trilinear blending for
  // `SkFilterMode::Linear` image minification, which keeps scaled raster images sharper and reduces
  // fixture diffs compared to always blending between levels.
  Some((base as u32, 0.0))
}

fn downsample_mipmap_level(
  src_pixels: &[u8],
  src_width: u32,
  src_height: u32,
  premultiplied: bool,
) -> RenderResult<Option<MipmapLevelBuf>> {
  if src_width == 0 || src_height == 0 {
    return Ok(None);
  }
  if src_width == 1 && src_height == 1 {
    return Ok(None);
  }
  let out_width = if src_width > 1 { src_width / 2 } else { 1 };
  let out_height = if src_height > 1 { src_height / 2 } else { 1 };
  if IntSize::from_wh(out_width, out_height).is_none() {
    return Ok(None);
  };
  let Some(bytes) = u64::from(out_width)
    .checked_mul(u64::from(out_height))
    .and_then(|px| px.checked_mul(4))
  else {
    return Ok(None);
  };

  let mut data = match reserve_buffer(bytes, "mipmap level") {
    Ok(buf) => buf,
    Err(_) => return Ok(None),
  };
  data.resize(bytes as usize, 0);

  check_active(RenderStage::Paint)?;
  let src_w = src_width as usize;
  let mut pixel_counter = 0usize;
  if src_width > 1 && src_height > 1 {
    // 2x2 box filter.
    for y in 0..out_height {
      let src_y = (y * 2) as usize;
      let row0 = src_y * src_w;
      let row1 = (src_y + 1) * src_w;
      for x in 0..out_width {
        if (pixel_counter & 4095) == 0 {
          check_active(RenderStage::Paint)?;
        }
        pixel_counter = pixel_counter.wrapping_add(1);

        let src_x = (x * 2) as usize;
        let idx00 = (row0 + src_x) * 4;
        let idx10 = idx00 + 4;
        let idx01 = (row1 + src_x) * 4;
        let idx11 = idx01 + 4;

        let (r00, g00, b00, a00) = read_image_pixel_premul(src_pixels, idx00, premultiplied);
        let (r10, g10, b10, a10) = read_image_pixel_premul(src_pixels, idx10, premultiplied);
        let (r01, g01, b01, a01) = read_image_pixel_premul(src_pixels, idx01, premultiplied);
        let (r11, g11, b11, a11) = read_image_pixel_premul(src_pixels, idx11, premultiplied);

        let inv = 0.25;
        let sum_r = (r00 + r10 + r01 + r11) * inv;
        let sum_g = (g00 + g10 + g01 + g11) * inv;
        let sum_b = (b00 + b10 + b01 + b11) * inv;
        let sum_a = (a00 + a10 + a01 + a11) * inv;

        let a = sum_a.floor().clamp(0.0, 255.0) as u8;
        let mut r = sum_r.floor().clamp(0.0, 255.0) as u8;
        let mut g = sum_g.floor().clamp(0.0, 255.0) as u8;
        let mut b = sum_b.floor().clamp(0.0, 255.0) as u8;

        r = r.min(a);
        g = g.min(a);
        b = b.min(a);

        let dst_idx = (y * out_width + x) as usize * 4;
        data[dst_idx] = r;
        data[dst_idx + 1] = g;
        data[dst_idx + 2] = b;
        data[dst_idx + 3] = a;
      }
    }
  } else if src_width > 1 {
    // 2x1 box filter (vertical dimension is already 1).
    for x in 0..out_width {
      if (pixel_counter & 4095) == 0 {
        check_active(RenderStage::Paint)?;
      }
      pixel_counter = pixel_counter.wrapping_add(1);

      let src_x = (x * 2) as usize;
      let idx0 = src_x * 4;
      let idx1 = idx0 + 4;

      let (r0, g0, b0, a0) = read_image_pixel_premul(src_pixels, idx0, premultiplied);
      let (r1, g1, b1, a1) = read_image_pixel_premul(src_pixels, idx1, premultiplied);

      let inv = 0.5;
      let sum_r = (r0 + r1) * inv;
      let sum_g = (g0 + g1) * inv;
      let sum_b = (b0 + b1) * inv;
      let sum_a = (a0 + a1) * inv;

      let a = sum_a.floor().clamp(0.0, 255.0) as u8;
      let mut r = sum_r.floor().clamp(0.0, 255.0) as u8;
      let mut g = sum_g.floor().clamp(0.0, 255.0) as u8;
      let mut b = sum_b.floor().clamp(0.0, 255.0) as u8;

      r = r.min(a);
      g = g.min(a);
      b = b.min(a);

      let dst_idx = x as usize * 4;
      data[dst_idx] = r;
      data[dst_idx + 1] = g;
      data[dst_idx + 2] = b;
      data[dst_idx + 3] = a;
    }
  } else {
    // 1x2 box filter (horizontal dimension is already 1).
    for y in 0..out_height {
      if (pixel_counter & 4095) == 0 {
        check_active(RenderStage::Paint)?;
      }
      pixel_counter = pixel_counter.wrapping_add(1);

      let src_y = (y * 2) as usize;
      let idx0 = src_y * 4;
      let idx1 = idx0 + src_w * 4;

      let (r0, g0, b0, a0) = read_image_pixel_premul(src_pixels, idx0, premultiplied);
      let (r1, g1, b1, a1) = read_image_pixel_premul(src_pixels, idx1, premultiplied);

      let inv = 0.5;
      let sum_r = (r0 + r1) * inv;
      let sum_g = (g0 + g1) * inv;
      let sum_b = (b0 + b1) * inv;
      let sum_a = (a0 + a1) * inv;

      let a = sum_a.floor().clamp(0.0, 255.0) as u8;
      let mut r = sum_r.floor().clamp(0.0, 255.0) as u8;
      let mut g = sum_g.floor().clamp(0.0, 255.0) as u8;
      let mut b = sum_b.floor().clamp(0.0, 255.0) as u8;

      r = r.min(a);
      g = g.min(a);
      b = b.min(a);

      let dst_idx = y as usize * out_width as usize * 4;
      data[dst_idx] = r;
      data[dst_idx + 1] = g;
      data[dst_idx + 2] = b;
      data[dst_idx + 3] = a;
    }
  }

  Ok(Some(MipmapLevelBuf {
    width: out_width,
    height: out_height,
    pixels: data,
  }))
}

fn image_data_to_scaled_pixmap_with_phase_inner(
  image: &ImageData,
  dest_device: Rect,
  out_width: u32,
  out_height: u32,
  out_origin_x_device: f32,
  out_origin_y_device: f32,
) -> RenderResult<Option<Pixmap>> {
  if out_width == 0
    || out_height == 0
    || !out_origin_x_device.is_finite()
    || !out_origin_y_device.is_finite()
  {
    return Ok(None);
  }
  if !(dest_device.width().is_finite()
    && dest_device.height().is_finite()
    && dest_device.width() > 0.0
    && dest_device.height() > 0.0
    && dest_device.x().is_finite()
    && dest_device.y().is_finite())
  {
    return Ok(None);
  }

  let src_w = image.width;
  let src_h = image.height;
  if src_w == 0 || src_h == 0 {
    return Ok(None);
  }

  let Some(size) = IntSize::from_wh(out_width, out_height) else {
    return Ok(None);
  };
  let Some(bytes) = u64::from(out_width)
    .checked_mul(u64::from(out_height))
    .and_then(|px| px.checked_mul(4))
  else {
    return Ok(None);
  };

  let mut data = match reserve_buffer(bytes, "scaled image pixmap (phase)") {
    Ok(buf) => buf,
    Err(_) => return Ok(None),
  };
  data.resize(bytes as usize, 0);

  check_active(RenderStage::Paint)?;
  let src_pixels = image.pixels.as_ref().as_slice();
  let Some(expected_src_bytes) = u64::from(src_w)
    .checked_mul(u64::from(src_h))
    .and_then(|px| px.checked_mul(4))
  else {
    return Ok(None);
  };
  let Ok(expected_src_len) = usize::try_from(expected_src_bytes) else {
    return Ok(None);
  };
  if src_pixels.len() != expected_src_len {
    return Ok(None);
  }

  #[derive(Clone, Copy)]
  struct AxisSample {
    i0: u32,
    i1: u32,
    w: u16,
  }

  // Skia uses linear filtering with mipmaps when downscaling raster images. This behaves closer to
  // an area filter than a single bilinear sample from the full-resolution image and materially
  // reduces fixture-vs-Chrome diffs for photo-heavy regions.
  let scale_x0 = src_w as f32 / dest_device.width();
  let scale_y0 = src_h as f32 / dest_device.height();
  if !scale_x0.is_finite() || !scale_y0.is_finite() {
    return Ok(None);
  }

  // For magnification (no minification in either axis), Chrome/Skia's output appears to:
  // - map into the integer output pixel grid (vs the exact float dest size),
  // - quantize bilinear weights to 16 phases (4-bit precision),
  // - and only floor-to-u8 once at the end (no truncation between axes).
  //
  // tiny-skia truncates intermediate results between the horizontal and vertical lerps, which can
  // produce pervasive ±1 diffs across photo-heavy regions.
  //
  // Use a float bilinear path for pure upscales to match Chrome/Skia more closely, and keep the
  // mipmap-capable fixed-point path for downscales.
  //
  // Use the specialized magnification path only when we're scaling up in *both* axes. When one
  // axis is 1:1 (e.g. 1px-tall gradients upscaled horizontally), the fixed-point sampler below
  // matches Chrome/Skia more closely.
  if scale_x0 < 1.0 && scale_y0 < 1.0 {
    #[derive(Clone, Copy)]
    struct AxisSampleF32 {
      i0: u32,
      i1: u32,
      t: f32,
    }

    let build_axis = |out_len: u32,
                      out_origin: f32,
                      dest_origin: f32,
                      dest_size: f32,
                      src_len: u32|
     -> Option<Vec<AxisSampleF32>> {
      if out_len == 0 || src_len == 0 {
        return None;
      }
      // Chrome's magnification path behaves closer to mapping the source image into the integer
      // output pixel grid (rather than using the exact floating destination size). Use `out_len`
      // for the scale so fractional destination sizes (e.g. 782.2222px) match Chrome more closely.
      //
      // However, `image_data_to_scaled_pixmap_with_phase_inner` is also used by the phase-aware
      // background-image fast path for `src_rect` draws. In that scenario, `dest_device` refers to
      // the mapping of the *full* image into device space (so we can preserve fractional
      // `src_rect` offsets), while `out_len` only spans the clipped destination rect. Using
      // `out_len` as the scale denominator would incorrectly squeeze the entire source image into
      // the clipped output width/height, making sprite backgrounds extremely faint.
      //
      // When `dest_size` is not approximately `out_len`, fall back to using the actual mapped
      // destination size for the sampling scale.
      let scale_den = if dest_size.is_finite() && dest_size > 0.0 {
        let out_len_f = out_len as f32;
        const DEST_SIZE_MATCH_EPSILON: f32 = 1.0;
        if (dest_size - out_len_f).abs() <= DEST_SIZE_MATCH_EPSILON {
          out_len_f
        } else {
          dest_size
        }
      } else {
        out_len as f32
      };
      let scale = src_len as f32 / scale_den;
      if !scale.is_finite() || !out_origin.is_finite() || !dest_origin.is_finite() {
        return None;
      }
      let max = src_len as f32 - 1.0;
      let mut samples = Vec::new();
      if samples.try_reserve_exact(out_len as usize).is_err() {
        return None;
      }
      for i in 0..out_len {
        let device = out_origin + i as f32 + 0.5;
        let mut s = (device - dest_origin) * scale - 0.5;
        if !s.is_finite() || !max.is_finite() {
          return None;
        }
        s = s.clamp(0.0, max);
        let s0 = s.floor();
        let i0 = s0 as u32;
        let i1 = (i0 + 1).min(src_len.saturating_sub(1));
        // Chrome's magnification path appears to quantize bilinear weights to 16 discrete phases
        // (4-bit precision) while keeping the lerps full-precision (no truncation between axes).
        //
        // The low weight precision is counter-intuitive, but it significantly reduces fixture diffs
        // for upscaled photos compared to using the full float fraction here.
        let t = (s - s0).clamp(0.0, 1.0);
        let t = (t * 16.0).floor() * (1.0 / 16.0);
        samples.push(AxisSampleF32 { i0, i1, t });
      }
      Some(samples)
    };

    let Some(xs) = build_axis(
      out_width,
      out_origin_x_device,
      dest_device.x(),
      dest_device.width(),
      src_w,
    ) else {
      return Ok(None);
    };
    let Some(ys) = build_axis(
      out_height,
      out_origin_y_device,
      dest_device.y(),
      dest_device.height(),
      src_h,
    ) else {
      return Ok(None);
    };

    #[inline]
    fn lerp(a: f32, b: f32, t: f32) -> f32 {
      a + (b - a) * t
    }

    let src_w_usize = src_w as usize;
    let mut pixel_counter = 0usize;
    for (y, ysamp) in ys.iter().enumerate() {
      let row0 = ysamp.i0 as usize * src_w_usize;
      let row1 = ysamp.i1 as usize * src_w_usize;
      let ty = ysamp.t;
      for (x, xsamp) in xs.iter().enumerate() {
        if (pixel_counter & 4095) == 0 {
          check_active(RenderStage::Paint)?;
        }
        pixel_counter = pixel_counter.wrapping_add(1);

        let col0 = xsamp.i0 as usize;
        let col1 = xsamp.i1 as usize;
        let tx = xsamp.t;

        let idx00 = (row0 + col0) * 4;
        let idx10 = (row0 + col1) * 4;
        let idx01 = (row1 + col0) * 4;
        let idx11 = (row1 + col1) * 4;

        let (r00, g00, b00, a00) = read_image_pixel_premul(src_pixels, idx00, image.premultiplied);
        let (r10, g10, b10, a10) = read_image_pixel_premul(src_pixels, idx10, image.premultiplied);
        let (r01, g01, b01, a01) = read_image_pixel_premul(src_pixels, idx01, image.premultiplied);
        let (r11, g11, b11, a11) = read_image_pixel_premul(src_pixels, idx11, image.premultiplied);

        let top_r = lerp(r00, r10, tx);
        let top_g = lerp(g00, g10, tx);
        let top_b = lerp(b00, b10, tx);
        let top_a = lerp(a00, a10, tx);

        let bot_r = lerp(r01, r11, tx);
        let bot_g = lerp(g01, g11, tx);
        let bot_b = lerp(b01, b11, tx);
        let bot_a = lerp(a01, a11, tx);

        let r = lerp(top_r, bot_r, ty);
        let g = lerp(top_g, bot_g, ty);
        let b = lerp(top_b, bot_b, ty);
        let a = lerp(top_a, bot_a, ty);

        // Chrome/Skia rounds down when converting to 8-bit channels.
        let a_u8 = a.floor().clamp(0.0, 255.0) as u8;
        let mut r_u8 = r.floor().clamp(0.0, 255.0) as u8;
        let mut g_u8 = g.floor().clamp(0.0, 255.0) as u8;
        let mut b_u8 = b.floor().clamp(0.0, 255.0) as u8;
        r_u8 = r_u8.min(a_u8);
        g_u8 = g_u8.min(a_u8);
        b_u8 = b_u8.min(a_u8);

        let dst_idx = (y as u32 * out_width + x as u32) as usize * 4;
        data[dst_idx] = r_u8;
        data[dst_idx + 1] = g_u8;
        data[dst_idx + 2] = b_u8;
        data[dst_idx + 3] = a_u8;
      }
    }

    return Ok(Pixmap::from_vec(data, size));
  }

  let (mut base_level, mut blend_t) = mipmap_lod_for_scale(scale_x0, scale_y0).unwrap_or((0, 0.0));
  let mut needs_second_level = blend_t > 0.0;
  let max_level = base_level + if needs_second_level { 1 } else { 0 };

  let mut mipmaps: Vec<MipmapLevelBuf> = Vec::new();
  if max_level > 0 {
    if mipmaps.try_reserve_exact(max_level as usize).is_err() {
      return Ok(None);
    }
    for level in 1..=max_level {
      let next = if level == 1 {
        downsample_mipmap_level(src_pixels, src_w, src_h, image.premultiplied)?
      } else {
        let prev = &mipmaps[(level - 2) as usize];
        downsample_mipmap_level(prev.pixels.as_slice(), prev.width, prev.height, true)?
      };
      let Some(next) = next else {
        break;
      };
      mipmaps.push(next);
    }
  }

  let max_available = mipmaps.len() as u32;
  if base_level > max_available {
    base_level = max_available;
    blend_t = 0.0;
    needs_second_level = false;
  } else if needs_second_level && base_level + 1 > max_available {
    blend_t = 0.0;
    needs_second_level = false;
  }

  let level_a = base_level;
  let level_b = needs_second_level.then(|| base_level + 1);

  let level_info = |level: u32| -> (u32, u32, &[u8], bool) {
    if level == 0 {
      (src_w, src_h, src_pixels, image.premultiplied)
    } else {
      let lvl = &mipmaps[(level - 1) as usize];
      (lvl.width, lvl.height, lvl.pixels.as_slice(), true)
    }
  };

  let build_axis = |out_len: u32,
                    out_origin: f32,
                    dest_origin: f32,
                    dest_size: f32,
                    src_len: u32|
   -> Option<Vec<AxisSample>> {
    if out_len == 0 || src_len == 0 || dest_size <= 0.0 || !dest_size.is_finite() {
      return None;
    }
    // Skia's raster pipeline uses 32-bit float (`SkScalar`) math when mapping from device pixels to
    // source coordinates. Using 64-bit float here can produce widespread ±1 channel diffs across
    // large photos due to slightly different fixed-point rounding, so keep the coordinate math in
    // f32 to match Skia more closely.
    let scale = src_len as f32 / dest_size;
    if !scale.is_finite() || !out_origin.is_finite() || !dest_origin.is_finite() {
      return None;
    }
    let max = src_len as f32 - 1.0;
    let mut samples = Vec::new();
    if samples.try_reserve_exact(out_len as usize).is_err() {
      return None;
    }
    for i in 0..out_len {
      let device = out_origin + i as f32 + 0.5;
      let mut s = (device - dest_origin) * scale - 0.5;
      if !s.is_finite() || !max.is_finite() {
        return None;
      }
      s = s.clamp(0.0, max);
      // Use a 16.16 fixed-point coordinate (and keep the upper 8 bits of the fractional part) so
      // the bilinear weights match Skia's truncating integer sampling.
      let s_fixed = (s * 65536.0).floor() as u64;
      let i0 = (s_fixed >> 16) as u32;
      let i1 = (i0 + 1).min(src_len - 1);
      let w = ((s_fixed >> 8) & 0xFF) as u16;
      samples.push(AxisSample { i0, i1, w });
    }
    Some(samples)
  };

  let (w_a, h_a, pixels_a, premul_a) = level_info(level_a);
  let Some(xs_a) = build_axis(
    out_width,
    out_origin_x_device,
    dest_device.x(),
    dest_device.width(),
    w_a,
  ) else {
    return Ok(None);
  };
  let Some(ys_a) = build_axis(
    out_height,
    out_origin_y_device,
    dest_device.y(),
    dest_device.height(),
    h_a,
  ) else {
    return Ok(None);
  };

  let (w_b, _h_b, pixels_b, premul_b, xs_b, ys_b) = if let Some(level_b) = level_b {
    let (w_b, _h_b, pixels_b, premul_b) = level_info(level_b);
    let Some(xs_b) = build_axis(
      out_width,
      out_origin_x_device,
      dest_device.x(),
      dest_device.width(),
      w_b,
    ) else {
      return Ok(None);
    };
    let Some(ys_b) = build_axis(
      out_height,
      out_origin_y_device,
      dest_device.y(),
      dest_device.height(),
      _h_b,
    ) else {
      return Ok(None);
    };
    (w_b, _h_b, pixels_b, premul_b, Some(xs_b), Some(ys_b))
  } else {
    (0, 0, &[][..], true, None, None)
  };

  #[inline]
  fn bilerp_u8_trunc(p00: u16, p10: u16, p01: u16, p11: u16, wx: u16, wy: u16) -> u16 {
    // `wx`/`wy` are in 0..=255, representing w/256.
    //
    // IMPORTANT: Do **not** truncate to 8-bit between the horizontal and vertical lerps.
    // Chrome/Skia appears to keep enough precision for the full 2D bilinear calculation and only
    // floors once when converting to u8 channels. Truncating the intermediate results introduces
    // widespread ±1 diffs across downscaled photos (e.g. arstechnica thumbnails).
    let inv_x = 256u32 - wx as u32;
    let inv_y = 256u32 - wy as u32;

    // Intermediate values are kept in fixed-point (1/256) until the final shift by 16.
    let top = u32::from(p00) * inv_x + u32::from(p10) * u32::from(wx);
    let bot = u32::from(p01) * inv_x + u32::from(p11) * u32::from(wx);
    let out = top * inv_y + bot * u32::from(wy);
    (out >> 16) as u16
  }
  let w0 = 1.0 - blend_t;
  let w1 = blend_t;

  let mut pixel_counter = 0usize;
  for (y, ysamp_a) in ys_a.iter().enumerate() {
    let y_u = y as u32;
    let (sy0_a, sy1_a, wy_a) = (ysamp_a.i0, ysamp_a.i1, ysamp_a.w);
    let row0_a = sy0_a as usize * w_a as usize;
    let row1_a = sy1_a as usize * w_a as usize;

    let (row0_b, row1_b, wy_b) = if let (Some(_), Some(ys_b)) = (xs_b.as_ref(), ys_b.as_ref()) {
      let ysamp_b = &ys_b[y];
      let row0_b = ysamp_b.i0 as usize * w_b as usize;
      let row1_b = ysamp_b.i1 as usize * w_b as usize;
      (Some(row0_b), Some(row1_b), Some(ysamp_b.w))
    } else {
      (None, None, None)
    };

    for (x, xsamp_a) in xs_a.iter().enumerate() {
      if (pixel_counter & 4095) == 0 {
        check_active(RenderStage::Paint)?;
      }
      pixel_counter = pixel_counter.wrapping_add(1);

      let (sx0_a, sx1_a, wx_a) = (xsamp_a.i0, xsamp_a.i1, xsamp_a.w);

      let idx00_a = (row0_a + sx0_a as usize) * 4;
      let idx10_a = (row0_a + sx1_a as usize) * 4;
      let idx01_a = (row1_a + sx0_a as usize) * 4;
      let idx11_a = (row1_a + sx1_a as usize) * 4;

      let (r00, g00, b00, a00) = read_image_pixel_premul_u16(pixels_a, idx00_a, premul_a);
      let (r10, g10, b10, a10) = read_image_pixel_premul_u16(pixels_a, idx10_a, premul_a);
      let (r01, g01, b01, a01) = read_image_pixel_premul_u16(pixels_a, idx01_a, premul_a);
      let (r11, g11, b11, a11) = read_image_pixel_premul_u16(pixels_a, idx11_a, premul_a);

      let r_a = bilerp_u8_trunc(r00, r10, r01, r11, wx_a, wy_a);
      let g_a = bilerp_u8_trunc(g00, g10, g01, g11, wx_a, wy_a);
      let b_a = bilerp_u8_trunc(b00, b10, b01, b11, wx_a, wy_a);
      let a_a = bilerp_u8_trunc(a00, a10, a01, a11, wx_a, wy_a);

      let mut r = r_a as f32;
      let mut g = g_a as f32;
      let mut b = b_a as f32;
      let mut a = a_a as f32;

      if let (Some(xs_b), Some(row0_b), Some(row1_b), Some(wy_b)) =
        (xs_b.as_ref(), row0_b, row1_b, wy_b)
      {
        let xsamp_b = &xs_b[x];
        let (sx0_b, sx1_b, wx_b) = (xsamp_b.i0, xsamp_b.i1, xsamp_b.w);

        let idx00_b = (row0_b + sx0_b as usize) * 4;
        let idx10_b = (row0_b + sx1_b as usize) * 4;
        let idx01_b = (row1_b + sx0_b as usize) * 4;
        let idx11_b = (row1_b + sx1_b as usize) * 4;

        let (r00, g00, b00, a00) = read_image_pixel_premul_u16(pixels_b, idx00_b, premul_b);
        let (r10, g10, b10, a10) = read_image_pixel_premul_u16(pixels_b, idx10_b, premul_b);
        let (r01, g01, b01, a01) = read_image_pixel_premul_u16(pixels_b, idx01_b, premul_b);
        let (r11, g11, b11, a11) = read_image_pixel_premul_u16(pixels_b, idx11_b, premul_b);

        let r_b = bilerp_u8_trunc(r00, r10, r01, r11, wx_b, wy_b) as f32;
        let g_b = bilerp_u8_trunc(g00, g10, g01, g11, wx_b, wy_b) as f32;
        let b_b = bilerp_u8_trunc(b00, b10, b01, b11, wx_b, wy_b) as f32;
        let a_b = bilerp_u8_trunc(a00, a10, a01, a11, wx_b, wy_b) as f32;

        r = r * w0 + r_b * w1;
        g = g * w0 + g_b * w1;
        b = b * w0 + b_b * w1;
        a = a * w0 + a_b * w1;
      }

      // Chrome/Skia rounds down when converting to 8-bit channels.
      let a_u8 = a.floor().clamp(0.0, 255.0) as u8;
      let mut r_u8 = r.floor().clamp(0.0, 255.0) as u8;
      let mut g_u8 = g.floor().clamp(0.0, 255.0) as u8;
      let mut b_u8 = b.floor().clamp(0.0, 255.0) as u8;

      r_u8 = r_u8.min(a_u8);
      g_u8 = g_u8.min(a_u8);
      b_u8 = b_u8.min(a_u8);

      let dst_idx = (y_u * out_width + x as u32) as usize * 4;
      data[dst_idx] = r_u8;
      data[dst_idx + 1] = g_u8;
      data[dst_idx + 2] = b_u8;
      data[dst_idx + 3] = a_u8;
    }
  }

  Ok(Pixmap::from_vec(data, size))
}

fn image_data_to_scaled_pixmap_from_src_rect_with_phase_inner(
  image: &ImageData,
  src_rect: Rect,
  dest_device: Rect,
  out_width: u32,
  out_height: u32,
  out_origin_x_device: f32,
  out_origin_y_device: f32,
) -> RenderResult<Option<Pixmap>> {
  if out_width == 0
    || out_height == 0
    || !out_origin_x_device.is_finite()
    || !out_origin_y_device.is_finite()
  {
    return Ok(None);
  }
  if !(dest_device.width().is_finite()
    && dest_device.height().is_finite()
    && dest_device.width() > 0.0
    && dest_device.height() > 0.0
    && dest_device.x().is_finite()
    && dest_device.y().is_finite())
  {
    return Ok(None);
  }

  if !(src_rect.x().is_finite()
    && src_rect.y().is_finite()
    && src_rect.width().is_finite()
    && src_rect.height().is_finite()
    && src_rect.width() > 0.0
    && src_rect.height() > 0.0)
  {
    return Ok(None);
  }

  let src_w = image.width;
  let src_h = image.height;
  if src_w == 0 || src_h == 0 {
    return Ok(None);
  }

  // `ImageItem::src_rect` is implemented by mapping the *full* image into the destination rect
  // (preserving fractional source offsets) and then clipping to the destination. Reconstruct that
  // same full-image destination mapping and feed it through the mipmap-capable Skia-aligned sampler
  // so downscaled backgrounds behave closer to Chrome.
  let scale_x = dest_device.width() / src_rect.width();
  let scale_y = dest_device.height() / src_rect.height();
  if !scale_x.is_finite() || !scale_y.is_finite() || scale_x <= 0.0 || scale_y <= 0.0 {
    return Ok(None);
  }
  let tx = dest_device.x() - src_rect.x() * scale_x;
  let ty = dest_device.y() - src_rect.y() * scale_y;
  let full_w = src_w as f32 * scale_x;
  let full_h = src_h as f32 * scale_y;
  if !(tx.is_finite()
    && ty.is_finite()
    && full_w.is_finite()
    && full_h.is_finite()
    && full_w > 0.0
    && full_h > 0.0)
  {
    return Ok(None);
  }
  let dest_full = Rect::from_xywh(tx, ty, full_w, full_h);

  image_data_to_scaled_pixmap_with_phase_inner(
    image,
    dest_full,
    out_width,
    out_height,
    out_origin_x_device,
    out_origin_y_device,
  )
}

fn image_data_to_scaled_pixmap_inner(
  image: &ImageData,
  target_width: u32,
  target_height: u32,
  quality: ImageFilterQuality,
) -> RenderResult<Option<Pixmap>> {
  if target_width == 0 || target_height == 0 {
    return Ok(None);
  }
  let src_w = image.width;
  let src_h = image.height;
  if src_w == 0 || src_h == 0 {
    return Ok(None);
  }
  if target_width == src_w && target_height == src_h {
    return image_data_to_pixmap_inner(image);
  }
  if quality != ImageFilterQuality::Linear {
    return image_data_to_pixmap_inner(image);
  }

  let dest = Rect::from_xywh(0.0, 0.0, target_width as f32, target_height as f32);
  image_data_to_scaled_pixmap_with_phase_inner(image, dest, target_width, target_height, 0.0, 0.0)
}

fn image_data_to_scaled_pixmap_from_rect_inner(
  image: &ImageData,
  src_x: u32,
  src_y: u32,
  src_width: u32,
  src_height: u32,
  target_width: u32,
  target_height: u32,
  quality: ImageFilterQuality,
) -> RenderResult<Option<Pixmap>> {
  if target_width == 0 || target_height == 0 {
    return Ok(None);
  }
  let full_w = image.width;
  let full_h = image.height;
  if full_w == 0 || full_h == 0 {
    return Ok(None);
  }
  if src_width == 0 || src_height == 0 {
    return Ok(None);
  }
  if src_x >= full_w || src_y >= full_h {
    return Ok(None);
  }
  if quality != ImageFilterQuality::Linear {
    return Ok(None);
  }

  let max_w = full_w.saturating_sub(src_x);
  let max_h = full_h.saturating_sub(src_y);
  let src_w = src_width.min(max_w);
  let src_h = src_height.min(max_h);
  if src_w == 0 || src_h == 0 {
    return Ok(None);
  }
  if target_width >= src_w || target_height >= src_h {
    return Ok(None);
  }

  let Some(size) = IntSize::from_wh(target_width, target_height) else {
    return Ok(None);
  };
  let Some(bytes) = u64::from(target_width)
    .checked_mul(u64::from(target_height))
    .and_then(|px| px.checked_mul(4))
  else {
    return Ok(None);
  };

  let mut data = match reserve_buffer(bytes, "scaled image pixmap") {
    Ok(buf) => buf,
    Err(_) => return Ok(None),
  };
  data.resize(bytes as usize, 0);

  check_active(RenderStage::Paint)?;
  let src_pixels = image.pixels.as_ref().as_slice();
  let Some(expected_src_bytes) = u64::from(full_w)
    .checked_mul(u64::from(full_h))
    .and_then(|px| px.checked_mul(4))
  else {
    return Ok(None);
  };
  let Ok(expected_src_len) = usize::try_from(expected_src_bytes) else {
    return Ok(None);
  };
  if src_pixels.len() != expected_src_len {
    return Ok(None);
  }

  #[derive(Clone, Copy)]
  struct AxisSample {
    i0: u32,
    i1: u32,
    t: f32,
  }

  let scale_x0 = src_w as f32 / target_width as f32;
  let scale_y0 = src_h as f32 / target_height as f32;
  if !scale_x0.is_finite() || !scale_y0.is_finite() {
    return Ok(None);
  }

  let (mut base_level, mut blend_t) = mipmap_lod_for_scale(scale_x0, scale_y0).unwrap_or((0, 0.0));
  let mut needs_second_level = blend_t > 0.0;
  let max_level = base_level + if needs_second_level { 1 } else { 0 };

  // Build a mipmap chain for the cropped region. Level 0 is the source crop; level 1 is generated
  // directly from the original image pixels without allocating an intermediate full-resolution crop.
  let mut mipmaps: Vec<MipmapLevelBuf> = Vec::new();
  if max_level > 0 {
    if mipmaps.try_reserve_exact(max_level as usize).is_err() {
      return Ok(None);
    }

    // Level 1: downsample from the crop region in the original image.
    let out_w1 = src_w / 2;
    let out_h1 = src_h / 2;
    if out_w1 > 0 && out_h1 > 0 && IntSize::from_wh(out_w1, out_h1).is_some() {
      let Some(level1_bytes) = u64::from(out_w1)
        .checked_mul(u64::from(out_h1))
        .and_then(|px| px.checked_mul(4))
      else {
        return Ok(None);
      };
      let mut level1 = match reserve_buffer(level1_bytes, "mipmap level (crop)") {
        Ok(buf) => buf,
        Err(_) => return Ok(None),
      };
      level1.resize(level1_bytes as usize, 0);

      check_active(RenderStage::Paint)?;
      let full_w_usize = full_w as usize;
      let premultiplied = image.premultiplied;
      let mut pixel_counter = 0usize;
      for y in 0..out_h1 {
        let oy0 = (src_y + y * 2) as usize;
        let oy1 = oy0 + 1;
        let row0 = oy0 * full_w_usize;
        let row1 = oy1 * full_w_usize;
        for x in 0..out_w1 {
          if (pixel_counter & 4095) == 0 {
            check_active(RenderStage::Paint)?;
          }
          pixel_counter = pixel_counter.wrapping_add(1);

          let ox0 = (src_x + x * 2) as usize;
          let idx00 = (row0 + ox0) * 4;
          let idx10 = idx00 + 4;
          let idx01 = (row1 + ox0) * 4;
          let idx11 = idx01 + 4;

          let (r00, g00, b00, a00) = read_image_pixel_premul(src_pixels, idx00, premultiplied);
          let (r10, g10, b10, a10) = read_image_pixel_premul(src_pixels, idx10, premultiplied);
          let (r01, g01, b01, a01) = read_image_pixel_premul(src_pixels, idx01, premultiplied);
          let (r11, g11, b11, a11) = read_image_pixel_premul(src_pixels, idx11, premultiplied);

          let inv = 0.25;
          let sum_r = (r00 + r10 + r01 + r11) * inv;
          let sum_g = (g00 + g10 + g01 + g11) * inv;
          let sum_b = (b00 + b10 + b01 + b11) * inv;
          let sum_a = (a00 + a10 + a01 + a11) * inv;

          let a = sum_a.floor().clamp(0.0, 255.0) as u8;
          let mut r = sum_r.floor().clamp(0.0, 255.0) as u8;
          let mut g = sum_g.floor().clamp(0.0, 255.0) as u8;
          let mut b = sum_b.floor().clamp(0.0, 255.0) as u8;

          r = r.min(a);
          g = g.min(a);
          b = b.min(a);

          let dst_idx = (y * out_w1 + x) as usize * 4;
          level1[dst_idx] = r;
          level1[dst_idx + 1] = g;
          level1[dst_idx + 2] = b;
          level1[dst_idx + 3] = a;
        }
      }

      mipmaps.push(MipmapLevelBuf {
        width: out_w1,
        height: out_h1,
        pixels: level1,
      });
    }

    // Higher levels: downsample the previous premultiplied level.
    for level in 2..=max_level {
      let next = if let Some(prev) = mipmaps.get((level - 2) as usize) {
        downsample_mipmap_level(prev.pixels.as_slice(), prev.width, prev.height, true)?
      } else {
        None
      };
      let Some(next) = next else {
        break;
      };
      mipmaps.push(next);
    }
  }

  let max_available = mipmaps.len() as u32;
  if base_level > max_available {
    base_level = max_available;
    blend_t = 0.0;
    needs_second_level = false;
  } else if needs_second_level && base_level + 1 > max_available {
    blend_t = 0.0;
    needs_second_level = false;
  }

  let level_a = base_level;
  let level_b = needs_second_level.then(|| base_level + 1);

  let build_axis = |out_len: u32, src_len: u32| -> Option<Vec<AxisSample>> {
    if out_len == 0 || src_len == 0 {
      return None;
    }
    let scale = src_len as f32 / out_len as f32;
    if !scale.is_finite() {
      return None;
    }
    let max = src_len as f32 - 1.0;
    let mut samples = Vec::new();
    if samples.try_reserve_exact(out_len as usize).is_err() {
      return None;
    }
    for i in 0..out_len {
      let mut s = (i as f32 + 0.5) * scale - 0.5;
      if !s.is_finite() {
        return None;
      }
      s = s.clamp(0.0, max);
      let i0 = s.floor() as u32;
      let i1 = (i0 + 1).min(src_len - 1);
      samples.push(AxisSample {
        i0,
        i1,
        t: s - i0 as f32,
      });
    }
    Some(samples)
  };

  let level_info = |level: u32| -> (u32, u32, &[u8], bool, u32, u32) {
    if level == 0 {
      (src_w, src_h, src_pixels, image.premultiplied, src_x, src_y)
    } else {
      let lvl = &mipmaps[(level - 1) as usize];
      (lvl.width, lvl.height, lvl.pixels.as_slice(), true, 0, 0)
    }
  };

  let (w_a, h_a, pixels_a, premul_a, off_x_a, off_y_a) = level_info(level_a);
  let Some(xs_a) = build_axis(target_width, w_a) else {
    return Ok(None);
  };
  let Some(ys_a) = build_axis(target_height, h_a) else {
    return Ok(None);
  };

  let (w_b, pixels_b, premul_b, off_x_b, off_y_b, xs_b, ys_b) = if let Some(level_b) = level_b {
    let (w_b, h_b, pixels_b, premul_b, off_x_b, off_y_b) = level_info(level_b);
    let Some(xs_b) = build_axis(target_width, w_b) else {
      return Ok(None);
    };
    let Some(ys_b) = build_axis(target_height, h_b) else {
      return Ok(None);
    };
    (
      w_b,
      pixels_b,
      premul_b,
      off_x_b,
      off_y_b,
      Some(xs_b),
      Some(ys_b),
    )
  } else {
    (0, &[][..], true, 0, 0, None, None)
  };

  let lerp = |a: f32, b: f32, t: f32| a + (b - a) * t;
  let w0 = 1.0 - blend_t;
  let w1 = blend_t;

  let mut pixel_counter = 0usize;
  for (y, ysamp_a) in ys_a.iter().enumerate() {
    let y_u = y as u32;
    let (sy0_a, sy1_a, fy_a) = (ysamp_a.i0 + off_y_a, ysamp_a.i1 + off_y_a, ysamp_a.t);
    let stride_a = if level_a == 0 {
      full_w as usize
    } else {
      w_a as usize
    };
    let row0_a = sy0_a as usize * stride_a;
    let row1_a = sy1_a as usize * stride_a;

    let (row0_b, row1_b, fy_b) = if let (Some(_), Some(ys_b)) = (xs_b.as_ref(), ys_b.as_ref()) {
      let ysamp_b = &ys_b[y];
      let sy0_b = ysamp_b.i0 + off_y_b;
      let sy1_b = ysamp_b.i1 + off_y_b;
      let stride_b = if level_b.is_some_and(|lvl| lvl == 0) {
        full_w as usize
      } else {
        w_b as usize
      };
      let row0_b = sy0_b as usize * stride_b;
      let row1_b = sy1_b as usize * stride_b;
      (Some(row0_b), Some(row1_b), Some(ysamp_b.t))
    } else {
      (None, None, None)
    };

    for (x, xsamp_a) in xs_a.iter().enumerate() {
      if (pixel_counter & 4095) == 0 {
        check_active(RenderStage::Paint)?;
      }
      pixel_counter = pixel_counter.wrapping_add(1);

      let (sx0_a, sx1_a, fx_a) = (xsamp_a.i0 + off_x_a, xsamp_a.i1 + off_x_a, xsamp_a.t);

      let idx00_a = (row0_a + sx0_a as usize) * 4;
      let idx10_a = (row0_a + sx1_a as usize) * 4;
      let idx01_a = (row1_a + sx0_a as usize) * 4;
      let idx11_a = (row1_a + sx1_a as usize) * 4;

      let (r00, g00, b00, a00) = read_image_pixel_premul(pixels_a, idx00_a, premul_a);
      let (r10, g10, b10, a10) = read_image_pixel_premul(pixels_a, idx10_a, premul_a);
      let (r01, g01, b01, a01) = read_image_pixel_premul(pixels_a, idx01_a, premul_a);
      let (r11, g11, b11, a11) = read_image_pixel_premul(pixels_a, idx11_a, premul_a);

      let top_r_a = lerp(r00, r10, fx_a);
      let top_g_a = lerp(g00, g10, fx_a);
      let top_b_a = lerp(b00, b10, fx_a);
      let top_a_a = lerp(a00, a10, fx_a);

      let bot_r_a = lerp(r01, r11, fx_a);
      let bot_g_a = lerp(g01, g11, fx_a);
      let bot_b_a = lerp(b01, b11, fx_a);
      let bot_a_a = lerp(a01, a11, fx_a);

      let mut r = lerp(top_r_a, bot_r_a, fy_a);
      let mut g = lerp(top_g_a, bot_g_a, fy_a);
      let mut b = lerp(top_b_a, bot_b_a, fy_a);
      let mut a = lerp(top_a_a, bot_a_a, fy_a);

      if let (Some(xs_b), Some(row0_b), Some(row1_b), Some(fy_b)) =
        (xs_b.as_ref(), row0_b, row1_b, fy_b)
      {
        let xsamp_b = &xs_b[x];
        let (sx0_b, sx1_b, fx_b) = (xsamp_b.i0 + off_x_b, xsamp_b.i1 + off_x_b, xsamp_b.t);

        let idx00_b = (row0_b + sx0_b as usize) * 4;
        let idx10_b = (row0_b + sx1_b as usize) * 4;
        let idx01_b = (row1_b + sx0_b as usize) * 4;
        let idx11_b = (row1_b + sx1_b as usize) * 4;

        let (r00, g00, b00, a00) = read_image_pixel_premul(pixels_b, idx00_b, premul_b);
        let (r10, g10, b10, a10) = read_image_pixel_premul(pixels_b, idx10_b, premul_b);
        let (r01, g01, b01, a01) = read_image_pixel_premul(pixels_b, idx01_b, premul_b);
        let (r11, g11, b11, a11) = read_image_pixel_premul(pixels_b, idx11_b, premul_b);

        let top_r_b = lerp(r00, r10, fx_b);
        let top_g_b = lerp(g00, g10, fx_b);
        let top_b_b = lerp(b00, b10, fx_b);
        let top_a_b = lerp(a00, a10, fx_b);

        let bot_r_b = lerp(r01, r11, fx_b);
        let bot_g_b = lerp(g01, g11, fx_b);
        let bot_b_b = lerp(b01, b11, fx_b);
        let bot_a_b = lerp(a01, a11, fx_b);

        let r_b = lerp(top_r_b, bot_r_b, fy_b);
        let g_b = lerp(top_g_b, bot_g_b, fy_b);
        let b_b = lerp(top_b_b, bot_b_b, fy_b);
        let a_b = lerp(top_a_b, bot_a_b, fy_b);

        r = r * w0 + r_b * w1;
        g = g * w0 + g_b * w1;
        b = b * w0 + b_b * w1;
        a = a * w0 + a_b * w1;
      }

      let a_u8 = a.floor().clamp(0.0, 255.0) as u8;
      let mut r_u8 = r.floor().clamp(0.0, 255.0) as u8;
      let mut g_u8 = g.floor().clamp(0.0, 255.0) as u8;
      let mut b_u8 = b.floor().clamp(0.0, 255.0) as u8;

      r_u8 = r_u8.min(a_u8);
      g_u8 = g_u8.min(a_u8);
      b_u8 = b_u8.min(a_u8);

      let dst_idx = (y_u * target_width + x as u32) as usize * 4;
      data[dst_idx] = r_u8;
      data[dst_idx + 1] = g_u8;
      data[dst_idx + 2] = b_u8;
      data[dst_idx + 3] = a_u8;
    }
  }

  Ok(Pixmap::from_vec(data, size))
}

fn sample_conic_stops(
  stops: &[(f32, crate::style::color::Rgba)],
  t: f32,
  repeating: bool,
  period: f32,
) -> crate::style::color::Rgba {
  if stops.is_empty() {
    return crate::style::color::Rgba::TRANSPARENT;
  }
  if stops.len() == 1 {
    return stops[0].1;
  }
  let total = if repeating {
    period
  } else {
    stops.last().map(|s| s.0).unwrap_or(1.0)
  };
  let mut pos = t;
  if repeating && total > 0.0 {
    pos = pos.rem_euclid(total);
  }
  if pos <= stops[0].0 {
    return stops[0].1;
  }
  if pos >= stops.last().unwrap().0 && !repeating {
    return stops.last().unwrap().1;
  }
  for window in stops.windows(2) {
    let (p0, c0) = window[0];
    let (p1, c1) = window[1];
    if pos < p0 {
      return c0;
    }
    if pos <= p1 || (repeating && (p1 - p0).abs() < f32::EPSILON) {
      let span = (p1 - p0).max(1e-6);
      let frac = ((pos - p0) / span).clamp(0.0, 1.0);
      return crate::style::color::Rgba {
        r: ((1.0 - frac) * c0.r as f32 + frac * c1.r as f32)
          .round()
          .clamp(0.0, 255.0) as u8,
        g: ((1.0 - frac) * c0.g as f32 + frac * c1.g as f32)
          .round()
          .clamp(0.0, 255.0) as u8,
        b: ((1.0 - frac) * c0.b as f32 + frac * c1.b as f32)
          .round()
          .clamp(0.0, 255.0) as u8,
        a: (1.0 - frac) * c0.a + frac * c1.a,
      };
    }
  }
  stops.last().unwrap().1
}
#[derive(Copy, Clone)]
struct BorderImageWidths {
  top: f32,
  right: f32,
  bottom: f32,
  left: f32,
}

fn resolve_slice_value(value: BorderImageSliceValue, axis_len: u32) -> f32 {
  match value {
    BorderImageSliceValue::Number(n) => n.max(0.0),
    BorderImageSliceValue::Percentage(p) => (p / 100.0) * axis_len as f32,
  }
}

fn resolve_length_for_border_image(
  len: &Length,
  percentage_base: f32,
  font_size: f32,
  root_font_size: f32,
  viewport: Option<(f32, f32)>,
) -> f32 {
  crate::paint::paint_bounds::resolve_length_for_paint(
    len,
    font_size,
    root_font_size,
    percentage_base,
    viewport,
  )
}

fn resolve_border_image_widths(
  widths: &BorderImageWidth,
  border: BorderImageWidths,
  box_width: f32,
  box_height: f32,
  font_size: f32,
  root_font_size: f32,
  viewport: Option<(f32, f32)>,
) -> BorderImageWidths {
  let resolve_single = |value: BorderImageWidthValue, border: f32, axis: f32| -> f32 {
    match value {
      BorderImageWidthValue::Auto => border,
      BorderImageWidthValue::Number(n) => (n * border).max(0.0),
      BorderImageWidthValue::Length(len) => {
        resolve_length_for_border_image(&len, axis, font_size, root_font_size, viewport).max(0.0)
      }
      BorderImageWidthValue::Percentage(p) => ((p / 100.0) * axis).max(0.0),
    }
  };

  BorderImageWidths {
    top: resolve_single(widths.top, border.top, box_height),
    right: resolve_single(widths.right, border.right, box_width),
    bottom: resolve_single(widths.bottom, border.bottom, box_height),
    left: resolve_single(widths.left, border.left, box_width),
  }
}

fn resolve_border_image_outset(
  outset: &crate::style::types::BorderImageOutset,
  border: BorderImageWidths,
  font_size: f32,
  root_font_size: f32,
  viewport: Option<(f32, f32)>,
) -> BorderImageWidths {
  let resolve_single = |value: BorderImageOutsetValue, border: f32| -> f32 {
    match value {
      BorderImageOutsetValue::Number(n) => (n * border).max(0.0),
      BorderImageOutsetValue::Length(len) => {
        resolve_length_for_border_image(&len, border.max(1.0), font_size, root_font_size, viewport)
          .max(0.0)
      }
    }
  };

  BorderImageWidths {
    top: resolve_single(outset.top, border.top),
    right: resolve_single(outset.right, border.right),
    bottom: resolve_single(outset.bottom, border.bottom),
    left: resolve_single(outset.left, border.left),
  }
}

fn normalize_color_stops(
  stops: &[ColorStop],
  current_color: Rgba,
  gradient_length: f32,
  font_size: f32,
  root_font_size: f32,
  viewport: Option<(f32, f32)>,
  is_dark: bool,
  forced_colors: bool,
) -> Vec<(f32, Rgba)> {
  // CSS Images 3: Gradient color stop “fixup”.
  //
  // https://www.w3.org/TR/css-images-3/#color-stop-fixup
  //
  // Stop positions are not clamped to the [0%, 100%] range; they may appear anywhere on the
  // infinite gradient line (e.g. `-50%`, `150%`).
  if stops.is_empty() {
    return Vec::new();
  }

  let gradient_length = if gradient_length.is_finite() && gradient_length > 0.0 {
    gradient_length
  } else {
    0.0
  };
  let (vw, vh) = viewport.unwrap_or((0.0, 0.0));

  let mut positions: Vec<Option<f32>> = stops
    .iter()
    .map(|stop| match stop.position {
      Some(crate::css::types::ColorStopPosition::Fraction(v)) => Some(v),
      Some(crate::css::types::ColorStopPosition::Length(len)) => {
        if gradient_length <= 0.0 {
          None
        } else {
          len
            .resolve_with_context(Some(gradient_length), vw, vh, font_size, root_font_size)
            .map(|px| px / gradient_length)
        }
      }
      None => None,
    })
    .collect();

  // If no stops had positions at all, evenly distribute them from 0%..100%.
  if positions.iter().all(|p| p.is_none()) {
    if stops.len() == 1 {
      return vec![(
        0.0,
        stops[0]
          .color
          .to_rgba_with_scheme_and_forced_colors(current_color, is_dark, forced_colors),
      )];
    }
    let denom = (stops.len() - 1) as f32;
    return stops
      .iter()
      .enumerate()
      .map(|(i, stop)| {
        (
          i as f32 / denom,
          stop
            .color
            .to_rgba_with_scheme_and_forced_colors(current_color, is_dark, forced_colors),
        )
      })
      .collect();
  }

  // Step 1: If the first stop has no position, set it to 0%.
  if positions.first().and_then(|p| *p).is_none() {
    positions[0] = Some(0.0);
  }
  // Step 2: If the last stop has no position, set it to 100%.
  if positions.last().and_then(|p| *p).is_none() {
    if let Some(last) = positions.last_mut() {
      *last = Some(1.0);
    }
  }

  // Step 3: Ensure positioned stops are non-decreasing.
  let mut max_specified = positions[0].unwrap_or(0.0);
  for pos in positions.iter_mut().skip(1) {
    if let Some(value) = *pos {
      if value < max_specified {
        *pos = Some(max_specified);
      } else {
        max_specified = value;
      }
    }
  }

  // Step 4: Distribute runs of missing stops between the nearest positioned stops.
  let mut idx = 0usize;
  while idx < positions.len() {
    if positions[idx].is_some() {
      idx += 1;
      continue;
    }

    // Safe because step 1 guarantees the first entry is positioned.
    let start_idx = idx.saturating_sub(1);
    let start_pos = positions[start_idx].unwrap_or(0.0);

    let mut end_idx = idx;
    while end_idx < positions.len() && positions[end_idx].is_none() {
      end_idx += 1;
    }
    // Safe because step 2 guarantees the last entry is positioned.
    if end_idx >= positions.len() {
      break;
    }
    let end_pos = positions[end_idx].unwrap_or(start_pos);

    let span = (end_idx - start_idx) as f32;
    for offset in 1..(end_idx - start_idx) {
      let t = offset as f32 / span;
      positions[start_idx + offset] = Some(start_pos + (end_pos - start_pos) * t);
    }

    idx = end_idx + 1;
  }

  // Pair the resolved positions with colors, keeping the result monotonic.
  let mut output = Vec::with_capacity(stops.len());
  let mut prev = f32::NEG_INFINITY;
  for (stop, pos_opt) in stops.iter().zip(positions.iter()) {
    let pos = pos_opt.unwrap_or(prev);
    let used = if pos < prev { prev } else { pos };
    prev = used;
    output.push((
      used,
      stop
        .color
        .to_rgba_with_scheme_and_forced_colors(current_color, is_dark, forced_colors),
    ));
  }

  output
}

fn normalize_color_stops_unclamped(
  stops: &[ColorStop],
  current_color: Rgba,
  gradient_length: f32,
  font_size: f32,
  root_font_size: f32,
  viewport: Option<(f32, f32)>,
  is_dark: bool,
  forced_colors: bool,
) -> Vec<(f32, Rgba)> {
  normalize_color_stops(
    stops,
    current_color,
    gradient_length,
    font_size,
    root_font_size,
    viewport,
    is_dark,
    forced_colors,
  )
}

fn gradient_stops(stops: &[(f32, Rgba)]) -> Vec<tiny_skia::GradientStop> {
  stops
    .iter()
    .map(|(p, c)| {
      tiny_skia::GradientStop::new(
        *p,
        tiny_skia::Color::from_rgba8(c.r, c.g, c.b, (c.a * 255.0).round().clamp(0.0, 255.0) as u8),
      )
    })
    .collect()
}

fn radial_geometry(
  rect: Rect,
  position: &BackgroundPosition,
  size: &RadialGradientSize,
  shape: RadialGradientShape,
  font_size: f32,
  root_font_size: f32,
  viewport: Option<(f32, f32)>,
) -> (f32, f32, f32, f32) {
  let (align_x, off_x, align_y, off_y) = match position {
    BackgroundPosition::Position { x, y } => {
      let ox = resolve_length_for_border_image(
        &x.offset,
        rect.width(),
        font_size,
        root_font_size,
        viewport,
      );
      let oy = resolve_length_for_border_image(
        &y.offset,
        rect.height(),
        font_size,
        root_font_size,
        viewport,
      );
      (x.alignment, ox, y.alignment, oy)
    }
  };
  let cx = rect.x() + align_x * rect.width() + off_x;
  let cy = rect.y() + align_y * rect.height() + off_y;

  let dx_left = (cx - rect.x()).max(0.0);
  let dx_right = (rect.x() + rect.width() - cx).max(0.0);
  let dy_top = (cy - rect.y()).max(0.0);
  let dy_bottom = (rect.y() + rect.height() - cy).max(0.0);

  let (mut radius_x, mut radius_y) = match size {
    RadialGradientSize::ClosestSide => (dx_left.min(dx_right), dy_top.min(dy_bottom)),
    RadialGradientSize::FarthestSide => (dx_left.max(dx_right), dy_top.max(dy_bottom)),
    RadialGradientSize::ClosestCorner => {
      let corners = [
        (dx_left, dy_top),
        (dx_left, dy_bottom),
        (dx_right, dy_top),
        (dx_right, dy_bottom),
      ];
      let mut best = f32::INFINITY;
      let mut best_pair = (0.0, 0.0);
      for (dx, dy) in corners {
        let dist = (dx * dx + dy * dy).sqrt();
        if dist < best {
          best = dist;
          best_pair = (dx, dy);
        }
      }
      (
        best_pair.0 * std::f32::consts::SQRT_2,
        best_pair.1 * std::f32::consts::SQRT_2,
      )
    }
    RadialGradientSize::FarthestCorner => {
      let corners = [
        (dx_left, dy_top),
        (dx_left, dy_bottom),
        (dx_right, dy_top),
        (dx_right, dy_bottom),
      ];
      let mut best = -f32::INFINITY;
      let mut best_pair = (0.0, 0.0);
      for (dx, dy) in corners {
        let dist = (dx * dx + dy * dy).sqrt();
        if dist > best {
          best = dist;
          best_pair = (dx, dy);
        }
      }
      (
        best_pair.0 * std::f32::consts::SQRT_2,
        best_pair.1 * std::f32::consts::SQRT_2,
      )
    }
    RadialGradientSize::Explicit { x, y } => {
      let rx =
        resolve_length_for_border_image(x, rect.width(), font_size, root_font_size, viewport)
          .max(0.0);
      let ry = y
        .as_ref()
        .map(|yy| {
          resolve_length_for_border_image(yy, rect.height(), font_size, root_font_size, viewport)
            .max(0.0)
        })
        .unwrap_or(rx);
      (rx, ry)
    }
  };

  if matches!(shape, RadialGradientShape::Circle) {
    let r = if matches!(
      size,
      RadialGradientSize::ClosestCorner | RadialGradientSize::FarthestCorner
    ) {
      let r_corner = ((radius_x * radius_x + radius_y * radius_y) / 2.0).sqrt();
      r_corner
    } else {
      radius_x.max(radius_y)
    };
    radius_x = r;
    radius_y = r;
  }

  (cx, cy, radius_x.max(0.0), radius_y.max(0.0))
}

fn resolve_gradient_center(
  rect: Rect,
  position: &BackgroundPosition,
  font_size: f32,
  root_font_size: f32,
  viewport: Option<(f32, f32)>,
) -> Point {
  let (align_x, off_x, align_y, off_y) = match position {
    BackgroundPosition::Position { x, y } => {
      let ox = resolve_length_for_border_image(
        &x.offset,
        rect.width(),
        font_size,
        root_font_size,
        viewport,
      );
      let oy = resolve_length_for_border_image(
        &y.offset,
        rect.height(),
        font_size,
        root_font_size,
        viewport,
      );
      (x.alignment, ox, y.alignment, oy)
    }
  };
  let cx = rect.x() + align_x * rect.width() + off_x;
  let cy = rect.y() + align_y * rect.height() + off_y;
  Point::new(cx, cy)
}

fn render_generated_border_image_subrect(
  bg: &BackgroundImage,
  current_color: Rgba,
  is_dark: bool,
  forced_colors: bool,
  full_width: u32,
  full_height: u32,
  crop_x: f32,
  crop_y: f32,
  width: u32,
  height: u32,
  font_size: f32,
  root_font_size: f32,
  viewport: Option<(f32, f32)>,
  pixmap_cache: &GradientPixmapCache,
  cache: &GradientLutCache,
) -> Option<Arc<Pixmap>> {
  if width == 0 || height == 0 || full_width == 0 || full_height == 0 {
    return None;
  }

  let crop_x = if crop_x.is_finite() { crop_x } else { 0.0 };
  let crop_y = if crop_y.is_finite() { crop_y } else { 0.0 };
  let crop_x_i32 = crop_x.floor() as i32;
  let crop_y_i32 = crop_y.floor() as i32;
  let dither_phase = (((crop_y_i32 & 7) as u8) << 3) | ((crop_x_i32 & 7) as u8);
  let rect = Rect::from_xywh(0.0, 0.0, full_width as f32, full_height as f32);
  match bg {
    BackgroundImage::LinearGradient { angle, stops } => {
      let rad = angle.to_radians();
      let dx = rad.sin();
      let dy = -rad.cos();
      let gradient_length = rect.width() * dx.abs() + rect.height() * dy.abs();
      let resolved = normalize_color_stops(
        stops,
        current_color,
        gradient_length,
        font_size,
        root_font_size,
        viewport,
        is_dark,
        forced_colors,
      );
      if resolved.is_empty() {
        return None;
      }
      let len = 0.5 * (rect.width() * dx.abs() + rect.height() * dy.abs());
      let cx = rect.width() * 0.5;
      let cy = rect.height() * 0.5;
      let start = Point::new(cx - dx * len - crop_x, cy - dy * len - crop_y);
      let end = Point::new(cx + dx * len - crop_x, cy + dy * len - crop_y);
      rasterize_linear_gradient_cached(
        pixmap_cache,
        width,
        height,
        start,
        end,
        SpreadMode::Pad,
        &resolved,
        cache,
        gradient_bucket(full_width.max(full_height)),
        dither_phase,
      )
      .ok()
      .flatten()
    }
    BackgroundImage::RepeatingLinearGradient { angle, stops } => {
      let rad = angle.to_radians();
      let dx = rad.sin();
      let dy = -rad.cos();
      let gradient_length = rect.width() * dx.abs() + rect.height() * dy.abs();
      let resolved = normalize_color_stops(
        stops,
        current_color,
        gradient_length,
        font_size,
        root_font_size,
        viewport,
        is_dark,
        forced_colors,
      );
      if resolved.is_empty() {
        return None;
      }
      let len = 0.5 * (rect.width() * dx.abs() + rect.height() * dy.abs());
      let cx = rect.width() * 0.5;
      let cy = rect.height() * 0.5;
      let start = Point::new(cx - dx * len - crop_x, cy - dy * len - crop_y);
      let end = Point::new(cx + dx * len - crop_x, cy + dy * len - crop_y);
      rasterize_linear_gradient_cached(
        pixmap_cache,
        width,
        height,
        start,
        end,
        SpreadMode::Repeat,
        &resolved,
        cache,
        gradient_bucket(full_width.max(full_height)),
        dither_phase,
      )
      .ok()
      .flatten()
    }
    BackgroundImage::RadialGradient {
      shape,
      size,
      position,
      stops,
    } => {
      let (cx, cy, radius_x, radius_y) = radial_geometry(
        rect,
        position,
        size,
        *shape,
        font_size,
        root_font_size,
        viewport,
      );
      let resolved = normalize_color_stops(
        stops,
        current_color,
        radius_x.max(radius_y),
        font_size,
        root_font_size,
        viewport,
        is_dark,
        forced_colors,
      );
      if resolved.is_empty() {
        return None;
      }
      let center = Point::new(cx - crop_x, cy - crop_y);
      let radii = Point::new(radius_x, radius_y);
      let key = GradientPixmapCacheKey::radial(
        width,
        height,
        center,
        radii,
        SpreadMode::Pad,
        &resolved,
        dither_phase,
      )?;
      let bucket = gradient_bucket(full_width.max(full_height));
      pixmap_cache
        .get_or_insert(key, || {
          rasterize_radial_gradient(
            width,
            height,
            center,
            radii,
            SpreadMode::Pad,
            &resolved,
            cache,
            bucket,
            dither_phase,
          )
        })
        .ok()
        .flatten()
    }
    BackgroundImage::RepeatingRadialGradient {
      shape,
      size,
      position,
      stops,
    } => {
      let (cx, cy, radius_x, radius_y) = radial_geometry(
        rect,
        position,
        size,
        *shape,
        font_size,
        root_font_size,
        viewport,
      );
      let resolved = normalize_color_stops(
        stops,
        current_color,
        radius_x.max(radius_y),
        font_size,
        root_font_size,
        viewport,
        is_dark,
        forced_colors,
      );
      if resolved.is_empty() {
        return None;
      }
      let center = Point::new(cx - crop_x, cy - crop_y);
      let radii = Point::new(radius_x, radius_y);
      let key = GradientPixmapCacheKey::radial(
        width,
        height,
        center,
        radii,
        SpreadMode::Repeat,
        &resolved,
        dither_phase,
      )?;
      let bucket = gradient_bucket(full_width.max(full_height));
      pixmap_cache
        .get_or_insert(key, || {
          rasterize_radial_gradient(
            width,
            height,
            center,
            radii,
            SpreadMode::Repeat,
            &resolved,
            cache,
            bucket,
            dither_phase,
          )
        })
        .ok()
        .flatten()
    }
    BackgroundImage::ConicGradient {
      from_angle,
      position,
      stops,
    } => {
      let resolved = normalize_color_stops_unclamped(
        stops,
        current_color,
        1.0,
        font_size,
        root_font_size,
        viewport,
        is_dark,
        forced_colors,
      );
      if resolved.is_empty() {
        return None;
      }
      let center = resolve_gradient_center(rect, position, font_size, root_font_size, viewport);
      let center = Point::new(center.x - crop_x, center.y - crop_y);
      rasterize_conic_gradient_cached(
        pixmap_cache,
        width,
        height,
        center,
        from_angle.to_radians(),
        SpreadMode::Pad,
        &resolved,
        cache,
        gradient_bucket(full_width.max(full_height).saturating_mul(2)),
      )
      .ok()
      .flatten()
    }
    BackgroundImage::RepeatingConicGradient {
      from_angle,
      position,
      stops,
    } => {
      let resolved = normalize_color_stops_unclamped(
        stops,
        current_color,
        1.0,
        font_size,
        root_font_size,
        viewport,
        is_dark,
        forced_colors,
      );
      if resolved.is_empty() {
        return None;
      }
      let center = resolve_gradient_center(rect, position, font_size, root_font_size, viewport);
      let center = Point::new(center.x - crop_x, center.y - crop_y);
      rasterize_conic_gradient_cached(
        pixmap_cache,
        width,
        height,
        center,
        from_angle.to_radians(),
        SpreadMode::Repeat,
        &resolved,
        cache,
        gradient_bucket(full_width.max(full_height).saturating_mul(2)),
      )
      .ok()
      .flatten()
    }
    BackgroundImage::None | BackgroundImage::Url(_) => None,
  }
}

fn render_generated_border_image(
  bg: &BackgroundImage,
  current_color: Rgba,
  is_dark: bool,
  forced_colors: bool,
  width: u32,
  height: u32,
  font_size: f32,
  root_font_size: f32,
  viewport: Option<(f32, f32)>,
  pixmap_cache: &GradientPixmapCache,
  cache: &GradientLutCache,
) -> Option<Arc<Pixmap>> {
  render_generated_border_image_subrect(
    bg,
    current_color,
    is_dark,
    forced_colors,
    width,
    height,
    0.0,
    0.0,
    width,
    height,
    font_size,
    root_font_size,
    viewport,
    pixmap_cache,
    cache,
  )
}

fn resolve_length_for_paint(
  len: &Length,
  font_size: f32,
  root_font_size: f32,
  percentage_base: f32,
  viewport: (f32, f32),
) -> f32 {
  crate::paint::paint_bounds::resolve_length_for_paint(
    len,
    font_size,
    root_font_size,
    percentage_base,
    Some(viewport),
  )
}

fn compute_background_size_from_value(
  size: &BackgroundSize,
  font_size: f32,
  root_font_size: f32,
  viewport: (f32, f32),
  area_w: f32,
  area_h: f32,
  img_w: f32,
  img_h: f32,
  intrinsic_ratio: Option<f32>,
) -> (f32, f32) {
  let natural_w = if img_w > 0.0 { Some(img_w) } else { None };
  let natural_h = if img_h > 0.0 { Some(img_h) } else { None };
  let ratio = intrinsic_ratio.filter(|r| r.is_finite() && *r > 0.0);

  match size {
    BackgroundSize::Keyword(BackgroundSizeKeyword::Cover) => {
      let area_w = area_w.max(0.0);
      let area_h = area_h.max(0.0);
      if let Some(ratio) = ratio {
        if area_w <= 0.0 || area_h <= 0.0 {
          return (area_w, area_h);
        }
        let area_ratio = if area_h != 0.0 {
          area_w / area_h
        } else {
          f32::INFINITY
        };
        if area_ratio > ratio {
          (area_w, area_w / ratio)
        } else {
          (area_h * ratio, area_h)
        }
      } else {
        (area_w, area_h)
      }
    }
    BackgroundSize::Keyword(BackgroundSizeKeyword::Contain) => {
      let area_w = area_w.max(0.0);
      let area_h = area_h.max(0.0);
      if let Some(ratio) = ratio {
        if area_w <= 0.0 || area_h <= 0.0 {
          return (area_w, area_h);
        }
        let area_ratio = if area_h != 0.0 {
          area_w / area_h
        } else {
          f32::INFINITY
        };
        if area_ratio > ratio {
          (area_h * ratio, area_h)
        } else {
          (area_w, area_w / ratio)
        }
      } else {
        (area_w, area_h)
      }
    }
    BackgroundSize::Explicit(x, y) => {
      let resolve = |component: BackgroundSizeComponent, area: f32| -> Option<f32> {
        match component {
          BackgroundSizeComponent::Auto => None,
          BackgroundSizeComponent::Length(len) => {
            Some(resolve_length_for_paint(&len, font_size, root_font_size, area, viewport).max(0.0))
          }
        }
      };

      let resolved_x = resolve(*x, area_w);
      let resolved_y = resolve(*y, area_h);

      match (resolved_x, resolved_y) {
        (Some(w), Some(h)) => (w, h),
        (Some(w), None) => {
          if let Some(r) = ratio {
            (w, (w / r).max(0.0))
          } else if let Some(h) = natural_h {
            (w, h)
          } else {
            (w, area_h.max(0.0))
          }
        }
        (None, Some(h)) => {
          if let Some(r) = ratio {
            ((h * r).max(0.0), h)
          } else if let Some(w) = natural_w {
            (w, h)
          } else {
            (area_w.max(0.0), h)
          }
        }
        (None, None) => {
          if let (Some(w), Some(h)) = (natural_w, natural_h) {
            (w, h)
          } else if let Some(ratio) = ratio {
            // CSS Backgrounds 3: if an image has an intrinsic ratio but no intrinsic dimensions,
            // `*-size: auto` behaves like `contain`.
            let area_w = area_w.max(0.0);
            let area_h = area_h.max(0.0);
            if area_w <= 0.0 || area_h <= 0.0 {
              (area_w, area_h)
            } else {
              let area_ratio = if area_h != 0.0 {
                area_w / area_h
              } else {
                f32::INFINITY
              };
              if area_ratio > ratio {
                (area_h * ratio, area_h)
              } else {
                (area_w, area_w / ratio)
              }
            }
          } else {
            (area_w.max(0.0), area_h.max(0.0))
          }
        }
      }
    }
  }
}

fn resolve_background_offset(
  pos: BackgroundPosition,
  area_w: f32,
  area_h: f32,
  tile_w: f32,
  tile_h: f32,
  font_size: f32,
  root_font_size: f32,
  viewport: (f32, f32),
) -> (f32, f32) {
  let resolve_axis =
    |comp: crate::style::types::BackgroundPositionComponent, area: f32, tile: f32| -> f32 {
      let available = area - tile;
      let offset =
        resolve_length_for_paint(&comp.offset, font_size, root_font_size, available, viewport);
      comp.alignment * available + offset
    };

  match pos {
    BackgroundPosition::Position { x, y } => {
      let x = resolve_axis(x, area_w, tile_w);
      let y = resolve_axis(y, area_h, tile_h);
      (x, y)
    }
  }
}

fn round_tile_length(area: f32, tile: f32) -> f32 {
  if tile <= 0.0 || area <= 0.0 {
    return tile;
  }
  let count = (area / tile).round().max(1.0);
  area / count
}

#[derive(Clone, Copy)]
struct TileAxisPlan {
  start: f32,
  step: f32,
  count: usize,
}

impl TileAxisPlan {
  fn empty() -> Self {
    Self {
      start: 0.0,
      step: 0.0,
      count: 0,
    }
  }

  fn iter(self) -> TileAxisIter {
    TileAxisIter {
      pos: self.start,
      step: self.step,
      remaining: self.count,
    }
  }
}

struct TileAxisIter {
  pos: f32,
  step: f32,
  remaining: usize,
}

impl Iterator for TileAxisIter {
  type Item = f32;

  fn next(&mut self) -> Option<Self::Item> {
    if self.remaining == 0 {
      return None;
    }
    let out = self.pos;
    self.pos += self.step;
    self.remaining -= 1;
    Some(out)
  }
}

fn tile_axis_plan(
  repeat: BackgroundRepeatKeyword,
  area_start: f32,
  area_len: f32,
  tile_len: f32,
  offset: f32,
  clip_start: f32,
  clip_end: f32,
) -> TileAxisPlan {
  if tile_len <= 0.0 || area_len <= 0.0 {
    return TileAxisPlan::empty();
  }
  match repeat {
    BackgroundRepeatKeyword::NoRepeat => {
      let start = area_start + offset;
      if start + tile_len < clip_start || start > clip_end {
        TileAxisPlan::empty()
      } else {
        TileAxisPlan {
          start,
          step: tile_len,
          count: 1,
        }
      }
    }
    BackgroundRepeatKeyword::Repeat => {
      let first = area_start + offset;
      let threshold = clip_start - 2.0 * tile_len;
      let mut start = first;
      if start < threshold {
        let delta = threshold - start;
        let steps = (delta / tile_len).ceil();
        if steps.is_finite() && steps > 0.0 {
          start += steps * tile_len;
        }
      }
      if start >= clip_end {
        return TileAxisPlan::empty();
      }
      let span = clip_end - start;
      let count = (span / tile_len).ceil();
      if !count.is_finite() || count <= 0.0 {
        return TileAxisPlan::empty();
      }
      TileAxisPlan {
        start,
        step: tile_len,
        count: count as usize,
      }
    }
    BackgroundRepeatKeyword::Space => {
      let count = (area_len / tile_len).floor();
      if count < 1.0 {
        TileAxisPlan {
          start: area_start + (area_len - tile_len) * 0.5,
          step: tile_len,
          count: 1,
        }
      } else if count < 2.0 {
        TileAxisPlan {
          start: area_start + (area_len - tile_len) * 0.5,
          step: tile_len,
          count: 1,
        }
      } else {
        let spacing = (area_len - tile_len * count) / (count - 1.0);
        TileAxisPlan {
          start: area_start,
          step: tile_len + spacing,
          count: count as usize,
        }
      }
    }
    BackgroundRepeatKeyword::Round => {
      if area_len <= 1e-3 {
        return TileAxisPlan::empty();
      }
      let count = (area_len / tile_len).round().max(1.0);
      let len = area_len / count;
      if !len.is_finite() || len <= 0.0 {
        return TileAxisPlan::empty();
      }
      TileAxisPlan {
        start: area_start,
        step: len,
        count: count as usize,
      }
    }
  }
}

fn mask_value_from_pixel(pixel: &[u8], mode: MaskMode) -> u8 {
  let a = pixel.get(3).copied().unwrap_or(0) as f32 / 255.0;
  let value = match mode {
    MaskMode::Alpha | MaskMode::MatchSource => a,
    MaskMode::Luminance => {
      if a <= 0.0 {
        0.0
      } else {
        let r = pixel.get(0).copied().unwrap_or(0) as f32 / 255.0 / a;
        let g = pixel.get(1).copied().unwrap_or(0) as f32 / 255.0 / a;
        let b = pixel.get(2).copied().unwrap_or(0) as f32 / 255.0 / a;
        (0.2126 * r + 0.7152 * g + 0.0722 * b) * a
      }
    }
  };
  (value * 255.0).round().clamp(0.0, 255.0) as u8
}

fn mask_tile_from_image(tile: &Pixmap, mode: MaskMode) -> RenderResult<Option<Pixmap>> {
  let Some(size) = IntSize::from_wh(tile.width(), tile.height()) else {
    return Ok(None);
  };

  let mut data = Vec::new();
  if data.try_reserve_exact(tile.data().len()).is_err() {
    return Ok(None);
  }
  let mut deadline_counter = 0usize;
  let chunk_bytes = CLIP_MASK_DEADLINE_STRIDE.saturating_mul(4);
  for pixel_chunk in tile.data().chunks(chunk_bytes) {
    check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
    for chunk in pixel_chunk.chunks_exact(4) {
      let v = mask_value_from_pixel(chunk, mode);
      data.extend_from_slice(&[v, v, v, v]);
    }
  }
  Ok(Pixmap::from_vec(data, size))
}

#[derive(Debug, Clone)]
struct OffsetMask {
  mask: Mask,
  origin: (i32, i32),
}

#[derive(Debug, Clone)]
enum CompositeMask {
  /// A fully transparent mask (alpha 0 everywhere).
  Transparent,
  /// A mask with explicit alpha values in the rectangle described by `origin` + `mask` size.
  Region(OffsetMask),
}

fn paint_mask_tile(
  dest: &mut Pixmap,
  tile: &Pixmap,
  tx: f32,
  ty: f32,
  tile_w: f32,
  tile_h: f32,
  clip_rect: Rect,
  scale: f32,
  dest_origin: (i32, i32),
) {
  if tile_w <= 0.0 || tile_h <= 0.0 {
    return;
  }
  let tile_rect = Rect::from_xywh(tx, ty, tile_w, tile_h);
  let Some(intersection) = tile_rect.intersection(clip_rect) else {
    return;
  };
  if intersection.width() <= 0.0 || intersection.height() <= 0.0 {
    return;
  }

  let device_clip = Rect::from_xywh(
    intersection.x() * scale - dest_origin.0 as f32,
    intersection.y() * scale - dest_origin.1 as f32,
    intersection.width() * scale,
    intersection.height() * scale,
  );
  if device_clip.width() <= 0.0 || device_clip.height() <= 0.0 {
    return;
  }
  let Some(src_rect) = tiny_skia::Rect::from_xywh(
    device_clip.x(),
    device_clip.y(),
    device_clip.width(),
    device_clip.height(),
  ) else {
    return;
  };

  let scale_x = tile_w / tile.width() as f32;
  let scale_y = tile_h / tile.height() as f32;

  let mut paint = tiny_skia::Paint::default();
  paint.shader = Pattern::new(
    tile.as_ref(),
    SpreadMode::Pad,
    tiny_skia::FilterQuality::Bilinear,
    1.0,
    Transform::from_row(
      scale_x * scale,
      0.0,
      0.0,
      scale_y * scale,
      tx * scale - dest_origin.0 as f32,
      ty * scale - dest_origin.1 as f32,
    ),
  );
  paint.anti_alias = false;
  dest.fill_rect(src_rect, &paint, Transform::identity(), None);
}

fn paint_mask_border_patch(
  dest: &mut Pixmap,
  source: &Pixmap,
  src_rect: Rect,
  dest_rect: Rect,
  repeat_x: BorderImageRepeat,
  repeat_y: BorderImageRepeat,
  clip_rect: Rect,
) {
  if src_rect.width() <= 0.0
    || src_rect.height() <= 0.0
    || dest_rect.width() <= 0.0
    || dest_rect.height() <= 0.0
  {
    return;
  }

  let Some(clip_rect) = dest_rect.intersection(clip_rect) else {
    return;
  };
  if clip_rect.width() <= 0.0 || clip_rect.height() <= 0.0 {
    return;
  }

  let sx0 = src_rect.x().max(0.0).floor() as u32;
  let sy0 = src_rect.y().max(0.0).floor() as u32;
  let sx1 = (src_rect.x() + src_rect.width())
    .ceil()
    .min(source.width() as f32)
    .max(0.0) as u32;
  let sy1 = (src_rect.y() + src_rect.height())
    .ceil()
    .min(source.height() as f32)
    .max(0.0) as u32;
  if sx1 <= sx0 || sy1 <= sy0 {
    return;
  }
  let width = sx1 - sx0;
  let height = sy1 - sy0;

  let Some(size) = IntSize::from_wh(width, height) else {
    return;
  };
  let Some(bytes) = rgba_bytes(width, height) else {
    return;
  };
  let mut patch = match reserve_buffer(bytes, "mask-border patch") {
    Ok(buf) => buf,
    Err(_) => return,
  };

  let data = source.data();
  let source_width = source.width();
  let Some(row_bytes) = u64::from(width).checked_mul(4) else {
    return;
  };
  for row in sy0..sy1 {
    let Some(start) = u64::from(row)
      .checked_mul(u64::from(source_width))
      .and_then(|v| v.checked_add(u64::from(sx0)))
      .and_then(|v| v.checked_mul(4))
    else {
      return;
    };
    let Some(end) = start.checked_add(row_bytes) else {
      return;
    };
    let Ok(start) = usize::try_from(start) else {
      return;
    };
    let Ok(end) = usize::try_from(end) else {
      return;
    };
    if end > data.len() || start > end {
      return;
    }
    patch.extend_from_slice(&data[start..end]);
  }
  let Some(patch_pixmap) = Pixmap::from_vec(patch, size) else {
    return;
  };

  let mut tile_w = dest_rect.width();
  let mut tile_h = dest_rect.height();

  let mut scale_x = tile_w / width as f32;
  let mut scale_y = tile_h / height as f32;

  if repeat_x != BorderImageRepeat::Stretch {
    scale_x = scale_y;
    tile_w = width as f32 * scale_x;
  }
  if repeat_y != BorderImageRepeat::Stretch {
    scale_y = scale_x;
    tile_h = height as f32 * scale_y;
  }

  if repeat_x == BorderImageRepeat::Round && tile_w > 0.0 {
    let count = (dest_rect.width() / tile_w).round().max(1.0);
    tile_w = dest_rect.width() / count;
    scale_x = tile_w / width as f32;
  }
  if repeat_y == BorderImageRepeat::Round && tile_h > 0.0 {
    let count = (dest_rect.height() / tile_h).round().max(1.0);
    tile_h = dest_rect.height() / count;
    scale_y = tile_h / height as f32;
  }

  // Avoid panics/aborts when the destination is extremely thin and would require an unbounded
  // number of tiles (e.g. a huge width with a near-zero height and repeat-x=space).
  const MAX_BORDER_IMAGE_TILES_PER_AXIS: f32 = 4096.0;
  let paint_repeated_patch = |dest: &mut Pixmap| {
    let Some(dest_sk_rect) = tiny_skia::Rect::from_xywh(
      clip_rect.x(),
      clip_rect.y(),
      clip_rect.width(),
      clip_rect.height(),
    ) else {
      return;
    };
    let mut paint = tiny_skia::Paint::default();
    paint.shader = Pattern::new(
      patch_pixmap.as_ref(),
      SpreadMode::Repeat,
      FilterQuality::Bilinear,
      1.0,
      Transform::from_row(scale_x, 0.0, 0.0, scale_y, dest_rect.x(), dest_rect.y()),
    );
    paint.anti_alias = false;
    paint.blend_mode = tiny_skia::BlendMode::SourceOver;
    dest.fill_rect(dest_sk_rect, &paint, Transform::identity(), None);
  };

  let tiles_x = dest_rect.width() / tile_w;
  let tiles_y = dest_rect.height() / tile_h;
  let too_many_x = repeat_x != BorderImageRepeat::Stretch
    && (!tiles_x.is_finite() || tiles_x > MAX_BORDER_IMAGE_TILES_PER_AXIS);
  let too_many_y = repeat_y != BorderImageRepeat::Stretch
    && (!tiles_y.is_finite() || tiles_y > MAX_BORDER_IMAGE_TILES_PER_AXIS);
  if too_many_x || too_many_y {
    paint_repeated_patch(dest);
    return;
  }

  let positions_x = match repeat_x {
    BorderImageRepeat::Stretch => vec![dest_rect.x()],
    BorderImageRepeat::Round => {
      let end = dest_rect.x() + dest_rect.width();
      if tile_w <= 0.0 {
        return;
      }
      let count = (tiles_x.ceil().max(1.0) as usize).min(MAX_BORDER_IMAGE_TILES_PER_AXIS as usize);
      let mut pos = Vec::new();
      if pos.try_reserve_exact(count).is_err() {
        paint_repeated_patch(dest);
        return;
      }
      let mut cursor = dest_rect.x();
      for _ in 0..count {
        if cursor >= end - 1e-3 {
          break;
        }
        pos.push(cursor);
        cursor += tile_w;
      }
      pos
    }
    BorderImageRepeat::Space => {
      if tile_w <= 0.0 {
        return;
      }
      let count = tiles_x.floor();
      if count < 1.0 {
        vec![dest_rect.x() + (dest_rect.width() - tile_w) * 0.5]
      } else if count < 2.0 {
        vec![dest_rect.x() + (dest_rect.width() - tile_w) * 0.5]
      } else {
        let spacing = (dest_rect.width() - tile_w * count) / (count - 1.0);
        let count = count as usize;
        let mut pos = Vec::new();
        if pos.try_reserve_exact(count).is_err() {
          paint_repeated_patch(dest);
          return;
        }
        let mut cursor = dest_rect.x();
        for _ in 0..count {
          pos.push(cursor);
          cursor += tile_w + spacing;
        }
        pos
      }
    }
    BorderImageRepeat::Repeat => {
      let end = dest_rect.x() + dest_rect.width();
      if tile_w <= 0.0 {
        return;
      }
      let count = (tiles_x.ceil().max(1.0) as usize).min(MAX_BORDER_IMAGE_TILES_PER_AXIS as usize);
      let mut pos = Vec::new();
      if pos.try_reserve_exact(count).is_err() {
        paint_repeated_patch(dest);
        return;
      }
      let mut cursor = dest_rect.x();
      for _ in 0..count {
        if cursor >= end - 1e-3 {
          break;
        }
        pos.push(cursor);
        cursor += tile_w;
      }
      pos
    }
  };

  let positions_y = match repeat_y {
    BorderImageRepeat::Stretch => vec![dest_rect.y()],
    BorderImageRepeat::Round => {
      let end = dest_rect.y() + dest_rect.height();
      if tile_h <= 0.0 {
        return;
      }
      let count = (tiles_y.ceil().max(1.0) as usize).min(MAX_BORDER_IMAGE_TILES_PER_AXIS as usize);
      let mut pos = Vec::new();
      if pos.try_reserve_exact(count).is_err() {
        paint_repeated_patch(dest);
        return;
      }
      let mut cursor = dest_rect.y();
      for _ in 0..count {
        if cursor >= end - 1e-3 {
          break;
        }
        pos.push(cursor);
        cursor += tile_h;
      }
      pos
    }
    BorderImageRepeat::Space => {
      if tile_h <= 0.0 {
        return;
      }
      let count = tiles_y.floor();
      if count < 1.0 {
        vec![dest_rect.y() + (dest_rect.height() - tile_h) * 0.5]
      } else if count < 2.0 {
        vec![dest_rect.y() + (dest_rect.height() - tile_h) * 0.5]
      } else {
        let spacing = (dest_rect.height() - tile_h * count) / (count - 1.0);
        let count = count as usize;
        let mut pos = Vec::new();
        if pos.try_reserve_exact(count).is_err() {
          paint_repeated_patch(dest);
          return;
        }
        let mut cursor = dest_rect.y();
        for _ in 0..count {
          pos.push(cursor);
          cursor += tile_h + spacing;
        }
        pos
      }
    }
    BorderImageRepeat::Repeat => {
      let end = dest_rect.y() + dest_rect.height();
      if tile_h <= 0.0 {
        return;
      }
      let count = (tiles_y.ceil().max(1.0) as usize).min(MAX_BORDER_IMAGE_TILES_PER_AXIS as usize);
      let mut pos = Vec::new();
      if pos.try_reserve_exact(count).is_err() {
        paint_repeated_patch(dest);
        return;
      }
      let mut cursor = dest_rect.y();
      for _ in 0..count {
        if cursor >= end - 1e-3 {
          break;
        }
        pos.push(cursor);
        cursor += tile_h;
      }
      pos
    }
  };

  for ty in positions_y.iter().copied() {
    for tx in positions_x.iter().copied() {
      let tile_rect = Rect::from_xywh(tx, ty, tile_w, tile_h);
      let Some(intersection) = tile_rect.intersection(clip_rect) else {
        continue;
      };
      if intersection.width() <= 0.0 || intersection.height() <= 0.0 {
        continue;
      }
      let Some(dst_rect) = tiny_skia::Rect::from_xywh(
        intersection.x(),
        intersection.y(),
        intersection.width(),
        intersection.height(),
      ) else {
        continue;
      };
      let mut paint = tiny_skia::Paint::default();
      paint.shader = Pattern::new(
        patch_pixmap.as_ref(),
        SpreadMode::Pad,
        FilterQuality::Bilinear,
        1.0,
        Transform::from_row(scale_x, 0.0, 0.0, scale_y, tx, ty),
      );
      paint.anti_alias = false;
      paint.blend_mode = tiny_skia::BlendMode::SourceOver;
      dest.fill_rect(dst_rect, &paint, Transform::identity(), None);
    }
  }
}

fn apply_mask_composite(
  dest: CompositeMask,
  src: CompositeMask,
  op: MaskComposite,
) -> RenderResult<Option<CompositeMask>> {
  use CompositeMask::*;

  match (dest, src) {
    (Transparent, Transparent) => Ok(Some(Transparent)),
    (Transparent, Region(mask)) => match op {
      MaskComposite::Intersect => Ok(Some(Transparent)),
      MaskComposite::Add | MaskComposite::Subtract | MaskComposite::Exclude => {
        Ok(Some(Region(mask)))
      }
    },
    (Region(mask), Transparent) => match op {
      MaskComposite::Add | MaskComposite::Exclude => Ok(Some(Region(mask))),
      MaskComposite::Subtract | MaskComposite::Intersect => Ok(Some(Transparent)),
    },
    (Region(dest), Region(src)) => composite_offset_masks(dest, src, op),
  }
}

fn composite_offset_masks(
  mut dest: OffsetMask,
  mut src: OffsetMask,
  op: MaskComposite,
) -> RenderResult<Option<CompositeMask>> {
  let dx0 = dest.origin.0;
  let dy0 = dest.origin.1;
  let dx1 = dx0 + dest.mask.width() as i32;
  let dy1 = dy0 + dest.mask.height() as i32;

  let sx0 = src.origin.0;
  let sy0 = src.origin.1;
  let sx1 = sx0 + src.mask.width() as i32;
  let sy1 = sy0 + src.mask.height() as i32;

  if dest.origin == src.origin
    && dest.mask.width() == src.mask.width()
    && dest.mask.height() == src.mask.height()
  {
    apply_mask_composite_same_bounds(dest.mask.data_mut(), src.mask.data(), op)?;
    return Ok(Some(CompositeMask::Region(dest)));
  }

  let (ox0, oy0, ox1, oy1) = match op {
    MaskComposite::Subtract => {
      let inter_x0 = dx0.max(sx0);
      let inter_y0 = dy0.max(sy0);
      let inter_x1 = dx1.min(sx1);
      let inter_y1 = dy1.min(sy1);
      if inter_x1 > inter_x0 && inter_y1 > inter_y0 {
        apply_mask_composite_into_src(
          &mut src,
          &dest,
          op,
          (inter_x0, inter_y0, inter_x1, inter_y1),
        )?;
      }
      return Ok(Some(CompositeMask::Region(src)));
    }
    MaskComposite::Intersect => {
      let contains =
        |ax0: i32, ay0: i32, ax1: i32, ay1: i32, bx0: i32, by0: i32, bx1: i32, by1: i32| {
          ax0 <= bx0 && ay0 <= by0 && ax1 >= bx1 && ay1 >= by1
        };
      if contains(dx0, dy0, dx1, dy1, sx0, sy0, sx1, sy1) {
        apply_mask_composite_into_src(&mut src, &dest, op, (sx0, sy0, sx1, sy1))?;
        return Ok(Some(CompositeMask::Region(src)));
      }
      if contains(sx0, sy0, sx1, sy1, dx0, dy0, dx1, dy1) {
        apply_mask_composite_into_dest(&mut dest, &src, op, (dx0, dy0, dx1, dy1))?;
        return Ok(Some(CompositeMask::Region(dest)));
      }

      (dx0.max(sx0), dy0.max(sy0), dx1.min(sx1), dy1.min(sy1))
    }
    MaskComposite::Add | MaskComposite::Exclude => {
      let contains =
        |ax0: i32, ay0: i32, ax1: i32, ay1: i32, bx0: i32, by0: i32, bx1: i32, by1: i32| {
          ax0 <= bx0 && ay0 <= by0 && ax1 >= bx1 && ay1 >= by1
        };
      if contains(dx0, dy0, dx1, dy1, sx0, sy0, sx1, sy1) {
        apply_mask_composite_into_dest(&mut dest, &src, op, (sx0, sy0, sx1, sy1))?;
        return Ok(Some(CompositeMask::Region(dest)));
      }
      if contains(sx0, sy0, sx1, sy1, dx0, dy0, dx1, dy1) {
        apply_mask_composite_into_src(&mut src, &dest, op, (dx0, dy0, dx1, dy1))?;
        return Ok(Some(CompositeMask::Region(src)));
      }

      (dx0.min(sx0), dy0.min(sy0), dx1.max(sx1), dy1.max(sy1))
    }
  };

  let out_w_i32 = ox1.saturating_sub(ox0);
  let out_h_i32 = oy1.saturating_sub(oy0);
  if out_w_i32 <= 0 || out_h_i32 <= 0 {
    return Ok(Some(CompositeMask::Transparent));
  }
  let out_w = out_w_i32 as u32;
  let out_h = out_h_i32 as u32;

  let Some(mut out) = Mask::new(out_w, out_h) else {
    return Ok(None);
  };
  let out_data = out.data_mut();

  let dst_w = dest.mask.width() as usize;
  let dst_data = dest.mask.data();
  let src_w = src.mask.width() as usize;
  let src_data = src.mask.data();

  match op {
    MaskComposite::Intersect => {
      let dst_x_offset = ox0.saturating_sub(dx0) as usize;
      let src_x_offset = ox0.saturating_sub(sx0) as usize;
      let mut deadline_counter = 0usize;
      for y in 0..out_h as usize {
        let global_y = oy0 + y as i32;
        let dst_row_idx = global_y.saturating_sub(dy0) as usize * dst_w;
        let src_row_idx = global_y.saturating_sub(sy0) as usize * src_w;
        let out_row_idx = y * out_w as usize;
        let row_len = out_w as usize;
        for x0 in (0..row_len).step_by(CLIP_MASK_DEADLINE_STRIDE) {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x1 = (x0 + CLIP_MASK_DEADLINE_STRIDE).min(row_len);
          for x in x0..x1 {
            let dst = dst_data[dst_row_idx + dst_x_offset + x] as u16;
            let src = src_data[src_row_idx + src_x_offset + x] as u16;
            out_data[out_row_idx + x] = div_255(src * dst) as u8;
          }
        }
      }
    }
    MaskComposite::Subtract => {
      let dst_y0 = dy0;
      let dst_y1 = dy1;
      let dst_x0 = dx0;
      let dst_x1 = dx1;
      let mut deadline_counter = 0usize;
      for y in 0..out_h as usize {
        let global_y = oy0 + y as i32;
        let src_row_idx = y * src_w;
        let out_row_idx = y * out_w as usize;
        let dst_row = if global_y >= dst_y0 && global_y < dst_y1 {
          let row_idx = (global_y - dst_y0) as usize * dst_w;
          Some(&dst_data[row_idx..row_idx + dst_w])
        } else {
          None
        };
        let row_len = out_w as usize;
        for x0 in (0..row_len).step_by(CLIP_MASK_DEADLINE_STRIDE) {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x1 = (x0 + CLIP_MASK_DEADLINE_STRIDE).min(row_len);
          for x in x0..x1 {
            let global_x = ox0 + x as i32;
            let src = src_data[src_row_idx + x] as u16;
            let dst = if let Some(row) = dst_row {
              if global_x >= dst_x0 && global_x < dst_x1 {
                row[(global_x - dst_x0) as usize] as u16
              } else {
                0
              }
            } else {
              0
            };
            out_data[out_row_idx + x] = div_255(src * (255 - dst)) as u8;
          }
        }
      }
    }
    MaskComposite::Add | MaskComposite::Exclude => {
      let mut deadline_counter = 0usize;
      for y in 0..out_h as usize {
        let global_y = oy0 + y as i32;
        let out_row_idx = y * out_w as usize;

        let dst_row = if global_y >= dy0 && global_y < dy1 {
          let row_idx = (global_y - dy0) as usize * dst_w;
          Some(&dst_data[row_idx..row_idx + dst_w])
        } else {
          None
        };
        let src_row = if global_y >= sy0 && global_y < sy1 {
          let row_idx = (global_y - sy0) as usize * src_w;
          Some(&src_data[row_idx..row_idx + src_w])
        } else {
          None
        };

        let row_len = out_w as usize;
        for x0 in (0..row_len).step_by(CLIP_MASK_DEADLINE_STRIDE) {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x1 = (x0 + CLIP_MASK_DEADLINE_STRIDE).min(row_len);
          for x in x0..x1 {
            let global_x = ox0 + x as i32;
            let dst = if let Some(row) = dst_row {
              if global_x >= dx0 && global_x < dx1 {
                row[(global_x - dx0) as usize] as u16
              } else {
                0
              }
            } else {
              0
            };
            let src = if let Some(row) = src_row {
              if global_x >= sx0 && global_x < sx1 {
                row[(global_x - sx0) as usize] as u16
              } else {
                0
              }
            } else {
              0
            };

            let out = match op {
              MaskComposite::Add => src + div_255(dst * (255 - src)),
              MaskComposite::Exclude => {
                let src_out = div_255(src * (255 - dst));
                let dst_out = div_255(dst * (255 - src));
                src_out + dst_out
              }
              _ => 0,
            };
            out_data[out_row_idx + x] = out.min(255) as u8;
          }
        }
      }
    }
  }

  Ok(Some(CompositeMask::Region(OffsetMask {
    mask: out,
    origin: (ox0, oy0),
  })))
}

fn apply_mask_composite_same_bounds(
  dest: &mut [u8],
  src: &[u8],
  op: MaskComposite,
) -> RenderResult<()> {
  debug_assert_eq!(dest.len(), src.len());
  let mut deadline_counter = 0usize;
  match op {
    MaskComposite::Add => {
      for (dest_chunk, src_chunk) in dest
        .chunks_mut(CLIP_MASK_DEADLINE_STRIDE)
        .zip(src.chunks(CLIP_MASK_DEADLINE_STRIDE))
      {
        check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
        for (d, s) in dest_chunk.iter_mut().zip(src_chunk.iter()) {
          let src = *s as u16;
          let dst = *d as u16;
          let out = src + div_255(dst * (255 - src));
          *d = out.min(255) as u8;
        }
      }
    }
    MaskComposite::Subtract => {
      for (dest_chunk, src_chunk) in dest
        .chunks_mut(CLIP_MASK_DEADLINE_STRIDE)
        .zip(src.chunks(CLIP_MASK_DEADLINE_STRIDE))
      {
        check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
        for (d, s) in dest_chunk.iter_mut().zip(src_chunk.iter()) {
          let src = *s as u16;
          let dst = *d as u16;
          *d = div_255(src * (255 - dst)) as u8;
        }
      }
    }
    MaskComposite::Intersect => {
      for (dest_chunk, src_chunk) in dest
        .chunks_mut(CLIP_MASK_DEADLINE_STRIDE)
        .zip(src.chunks(CLIP_MASK_DEADLINE_STRIDE))
      {
        check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
        for (d, s) in dest_chunk.iter_mut().zip(src_chunk.iter()) {
          let src = *s as u16;
          let dst = *d as u16;
          *d = div_255(src * dst) as u8;
        }
      }
    }
    MaskComposite::Exclude => {
      for (dest_chunk, src_chunk) in dest
        .chunks_mut(CLIP_MASK_DEADLINE_STRIDE)
        .zip(src.chunks(CLIP_MASK_DEADLINE_STRIDE))
      {
        check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
        for (d, s) in dest_chunk.iter_mut().zip(src_chunk.iter()) {
          let src = *s as u16;
          let dst = *d as u16;
          let src_out = div_255(src * (255 - dst));
          let dst_out = div_255(dst * (255 - src));
          *d = (src_out + dst_out).min(255) as u8;
        }
      }
    }
  }
  Ok(())
}

fn apply_mask_composite_into_src(
  src: &mut OffsetMask,
  dest: &OffsetMask,
  op: MaskComposite,
  (ox0, oy0, ox1, oy1): (i32, i32, i32, i32),
) -> RenderResult<()> {
  let out_w = src.mask.width() as usize;
  let dst_w = dest.mask.width() as usize;
  let out_data = src.mask.data_mut();
  let dst_data = dest.mask.data();
  let x_span = ox1.saturating_sub(ox0).max(0) as usize;
  let src_x0 = (ox0 - src.origin.0).max(0) as usize;
  let dst_x0 = (ox0 - dest.origin.0).max(0) as usize;
  let mut deadline_counter = 0usize;

  match op {
    MaskComposite::Add => {
      for y in oy0..oy1 {
        let out_y = (y - src.origin.1) as usize;
        let dst_y = (y - dest.origin.1) as usize;
        let out_row = out_y * out_w + src_x0;
        let dst_row = dst_y * dst_w + dst_x0;
        let mut x = 0usize;
        while x < x_span {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x_end = (x + CLIP_MASK_DEADLINE_STRIDE).min(x_span);
          for i in x..x_end {
            let idx_out = out_row + i;
            let dst = dst_data[dst_row + i] as u16;
            let src_v = out_data[idx_out] as u16;
            let out = src_v + div_255(dst * (255 - src_v));
            out_data[idx_out] = out.min(255) as u8;
          }
          x = x_end;
        }
      }
    }
    MaskComposite::Subtract => {
      for y in oy0..oy1 {
        let out_y = (y - src.origin.1) as usize;
        let dst_y = (y - dest.origin.1) as usize;
        let out_row = out_y * out_w + src_x0;
        let dst_row = dst_y * dst_w + dst_x0;
        let mut x = 0usize;
        while x < x_span {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x_end = (x + CLIP_MASK_DEADLINE_STRIDE).min(x_span);
          for i in x..x_end {
            let idx_out = out_row + i;
            let dst = dst_data[dst_row + i] as u16;
            let src_v = out_data[idx_out] as u16;
            out_data[idx_out] = div_255(src_v * (255 - dst)) as u8;
          }
          x = x_end;
        }
      }
    }
    MaskComposite::Intersect => {
      for y in oy0..oy1 {
        let out_y = (y - src.origin.1) as usize;
        let dst_y = (y - dest.origin.1) as usize;
        let out_row = out_y * out_w + src_x0;
        let dst_row = dst_y * dst_w + dst_x0;
        let mut x = 0usize;
        while x < x_span {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x_end = (x + CLIP_MASK_DEADLINE_STRIDE).min(x_span);
          for i in x..x_end {
            let idx_out = out_row + i;
            let dst = dst_data[dst_row + i] as u16;
            let src_v = out_data[idx_out] as u16;
            out_data[idx_out] = div_255(src_v * dst) as u8;
          }
          x = x_end;
        }
      }
    }
    MaskComposite::Exclude => {
      for y in oy0..oy1 {
        let out_y = (y - src.origin.1) as usize;
        let dst_y = (y - dest.origin.1) as usize;
        let out_row = out_y * out_w + src_x0;
        let dst_row = dst_y * dst_w + dst_x0;
        let mut x = 0usize;
        while x < x_span {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x_end = (x + CLIP_MASK_DEADLINE_STRIDE).min(x_span);
          for i in x..x_end {
            let idx_out = out_row + i;
            let dst = dst_data[dst_row + i] as u16;
            let src_v = out_data[idx_out] as u16;
            let src_out = div_255(src_v * (255 - dst));
            let dst_out = div_255(dst * (255 - src_v));
            out_data[idx_out] = (src_out + dst_out).min(255) as u8;
          }
          x = x_end;
        }
      }
    }
  }
  Ok(())
}

fn apply_mask_composite_into_dest(
  dest: &mut OffsetMask,
  src: &OffsetMask,
  op: MaskComposite,
  (ox0, oy0, ox1, oy1): (i32, i32, i32, i32),
) -> RenderResult<()> {
  let dst_w = dest.mask.width() as usize;
  let src_w = src.mask.width() as usize;
  let dst_data = dest.mask.data_mut();
  let src_data = src.mask.data();
  let x_span = ox1.saturating_sub(ox0).max(0) as usize;
  let dst_x0 = (ox0 - dest.origin.0).max(0) as usize;
  let src_x0 = (ox0 - src.origin.0).max(0) as usize;
  let mut deadline_counter = 0usize;

  match op {
    MaskComposite::Add => {
      for y in oy0..oy1 {
        let dst_y = (y - dest.origin.1) as usize;
        let src_y = (y - src.origin.1) as usize;
        let dst_row = dst_y * dst_w + dst_x0;
        let src_row = src_y * src_w + src_x0;
        let mut x = 0usize;
        while x < x_span {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x_end = (x + CLIP_MASK_DEADLINE_STRIDE).min(x_span);
          for i in x..x_end {
            let idx_dst = dst_row + i;
            let dst = dst_data[idx_dst] as u16;
            let src_v = src_data[src_row + i] as u16;
            let out = src_v + div_255(dst * (255 - src_v));
            dst_data[idx_dst] = out.min(255) as u8;
          }
          x = x_end;
        }
      }
    }
    MaskComposite::Subtract => {
      for y in oy0..oy1 {
        let dst_y = (y - dest.origin.1) as usize;
        let src_y = (y - src.origin.1) as usize;
        let dst_row = dst_y * dst_w + dst_x0;
        let src_row = src_y * src_w + src_x0;
        let mut x = 0usize;
        while x < x_span {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x_end = (x + CLIP_MASK_DEADLINE_STRIDE).min(x_span);
          for i in x..x_end {
            let idx_dst = dst_row + i;
            let dst = dst_data[idx_dst] as u16;
            let src_v = src_data[src_row + i] as u16;
            dst_data[idx_dst] = div_255(src_v * (255 - dst)) as u8;
          }
          x = x_end;
        }
      }
    }
    MaskComposite::Intersect => {
      for y in oy0..oy1 {
        let dst_y = (y - dest.origin.1) as usize;
        let src_y = (y - src.origin.1) as usize;
        let dst_row = dst_y * dst_w + dst_x0;
        let src_row = src_y * src_w + src_x0;
        let mut x = 0usize;
        while x < x_span {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x_end = (x + CLIP_MASK_DEADLINE_STRIDE).min(x_span);
          for i in x..x_end {
            let idx_dst = dst_row + i;
            let dst = dst_data[idx_dst] as u16;
            let src_v = src_data[src_row + i] as u16;
            dst_data[idx_dst] = div_255(src_v * dst) as u8;
          }
          x = x_end;
        }
      }
    }
    MaskComposite::Exclude => {
      for y in oy0..oy1 {
        let dst_y = (y - dest.origin.1) as usize;
        let src_y = (y - src.origin.1) as usize;
        let dst_row = dst_y * dst_w + dst_x0;
        let src_row = src_y * src_w + src_x0;
        let mut x = 0usize;
        while x < x_span {
          check_active_periodic(&mut deadline_counter, 1, RenderStage::Paint)?;
          let x_end = (x + CLIP_MASK_DEADLINE_STRIDE).min(x_span);
          for i in x..x_end {
            let idx_dst = dst_row + i;
            let dst = dst_data[idx_dst] as u16;
            let src_v = src_data[src_row + i] as u16;
            let src_out = div_255(src_v * (255 - dst));
            let dst_out = div_255(dst * (255 - src_v));
            dst_data[idx_dst] = (src_out + dst_out).min(255) as u8;
          }
          x = x_end;
        }
      }
    }
  }
  Ok(())
}

#[inline]
fn div_255(value: u16) -> u16 {
  // Exact floor division by 255 for values in the 0..=65025 range (the max product of two u8s).
  // This is faster than a general integer division and keeps mask composites deterministic.
  (value + 1 + (value >> 8)) >> 8
}

/// Render a device-pixel tile of a display list.
///
/// This is used by incremental repaint paths that want to re-rasterize a sub-rectangle without
/// rebuilding the full `DisplayListRenderer` pipeline.
///
/// `render_x/render_y/render_w/render_h` are in *device pixels* (after scaling).
pub(crate) fn render_display_list_tile(
  list: &DisplayList,
  render_x: u32,
  render_y: u32,
  render_w: u32,
  render_h: u32,
  background: Rgba,
  font_ctx: FontContext,
  scale: f32,
) -> Result<Pixmap> {
  // Match `DisplayListRenderer::render_with_report` preserve-3d fallback handling so partial repaints
  // remain byte-identical to full paints when the scene renderer is disabled.
  let composed = runtime_flag("FASTR_PRESERVE3D_DISABLE_SCENE")
    .then(|| crate::paint::preserve_3d::composite_preserve_3d(list));
  let list = composed.as_ref().unwrap_or(list);

  let scale = if scale.is_finite() && scale > 0.0 { scale } else { 1.0 };
  let render_css_rect = Rect::from_xywh(
    render_x as f32 / scale,
    render_y as f32 / scale,
    render_w as f32 / scale,
    render_h as f32 / scale,
  );
  let optimizer = DisplayListOptimizer::new();
  let slice = optimizer
    .intersect_view(list.items(), render_css_rect)
    .map_err(Error::Render)?;

  let mut renderer = DisplayListRenderer::new_with_text_state(
    render_w,
    render_h,
    background,
    font_ctx,
    scale,
    shared_color_renderer(),
    shared_color_cache(),
    shared_glyph_cache(),
  )?;
  renderer.paint_parallelism = PaintParallelism::disabled();
  if render_x > 0 || render_y > 0 {
    renderer
      .canvas
      .translate(-(render_x as f32), -(render_y as f32));
  }
  renderer.render_slice(&slice)?;
  // Ensure we catch deadlines that expire during the final item.
  check_active(RenderStage::Paint).map_err(Error::Render)?;
  Ok(renderer.canvas.into_pixmap())
}

#[cfg(test)]
