  #[test]
  fn rgba_bytes_rejects_overflow() {
    assert_eq!(rgba_bytes(2, 3), Some(24));
    assert!(rgba_bytes(u32::MAX, u32::MAX).is_none());
  }

  #[test]
  fn maybe_snap_unscaled_image_dest_rect_snaps_near_integer_size() {
    let renderer = DisplayListRenderer::new(10, 10, Rgba::TRANSPARENT, FontContext::new()).unwrap();
    let pixmap = Pixmap::new(115, 115).unwrap();
    let dest_rect = Rect::from_xywh(10.9, 20.4, 115.0001, 114.99999);
    let snapped = renderer.maybe_snap_unscaled_image_dest_rect(dest_rect, &pixmap);
    assert_eq!(snapped.x(), 11.0);
    assert_eq!(snapped.y(), 20.0);
    assert_eq!(snapped.width(), 115.0);
    assert_eq!(snapped.height(), 115.0);
  }

  #[test]
  fn snap_rect_to_near_integer_edges_or_size_snaps_one_axis() {
    // Regression test: even if a scaled image's rect is only "nearly" integer-aligned on one axis,
    // snapping that axis can materially reduce bilinear phase drift vs Chrome while leaving the
    // other axis untouched.
    let rect = Rect::from_xywh(34.944427, 345.91968, 529.88794, 309.4463);
    let snapped =
      DisplayListRenderer::snap_rect_to_near_integer_edges_or_size(rect, 0.125).expect("snapped");
    assert_eq!(snapped.x(), 35.0);
    assert_eq!(snapped.width(), 530.0);
    assert!((snapped.y() - rect.y()).abs() < 1e-6);
    assert!((snapped.height() - rect.height()).abs() < 1e-6);

    // If only the origin is near-integer but the size isn't, do not snap.
    let rect2 = Rect::from_xywh(34.944427, 0.0, 529.6, 10.0);
    assert!(
      DisplayListRenderer::snap_rect_to_near_integer_edges_or_size(rect2, 0.125).is_none(),
      "rect2 should not snap"
    );
  }

  #[test]
  fn text_shadow_allocation_budget_exceeded_propagates() {
    let mut renderer =
      DisplayListRenderer::new(64, 64, Rgba::TRANSPARENT, FontContext::new()).expect("renderer");

    let budget = Arc::new(StageAllocationBudget::new(1));
    let _budget_guard = StageAllocationBudgetGuard::install(Some(&budget));
    let _stage_guard = StageGuard::install(Some(RenderStage::Paint));

    let font = LoadedFont {
      id: None,
      data: Arc::new(Vec::new()),
      index: 0,
      face_metrics_overrides: crate::text::font_db::FontFaceMetricsOverrides::default(),
      face_settings: crate::text::font_db::FontFaceShapingDescriptors::default(),
      family: "Dummy".to_string(),
      weight: crate::text::font_db::FontWeight::NORMAL,
      style: crate::text::font_db::FontStyle::Normal,
      stretch: crate::text::font_db::FontStretch::Normal,
    };

    let mut item = TextItem::default();
    item.origin = Point::new(0.0, 20.0);
    item.font_size = 10.0;
    item.scale = 1.0;
    item.glyphs = vec![GlyphInstance {
      glyph_id: 1,
      cluster: 0,
      x_offset: 0.0,
      y_offset: 0.0,
      x_advance: 10.0,
      y_advance: 0.0,
    }];
    item.shadows = vec![TextShadowItem {
      offset: Point::ZERO,
      blur_radius: 0.0,
      color: Rgba::BLACK,
    }];

    let err = renderer
      .render_text_shadows(&font, &item)
      .expect_err("expected allocation budget error");
    match err {
      Error::Render(RenderError::StageAllocationBudgetExceeded { stage, .. }) => {
        assert_eq!(stage, RenderStage::Paint);
      }
      other => panic!("expected StageAllocationBudgetExceeded, got {other:?}"),
    }
  }

  fn pixel(pixmap: &Pixmap, x: u32, y: u32) -> (u8, u8, u8, u8) {
    let idx = ((y * pixmap.width() + x) * 4) as usize;
    let data = pixmap.data();
    (data[idx], data[idx + 1], data[idx + 2], data[idx + 3])
  }

  #[test]
  fn backdrop_filter_clamps_write_region_to_filtered_bounds() {
    // Regression test for an out-of-bounds panic in `apply_backdrop_filters_with_region_filler`.
    //
    // `write_rect` is computed using float intersections and then rounded with floor/ceil. When a
    // clip starts partway through the filtered region (so `src_start_y > 0`), rounding could produce
    // `write_h` that extends 1px past the filtered region's height, causing mask indexing to panic.
    //
    // Repro: region_h=35, src_start_y=1, write_h=35 => mask_idx == len.
    let mut dest = Pixmap::new(40, 40).expect("dest pixmap");
    dest.fill(tiny_skia::Color::from_rgba8(0, 0, 0, 255));

    let bounds_in_src = Rect::from_xywh(0.0, 0.0, 35.0, 35.0);
    let clip_bounds = Rect::from_xywh(0.0, 1.0, 35.0, 34.0001);
    let filters = [ResolvedFilter::Blur(1.0)];

    let result = apply_backdrop_filters_with_region_filler(
      &mut dest,
      (40, 40),
      (0, 0),
      bounds_in_src,
      bounds_in_src,
      &filters,
      BorderRadii::uniform(4.0),
      1.0,
      None,
      Some(clip_bounds),
      (0, 0),
      bounds_in_src,
      Transform::identity(),
      None,
      None,
      |region, _clamped_x, _clamped_y| {
        for px in region.data_mut().chunks_exact_mut(4) {
          px.copy_from_slice(&[255, 0, 0, 255]);
        }
        Ok(())
      },
      None,
      None,
    );

    assert!(result.is_ok(), "expected no panic/error, got: {result:?}");
  }

  #[test]
  fn estimate_expensive_raster_pixels_counts_opacity_groups() {
    let mut list = DisplayList::new();
    list.push(DisplayItem::PushOpacity(OpacityItem { opacity: 0.5 }));
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(0.0, 0.0, 50.0, 50.0),
      color: Rgba::RED,
    }));
    list.push(DisplayItem::PopOpacity);

    let renderer = DisplayListRenderer::new(100, 100, Rgba::WHITE, FontContext::new()).unwrap();
    let (expensive_pixels, image_source_pixels, image_tiles) = renderer
      .estimate_expensive_raster_pixels(list.items(), 4)
      .unwrap();

    assert_eq!(expensive_pixels, 2500);
    assert_eq!(image_source_pixels, 0);
    assert_eq!(image_tiles, 0);
  }

