  #[test]
  fn preserve_3d_scene_toggle_enables_parallel_tiling() {
    let mut list = DisplayList::new();
    let rect = Rect::from_xywh(0.0, 0.0, 512.0, 512.0);
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: false,
      has_backdrop_sensitive_descendants: false,
      bounds: rect,
      plane_rect: rect,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: None,
      child_perspective: None,
      transform_style: TransformStyle::Preserve3d,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: Vec::new(),
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));
    list.push(DisplayItem::FillRect(FillRectItem {
      rect,
      color: Rgba::RED,
    }));
    list.push(DisplayItem::PopStackingContext);

    let parallelism = PaintParallelism::enabled();

    let paint_threads = Arc::new(crate::debug::runtime::RuntimeToggles::from_map(
      std::collections::HashMap::from([("FASTR_PAINT_THREADS".to_string(), "2".to_string())]),
    ));

    let report =
      crate::debug::runtime::with_thread_runtime_toggles(Arc::clone(&paint_threads), || {
        DisplayListRenderer::new(512, 512, Rgba::WHITE, FontContext::new())
          .unwrap()
          .with_parallelism(parallelism)
          .render_with_report(&list)
          .unwrap()
      });
    assert!(
      !report.parallel_used,
      "expected preserve-3d scene compositor to force serial paint"
    );
    assert!(
      report
        .fallback_reason
        .as_deref()
        .unwrap_or_default()
        .contains("preserve-3d"),
      "expected preserve-3d to be the serial fallback reason, got {:?}",
      report.fallback_reason
    );

    let renderer = crate::debug::runtime::with_runtime_toggles(
      Arc::new(crate::debug::runtime::RuntimeToggles::from_map(
        std::collections::HashMap::from([(
          "FASTR_PRESERVE3D_DISABLE_SCENE".to_string(),
          "1".to_string(),
        )]),
      )),
      || {
        DisplayListRenderer::new(512, 512, Rgba::WHITE, FontContext::new())
          .unwrap()
          .with_parallelism(parallelism)
      },
    );
    let report =
      crate::debug::runtime::with_thread_runtime_toggles(Arc::clone(&paint_threads), || {
        renderer.render_with_report(&list).unwrap()
      });
    assert!(
      report.parallel_used,
      "expected preserve-3d scene compositor toggle to allow parallel tiling (fallback_reason={:?})",
      report.fallback_reason
    );
    assert!(
      report.tiles > 1,
      "expected multiple tiles, got {}",
      report.tiles
    );
  }

  #[test]
  fn preserve_3d_scene_depth_limit_disables_depth_sorting() {
    // Preserve-3D rendering recurses through `render_scene_item` for planes that must be
    // flattened into offscreen pixmaps. The renderer guards against pathological recursion
    // depth by disabling preserve-3d processing once `preserve_3d_scene_depth` reaches
    // `PRESERVE_3D_SCENE_RECURSION_LIMIT`.
    //
    // This test asserts that the guard is actually wired up by forcing the renderer to start
    // at the recursion limit and verifying that it falls back to DOM paint order (no depth
    // sorting) for a scene where preserve-3d depth sorting changes the final pixels.
    let tilted_rect = Rect::from_xywh(10.0, 10.0, 40.0, 20.0);
    let front_rect = Rect::from_xywh(5.0, 10.0, 20.0, 20.0);

    let tilt = Transform3D::translate(0.0, 0.0, 5.0)
      .multiply(&Transform3D::translate(30.0, 20.0, 0.0))
      .multiply(&Transform3D::rotate_y(60_f32.to_radians()))
      .multiply(&Transform3D::translate(-30.0, -20.0, 0.0));

    let mut list = DisplayList::new();
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: false,
      has_backdrop_sensitive_descendants: false,
      bounds: Rect::from_xywh(0.0, 0.0, 80.0, 50.0),
      plane_rect: Rect::from_xywh(0.0, 0.0, 80.0, 50.0),
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: None,
      child_perspective: None,
      transform_style: TransformStyle::Preserve3d,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: Vec::new(),
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));

    // Tilted plane is emitted first in DOM order but should win at the overlap point when
    // preserve-3d depth sorting is active.
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: false,
      has_backdrop_sensitive_descendants: false,
      bounds: tilted_rect,
      plane_rect: tilted_rect,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: Some(tilt),
      child_perspective: None,
      transform_style: TransformStyle::Preserve3d,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: Vec::new(),
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: tilted_rect,
      color: Rgba::BLUE,
    }));
    list.push(DisplayItem::PopStackingContext);

    // Front plane is emitted later in DOM order but is further away at the overlap point.
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: false,
      has_backdrop_sensitive_descendants: false,
      bounds: front_rect,
      plane_rect: front_rect,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: Some(Transform3D::translate(0.0, 0.0, 10.0)),
      child_perspective: None,
      transform_style: TransformStyle::Preserve3d,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: Vec::new(),
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: front_rect,
      color: Rgba::GREEN,
    }));
    list.push(DisplayItem::PopStackingContext);

    list.push(DisplayItem::PopStackingContext);

    let pixmap = DisplayListRenderer::new(80, 50, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list)
      .unwrap();
    let overlap = pixel(&pixmap, 22, 20);
    assert!(
      overlap.2 > overlap.1,
      "expected preserve-3d depth sorting to paint the tilted plane on top"
    );

    let mut renderer = DisplayListRenderer::new(80, 50, Rgba::WHITE, FontContext::new()).unwrap();
    renderer.preserve_3d_scene_depth = PRESERVE_3D_SCENE_RECURSION_LIMIT;
    let pixmap = renderer.render(&list).unwrap();
    let overlap = pixel(&pixmap, 22, 20);
    assert!(
      overlap.1 > overlap.2,
      "expected recursion depth guard to disable preserve-3d depth sorting and fall back to DOM paint order"
    );
  }

  #[test]
  fn preserve_3d_backdrop_filter_samples_composited_backdrop() {
    let bounds = Rect::from_xywh(0.0, 0.0, 50.0, 20.0);
    let left = Rect::from_xywh(0.0, 0.0, 25.0, 20.0);
    let right = Rect::from_xywh(25.0, 0.0, 25.0, 20.0);

    let render = |backdrop_filters: Vec<ResolvedFilter>| -> Pixmap {
      let mut list = DisplayList::new();
      list.push(DisplayItem::PushStackingContext(StackingContextItem {
        z_index: 0,
        creates_stacking_context: true,
        is_root: false,
        establishes_backdrop_root: false,
        has_backdrop_sensitive_descendants: !backdrop_filters.is_empty(),
        bounds,
        plane_rect: bounds,
        mix_blend_mode: BlendMode::Normal,
        opacity: 1.0,
        is_isolated: false,
        transform: None,
        child_perspective: None,
        transform_style: TransformStyle::Preserve3d,
        backface_visibility: BackfaceVisibility::Visible,
        filters: Vec::new(),
        backdrop_filters: Vec::new(),
        radii: BorderRadii::ZERO,
        mask: None,
        mask_border: None,
        has_clip_path: false,
      }));

      // Back plane paints a hard black/white edge at x=25.
      list.push(DisplayItem::PushStackingContext(StackingContextItem {
        z_index: 0,
        creates_stacking_context: true,
        is_root: false,
        establishes_backdrop_root: false,
        has_backdrop_sensitive_descendants: false,
        bounds,
        plane_rect: bounds,
        mix_blend_mode: BlendMode::Normal,
        opacity: 1.0,
        is_isolated: false,
        transform: Some(Transform3D::translate(0.0, 0.0, -10.0)),
        child_perspective: None,
        transform_style: TransformStyle::Flat,
        backface_visibility: BackfaceVisibility::Visible,
        filters: Vec::new(),
        backdrop_filters: Vec::new(),
        radii: BorderRadii::ZERO,
        mask: None,
        mask_border: None,
        has_clip_path: false,
      }));
      list.push(DisplayItem::FillRect(FillRectItem {
        rect: left,
        color: Rgba::BLACK,
      }));
      list.push(DisplayItem::FillRect(FillRectItem {
        rect: right,
        color: Rgba::WHITE,
      }));
      list.push(DisplayItem::PopStackingContext);

      // Front plane applies the backdrop filter (content is empty/transparent so only the filtered
      // backdrop is visible).
      list.push(DisplayItem::PushStackingContext(StackingContextItem {
        z_index: 0,
        creates_stacking_context: true,
        is_root: false,
        establishes_backdrop_root: !backdrop_filters.is_empty(),
        has_backdrop_sensitive_descendants: !backdrop_filters.is_empty(),
        bounds,
        plane_rect: bounds,
        mix_blend_mode: BlendMode::Normal,
        opacity: 1.0,
        is_isolated: !backdrop_filters.is_empty(),
        transform: Some(Transform3D::translate(0.0, 0.0, 10.0)),
        child_perspective: None,
        transform_style: TransformStyle::Flat,
        backface_visibility: BackfaceVisibility::Visible,
        filters: Vec::new(),
        backdrop_filters,
        radii: BorderRadii::ZERO,
        mask: None,
        mask_border: None,
        has_clip_path: false,
      }));
      list.push(DisplayItem::PopStackingContext);

      list.push(DisplayItem::PopStackingContext);

      DisplayListRenderer::new(50, 20, Rgba::TRANSPARENT, FontContext::new())
        .unwrap()
        .render(&list)
        .unwrap()
    };

    let baseline = render(Vec::new());
    let blurred = render(vec![ResolvedFilter::Blur(5.0)]);

    let baseline_px = pixel(&baseline, 24, 10);
    let blurred_px = pixel(&blurred, 24, 10);
    assert_ne!(
      baseline_px, blurred_px,
      "expected backdrop-filter to sample the composited backdrop in preserve-3d scenes"
    );
    assert!(
      blurred_px.0 > baseline_px.0,
      "expected blur to mix in white pixels across the edge; baseline={baseline_px:?} blurred={blurred_px:?}"
    );
  }

  #[test]
  fn backdrop_filter_scopes_to_explicit_backdrop_root_layers() {
    let viewport = 16u32;
    let bounds = Rect::from_xywh(0.0, 0.0, viewport as f32, viewport as f32);

    let render = |outer_backdrop_root: bool| -> Pixmap {
      let mut list = DisplayList::new();
      list.push(DisplayItem::FillRect(FillRectItem {
        rect: bounds,
        color: Rgba::rgb(255, 0, 0),
      }));

      list.push(DisplayItem::PushStackingContext(StackingContextItem {
        z_index: 0,
        creates_stacking_context: true,
        is_root: false,
        establishes_backdrop_root: outer_backdrop_root,
        has_backdrop_sensitive_descendants: true,
        bounds,
        plane_rect: bounds,
        mix_blend_mode: BlendMode::Normal,
        opacity: 1.0,
        is_isolated: false,
        transform: None,
        child_perspective: None,
        transform_style: TransformStyle::Flat,
        backface_visibility: BackfaceVisibility::Visible,
        filters: Vec::new(),
        backdrop_filters: Vec::new(),
        radii: BorderRadii::ZERO,
        mask: None,
        mask_border: None,
        has_clip_path: false,
      }));

      list.push(DisplayItem::PushStackingContext(StackingContextItem {
        z_index: 0,
        creates_stacking_context: true,
        is_root: false,
        establishes_backdrop_root: true,
        has_backdrop_sensitive_descendants: true,
        bounds,
        plane_rect: bounds,
        mix_blend_mode: BlendMode::Normal,
        opacity: 1.0,
        is_isolated: false,
        transform: None,
        child_perspective: None,
        transform_style: TransformStyle::Flat,
        backface_visibility: BackfaceVisibility::Visible,
        filters: Vec::new(),
        backdrop_filters: vec![ResolvedFilter::Invert(1.0)],
        radii: BorderRadii::ZERO,
        mask: None,
        mask_border: None,
        has_clip_path: false,
      }));
      list.push(DisplayItem::PopStackingContext);

      list.push(DisplayItem::PopStackingContext);

      DisplayListRenderer::new(viewport, viewport, Rgba::WHITE, FontContext::new())
        .unwrap()
        .render(&list)
        .unwrap()
    };

    let baseline = render(false);
    let scoped = render(true);

    assert_eq!(
      pixel(&baseline, 8, 8),
      (0, 255, 255, 255),
      "expected backdrop-filter to sample the red backdrop when no backdrop root is present"
    );
    assert_eq!(
      pixel(&scoped, 8, 8),
      (255, 0, 0, 255),
      "expected establishes_backdrop_root to scope backdrop-filter sampling (preventing sampling from the red base)"
    );
  }

  #[test]
  fn preserve_3d_backdrop_filter_scopes_to_explicit_backdrop_root_layers() {
    let width = 50u32;
    let height = 20u32;
    let bounds = Rect::from_xywh(0.0, 0.0, width as f32, height as f32);
    let plane = Rect::from_xywh(10.0, 0.0, 25.0, height as f32);

    let render = |outer_backdrop_root: bool| -> Pixmap {
      let mut list = DisplayList::new();
      list.push(DisplayItem::FillRect(FillRectItem {
        rect: bounds,
        color: Rgba::rgb(255, 0, 0),
      }));

      // Preserve-3d roots are rendered via a dedicated scene compositor. Ensure Backdrop Root
      // scoping still applies when the preserve-3d context establishes a Backdrop Root boundary
      // (e.g. due to `will-change` triggers).
      list.push(DisplayItem::PushStackingContext(StackingContextItem {
        z_index: 0,
        creates_stacking_context: true,
        is_root: false,
        establishes_backdrop_root: outer_backdrop_root,
        has_backdrop_sensitive_descendants: true,
        bounds,
        plane_rect: bounds,
        mix_blend_mode: BlendMode::Normal,
        opacity: 1.0,
        is_isolated: false,
        transform: None,
        child_perspective: None,
        transform_style: TransformStyle::Preserve3d,
        backface_visibility: BackfaceVisibility::Visible,
        filters: Vec::new(),
        backdrop_filters: Vec::new(),
        radii: BorderRadii::ZERO,
        mask: None,
        mask_border: None,
        has_clip_path: false,
      }));

      list.push(DisplayItem::PushStackingContext(StackingContextItem {
        z_index: 0,
        creates_stacking_context: true,
        is_root: false,
        establishes_backdrop_root: true,
        has_backdrop_sensitive_descendants: true,
        bounds: plane,
        plane_rect: plane,
        mix_blend_mode: BlendMode::Normal,
        opacity: 1.0,
        is_isolated: true,
        transform: Some(Transform3D::translate(0.0, 0.0, 10.0)),
        child_perspective: None,
        transform_style: TransformStyle::Flat,
        backface_visibility: BackfaceVisibility::Visible,
        filters: Vec::new(),
        backdrop_filters: vec![ResolvedFilter::Invert(1.0)],
        radii: BorderRadii::ZERO,
        mask: None,
        mask_border: None,
        has_clip_path: false,
      }));
      list.push(DisplayItem::PopStackingContext);

      list.push(DisplayItem::PopStackingContext);

      DisplayListRenderer::new(width, height, Rgba::WHITE, FontContext::new())
        .unwrap()
        .render(&list)
        .unwrap()
    };

    let baseline = render(false);
    let scoped = render(true);

    assert_eq!(
      pixel(&baseline, 20, 10),
      (0, 255, 255, 255),
      "expected preserve-3d backdrop-filter to sample the red backdrop when no backdrop root is present"
    );
    assert_eq!(
      pixel(&scoped, 20, 10),
      (255, 0, 0, 255),
      "expected preserve-3d Backdrop Root boundaries to scope backdrop-filter sampling"
    );
  }

  #[test]
  fn backdrop_filter_crosses_isolation_layers_for_backdrop_root_sampling() {
    let bounds = Rect::from_xywh(0.0, 0.0, 50.0, 20.0);
    let plane = Rect::from_xywh(0.0, 0.0, 25.0, 20.0);

    let mut list = DisplayList::new();
    // Paint a red backdrop outside the isolation layer.
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: bounds,
      color: Rgba::RED,
    }));

    // `isolation: isolate` creates an implementation layer, but it must *not* establish a new
    // Backdrop Root. A descendant backdrop-filter should still see the red backdrop behind it.
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: false,
      has_backdrop_sensitive_descendants: true,
      bounds,
      plane_rect: bounds,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: true,
      transform: None,
      child_perspective: None,
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: Vec::new(),
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));

    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: true,
      has_backdrop_sensitive_descendants: true,
      bounds: plane,
      plane_rect: plane,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: true,
      transform: None,
      child_perspective: None,
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: vec![ResolvedFilter::Invert(1.0)],
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));
    list.push(DisplayItem::PopStackingContext);
    list.push(DisplayItem::PopStackingContext);

    let pixmap = DisplayListRenderer::new(50, 20, Rgba::TRANSPARENT, FontContext::new())
      .unwrap()
      .render(&list)
      .unwrap();

    assert_eq!(
      pixel(&pixmap, 10, 10),
      (0, 255, 255, 255),
      "expected backdrop-filter to invert the red backdrop across isolation layers"
    );
    assert_eq!(
      pixel(&pixmap, 40, 10),
      (255, 0, 0, 255),
      "expected pixels outside the backdrop-filter bounds to remain unchanged"
    );
  }

