  #[test]
  fn backdrop_filters_offset_clip_matches_global_clip() {
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = BackdropFilterScratch::default();
    });

    let mut base = new_pixmap(10, 10).unwrap();
    for y in 0..base.height() {
      for x in 0..base.width() {
        let idx = ((y * base.width() + x) * 4) as usize;
        base.data_mut()[idx] = 100;
        base.data_mut()[idx + 1] = 110;
        base.data_mut()[idx + 2] = 120;
        base.data_mut()[idx + 3] = 255;
      }
    }

    let bounds = Rect::from_xywh(2.0, 2.0, 6.0, 6.0);
    let filters = vec![ResolvedFilter::Brightness(1.25)];

    let clip_bounds_global = Rect::from_xywh(3.0, 4.0, 4.0, 3.0);
    let clip_origin = (clip_bounds_global.x() as i32, clip_bounds_global.y() as i32);
    let clip_bounds_local = Rect::from_xywh(
      clip_bounds_global.x() - clip_origin.0 as f32,
      clip_bounds_global.y() - clip_origin.1 as f32,
      clip_bounds_global.width(),
      clip_bounds_global.height(),
    );

    let mut clip_mask_global = Mask::new(10, 10).unwrap();
    clip_mask_global.data_mut().fill(0);
    for y in clip_origin.1 as u32..(clip_origin.1 as u32 + clip_bounds_global.height() as u32) {
      for x in clip_origin.0 as u32..(clip_origin.0 as u32 + clip_bounds_global.width() as u32) {
        let idx = (y * clip_mask_global.width() + x) as usize;
        // Make the mask non-rectangular so the per-pixel clip path is exercised.
        clip_mask_global.data_mut()[idx] = if (x + y) % 2 == 0 { 255 } else { 0 };
      }
    }

    let mut clip_mask_local = Mask::new(
      clip_bounds_global.width() as u32,
      clip_bounds_global.height() as u32,
    )
    .unwrap();
    for y in 0..clip_mask_local.height() {
      for x in 0..clip_mask_local.width() {
        let global_x = x + clip_origin.0 as u32;
        let global_y = y + clip_origin.1 as u32;
        let global_idx = (global_y * clip_mask_global.width() + global_x) as usize;
        let local_idx = (y * clip_mask_local.width() + x) as usize;
        clip_mask_local.data_mut()[local_idx] = clip_mask_global.data()[global_idx];
      }
    }

    let mut global_clip = base.clone();
    let mut offset_clip = base.clone();

    apply_backdrop_filters(
      &mut global_clip,
      &base,
      (0, 0),
      bounds,
      bounds,
      &filters,
      BorderRadii::ZERO,
      1.0,
      Some(&clip_mask_global),
      Some(clip_bounds_global),
      (0, 0),
      bounds,
      Transform::identity(),
      None,
      None,
    )
    .unwrap();

    apply_backdrop_filters(
      &mut offset_clip,
      &base,
      (0, 0),
      bounds,
      bounds,
      &filters,
      BorderRadii::ZERO,
      1.0,
      Some(&clip_mask_local),
      Some(clip_bounds_local),
      clip_origin,
      bounds,
      Transform::identity(),
      None,
      None,
    )
    .unwrap();

    assert_eq!(
      global_clip.data(),
      offset_clip.data(),
      "expected clip mask/bounds origins to be interpreted in the target pixmap coordinate space"
    );

    // Spot-check that at least one pixel inside the mask changed.
    let masked = pixel(&global_clip, 4, 4);
    let baseline = pixel(&base, 4, 4);
    assert_ne!(masked, baseline, "expected filtered pixel to change");
    // And that pixels outside the clip bounds remain unchanged.
    assert_eq!(
      pixel(&global_clip, 0, 0),
      pixel(&base, 0, 0),
      "expected pixels outside the clip bounds to remain unchanged"
    );
  }

  #[test]
  fn backdrop_filters_clamp_write_region_to_dest_bounds() {
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = BackdropFilterScratch::default();
    });

    let backdrop = {
      let mut pixmap = new_pixmap(10, 10).unwrap();
      for y in 0..pixmap.height() {
        for x in 0..pixmap.width() {
          let idx = ((y * pixmap.width() + x) * 4) as usize;
          pixmap.data_mut()[idx] = 100;
          pixmap.data_mut()[idx + 1] = 110;
          pixmap.data_mut()[idx + 2] = 120;
          pixmap.data_mut()[idx + 3] = 255;
        }
      }
      pixmap
    };

    let mut dest = new_pixmap(10, 10).unwrap();
    for y in 0..dest.height() {
      for x in 0..dest.width() {
        let idx = ((y * dest.width() + x) * 4) as usize;
        dest.data_mut()[idx] = 10;
        dest.data_mut()[idx + 1] = 20;
        dest.data_mut()[idx + 2] = 30;
        dest.data_mut()[idx + 3] = 255;
      }
    }

    // Offset the destination one pixel down relative to the backdrop. This makes the local
    // destination write bounds partially negative (and therefore clipped to y=0).
    let dest_origin_in_backdrop = (0, 1);
    let bounds = Rect::from_xywh(0.0, 0.0, 10.0, 10.0);
    let filters = vec![ResolvedFilter::Brightness(1.25)];

    let before_inside = pixel(&dest, 5, 5);
    let before_outside = pixel(&dest, 5, 9);

    apply_backdrop_filters(
      &mut dest,
      &backdrop,
      dest_origin_in_backdrop,
      bounds,
      bounds,
      &filters,
      BorderRadii::uniform(2.0),
      1.0,
      None,
      None,
      (0, 0),
      bounds,
      Transform::identity(),
      None,
      None,
    )
    .unwrap();

    assert_ne!(
      pixel(&dest, 5, 5),
      before_inside,
      "expected pixels inside the clipped write region to be updated"
    );
    assert_eq!(
      pixel(&dest, 5, 9),
      before_outside,
      "expected pixels outside the clipped write region to remain unchanged"
    );
  }

  #[test]
  fn backdrop_filters_clamp_write_region_to_filtered_bounds() {
    BACKDROP_FILTER_SCRATCH.with(|cell| {
      *cell.borrow_mut() = BackdropFilterScratch::default();
    });

    // Simulate a bounded layer that extends beyond the available backdrop root source pixmap.
    // This can happen when a backdrop-filter stacking context is padded by filter outsets near the
    // viewport edge.
    //
    // `apply_backdrop_filters_with_region_filler` clamps the filtered region size to the available
    // source pixmap, but it must also clamp the destination write region to the filtered bounds so
    // we don't index beyond `filtered_data` / masks.
    let backdrop = {
      let mut pixmap = new_pixmap(100, 20).unwrap();
      for px in pixmap.data_mut().chunks_exact_mut(4) {
        px[0] = 10;
        px[1] = 20;
        px[2] = 30;
        px[3] = 255;
      }
      pixmap
    };

    let mut dest = new_pixmap(80, 20).unwrap();
    dest.data_mut().fill(0);

    // Destination layer at x=40 with width=80 covers source coords [40..120), but the source
    // pixmap only covers [0..100). The last 20 columns should be ignored rather than indexing past
    // the filtered scratch.
    let dest_origin_in_src = (40, 0);
    let bounds_in_src = Rect::from_xywh(40.0, 0.0, 80.0, 20.0);
    let filters = vec![ResolvedFilter::Blur(0.0)];
    let world_to_dest = Transform::from_translate(-(dest_origin_in_src.0 as f32), 0.0);

    apply_backdrop_filters(
      &mut dest,
      &backdrop,
      dest_origin_in_src,
      bounds_in_src,
      bounds_in_src,
      &filters,
      BorderRadii::uniform(4.0),
      1.0,
      None,
      None,
      (0, 0),
      bounds_in_src,
      world_to_dest,
      None,
      None,
    )
    .expect("apply backdrop filter");

    // Pixels sourced from the backdrop should be written.
    assert_eq!(pixel(&dest, 10, 10), (10, 20, 30, 255));
    assert_eq!(pixel(&dest, 59, 10), (10, 20, 30, 255));
    // Pixels beyond the available source should be left unchanged.
    assert_eq!(pixel(&dest, 60, 10), (0, 0, 0, 0));
    assert_eq!(pixel(&dest, 79, 10), (0, 0, 0, 0));
  }

  #[test]
  fn backdrop_filter_stacking_context_uses_bounded_layer_allocation() {
    let diag = Arc::new(LayerAllocationDiagnostics::default());
    let mut renderer = DisplayListRenderer::new(100, 100, Rgba::WHITE, FontContext::new()).unwrap();
    renderer.set_parallelism(PaintParallelism::disabled());
    renderer.layer_alloc_diagnostics = Some(diag.clone());

    let mut list = DisplayList::new();
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: true,
      has_backdrop_sensitive_descendants: true,
      bounds: Rect::from_xywh(10.0, 10.0, 20.0, 20.0),
      plane_rect: Rect::from_xywh(10.0, 10.0, 20.0, 20.0),
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: None,
      child_perspective: None,
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: vec![ResolvedFilter::Brightness(1.0)],
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));
    list.push(DisplayItem::PopStackingContext);

    renderer.render(&list).unwrap();
    let snapshot = diag.snapshot();
    assert_eq!(snapshot.allocations, 1);
    assert_eq!(
      snapshot.bytes,
      20u64.saturating_mul(20).saturating_mul(4),
      "expected backdrop-filter stacking context to allocate a bounded layer"
    );
  }

  #[test]
  fn backdrop_filter_projective_transform_uses_bounded_layer_allocation() {
    let diag = Arc::new(LayerAllocationDiagnostics::default());
    let mut renderer = DisplayListRenderer::new(100, 100, Rgba::WHITE, FontContext::new()).unwrap();
    renderer.set_parallelism(PaintParallelism::disabled());
    renderer.layer_alloc_diagnostics = Some(diag.clone());

    let bounds = Rect::from_xywh(10.0, 10.0, 20.0, 20.0);
    let center = bounds.center();
    let rotate = Transform3D::translate(center.x, center.y, 0.0)
      .multiply(&Transform3D::rotate_y(35_f32.to_radians()))
      .multiply(&Transform3D::translate(-center.x, -center.y, 0.0));
    let transform = Transform3D::perspective(200.0).multiply(&rotate);

    let mut list = DisplayList::new();
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: true,
      has_backdrop_sensitive_descendants: true,
      bounds,
      plane_rect: bounds,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: Some(transform),
      child_perspective: None,
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: vec![ResolvedFilter::Brightness(1.0)],
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));
    list.push(DisplayItem::PopStackingContext);

    renderer.render(&list).unwrap();
    let snapshot = diag.snapshot();
    assert_eq!(snapshot.allocations, 1);
    let full_canvas_bytes = 100u64.saturating_mul(100).saturating_mul(4);
    assert!(
      snapshot.bytes > 0 && snapshot.bytes < full_canvas_bytes,
      "expected bounded projective+backdrop allocation, got {} bytes for a {}-byte canvas",
      snapshot.bytes,
      full_canvas_bytes
    );
  }

  #[test]
  fn backdrop_filter_projective_transform_changes_pixels() {
    let viewport = 64u32;
    let bounds = Rect::from_xywh(10.0, 10.0, 20.0, 20.0);
    let center = bounds.center();
    let rotate = Transform3D::translate(center.x, center.y, 0.0)
      .multiply(&Transform3D::rotate_y(20_f32.to_radians()))
      .multiply(&Transform3D::translate(-center.x, -center.y, 0.0));
    let transform = Transform3D::perspective(400.0).multiply(&rotate);

    let mut base = DisplayList::new();
    base.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(0.0, 0.0, viewport as f32, viewport as f32),
      color: Rgba::rgb(255, 0, 0),
    }));
    base.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: false,
      has_backdrop_sensitive_descendants: false,
      bounds,
      plane_rect: bounds,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: Some(transform),
      child_perspective: None,
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: Vec::new(),
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));
    base.push(DisplayItem::PopStackingContext);

    let mut filtered = base.clone();
    if let Some(DisplayItem::PushStackingContext(ctx)) = filtered.items_mut().get_mut(1) {
      ctx.backdrop_filters = vec![ResolvedFilter::Invert(1.0)];
      ctx.establishes_backdrop_root = true;
      ctx.has_backdrop_sensitive_descendants = true;
    }

    let baseline_pixmap =
      DisplayListRenderer::new(viewport, viewport, Rgba::WHITE, FontContext::new())
        .unwrap()
        .render(&base)
        .unwrap();
    let filtered_pixmap =
      DisplayListRenderer::new(viewport, viewport, Rgba::WHITE, FontContext::new())
        .unwrap()
        .render(&filtered)
        .unwrap();

    let union = bounds.union(transform.transform_rect(bounds));
    let Some(check_rect) =
      union.intersection(Rect::from_xywh(0.0, 0.0, viewport as f32, viewport as f32))
    else {
      panic!("expected projected bounds to intersect viewport");
    };
    let x0 = check_rect.min_x().floor().max(0.0) as u32;
    let y0 = check_rect.min_y().floor().max(0.0) as u32;
    let x1 = check_rect.max_x().ceil().min(viewport as f32) as u32;
    let y1 = check_rect.max_y().ceil().min(viewport as f32) as u32;

    let mut changed = false;
    'outer: for y in y0..y1 {
      for x in x0..x1 {
        if pixel(&baseline_pixmap, x, y) != pixel(&filtered_pixmap, x, y) {
          changed = true;
          break 'outer;
        }
      }
    }
    assert!(
      changed,
      "expected backdrop-filter to change at least one pixel"
    );
  }

  #[test]
  fn backdrop_filter_projective_transform_sampling_is_screen_aligned() {
    let viewport = 64u32;
    let bounds = Rect::from_xywh(0.0, 0.0, viewport as f32, viewport as f32);
    let center = bounds.center();
    let rotate = Transform3D::translate(center.x, center.y, 0.0)
      .multiply(&Transform3D::rotate_y(70_f32.to_radians()))
      .multiply(&Transform3D::translate(-center.x, -center.y, 0.0));
    let transform = Transform3D::perspective(200.0).multiply(&rotate);

    // Pick a backdrop boundary that is not aligned with the projective transform's rotation axis so
    // we can find pixels whose inverse-mapped backdrop sample crosses the boundary.
    let boundary = viewport as f32 * 0.5 - 8.0;
    let mut list = DisplayList::new();
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(0.0, 0.0, boundary, viewport as f32),
      color: Rgba::rgb(255, 0, 0),
    }));
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(boundary, 0.0, viewport as f32 - boundary, viewport as f32),
      color: Rgba::rgb(0, 255, 0),
    }));
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: true,
      has_backdrop_sensitive_descendants: true,
      bounds,
      plane_rect: bounds,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: Some(transform),
      child_perspective: None,
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: vec![ResolvedFilter::Invert(1.0)],
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));
    list.push(DisplayItem::PopStackingContext);

    let pixmap = DisplayListRenderer::new(viewport, viewport, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list)
      .unwrap();

    let homography = Homography::from_transform3d_z0(&transform);
    let inv = homography
      .inverse()
      .expect("expected projective transform homography to be invertible");
    let corners = [
      Point::new(bounds.min_x(), bounds.min_y()),
      Point::new(bounds.max_x(), bounds.min_y()),
      Point::new(bounds.max_x(), bounds.max_y()),
      Point::new(bounds.min_x(), bounds.max_y()),
    ];
    let projected = corners.map(|corner| {
      homography
        .map_point(corner)
        .expect("expected projected quad corner to be finite")
    });

    let point_in_quad = |p: Point, quad: &[Point; 4]| -> bool {
      let mut sign = 0.0f32;
      for i in 0..4 {
        let p1 = quad[i];
        let p2 = quad[(i + 1) % 4];
        let cross = (p2.x - p1.x) * (p.y - p1.y) - (p2.y - p1.y) * (p.x - p1.x);
        if !cross.is_finite() {
          return false;
        }
        if cross.abs() < 1e-6 {
          continue;
        }
        if sign.abs() < 1e-6 {
          sign = cross;
          continue;
        }
        if cross * sign < 0.0 {
          return false;
        }
      }
      true
    };

    let min_distance_to_quad_edge = |p: Point, quad: &[Point; 4]| -> f32 {
      let mut min = f32::INFINITY;
      for i in 0..4 {
        let a = quad[i];
        let b = quad[(i + 1) % 4];
        let abx = b.x - a.x;
        let aby = b.y - a.y;
        let denom = abx * abx + aby * aby;
        if denom <= 1e-6 {
          continue;
        }
        let apx = p.x - a.x;
        let apy = p.y - a.y;
        let mut t = (apx * abx + apy * aby) / denom;
        t = t.clamp(0.0, 1.0);
        let cx = a.x + t * abx;
        let cy = a.y + t * aby;
        let dx = p.x - cx;
        let dy = p.y - cy;
        min = min.min((dx * dx + dy * dy).sqrt());
      }
      min
    };

    let edge_margin = 4.0f32;
    let boundary_margin = 2.0f32;
    let mut candidate: Option<(u32, u32, bool)> = None;
    for y in 0..viewport {
      for x in 0..viewport {
        let p = Point::new(x as f32 + 0.5, y as f32 + 0.5);
        if !point_in_quad(p, &projected) {
          continue;
        }
        if min_distance_to_quad_edge(p, &projected) < edge_margin {
          continue;
        }
        let Some((qx, qy)) = inv.transform_point(p.x, p.y) else {
          continue;
        };
        if qx < 0.0
          || qy < 0.0
          || qx >= viewport as f32
          || qy >= viewport as f32
          || qx < edge_margin
          || qy < edge_margin
          || qx > viewport as f32 - edge_margin
          || qy > viewport as f32 - edge_margin
        {
          continue;
        }

        let p_left = p.x < boundary;
        let q_left = qx < boundary;
        if p_left == q_left {
          continue;
        }
        if (p.x - boundary).abs() < boundary_margin || (qx - boundary).abs() < boundary_margin {
          continue;
        }
        candidate = Some((x, y, p_left));
        break;
      }
      if candidate.is_some() {
        break;
      }
    }

    let (x, y, p_left) = candidate
      .expect("expected to find a pixel whose inverse-mapped sample crosses the backdrop boundary");
    let expected = if p_left {
      // Invert(red) -> cyan.
      (0, 255, 255, 255)
    } else {
      // Invert(green) -> magenta.
      (255, 0, 255, 255)
    };
    let p_center = Point::new(x as f32 + 0.5, y as f32 + 0.5);
    let (qx, qy) = inv
      .transform_point(p_center.x, p_center.y)
      .expect("inverse map candidate");
    assert_eq!(
      pixel(&pixmap, x, y),
      expected,
      "expected projective backdrop-filter sampling to remain screen-aligned (candidate=({x},{y}) p_left={p_left} q=({qx:.2},{qy:.2}))"
    );
  }

  #[test]
  fn perspective_stack_affects_translate_z_transforms() {
    let mut list = DisplayList::new();
    let viewport = Rect::from_xywh(0.0, 0.0, 64.0, 64.0);

    // Parent establishes a CSS `perspective` that applies to children only.
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: false,
      has_backdrop_sensitive_descendants: false,
      bounds: viewport,
      plane_rect: viewport,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: None,
      child_perspective: Some(Transform3D::perspective(100.0)),
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: Vec::new(),
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));

    // Child is translated towards the camera, which under perspective should scale up its plane.
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: false,
      has_backdrop_sensitive_descendants: false,
      bounds: viewport,
      plane_rect: viewport,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: Some(Transform3D::translate(0.0, 0.0, 50.0)),
      child_perspective: None,
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: Vec::new(),
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));

    list.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(10.0, 10.0, 10.0, 10.0),
      color: Rgba::RED,
    }));
    list.push(DisplayItem::PopStackingContext);
    list.push(DisplayItem::PopStackingContext);

    let pixmap = DisplayListRenderer::new(64, 64, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list)
      .unwrap();

    // With perspective=100 and translateZ(50), the projected scale factor is 2×. The filled rect
    // should therefore move from (10,10)-(20,20) to (20,20)-(40,40).
    assert_eq!(
      pixel(&pixmap, 15, 15),
      (255, 255, 255, 255),
      "expected original location to remain background"
    );
    assert_eq!(
      pixel(&pixmap, 25, 25),
      (255, 0, 0, 255),
      "expected scaled rect to cover a pixel in the projected area"
    );
  }

  fn non_background_bounds(
    pixmap: &Pixmap,
    background: (u8, u8, u8, u8),
  ) -> Option<(u32, u32, u32, u32)> {
    let mut min_x = u32::MAX;
    let mut min_y = u32::MAX;
    let mut max_x = 0u32;
    let mut max_y = 0u32;
    let mut any = false;
    for y in 0..pixmap.height() {
      for x in 0..pixmap.width() {
        if pixel(pixmap, x, y) != background {
          any = true;
          min_x = min_x.min(x);
          min_y = min_y.min(y);
          max_x = max_x.max(x);
          max_y = max_y.max(y);
        }
      }
    }
    any.then_some((min_x, min_y, max_x, max_y))
  }

  #[test]
  fn perspective_translate_z_composes_with_nested_projective_transforms() {
    let size = 128u32;
    let viewport = Rect::from_xywh(0.0, 0.0, size as f32, size as f32);
    let perspective = Transform3D::perspective(100.0);
    let translate_z = Transform3D::translate(0.0, 0.0, 50.0);
    let rotate_y = Transform3D::rotate_y(30_f32.to_radians());

    let rect = Rect::from_xywh(40.0, 40.0, 20.0, 20.0);

    let parent = StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: false,
      has_backdrop_sensitive_descendants: false,
      bounds: viewport,
      plane_rect: viewport,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: None,
      child_perspective: Some(perspective),
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: Vec::new(),
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    };

    let mut nested = DisplayList::new();
    nested.push(DisplayItem::PushStackingContext(parent.clone()));
    nested.push(DisplayItem::PushStackingContext(StackingContextItem {
      transform: Some(translate_z),
      child_perspective: None,
      ..parent.clone()
    }));
    nested.push(DisplayItem::PushStackingContext(StackingContextItem {
      transform: Some(rotate_y),
      child_perspective: None,
      ..parent.clone()
    }));
    nested.push(DisplayItem::FillRect(FillRectItem {
      rect,
      color: Rgba::RED,
    }));
    nested.push(DisplayItem::PopStackingContext);
    nested.push(DisplayItem::PopStackingContext);
    nested.push(DisplayItem::PopStackingContext);

    let mut combined = DisplayList::new();
    combined.push(DisplayItem::PushStackingContext(parent.clone()));
    combined.push(DisplayItem::PushStackingContext(StackingContextItem {
      transform: Some(translate_z.multiply(&rotate_y)),
      child_perspective: None,
      ..parent.clone()
    }));
    combined.push(DisplayItem::FillRect(FillRectItem {
      rect,
      color: Rgba::RED,
    }));
    combined.push(DisplayItem::PopStackingContext);
    combined.push(DisplayItem::PopStackingContext);

    let render = |list: &DisplayList| {
      DisplayListRenderer::new(size, size, Rgba::WHITE, FontContext::new())
        .unwrap()
        .render(list)
        .unwrap()
    };

    let nested_pixmap = render(&nested);
    let combined_pixmap = render(&combined);
    let bg = (255, 255, 255, 255);
    let nested_bounds = non_background_bounds(&nested_pixmap, bg).expect("nested draws pixels");
    let combined_bounds =
      non_background_bounds(&combined_pixmap, bg).expect("combined draws pixels");

    assert_eq!(
      nested_bounds, combined_bounds,
      "expected nested stacking-context composition to match combined transform composition"
    );
  }

