  #[test]
  fn image_filter_quality_respects_sampling_mode() {
    let pixels = vec![
      255, 0, 0, 255, // red
      0, 0, 255, 255, // blue
    ];
    let image = Arc::new(ImageData::new_pixels(2, 1, pixels));

    let render_with_quality = |quality: ImageFilterQuality| {
      let mut list = DisplayList::new();
      list.push(DisplayItem::Image(ImageItem {
        dest_rect: Rect::from_xywh(0.0, 0.0, 4.0, 1.0),
        image: image.clone(),
        filter_quality: quality,
        src_rect: None,
      }));
      DisplayListRenderer::new(4, 1, Rgba::WHITE, FontContext::new())
        .unwrap()
        .render(&list)
        .unwrap()
    };

    let nearest = render_with_quality(ImageFilterQuality::Nearest);
    let linear = render_with_quality(ImageFilterQuality::Linear);

    assert_eq!(pixel(&nearest, 0, 0), (255, 0, 0, 255));
    assert_eq!(pixel(&nearest, 1, 0), (255, 0, 0, 255));

    let blended = pixel(&linear, 1, 0);
    assert!(
      blended.0 < 255 && blended.2 < 255,
      "expected interpolation with linear sampling"
    );
  }

  #[test]
  fn image_src_rect_fractional_offsets_use_phase_corrected_resampling() {
    // 4x1 black→red→black ramp rendered to 3 output pixels.
    //
    // Use a <2x downscale so the mipmap LOD stays at 0 and the subpixel translation phase affects
    // the bilinear sample coordinates. This regression ensures fractional `src_rect` offsets are
    // incorporated into the sampling phase (common with `background-size: cover/contain`).
    let pixels = vec![
      0, 0, 0, 255, // black
      255, 0, 0, 255, // red
      0, 0, 0, 255, // black
      0, 0, 0, 255, // black
    ];
    let image = Arc::new(ImageData::new_pixels(4, 1, pixels));

    let mut list = DisplayList::new();
    list.push(DisplayItem::Image(ImageItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 3.0, 1.0),
      image,
      filter_quality: ImageFilterQuality::Linear,
      // Forces a non-integer translation phase for the full image even though the destination is
      // pixel-aligned.
      src_rect: Some(Rect::from_xywh(0.25, 0.0, 4.0, 1.0)),
    }));

    let pixmap = DisplayListRenderer::new(3, 1, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list)
      .unwrap();

    // The second output pixel samples 75% between the red and black texels, producing 63.75 which
    // Chrome/Skia floors to 63 when converting to 8-bit channels.
    assert_eq!(pixel(&pixmap, 1, 0), (63, 0, 0, 255));
  }

  #[test]
  fn image_src_rect_is_cropped_before_scaling() {
    let pixels = vec![
      255, 0, 0, 255, // red
      0, 255, 0, 255, // green
      0, 0, 255, 255, // blue
      255, 255, 0, 255, // yellow
    ];
    let image = Arc::new(ImageData::new_pixels(2, 2, pixels));

    let mut list = DisplayList::new();
    list.push(DisplayItem::Image(ImageItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 4.0, 4.0),
      image: image.clone(),
      filter_quality: ImageFilterQuality::Nearest,
      src_rect: Some(Rect::from_xywh(1.0, 0.0, 1.0, 2.0)), // right column (green/yellow)
    }));

    let pixmap = DisplayListRenderer::new(4, 4, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list)
      .unwrap();

    // Top-left pixel should come from the cropped source's first row: green.
    assert_eq!(pixel(&pixmap, 0, 0), (0, 255, 0, 255));
    // Bottom-left pixel should come from yellow.
    assert_eq!(pixel(&pixmap, 0, 3), (255, 255, 0, 255));
  }

  #[test]
  fn image_fractional_src_rect_uses_skia_aligned_bilinear_sampling() {
    // 3x1 image (black/red/black). Use a fractional src_rect so the renderer can't crop to integer
    // pixel bounds without losing sampling phase (e.g. background-size: cover).
    let pixels = vec![
      0, 0, 0, 255, // black
      255, 0, 0, 255, // red
      0, 0, 0, 255, // black
    ];
    let image = Arc::new(ImageData::new_pixels(3, 1, pixels));
    let mut list = DisplayList::new();
    list.push(DisplayItem::Image(ImageItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 1.0, 1.0),
      image,
      filter_quality: ImageFilterQuality::Linear,
      src_rect: Some(Rect::from_xywh(0.25, 0.0, 1.5, 1.0)),
    }));
    let pixmap = DisplayListRenderer::new(1, 1, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list)
      .unwrap();

    // For this mapping, the single destination pixel samples exactly halfway between the first two
    // source pixels. Skia floors the interpolated channel values, so 127.5 becomes 127.
    assert_eq!(pixel(&pixmap, 0, 0), (127, 0, 0, 255));
  }

  #[test]
  fn image_fractional_destination_edges_use_skia_aligned_sampling() {
    // 1x2 image (red/black). Draw into a destination rect whose bottom edge falls between device
    // pixels so sampling must account for the fractional destination height.
    let pixels = vec![
      255, 0, 0, 255, // red
      0, 0, 0, 255, // black
    ];
    let image = Arc::new(ImageData::new_pixels(1, 2, pixels));
    let mut list = DisplayList::new();
    list.push(DisplayItem::Image(ImageItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 1.0, 1.4),
      image,
      filter_quality: ImageFilterQuality::Linear,
      src_rect: Some(Rect::from_xywh(0.0, 0.0, 1.0, 2.0)),
    }));
    let pixmap = DisplayListRenderer::new(1, 1, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list)
      .unwrap();

    // The single destination pixel's center is 0.5 CSS px from the top; with `dest_h=1.4` the
    // sample lands ~21.4% toward the second source pixel. Skia floors the channel conversion.
    let (r, g, b, a) = pixel(&pixmap, 0, 0);
    assert_eq!((g, b, a), (0, 0, 255));
    assert!(
      (i32::from(r) - 200).abs() <= 1,
      "expected red channel close to 200, got {r}"
    );
  }

  #[test]
  fn image_full_src_rect_does_not_allocate_crop_pixmap() {
    let pixels = vec![
      255, 0, 0, 255, // red
      0, 255, 0, 255, // green
      0, 0, 255, 255, // blue
      255, 255, 0, 255, // yellow
    ];
    let image = Arc::new(ImageData::new_pixels(2, 2, pixels));

    let mut list = DisplayList::new();
    list.push(DisplayItem::Image(ImageItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 2.0, 2.0),
      image: image.clone(),
      filter_quality: ImageFilterQuality::Nearest,
      src_rect: Some(Rect::from_xywh(0.0, 0.0, 2.0, 2.0)),
    }));

    let renderer = DisplayListRenderer::new(2, 2, Rgba::WHITE, FontContext::new())
      .unwrap()
      .with_parallelism(PaintParallelism::disabled());
    let recorder = crate::paint::pixmap::NewPixmapAllocRecorder::start();
    let _ = renderer.render(&list).unwrap();
    let records = recorder.take();
    drop(recorder);

    let renderer_allocs: Vec<_> = records
      .iter()
      .filter(|r| r.file.ends_with("display_list_renderer.rs"))
      .collect();

    assert!(
      renderer_allocs.is_empty(),
      "expected full-image src_rect to avoid crop allocations, got {renderer_allocs:?}"
    );
  }

  #[test]
  fn image_src_rect_crop_is_cached_across_draws() {
    let pixels = vec![
      255, 0, 0, 255, // red
      0, 255, 0, 255, // green
      0, 0, 255, 255, // blue
      255, 255, 0, 255, // yellow
    ];
    let image = Arc::new(ImageData::new_pixels(2, 2, pixels));

    let mut list = DisplayList::new();
    let item = ImageItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 4.0, 4.0),
      image: image.clone(),
      filter_quality: ImageFilterQuality::Nearest,
      src_rect: Some(Rect::from_xywh(1.0, 0.0, 1.0, 2.0)),
    };
    list.push(DisplayItem::Image(item.clone()));
    list.push(DisplayItem::Image(item));

    let renderer = DisplayListRenderer::new(4, 4, Rgba::WHITE, FontContext::new())
      .unwrap()
      .with_parallelism(PaintParallelism::disabled());
    let recorder = crate::paint::pixmap::NewPixmapAllocRecorder::start();
    let _ = renderer.render(&list).unwrap();
    let records = recorder.take();
    drop(recorder);

    let renderer_allocs: Vec<_> = records
      .iter()
      .filter(|r| r.file.ends_with("display_list_renderer.rs"))
      .collect();

    assert_eq!(
      renderer_allocs.len(),
      1,
      "expected exactly one crop allocation for repeated src_rect draws, got {renderer_allocs:?}"
    );
    assert_eq!(
      (renderer_allocs[0].width, renderer_allocs[0].height),
      (1, 2),
      "unexpected cropped pixmap dimensions: {:?}",
      renderer_allocs[0]
    );
  }

  #[test]
  fn image_pixmap_conversion_is_cached_per_renderer() {
    let pixels = vec![255, 0, 0, 255];
    let image = Arc::new(ImageData::new_pixels(1, 1, pixels));

    let mut list = DisplayList::new();
    let item = ImageItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 1.0, 1.0),
      image: image.clone(),
      filter_quality: ImageFilterQuality::Nearest,
      src_rect: None,
    };
    list.push(DisplayItem::Image(item.clone()));
    list.push(DisplayItem::Image(item));

    let renderer = DisplayListRenderer::new(1, 1, Rgba::WHITE, FontContext::new()).unwrap();
    let cache_misses = renderer.image_cache_misses.clone();

    let _ = renderer.render(&list).unwrap();

    assert_eq!(
      cache_misses.load(Ordering::SeqCst),
      1,
      "expected pixmap conversion to be cached across repeated draws"
    );
  }

  #[test]
  fn image_pixmap_cache_enforces_item_cap() {
    let toggles = RuntimeToggles::from_map(HashMap::from([
      (ENV_IMAGE_PIXMAP_CACHE_ITEMS.to_string(), "8".to_string()),
      (ENV_IMAGE_PIXMAP_CACHE_BYTES.to_string(), "1024".to_string()),
    ]));

    with_runtime_toggles(Arc::new(toggles), || {
      let mut renderer =
        DisplayListRenderer::new(1, 1, Rgba::TRANSPARENT, FontContext::new()).unwrap();
      let images: Vec<_> = (0..32u8)
        .map(|i| ImageData::new_pixels(1, 1, vec![i, 0, 0, 255]))
        .collect();
      for image in &images {
        let pixmap = renderer.image_data_to_pixmap(image).unwrap().unwrap();
        assert_eq!((pixmap.width(), pixmap.height()), (1, 1));
      }

      assert!(renderer.image_cache.len() <= 8);
      assert!(renderer.image_cache.evictions() > 0);
    });
  }

  #[test]
  fn image_pixmap_cache_enforces_byte_cap() {
    let toggles = RuntimeToggles::from_map(HashMap::from([
      (ENV_IMAGE_PIXMAP_CACHE_ITEMS.to_string(), "64".to_string()),
      // A 1x1 pixmap stores 4 bytes. With an 8 byte cap we should never retain more than 2 entries.
      (ENV_IMAGE_PIXMAP_CACHE_BYTES.to_string(), "8".to_string()),
    ]));

    with_runtime_toggles(Arc::new(toggles), || {
      let mut renderer =
        DisplayListRenderer::new(1, 1, Rgba::TRANSPARENT, FontContext::new()).unwrap();
      let images: Vec<_> = (0..16u8)
        .map(|i| ImageData::new_pixels(1, 1, vec![i, 0, 0, 255]))
        .collect();
      for image in &images {
        let _ = renderer.image_data_to_pixmap(image).unwrap().unwrap();
      }

      assert!(renderer.image_cache.bytes() <= 8);
      assert!(renderer.image_cache.len() <= 2);
      assert!(renderer.image_cache.evictions() > 0);
    });
  }

  #[test]
  fn shared_image_pixmap_cache_enforces_item_cap() {
    let shared = SharedImagePixmaps::new(4, 0);
    let images: Vec<_> = (0..16u8)
      .map(|i| ImageData::new_pixels(1, 1, vec![i, 0, 0, 255]))
      .collect();
    for image in &images {
      let key = ImageKey::new(image);
      let _ = shared.image_cell(key);
    }

    let guard = shared
      .image_cache
      .lock()
      .unwrap_or_else(|poisoned| poisoned.into_inner());
    assert!(guard.len() <= 4);
  }

  #[test]
  fn scaled_image_pixmap_is_not_used_for_subpixel_unaligned_draws() {
    let pixels = vec![255u8; 100 * 100 * 4];
    let image = Arc::new(ImageData::new_pixels(100, 100, pixels));

    let mut renderer = DisplayListRenderer::new(200, 200, Rgba::WHITE, FontContext::new()).unwrap();

    // Integer-aligned image draws are safe to pre-scale: translation does not affect sampling.
    let aligned = ImageItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 10.0, 10.0),
      image: image.clone(),
      filter_quality: ImageFilterQuality::Linear,
      src_rect: None,
    };
    let aligned_pixmap = renderer
      .image_to_pixmap(&aligned)
      .expect("aligned pixmap")
      .expect("pixmap exists");
    assert_eq!(
      (aligned_pixmap.width(), aligned_pixmap.height()),
      (10, 10),
      "expected aligned draw to use scaled pixmap"
    );

    // Subpixel translations influence sampling. Avoid the scaled-pixmap fast path so we match
    // Skia/Chrome's behaviour for fractional destination rectangles.
    let subpixel = ImageItem {
      dest_rect: Rect::from_xywh(0.25, 0.0, 10.0, 10.0),
      image,
      filter_quality: ImageFilterQuality::Linear,
      src_rect: None,
    };
    let subpixel_pixmap = renderer
      .image_to_pixmap(&subpixel)
      .expect("subpixel pixmap")
      .expect("pixmap exists");
    assert_eq!(
      (subpixel_pixmap.width(), subpixel_pixmap.height()),
      (100, 100),
      "expected subpixel draw to use full-resolution pixmap"
    );
  }

  #[test]
  fn scaled_image_resampling_accounts_for_subpixel_translation_phase() {
    // 8x1 red ramp (0..224) so we can reason about sampling.
    let mut pixels = Vec::new();
    for i in 0..8u8 {
      pixels.extend_from_slice(&[i * 32, 0, 0, 255]);
    }
    let image = ImageData::new_pixels(8, 1, pixels);

    // Downscale to 4x1 at an integer origin. With a 2x downscale, each output pixel becomes the
    // average of a 2px span.
    let dest0 = Rect::from_xywh(0.0, 0.0, 4.0, 1.0);
    let origin0_x = (dest0.x() - 0.5).ceil();
    let origin0_y = (dest0.y() - 0.5).ceil();
    let out0_w = ((dest0.x() + dest0.width() - 0.5).ceil() - origin0_x).round() as u32;
    let out0_h = ((dest0.y() + dest0.height() - 0.5).ceil() - origin0_y).round() as u32;
    let pixmap0 = super::image_data_to_scaled_pixmap_with_phase_inner(
      &image, dest0, out0_w, out0_h, origin0_x, origin0_y,
    )
    .unwrap()
    .unwrap();
    assert_eq!((pixmap0.width(), pixmap0.height()), (4, 1));
    assert_eq!(pixel(&pixmap0, 0, 0), (16, 0, 0, 255));
    assert_eq!(pixel(&pixmap0, 1, 0), (80, 0, 0, 255));
    assert_eq!(pixel(&pixmap0, 2, 0), (144, 0, 0, 255));
    assert_eq!(pixel(&pixmap0, 3, 0), (208, 0, 0, 255));

    // A fractional destination origin changes sampling phase (subpixel translations should not be
    // treated as an afterthought once the image has been downsampled).
    let dest1 = Rect::from_xywh(0.5, 0.0, 4.0, 1.0);
    let origin1_x = (dest1.x() - 0.5).ceil();
    let origin1_y = (dest1.y() - 0.5).ceil();
    let out1_w = ((dest1.x() + dest1.width() - 0.5).ceil() - origin1_x).round() as u32;
    let out1_h = ((dest1.y() + dest1.height() - 0.5).ceil() - origin1_y).round() as u32;
    let pixmap1 = super::image_data_to_scaled_pixmap_with_phase_inner(
      &image, dest1, out1_w, out1_h, origin1_x, origin1_y,
    )
    .unwrap()
    .unwrap();
    assert_eq!((pixmap1.width(), pixmap1.height()), (4, 1));
    assert_eq!(pixel(&pixmap1, 0, 0), (0, 0, 0, 255));
    assert_eq!(pixel(&pixmap1, 1, 0), (48, 0, 0, 255));
    assert_eq!(pixel(&pixmap1, 2, 0), (112, 0, 0, 255));
    assert_eq!(pixel(&pixmap1, 3, 0), (176, 0, 0, 255));
  }

  #[test]
  fn scaled_image_resampling_from_src_rect_does_not_squeeze_full_image_into_clipped_output() {
    // Regression for wikipedia.org fixture: sprite backgrounds are painted via `ImageItem::src_rect`
    // by mapping the full image into device space and then clipping to the destination rect.
    //
    // The phase-aware sampling fast-path used the clipped output width/height as the sampling scale
    // denominator for Chrome-aligned magnification, which effectively squeezed the entire sprite
    // into the small clipped output and made icons nearly invisible (very light grey).

    // 64x1 row: first 8 pixels are black, the rest are white.
    let mut pixels = Vec::new();
    for x in 0..64u8 {
      if x < 8 {
        pixels.extend_from_slice(&[0, 0, 0, 255]);
      } else {
        pixels.extend_from_slice(&[255, 255, 255, 255]);
      }
    }
    let image = ImageData::new_pixels(64, 1, pixels);

    // `src_rect` selects the black region, mapped 1:1 into an 8px-wide destination rect that is
    // placed at a fractional X position (matching the fixture's subpixel-aligned sprite draws).
    let src_rect = Rect::from_xywh(0.0, 0.0, 8.0, 1.0);
    let dest_device = Rect::from_xywh(0.391, 0.0, 8.0, 1.0);

    let pixmap = super::image_data_to_scaled_pixmap_from_src_rect_with_phase_inner(
      &image, src_rect, dest_device, 8, 1, 0.0, 0.0,
    )
    .unwrap()
    .unwrap();

    assert_eq!((pixmap.width(), pixmap.height()), (8, 1));
    assert_eq!(pixel(&pixmap, 0, 0), (0, 0, 0, 255));
    assert_eq!(pixel(&pixmap, 7, 0), (0, 0, 0, 255));
  }

  #[test]
  fn scaled_image_resampling_snaps_near_integer_dest_rect() {
    let mut pixels = Vec::new();
    for y in 0..8u8 {
      for x in 0..8u8 {
        pixels.extend_from_slice(&[x * 32, y * 32, 0, 255]);
      }
    }
    let image = Arc::new(ImageData::new_pixels(8, 8, pixels));

    let mut list0 = DisplayList::new();
    list0.push(DisplayItem::Image(ImageItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 4.0, 4.0),
      image: image.clone(),
      filter_quality: ImageFilterQuality::Linear,
      src_rect: None,
    }));
    let pixmap0 = DisplayListRenderer::new(5, 5, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list0)
      .unwrap();

    let mut list1 = DisplayList::new();
    list1.push(DisplayItem::Image(ImageItem {
      dest_rect: Rect::from_xywh(0.05, 0.07, 3.98, 3.96),
      image,
      filter_quality: ImageFilterQuality::Linear,
      src_rect: None,
    }));
    let pixmap1 = DisplayListRenderer::new(5, 5, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list1)
      .unwrap();

    assert_eq!(pixmap0.data(), pixmap1.data());
  }

  #[test]
  fn moderate_upscale_with_fractional_dest_rect_uses_phase_aware_sampling() {
    // 9x9 gradient so upscaling yields fractional intermediate values.
    let mut pixels = Vec::new();
    for y in 0..9u8 {
      for x in 0..9u8 {
        pixels.extend_from_slice(&[x * 28, y * 28, 0, 255]);
      }
    }
    let image = Arc::new(ImageData::new_pixels(9, 9, pixels));

    // Modest upscale (9 -> 12) with a fractional max edge. This is large enough to avoid the small
    // image fast-paths, but small enough to be practical in unit tests.
    let dest = Rect::from_xywh(0.0, 0.0, 12.1, 12.1);
    let mut list = DisplayList::new();
    list.push(DisplayItem::Image(ImageItem {
      dest_rect: dest,
      image: image.clone(),
      filter_quality: ImageFilterQuality::Linear,
      src_rect: None,
    }));

    let rendered = DisplayListRenderer::new(12, 12, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list)
      .unwrap();

    // The renderer should use the phase-aware Skia-aligned sampler (see
    // `image_data_to_scaled_pixmap_with_phase_inner`) for this draw, so the final canvas should
    // match the sampler output exactly.
    let origin_x = (dest.x() - 0.5).ceil();
    let origin_y = (dest.y() - 0.5).ceil();
    let out_w = ((dest.x() + dest.width() - 0.5).ceil() - origin_x).round() as u32;
    let out_h = ((dest.y() + dest.height() - 0.5).ceil() - origin_y).round() as u32;
    let expected = super::image_data_to_scaled_pixmap_with_phase_inner(
      image.as_ref(),
      dest,
      out_w,
      out_h,
      origin_x,
      origin_y,
    )
    .unwrap()
    .unwrap();

    assert_eq!(
      (rendered.width(), rendered.height()),
      (expected.width(), expected.height())
    );
    assert_eq!(rendered.data(), expected.data());
  }

  #[test]
  fn scaled_image_resampling_uses_mipmapped_nearest_filtering() {
    // 8x1 red ramp (0..224).
    let mut pixels = Vec::new();
    for i in 0..8u8 {
      pixels.extend_from_slice(&[i * 32, 0, 0, 255]);
    }
    let image = ImageData::new_pixels(8, 1, pixels);

    // Downscale to 3px wide: Skia picks a single mip level (no trilinear blend) and uses bilinear
    // filtering within that level.
    let pixmap = super::image_data_to_scaled_pixmap_inner(&image, 3, 1, ImageFilterQuality::Linear)
      .unwrap()
      .unwrap();
    assert_eq!((pixmap.width(), pixmap.height()), (3, 1));
    assert_eq!(pixel(&pixmap, 0, 0), (26, 0, 0, 255));
    assert_eq!(pixel(&pixmap, 1, 0), (112, 0, 0, 255));
    assert_eq!(pixel(&pixmap, 2, 0), (197, 0, 0, 255));
  }

  #[test]
  fn scaled_image_resampling_does_not_truncate_between_axes_on_downscale() {
    // 2x2 red channel values chosen so that:
    // - a mathematically exact bilinear sample would land on an integer (64),
    // - and any truncation between the horizontal/vertical lerps would incorrectly yield 63.
    //
    // Layout (red, alpha=255):
    //   0   255
    //   1     0
    let pixels = vec![
      0, 0, 0, 255, 255, 0, 0, 255, // first row
      1, 0, 0, 255, 0, 0, 0, 255, // second row
    ];
    let image = ImageData::new_pixels(2, 2, pixels);

    // Use a <2x downscale so mipmaps are *not* selected (otherwise we'd just sample the 1x1 mip
    // level and never hit the bilinear path).
    //
    // This geometry ensures the only output pixel maps to the source center (0.5, 0.5), producing
    // a 50/50 bilinear weight in both axes.
    let dest = Rect::from_xywh(-0.25, -0.25, 1.5, 1.5);
    let origin_x = (dest.x() - 0.5).ceil();
    let origin_y = (dest.y() - 0.5).ceil();
    let out_w = ((dest.x() + dest.width() - 0.5).ceil() - origin_x).round() as u32;
    let out_h = ((dest.y() + dest.height() - 0.5).ceil() - origin_y).round() as u32;
    let pixmap = super::image_data_to_scaled_pixmap_with_phase_inner(
      &image, dest, out_w, out_h, origin_x, origin_y,
    )
    .unwrap()
    .unwrap();
    assert_eq!((pixmap.width(), pixmap.height()), (1, 1));
    assert_eq!(pixel(&pixmap, 0, 0), (64, 0, 0, 255));
  }

  #[test]
  fn scaled_image_resampling_does_not_truncate_between_axes_on_upscale() {
    // Same 2x2 layout as `scaled_image_resampling_does_not_truncate_between_axes_on_downscale`, but rendered
    // through a magnification path. Chrome's bilinear magnification does not truncate between
    // axes, and rounds down once at the end, yielding 64 (not 63). (Weight quantization to 16
    // phases does not affect this particular sample because the weight is exactly 0.5.)
    //
    // Layout (red, alpha=255):
    //   0   255
    //   1     0
    let pixels = vec![
      0, 0, 0, 255, 255, 0, 0, 255, // first row
      1, 0, 0, 255, 0, 0, 0, 255, // second row
    ];
    let image = ImageData::new_pixels(2, 2, pixels);

    // Upscale to 3x3; the center output pixel maps to the source center (0.5, 0.5).
    let dest = Rect::from_xywh(0.0, 0.0, 3.0, 3.0);
    let origin_x = (dest.x() - 0.5).ceil();
    let origin_y = (dest.y() - 0.5).ceil();
    let out_w = ((dest.x() + dest.width() - 0.5).ceil() - origin_x).round() as u32;
    let out_h = ((dest.y() + dest.height() - 0.5).ceil() - origin_y).round() as u32;
    let pixmap = super::image_data_to_scaled_pixmap_with_phase_inner(
      &image, dest, out_w, out_h, origin_x, origin_y,
    )
    .unwrap()
    .unwrap();
    assert_eq!((pixmap.width(), pixmap.height()), (3, 3));
    assert_eq!(pixel(&pixmap, 1, 1), (64, 0, 0, 255));
  }

  #[test]
  fn scaled_image_resampling_quantizes_upscale_weights_to_16_phases() {
    // Chrome/Skia's magnification path appears to quantize bilinear weights to 16 phases (4-bit
    // precision). This is observable on simple ramps where the exact weight would otherwise yield
    // a different u8 result.
    //
    // 2x1 red ramp:
    //   0 255
    let pixels = vec![
      0, 0, 0, 255, 255, 0, 0, 255, // row
    ];
    let image = ImageData::new_pixels(2, 1, pixels);

    // Upscale to 5px wide; the pixel at x=1 maps to source x ~= 0.1, which quantizes to 1/16.
    // Expected red = floor(255 * (1/16)) = 15.
    let dest = Rect::from_xywh(0.0, 0.0, 5.0, 1.0);
    let origin_x = (dest.x() - 0.5).ceil();
    let origin_y = (dest.y() - 0.5).ceil();
    let out_w = ((dest.x() + dest.width() - 0.5).ceil() - origin_x).round() as u32;
    let out_h = ((dest.y() + dest.height() - 0.5).ceil() - origin_y).round() as u32;
    let pixmap = super::image_data_to_scaled_pixmap_with_phase_inner(
      &image, dest, out_w, out_h, origin_x, origin_y,
    )
    .unwrap()
    .unwrap();
    assert_eq!((pixmap.width(), pixmap.height()), (5, 1));
    assert_eq!(pixel(&pixmap, 1, 0), (15, 0, 0, 255));
  }

  #[test]
  fn scaled_image_resampling_continues_mipmap_chain_when_axis_hits_one_pixel() {
    // 2x8 image: last row is bright red, remaining rows are black. This exercises a mip chain where
    // width reaches 1px quickly but height needs additional levels.
    let mut pixels = Vec::new();
    for y in 0..8u8 {
      let r = if y == 7 { 255 } else { 0 };
      for _ in 0..2u8 {
        pixels.extend_from_slice(&[r, 0, 0, 255]);
      }
    }
    let image = ImageData::new_pixels(2, 8, pixels);

    // Downscale to 1x1: lod is driven by the vertical scale (8x). If the mipmap builder stops once
    // width reaches 1, we would sample from a 1x4 level and miss the bright row entirely.
    let pixmap = super::image_data_to_scaled_pixmap_inner(&image, 1, 1, ImageFilterQuality::Linear)
      .unwrap()
      .unwrap();
    assert_eq!((pixmap.width(), pixmap.height()), (1, 1));
    assert_eq!(pixel(&pixmap, 0, 0), (31, 0, 0, 255));
  }

  #[test]
  fn parallel_paint_shares_scaled_image_pixmaps_across_tiles() {
    crate::paint::painter::enable_paint_diagnostics();
    if crate::paint::paint_thread_pool::paint_pool().threads < 2 {
      let _ = crate::paint::painter::take_paint_diagnostics();
      return;
    }

    let pixels = vec![255u8; 64 * 64 * 4];
    let image = Arc::new(ImageData::new_pixels(64, 64, pixels));

    let mut list = DisplayList::new();
    list.push(DisplayItem::ImagePattern(ImagePatternItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 64.0, 64.0),
      image,
      tile_size: Size::new(16.0, 16.0),
      origin: Point::new(0.0, 0.0),
      repeat: ImagePatternRepeat::Repeat,
      filter_quality: ImageFilterQuality::Linear,
    }));

    let mut parallelism = PaintParallelism::enabled();
    parallelism.tile_size = 16;
    parallelism.min_display_items = 0;
    parallelism.min_tiles = 0;
    parallelism.max_threads = Some(2);

    let renderer = DisplayListRenderer::new(64, 64, Rgba::WHITE, FontContext::new())
      .unwrap()
      .with_parallelism(parallelism);
    let report = renderer.render_with_report(&list).unwrap();
    assert_eq!(
      report.image_pixmap_cache_misses, 1,
      "expected scaled image pixmap conversion to be shared across tiles"
    );

    let _ = crate::paint::painter::take_paint_diagnostics();
  }

  #[test]
  fn pixelated_nearest_snaps_upscale_to_integer_factor() {
    let pixels = vec![
      0, 0, 0, 255, 0, 0, 0, 255, // 2x1 black strip
    ];
    let image = Arc::new(ImageData::new_pixels(2, 1, pixels));

    let mut list = DisplayList::new();
    list.push(DisplayItem::Image(ImageItem {
      dest_rect: Rect::from_xywh(0.0, 0.0, 5.0, 1.0),
      image: image.clone(),
      filter_quality: ImageFilterQuality::Nearest,
      src_rect: None,
    }));

    let pixmap = DisplayListRenderer::new(5, 1, Rgba::WHITE, FontContext::new())
      .unwrap()
      .render(&list)
      .unwrap();

    // Snapped scaling shrinks to a 2x integer factor (4px) centered in the 5px box.
    assert_eq!(pixel(&pixmap, 0, 0), (255, 255, 255, 255));
    assert_eq!(pixel(&pixmap, 1, 0), (0, 0, 0, 255));
    assert_eq!(pixel(&pixmap, 4, 0), (0, 0, 0, 255));
  }

  #[test]
