  #[test]
  fn solid_text_decoration_snaps_to_device_pixels_to_avoid_blurred_1px_lines() {
    // `TextDecorationItem` stroke centers come from font metrics and commonly land on fractional
    // device pixel boundaries (e.g. `*.692` in si.edu), which causes a 1px underline to be
    // anti-aliased across two rows. When there is no transform and the thickness is an integer
    // device pixel count, the renderer should snap the stroke origin to the device pixel grid so
    // the underline paints crisply on a single row.
    let mut list = DisplayList::new();
    list.push(DisplayItem::TextDecoration(TextDecorationItem {
      bounds: Rect::from_xywh(0.0, 0.0, 10.0, 2.0),
      line_start: 0.0,
      line_width: 10.0,
      inline_vertical: false,
      decorations: vec![DecorationPaint {
        style: TextDecorationStyle::Solid,
        color: Rgba::from_rgba8(255, 0, 0, 255),
        underline: Some(DecorationStroke {
          center: 0.692,
          thickness: 1.0,
          segments: None,
        }),
        overline: None,
        line_through: None,
      }],
    }));

    let pixmap = DisplayListRenderer::new(10, 2, Rgba::WHITE, FontContext::new())
      .expect("renderer")
      .render(&list)
      .expect("rendered");

    for x in 0..10 {
      assert_eq!(pixel(&pixmap, x, 0), (255, 0, 0, 255));
      assert_eq!(pixel(&pixmap, x, 1), (255, 255, 255, 255));
    }
  }

  #[test]
  fn text_decoration_solid_snaps_fractional_thickness_to_device_pixels() {
    let mut list = DisplayList::new();
    list.push(DisplayItem::TextDecoration(TextDecorationItem {
      bounds: Rect::from_xywh(0.0, 0.0, 20.0, 15.0),
      line_start: 0.0,
      line_width: 20.0,
      inline_vertical: false,
      decorations: vec![
        DecorationPaint {
          style: TextDecorationStyle::Solid,
          color: Rgba::from_rgba8(0, 0, 255, 255),
          underline: Some(DecorationStroke {
            // pre-snap edge = 6.8 - 0.9 = 5.9, so snap edge to 6 and thickness to 1.
            center: 6.8,
            thickness: 1.8,
            segments: None,
          }),
          overline: None,
          line_through: None,
        },
        DecorationPaint {
          style: TextDecorationStyle::Solid,
          color: Rgba::from_rgba8(255, 0, 0, 255),
          underline: Some(DecorationStroke {
            // pre-snap edge = 10.8 - 1.35 = 9.45, so snap edge to 9 and thickness to 2.
            center: 10.8,
            thickness: 2.7,
            segments: None,
          }),
          overline: None,
          line_through: None,
        },
      ],
    }));

    let pixmap = DisplayListRenderer::new(20, 15, Rgba::WHITE, FontContext::new())
      .expect("renderer")
      .render(&list)
      .expect("rendered");

    // 1.8px thickness should snap down to a crisp 1px line at y=6.
    assert_eq!(pixel(&pixmap, 10, 6), (0, 0, 255, 255));
    assert_eq!(pixel(&pixmap, 10, 5), (255, 255, 255, 255));
    assert_eq!(pixel(&pixmap, 10, 7), (255, 255, 255, 255));
    // 2.7px thickness should snap down to a crisp 2px line at y=9..10.
    assert_eq!(pixel(&pixmap, 10, 9), (255, 0, 0, 255));
    assert_eq!(pixel(&pixmap, 10, 10), (255, 0, 0, 255));
    assert_eq!(pixel(&pixmap, 10, 11), (255, 255, 255, 255));
  }

  #[test]
  fn text_decoration_segments_respect_gaps() {
    let mut list = DisplayList::new();
    list.push(DisplayItem::TextDecoration(TextDecorationItem {
      bounds: Rect::from_xywh(0.0, 0.0, 20.0, 10.0),
      line_start: 0.0,
      line_width: 20.0,
      inline_vertical: false,
      decorations: vec![DecorationPaint {
        style: TextDecorationStyle::Solid,
        color: Rgba::from_rgba8(0, 0, 255, 255),
        underline: Some(DecorationStroke {
          center: 5.0,
          thickness: 2.0,
          segments: Some(vec![(0.0, 6.0), (14.0, 20.0)]),
        }),
        overline: None,
        line_through: None,
      }],
    }));

    let pixmap = DisplayListRenderer::new(20, 10, Rgba::WHITE, FontContext::new())
      .expect("renderer")
      .render(&list)
      .expect("rendered");
    // Painted segments should hit inside and right span.
    assert_eq!(pixel(&pixmap, 2, 5), (0, 0, 255, 255));
    assert_eq!(pixel(&pixmap, 16, 5), (0, 0, 255, 255));
    // Gap should remain white.
    assert_eq!(pixel(&pixmap, 10, 5), (255, 255, 255, 255));
  }

  #[test]
  fn text_decoration_percentage_thickness_paints_font_relative_size() {
    let mut style = ComputedStyle::default();
    style.color = Rgba::BLACK;
    style.font_size = 20.0;
    style.text_decoration.lines = TextDecorationLine::UNDERLINE;
    style.text_decoration.color = Some(Rgba::from_rgba8(255, 0, 0, 255));
    style.text_decoration.thickness = TextDecorationThickness::Length(Length::percent(50.0));
    let style = Arc::new(style);

    let text_rect = Rect::from_xywh(10.0, 10.0, 80.0, 30.0);
    let fragment = FragmentNode::new_text_styled(text_rect, "Hi".to_string(), 22.0, style);
    let root = FragmentNode::new_block(Rect::from_xywh(0.0, 0.0, 120.0, 60.0), vec![fragment]);

    let font_ctx = FontContext::new();
    let list = DisplayListBuilder::new()
      .with_font_context(font_ctx.clone())
      .build(&root);
    let pixmap = DisplayListRenderer::new(120, 60, Rgba::WHITE, font_ctx)
      .expect("renderer")
      .render(&list)
      .expect("rendered");

    let red_bbox =
      bounding_box_for_color(&pixmap, |(r, g, b, a)| a > 0 && r > 200 && g < 80 && b < 80)
        .expect("underline");
    let height = red_bbox.3 - red_bbox.1 + 1;
    assert!(
      (9..=11).contains(&height),
      "expected underline thickness around 10px (50% of 20px font), got {height}"
    );
  }

