  #[test]
  fn linear_gradient_pattern_matches_explicit_tiling() {
    let origin = Point::new(2.0, 3.0);
    let tile_size = Size::new(8.0, 8.0);
    // Align the destination rect to the pattern grid so all tiles are full-sized. When edge tiles
    // are clipped the per-tile rasterization uses smaller LUT buckets which can produce tiny
    // rounding differences vs sampling from a full tile pixmap.
    let dest_rect = Rect::from_xywh(
      origin.x,
      origin.y,
      tile_size.width * 3.0,
      tile_size.height * 3.0,
    );

    let stops = vec![
      GradientStop {
        position: 0.0,
        color: Rgba::rgb(255, 0, 0),
      },
      GradientStop {
        position: 1.0,
        color: Rgba::rgb(0, 0, 255),
      },
    ];

    let angle = 45.0f32;
    let rad = angle.to_radians();
    let dx = rad.sin();
    let dy = -rad.cos();
    let len = 0.5 * (tile_size.width * dx.abs() + tile_size.height * dy.abs());

    let tile_center_x = tile_size.width * 0.5;
    let tile_center_y = tile_size.height * 0.5;
    let tile_start = Point::new(tile_center_x - dx * len, tile_center_y - dy * len);
    let tile_end = Point::new(tile_center_x + dx * len, tile_center_y + dy * len);

    let aligned_start = |origin: f32, tile: f32, clip_min: f32| -> f32 {
      if tile == 0.0 {
        return origin;
      }
      let steps = ((clip_min - origin) / tile).floor();
      origin + steps * tile
    };

    let build_positions = |origin: f32, tile: f32, clip_min: f32, clip_max: f32| -> Vec<f32> {
      if tile <= 0.0 {
        return Vec::new();
      }
      let start = aligned_start(origin, tile, clip_min);
      let mut positions = Vec::new();
      let mut pos = start;
      while pos < clip_max {
        positions.push(pos);
        pos += tile;
      }
      positions
    };

    let positions_x = build_positions(
      origin.x,
      tile_size.width,
      dest_rect.min_x(),
      dest_rect.max_x(),
    );
    let positions_y = build_positions(
      origin.y,
      tile_size.height,
      dest_rect.min_y(),
      dest_rect.max_y(),
    );

    let mut explicit = DisplayList::new();
    for ty in positions_y.iter().copied() {
      for tx in positions_x.iter().copied() {
        let tile_rect = Rect::from_xywh(tx, ty, tile_size.width, tile_size.height);
        let Some(intersection) = tile_rect.intersection(dest_rect) else {
          continue;
        };
        if intersection.width() <= 0.0 || intersection.height() <= 0.0 {
          continue;
        }

        let cx = tile_rect.x() + tile_size.width * 0.5;
        let cy = tile_rect.y() + tile_size.height * 0.5;
        let start = Point::new(
          cx - dx * len - intersection.x(),
          cy - dy * len - intersection.y(),
        );
        let end = Point::new(
          cx + dx * len - intersection.x(),
          cy + dy * len - intersection.y(),
        );

        explicit.push(DisplayItem::LinearGradient(LinearGradientItem {
          rect: intersection,
          start,
          end,
          spread: GradientSpread::Pad,
          stops: stops.clone(),
        }));
      }
    }

    let mut patterned = DisplayList::new();
    patterned.push(DisplayItem::LinearGradientPattern(
      LinearGradientPatternItem {
        dest_rect,
        tile_size,
        origin,
        start: tile_start,
        end: tile_end,
        stops: stops.clone(),
        spread: GradientSpread::Pad,
      },
    ));

    let font_ctx = FontContext::new();
    let pixmap_explicit = DisplayListRenderer::new(32, 32, Rgba::WHITE, font_ctx.clone())
      .expect("renderer")
      .render(&explicit)
      .expect("render explicit");
    let pixmap_pattern = DisplayListRenderer::new(32, 32, Rgba::WHITE, font_ctx)
      .expect("renderer")
      .render(&patterned)
      .expect("render pattern");

    if pixmap_explicit.data() != pixmap_pattern.data() {
      let (width, height) = (pixmap_explicit.width(), pixmap_explicit.height());
      assert_eq!(
        (width, height),
        (pixmap_pattern.width(), pixmap_pattern.height()),
        "pixmap sizes must match"
      );
      let mut mismatch = None;
      for y in 0..height {
        for x in 0..width {
          let idx = ((y * width + x) * 4) as usize;
          let a = &pixmap_explicit.data()[idx..idx + 4];
          let b = &pixmap_pattern.data()[idx..idx + 4];
          if a != b {
            mismatch = Some((x, y, [a[0], a[1], a[2], a[3]], [b[0], b[1], b[2], b[3]]));
            break;
          }
        }
        if mismatch.is_some() {
          break;
        }
      }
      let (x, y, a, b) = mismatch.expect("pixmaps differ but no mismatch located");

      panic!(
        "pattern-based gradient rendering should match explicit tiling; first mismatch at ({x},{y}): explicit={a:?} pattern={b:?}"
      );
    }
  }

  #[test]
  fn linear_gradient_pattern_does_not_overpaint_fractional_edges() {
    let renderer = DisplayListRenderer::new(3, 3, Rgba::WHITE, FontContext::new()).unwrap();
    let mut list = DisplayList::new();
    list.push(DisplayItem::LinearGradientPattern(
      LinearGradientPatternItem {
        dest_rect: Rect::from_xywh(0.0, 0.99, 3.0, 1.0),
        tile_size: Size::new(3.0, 1.0),
        origin: Point::new(0.0, 0.99),
        start: Point::new(0.0, 0.5),
        end: Point::new(3.0, 0.5),
        stops: vec![
          GradientStop {
            position: 0.0,
            color: Rgba::rgb(255, 0, 0),
          },
          GradientStop {
            position: 1.0,
            color: Rgba::rgb(255, 0, 0),
          },
        ],
        spread: GradientSpread::Pad,
      },
    ));

    let pixmap = renderer.render(&list).unwrap();
    assert_eq!(pixel(&pixmap, 0, 0), (255, 255, 255, 255));
    assert_eq!(pixel(&pixmap, 0, 1), (255, 0, 0, 255));
    assert_eq!(pixel(&pixmap, 0, 2), (255, 255, 255, 255));
  }

  #[test]
  fn linear_gradient_pattern_composites_with_truncating_mul_div_255() {
    // Regression test: the axis-aligned pattern fast-path builds a fully-rasterized pixmap and
    // then composites it into the destination surface. Use a semi-transparent source color over a
    // non-white background so `mul/255` rounding differences show up as ±1 channel diffs.
    let background = Rgba::rgb(101, 102, 103);
    let renderer = DisplayListRenderer::new(4, 2, background, FontContext::new()).unwrap();
    let mut list = DisplayList::new();
    list.push(DisplayItem::LinearGradientPattern(
      LinearGradientPatternItem {
        dest_rect: Rect::from_xywh(0.0, 0.0, 4.0, 2.0),
        tile_size: Size::new(2.0, 2.0),
        origin: Point::new(0.0, 0.0),
        // Degenerate gradient (start == end) produces a solid tile without ordered dithering.
        start: Point::new(0.0, 0.0),
        end: Point::new(0.0, 0.0),
        stops: vec![
          GradientStop {
            position: 0.0,
            color: Rgba::new(0, 0, 0, 0.4),
          },
          GradientStop {
            position: 1.0,
            color: Rgba::new(0, 0, 0, 0.4),
          },
        ],
        spread: GradientSpread::Pad,
      },
    ));

    let pixmap = renderer.render(&list).unwrap();
    for y in 0..2 {
      for x in 0..4 {
        assert_rgba_close(pixel(&pixmap, x, y), (60, 61, 61, 255), 1);
      }
    }
  }

  #[test]
  fn linear_gradient_pattern_single_tile_matches_direct_gradient() {
    // The pattern renderer rasterizes a tile pixmap at an integer size and can then scale it back
    // to the intended tile size. When the tile size is fractional, sampling can diverge from
    // directly evaluating the gradient. For destination rects that fall entirely within a single
    // tile, the correct behavior is equivalent to rendering the gradient directly with the tile
    // phase applied.
    let tile_size = Size::new(10.0, 3.5);
    let origin = Point::new(0.0, 0.0);
    // Pick a destination rect that is wholly contained within one tile and aligned to integer
    // device pixels so any mismatch is due to gradient evaluation, not edge coverage.
    let dest_rect = Rect::from_xywh(1.0, 1.0, 4.0, 2.0);

    let stops = vec![
      GradientStop {
        position: 0.0,
        color: Rgba::rgb(0, 0, 0),
      },
      GradientStop {
        position: 1.0,
        color: Rgba::rgb(255, 255, 255),
      },
    ];

    let tile_start = Point::new(0.0, 0.0);
    let tile_end = Point::new(0.0, tile_size.height);

    let phase_x = (dest_rect.x() - origin.x).rem_euclid(tile_size.width);
    let phase_y = (dest_rect.y() - origin.y).rem_euclid(tile_size.height);
    let direct_start = Point::new(tile_start.x - phase_x, tile_start.y - phase_y);
    let direct_end = Point::new(tile_end.x - phase_x, tile_end.y - phase_y);

    let mut patterned = DisplayList::new();
    patterned.push(DisplayItem::LinearGradientPattern(
      LinearGradientPatternItem {
        dest_rect,
        tile_size,
        origin,
        start: tile_start,
        end: tile_end,
        stops: stops.clone(),
        spread: GradientSpread::Pad,
      },
    ));

    let mut direct = DisplayList::new();
    direct.push(DisplayItem::LinearGradient(LinearGradientItem {
      rect: dest_rect,
      start: direct_start,
      end: direct_end,
      stops,
      spread: GradientSpread::Pad,
    }));

    let font_ctx = FontContext::new();
    let pixmap_pattern = DisplayListRenderer::new(16, 8, Rgba::WHITE, font_ctx.clone())
      .expect("renderer")
      .render(&patterned)
      .expect("render pattern");
    let pixmap_direct = DisplayListRenderer::new(16, 8, Rgba::WHITE, font_ctx)
      .expect("renderer")
      .render(&direct)
      .expect("render direct");

    if pixmap_direct.data() != pixmap_pattern.data() {
      let (width, height) = (pixmap_direct.width(), pixmap_direct.height());
      assert_eq!(
        (width, height),
        (pixmap_pattern.width(), pixmap_pattern.height()),
        "pixmap sizes must match"
      );
      let mut mismatch = None;
      for y in 0..height {
        for x in 0..width {
          let idx = ((y * width + x) * 4) as usize;
          let a = &pixmap_direct.data()[idx..idx + 4];
          let b = &pixmap_pattern.data()[idx..idx + 4];
          if a != b {
            mismatch = Some((x, y, [a[0], a[1], a[2], a[3]], [b[0], b[1], b[2], b[3]]));
            break;
          }
        }
        if mismatch.is_some() {
          break;
        }
      }
      let (x, y, a, b) = mismatch.expect("pixmaps differ but no mismatch located");
      panic!(
        "single-tile pattern gradient should match direct gradient; first mismatch at ({x},{y}): direct={a:?} pattern={b:?}"
      );
    }
  }

  #[test]
  fn linear_gradient_clips_to_visible_bounds_and_does_not_skip() {
    let mut renderer = DisplayListRenderer::new(64, 64, Rgba::WHITE, FontContext::new()).unwrap();
    renderer.diagnostics_enabled = true;
    let mut list = DisplayList::new();
    let rect = Rect::from_xywh(-10_000.0, -10_000.0, 20_000.0, 20_000.0);
    let start = Point::new(0.0, 0.0);
    let end = Point::new(20_000.0, 0.0);
    list.push(DisplayItem::LinearGradient(LinearGradientItem {
      rect,
      start,
      end,
      spread: GradientSpread::Pad,
      stops: vec![
        GradientStop {
          position: 0.0,
          color: Rgba::rgb(255, 0, 0),
        },
        GradientStop {
          position: 1.0,
          color: Rgba::rgb(0, 0, 255),
        },
      ],
    }));

    let report = renderer.render_with_report(&list).unwrap();
    assert_eq!(
      report.gradient_stats.pixels,
      (64 * 64) as u64,
      "should only rasterize the visible portion of the oversized gradient"
    );

    let pixmap = report.pixmap;
    let actual = pixel(&pixmap, 0, 0);
    let expected = expected_linear_red_blue(rect, start, end, 0, 0);
    assert_rgba_close(actual, expected, 1);

    let actual = pixel(&pixmap, 63, 0);
    let expected = expected_linear_red_blue(rect, start, end, 63, 0);
    assert_rgba_close(actual, expected, 1);
  }

