  #[test]
  fn filter_outset_accumulates_blurs() {
    let filters = vec![ResolvedFilter::Blur(2.0), ResolvedFilter::Blur(3.0)];
    let (l, t, r, b) = filter_outset(&filters, 1.0).as_tuple();
    assert!(
      (l - 15.0).abs() < 0.01
        && (t - 15.0).abs() < 0.01
        && (r - 15.0).abs() < 0.01
        && (b - 15.0).abs() < 0.01,
      "blur outsets should add up across filter chain"
    );
  }

  #[test]
  fn filter_outset_accumulates_drop_shadow_offsets() {
    let filters = vec![
      ResolvedFilter::Blur(2.0),
      ResolvedFilter::DropShadow {
        offset_x: -4.0,
        offset_y: 3.0,
        blur_radius: 1.0,
        spread: 0.0,
        color: Rgba::BLACK,
      },
    ];
    let (l, t, r, b) = filter_outset(&filters, 1.0).as_tuple();
    assert!(
      (l - 13.0).abs() < 0.01
        && (t - 6.0).abs() < 0.01
        && (r - 6.0).abs() < 0.01
        && (b - 12.0).abs() < 0.01,
      "expected accumulated outsets to be l=13,t=6,r=6,b=12 but got {l},{t},{r},{b}"
    );
  }

  #[test]
  fn blur_filter_outset_scales_with_device_pixel_ratio() {
    let filters = vec![ResolvedFilter::Blur(4.0)];
    let (l, t, r, b) = filter_outset(&filters, 1.0).as_tuple();
    // Blur outset is radius * 3 per side.
    assert!(
      (l - 12.0).abs() < 0.01
        && (t - 12.0).abs() < 0.01
        && (r - 12.0).abs() < 0.01
        && (b - 12.0).abs() < 0.01
    );

    let filters = vec![ResolvedFilter::Blur(2.0)];
    let (l, t, r, b) = filter_outset(&filters, 2.0).as_tuple();
    // Device pixel ratio doubles the blur radius before computing outsets.
    assert!(
      (l - 12.0).abs() < 0.01
        && (t - 12.0).abs() < 0.01
        && (r - 12.0).abs() < 0.01
        && (b - 12.0).abs() < 0.01
    );
  }

  #[test]
  fn stacking_context_filter_stays_bounded() {
    let filters = vec![ResolvedFilter::Blur(1.0)];
    let renderer = DisplayListRenderer::new(20, 20, Rgba::WHITE, FontContext::new()).unwrap();
    let mut list = DisplayList::new();
    let bounds = Rect::from_xywh(2.0, 2.0, 4.0, 4.0);
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: true,
      has_backdrop_sensitive_descendants: false,
      bounds,
      plane_rect: bounds,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: true,
      transform: None,
      child_perspective: None,
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: filters.clone(),
      backdrop_filters: Vec::new(),
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: bounds,
      color: Rgba::RED,
    }));
    list.push(DisplayItem::PopStackingContext);

    let pixmap = renderer.render(&list).unwrap();
    let bbox = bounding_box_for_color(&pixmap, |(r, g, b, a)| a > 0 && r > g && r > b)
      .expect("blurred content");
    let (out_l, out_t, out_r, out_b) = filter_outset(&filters, 1.0).as_tuple();
    let expected = Rect::from_xywh(
      bounds.x() - out_l,
      bounds.y() - out_t,
      bounds.width() + out_l + out_r,
      bounds.height() + out_t + out_b,
    );
    assert!(
      bbox.0 >= expected.min_x().floor() as u32 && bbox.1 >= expected.min_y().floor() as u32,
      "expected bbox {:?} to start within {:?}",
      bbox,
      expected
    );
    assert!(
      bbox.2 <= expected.max_x().ceil() as u32 && bbox.3 <= expected.max_y().ceil() as u32,
      "expected bbox {:?} to end within {:?}",
      bbox,
      expected
    );
  }

  #[test]
  fn backdrop_filter_allocates_bounded_layer() {
    crate::paint::painter::enable_paint_diagnostics();
    struct DiagnosticsGuard;
    impl Drop for DiagnosticsGuard {
      fn drop(&mut self) {
        let _ = crate::paint::painter::take_paint_diagnostics();
      }
    }
    let _guard = DiagnosticsGuard;

    const SIZE: u32 = 1024;
    let renderer = DisplayListRenderer::new(SIZE, SIZE, Rgba::WHITE, FontContext::new())
      .unwrap()
      .with_parallelism(PaintParallelism::disabled());
    let mut list = DisplayList::new();
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(0.0, 0.0, SIZE as f32, SIZE as f32),
      color: Rgba::RED,
    }));

    let bounds = Rect::from_xywh(500.0, 500.0, 10.0, 10.0);
    list.push(DisplayItem::PushStackingContext(StackingContextItem {
      z_index: 0,
      creates_stacking_context: true,
      is_root: false,
      establishes_backdrop_root: true,
      has_backdrop_sensitive_descendants: true,
      bounds,
      plane_rect: bounds,
      mix_blend_mode: BlendMode::Normal,
      opacity: 1.0,
      is_isolated: false,
      transform: None,
      child_perspective: None,
      transform_style: TransformStyle::Flat,
      backface_visibility: BackfaceVisibility::Visible,
      filters: Vec::new(),
      backdrop_filters: vec![ResolvedFilter::Invert(1.0)],
      radii: BorderRadii::ZERO,
      mask: None,
      mask_border: None,
      has_clip_path: false,
    }));
    list.push(DisplayItem::PopStackingContext);

    let report = renderer.render_with_report(&list).unwrap();
    assert_eq!(
      report.layer_allocations, 1,
      "expected exactly one isolated layer allocation"
    );
    let full_canvas_bytes = u64::from(SIZE)
      .saturating_mul(u64::from(SIZE))
      .saturating_mul(4);
    assert!(
      report.layer_alloc_bytes < full_canvas_bytes / 4,
      "expected backdrop-filter to allocate a bounded layer; got {} bytes for a {}-byte canvas",
      report.layer_alloc_bytes,
      full_canvas_bytes
    );
  }

  #[test]
  fn push_blend_mode_allocates_bounded_layer_when_clipped() {
    crate::paint::painter::enable_paint_diagnostics();
    struct DiagnosticsGuard;
    impl Drop for DiagnosticsGuard {
      fn drop(&mut self) {
        let _ = crate::paint::painter::take_paint_diagnostics();
      }
    }
    let _guard = DiagnosticsGuard;

    const SIZE: u32 = 1024;
    let renderer = DisplayListRenderer::new(SIZE, SIZE, Rgba::WHITE, FontContext::new())
      .unwrap()
      .with_parallelism(PaintParallelism::disabled());

    let mut list = DisplayList::new();
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(0.0, 0.0, SIZE as f32, SIZE as f32),
      color: Rgba::from_rgba8(30, 120, 220, 255),
    }));

    let clip1 = Rect::from_xywh(128.0, 256.0, 64.0, 32.0);
    list.push(DisplayItem::PushClip(ClipItem {
      shape: ClipShape::Rect {
        rect: clip1,
        radii: None,
      },
    }));
    list.push(DisplayItem::PushBlendMode(BlendModeItem {
      mode: BlendMode::Multiply,
    }));
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(0.0, 0.0, SIZE as f32, SIZE as f32),
      color: Rgba::from_rgba8(200, 200, 40, 255),
    }));
    list.push(DisplayItem::PopBlendMode);
    list.push(DisplayItem::PopClip);

    let clip2 = Rect::from_xywh(64.0, 64.0, 32.0, 16.0);
    list.push(DisplayItem::PushClip(ClipItem {
      shape: ClipShape::Rect {
        rect: clip2,
        radii: None,
      },
    }));
    list.push(DisplayItem::PushBlendMode(BlendModeItem {
      mode: BlendMode::Hue,
    }));
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(0.0, 0.0, SIZE as f32, SIZE as f32),
      color: Rgba::from_rgba8(200, 40, 60, 255),
    }));
    list.push(DisplayItem::PopBlendMode);
    list.push(DisplayItem::PopClip);

    let report = renderer.render_with_report(&list).unwrap();
    assert_eq!(
      report.layer_allocations, 2,
      "expected each clipped PushBlendMode to allocate its own layer"
    );
    let expected_bytes = (64u64 * 32u64)
      .saturating_add(32u64 * 16u64)
      .saturating_mul(4);
    assert_eq!(
      report.layer_alloc_bytes, expected_bytes,
      "expected PushBlendMode layers to be allocated at the clip bounds"
    );
  }

  #[test]
  fn push_blend_mode_does_not_seed_opacity_group_backdrop() {
    // `PushBlendMode` is used for CSS `background-blend-mode` (blending between background layers).
    // It must not cause the active compositing group to be initialized from the already-painted
    // backdrop, otherwise background layers would incorrectly blend against page contents.
    //
    // This test exercises the renderer's lazy backdrop seeding logic: an opacity group with
    // `opacity == 1` is a non-isolated group surface, but a background blend must still start from
    // a transparent backdrop (the element's own background stack), not the underlying canvas.
    let renderer = DisplayListRenderer::new(4, 4, Rgba::WHITE, FontContext::new()).unwrap();

    let mut list = DisplayList::new();
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(0.0, 0.0, 4.0, 4.0),
      color: Rgba::from_rgba8(0, 255, 0, 255),
    }));
    list.push(DisplayItem::PushOpacity(OpacityItem { opacity: 1.0 }));
    list.push(DisplayItem::PushBlendMode(BlendModeItem {
      mode: BlendMode::Multiply,
    }));
    list.push(DisplayItem::FillRect(FillRectItem {
      rect: Rect::from_xywh(0.0, 0.0, 4.0, 4.0),
      color: Rgba::from_rgba8(0, 0, 255, 255),
    }));
    list.push(DisplayItem::PopBlendMode);
    list.push(DisplayItem::PopOpacity);

    let pixmap = renderer.render(&list).unwrap();
    assert_eq!(
      pixel(&pixmap, 2, 2),
      (0, 0, 255, 255),
      "expected PushBlendMode subtree to blend over a transparent group backdrop (blue), not the already-painted canvas (would multiply to black)"
    );
  }

